const GalaxyComp(id: '0xnihilism_cold-tiger-22', cat: 'Cards', author: '0xnihilism', tags: 'simple,card,smooth,hover effect,advanced,card hover', html: '<div class="card">\n  <div data-text="The Eye of Providence" class="title">\n    The Eye of Providence\n  </div>\n  <div class="eye-of-providence">\n    <div class="triangle"></div>\n    <div class="eye">\n      <div class="eyelid"></div>\n      <div class="iris">\n        <div class="pupil"></div>\n      </div>\n    </div>\n  </div>\n  <div class="spotlight"></div>\n  <div class="scan-line"></div>\n  <div class="glitch-text">Always Watching</div>\n  <div class="footer-text">Obey. Trust. Consume</div>\n</div>', css: '\n/* From Uiverse.io by 0xnihilism  - Tags: simple, card, smooth, hover effect, advanced, card hover */\n.card {\n  background-color: #222;\n  border: 10px solid rgb(161, 156, 116);\n  padding: 30px;\n  width: 400px;\n  text-align: center;\n  position: relative;\n  box-shadow: 9px 11px 1px rgb(0, 0, 0);\n  transition: transform 0.3s ease, box-shadow 0.3s ease;\n  cursor: pointer;\n  overflow: hidden;\n  z-index: 1;\n}\n\n.card::before {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  background: repeating-linear-gradient(\n    0deg,\n    rgba(255, 255, 255, 0.05),\n    rgba(255, 255, 255, 0.05) 1px,\n    transparent 1px,\n    transparent 2px\n  );\n\n  opacity: 0.3;\n  pointer-events: none;\n  z-index: 2;\n  animation: tv-static 0.2s infinite linear alternate;\n}\n\n.card::after {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.25) 50%),\n    linear-gradient(\n      90deg,\n      rgba(255, 0, 0, 0.06),\n      rgba(0, 255, 0, 0.02),\n      rgba(0, 0, 255, 0.06)\n    );\n  background-size: 100% 2px, 3px 100%;\n  animation: tv-flicker 0.15s infinite;\n  z-index: 35;\n  pointer-events: none;\n  opacity: 0.5;\n}\n\n@keyframes tv-static {\n  0% {\n    opacity: 0.3;\n  }\n  100% {\n    opacity: 0.1;\n  }\n}\n\n.eye-of-providence {\n  position: relative;\n  width: 220px;\n  height: 220px;\n  margin: 0 auto 20px;\n}\n\n.triangle {\n  width: 0;\n  height: 0;\n  border-left: 110px solid transparent;\n  border-right: 110px solid transparent;\n  border-bottom: 190px solid rgb(198, 181, 113);\n  position: absolute;\n  top: 0;\n  left: 0;\n  z-index: 1;\n  transition: transform 0.3s ease;\n}\n\n.card:hover .triangle {\n  transform: scale(1.05);\n}\n\n.eye {\n  width: 90px;\n  height: 50px;\n  background: radial-gradient(circle at 30% 30%, #fff, #e6e6e6);\n  border-radius: 50%;\n  position: absolute;\n  top: 90px;\n  left: 65px;\n  overflow: hidden;\n  box-shadow: 0 0 0 10px rgb(115, 112, 92), 15px 15px 0 #000,\n    inset -5px', colors: '#e6e6e6,#0ff,#000,#222,#f00,#444,#fff', radii: '50%', shadows: '9px 11px 1px rgb(0, 0, 0),0 0 0 10px rgb(115, 112, 92), 15px 15px 0 #000,\n    inset -5px -5px 10px rgba(0, 0, 0, 0.2),\n    inset 5px 5px 10px rgba,inset 0 0 10px rgba(203, 4, 4, 0.2), 0 0 10px rgba(0, 0, 0, 0.5)', techniques: 'cubic-bezier,3d-transform,glow-shadow,text-shadow,gradient,animation,clip-path,typography-transform,pseudo-elements'),
