pective: 1000px;\n  overflow: hidden;\n  transition: transform 0.6s ease-in-out, box-shadow 0.6s ease-in-out;\n  text-align: center;\n  color: #fff;\n  cursor: pointer;\n}\n\n.card:hover {\n  transform: scale(1.05) rotateX(-10deg) rotateY(-10deg);\n  box-shadow: 0 8px 40px rgba(0, 0, 0, 0.8), 0 12px 60px rgba(0, 0, 0, 1);\n}\n\n.card::before,\n.card::after {\n  content: "";\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  top: 0;\n  left: 0;\n  border-radius: 16px;\n  z-index: -1;\n  transition: all 0.6s ease-in-out;\n}\n\n.card::before {\n  background: linear-gradient(\n    135deg,\n    rgba(96, 139, 188, 0.15),\n    rgba(70, 103, 152, 0.15)\n  );\n  transform: translateY(-10px) translateX(10px);\n  box-shadow: 0 0 30px rgba(96, 139, 188, 0.2);\n}\n\n.card::after {\n  border: 1px dashed rgba(71, 71, 71, 0.425);\n  transform: translateY(20px) translateX(-20px);\n}\n\n.card:hover::before {\n  transform: translateY(-20px) translateX(20px);\n  box-shadow: 0 0 60px rgba(96, 139, 188, 0.4);\n}\n\n.card:hover::after {\n  transform: translateY(40px) translateX(-40px);\n  border: 1px dashed rgba(0, 140, 255, 0.5);\n}\n\n.card .image {\n  width: 150px;\n  margin: 0 auto;\n  animation: float 4s ease-in-out infinite;\n}\n\n@keyframes float {\n  0%,\n  100% {\n    transform: translateY(0);\n  }\n  50% {\n    transform: translateY(-10px);\n  }\n}\n\n.card .heading {\n  font-size: 1.5rem;\n  font-weight: 600;\n  margin: 1rem 0;\n  color: #956afa;\n  text-shadow: 0 0 10px rgba(149, 106, 250, 0.8);\n  text-transform: uppercase;\n}\n\n.card .icons {\n  display: flex;\n  justify-content: center;\n  gap: 15px;\n}\n\n.card .icons a {\n  color: #fff;\n  transition: transform 0.3s ease, color 0.3s ease;\n}\n\n.card .icons a svg {\n  w', colors: '#7289da,#1da1f2,#956afa,#2c2c2c,#e4405f,#fff,#1a1a1a', radii: '16px', shadows: '0 4px 20px rgba(0, 0, 0, 0.4), 0 8px 40px rgba(0, 0, 0, 0.6),0 8px 40px rgba(0, 0, 0, 0.8), 0 12px 60px rgba(0, 0, 0, 1),0 0 30px rgba(96, 139, 188, 0.2)', 