gba(255, 255, 255, 0.1);\n  border-radius: 20px;\n  backdrop-filter: blur(10px);\n  border: 1px solid rgba(255, 255, 255, 0.2);\n  overflow: hidden;\n  box-shadow: 0px 10px 20px rgba(0, 0, 0, 0.2);\n  transition: transform 0.3s ease, box-shadow 0.3s ease;\n  max-width: 400px;\n  height: auto;\n  transition: all ease-in-out 0.5s;\n}\n.card::before,\n.card::after {\n  content: "";\n  position: absolute;\n  width: 150px;\n  height: 150px;\n  border-radius: 50%;\n  z-index: -2;\n}\n.card::before {\n  top: -25px;\n  left: -25px;\n  background: radial-gradient(circle, #875c98, #4a236a);\n  filter: blur(20px);\n  opacity: 0.8;\n  animation: glowBall1 5s infinite ease-in-out;\n}\n\n.card::after {\n  bottom: -25px;\n  right: -25px;\n  background: radial-gradient(circle, #4a236a, #875c98);\n  filter: blur(20px);\n  opacity: 0.8;\n  animation: glowBall2 7s infinite ease-in-out;\n}\n.image {\n  width: 70%;\n  height: auto;\n  border-radius: 20px 20px 0 0; /* Adjust rounded corners */\n  transition: transform 0.3s ease;\n  z-index: 9; /* Ensure the image is above the balls */\n  display: block;\n  margin: 0 auto; /* Center the image horizontally */\n}\n.image:hover {\n  transform: scale(1.05);\n}\n.card:hover {\n  transform: translateY(-5px);\n  box-shadow: 0px 15px 30px rgba(0, 0, 0, 0.4);\n}\n.heading {\n  position: relative;\n  font-size: 18px;\n  font-weight: bold;\n  color: #fff;\n  text-align: center;\n  padding: 10px;\n  margin: 0;\n  z-index: 6;\n  transition: transform 0.3s ease;\n  font-family: "Poppins", sans-serif;\n}\n.heading,\n.icons {\n  position: relative;\n  transition: transform 0.5s ease-out;\n}\n.image:hover + .card .heading,\n.image:hover + .card .icons {\n  transform: translateY(-15px);\n}\n.icons a {\n  opacity: 0.7;\n  transition: opacity 0.3s ea', colors: '#4b0082,#ffd700,#800080,#00bfff,#875c98,#32cd32,#ff8c00,#fff,#8a2be2,#ff1493', radii: '50%,20px,20px 20px 0 0', shadows: '0px 10px 20px rgba(0, 0, 0, 0.2),0px 15px 30px rgba(0, 0, 0, 0.4),0 0 100px 40