ore {\n  content: \'\';\n  width: 5rem;\n  height: 5rem;\n  border-radius: 100%;\n  position: absolute;\n  top: 0%;\n  left: 0%;\n  background-color: rgb(163, 159, 198);\n  filter: blur(50px) saturate(5);\n  animation: top 8s infinite ease-in-out;\n}\n\n.card::after {\n  content: \'\';\n  width: 5rem;\n  height: 5rem;\n  border-radius: 100%;\n  position: absolute;\n  bottom: 0%;\n  left: 85%;\n  background-color: rgba(163, 159, 198);\n  filter: blur(50px) saturate(5);\n  animation: bottom 8s infinite ease-in-out;\n}\n\n.card .heading {\n  display: flex;\n  flex-direction: column;\n  font-size: 1.3rem;\n  justify-content: center;\n  align-items: center;\n  user-select: none;\n}\n\n.card .heading span {\n  font-size: 3rem;\n  text-transform: uppercase;\n  letter-spacing: 0.4rem;\n  text-shadow: 0 0 19px rgba(255, 255, 255, 0.695), 0 0 20px rgba(255, 255, 255, 0.568), 0 0 30px #1a0e34, 0 0 40px #721faad9, 0 0 50px #2c26729f, 0 0 60px #180e5c5c, 0 0 70px #101d3548;\n  border-radius: 70%;\n  padding: 0.5rem;\n  position: relative;\n}\n\n.card .content {\n  display: flex;\n}\n\n.card .content .item {\n  padding: 0.7rem;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  gap: 5px;\n  opacity: 70%;\n  transition: 0.5s ease;\n  margin: 0 0.5rem;\n  position: relative;\n  border-radius: 2rem;\n}\n\n.item::before {\n  content: \'\';\n  width: 1.5rem;\n  height: 1.5rem;\n  border-radius: 100%;\n  background-color: rgba(255, 255, 255, 0.466);\n  position: absolute;\n  filter: blur(20px);\n  top: 0%;\n}\n\nbutton {\n  background-color: transparent;\n  font-size: 1.3rem;\n  padding: 1rem;\n  color: rgba(255, 255, 255, 0.948);\n  transition: 0.5s ease-in-out;\n  cursor: pointer;\n  position: relative;\n  border: none;\n  border-radius: 2rem;\n  box-shadow: 0px 10px 70p', colors: '#721faad9,#1a0e34,#2c26729f,#101d3548,#180e5c5c', radii: '1rem,100%,70%,2rem', shadows: '0px 10px 70px 33px rgba(0,0,0,0.1)', techniques: 'glassmorphism,3d-transform,glow-shadow,text-shadow,g