const GalaxyComp(id: '0xnihilism_wise-lizard-57', cat: 'Inputs', author: '0xnihilism', tags: '3d,input,username,brutalism,raw', html: '<div class="input__container">\n  <div class="shadow__input"></div>\n  <button class="input__button__shadow">\n    <svg\n      xmlns="http://www.w3.org/2000/svg"\n      viewBox="0 0 24 24"\n      fill="#000000"\n      width="20px"\n      height="20px"\n    >\n      <path d="M0 0h24v24H0z" fill="none"></path>\n      <path\n        d="M12 12c2.21 0 4-1.79 4-4s-1.79-4-4-4-4 1.79-4 4 1.79 4 4 4zm0 2c-2.67 0-8 1.34-8 4v2h16v-2c0-2.66-5.33-4-8-4z"\n      ></path>\n    </svg>\n  </button>\n  <input\n    type="text"\n    name="username"\n    class="input__search"\n    placeholder="Enter username"\n  />\n</div>', css: '\n/* From Uiverse.io by 0xnihilism  - Tags: 3d, input, username, brutalism, raw */\n.input__container {\n  position: relative;\n  background: #f0f0f0;\n  padding: 20px;\n  display: flex;\n  justify-content: flex-start;\n  align-items: center;\n  gap: 15px;\n  border: 4px solid #000;\n  max-width: 350px;\n  transition: all 400ms cubic-bezier(0.23, 1, 0.32, 1);\n  transform-style: preserve-3d;\n  transform: rotateX(10deg) rotateY(-10deg);\n  perspective: 1000px;\n  box-shadow: 10px 10px 0 #000;\n}\n\n.input__container:hover {\n  transform: rotateX(5deg) rotateY(1 deg) scale(1.05);\n  box-shadow: 25px 25px 0 -5px #e9b50b, 25px 25px 0 0 #000;\n}\n\n.shadow__input {\n  content: "";\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  left: 0;\n  bottom: 0;\n  z-index: -1;\n  transform: translateZ(-50px);\n  background: linear-gradient(\n    45deg,\n    rgba(255, 107, 107, 0.4) 0%,\n    rgba(255, 107, 107, 0.1) 100%\n  );\n  filter: blur(20px);\n}\n\n.input__button__shadow {\n  cursor: pointer;\n  border: 3px solid #000;\n  background: #e9b50b;\n  transition: all 400ms cubic-bezier(0.23, 1, 0.32, 1);\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  padding: 10px;\n  transform: translateZ(20px);\n  position: relative;\n  z-index: 3;\n  font-weight: bold;\n  text-transform: uppercase;\n}\n\n.input__button__shadow:hover {\n  background: #e9b50b;\n  transform: translateZ(10px) translateX(-5px) translateY(-5px);\n  box-shadow: 5px 5px 0 0 #000;\n}\n\n.input__button__shadow svg {\n  fill: #000;\n  width: 25px;\n  height: 25px;\n}\n\n.input__search {\n  width: 100%;\n  outline: none;\n  border: 3px solid #000;\n  padding: 15px;\n  font-size: 18px;\n  background: #fff;\n  color: #000;\n  transform: translateZ(10px);\n  transition: all 400ms cubic-bezier(0.23, 1, 0.32, 1);\n  position: relative;\n  z-index: 3;\n  font-family: "Roboto", Arial, sans-serif;\n  letter-spacing: -0.5px;\n}\n\n.input__search::placeholder {\n  color: #666;\n  font-weight: bold;\n  text-transform: uppercase;\n}\n\n.input__search:hover,\n.input__search:focus {\n  backg', colors: '#e9b50b,#000,#f0f0f0,#666,#fff', radii: '', shadows: '10px 10px 0 #000,25px 25px 0 -5px #e9b50b, 25px 25px 0 0 #000,5px 5px 0 0 #000', techniques: 'glassmorphism,cubic-bezier,3d-transform,glow-shadow,gradient,perspective,typography-transform,svg-icon,pseudo-elements'),
