background: linear-gradient(135deg, #6e8efb, #a777e3);\n  color: white;\n  padding: 14px 28px;\n  border-radius: 50px;\n  cursor: pointer;\n  transition:\n    background 0.4s cubic-bezier(0.25, 0.8, 0.25, 1),\n    transform 0.3s ease,\n    box-shadow 0.4s ease;\n  box-shadow: 0 8px 15px rgba(0, 0, 0, 0.1);\n  position: relative;\n  z-index: 10;\n  overflow: hidden;\n}\n\n.button-content::before {\n  content: "";\n  position: absolute;\n  inset: 0;\n  border-radius: inherit;\n  background: linear-gradient(\n    135deg,\n    rgba(110, 142, 251, 0.4),\n    rgba(167, 119, 227, 0.4)\n  );\n  filter: blur(15px);\n  opacity: 0;\n  transition: opacity 0.5s ease;\n  z-index: -1;\n}\n\n.button-content::after {\n  content: "";\n  position: absolute;\n  top: -50%;\n  left: -50%;\n  width: 200%;\n  height: 200%;\n  background: radial-gradient(\n    circle,\n    rgba(255, 255, 255, 0.3) 0%,\n    rgba(255, 255, 255, 0) 70%\n  );\n  transform: scale(0);\n  transition: transform 0.6s ease-out;\n  z-index: -1;\n}\n\n.button-content:hover::before {\n  opacity: 1;\n}\n\n.button-content:hover::after {\n  transform: scale(1);\n}\n\n.button-content:hover {\n  background: linear-gradient(135deg, #a777e3, #6e8efb);\n  box-shadow: 0 12px 24px rgba(0, 0, 0, 0.2);\n  transform: translateY(-4px) scale(1.03);\n}\n\n.button-content:active {\n  transform: translateY(-2px) scale(0.98);\n  box-shadow: 0 5px 10px rgba(0, 0, 0, 0.15);\n}\n\n.text {\n  font-size: 18px;\n  font-weight: 600;\n  margin-right: 12px;\n  white-space: nowrap;\n  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.1);\n  transition: letter-spacing 0.3s ease;\n}\n\n.button-content:hover .text {\n  letter-spacing: 1px;\n}\n\n.share-icon {\n  fill: white;\n  transition:\n    transform 0.4s cubic-bezier(0.68, -', colors: '#1877f2,#0077b5,#f1f1f1,#165ed0,#1da1f2,#2a2a2a,#e0e0e0,#a777e3,#f0f0f0,#888', radii: '50px,50%,3px,15px,inherit', shadows: '0 8px 15px rgba(0, 0, 0, 0.1),0 12px 24px rgba(0, 0, 0, 0.2),0 5px 10px rgba(0, 0, 0, 0.15)', techni