const GalaxyComp(id: 'elijahgummer_breezy-liger-35', cat: 'Buttons', author: 'elijahgummer', tags: 'simple,animation,button,moon,sun,space,cool', html: '<div class="galaxy-button">\n  <button class="space-button">\n    <span class="backdrop"></span>\n    <span class="galaxy"></span>\n    <label class="text">Space</label>\n  </button>\n  <div class="bodydrop"></div>\n</div>', css: '\n/* From Uiverse.io by elijahgummer  - Tags: simple, animation, button, moon, sun, space, cool */\n.text {\n  translate: 2% -6%;\n  letter-spacing: 0.01ch;\n  color: hsl(0 0% calc(60% + (var(--active) * 26%)));\n  z-index: 999;\n  padding: 0 34px;\n  font-weight: 600;\n}\n.text::before {\n  content: "";\n  position: absolute;\n  top: -290%;\n  left: 90%;\n  rotate: -45deg;\n  width: 5em;\n  height: 1px;\n  background: linear-gradient(90deg, #ffffff, transparent);\n  animation: 4s shootingStar ease-in-out infinite;\n  transition: 1s ease;\n  z-index: -1;\n  animation-delay: 1s;\n  display: none;\n}\n.text::after {\n  content: "";\n  display: none;\n  position: absolute;\n  top: -290%;\n  left: 10%;\n  rotate: -45deg;\n  width: 5em;\n  height: 1px;\n  background: linear-gradient(90deg, #ffffff, transparent);\n  animation: 7s shootingStar ease-in-out infinite;\n  animation-delay: 3s;\n}\n.space-button:hover .text::before,\n.space-button:hover .text::after {\n  display: block;\n}\n.galaxy::before {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 2px;\n  height: 2px;\n  border-radius: 50%;\n  opacity: 1;\n  box-shadow:\n    140px 20px #fff,\n    425px 20px #fff,\n    70px 120px #fff,\n    20px 130px #fff,\n    110px 80px #fff,\n    280px 80px #fff,\n    250px 350px #fff,\n    280px 230px #fff,\n    220px 190px #fff,\n    450px 100px #fff,\n    380px 80px #fff,\n    520px 50px #fff;\n  z-index: -1;\n  transition: all 1.5s ease-in-out;\n  animation: 1s glowing-stars linear alternate infinite;\n  animation-delay: 0.4s;\n}\n.galaxy::after {\n  content: "";\n  position: abso