s);\n  text-shadow: 0 1px 1px rgba(0, 0, 0, 0.3);\n  border: none;\n  box-shadow: 0 0.5px 0.5px 1px rgba(255, 255, 255, 0.2),\n    0 10px 20px rgba(0, 0, 0, 0.2), 0 4px 5px 0px rgba(0, 0, 0, 0.05);\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  position: relative;\n  transition: all 0.3s ease;\n  min-width: 200px;\n  padding: 20px;\n  height: 68px;\n  font-family: "Galano Grotesque", Poppins, Montserrat, sans-serif;\n  font-style: normal;\n  font-size: 18px;\n  font-weight: 600;\n}\n.button:hover {\n  transform: scale(1.02);\n  box-shadow: 0 0 1px 2px rgba(255, 255, 255, 0.3),\n    0 15px 30px rgba(0, 0, 0, 0.3), 0 10px 3px -3px rgba(0, 0, 0, 0.04);\n}\n.button:active {\n  transform: scale(1);\n  box-shadow: 0 0 1px 2px rgba(255, 255, 255, 0.3),\n    0 10px 3px -3px rgba(0, 0, 0, 0.2);\n}\n.button:after {\n  content: "";\n  position: absolute;\n  inset: 0;\n  border-radius: var(--radius);\n  border: 2.5px solid transparent;\n  background: linear-gradient(var(--neutral-1), var(--neutral-2)) padding-box,\n    linear-gradient(to bottom, rgba(0, 0, 0, 0.1), rgba(0, 0, 0, 0.45))\n      border-box;\n  z-index: 0;\n  transition: all 0.4s ease;\n}\n.button:hover::after {\n  transform: scale(1.05, 1.1);\n  box-shadow: inset 0 -1px 3px 0 rgba(255, 255, 255, 1);\n}\n.button::before {\n  content: "";\n  inset: 7px 6px 6px 6px;\n  position: absolute;\n  background: linear-gradient(to top, var(--neutral-1), var(--neutral-2));\n  border-radius: 30px;\n  filter: blur(0.5px);\n  z-index: 2;\n}\n.state p {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n.state .icon {\n  position: absolute;\n  left: 0;\n  top: 0;\n  bottom: 0;\n  margin: auto;\n  transform: scale(1.25);\n  transition: all 0.3s ease;\n  display: flex;\n  align-', colors: '#ff5569,#e7e7e7,#f7f8f7', radii: '30px,var(--radius),inherit', shadows: '0 0.5px 0.5px 1px rgba(255, 255, 255, 0.2),\n    0 10px 20px rgba(0, 0, 0, 0.2), 0 4px 5px 0px rgba(0, 0, 0, 0.05),0 0 1px 2px rgba(255, 255, 255, 0.3),\n    0 15px 30px rgba(0, 0, 0, 0.3), 0 10px 3px -3px rgba(0, 0, 0, 0.04),0 0 1px 2px rgba(255, 255, 255, 0.3),\n    0 10px 3px -3px rgba(0, 0, 0, 0.2)', techniques: 'glassmorphism,3d-transform,glow-shadow,text-shadow,gradient,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: '0xnihilism_moody-moth-91', cat: 'Cards', author: '0xnihilism', tags: 'simple,card,light', html: '<div class="card">\n  <div class="content">\n    <div class="name">Nihilist</div>\n    <div class="handle">@0xNihilist</div>\n    <div class="title">\n      <span class="emoji">😊</span> Happy<br />\n      Product Designer\n    </div>\n  </div>\n  <div class="dots orange-dots"></div>\n  <div class="dots pink-dots"></div>\n</div>', css: '\n/* From Uiverse.io by 0xnihilism  - Tags: simple, card, light */\n.card-container {\n  margin: 0;\n  padding: 0;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  font-family: Arial, sans-serif;\n  background: linear-gradient(135deg, #ffa07a 25%, transparent 25%) -50px 0,\n    linear-gradient(225deg, #ffa07a 25%, transparent 25%) -50px 0,\n    linear-gradient(315deg, #ffa07a 25%, transparent 25%),\n    linear-gradient(45deg, #ffa07a 25%, transparent 25%);\n  background-size: 100px 100px;\n  background-color: #ffffff;\n  perspective: 1000px;\n}\n\n.card {\n  width: 400px;\n  background-color: rgba(223, 216, 179, 0.9);\n  border-radius: 20px;\n  position: relative;\n  border: 3px solid #000;\n  box-shadow: 10px 10px 0 rgba(0, 0, 0, 0.1);\n  overflow: hidden;\n  transition: transform 0.5s cubic-bezier(0.23, 1, 0.32, 1),\n    box-shadow 0.5s cubic-bezier(0.23, 1, 0.32, 1);\n  transform-style: preserve-3d;\n}\n\n.card:hover {\n  transform: translateZ(20px) rotateX(5deg) rotateY(-5deg);\n  box-shadow: 20px 20px 0 rgba(0, 0, 0, 0.2);\n}\n\n.card .content {\n  padding: 30px;\n  padding-top: 60px;\n}\n\n.card .name {\n  font-size: 36px;\n  font-weight: bold;\n  margin-bottom: 20px;\n}\n\n.card .handle {\n  position: absolute;\n  top: 0;\n  right: 20px;\n  background-color: #f4c430;\n  padding: 10px 20px;\n  border-radius: 0 0 15px 15px;\n  border: 2px solid #000;\n  border-top: none;\n  font-weight: bold;\n}\n\n.card .title {\n  font-size: 18px;\n}\n\n.card .emoji {\n  font-size: 24px;\n}\n\n.card::before {\n  content: "";\n  position: absolute;\n  top: -50%;\n  left: -50%;\n  width: 200%;\n  height: 200%;\n  background: linear-gradient(\n    to bottom right,\n    rgba(255, 255, 255, 0.3),\n    rgba(255, 255, 255, 0) 80%\n  );\n  transform: rotate(-30deg);\n  pointer-events: none;\n}\n\n.card .name,\n.card .title {\n  transition: transform 0.3s ease-out, opacity 0.3s ease-out;\n}\n\n.card:hover .name {\n  transform: translateZ(30px);\n}\n\n.card:hover .title {\n  transform: translateZ(20px);\n}\n\n.card .handle {\n  transition: transform 0.3s ea', colors: '#ffa07a,#000,#f4c430,#ffdb58,#ffffff', radii: '0 0 15px 15px,20px', shadows: '10px 10px 0 rgba(0, 0, 0, 0.1),20px 20px 0 rgba(0, 0, 0, 0.2)', techniques: 'cubic-bezier,3d-transform,glow-shadow,gradient,animation,clip-path,perspective,pseudo-elements'),
