x),\n    linear-gradient(to bottom, var(--color) 1px, transparent 1px);\n  background-size: 0.5rem 0.5rem;\n  box-shadow: inset 0 0 40px 20px rgb(0, 0, 0);\n  flex-direction: column;\n  align-content: center;\n  justify-content: center;\n  gap: 1rem;\n}\n\n.border-light {\n  position: relative;\n  display: flex;\n  border-radius: 8px;\n  background: transparent;\n}\n\n.border-light::before {\n  content: "";\n  position: absolute;\n  width: 40px;\n  height: 20px;\n  border-radius: 50%;\n  top: 0%;\n  left: 0%;\n  box-shadow: 0px 0px 30px 5px hsl(310, 90%, 65%, 0.5),\n    0px 0px 30px 30px hsla(310, 91%, 25%, 0.5);\n  animation: border-light 16s linear infinite;\n}\n\n.border-light::after {\n  content: "";\n  position: absolute;\n  top: 0%;\n  left: 0%;\n  width: 40px;\n  height: 20px;\n  border-radius: 50%;\n  box-shadow: 0px 0px 30px 5px hsl(247, 90%, 65%, 0.5),\n    0px 0px 30px 30px hsl(247, 90%, 25%, 0.5);\n  animation: border-light 16s linear infinite -8s;\n}\n\n@keyframes border-light {\n  0% {\n    top: 0%;\n    left: 0%;\n    animation-timing-function: cubic-bezier(0.19, 0.64, 0.85, 0.36);\n  }\n  48% {\n    top: 0%;\n    left: 80%;\n  }\n  50% {\n    top: 50%;\n    left: 80%;\n    animation-timing-function: cubic-bezier(0.19, 0.64, 0.85, 0.36);\n  }\n  98% {\n    top: 50%;\n    left: 0%;\n  }\n  100% {\n    top: 0%;\n    left: 0%;\n  }\n}\n\n.input-content {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  background: rgb(0, 0, 0);\n  padding: 5px 5px 5px 10px;\n  align-items: center;\n  justify-content: center;\n  justify-items: center;\n  position: relative;\n  border-radius: 8px;\n  overflow: hidden;\n}\n\n.input-content::before {\n  content: "";\n  position: absolute;\n  height: 300px;\n  aspect-ratio: 1/1;\n  backgrou', colors: '', radii: '50%,20% 20%,8px,80% 80%', shadows: 'inset 0 0 40px 20px rgb(0, 0, 0),0px 0px 30px 5px hsl(310, 90%, 65%, 0.5),\n    0px 0px 30px 30px hsla(310, 91%, 25%, 0.5),0px 0px 30px 5px hsl(247, 90%, 65%, 0.5),\n 