rection: column;\n  position: absolute;\n  width: 300px;\n  height: 200px;\n  justify-content: space-between;\n  align-items: center;\n  padding: 0.5rem;\n  top: 1.5rem;\n}\n\nstrong {\n  background-size: 300% 300%;\n  background-clip: text;\n  -webkit-background-clip: text;\n  color: transparent;\n  background-image: linear-gradient(137.48deg, #ffdb3b 10%,#FE53BB 45%, #8F51EA 67%, #0044ff 87%);\n  font-family: \'Gill Sans\', \'Gill Sans MT\', Calibri, \'Trebuchet MS\', sans-serif;\n  text-shadow: 0 0 5px rgba(255, 255, 255, 0.438);\n  animation: gradient 5s ease infinite;\n}\n\n.notification:hover .text {\n  opacity: 1;\n  transition: 1s;\n  transition-delay: 3s;\n  transform: translateY(-1.5rem);\n}\n\n.notification:hover .crystal {\n  animation: pulse_crystal 1s ease;\n  transition: 1s;\n  transform: scale(1.3);\n  box-shadow: 0 0 5px rgb(255, 255, 255);\n  background: conic-gradient(#3fb2ff 0%, #261caf 45%, #44d2eb 50%, #fdfdfd 100%);\n  clip-path: polygon(50% 0, 84% 30%, 84% 70%, 50% 100%, 15% 70%, 15% 30%);\n}\n\n.notification:hover .crystal-border {\n  transition: 1s;\n  clip-path: polygon(50% 0, 90% 30%, 90% 70%, 50% 100%, 10% 70%, 10% 30%);\n}\n\n.crystal-border {\n  z-index: 3;\n  display: flex;\n  position: absolute;\n  width: 45px;\n  height: 45px;\n  background: #000000;\n  clip-path: polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%);\n}\n\n.crystal {\n  inset: 12px;\n  position: absolute;\n  width: 20px;\n  height: 20px;\n  background: conic-gradient(#ca22b9 0%, #792e83 45%, #ff26e9 50%, #ffffff 100%);\n  clip-path: polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%);\n  transition: all 1s ease;\n}\n\n.line-center-border {\n  z-index: 2;\n  display: flex;\n  position: absolute;\n  width: 1', colors: '#44d2eb,#796f1c,#c7b82f,#ca22b9,#b9a80f,#8f51ea,#0044ff,#fe53bb,#fdfdfd,#000000', radii: '50%,0.3rem', shadows: '0 0 5px rgb(255, 255, 255)', techniques: '3d-transform,glow-shadow,text-shadow,gradient,animation,filter-effect,clip-path,svg-icon'),
const GalaxyComp(id: '0xnihilism_pretty-fireant-33', cat: 'Buttons', author: '0xnihilism', tags: 'button,button hover effect,brutalism,minimalism,openai', html: '<div class="button-container">\n  <a href="/" class="brutalist-button openai button-1">\n    <div class="openai-logo">\n      <svg\n        xmlns="http://www.w3.org/2000/svg"\n        viewBox="0 0 24 24"\n        class="openai-icon"\n      >\n        <path\n          fill="#10A37F"\n          d="M22.2819 9.8211a5.9847 5.9847 0 0 0-.5157-4.9108 6.0462 6.0462 0 0 0-6.5098-2.9A6.0651 6.0651 0 0 0 4.9807 4.1818a5.9847 5.9847 0 0 0-3.9977 2.9 6.0462 6.0462 0 0 0 .7427 7.0966 5.98 5.98 0 0 0 .511 4.9107 6.051 6.051 0 0 0 6.5146 2.9001A5.9847 5.9847 0 0 0 13.2599 24a6.0557 6.0557 0 0 0 5.7718-4.2058 5.9894 5.9894 0 0 0 3.9977-2.9001 6.0557 6.0557 0 0 0-.7475-7.0729zm-9.022 12.6081a4.4755 4.4755 0 0 1-2.8764-1.0408l.1419-.0804 4.7783-2.7582a.7948.7948 0 0 0 .3927-.6813v-6.7369l2.02 1.1686a.071.071 0 0 1 .038.052v5.5826a4.504 4.504 0 0 1-4.4945 4.4944zm-9.6607-4.1254a4.4708 4.4708 0 0 1-.5346-3.0137l.142.0852 4.783 2.7582a.7712.7712 0 0 0 .7806 0l5.8428-3.3685v2.3324a.0804.0804 0 0 1-.0332.0615L9.74 19.9502a4.4992 4.4992 0 0 1-6.1408-1.6464zM2.3408 7.8956a4.485 4.485 0 0 1 2.3655-1.9728V11.6a.7664.7664 0 0 0 .3879.6765l5.8144 3.3543-2.0201 1.1685a.0757.0757 0 0 1-.071 0l-4.8303-2.7865A4.504 4.504 0 0 1 2.3408 7.8956zm16.0993 3.8558L12.5907 8.3829 14.6108 7.2144a.0757.0757 0 0 1 .071 0l4.8303 2.7913a4.4944 4.4944 0 0 1-.6765 8.1042v-5.6772a.79.79 0 0 0-.3927-.6813zm2.0107-3.0231l-.142-.0852-4.7735-2.7818a.7759.7759 0 0 0-.7854 0L9.409 9.2297V6.8974a.0662.0662 0 0 1 .0284-.0615l4.8303-2.7866a4.49', css: '\n/* From Uiverse.io by 0xnihilism  - Tags: button, button hover effect , brutalism, minimalism, openai */\n.button-container {\n  display: flex;\n  justify-content: center;\n  gap: 20px;\n}\n\n/* Common styles for both buttons */\n.brutalist-button {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  width: 142px;\n  height: 142px;\n  color: #e5dede;\n  font-weight: bold;\n  text-decoration: none;\n  position: relative;\n  cursor: pointer;\n  overflow: hidden;\n  transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);\n}\n\n/* Styles for the first button */\n.button-1 {\n  background-color: #063525;\n  border: 3px solid #42c498;\n  border-radius: 12px;\n  box-shadow: 4px 4px 1px #000000;\n}\n\n.button-1:hover {\n  background-color: #1a5c46;\n  border-color: #030504;\n  transform: translate(-6px, -6px) rotate(1deg);\n  box-shadow: 10px 10px 0 #000000, 15px 15px 20px rgba(64, 164, 122, 0.2);\n}\n\n.button-1::before,\n.button-1::after {\n  content: "";\n  position: absolute;\n  top: 0;\n  width: 100%;\n  height: 100%;\n  background: linear-gradient(\n    90deg,\n    transparent,\n    rgba(255, 255, 255, 0.1),\n    transparent\n  );\n  transition: 0.6s;\n}\n\n.button-1::before {\n  left: -100%;\n}\n.button-1::after {\n  left: 100%;\n}\n\n.button-1:hover::before {\n  animation: swipeRight 1.5s infinite;\n}\n.button-1:hover::after {\n  animation: swipeLeft 1.5s infinite;\n}\n\n@keyframes swipeRight {\n  100% {\n    transform: translateX(200%) skew(-45deg);\n  }\n}\n\n@keyframes swipeLeft {\n  100% {\n    transform: translateX(-200%) skew(-45deg);\n  }\n}\n\n/* Hover effects */\n.brutalist-button:hover .openai-logo {\n  transform: translateY(-10px);\n}\n\n.brutalist-button:hover .openai-icon {\n  width: 40px;\n  height: 40px;\n}\n\n.bruta.brutalist-button:hover .openai-text {\n  opacity: 1;\n  max-height: 60px;\n  margin-top: 8px;\n}\n\n/* Styles for the OpenAI logo and text */\n.openai-logo {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  transition: all 0.3s cubic-bezier(0', colors: '#e5dede,#1a5c46,#063525,#000000,#030504,#42c498', radii: '12px', shadows: '4px 4px 1px #000000,10px 10px 0 #000000, 15px 15px 20px rgba(64, 164, 122, 0.2)', techniques: 'cubic-bezier,3d-transform,text-shadow,gradient,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'EddyBel_brave-horse-21', cat: 'Buttons', author: 'EddyBel', tags: 'gradient,button,click', html: '<button class="button__click">\n  <div class="button__click__background"></div>\n  Click me\n</button>', css: '\n/* From Uiverse.io by EddyBel - Tags: gradient, button, click */\n.button__click {\n  border: none;\n  cursor: pointer;\n  position: relative;\n  overflow: hidden;\n  text-transform: uppercase;\n  transition: box-shadow 400ms;\n  padding: 0.7em 1.7em;\n  font-size: 1rem;\n  border-radius: 20px;\n  color: rgb(0, 0, 0, 0.75);\n  background: transparent;\n  transform: scale(1.1) perspective(500px) rotateX(15deg) rotateY(-10deg);\n}\n\n.button__click:hover {\n  animation: button__click__animation 5.5s infinite both;\n}\n\n.button__click__background {\n  transition: transform 1.5s;\n  z-index: -2;\n  position: absolute;\n  left: 0;\n  top: 0;\n  width: 200%;\n  height: 200%;\n  animation: button__click__background 10s infinite;\n  background-color: #99fff8;\n  background-image: radial-gradient(at 89% 76%, hsla(13,63%,73%,1) 0px, transparent 50%),\n  radial-gradient(at 69% 38%, hsla(217,85%,71%,1) 0px, transparent 50%),\n  radial-gradient(at 12% 8%, hsla(214,70%,64%,1) 0px, transparent 50%),\n  radial-gradient(at 53% 10%, hsla(339,64%,65%,1) 0px, transparent 50%),\n  radial-gradient(at 5% 67%, hsla(212,74%,70%,1) 0px, transparent 50%);\n}\n\n.button__click::before {\n  content: "";\n  width: 100%;\n  height: 100%;\n  position: absolute;\n  left: 0;\n  top: 0;\n  z-index: -1;\n  background: rgba(255, 255, 255, 0.295);\n}\n\n.button__click:focus {\n  box-shadow: 0px 0px 0px 2px #000;\n}\n\n@keyframes button__click__animation {\n  0%, 100% {\n    transform: scale(1.1) perspective(500px) rotateX(15deg) rotateY(-10deg);\n  }\n\n  50% {\n    transform: scale(0.9) perspective(500px) rotateX(-15deg) rotateY(15deg);\n  }\n}\n\n@keyframes button__click__background {\n  0%, 100% {\n    transform: translateX(0%);\n  }\n\n  25% {\n    transform: translateX(-50%);\n  }\n\n  50% {\n    transform: translateX(-50%) translateY(-50%);\n  }\n\n  75% {\n    transform: translateX(0%) translateY(-50%);\n  }\n}\n', colors: '#99fff8,#000', radii: '20px', shadows: '0px 0px 0px 2px #000', techniques: '3d-transform,glow-shadow,gradient,animation,perspective,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'flxderdev_fast-treefrog-50', cat: 'Buttons', author: 'flxderdev', tags: 'gradient,button,modern,futuristic', html: '<button class="button">HOVER ME</button>', css: '\n/* From Uiverse.io by flxderdev  - Tags: gradient, button, modern, futuristic */\n.button {\n  height: 55px;\n  width: 175px;\n  margin: auto;\n  align-items: center;\n  border-radius: 50px;\n  border: none;\n  text-align: center;\n  color: transparent;\n  text-shadow: 0 0 0 rgb(255, 255, 255);\n  font-size: 17px;\n  font-weight: 500;\n  text-transform: uppercase;\n  text-decoration: none;\n  box-sizing: border-box;\n  cursor: pointer;\n  transition: transform 50ms ease;\n  background: linear-gradient(90deg, #5f03f4, #f441a5, #b81fff, #5f03f4);\n  background-size: 400%;\n  display: block;\n  margin-right: auto;\n  margin-left: auto;\n  font-family: "Montserrat", sans-serif;\n}\n\n.button:hover {\n  -webkit-box-shadow: 0px 0px 15px 0px rgba(155, 0, 194, 0.9);\n  -moz-box-shadow: 0px 0px 15px 0px rgba(155, 0, 194, 0.9);\n  box-shadow: 0px 0px 15px 0px rgba(155, 0, 194, 0.9);\n  animation: animate 8s ease infinite;\n  transition: box-shadow, 0.4s;\n  border: none;\n  font-size: 19px;\n  transform: scale(1.05, 1.05);\n  background: linear-gradient(90deg, #5f03f4, #f441a5, #b81fff, #5f03f4);\n  background-size: 400%;\n}\n\n.button:hover:before {\n  filter: blur(20px);\n  opacity: 1;\n  animation: animate 8s linear infinite;\n}\n\n@keyframes animate {\n  0% {\n    background-position: 0%;\n  }\n\n  100% {\n    background-position: 400%;\n  }\n}\n\n', colors: '#f441a5,#5f03f4,#b81fff', radii: '50px', shadows: '0px 0px 15px 0px rgba(155, 0, 194, 0.9),0px 0px 15px 0px rgba(155, 0, 194, 0.9),0px 0px 15px 0px rgba(155, 0, 194, 0.9)', techniques: 'glassmorphism,3d-transform,glow-shadow,text-shadow,gradient,animation,typography-transform'),
const GalaxyComp(id: 'jdm-encompass_clever-lizard-42', cat: 'Buttons', author: 'jdm-encompass', tags: 'button,social media,animated,follow', html: '<button class="button">\n  <a href="https://www.facebook.com/JDmOwO" class="no-link-style">\n    <svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" version="1.0" x="0px" y="0px" width="50" height="50" viewBox="0 0 50 50" style="null" class="icon icons8-Facebook-Filled">\n      <path d="M40,0H10C4.486,0,0,4.486,0,10v30c0,5.514,4.486,10,10,10h30c5.514,0,10-4.486,10-10V10C50,4.486,45.514,0,40,0z M39,17h-3 c-2.145,0-3,0.504-3,2v3h6l-1,6h-5v20h-7V28h-3v-6h3v-3c0-4.677,1.581-8,7-8c2.902,0,6,1,6,1V17z" fill="#ffffff"></path>\n    </svg>\n  </a>\n</button><br>', css: '\n/* From Uiverse.io by jdm-encompass - Tags: button, social media, animated, follow */\n.button {\n  background-color: #1877F2;\n  border: none;\n  border-radius: 50%;\n  box-shadow: 0 0 20px 0 rgba(0, 0, 0, 0.5);\n  animation: sway 2s infinite alternate;\n  width: 70px;\n  height: 70px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  perspective: 500px;\n  transition: transform 0.5s, box-shadow 0.5s;\n}\n\n.button:hover {\n  transform: rotate(-360deg);\n  box-shadow: 0 0 20px 0 rgba(0, 0, 255, 0.5);\n}\n\n@keyframes grow {\n  0% {\n    transform: scale(1);\n  }\n\n  100% {\n    transform: scale(10);\n  }\n}\n\n@keyframes glow {\n  0% {\n    text-shadow: gold 1px 1px 1px;\n  }\n\n  100% {\n    text-shadow: gold 0 0 10px gold;\n  }\n}\n\n.icon {\n  filter: drop-shadow(0 2px 4px rgba(0, 0, 0, 0.6));\n  transition: transform 0.5s;\n}\n\n.icon:hover {\n  transform: scale(1.5);\n  filter: drop-shadow(1px 2px 4px rgba(0,0,0,0.9))\n}\n\n.follow-text {\n  color: white;\n  position: relative;\n  top: 3em;\n  left: -4em;\n  transition: transform 0.5s;\n}\n\n.follow-text:hover {\n  transform: scale(1.2);\n  color: rgba(31,81,255,100);\n  filter: drop-shadow(2px 2px 4px rgba(31,81,255,2.0))\n}\n\n', colors: '#1877f2', radii: '50%', shadows: '0 0 20px 0 rgba(0, 0, 0, 0.5),0 0 20px 0 rgba(0, 0, 255, 0.5)', techniques: '3d-transform,glow-shadow,text-shadow,animation,filter-effect,perspective,svg-icon'),
const GalaxyComp(id: 'John-CFO_calm-kangaroo-15', cat: 'Buttons', author: 'John-CFO', tags: 'simple,button,hover,hover effect', html: '<button class="BTN-style">\n  <span class="BTN-text">Hover me</span>\n</button>', css: '\n/* From Uiverse.io by John-CFO  - Tags: simple, button, hover, hover effect */\n.BTN-style {\n  position: relative;\n  width: 12em;\n  height: 3.8em;\n  border-width: 2px;\n  border-radius: 6px;\n  border-color: #ffff;\n  display: block;\n  padding: 8px;\n  background: linear-gradient(to left, #c0c0c0, #dcdcdc);\n  color: #ffffff;\n  line-height: 1.25rem;\n  box-shadow: 5px 5px 5px rgba(0, 0, 0, 0.5);\n  overflow: hidden;\n}\n\n.BTN-text {\n  font-weight: 500;\n  font-size: 0.975rem;\n  text-shadow: 1px 1px 1px rgba(0, 0, 0, 0.9);\n  text-transform: uppercase;\n}\n\n.BTN-style:hover {\n  -webkit-transition: all 0.2s ease-out;\n  -moz-transition: all 0.2s ease-out;\n  transition: all 0.2s ease-out;\n\n  cursor: pointer;\n}\n\n.BTN-style:hover::before {\n  -webkit-animation: sh02 0.5s 0s linear;\n  -moz-animation: sh02 0.5s 0s linear;\n  animation: sh02 0.5s 0s linear;\n}\n\n.BTN-style::before {\n  content: "";\n  display: block;\n  width: 0px;\n  height: 85%;\n  position: absolute;\n  top: 50%;\n  left: 0%;\n  opacity: 0;\n  background: #fff;\n  box-shadow: 0 0 50px 30px #fff;\n  -webkit-transform: skewX(-20deg);\n  -moz-transform: skewX(-20deg);\n  -ms-transform: skewX(-20deg);\n  -o-transform: skewX(-20deg);\n  transform: skewX(-20deg);\n}\n\n@keyframes sh02 {\n  from {\n    opacity: 0;\n    left: 0%;\n  }\n\n  50% {\n    opacity: 1;\n  }\n\n  to {\n    opacity: 0;\n    left: 100%;\n  }\n}\n\n', colors: '#dcdcdc,#c0c0c0,#ffff,#ffffff,#fff', radii: '6px', shadows: '5px 5px 5px rgba(0, 0, 0, 0.5),0 0 50px 30px #fff', techniques: '3d-transform,glow-shadow,text-shadow,gradient,animation,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'kennyotsu_witty-bullfrog-54', cat: 'Buttons', author: 'kennyotsu', tags: 'complex,3d,action,button,spaceship', html: '<div class="container noselect">\n  \n  <label for="checkbox" id="clickHandler"></label>\n  <input type="checkbox" id="checkbox">\n\n  <button id="button">\n    <p id="to-launch">let\'s launch!</p>\n    <p id="tag">by kennyotsu &lt;3</p>\n    <div id="platform"></div>\n  <div class="caution">\n    <div id="caution-left">LAUNCH ZONE</div>\n    <div id="caution-right">LAUNCH ZONE</div>\n  </div>\n  </button>\n  \n  <p id="to-hover">hover me</p>\n  <div id="shuttle-wrapper">\n    \n    <div id="shadow"></div>\n    <svg viewBox="0 0 230.24 542.46" xmlns:xlink="http://www.w3.org/1999/xlink" xmlns="http://www.w3.org/2000/svg" id="b"><defs><linearGradient gradientUnits="userSpaceOnUse" gradientTransform="translate(160.35 -471.85) rotate(-7.06) scale(1.56 1.68)" y2="549.77" x2="-104.11" y1="545.09" x1="-130.63" id="d"><stop stop-color="#c6c6c6" offset="0"></stop><stop stop-color="#b1b1b1" offset="0"></stop><stop stop-color="#858585" offset=".02"></stop><stop stop-color="#606060" offset=".04"></stop><stop stop-color="#424242" offset=".05"></stop><stop stop-color="#2a2a2a" offset=".07"></stop><stop stop-color="#191919" offset=".09"></stop><stop stop-color="#101010" offset=".1"></stop><stop stop-color="#0d0d0d" offset=".13"></stop><stop stop-color="#454545" offset=".31"></stop><stop stop-color="#4c4c4c" offset=".33"></stop><stop stop-color="#484848" offset=".35"></stop><stop stop-color="#2b2c2b" offset=".52"></stop><stop stop-color="#171817" offset=".68"></stop><stop stop-color="#0b0c0b" offset=".84"></sto', css: '\n/* From Uiverse.io by kennyotsu - Tags: complex, 3d, action, button, spaceship */\n/* overengeneered pure css action button */\n/* UIVERSE CSS Challenge entry */\n/* by kennyotsu <3 */\n\n/* container wraps everything together, applies general styles and does nothing else*/\n.container {\n  position: relative;\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-orient: vertical;\n  -webkit-box-direction: normal;\n  -ms-flex-direction: column;\n  flex-direction: column;\n  -webkit-box-pack: center;\n  -ms-flex-pack: center;\n  justify-content: center;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n  width: 200px;\n  height: 200px;\n  color: rgb(131, 131, 131);\n  -webkit-transition: 400ms ease-in-out;\n  transition: 400ms ease-in-out;\n  transform: translateY(20px);\n}\n  \n  /* clickHandler, as the name suggests, handles clicks. \n	 Its a label for invisible checkbox, positioned absolutely and taking whole container space.\n	 Comes with insane z-index. Stays above .container\n	 When clicked, will change input state to checked */\n#shuttle-wrapper {\n  position: absolute;\n  opacity: 0;\n  -webkit-transition: 200ms ease-in;\n  transition: 200ms ease-in;\n  z-index: 200;\n}\n\n#b {\n  width: 80px;\n  height: auto;\n  z-index: 200;\n}\n\n#shadow {\n  position: absolute;\n  width: 100px;\n  height: 80px;\n  -webkit-transform: rotateX(45deg) rotateZ(45deg);\n  transform: rotateX(45deg) rotateZ(45deg);\n  bottom: -10px;\n  z-index: -1;\n  background: radial-gradient(rgba(0, 0, 0, 0.382) 0%, rgba(0, 0, 0, 0) 70%);\n}\n\n#clickHandler {\n  display: block;\n  position: absolute;\n  inset: 0;\n  z-index: 999;\n}\n\n#clickHandler:hover {\n  cursor: pointer;\n}\n\n.container:hover #shuttle-wrapper {\n  opacity: 1;\n  -webkit-transform: translateY(-100px) translateZ(140px);\n  -ms-transform: translateY(-100px) translateZ(140px);\n  transform: translateY(-100px) translateZ(140px);\n  -webkit-transition: 400ms ease-in-out;\n  transition: 400ms ease-in-out;\n}\n\n#checkbox {\n	/* comment out t', colors: '#b2b2b2,#ffffff,#f5f5ff,#ececec', radii: '16px,1.8rem', shadows: '2px 2px 0 2px #b2b2b2, -1px 0 28px 0 rgba(255, 250, 225, 0.512),\n  28px 28px 28px 0 rgba(28, 27, 88, 0.315),2px 2px 0 2px #b2b2b2, -1px 0 28px 0 rgba(255, 250, 225, 0.512),\n  28px 28px 28px 0 rgba(28, 27, 88, 0.315),5px 5px 8px 0 rgba(28, 27, 88, 0.315)', techniques: '3d-transform,glow-shadow,gradient,animation,filter-effect,checkbox-input,svg-icon'),
const GalaxyComp(id: 'mRcOol7_rotten-yak-63', cat: 'Buttons', author: 'mRcOol7', tags: 'button,#button,button hover effect', html: '<button\n  aria-label="Send Message"\n  class="button relative overflow-hidden flex items-center px-6 py-3 bg-gradient-to-r from-blue-500 to-purple-600 border border-transparent rounded-full shadow-lg text-white cursor-pointer transition-all duration-300 ease-in-out transform hover:scale-105 focus:outline-none focus:ring-4 focus:ring-blue-300 focus:ring-opacity-50 focus:scale-105 active:scale-95"\n>\n  <div class="ripple"></div>\n  <svg\n    class="relative w-12 h-12 mr-2 z-10 transition-transform duration-300 ease-in-out transform hover:rotate-12 shadow-sm transition-colors duration-300 ease-in-out"\n    preserveAspectRatio="xMidYMid meet"\n    viewBox="0 0 36.000000 75.000000"\n    height="80pt"\n    width="80pt"\n    xmlns="http://www.w3.org/2000/svg"\n    version="1.0"\n  >\n    <g\n      stroke="none"\n      fill="#ffffff"\n      transform="translate(0.000000,75.000000) scale(0.100000,-0.100000)"\n    >\n      <path\n        d="M188 481 c-42 -15 -84 -34 -93 -41 -27 -22 -14 -53 31 -74 30 -14 46  -30 60 -60 23 -50 55 -59 78 -24 24 36 56 137 56 174 0 23 -6 37 -19 44 -25 13 -23 13 -113 -19z m110 -20 c4 -28 -37 -158 -55 -173 -17 -14 -39 4 -48 39 -4 19 0 35 14 54 30 41 26 47 -9 14 -30 -29 -30 -29 -65 -12 -58 28 -47 42 65 81 41 14 80 24 85 22 6 -1 11 -13 13 -25z"\n      ></path>\n    </g>\n  </svg>\n  <svg\n    class="relative w-8 h-8 mr-2 z-10 transition-transform duration-300 ease-in-out transform hover:rotate-12 shadow-sm transition-colors duration-300 ease-in-out"\n    preserveAspectRatio="xMidYMid ', css: '\n/* From Uiverse.io by mRcOol7  - Tags: button, #button, button hover effect  */\n.button {\n  position: relative;\n  display: flex;\n  align-items: center;\n  padding: 0.75rem 1.5rem;\n  background: linear-gradient(to right, #3b82f6, #9333ea);\n  border: none;\n  border-radius: 9999px;\n  box-shadow: 0 4px 14px rgba(0, 0, 0, 0.25);\n  color: white;\n  cursor: pointer;\n  overflow: hidden;\n  transition: all 0.3s ease-in-out;\n}\n\n.button:hover {\n  transform: scale(1.05);\n  box-shadow: 0 8px 20px rgba(0, 0, 0, 0.35);\n}\n\n.button:active {\n  transform: scale(0.95);\n}\n\n.button:focus {\n  outline: none;\n  box-shadow: 0 0 0 4px rgba(59, 130, 246, 0.5);\n}\n\n.button svg {\n  width: 3rem;\n  height: 3rem;\n  margin-right: 0.5rem;\n  transition: transform 0.3s ease-in-out, filter 0.3s ease-in-out;\n}\n\n.button:hover svg {\n  transform: rotate(20deg) scale(1.1);\n  filter: drop-shadow(0 0 10px #ffd700);\n}\n\n.button span {\n  font-size: 1.125rem;\n  font-weight: 600;\n  transition: transform 0.3s ease-in-out, color 0.3s ease-in-out,\n    text-shadow 0.3s ease-in-out;\n}\n\n.button:hover span {\n  color: #ffd700;\n  text-shadow: 0 0 10px #ffd700;\n}\n\n.button .text-md {\n  font-size: 1rem;\n  margin-left: 0.5rem;\n  transition: transform 0.3s ease-in-out, color 0.3s ease-in-out,\n    text-shadow 0.3s ease-in-out;\n}\n\n.button:hover .text-md {\n  color: #ffd700;\n  text-shadow: 0 0 10px #ffd700;\n}\n\n.ripple {\n  position: absolute;\n  border-radius: 50%;\n  background: rgba(255, 255, 255, 0.6);\n  animation: ripple 1s linear infinite;\n  pointer-events: none;\n}\n\n.button:active .ripple {\n  animation: ripple-on-click 0.6s linear;\n}\n\n@keyframes ripple {\n  0% {\n    transform: scale(0);\n    opacity: 1;\n  }\n  100% {\n    transform: scale(4);\n    opacity: 0;\n  }\n}\n\n@keyframes ripple-on-click {\n  0% {\n    transform: scale(0);\n    opacity: 1;\n  }\n  100% {\n    transform: scale(4);\n    opacity: 0;\n  }\n}\n\n', colors: '#ffd700,#9333ea,#3b82f6', radii: '50%,9999px', shadows: '0 4px 14px rgba(0, 0, 0, 0.25),0 8px 20px rgba(0, 0, 0, 0.35),0 0 0 4px rgba(59, 130, 246, 0.5)', techniques: '3d-transform,glow-shadow,text-shadow,gradient,animation,filter-effect,svg-icon'),
const GalaxyComp(id: 'MRez321_tame-squid-31', cat: 'Buttons', author: 'MRez321', tags: 'button,hover,animated,hover button,#button,button hover effect', html: '<button class="button">\n  <svg\n    viewBox="0 0 48 48"\n    height="100"\n    width="100"\n    y="0px"\n    x="0px"\n    xmlns="http://www.w3.org/2000/svg"\n  >\n    <path\n      d="M39.175,10.016c1.687,0,2.131,1.276,1.632,4.272c-0.571,3.426-2.216,14.769-3.528,21.83 c-0.502,2.702-1.407,3.867-2.724,3.867c-0.724,0-1.572-0.352-2.546-0.995c-1.32-0.872-7.984-5.279-9.431-6.314 c-1.32-0.943-3.141-2.078-0.857-4.312c0.813-0.796,6.14-5.883,10.29-9.842c0.443-0.423,0.072-1.068-0.42-1.068 c-0.112,0-0.231,0.034-0.347,0.111c-5.594,3.71-13.351,8.859-14.338,9.53c-0.987,0.67-1.949,1.1-3.231,1.1 c-0.655,0-1.394-0.112-2.263-0.362c-1.943-0.558-3.84-1.223-4.579-1.477c-2.845-0.976-2.17-2.241,0.593-3.457 c11.078-4.873,25.413-10.815,27.392-11.637C36.746,10.461,38.178,10.016,39.175,10.016 M39.175,7.016L39.175,7.016 c-1.368,0-3.015,0.441-5.506,1.474L33.37,8.614C22.735,13.03,13.092,17.128,6.218,20.152c-1.074,0.473-4.341,1.91-4.214,4.916 c0.054,1.297,0.768,3.065,3.856,4.124l0.228,0.078c0.862,0.297,2.657,0.916,4.497,1.445c1.12,0.322,2.132,0.478,3.091,0.478 c1.664,0,2.953-0.475,3.961-1.028c-0.005,0.168-0.001,0.337,0.012,0.507c0.182,2.312,1.97,3.58,3.038,4.338l0.149,0.106 c1.577,1.128,8.714,5.843,9.522,6.376c1.521,1.004,2.894,1.491,4.199,1.491c2.052,0,4.703-1.096,5.673-6.318 c0.921-4.953,1.985-11.872,2.762-16.924c0.331-2.156,0.603-3.924,0.776-4.961c0.349-2.094,0.509-4.466-0.948-6.185 C42.208,7.875,41.08,7.016,39.175,7.016L39.175,7.016z"\n    ></path>\n  </svg>\n\n  Send Message\n</button>', css: '\n/* From Uiverse.io by MRez321  - Tags: button, hover, animated, hover button, #button, button hover effect  */\n.button {\n  position: relative;\n  z-index: 5;\n  isolation: isolate;\n  cursor: pointer;\n  transition: 0.4s;\n\n  width: fit-content;\n  height: 4.8rem;\n  padding: 1rem;\n  margin-inline: auto;\n  border: solid 3px;\n  border-color: #0000004d #0000004d #00000080 #00000080;\n  border-radius: 0.8rem;\n\n  font-family: cursive;\n  font-size: 1.4rem;\n  font-weight: 700;\n\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  gap: 0.5rem;\n\n  animation: boxShadowRotation 2s linear infinite;\n}\n.button:hover,\n.button:active {\n  scale: 0.96;\n  border-color: #00000080 #00000080 #0000004d #0000004d;\n  padding: 2rem;\n  box-shadow: 0 0 4px 2px rgba(208, 212, 218, 0.979);\n  background: #fbfdfc;\n}\n\n.button::before,\n.button::after {\n  position: absolute;\n  content: "";\n  background: #f4f5f4;\n  transition: 0.4s;\n}\n.button::before {\n  z-index: -1;\n  inset: 0.3rem;\n  border-radius: 4rem;\n  box-shadow: inset 0 0 4px 2px rgba(208, 212, 218, 0.979);\n}\n.button:hover::before {\n  inset: 0.1rem;\n  z-index: -1;\n  margin-inline: auto;\n  border: solid 1px;\n  border-color: #00000080 #00000080 #0000004d #0000004d;\n  border-radius: 0.8rem;\n  animation: boxShadowRotation 2s linear infinite;\n  background-image: linear-gradient(120deg, #a1c4fd 0%, #c2e9fb 100%);\n}\n.button::after {\n  background: none;\n  z-index: -2;\n  border-radius: 1rem;\n}\n.button:hover::after {\n  inset: -0.5rem;\n  border: solid 1px #00000080;\n  box-shadow: 0 0 10px 4px #a1c4fd;\n  background: #c2e9fb;\n}\n\n.button svg {\n  width: 2rem;\n  height: 2rem;\n  z-index: 10;\n}\n.button:hover svg {\n  animation: rotation 0.8s linear;\n  filter: drop-shadow(0 0 10px 10px rgb(170, 166, 166));\n}\n\n@keyframes rotation {\n  0% {\n    transform: rotate(0deg) translate(0, 0) scale(1);\n  }\n  50% {\n    transform: rotate(180deg) translate(-4rem, -2rem) scale(1.4);\n  }\n  100% {\n    transform: rotate(360deg) translate(0, 0) scale(1);\n  }\n}\n@keyframes b', colors: '#c2e9fb,#f4f5f4,#00000080,#0000004d,#fbfdfc,#a1c4fd', radii: '4rem,1rem,0.8rem', shadows: '0 0 4px 2px rgba(208, 212, 218, 0.979),inset 0 0 4px 2px rgba(208, 212, 218, 0.979),0 0 10px 4px #a1c4fd', techniques: '3d-transform,glow-shadow,gradient,animation,filter-effect,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'SanthoshSJ-Dev_slimy-lionfish-25', cat: 'Buttons', author: 'SanthoshSJ-Dev', tags: 'glassmorphism,button,colorful,battery', html: '<div class="container">\n  <button class="button">\n    <div class="plate"></div>\n    <div class="plate"></div>\n    <div class="plate"></div>\n    <div class="plate"></div>\n    <div class="plate"></div>\n    <div class="button__wrapper">\n      <span class="button__text">Battery</span>\n    </div>\n    <div class="button__box">\n      <div class="inner inner__top"></div>\n      <div class="inner inner__front"></div>\n      <div class="inner inner__bottom"></div>\n      <div class="inner inner__back"></div>\n      <div class="inner inner__left"></div>\n      <div class="inner inner__right"></div>\n    </div>\n  </button>\n</div>', css: '\n/* From Uiverse.io by SanthoshSJ-Dev - Tags: glassmorphism, button, colorful, battery */\n.button {\n  display: flex;\n  position: relative;\n  width: 200px;\n  height: 60px;\n  text-decoration: none;\n  perspective: 600px;\n  background: linear-gradient(#ffffff1a 0%, #ffffff00 30%, #ffffff00 70%, #ffffff1a);\n  box-shadow: 0 0 32px #000000;\n}\n\n.button::before,\n.button::after {\n  content: \'\';\n  position: absolute;\n  top: 0;\n  left: 0;\n  right: 0;\n  margin: 0 auto;\n  width: 100%;\n  height: 100%;\n}\n\n.button::before {\n  top: 0;\n  transform-origin: top center;\n  transform: rotateX(70deg);\n  background: linear-gradient(135deg, #ffffff4d 10%, #ffffff00 60%);\n}\n\n.button::after {\n  bottom: 0;\n  transform-origin: bottom center;\n  transform: rotateX(-110deg);\n  background: radial-gradient(#ffffff00 40%, #ffffff1a);\n}\n\n.button__wrapper {\n  position: relative;\n  z-index: 2;\n  width: 100%;\n  height: 100%;\n  background: linear-gradient(#ffffff66 0%, #ffffff00 30%, #ffffff00 70%, #ffffff33);\n  transform: translate3d(0, 27px, 74px);\n  perspective: 600px;\n}\n\n.button__text {\n  position: relative;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  width: 100%;\n  height: 100%;\n  font-size: 32px;\n  font-weight: 900;\n  color: #ffffff33;\n  transition: all ease-in-out 1s;\n}\n\n.button__text::before {\n  content: \'\';\n  position: absolute;\n  z-index: 1;\n  top: 0;\n  left: 0;\n  width: 200px;\n  height: 60px;\n  background: linear-gradient(25deg, #ffffff1a, #ffffff00);\n  clip-path: path(\'M230,0H0V80H146.96c0-35.33,33.95-65.83,83.04-80Z\');\n}\n\n.button__text::after {\n  content: \'\';\n  position: absolute;\n  z-index: 2;\n  top: 4px;\n  left: 4px;\n  width: 272px;\n  height: 40px;\n  background: linear-gradient(25deg, #ffffff4d, #ffffff00);\n  clip-path: path(\'M272,9.22V0H0V40H.32C48.19,22.59,151.14,10.26,272,9.22Z\');\n}\n\n.button__wrapper::before,\n.button__wrapper::after {\n  content: \'\';\n  position: absolute;\n  top: 0;\n  width: 84px;\n  height: 100%;\n  background: linear-gradient(90deg, #ffffff33 0%, #ff', colors: '#ffffff1a,#64646480,#0064be33,#0064becc,#000000,#00aa6480,#ffffff,#d8003ccc,#9b32ffcc,#ffffff4d', radii: '10px', shadows: '0 0 32px #000000', techniques: '3d-transform,glow-shadow,gradient,animation,clip-path,perspective,pseudo-elements'),
const GalaxyComp(id: 'SelfMadeSystem_white-stingray-85', cat: 'Buttons', author: 'SelfMadeSystem', tags: '3d,pink,gradient,button,hover,active,3d button', html: '<svg width="0">\n  <filter id="l-distort">\n    <feTurbulence\n      numOctaves="20"\n      baseFrequency=".03"\n      type="fractalNoise"\n    ></feTurbulence>\n    <feDisplacementMap scale="60" in="SourceGraphic"></feDisplacementMap>\n  </filter>\n  <filter id="m-distort">\n    <feTurbulence\n      numOctaves="20"\n      baseFrequency=".02"\n      type="fractalNoise"\n    ></feTurbulence>\n    <feDisplacementMap scale="30" in="SourceGraphic"></feDisplacementMap>\n  </filter>\n</svg>\n\n<button class="button">\n  <div class="btn-bg">\n    <div class="bg1"></div>\n    <div class="bg2"></div>\n    <div class="bd1"></div>\n    <div class="bd1h"></div>\n    <div\n      class="bg-cloud"\n      style="inset: unset; left: -10px; bottom: -20px; height: 70px; scale: 0.5;"\n    ></div>\n    <div class="bd6"></div>\n    <div class="bd-sat"></div>\n    <div class="bg-cloud" style="top: 30px; left: 270px; height: 50px;"></div>\n    <div class="bg-cloud" style="top: 7px; left: 10px; height: 30px;"></div>\n    <div\n      class="bg-cloud"\n      style="top: 0px; left: 70px; height: 30px; aspect-ratio: 5;"\n    ></div>\n    <div\n      class="bg-cloud"\n      style="top: 0px; left: -39px; rotate: 215deg; height: 30px; aspect-ratio: 3;"\n    ></div>\n    <div class="bd3"></div>\n    <div class="bd3a"></div>\n    <div class="bd4"></div>\n    <div class="bd4h"></div>\n    <div class="bd4d"></div>\n    <div class="bd5"></div>\n  </div>\n  <span class="btn-txt">\n    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">\n      <path d="M', css: '\n/* From Uiverse.io by SelfMadeSystem  - Tags: 3d, pink, gradient, button, hover, active, 3d button */\n.button {\n  --br: 27px;\n  --w: 360px;\n  --h: 113px;\n  --bg-grad: radial-gradient(#fffd 10px, #0000 calc(var(--w) - 60px)),\n    linear-gradient(\n      70deg in lch,\n      #8e0dff,\n      #e39cf6 15%,\n      #fd9b9a 45%,\n      #ff7139 65%,\n      #fdbff1 85%\n    );\n\n  position: relative;\n  cursor: pointer;\n  border-radius: var(--br);\n  isolation: isolate;\n  border: 0;\n  overflow: hidden;\n  width: var(--w);\n  height: var(--h);\n}\n\n.btn-bg {\n  position: absolute;\n  inset: 0;\n  z-index: -1;\n}\n\n:where(.btn-bg > div) {\n  position: absolute;\n  inset: 0;\n}\n\n.bg1 {\n  inset: -30px;\n  filter: url("#l-distort");\n  background: var(--bg-grad);\n}\n\n.bg2 {\n  left: 0;\n  top: 0;\n  height: 100%;\n  aspect-ratio: 1.5;\n  background: radial-gradient(#fffd 10px, #0000 60px);\n  filter: url("#m-distort");\n}\n\n.bg-cloud {\n  transform: translate(-50%);\n  aspect-ratio: 1.5;\n  background: radial-gradient(#fffd, #0000 70%);\n  filter: url("#m-distort");\n}\n\n.bd-sat {\n  mask: linear-gradient(#fff, #fff0 40% 60%, #fff);\n}\n\n.bd-sat::after {\n  content: "";\n  position: absolute;\n  inset: -30px;\n  border-radius: calc(var(--br) + 30px);\n  mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);\n  /* I forgor that I need the two mask composites because of firefoxxxxxx */\n  mask-composite: exclude;\n  mask-composite: xor;\n  background: var(--bg-grad);\n  filter: url("#l-distort") saturate(3);\n  padding: calc(30px + 7px);\n}\n\n.bd1 {\n  transition: opacity 0.5s;\n  border-radius: calc(var(--br) - 18px);\n  inset: 6px;\n  box-shadow: inset -13px -13px 5px -10px #fffa;\n}\n\n.button:hover .bd1 {\n  opacity: 0;\n}\n\n.bd1h {\n  transition: opacity 0.5s;\n  border-radius: calc(var(--br) - 18px);\n  opacity: 0;\n  inset: 6px;\n  box-shadow: inset 13px 13px 5px -10px #fffa;\n}\n\n.button:hover:not(:active) .bd1h {\n  opacity: 1;\n}\n\n.bd3 {\n  inset: 20px;\n  border-radius: 17px;\n  border: 2px solid #fff8;\n  box-shadow: 0px 0px 6px ', colors: '#fffd,#0005,#8e0dff,#e39cf6,#fff0,#fd9b9a,#fffa,#fff8,#0001,#ff7139', radii: '99px,var(--br),calc(var(--br) - 18px),17px,calc(var(--br) - 5px)', shadows: 'inset -1