const GalaxyComp(id: 'StealthWorm_pretty-lion-68', cat: 'Buttons', author: 'StealthWorm', tags: 'button', html: '<button class="btn" type="button">\n  <strong>SPACE</strong>\n  <div id="container-stars">\n    <div id="stars"></div>\n  </div>\n\n  <div id="glow">\n    <div class="circle"></div>\n    <div class="circle"></div>\n  </div>\n</button>', css: '\n/* From Uiverse.io by StealthWorm - Tags: button */\n.btn {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  width: 13rem;\n  height: 3rem;\n  background-size: 300% 300%;\n  backdrop-filter: blur(1rem);\n  border-radius: 5rem;\n  transition: 0.5s;\n  animation: gradient_301 5s ease infinite;\n  border: double 4px transparent;\n  background-image: linear-gradient(#212121, #212121),  linear-gradient(137.48deg, #ffdb3b 10%,#FE53BB 45%, #8F51EA 67%, #0044ff 87%);\n  background-origin: border-box;\n  background-clip: content-box, border-box;\n}\n\n#container-stars {\n  position: fixed;\n  z-index: -1;\n  width: 100%;\n  height: 100%;\n  overflow: hidden;\n  transition: 0.5s;\n  backdrop-filter: blur(1rem);\n  border-radius: 5rem;\n}\n\nstrong {\n  z-index: 2;\n  font-family: \'Avalors Personal Use\';\n  font-size: 12px;\n  letter-spacing: 5px;\n  color: #FFFFFF;\n  text-shadow: 0 0 4px white;\n}\n\n#glow {\n  position: absolute;\n  display: flex;\n  width: 12rem;\n}\n\n.circle {\n  width: 100%;\n  height: 30px;\n  filter: blur(2rem);\n  animation: pulse_3011 4s infinite;\n  z-index: -1;\n}\n\n.circle:nth-of-type(1) {\n  background: rgba(254, 83, 186, 0.636);\n}\n\n.circle:nth-of-type(2) {\n  background: rgba(142, 81, 234, 0.704);\n}\n\n.btn:hover #container-stars {\n  z-index: 1;\n  background-color: #212121;\n}\n\n.btn:hover {\n  transform: scale(1.1)\n}\n\n.btn:active {\n  border: double 4px #FE53BB;\n  background-origin: border-box;\n  background-clip: content-box, border-box;\n  animation: none;\n}\n\n.btn:active .circle {\n  background: #FE53BB;\n}\n\n#stars {\n  position: relative;\n  backg