const GalaxyComp(id: 'zanina-yassine_shy-octopus-85', cat: 'Buttons', author: 'zanina-yassine', tags: 'button', html: '<div class="btn-container">\n<button id="space-btn" name="space-button" type="submit">\n  <span>Let\'s Go to Space</span>\n<div style="position: absolute; left: 119.273px; top: 18.0747px; animation-delay: 3.37051s; transform: scale(0.196521);" class="star"></div><div style="position: absolute; left: 166.774px; top: 47.4519px; animation-delay: 3.03913s; transform: scale(0.33078);" class="star"></div><div style="position: absolute; left: 238.677px; top: 19.6434px; animation-delay: 3.85796s; transform: scale(1.29037);" class="star"></div><div style="position: absolute; left: 22.2022px; top: 4.69534px; animation-delay: 4.9415s; transform: scale(1.82231);" class="star"></div><div style="position: absolute; left: 206.74px; top: 40.7685px; animation-delay: 1.59195s; transform: scale(1.01375);" class="star"></div><div style="position: absolute; left: 241.531px; top: 14.2516px; animation-delay: 1.67616s; transform: scale(0.811597);" class="star"></div><div style="position: absolute; left: 14.754px; top: 25.2924px; animation-delay: 0.0348248s; transform: scale(0.102529);" class="star"></div><div style="position: absolute; left: 220.444px; top: 43.9803px; animation-delay: 1.5106s; transform: scale(0.16088);" class="star"></div><div style="position: absolute; left: 95.948px; top: 54.8942px; animation-delay: 3.18662s; transform: scale(1.7822);" class="star"></div><div style="position: absolute; left: 30.3484px; top: 36.5984px; animation-delay: 4.30868s; transform: scale(1.16326);" class="star', css: '\n/* From Uiverse.io by zanina-yassine - Tags: button */\nbutton#space-btn {\n  width: 100%;\n  height: 100%;\n  position: relative;\n  overflow: hidden;\n  border: 0;\n  outline: 0;\n  border-radius: 11px;\n  background: #03001e;\n  background: linear-gradient(80deg, #ffcbf2, #ec38bc, #7303c0, #03001e);\n  cursor: pointer;\n}\n\n.btn-container {\n  width: 200px;\n  height: 60px;\n  position: relative;\n  overflow: visible;\n}\n\n.btn-container::after {\n  content: "";\n  width: 100%;\n  height: 100%;\n  position: absolute;\n  left: 0;\n  top: 20px;\n  z-index: -1;\n  background: #03001e;\n  background: linear-gradient(80deg, #ffcbf2, #ec38bc, #7303c0, #03001e);\n  filter: blur(20px);\n  opacity: 0;\n}\n\n.btn-container:hover {\n  transform: scale(1.1);\n  transition: all 0.6s cubic-bezier(0.15, 0.83, 0.66, 1);\n}\n\n.btn-container:hover:after {\n  transition: all 0.6s cubic-bezier(0.15, 0.83, 0.66, 1);\n  opacity: 0.6;\n}\n\nbutton span {\n  color: white;\n  font-weight: 700;\n  font-size: 16px;\n}\n\nbutton#space-btn div.star {\n  width: 1px;\n  height: 1px;\n  background-color: white;\n  border-radius: 50%;\n  animation: blink 2s cubic-bezier(0.15, 0.83, 0.66, 1) infinite;\n}\n\nbutton#space-btn div.shooting-star {\n  width: 80px;\n  height: 1px;\n  position: absolute;\n  background: linear-gradient(80deg, #ffffffff, #ffffff00);\n  border-radius: 50%;\n  transform: rotate(-40deg);\n  opacity: 0\n}\n\nbutton#space-btn div.shooting-star-1 {\n  animation: fallingStar1 4s 6s cubic-bezier(0.15, 0.83, 0.66, 1) infinite;\n}\n\nbutton#space-btn div.shooting-star-2 {\n  animation: fallingStar2 2s 10s cubic-bezier(0.15, 0.83, 0.66, 1) infinite;\n}\n\nbutton#space-btn div.shooting-star-3 {\n  animation: fallingStar3 8s 20s cubic-bezier(0.15, 0.83, 0.66, 1) infinite;\n}\n\nbutton#space-btn div.shooting-star-4 {\n  animation: fallingStar4 4s 6s cubic-bezier(0.15, 0.83, 0.66, 1) infinite;\n}\n\n@keyframes blink {\n  0% {\n    box-shadow: 0 0 10px 0 white;\n  }\n\n  50% {\n    box-shadow: 0 0 10px 2px white;\n  }\n\n  100% {\n    box-shadow: 0 0 10px 0 white;\n  }\n}\n\n@keyf', colors: '#ffcbf2,#03001e,#7303c0,#ffffff00,#ec38bc,#ffffffff', radii: '50%,11px', shadows: '0 0 10px 0 white,0 0 10px 2px white,0 0 10px 0 white', techniques: 'glassmorphism,cubic-bezier,3d-transform,glow-shadow,gradient,animation,pseudo-elements'),
