 0px rgba(82, 20, 137, 0.059);\n  transform: scale(1.02);\n  transition: all 0.1s ease-in;\n}\n.card:hover::before {\n  content: "";\n  width: 100%;\n  height: 100%;\n  position: absolute;\n  top: 0;\n  left: 0%;\n  background-image: radial-gradient(#ffffff2b 2%, transparent 0%),\n    radial-gradient(#ffffff17 1%, transparent 0%);\n  background-size: 100px 100px;\n  background-position: 0 0, 50px 50px;\n  animation: stars 8s ease-in-out infinite;\n}\n\n.image {\n  width: 100%;\n  max-width: 190px;\n  display: block;\n  margin: auto;\n  border-radius: 10px;\n}\n\n.card:hover .image {\n  animation: hoverman 8s ease-in-out infinite;\n}\n\n.heading {\n  font-size: 19px;\n  font-weight: bold;\n  margin-top: 15px;\n  text-transform: uppercase;\n}\n\n.icons {\n  margin-top: 15px;\n  width: 100%;\n  display: flex;\n  justify-content: center;\n}\n\n.icons a {\n  display: inline-block;\n  margin-right: 10px;\n}\n\n.icons a:last-child {\n  margin-right: 0;\n}\n\n.card svg {\n  width: 24px;\n  height: 24px;\n}\n\n.instagram path,\n.twitter path,\n.discord path {\n  stroke: #fff;\n}\n\n.instagram:hover path,\n.twitter:hover path,\n.discord:hover path {\n  stroke: #55acee;\n}\n\n@keyframes hoverman {\n  0% {\n    transform: rotate(0deg);\n  }\n  50% {\n    transform: rotate(-20deg);\n  }\n  100% {\n    transform: rotate(0deg);\n  }\n}\n@keyframes stars {\n  0% {\n    background-position: 0 0, 50px 50px;\n    opacity: 0;\n  }\n  50% {\n    background-position: 30px 10px, 50px 50px;\n    opacity: 1;\n  }\n  100% {\n    opacity: 0;\n  }\n}\n\n', colors: '#ffffff17,#55acee,#ffffff2b,#fff,#1a1a1a', radii: '10px', shadows: '2px 2px 3px 0px rgba(0, 0, 0, 0.1),4px 4px 6px 0px rgba(82, 20, 137, 0.059)', techniques: '3d-transform,glow-shadow,gradient,animation,typography-transform,svg-icon,pseudo-elements'),
