0px 30px -20px;\n  transition: all 0.5s ease-in-out;\n}\n\n.card .image-container {\n  position: relative;\n  width: 100%;\n  height: 130px;\n  border-radius: 0.7rem;\n  border-top-right-radius: 4rem;\n  margin-bottom: 1rem;\n}\n\n.card .image-container img {\n  width: 100%;\n  height: 100%;\n  -o-object-fit: cover;\n  object-fit: cover;\n  border-radius: inherit;\n}\n\n.card .image-container .svg {\n  height: 100%;\n  width: 100%;\n  border-radius: inherit;\n}\n\n.card .image-container .price {\n  position: absolute;\n  right: 0.7rem;\n  bottom: -1rem;\n  background: white;\n  color: var(--accent-color);\n  font-weight: 900;\n  font-size: 0.9rem;\n  padding: 0.5rem;\n  border-radius: 1rem 1rem 2rem 2rem;\n  box-shadow: rgba(100, 100, 111, 0.2) 0px 0px 15px 0px;\n}\n\n.card .favorite {\n  position: absolute;\n  width: 19px;\n  height: 19px;\n  top: 5px;\n  right: 5px;\n  cursor: pointer;\n}\n\n.card .favorite input {\n  position: absolute;\n  opacity: 0;\n  width: 0;\n  height: 0;\n}\n\n.card .favorite input:checked ~ svg {\n  animation: bouncing 0.5s;\n  fill: rgb(255, 95, 95);\n  filter: drop-shadow(0px 3px 1px rgba(53, 53, 53, 0.14));\n}\n\n.card .favorite svg {\n  fill: #a8a8a8;\n}\n\n.card .content {\n  padding: 0px 0.8rem;\n  margin-bottom: 1rem;\n}\n\n.card .content .brand {\n  font-weight: 900;\n  color: #a6a6a6;\n}\n\n.card .content .product-name {\n  font-weight: 700;\n  color: #666666;\n  font-size: 0.7rem;\n  margin-bottom: 1rem;\n}\n\n.card .content .color-size-container {\n  display: flex;\n  justify-content: space-between;\n  text-transform: uppercase;\n  font-size: 0.7rem;\n  font-weight: 700;\n  color: #a8a8a8;\n  gap: 2rem;\n  margin-bottom: 1.5rem;\n}\n\n.card .content .color-size-container > * {\n  flex: 1;\n}\n\n.card .content .color-size-container .', colors: '#a8a8a8,#144076,#a6a6a6,#ffd426,#666666,#00b9ff,#484848,#ff6ba1', radii: '50%,inherit,1.4rem 1.4rem 0.7rem 0.7rem,1rem 1rem 2rem 2rem,2rem 2rem 1.5rem 1.5rem', shadows: 'rgba(100, 100, 11