ue-rotate(60deg) brightness(3);\n}\n.card .boxshadow {\n  position: absolute;\n  height: 100%;\n  width: 100%;\n  border: 1px solid red;\n  transform: scale(0.8);\n  box-shadow: rgba(255, 0, 0, 1) 0px 30px 70px 0px;\n  transition: all 0.5s cubic-bezier(0.785, 0.135, 0.15, 0.86);\n}\n.card .main {\n  width: 230px;\n  height: 300px;\n  overflow: hidden;\n  background: red;\n  background: linear-gradient(\n    0deg,\n    #3e0000 0%,\n    rgba(255, 0, 0, 1) 60%,\n    #3e0000 100%\n  );\n  position: relative;\n  clip-path: polygon(\n    0 0,\n    100% 0,\n    100% 40px,\n    100% calc(100% - 40px),\n    calc(100% - 40px) 100%,\n    40px 100%,\n    0 calc(100% - 40px)\n  );\n  box-shadow: rgba(255, 0, 0, 1) 0px 7px 29px 0px;\n  transition: all 0.3s cubic-bezier(0.785, 0.135, 0.15, 0.86);\n}\n.card .main .top {\n  position: absolute;\n  top: 0px;\n  left: 0;\n  width: 0px;\n  height: 0px;\n  z-index: 2;\n  border-top: 115px solid black;\n  border-left: 115px solid transparent;\n  border-right: 115px solid transparent;\n  transition: all 0.5s cubic-bezier(0.785, 0.135, 0.15, 0.86);\n}\n.card .main .side {\n  position: absolute;\n  width: 100%;\n  top: 0;\n  transform: translateX(-50%);\n  height: 101%;\n  background: black;\n  clip-path: polygon(0% 0%, 50% 0, 95% 45%, 100% 100%, 0% 100%);\n  transition: all 0.5s cubic-bezier(0.785, 0.135, 0.15, 0.86) 1s;\n}\n.card .main .left {\n  left: 0;\n}\n.card .main .right {\n  right: 0;\n  transform: translateX(50%) scale(-1, 1);\n}\n.card .main .title {\n  position: absolute;\n  left: 50%;\n  transform: translateX(-50%);\n  top: 90px;\n  font-weight: bold;\n  font-size: 25px;\n  opacity: 0;\n  z-index: -1;\n  transition: all 0.2s ease-out 0s;\n}\n.card .main .button-container {\n  position: absolute;\n  bot', colors: '#3e0000', radii: '', shadows: 'rgba(255, 0, 0, 1) 0px 30px 70px 0px,rgba(255, 0, 0, 1) 0px 7px 29px 0px', techniques: 'cubic-bezier,3d-transform,glow-shadow,gradient,filter-effect,clip-path,svg-icon'),
