e;\n  bottom: 0;\n  left: 0;\n  height: 100%;\n  width: 100%;\n  background-image: linear-gradient(to bottom, transparent 10%,rgba(0,0,0,0.5) 50%,rgba(0,0,0) 90%);\n  transition: all .3 ease;\n  opacity: 0;\n}\n\n.card:hover::before {\n  opacity: 1;\n}\n\n.card::after {\n  content: "";\n  position: absolute;\n  left: -2em;\n  width: 5em;\n  height: 175%;\n  top: -15em;\n  rotate: 45deg;\n  opacity: 0;\n  z-index: 1;\n  transform: perspective(250px);\n  transition: transform .7s ease-in-out;\n  background: linear-gradient(to right, transparent 1%, rgba(255, 255, 255, 0.1) 40%,rgba(255, 255, 255, 0.1) 60% , transparent 100%);\n}\n\n.card:hover::after {\n  overflow: auto;\n  opacity: 1;\n  transform: translateX(35em);\n}\n\n.card button {\n  --border-width: 4px;\n  appearance: none;\n  position: relative;\n  margin-top: 10%;\n  padding: 1em 2em;\n  border: 1px;\n  width: 96%;\n  background-color: #212121;\n  border-radius: 100px;\n  font-size: 15px;\n  font-weight: 900;\n  color: #fff;\n  z-index: 2;\n}\n\nbutton::after {\n  --m-i: linear-gradient(#000, #000);\n  --m-o: content-box, padding-box;\n  content: "";\n  position: absolute;\n  left: -0.2em;\n  top: -0.2em;\n  width: 99%;\n  height: 95%;\n  padding: var(--border-width);\n  background-image: conic-gradient(\n		#488cfb,\n		#29dbbc,\n		#ddf505,\n		#ff9f0e,\n		#e440bb,\n		#655adc,\n		#488cfb\n	);\n  mask-image: var(--m-i), var(--m-i);\n  -webkit-mask-clip: var(--m-o);\n  mask-composite: exclude;\n  border-radius: 100px;\n}\n\nbutton:hover::after {\n  opacity: 0;\n}\n\n.card button:hover {\n  color: #fff;\n  font-weight: 900;\n  font-size: 1em;\n  text-transform: uppercase;\n  transform: perspective(50px) rotateX(-10deg);\n  background-image: linear-g', colors: '#488dfbd0,#ffee00,#e440bbd0,#333,#ddf505e1,#fff,#488dfbe1,#000,#29dbbc,#e440bb', radii: '100px', shadows: '0px 60px 60px -60px rgba(0,30,255,0.5),-2px -2px 10px 4px rgba(0, 0, 0, 0.5)', techniques: '3d-transform,gradient,css-mask,perspective,typography-transform,svg-icon,pseudo-elements'),
