const GalaxyComp(id: 'omriluz_black-panda-47', cat: 'loaders', author: '', tags: '', html: '<div class="container">\n  <div class="road">\n    <div class="police">\n      <div class="light_beam"></div>\n      <p>Police</p>\n      <article>Police</article>\n      <div class="side_mirror"></div>\n      <span>\n        <b></b>\n        <i></i>\n      </span>\n    </div>\n    <div class="police">\n      <div class="light_beam"></div>\n      <p>Police</p>\n      <article>Police</article>\n      <div class="side_mirror"></div>\n      <span>\n        <b></b>\n        <i></i>\n      </span>\n    </div>\n    <div class="taxi">\n      <div class="light_beam"></div>\n      <div class="side_mirror"></div>\n      <span>\n        <b></b>\n        <i></i>\n      </span>\n    </div>\n  </div>\n  <span class="loading">Loading..</span>\n</div>', css: '\n/* From Uiverse.io by omriluz  - Website: https://www.youtube.com/watch?v=3sQupmAMUhs&ab_channel=OnlineTutorials - Name: online tutorials - Tags: flashy, animation, red, blue, loader */\n.container {\n  background-color: #355463;\n  height: 100%;\n  width: 100%;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n.road {\n  position: relative;\n  width: 100%;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  transform-style: preserve-3d;\n  transform: rotate(-15deg);\n}\n\n.road::before {\n  content: "";\n  position: absolute;\n  width: 100%;\n  height: 4px;\n  background: linear-gradient(\n    90deg,\n    #fff,\n    #fff 50%,\n    transparent 50%,\n    transparent 100%\n  );\n  background-size: 50px;\n  animation: animate_road 0.07s linear infinite;\n}\n\n@keyframes animate_road {\n  0% {\n    background-position: 50px 0;\n  }\n  100% {\n    background-position: 0px 0;\n  }\n}\n\n.police {\n  position: absolute;\n  left: -100px;\n  width: 200px;\n  height: 80px;\n  background-color: #3f4c54;\n  border-radius: 10px;\n  box-shadow: -10px 10px rgba(0, 0, 0, 0.05);\n  transform-style: preserve-3d;\n  perspective: 800px;\n  z-index: 10;\n  animation: animate_police_car 5s linear infinite;\n}\n\n.police:nth-child(2) {\n  left: 200px;\n  animation-delay: -2.5s;\n}\n\n@keyframes animate_police_car {\n  0% {\n    transform: translateX(20px) translateY(-50px);\n  }\n  25% {\n    transform: translateX(-10px) translateY(0);\n  }\n  50% {\n    transform: translateX(20px) translateY(50px);\n  }\n  75% {\n    transform: translateX(-10px) translateY(0px);\n  }\n  100% {\n    transform: translateX(20px) translateY(-50px);\n  }\n}\n\n.police::before {\n  content: "";\n  position: absolute;\n  top: 12px;\n  left: 3px;\n  width: 5px;\n  height: 15px;\n  border-radius: 2px;\n  box-shadow: 0 42px #fc3c25;\n  background-color: #fc3c25;\n}\n\n.police::after {\n  content: "";\n  position: absolute;\n  top: 12px;\n  right: 2px;\n  width: 6px;\n  height: 16px;\n  border-radius: 2px;\n  box-shadow: 0 44px #fff;\n  background-color: #fff;\n}\n\n.poli', colors: '#475b66,#fff6,#3f4c54,#0005,#355463,#fc3c25,#ebebeb,#111,#fdd206,#344650', radii: '10px,15px,2px,5px', shadows: '-10px 10px rgba(0, 0, 0, 0.05),0 42px #fc3c25,0 44px #fff', techniques: '3d-transform,glow-shadow,gradient,animation,perspective,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'Praashoo7_lucky-hound-44', cat: 'loaders', author: 'Praashoo7', tags: 'neumorphism,animation,loader,smooth,shadow,realistic,circle loader,spin', html: '<div class="main">\n  <div class="up">\n    <div class="loaders">\n      <div class="loader"></div>\n      <div class="loader"></div>\n      <div class="loader"></div>\n      <div class="loader"></div>\n      <div class="loader"></div>\n      <div class="loader"></div>\n      <div class="loader"></div>\n      <div class="loader"></div>\n      <div class="loader"></div>\n      <div class="loader"></div>\n    </div>\n    <div class="loadersB">\n      <div class="loaderA">\n        <div class="ball0"></div>\n      </div>\n      <div class="loaderA">\n        <div class="ball1"></div>\n      </div>\n      <div class="loaderA">\n        <div class="ball2"></div>\n      </div>\n      <div class="loaderA">\n        <div class="ball3"></div>\n      </div>\n      <div class="loaderA">\n        <div class="ball4"></div>\n      </div>\n      <div class="loaderA">\n        <div class="ball5"></div>\n      </div>\n      <div class="loaderA">\n        <div class="ball6"></div>\n      </div>\n      <div class="loaderA">\n        <div class="ball7"></div>\n      </div>\n      <div class="loaderA">\n        <div class="ball8"></div>\n      </div>\n    </div>\n  </div>\n</div>', css: '\n/* From Uiverse.io by Praashoo7  - Tags: neumorphism, animation, loader, smooth, shadow, realistic, circle loader, spin */\n.main {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.loaders,\n.loadersB {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.loader {\n  position: absolute;\n  width: 1.15em;\n  height: 13em;\n  border-radius: 50px;\n  background: #e0e0e0;\n}\n.loader:after {\n  content: "";\n  position: absolute;\n  top: 0;\n  width: 1.15em;\n  height: 5em;\n  background: #e0e0e0;\n  border-radius: 50px;\n  border: 1px solid #e2e2e2;\n  box-shadow: inset 5px 5px 15px #d3d2d2ab, inset -5px -5px 15px #e9e9e9ab;\n  mask-image: linear-gradient(\n    to bottom,\n    black calc(100% - 48px),\n    transparent 100%\n  );\n}\n.loader::before {\n  content: "";\n  position: absolute;\n  bottom: 0;\n  width: 1.15em;\n  height: 4.5em;\n  background: #e0e0e0;\n  border-radius: 50px;\n  border: 1px solid #e2e2e2;\n  box-shadow: inset 5px 5px 15px #d3d2d2ab, inset -5px -5px 15px #e9e9e9ab;\n  mask-image: linear-gradient(\n    to top,\n    black calc(100% - 48px),\n    transparent 100%\n  );\n}\n.loaderA {\n  position: absolute;\n  width: 1.15em;\n  height: 13em;\n  border-radius: 50px;\n  background: transparent;\n}\n.ball0,\n.ball1,\n.ball2,\n.ball3,\n.ball4,\n.ball5,\n.ball6,\n.ball7,\n.ball8,\n.ball9 {\n  width: 1.15em;\n  height: 1.15em;\n  box-shadow: rgba(0, 0, 0, 0.17) 0px -10px 10px 0px inset,\n    rgba(0, 0, 0, 0.15) 0px -15px 15px 0px inset,\n    rgba(0, 0, 0, 0.1) 0px -40px 20px 0px inset, rgba(0, 0, 0, 0.06) 0px 2px 1px,\n    rgba(0, 0, 0, 0.09) 0px 4px 2px, rgba(0, 0, 0, 0.09) 0px 8px 4px,\n    rgba(0, 0, 0, 0.09) 0px 16px 8px, rgba(0, 0, 0, 0.09) 0px 32px 16px,\n    0px -1px 15px -8px rgba(0, 0, 0, 0.09);\n  border-radius: 50%;\n  transition: transform 800ms cubic-bezier(1, -0.4, 0, 1.4);\n  background-color: rgb(232, 232, 232, 1);\n  animation: 3.63s move ease-in-out infinite;\n}\n.loader:nth-child(2) {\n  transform: rotate(20deg);\n}\n.loader:nth-child(3) {\n  transform: rotate(40deg);\n', colors: '#e2e2e2,#d3d2d2ab,#e9e9e9ab,#e0e0e0', radii: '50px,50%', shadows: 'inset 5px 5px 15px #d3d2d2ab, inset -5px -5px 15px #e9e9e9ab,inset 5px 5px 15px #d3d2d2ab, inset -5px -5px 15px #e9e9e9ab,rgba(0, 0, 0, 0.17) 0px -10px 10px 0px inset,\n    rgba(0, 0, 0, 0.15) 0px -15px 15px 0px inset,\n    rgba(0, 0, 0, 0.1) 0', techniques: 'cubic-bezier,3d-transform,glow-shadow,gradient,animation,css-mask,pseudo-elements'),
const GalaxyComp(id: 'Admin12121_strong-penguin-65', cat: 'Toggle-switches', author: 'Admin12121', tags: 'switch,toggle,toggle switch,3d button', html: '<label class="switch">\n  <input role="switch" type="checkbox" class="switch__input" />\n  <span class="switch__bg"></span>\n  <span class="switch__label">Power</span>\n</label>', css: '\n/* From Uiverse.io by Admin12121  - Tags: switch, toggle, toggle switch, 3d button */\n.switch,\n.switch__input {\n  --hue: 223;\n  --bg: hsl(var(--hue), 90%, 60%);\n  --fg: hsl(var(--hue), 90%, 10%);\n  --primary: hsl(var(--hue), 90%, 50%);\n  --trans-dur: 0.3s;\n  --trans-timing: cubic-bezier(0.65, 0, 0.35, 1);\n  font-size: calc(40px + (80 - 40) * (100px - 320px) / (2560 - 320));\n  position: relative;\n  -webkit-tap-highlight-color: transparent;\n}\n.switch {\n  display: block;\n  filter: grayscale(0.9);\n  margin: auto;\n  transition: filter var(--trans-dur) var(--trans-timing);\n  width: 6em;\n  height: 2.75em;\n}\n.switch:has(:checked) {\n  filter: grayscale(0);\n}\n.switch__input {\n  cursor: pointer;\n  outline: transparent;\n  width: 100%;\n  height: 100%;\n  -webkit-appearance: none;\n  appearance: none;\n  z-index: 2;\n}\n.switch__bg {\n  background: radial-gradient(\n    7.75em 7.75em at 50% 4.0625em,\n    hsla(var(--hue), 90%, 90%, 0) 29.9%,\n    hsl(var(--hue), 90%, 90%) 30.1% 31.9%,\n    hsl(0, 0%, 100%) 32.1% 35.2%,\n    hsl(var(--hue), 50%, 80%) 35.4% 36%,\n    hsl(var(--hue), 90%, 70%) 36.2% 41.8%,\n    hsl(var(--hue), 90%, 65%) 42% 43.6%,\n    hsl(var(--hue), 50%, 80%) 43.8% 44.4%,\n    hsl(0, 0%, 100%) 44.6% 46.6%,\n    hsl(var(--hue), 90%, 90%) 46.8% 49.3%,\n    hsl(var(--hue), 90%, 98%) 49.5% 49.8%,\n    hsla(var(--hue), 90%, 98%, 0) 49.9%\n  );\n  clip-path: polygon(0 0, 100% 0, 100% 50%, 75% 100%, 25% 100%, 0 50%);\n  display: block;\n  position: absolute;\n  inset: 0;\n  z-index: 1;\n}\n.switch:before,\n.switch:after,\n.switch__input:before {\n  content: "";\n  display: block;\n  position: absolute;\n  top: 0;\n  left: 0;\n}\n.switch:before,\n.switch:after {\n  background: radial-gradient(\n      60% 60% at 50% 50%,\n      hsla(var(--hue), 50%, 80%, 0) 34%,\n      hsl(var(--hue), 50%, 80%) 35% 40.5%,\n      hsl(0, 0%, 100%) 41.5% 49%,\n      hsla(0, 0%, 100%, 0) 50%\n    ),\n    linear-gradient(\n        hsla(var(--hue), 90%, 65%, 0) 30%,\n        hsl(var(--hue), 90%, 65%) 30% 40%,\n        hsla(var(--hue), 90%, ', colors: '', radii: '50%', shadows: '0 0 0 0.5em hsla(var(--hue), 90%, 40%, 0),\n    0 0.25em 0.5em 0.125em hsl(var(--hue), 90%, 50%),0 0 0 0.5em hsla(var(--hue), 90%, 40%, 0.5),\n    0 0.25em 0.5em 0.125em hsl(var(--hue), 90%, 50%)', techniques: 'cubic-bezier,3d-transform,glow-shadow,gradient,filter-effect,clip-path,checkbox-input'),
const GalaxyComp(id: 'csemszepp_curly-parrot-90', cat: 'Toggle-switches', author: '', tags: '', html: '<div class="container">\n<label class="switch">\n	<input role="switch" type="checkbox" class="switch__input">\n	<svg aria-hidden="true" height="12px" width="12px" viewBox="0 0 12 12" class="switch__icon switch__icon--light">\n		<g stroke-linecap="round" stroke-width="1" stroke="#fff" fill="none">\n			<circle r="2" cy="6" cx="6"></circle>\n			<g stroke-dasharray="1.5 1.5">\n				<polyline transform="rotate(0,6,6)" points="6 10,6 11.5"></polyline>\n				<polyline transform="rotate(45,6,6)" points="6 10,6 11.5"></polyline>\n				<polyline transform="rotate(90,6,6)" points="6 10,6 11.5"></polyline>\n				<polyline transform="rotate(135,6,6)" points="6 10,6 11.5"></polyline>\n				<polyline transform="rotate(180,6,6)" points="6 10,6 11.5"></polyline>\n				<polyline transform="rotate(225,6,6)" points="6 10,6 11.5"></polyline>\n				<polyline transform="rotate(270,6,6)" points="6 10,6 11.5"></polyline>\n				<polyline transform="rotate(315,6,6)" points="6 10,6 11.5"></polyline>\n			</g>\n		</g>\n	</svg>\n	<svg aria-hidden="true" height="12px" width="12px" viewBox="0 0 12 12" class="switch__icon switch__icon--dark">\n		<g transform="rotate(-45,6,6)" stroke-linejoin="round" stroke-width="1" stroke="#fff" fill="none">\n			<path d="m9,10c-2.209,0-4-1.791-4-4s1.791-4,4-4c.304,0,.598.041.883.105-.995-.992-2.367-1.605-3.883-1.605C2.962.5.5,2.962.5,6s2.462,5.5,5.5,5.5c1.516,0,2.888-.613,3.883-1.605-.285.064-.578.105-.883.105Z"></path>\n		</g>	\n	</svg>\n	<span class="switch__sr">Dark Mode</span>\n</label>\n<div></div></di', css: '\n/* From Uiverse.io by csemszepp - Source: https://codepen.io/jkantner/pen/eYPYppR - Tags: switch, toggle switch */\n:root {\n  --hue: 223;\n  --bg: hsl(var(--hue),10%,90%);\n  --fg: hsl(var(--hue),10%,10%);\n  --primary: hsl(var(--hue),90%,50%);\n  --trans-dur: 0.3s;\n  --trans-timing: cubic-bezier(0.76,0.05,0.24,0.95);\n  --trans-timing-in: cubic-bezier(0.76,0.05,0.86,0.06);\n  --trans-timing-out: cubic-bezier(0.05,0.76,0.06,0.86);\n  font-size: calc(40px + (80 - 40) * (100px - 320px) / (2560 - 320));\n}\n\n.container,\n.switch__input {\n  color: var(--fg);\n  font: 1em/1.5 sans-serif;\n}\n\n.container {\n  background-color: var(--bg);\n  display: flex;\n  height: 100%;\n  transition: background-color var(--trans-dur),\n		color var(--trans-dur);\n}\n\n.container:has(.switch__input:checked) {\n  background-color: var(--fg);\n  color: var(--bg);\n}\n\n.switch {\n  margin: auto;\n  position: relative;\n}\n\n.switch__icon,\n.switch__input {\n  display: block;\n}\n\n.switch__icon {\n  position: absolute;\n  top: 0.375em;\n  right: 0.375em;\n  width: 0.75em;\n  height: 0.75em;\n  transition: opacity calc(var(--trans-dur) / 2),\n		transform calc(var(--trans-dur) / 2);\n}\n\n.switch__icon polyline {\n  transition: stroke-dashoffset calc(var(--trans-dur) / 2);\n}\n\n.switch__icon--light,\n.switch__icon--light polyline {\n  transition-delay: calc(var(--trans-dur) / 2);\n  transition-timing-function: var(--trans-timing-out);\n}\n\n.switch__icon--dark {\n  opacity: 0;\n  transform: translateX(-0.75em) rotate(30deg) scale(0.75);\n  transition-timing-function: var(--trans-timing-in);\n}\n\n.switch__input {\n  background-color: hsl(210,90%,70%);\n  border-radius: 0.75em;\n  box-shadow: 0 0 0 0.125em hsla(var(--hue),90%,50%,0),\n		0.125em 0.125em 0.25em hsla(var(--hue),90%,10%,0.2);\n  outline: transparent;\n  position: relative;\n  width: 3em;\n  height: 1.5em;\n  -webkit-appearance: none;\n  appearance: none;\n  -webkit-tap-highlight-color: transparent;\n  transition: background-color var(--trans-dur) var(--trans-timing),\n		box-shadow 0.15s linear;\n}\n\n.swi', colors: '', radii: '50%,0.75em,inherit', shadows: '0 0 0 0.125em hsla(var(--hue),90%,50%,0),\n		0.125em 0.125em 0.25em hsla(var(--hue),90%,10%,0.2),0 0 0 0.125em hsl(var(--hue),90%,50%),\n		0.125em 0.125em 0.25em hsla(var(--hue),90%,10%,0.2),0.05em 0.05em 0.05em hsla(var(--hue),90%,10%,0.1)', techniques: 'cubic-bezier,3d-transform,glow-shadow,gradient,css-mask,checkbox-input,svg-icon'),
const GalaxyComp(id: 'Galahhad_strong-squid-82', cat: 'Toggle-switches', author: '', tags: '', html: '<label class="theme-switch">\n  <input type="checkbox" class="theme-switch__checkbox">\n  <div class="theme-switch__container">\n    <div class="theme-switch__clouds"></div>\n    <div class="theme-switch__stars-container">\n      <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 144 55" fill="none">\n        <path fill-rule="evenodd" clip-rule="evenodd" d="M135.831 3.00688C135.055 3.85027 134.111 4.29946 133 4.35447C134.111 4.40947 135.055 4.85867 135.831 5.71123C136.607 6.55462 136.996 7.56303 136.996 8.72727C136.996 7.95722 137.172 7.25134 137.525 6.59129C137.886 5.93124 138.372 5.39954 138.98 5.00535C139.598 4.60199 140.268 4.39114 141 4.35447C139.88 4.2903 138.936 3.85027 138.16 3.00688C137.384 2.16348 136.996 1.16425 136.996 0C136.996 1.16425 136.607 2.16348 135.831 3.00688ZM31 23.3545C32.1114 23.2995 33.0551 22.8503 33.8313 22.0069C34.6075 21.1635 34.9956 20.1642 34.9956 19C34.9956 20.1642 35.3837 21.1635 36.1599 22.0069C36.9361 22.8503 37.8798 23.2903 39 23.3545C38.2679 23.3911 37.5976 23.602 36.9802 24.0053C36.3716 24.3995 35.8864 24.9312 35.5248 25.5913C35.172 26.2513 34.9956 26.9572 34.9956 27.7273C34.9956 26.563 34.6075 25.5546 33.8313 24.7112C33.0551 23.8587 32.1114 23.4095 31 23.3545ZM0 36.3545C1.11136 36.2995 2.05513 35.8503 2.83131 35.0069C3.6075 34.1635 3.99559 33.1642 3.99559 32C3.99559 33.1642 4.38368 34.1635 5.15987 35.0069C5.93605 35.8503 6.87982 36.2903 8 36.3545C7.26792 36.3911 6.59757 36.602 5.98015 37.0053C5.37155 37.3995 4.88644 37.9312 4.52481 38.5913C4', css: '\n/* From Uiverse.io by Galahhad - Source: https://youtu.be/S6T6hrc8cQo - Tags: switch, light&dark, bounce animation */\n.theme-switch {\n  --toggle-size: 30px;\n  /* the size is adjusted using font-size,\n     this is not transform scale,\n     so you can choose any size */\n  --container-width: 5.625em;\n  --container-height: 2.5em;\n  --container-radius: 6.25em;\n  /* radius 0 - minecraft mode :) */\n  --container-light-bg: #3D7EAE;\n  --container-night-bg: #1D1F2C;\n  --circle-container-diameter: 3.375em;\n  --sun-moon-diameter: 2.125em;\n  --sun-bg: #ECCA2F;\n  --moon-bg: #C4C9D1;\n  --spot-color: #959DB1;\n  --circle-container-offset: calc((var(--circle-container-diameter) - var(--container-height)) / 2 * -1);\n  --stars-color: #fff;\n  --clouds-color: #F3FDFF;\n  --back-clouds-color: #AACADF;\n  --transition: .5s cubic-bezier(0, -0.02, 0.4, 1.25);\n  --circle-transition: .3s cubic-bezier(0, -0.02, 0.35, 1.17);\n}\n\n.theme-switch, .theme-switch *, .theme-switch *::before, .theme-switch *::after {\n  -webkit-box-sizing: border-box;\n  box-sizing: border-box;\n  margin: 0;\n  padding: 0;\n  font-size: var(--toggle-size);\n}\n\n.theme-switch__container {\n  width: var(--container-width);\n  height: var(--container-height);\n  background-color: var(--container-light-bg);\n  border-radius: var(--container-radius);\n  overflow: hidden;\n  cursor: pointer;\n  -webkit-box-shadow: 0em -0.062em 0.062em rgba(0, 0, 0, 0.25), 0em 0.062em 0.125em rgba(255, 255, 255, 0.94);\n  box-shadow: 0em -0.062em 0.062em rgba(0, 0, 0, 0.25), 0em 0.062em 0.125em rgba(255, 255, 255, 0.94);\n  -webkit-transition: var(--transition);\n  -o-transition: var(--transition);\n  transition: var(--transition);\n  position: relative;\n}\n\n.theme-switch__container::before {\n  content: "";\n  position: absolute;\n  z-index: 1;\n  inset: 0;\n  -webkit-box-shadow: 0em 0.05em 0.187em rgba(0, 0, 0, 0.25) inset, 0em 0.05em 0.187em rgba(0, 0, 0, 0.25) inset;\n  box-shadow: 0em 0.05em 0.187em rgba(0, 0, 0, 0.25) inset, 0em 0.05em 0.187em rgba(0, 0, 0, 0.25) i', colors: '#3d7eae,#1d1f2c,#c4c9d1,#a1872a,#959db1,#ecca2f,#aacadf,#f3fdff,#fff,#969696', radii: 'var(--container-radius),inherit,var(--container-radius)\n}\n\n.theme-switch__checkbox {\n  display: none', shadows: '0em -0.062em 0.062em rgba(0, 0, 0, 0.25), 0em 0.062em 0.125em rgba(255, 255, 255, 0.94),0em -0.062em 0.062em rgba(0, 0, 0, 0.25), 0em 0.062em 0.125em rgba(255, 255, 255, 0.94),0em 0.05em 0.187em rgba(0, 0, 0, 0.25) inset, 0em 0.05em 0.187em rgba(0, 0, 0, 0.25) inset', techniques: 'cubic-bezier,3d-transform,glow-shadow,filter-effect,checkbox-input,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'ilkhoeri_blue-zebra-2', cat: 'Toggle-switches', author: 'ilkhoeri', tags: 'switch', html: '<div class="switch-wrap">\n  <input\n    class="switch-input"\n    aria-label="switch"\n    name="switch"\n    id="switch"\n    type="checkbox"\n    hidden=""\n  />\n  <label class="switch-label" for="switch"></label>\n  <span class="switch-marbles"></span>\n</div>', css: '\n/* From Uiverse.io by ilkhoeri  - Tags: switch */\n.switch-wrap {\n  z-index: 20;\n  position: relative;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  border-radius: 9999px;\n  width: calc(var(--w-switch) + calc(var(--p) * 2));\n  height: calc(var(--h-switch) + calc(var(--p) * 2));\n  box-shadow: hsla(var(--pure-black), 0.25) 2px -5px 4px inset,\n    hsla(var(--pure-black), 0.25) 0px 2px 5px -1px,\n    hsla(var(--pure-black), 0.3) 0 1px 3px -1px,\n    0 70px 40px -20px hsla(var(--pure-black), 0.2),\n    hsla(var(--pure-black), 0.2) 0 0 0 1px inset;\n  --round: 4rem;\n  --pure-black: 0, 0%, 0%;\n  --pure-white: 0, 0%, 100%;\n  --scale-x: calc(1.35 * var(--round));\n  --p: calc(calc(6.25 / 100) * var(--round));\n  --checked: calc(100% - calc(var(--round) + var(--p)));\n  --sz-marbles: calc(var(--w-switch) + calc(var(--p) * 2));\n  --h-switch: calc(var(--round) + calc(var(--p) * 2));\n  --w-switch: calc(calc(var(--round) * 2) + calc(var(--p) * 2));\n  --bg-switch: var(--pure-black);\n  --box: var(--pure-white);\n}\n\n.switch-wrap .switch-input {\n  display: none;\n  background: transparent none;\n  visibility: hidden;\n}\n\n.switch-label {\n  cursor: pointer;\n  user-select: none;\n  position: relative;\n  z-index: 20;\n  width: var(--w-switch);\n  height: var(--h-switch);\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  outline: none;\n  background-color: hsl(var(--pure-white));\n  border-radius: 9999px;\n  border-width: 0px;\n  transition: all linear 300ms;\n  box-shadow: var(--shadow);\n  --shadow: hsla(var(--pure-black), 0.4) 0 2px 4px,\n    hsla(var(--pure-black), 0.3) 0 7px 13px -3px,\n    hsla(var(--pure-black), 0.25) -2px -5px 4px inset,\n    hsla(var(--pure-black), 0.2) 0 0 0 1px inset;\n}\n\n.switch-label::after {\n  position: absolute;\n  display: block;\n  content: "";\n  width: var(--round);\n  height: var(--round);\n  left: var(--p);\n  border-radius: 9999px;\n  background-color: hsl(0, 0%, 100%);\n  will-change: left, width, margin, padding;\n  box-shadow: var(--shado', colors: '#696eff,#f8acff', radii: '9999px', shadows: 'hsla(var(--pure-black), 0.25) 2px -5px 4px inset,\n    hsla(var(--pure-black), 0.25) 0px 2px 5px -1px,\n    hsla(var(--pur,var(--shadow),var(--shadow)', techniques: 'glassmorphism,cubic-bezier,glow-shadow,gradient,animation,checkbox-input,pseudo-elements'),
const GalaxyComp(id: 'MuhammadHasann_nasty-moth-15', cat: 'Toggle-switches', author: 'MuhammadHasann', tags: 'animation,minimalist,switch', html: '<div class="toggle-cont">\n  <input class="toggle-input" id="toggle" name="toggle" type="checkbox" />\n  <label class="toggle-label" for="toggle">\n    <div class="cont-icon">\n      <span\n        style="--width: 2; --deg: 25; --duration: 11"\n        class="sparkle"\n      ></span>\n      <span\n        style="--width: 1; --deg: 100; --duration: 18"\n        class="sparkle"\n      ></span>\n      <span\n        style="--width: 1; --deg: 280; --duration: 5"\n        class="sparkle"\n      ></span>\n      <span\n        style="--width: 2; --deg: 200; --duration: 3"\n        class="sparkle"\n      ></span>\n      <span\n        style="--width: 2; --deg: 30; --duration: 20"\n        class="sparkle"\n      ></span>\n      <span\n        style="--width: 2; --deg: 300; --duration: 9"\n        class="sparkle"\n      ></span>\n      <span\n        style="--width: 1; --deg: 250; --duration: 4"\n        class="sparkle"\n      ></span>\n      <span\n        style="--width: 2; --deg: 210; --duration: 8"\n        class="sparkle"\n      ></span>\n      <span\n        style="--width: 2; --deg: 100; --duration: 9"\n        class="sparkle"\n      ></span>\n      <span\n        style="--width: 1; --deg: 15; --duration: 13"\n        class="sparkle"\n      ></span>\n      <span\n        style="--width: 1; --deg: 75; --duration: 18"\n        class="sparkle"\n      ></span>\n      <span style="--width: 2; --deg: 65; --duration: 6" class="sparkle"></span>\n      <span style="--width: 2; --deg: 50; --duration: 7" class="sparkle"></span>\n      <sp', css: '\n/* From Uiverse.io by MuhammadHasann  - Tags: animation, minimalist, switch */\n.toggle-cont {\n  --primary: #54a8fc;\n  --light: #d9d9d9;\n  --dark: #121212;\n  --gray: #414344;\n\n  position: relative;\n  z-index: 10;\n\n  width: fit-content;\n  height: 50px;\n\n  border-radius: 9999px;\n}