0.5rem 0.75rem var(--second),0 1rem 2.5rem -2rem #0080ff', techniques: '3d-transform,glow-shadow,gradient,animation,checkbox-input,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'Nawsome_dry-treefrog-99', cat: 'Toggle-switches', author: 'Nawsome', tags: 'switch', html: '<input type="checkbox" class="plus-minus">', css: '\n/* From Uiverse.io by Nawsome - Tags: switch */\n.plus-minus {\n  --primary: #1E2235;\n  --secondary: #FAFBFF;\n  --duration: .5s;\n  -webkit-appearance: none;\n  -moz-appearance: none;\n  -webkit-tap-highlight-color: transparent;\n  -webkit-mask-image: -webkit-radial-gradient(white, black);\n  outline: none;\n  cursor: pointer;\n  position: relative;\n  overflow: hidden;\n  transform-style: preserve-3d;\n  perspective: 240px;\n  border-radius: 50%;\n  width: 36px;\n  height: 36px;\n  border: 4px solid var(--primary);\n  background-size: 300% 300%;\n  transition: transform 0.3s;\n  transform: scale(var(--scale, 1)) translateZ(0);\n  -webkit-animation: var(--name, unchecked) var(--duration) ease forwards;\n  animation: var(--name, unchecked) var(--duration) ease forwards;\n}\n\n.plus-minus:before, .plus-minus:after {\n  content: "";\n  position: absolute;\n  width: 16px;\n  height: var(--height, 16px);\n  left: 6px;\n  top: var(--top, 6px);\n  background: var(--background, var(--primary));\n  -webkit-animation: var(--name-icon-b, var(--name-icon, unchecked-icon)) var(--duration) ease forwards;\n  animation: var(--name-icon-b, var(--name-icon, unchecked-icon)) var(--duration) ease forwards;\n}\n\n.plus-minus:before {\n  -webkit-clip-path: polygon(0 6px, 6px 6px, 6px 0, 10px 0, 10px 6px, 16px 6px, 16px 10px, 10px 10px, 10px 16px, 6px 16px, 6px 10px, 0 10px);\n  clip-path: polygon(0 6px, 6px 6px, 6px 0, 10px 0, 10px 6px, 16px 6px, 16px 10px, 10px 10px, 10px 16px, 6px 16px, 6px 10px, 0 10px);\n}\n\n.plus-minus:after {\n  --height: 4px;\n  --top: 12px;\n  --background: var(--secondary);\n  --name-icon-b: var(--name-icon-a, checked-icon);\n}\n\n.plus-minus:active {\n  --scale: .95;\n}\n\n.plus-minus:checked {\n  --name: checked;\n  --name-icon-b: checked-icon;\n  --name-icon-a: unchecked-icon;\n}\n\n@keyframes checked-icon {\n  from {\n    transform: translateZ(12px);\n  }\n\n  to {\n    transform: translateX(16px) rotateY(90deg) translateZ(12px);\n  }\n}\n\n@keyframes unchecked-icon {\n  from {\n    transform: translateX(-16px) rotateY(-90de', colors: '#1e2235,#fafbff', radii: '50%', shadows: '', techniques: '3d-transform,gradient,animation,clip-path,css-mask,perspective,checkbox-input'),
const GalaxyComp(id: 'Nawsome_silent-owl-45', cat: 'Toggle-switches', author: 'Nawsome', tags: 'switch,plane', html: '<label class="plane-switch">\n    <input type="checkbox">\n    <div>\n        <div>\n            <svg viewBox="0 0 13 13">\n                <path d="M1.55989957,5.41666667 L5.51582215,5.41666667 L4.47015462,0.108333333 L4.47015462,0.108333333 C4.47015462,0.0634601974 4.49708054,0.0249592654 4.5354546,0.00851337035 L4.57707145,0 L5.36229752,0 C5.43359776,0 5.50087375,0.028779451 5.55026392,0.0782711996 L5.59317877,0.134368264 L7.13659662,2.81558333 L8.29565964,2.81666667 C8.53185377,2.81666667 8.72332694,3.01067661 8.72332694,3.25 C8.72332694,3.48932339 8.53185377,3.68333333 8.29565964,3.68333333 L7.63589819,3.68225 L8.63450135,5.41666667 L11.9308317,5.41666667 C12.5213171,5.41666667 13,5.90169152 13,6.5 C13,7.09830848 12.5213171,7.58333333 11.9308317,7.58333333 L8.63450135,7.58333333 L7.63589819,9.31666667 L8.29565964,9.31666667 C8.53185377,9.31666667 8.72332694,9.51067661 8.72332694,9.75 C8.72332694,9.98932339 8.53185377,10.1833333 8.29565964,10.1833333 L7.13659662,10.1833333 L5.59317877,12.8656317 C5.55725264,12.9280353 5.49882018,12.9724157 5.43174295,12.9907056 L5.36229752,13 L4.57707145,13 L4.55610333,12.9978962 C4.51267695,12.9890959 4.48069792,12.9547924 4.47230803,12.9134397 L4.47223088,12.8704208 L5.51582215,7.58333333 L1.55989957,7.58333333 L0.891288881,8.55114605 C0.853775374,8.60544678 0.798421006,8.64327676 0.73629202,8.65879796 L0.672314689,8.66666667 L0.106844414,8.66666667 L0.0715243949,8.66058466 L0.0715243949,8.66058466 C0.0297243066,8.6457608 0.00275502199,8.607', css: '\n/* From Uiverse.io by Nawsome - Tags: switch, plane */\n.plane-switch {\n  --dot: #fff;\n  --street: #6B6D76;\n  --street-line: #A8AAB4;\n  --street-line-mid: #C0C2C8;\n  --sky-1: #60A7FA;\n  --sky-2: #2F8EFC;\n  --light-1: rgba(255, 233, 0, 1);\n  --light-2: rgba(255, 233, 0, .3);\n  cursor: pointer;\n  -webkit-tap-highlight-color: transparent;\n}\n\n.plane-switch input {\n  display: none;\n}\n\n.plane-switch input + div {\n  -webkit-mask-image: -webkit-radial-gradient(white, black);\n  position: relative;\n  overflow: hidden;\n  width: 50px;\n  height: 25px;\n  padding: 1px;\n  border-radius: 13px;\n  background: linear-gradient(90deg, var(--street) 0%, var(--street) 25%, var(--sky-1) 75%, var(--sky-2) 100%) left var(--p, 0%) top 0;\n  background-position-x: var(--p, 0%);\n  background-size: 400% auto;\n  transition: background-position 0.6s;\n}\n\n.plane-switch input + div:before, .plane-switch input + div:after {\n  content: "";\n  display: block;\n  position: absolute;\n  transform: translateX(var(--s, 0));\n  transition: transform 0.3s;\n}\n\n.plane-switch input + div:before {\n  width: 42px;\n  right: 2px;\n  top: 4px;\n  height: 1px;\n  background: var(--street-line);\n  box-shadow: 0 16px 0 0 var(--street-line);\n}\n\n.plane-switch input + div:after {\n  width: 2px;\n  height: 2px;\n  border-radius: 50%;\n  left: 23px;\n  top: 1px;\n  -webkit-animation: lights2 2s linear infinite;\n  animation: lights2 2s linear infinite;\n  box-shadow: inset 0 0 0 2px var(--light-1), 0 21px 0 var(--light-1), 8px 0 0 var(--light-2), 8px 21px 0 var(--light-2), 16px 0 0 var(--light-2), 16px 21px 0 var(--light-2);\n}\n\n.plane-switch input + div span {\n  display: block;\n  position: absolute;\n}\n\n.plane-switch input + div span.street-middle {\n  top: 12px;\n  left: 21px;\n  width: 3px;\n  height: 1px;\n  transform: translateX(var(--s, 0));\n  background: var(--street-line-mid);\n  box-shadow: 5px 0 0 var(--street-line-mid), 10px 0 0 var(--street-line-mid), 15px 0 0 var(--street-line-mid), 20px 0 0 var(--street-line-mid), 25px 0 0 var(--street-', colors: '#c0c2c8,#6b6d76,#2f8efc,#60a7fa,#a8aab4,#fff', radii: '50%,13px,2px', shadows: '0 16px 0 0 var(--street-line),inset 0 0 0 2px var(--light-1), 0 21px 0 var(--light-1), 8px 0 0 var(--light-2), 8px 21px 0 var(--light-2), 16px 0 0 var,5px 0 0 var(--street-line-mid), 10px 0 0 var(--street-line-mid), 15px 0 0 var(--street-line-mid), 20px 0 0 var(--street-', techniques: 'cubic-bezier,glow-shadow,gradient,animation,css-mask,checkbox-input,svg-icon'),
const GalaxyComp(id: 'njesenberger_brave-firefox-90', cat: 'Toggle-switches', author: 'njesenberger', tags: 'skeuomorphism,switch,realistic,toggle,toggle switch', html: '<div class="toggle-container">\n  <input class="toggle-input" type="checkbox">\n  <div class="toggle-handle-wrapper">\n    <div class="toggle-handle">\n      <div class="toggle-handle-knob"></div>\n      <div class="toggle-handle-bar-wrapper">\n        <div class="toggle-handle-bar"></div>\n      </div>\n    </div>\n  </div>\n  <div class="toggle-base">\n    <div class="toggle-base-inside"></div>\n  </div>\n</div>', css: '\n/* From Uiverse.io by njesenberger - Tags: skeuomorphism, switch, realistic, toggle, toggle switch */\n.toggle-container {\n  --knob-size: 1.75em;\n  display: flex;\n  justify-content: center;\n  position: relative;\n}\n\n.toggle-input {\n  position: absolute;\n  z-index: 2;\n  bottom: 132.5%;\n  border-radius: 50%;\n  transform: rotate(-25deg);\n  transform-origin: 50% 4.75em;\n  width: var(--knob-size);\n  height: var(--knob-size);\n  opacity: 0;\n  /* fix em sizing */\n  font: inherit;\n  transition: transform .24s cubic-bezier(.65, 1.35, .5, 1);\n  cursor: pointer;\n}\n\n.toggle-input:checked {\n  transform: rotate(25deg);\n}\n\n.toggle-handle-wrapper {\n  position: absolute;\n  z-index: 1;\n  bottom: -135%;\n  -webkit-mask-image: linear-gradient(to bottom, #000 62.125%, transparent 50%);\n  mask-image: linear-gradient(to bottom, #000 62.125%, transparent 50%);\n  width: 200%;\n  overflow: hidden;\n}\n\n.toggle-handle {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  transform: rotate(-25deg);\n  transform-origin: bottom center;\n  transition: transform .24s cubic-bezier(.65, 1.35, .5, 1);\n}\n\n.toggle-input:checked + .toggle-handle-wrapper > .toggle-handle {\n  transform: rotate(25deg);\n}\n\n.toggle-handle-knob {\n  position: relative;\n  z-index: 1;\n  border-radius: 50%;\n  width: var(--knob-size);\n  height: var(--knob-size);\n  background-image: radial-gradient(farthest-corner at 70% 30%, #fedee2 4%, #d63534 12% 24%, #a81a1a 50% 65%, #d63534 75%);\n  transition: transform .24s cubic-bezier(.65, 1.35, .5, 1);\n}\n\n.toggle-input:checked + .toggle-handle-wrapper .toggle-handle-knob {\n  transform: rotate(-90deg);\n}\n\n/* toggle handle knob hover inner shadow */\n.toggle-handle-knob::after {\n  content: \'\';\n  position: absolute;\n  top: 0;\n  left: 0;\n  border-radius: inherit;\n  width: 100%;\n  height: 100%;\n  box-shadow: inset 0 0 8px 2px rgb(255 255 255 / .4);\n  opacity: 0;\n  transition: opacity .2s;\n}\n\n@media (hover: hover) {\n  .toggle-input:hover + .toggle-handle-wrapper .toggle-handle-knob::after', colors: '#fedee2,#d7d7d7,#a6a6a6,#777475,#000,#a81a1a,#d63534,#5ab054,#a4a4a4,#438c3c', radii: '50%,inherit,3.125em', shadows: 'inset 0 0 8px 2px rgb(255 255 255 / .4),inset 0 1em .25em rgb(0 0 0 / .4),0 -.25em .5em #fff, 0 .25em .5em #d7d7d7', techniques: 'cubic-bezier,3d-transform,glow-shadow,gradient,css-mask,checkbox-input,pseudo-elements'),
const GalaxyComp(id: '0xnihilism_calm-baboon-55', cat: 'Inputs', author: '0xnihilism', tags: 'simple,input,smooth,flip,hover button,brutalist', html: '<div class="brutalist-container">\n  <input\n    placeholder="TYPE HERE"\n    class="brutalist-input smooth-type"\n    type="text"\n  />\n  <label class="brutalist-label">SMOOTH BRUTALIST</label>\n</div>', css: '\n/* From Uiverse.io by 0xnihilism  - Tags: simple, input, smooth, flip, hover button, brutalist */\n.brutalist-container {\n  position: relative;\n  width: 250px;\n  font-family: monospace;\n}\n\n.brutalist-input {\n  width: 100%;\n  padding: 15px;\n  font-size: 18px;\n  font-weight: bold;\n  color: #000;\n  background-color: #fff;\n  border: 4px solid #000;\n  position: relative;\n  overflow: hidden;\n  border-radius: 0;\n  outline: none;\n  transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);\n  box-shadow: 5px 5px 0 #000, 10px 10px 0 #4a90e2;\n}\n\n@keyframes glitch {\n  0% {\n    transform: translate(0);\n  }\n  20% {\n    transform: translate(-2px, 2px);\n  }\n  40% {\n    transform: translate(-2px, -2px);\n  }\n  60% {\n    transform: translate(2px, 2px);\n  }\n  80% {\n    transform: translate(2px, -2px);\n  }\n  100% {\n    transform: translate(0);\n  }\n}\n\n.brutalist-input:focus {\n  animation: focus-pulse 4s cubic-bezier(0.25, 0.8, 0.25, 1) infinite,\n    glitch 0.3s cubic-bezier(0.25, 0.8, 0.25, 1) infinite;\n}\n\n.brutalist-input:focus::after {\n  content: "";\n  position: absolute;\n  top: -2px;\n  left: -2px;\n  right: -2px;\n  bottom: -2px;\n  background: white;\n  z-index: -1;\n}\n\n.brutalist-input:focus::before {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  background: black;\n  z-index: -2;\n  clip-path: inset(0 100% 0 0);\n  animation: glitch-slice 4s steps(2, end) infinite;\n}\n\n@keyframes glitch-slice {\n  0% {\n    clip-path: inset(0 100% 0 0);\n  }\n  10% {\n    clip-path: inset(0 5% 0 0);\n  }\n  20% {\n    clip-path: inset(0 80% 0 0);\n  }\n  30% {\n    clip-path: inset(0 10% 0 0);\n  }\n  40% {\n    clip-path: inset(0 50% 0 0);\n  }\n  50% {\n    clip-path: inset(0 30% 0 0);\n  }\n  60% {\n    clip-path: inset(0 70% 0 0);\n  }\n  70% {\n    clip-path: inset(0 15% 0 0);\n  }\n  80% {\n    clip-path: inset(0 90% 0 0);\n  }\n  90% {\n    clip-path: inset(0 5% 0 0);\n  }\n  100% {\n    clip-path: inset(0 100% 0 0);\n  }\n}\n\n.brutalist-label {\n  position: absolute;\n  left: -3px;\n  top: -35px;', colors: '#4a90e2,#000,#fff,#888', radii: '0', shadows: '5px 5px 0 #000, 10px 10px 0 #4a90e2', techniques: 'cubic-bezier,3d-transform,glow-shadow,gradient,animation,clip-path,pseudo-elements'),
