, 220, 1);\n  --border-color-2: rgba(120, 100, 255, 1);\n  --search-bar-gradient: linear-gradient(\n    135deg,\n    rgba(0, 0, 0, 0.541) 0%,\n    rgba(0, 0, 0, 0.226) 100%\n  );\n  --filter-button-gradient: linear-gradient(\n    135deg,\n    rgba(120, 100, 255, 0.2) 0%,\n    rgba(120, 100, 255, 0.1) 100%\n  );\n\n  width: 400px;\n  height: 120px;\n  position: relative;\n  font-family: Arial, sans-serif;\n}\n\n.neon-search-container .glow-container {\n  position: relative;\n  width: 100%;\n  height: 100%;\n}\n\n.neon-search-container .glow-effect-left,\n.neon-search-container .glow-effect-right {\n  position: absolute;\n  width: 150px;\n  height: 150px;\n  border-radius: 50%;\n  filter: blur(30px);\n  transition: all 0.3s ease;\n}\n\n.neon-search-container .glow-effect-left {\n  top: -40px;\n  left: -30px;\n  background: radial-gradient(circle, var(--glow-color-1) 0%, transparent 70%);\n}\n\n.neon-search-container .glow-effect-right {\n  bottom: -40px;\n  right: -30px;\n  background: radial-gradient(circle, var(--glow-color-2) 0%, transparent 70%);\n}\n\n.neon-search-container .search-bar {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  display: flex;\n  align-items: center;\n  width: 350px;\n  height: 60px;\n  background: var(--search-bar-gradient);\n  border-radius: 8px;\n  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);\n  overflow: visible;\n  transition: all 0.3s ease;\n}\n\n.neon-search-container .search-bar::before,\n.neon-search-container .search-bar::after {\n  content: "";\n  position: absolute;\n  width: 60%;\n  height: 60%;\n  pointer-events: none;\n  transition: all 0.3s ease;\n}\n\n.neon-search-container .search-bar::before {\n  top: 0;\n  left: 0;\n  background: linear-gradient(to right, var(--bor', colors: '', radii: '50%,6px,8px', shadows: '0 4px 6px rgba(0, 0, 0, 0.1),0 2px 4px rgba(0, 0, 0, 0.2),0 0 15px rgba(255, 100, 220, 0.3),\n    0 0 15px rgba(120, 100, 255, 0.3)', techniques: 'glassmorphism,3d-transform,glow-shadow,gradient,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'MijailVillegas_grumpy-horse-85', cat: 'Inputs', author: 'MijailVillegas', tags: 'cyberpunk,input,neon,futuristic', html: '<form class="container" action="">\n  <div class="input-container">\n    <div class="input-content">\n      <div class="input-dist">\n        <div class="input-type">\n          <input class="input-is" type="text" required="" placeholder="User" />\n          <input\n            class="input-is"\n            type="password"\n            required=""\n            placeholder="Password"\n          />\n        </div>\n      </div>\n    </div>\n  </div>\n  <button class="submit-button">Log in</button>\n</form>', css: '\n/* From Uiverse.io by MijailVillegas  - Tags: cyberpunk, input, neon, futuristic */\n/*The eye icon on the password can be stylize with any tool you want\nto use (the only way i know to do this correctly is using JS)\nthis is meant to be wide supported and it really depends on you browsers\nif i realize any way to stylize the eye it could be added in the future\nin other input type*/\n\n.container {\n  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;\n  font-style: italic;\n  font-weight: bold;\n  display: flex;\n  margin: auto;\n  aspect-ratio: 16/9;\n  align-items: center;\n  justify-items: center;\n  justify-content: center;\n  flex-wrap: nowrap;\n  flex-direction: column;\n  gap: 1em;\n}\n\n.input-container {\n  filter: drop-shadow(46px 36px 24px #4090b5)\n    drop-shadow(-55px -40px 25px #9e30a9);\n  animation: blinkShadowsFilter 8s ease-in infinite;\n}\n\n.input-content {\n  display: grid;\n  align-content: center;\n  justify-items: center;\n  align-items: center;\n  text-align: center;\n  padding-inline: 1em;\n}\n\n.input-content::before {\n  content: "";\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  filter: blur(40px);\n  -webkit-clip-path: polygon(\n    26% 0,\n    66% 0,\n    92% 0,\n    100% 8%,\n    100% 89%,\n    91% 100%,\n    7% 100%,\n    0 92%,\n    0 0\n  );\n  clip-path: polygon(\n    26% 0,\n    66% 0,\n    92% 0,\n    100% 8%,\n    100% 89%,\n    91% 100%,\n    7% 100%,\n    0 92%,\n    0 0\n  );\n  background: rgba(122, 251, 255, 0.5568627451);\n  transition: all 1s ease-in-out;\n}\n\n.input-content::after {\n  content: "";\n  position: absolute;\n  width: 98%;\n  height: 98%;\n  box-shadow: inset 0px 0px 20px 20px #212121;\n  background: repeating-linear-gradient(\n      to bottom,\n      transparent 0%,\n      rgba(64, 144, 181, 0.6) 1px,\n      rgb(0, 0, 0) 3px,\n      hsl(295, 60%, 12%) 5px,\n      #153544 4px,\n      transparent 0.5%\n    ),\n    repeating-linear-gradient(\n      to left,\n      hsl(295, 60%, 12%) 100%,\n      hsla(295, 60%, 12%, 0.99) 100%\n    );\n  -webkit-clip-path: polygon(\n    ', colors: '#212121,#153544,#4090b5,#9e30a9,#fff', radii: '', shadows: 'inset 0px 0px 20px 20px #212121,inset 0px 20px 20px 30px #212121,inset 0px -20px 20px 30px hsl(297, 42%, 10%)', techniques: 'glassmorphism,3d-transform,glow-shadow,gradient,animation,clip-path,pseudo-elements'),
