0.1), 0 0 10px rgba(0, 0, 0, 0.2) inset; /* Improved box-shadow on hover */\n  background: linear-gradient(to right, #e6e6e6, #f9f9f9);\n  border-color: #999;\n}\n\n.clear-button {\n  position: absolute;\n  top: 50%;\n  right: 20px;\n  transform: translateY(-50%);\n  color: #999;\n  cursor: pointer;\n  opaci', colors: '#999,#c2f0c2,#f9f9f9,#e6e6e6,#5c5c5c,#ccc,#f5f5f5,#f8f8f8,#f0f0f0,#d9d9d9', radii: '15px,50%,8px', shadows: '0 2px 5px rgba(0, 0, 0, 0.1), 0 0 5px rgba(0, 0, 0, 0.2) inset,0 2px 5px rgba(0, 0, 0, 0.1), 0 0 10px rgba(0, 0, 0, 0.2) inset,0 2px 5px rgba(0, 0, 0, 0.1), 0 0 10px rgba(0, 0, 0, 0.2) inset', techniques: '3d-transform,glow-shadow,text-shadow,gradient,animation,filter-effect,perspective'),
const GalaxyComp(id: 'John-CFO_spicy-horse-10', cat: 'Forms', author: 'John-CFO', tags: 'sign-in,form,sign-up,login,login form', html: '<form class="form">\n     <div class="form-title"><span>sign in to your</span></div>\n      <div class="title-2"><span>SPACE</span></div>\n      <div class="input-container">\n        <input class="input-mail" type="email" placeholder="Enter email">\n        <span> </span>\n      </div>\n\n      <section class="bg-stars">\n        <span class="star"></span>\n        <span class="star"></span>\n        <span class="star"></span>\n        <span class="star"></span>\n      </section>\n\n      <div class="input-container">\n        <input class="input-pwd" type="password" placeholder="Enter password">\n      </div>\n      <button type="submit" class="submit">\n        <span class="sign-text">Sign in</span>\n      </button>\n\n      <p class="signup-link">\n        No account?\n        <a href="" class="up">Sign up!</a>\n      </p>\n       \n   </form>', css: '\n/* From Uiverse.io by John-CFO - Tags: sign-in, form, sign-up, login , login form */\n.form {\n  position: relative;\n  display: block;\n  padding: 2.2rem;\n  max-width: 350px;\n  background: linear-gradient(14deg, rgba(2,0,36, 0.8) 0%, rgba(24, 24, 65, 0.7) 66%, \n            rgb(20, 76, 99) 100%), radial-gradient(circle, rgba(2,0,36, 0.5) 0%, \n            rgba(32, 15, 53, 0.2) 65%, rgba(14, 29, 28, 0.9) 100%);\n  border: 2px solid #fff;\n  -webkit-box-shadow: rgba(0,212,255) 0px 0px 50px -15px;\n  box-shadow: rgba(0,212,255) 0px 0px 50px -15px;\n  overflow: hidden;\n  z-index: +1;\n}\n\n/*------input and submit section-------*/\n\n.input-container {\n  position: relative;\n}\n\n.input-container input, .form button {\n  outline: none;\n  border: 2px solid #ffffff;\n  margin: 8px 0;\n  font-family: monospace;\n}\n\n.input-container input {\n  background-color: #fff;\n  padding: 6px;\n  font-size: 0.875rem;\n  line-height: 1.25rem;\n  width: 250px;\n  box-shadow: 0 1px 2px 0 rgba(0, 0, 0, 0.05);\n}\n\n.input-mail:focus::placeholder {\n  opacity: 0;\n  transition: opacity .9s;\n}\n\n.input-pwd:focus::placeholder {\n  opacity: 0;\n  transition: opacity .9s;\n}\n\n.submit {\n  position: relative;\n  display: block;\n  padding: 8px;\n  background-color: #c0c0c0;\n  color: #ffffff;\n  text-shadow: 1px 1px 1px rgba(0, 0, 0, 0.5);\n  font-size: 0.875rem;\n  line-height: 1.25rem;\n  font-weight: 500;\n  width: 100%;\n  text-transform: uppercase;\n  overflow: hidden;\n}\n\n.submit:hover {\n  -webkit-transition: all 0.2s ease-out;\n  -moz-transition: all 0.2s ease-out;\n  transition: all 0.2s ease-out;\n  border-radius: 3.9px;\n  box-shadow: 4px 5px 17px -4px #ffffff;\n  cursor: pointer;\n}\n\n.submit:hover::before {\n  -webkit-animation: sh02 0.5s 0s linear;\n  -moz-animation: sh02 0.5s 0s linear;\n  animation: sh02 .5s 0s linear;\n}\n\n.submit::before {\n  content: \'\';\n  display: block;\n  width: 0px;\n  height: 85%;\n  position: absolute;\n  top: 50%;\n  left: 0%;\n  opacity: 0;\n  background: #fff;\n  box-shadow: 0 0 50px 30px #fff;\n  -webkit-transform: sk', colors: '#cecece,#c0c0c0,#ffffff,#fff', radii: '50%,3.9px', shadows: 'rgba(0,212,255) 0px 0px 50px -15px,rgba(0,212,255) 0px 0px 50px -15px,0 1px 2px 0 rgba(0, 0, 0, 0.05)', techniques: '3d-transform,glow-shadow,text-shadow,gradient,animation,typography-transform,pseudo-elements'),
