 linear-gradient(85deg, #FEC195, #fcc196, #fabd92, #fac097, #fac39c);\n  animation: wind 2s ease-in-out infinite;\n}\n\n@keyframes wind {\n  0% {\n    background-position: 0% 50%;\n  }\n\n  0% {\n    background-position: 50% 100%;\n  }\n\n  0% {\n    background-position: 0% 50%;\n  }\n}\n\n.icon-1 {\n  position: absolute;\n  top: 0;\n  right: 0;\n  width: 25px;\n  transform-origin: 0 0;\n  transform: rotate(10deg);\n  transition: all .5s ease-in-out;\n  filter: drop-shadow(2px 2px 3px rgba(0, 0, 0, .3));\n}\n\nbutton:hover .icon-1 {\n  animation: slay-1 3s cubic-bezier(0.52, 0, 0.58, 1) infinite;\n  transform: rotate(10deg);\n}\n\n@keyframes slay-1 {\n  0% {\n    transform: rotate(10deg);\n  }\n\n  50% {\n    transform: rotate(-5deg);\n  }\n\n  100% {\n    transform: rotate(10deg);\n  }\n}\n\n.icon-2 {\n  position: absolute;\n  top: 0;\n  left: 25px;\n  width: 12px;\n  transform-origin: 50% 0;\n  transform: rotate(10deg);\n  transition: all 1s ease-in-out;\n  filter: drop-shadow(2px 2px 3px rgba(0, 0, 0, .5));\n}\n\nbutton:hover .icon-2 {\n  animation: slay-2 3s cubic-bezier(0.52, 0, 0.58, 1) 1s infinite;\n  transform: rotate(0);\n}\n\n@keyframes slay-2 {\n  0% {\n    transform: rotate(0deg);\n  }\n\n  50% {\n    transform: rotate(15deg);\n  }\n\n  100% {\n    transform: rotate(0);\n  }\n}\n\n.icon-3 {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 18px;\n  transform-origin: 50% 0;\n  transform: rotate(-5deg);\n  transition: all 1s ease-in-out;\n  filter: drop-shadow(2px 2px 3px rgba(0, 0, 0, .5));\n}\n\nbutton:hover .icon-3 {\n  animation: slay-3 2s cubic-bezier(0.52, 0, 0.58, 1) 1s infinite;\n  transform: rotate(0);\n}\n\n@keyframes slay-3 {\n  0% {\n    transform: rotate(0deg);\n  }\n\n  50% {\n    transf', colors: '#fcc196,#fabd92,#181818,#fec195,#f3b182,#fac097,#fac39c', radii: '8px', shadows: '', techniques: 'cubic-bezier,3d-transform,gradient,animation,filter-effect,svg-icon'),
const GalaxyComp(id: 'MuhammadHasann_mean-bird-62', cat: 'Buttons', author: '', tags: '', html: '<button class="button">\n  <div class="dots_border"></div>\n  <svg\n    xmlns="http://www.w3.org/2000/svg"\n    fill="none"\n    viewBox="0 0 24 24"\n    class="sparkle"\n  >\n    <path\n      class="path"\n      stroke-linejoin="round"\n      stroke-linecap="round"\n      stroke="black"\n      fill="black"\n      d="M14.187 8.096L15 5.25L15.813 8.096C16.0231 8.83114 16.4171 9.50062 16.9577 10.0413C17.4984 10.5819 18.1679 10.9759 18.903 11.186L21.75 12L18.904 12.813C18.1689 13.0231 17.4994 13.4171 16.9587 13.9577C16.4181 14.4984 16.0241 15.1679 15.814 15.903L15 18.75L14.187 15.904C13.9769 15.1689 13.5829 14.4994 13.0423 13.9587C12.5016 13.4181 11.8321 13.0241 11.097 12.814L8.25 12L11.096 11.187C11.8311 10.9769 12.5006 10.5829 13.0413 10.0423C13.5819 9.50162 13.9759 8.83214 14.186 8.097L14.187 8.096Z"\n    ></path>\n    <path\n      class="path"\n      stroke-linejoin="round"\n      stroke-linecap="round"\n      stroke="black"\n      fill="black"\n      d="M6 14.25L5.741 15.285C5.59267 15.8785 5.28579 16.4206 4.85319 16.8532C4.42059 17.2858 3.87853 17.5927 3.285 17.741L2.25 18L3.285 18.259C3.87853 18.4073 4.42059 18.7142 4.85319 19.1468C5.28579 19.5794 5.59267 20.1215 5.741 20.715L6 21.75L6.259 20.715C6.40725 20.1216 6.71398 19.5796 7.14639 19.147C7.5788 18.7144 8.12065 18.4075 8.714 18.259L9.75 18L8.714 17.741C8.12065 17.5925 7.5788 17.2856 7.14639 16.853C6.71398 16.4204 6.40725 15.8784 6.259 15.285L6 14.25Z"\n    ></path>\n    <path\n      class="path"\n      stroke-linejoin="round"\n      stroke-line', css: '\n/* From Uiverse.io by MuhammadHasann  - Website: https://twitter.com/jh3yy/status/1639001228985225228 - Name: Jhey - Tags: simple, neumorphism, button */\n.button {\n  --black-700: hsla(0 0% 12% / 1);\n  --border_radius: 9999px;\n  --transtion: 0.3s ease-in-out;\n  --offset: 2px;\n\n  cursor: pointer;\n  position: relative;\n\n  display: flex;\n  align-items: center;\n  gap: 0.5rem;\n\n  transform-origin: center;\n\n  padding: 1rem 2rem;\n  background-color: transparent;\n\n  border: none;\n  border-radius: var(--border_radius);\n  transform: scale(calc(1 + (var(--active, 0) * 0.1)));\n\n  transition: transform var(--transtion);\n}\n\n.button::before {\n  content: "";\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n\n  width: 100%;\n  height: 100%;\n  background-color: var(--black-700);\n\n  border-radius: var(--border_radius);\n  box-shadow: inset 0 0.5px hsl(0, 0%, 100%), inset 0 -1px 2px 0 hsl(0, 0%, 0%),\n    0px 4px 10px -4px hsla(0 0% 0% / calc(1 - var(--active, 0))),\n    0 0 0 calc(var(--active, 0) * 0.375rem) hsl(260 97% 50% / 0.75);\n\n  transition: all var(--transtion);\n  z-index: 0;\n}\n\n.button::after {\n  content: "";\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n\n  width: 100%;\n  height: 100%;\n  background-color: hsla(260 97% 61% / 0.75);\n  background-image: radial-gradient(\n      at 51% 89%,\n      hsla(266, 45%, 74%, 1) 0px,\n      transparent 50%\n    ),\n    radial-gradient(at 100% 100%, hsla(266, 36%, 60%, 1) 0px, transparent 50%),\n    radial-gradient(at 22% 91%, hsla(266, 36%, 60%, 1) 0px, transparent 50%);\n  background-position: top;\n\n  opacity: var(--active, 0);\n  border-radius: var(--border_radius);\n  transition: opacity var(--transtion);\n  z-index: 2;\n}\n\n.button:is(:hover, :focus-visible) {\n  --active: 1;\n}\n.button:active {\n  transform: scale(1);\n}\n\n.button .dots_border {\n  --size_border: calc(100% + 2px);\n\n  overflow: hidden;\n\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n\n  ', colors: '', radii: 'var(--border_radius)', shadows: 'inset 0 0.5px hsl(0, 0%, 100%), inset 0 -1px 2px 0 hsl(0, 0%, 0%),\n    0px 4px 10px -4px hsla(0 0% 0% / calc(1 - var(--a', techniques: '3d-transform,glow-shadow,gradient,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'MuhammadHasann_old-wombat-33', cat: 'Buttons', author: 'MuhammadHasann', tags: 'button', html: '<button>\n  Button\n</button>', css: '\n/* From Uiverse.io by MuhammadHasann - Tags: button */\nbutton {\n  position: relative;\n  padding: 18px 55px;\n  font-size: 15px;\n  font-weight: bold;\n  color: #fff;\n  background: linear-gradient(87deg, #6d67e4, #7743db, #4e31aa, #6d67e4, #6d67e4);\n  background-size: 600% 600%;\n  border: 3px solid #7743db;\n  border-radius: 8px;\n  /* filter: drop-shadow(0 0 4px #9F73AB); */\n  box-shadow: inset 0 0 10px 1px #7743db, 0 0 10px 5px #7743db;\n  cursor: pointer;\n  transition: all 0.5s;\n  animation: GradientAnimation 25s ease infinite;\n}\n\nbutton::after {\n  content: "";\n  position: absolute;\n  width: 202px;\n  height: 54px;\n  top: 0;\n  left: -17px;\n  border: 5px solid #453c67;\n  border-width: 0 2px 4px 0;\n  border-radius: 100%;\n  filter: drop-shadow(0px 0px 6px rgba(78, 49, 180, 1));\n  transform: rotate(-30deg);\n  animation: LinerAfter 15s ease infinite;\n}\n\nbutton::before {\n  content: "";\n  position: absolute;\n  width: 200px;\n  height: 50px;\n  top: 0;\n  left: -20px;\n  border: 5px solid #6d67e4;\n  border-width: 0 12px 8px 4px;\n  border-radius: 100%;\n  filter: drop-shadow(0px 0px 6px rgba(109, 103, 228, 1));\n  /* box-shadow: inset 0 0 10px 1px #4E31AA, 0 0 10px 5px #4E31AA; */\n  transform: rotate(-30deg);\n  transition: all 0.5s;\n  animation: LinerBefore 15s ease infinite;\n}\n\n@keyframes GradientAnimation {\n  0% {\n    background-position: 0% 50%;\n  }\n\n  50% {\n    background-position: 100% 50%;\n  }\n\n  100% {\n    background-position: 0% 50%;\n  }\n}\n\n@keyframes LinerAfter {\n  0% {\n    left: -27px;\n    height: 54px;\n  }\n\n  50% {\n    left: -7px;\n    height: 37px;\n  }\n\n  100% {\n    left: -27px;\n    height: 54px;\n  }\n}\n\n@keyframes LinerBefore {\n  0% {\n    left: -30px;\n    height: 50px;\n  }\n\n  50% {\n    left: -10px;\n    height: 33px;\n  }\n\n  100% {\n    left: -30px;\n    height: 50px;\n  }\n}\n\n', colors: '#7743db,#6d67e4,#4e31aa,#9f73ab,#fff,#453c67', radii: '100%,8px', shadows: 'inset 0 0 10px 1px #7743db, 0 0 10px 5px #7743db,inset 0 0 10px 1px #4E31AA, 0 0 10px 5px #4E31AA', techniques: '3d-transform,glow-shadow,gradient,animation,filter-effect,pseudo-elements'),
const GalaxyComp(id: 'namecho_slippery-moth-23', cat: 'Buttons', author: 'namecho', tags: 'button,glitch', html: '<button> HOVER ME\n</button>', css: '\n/* From Uiverse.io by namecho - Tags: button, glitch */\nbutton,\nbutton::after {\n padding: 16px 20px;\n font-size: 18px;\n background: linear-gradient(45deg, transparent 5%, #ff013c 5%);\n border: 0;\n color: #fff;\n letter-spacing: 3px;\n line-height: 1;\n box-shadow: 6px 0px 0px #00e6f6;\n outline: transparent;\n position: relative;\n}\n\nbutton::after {\n --slice-0: inset(50% 50% 50% 50%);\n --slice-1: inset(80% -6px 0 0);\n --slice-2: inset(50% -6px 30% 0);\n --slice-3: inset(10% -6px 85% 0);\n --slice-4: inset(40% -6px 43% 0);\n --slice-5: inset(80% -6px 5% 0);\n content: "HOVER ME";\n display: block;\n position: absolute;\n top: 0;\n left: 0;\n right: 0;\n bottom: 0;\n background: linear-gradient(45deg, transparent 3%, #00e6f6 3%, #00e6f6 5%, #ff013c 5%);\n text-shadow: -3px -3px 0px #f8f005, 3px 3px 0px #00e6f6;\n clip-path: var(--slice-0);\n}\n\nbutton:hover::after {\n animation: 1s glitch;\n animation-timing-function: steps(2, end);\n}\n\n@keyframes glitch {\n 0% {\n  clip-path: var(--slice-1);\n  transform: translate(-20px, -10px);\n }\n\n 10% {\n  clip-path: var(--slice-3);\n  transform: translate(10px, 10px);\n }\n\n 20% {\n  clip-path: var(--slice-1);\n  transform: translate(-10px, 10px);\n }\n\n 30% {\n  clip-path: var(--slice-3);\n  transform: translate(0px, 5px);\n }\n\n 40% {\n  clip-path: var(--slice-2);\n  transform: translate(-5px, 0px);\n }\n\n 50% {\n  clip-path: var(--slice-3);\n  transform: translate(5px, 0px);\n }\n\n 60% {\n  clip-path: var(--slice-4);\n  transform: translate(5px, 10px);\n }\n\n 70% {\n  clip-path: var(--slice-2);\n  transform: translate(-10px, 10px);\n }\n\n 80% {\n  clip-path: var(--slice-5);\n  transform: translate(20px, -10px);\n }\n\n 90% {\n  clip-path: var(--slice-1);\n  transform: translate(-10px, 0px);\n }\n\n 100% {\n  clip-path: var(--slice-1);\n  transform: translate(0);\n }\n}\n\n', colors: '#00e6f6,#fff,#ff013c,#f8f005', radii: '', shadows: '6px 0px 0px #00e6f6', techniques: 'glow-shadow,text-shadow,gradient,animation,clip-path,pseudo-elements'),
const GalaxyComp(id: 'Nawsome_unlucky-mayfly-5', cat: 'Buttons', author: 'Nawsome', tags: 'icon,animation,button', html: '<button class="continue-application">\n    <div>\n        <div class="pencil"></div>\n        <div class="folder">\n            <div class="top">\n                <svg viewBox="0 0 24 27">\n                    <path d="M1,0 L23,0 C23.5522847,-1.01453063e-16 24,0.44771525 24,1 L24,8.17157288 C24,8.70200585 23.7892863,9.21071368 23.4142136,9.58578644 L20.5857864,12.4142136 C20.2107137,12.7892863 20,13.2979941 20,13.8284271 L20,26 C20,26.5522847 19.5522847,27 19,27 L1,27 C0.44771525,27 6.76353751e-17,26.5522847 0,26 L0,1 C-6.76353751e-17,0.44771525 0.44771525,1.01453063e-16 1,0 Z"></path>\n                </svg>\n            </div>\n            <div class="paper"></div>\n        </div>\n    </div>\n    Continue Application\n</button>', css: '\n/* From Uiverse.io by Nawsome - Tags: icon, animation, button */\n.continue-application {\n  --color: #fff;\n  --background: #404660;\n  --background-hover: #3A4059;\n  --background-left: #2B3044;\n  --folder: #F3E9CB;\n  --folder-inner: #BEB393;\n  --paper: #FFFFFF;\n  --paper-lines: #BBC1E1;\n  --paper-behind: #E1E6F9;\n  --pencil-cap: #fff;\n  --pencil-top: #275EFE;\n  --pencil-middle: #fff;\n  --pencil-bottom: #5C86FF;\n  --shadow: rgba(13, 15, 25, .2);\n  border: none;\n  outline: none;\n  cursor: pointer;\n  position: relative;\n  border-radius: 5px;\n  font-size: 14px;\n  font-weight: 500;\n  line-height: 19px;\n  -webkit-appearance: none;\n  -webkit-tap-highlight-color: transparent;\n  padding: 17px 29px 17px 69px;\n  transition: background 0.3s;\n  color: var(--color);\n  background: var(--bg, var(--background));\n}\n\n.continue-application > div {\n  top: 0;\n  left: 0;\n  bottom: 0;\n  width: 53px;\n  position: absolute;\n  overflow: hidden;\n  border-radius: 5px 0 0 5px;\n  background: var(--background-left);\n}\n\n.continue-application > div .folder {\n  width: 23px;\n  height: 27px;\n  position: absolute;\n  left: 15px;\n  top: 13px;\n}\n\n.continue-application > div .folder .top {\n  left: 0;\n  top: 0;\n  z-index: 2;\n  position: absolute;\n  transform: translateX(var(--fx, 0));\n  transition: transform 0.4s ease var(--fd, 0.3s);\n}\n\n.continue-application > div .folder .top svg {\n  width: 24px;\n  height: 27px;\n  display: block;\n  fill: var(--folder);\n  transform-origin: 0 50%;\n  transition: transform 0.3s ease var(--fds, 0.45s);\n  transform: perspective(120px) rotateY(var(--fr, 0deg));\n}\n\n.continue-application > div .folder:before, .continue-application > div .folder:after,\n.continue-application > div .folder .paper {\n  content: "";\n  position: absolute;\n  left: var(--l, 0);\n  top: var(--t, 0);\n  width: var(--w, 100%);\n  height: var(--h, 100%);\n  border-radius: 1px;\n  background: var(--b, var(--folder-inner));\n}\n\n.continue-application > div .folder:before {\n  box-shadow: 0 1.5px 3px var(--shadow), 0 2.5px ', colors: '#275efe,#f3e9cb,#beb393,#5c86ff,#2b3044,#bbc1e1,#3a4059,#e1e6f9,#404660,#ffffff', radii: '5px 0 0 5px,1px 1px 0 0,var(--br, 2px 2px 0 0),1px,5px', shadows: '0 1.5px 3px var(--shadow), 0 2.5px 5px var(--shadow), 0 3.5px 7px var(--shadow),0 12px 0 0 var(--paper-lines), 0 24px 0 0 var(--paper-lines)', techniques: '3d-transform,glow-shadow,gradient,clip-path,perspective,svg-icon'),
const GalaxyComp(id: 'NguyenHaiNam24082000_nervous-insect-23', cat: 'Buttons', author: 'NguyenHaiNam24082000', tags: 'skeuomorphism,button,emergency', html: '<div class="background-button">\n  <button class="button">\n    EMERGENCY\n  </button>\n</div>', css: '\n/* From Uiverse.io by NguyenHaiNam24082000 - Tags: skeuomorphism, button, emergency */\n.background-button {\n  background: repeating-linear-gradient(\n    45deg,\n    #3c2209 0 20px,\n    #ff9c00 20px 40px\n  );\n  width: 10em;\n  height: 10em;\n  -webkit-box-shadow: 15px 15px 50px 5px #5f5f5f;\n  box-shadow: 15px 15px 50px 5px #5f5f5f;\n  position: relative;\n  display: inline-block;\n  outline: 2px solid black;\n}\n\n.background-button::before {\n  content: "";\n  display: inline-block;\n  position: absolute;\n  top: 15%;\n  left: 15%;\n  width: 70%;\n  height: 70%;\n  background: #a0b8c4;\n  border: 2px solid #3c2209;\n}\n\n.button {\n  background: #cc2a1f;\n  width: 65%;\n  height: 65%;\n  border-radius: 50%;\n  position: absolute;\n  top: 7.5%;\n  left: 18.25%;\n  color: white;\n  font-size: 1em;\n  font-weight: 900;\n  font-family: \'Courier New\', Courier, monospace;\n  -webkit-box-shadow: 0 15px 0 0 #842a2a;\n  box-shadow: 0 15px 0 0 #842a2a;\n  -webkit-transition: all .5s ease;\n  transition: all .5s ease;\n  border: 2px solid black;\n}\n\n.button:active {\n  -webkit-box-shadow: 0 1px 1px 1px #8C0606;\n  box-shadow: 0 1px 1px 1px #8C0606;\n  top: 15%;\n}\n\n.background-button:has(.button:active) + .emergency {\n  display: block;\n  -webkit-transform: rotate(0deg) scaleY(1);\n  -ms-transform: rotate(0deg) scaleY(1);\n  transform: rotate(0deg) scaleY(1);\n  -webkit-animation: anims 0.25s cubic-bezier(0.075, 0.82, 0.165, 1);\n  animation: anims 0.25s cubic-bezier(0.075, 0.82, 0.165, 1);\n}\n\n@keyframes anims {\n  0% {\n    -webkit-transform: rotate(-30deg) scaleY(0.25);\n    transform: rotate(-30deg) scaleY(0.25);\n  }\n\n  100% {\n    -webkit-transform: rotate(0deg) scaleY(1);\n    transform: rotate(0deg) scaleY(1);\n  }\n}\n\n.emergency {\n  position: absolute;\n  display: none;\n}\n\n', colors: '#a0b8c4,#842a2a,#ff9c00,#cc2a1f,#8c0606,#3c2209,#5f5f5f', radii: '50%', shadows: '15px 15px 50px 5px #5f5f5f,15px 15px 50px 5px #5f5f5f,0 15px 0 0 #842a2a', techniques: 'cubic-bezier,3d-transform,glow-shadow,gradient,animation,pseudo-elements'),
