const GalaxyComp(id: 'pminedev_sharp-gecko-68', cat: 'Buttons', author: 'pminedev', tags: 'button', html: '<button class="space-button">\n      <div class="butonTxt">launch</div>\n      <div class="sol">\n        \n        <svg xmlns="http://www.w3.org/2000/svg" id="svg22" viewBox="0 0 1983.9 1765.4" version="1.1">\n          \n          <defs id="defs8">\n            \n            <filter color-interpolation-filters="sRGB" height="1.4131172" width="1.4131172" y="-0.20655862" x="-0.20655862" id="d">\n              <feGaussianBlur id="feGaussianBlur2" stdDeviation="41.065573"></feGaussianBlur>\n            </filter>\n            <filter color-interpolation-filters="sRGB" height="1.3541005" width="1.3541005" y="-0.17705024" x="-0.17705024" id="e">\n              <feGaussianBlur id="feGaussianBlur5" stdDeviation="35.199063"></feGaussianBlur>\n            </filter>\n            <filter color-interpolation-filters="sRGB" height="1.4131172" width="1.4131172" y="-0.20655862" x="-0.20655862" id="d-6">\n              <feGaussianBlur id="feGaussianBlur2-9" stdDeviation="41.065573"></feGaussianBlur>\n            </filter>\n            <filter color-interpolation-filters="sRGB" height="1.3541005" width="1.3541005" y="-0.17705024" x="-0.17705024" id="e-7">\n              <feGaussianBlur id="feGaussianBlur5-6" stdDeviation="35.199063"></feGaussianBlur>\n            </filter>\n          </defs>\n          <path id="path944" d="M 14.914286,508.57739 V -308.72587 H 830.72607 1646.538 V 508.57739 1325.8807 H 830.72607 14.914286 Z M 924.33787,1179.0035 c 13.2878,-3.2008 30.7842,-6.7945 38.881,-7.986 8.0968,-1.1914 16.57', css: '\n/* From Uiverse.io by pminedev - Tags: button */\n.butonTxt {\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  display: flex;\n  margin-left: 27px;\n  margin-top: 3px;\n  align-items: center;\n  font-family: "Courier New", Courier, monospace;\n  letter-spacing: 1px;\n  font-weight: bold;\n  text-transform: uppercase;\n  z-index: 2;\n  color: rgb(42, 8, 73);\n  font-size: 30px;\n}\n\n.space-button {\n  position: relative;\n  width: 200px;\n  height: 80px;\n  border-radius: 25px;\n  border: 2px solid rgb(103, 20, 180);\n  background-color: blueviolet;\n  overflow: hidden;\n  background-image: radial-gradient(\n    circle at 80% 2rem,\n    rgb(192, 154, 228) 0%,\n    rgb(103, 20, 180) 100%\n  );\n  transition: background-image 1s ease-in-out;\n}\n\n.estrella {\n  position: absolute;\n  border-radius: 50%;\n  background: radial-gradient(\n    closest-side,\n    rgba(224, 224, 5, 0.678),\n    transparent\n  );\n  animation: brillar 8s ease-in-out infinite;\n  border: none;\n  z-index: 0;\n}\n\n.sol {\n  position: absolute;\n  top: 10px;\n  left: 10px;\n  width: 10px;\n  opacity: 0.4;\n  transform: scale(1);\n  transform-origin: center center;\n  transition: transform 0.5s ease;\n  z-index: 1;\n}\n/* ANIMACIONES */\n@keyframes girar {\n  from {\n    transform: rotate(0deg);\n  }\n\n  to {\n    transform: rotate(360deg);\n  }\n}\n\n@keyframes brillar {\n  0% {\n    background: radial-gradient(\n      closest-side,\n      rgba(224, 224, 5, 0.678),\n      transparent\n    );\n    box-shadow: outset 0 0 11px 0 rgba(224, 224, 5, 0.678);\n  }\n\n  10% {\n    box-shadow: 0 0 11px 3px rgb(255, 255, 0, 0.678);\n  }\n\n  20% {\n    background: radial-gradient(\n      closest-side,\n      rgba(224, 224, 5, 0.678),\n      transparent\n    );\n    box-shadow: none;\n  }\n}\n\n.space-button:hover {\n  cursor: pointer;\n  border: 2px solid #fff;\n}\n\n.space-button:hover .estrella {\n  animation: brillar 2s ease-in-out infinite;\n}\n\n.space-button:hover .butonTxt {\n  color: #fff;\n  font-size: 40px;\n}\n\n.space-button .butonTxt {\n  transition: font-size 1s ease-in-out;\n}\n\n/* gi', colors: '#fff', radii: '50%,25px', shadows: 'outset 0 0 11px 0 rgba(224, 224, 5, 0.678),0 0 11px 3px rgb(255, 255, 0, 0.678),none', techniques: '3d-transform,glow-shadow,gradient,animation,typography-transform,svg-icon'),
const GalaxyComp(id: 'Praashoo7_smooth-crab-52', cat: 'Buttons', author: 'Praashoo7', tags: 'social,twitter,instagram,button,discord,github,social media,rounded,button,text,gradient,blue,pink,hover,social', html: '<div class="main">\n  <div class="card">\n    <svg\n      fill-rule="nonzero"\n      height="30px"\n      width="30px"\n      viewBox="0,0,256,256"\n      xmlns:xlink="http://www.w3.org/1999/xlink"\n      xmlns="http://www.w3.org/2000/svg"\n      class="instagram"\n    >\n      <g\n        style="mix-blend-mode: normal"\n        text-anchor="none"\n        font-size="none"\n        font-weight="none"\n        font-family="none"\n        stroke-dashoffset="0"\n        stroke-dasharray=""\n        stroke-miterlimit="10"\n        stroke-linejoin="miter"\n        stroke-linecap="butt"\n        stroke-width="1"\n        stroke="none"\n        fill-rule="nonzero"\n      >\n        <g transform="scale(8,8)">\n          <path\n            d="M11.46875,5c-3.55078,0 -6.46875,2.91406 -6.46875,6.46875v9.0625c0,3.55078 2.91406,6.46875 6.46875,6.46875h9.0625c3.55078,0 6.46875,-2.91406 6.46875,-6.46875v-9.0625c0,-3.55078 -2.91406,-6.46875 -6.46875,-6.46875zM11.46875,7h9.0625c2.47266,0 4.46875,1.99609 4.46875,4.46875v9.0625c0,2.47266 -1.99609,4.46875 -4.46875,4.46875h-9.0625c-2.47266,0 -4.46875,-1.99609 -4.46875,-4.46875v-9.0625c0,-2.47266 1.99609,-4.46875 4.46875,-4.46875zM21.90625,9.1875c-0.50391,0 -0.90625,0.40234 -0.90625,0.90625c0,0.50391 0.40234,0.90625 0.90625,0.90625c0.50391,0 0.90625,-0.40234 0.90625,-0.90625c0,-0.50391 -0.40234,-0.90625 -0.90625,-0.90625zM16,10c-3.30078,0 -6,2.69922 -6,6c0,3.30078 2.69922,6 6,6c3.30078,0 6,-2.69922 6,-6c0,-3.30078 -2.69922,-6 -6,-6zM16,12c2.22266,0 4,1.77734 4,4c0,2.22266 -1.', css: '\n/* From Uiverse.io by Praashoo7  - Tags: social, twitter, instagram, button, Discord, github, social media, rounded, button, text, gradient, blue, pink, hover, social */\n.main_back {\n  position: absolute;\n  border-radius: 10px;\n  transform: rotate(90deg);\n  width: 11em;\n  height: 11em;\n  background: linear-gradient(270deg, #03a9f4, #cc39a4, #ffb5d2);\n  z-index: -2;\n  box-shadow: inset 0px 0px 180px 5px #ffffff;\n}\n\n.main {\n  display: flex;\n  flex-wrap: wrap;\n  width: 14em;\n  align-items: center;\n  justify-content: center;\n  z-index: -1;\n}\n\n.card {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  width: 60px;\n  height: 60px;\n  border-top-left-radius: 10px;\n  background: lightgrey;\n  transition: 0.4s ease-in-out, 0.2s background-color ease-in-out,\n    0.2s background-image ease-in-out;\n  background: rgba(255, 255, 255, 0.596);\n  backdrop-filter: blur(5px);\n  border: 1px solid transparent;\n  -webkit-backdrop-filter: blur(5px);\n}\n\n.card .instagram {\n  opacity: 0;\n  transition: 0.2s ease-in-out;\n  fill: #cc39a4;\n}\n\n.card:nth-child(2) {\n  border-radius: 0px;\n}\n\n.card:nth-child(2) .twitter {\n  opacity: 0;\n  transition: 0.2s ease-in-out;\n  fill: #03a9f4;\n}\n\n.card:nth-child(3) {\n  border-top-right-radius: 10px;\n  border-top-left-radius: 0px;\n}\n\n.card:nth-child(3) .dribble {\n  opacity: 0;\n  transition: 0.2s ease-in-out;\n  fill: #ffb5d2;\n}\n\n.card:nth-child(4) {\n  border-radius: 0px;\n}\n\n.card:nth-child(4) .codepen {\n  opacity: 0;\n  transition: 0.2s ease-in-out;\n  fill: black;\n}\n\n.card:nth-child(5) {\n  border-radius: 0px;\n}\n\n.card:nth-child(5) .uiverse {\n  position: absolute;\n  margin-left: 0.2em;\n  margin-top: 0.2em;\n  opacity: 0;\n  transition: 0.2s ease-in-out;\n}\n\n.card:nth-child(6) {\n  border-radius: 0px;\n}\n\n.card:nth-child(6) .discord {\n  opacity: 0;\n  transition: 0.2s ease-in-out;\n  fill: #8c9eff;\n}\n\n.card:nth-child(7) {\n  border-bottom-left-radius: 10px;\n  border-top-left-radius: 0px;\n}\n\n.card:nth-child(7) .github {\n  opacity: 0;\n  transition: 0.2s ease', colors: '#00ddeb,#ffb5d2,#bf66ff,#29b6f6,#8c9eff,#6248ff,#1e1f26,#03a9f4,#cc39a4,#ffffff', radii: '10px,0px', shadows: 'inset 0px 0px 180px 5p