const GalaxyComp(id: 'roroland_wonderful-owl-61', cat: 'Buttons', author: 'roroland', tags: 'glassmorphism,pink,gradient,button,rounded,smooth,colorful', html: '<button class="button">Join now</button>', css: '\n/* From Uiverse.io by roroland  - Tags: glassmorphism, pink, gradient, button, rounded, smooth, colorful */\n.button {\n  --radius: 20px;\n  --col0: 0, 0, 0;\n  --col1: 219, 161, 240;\n  --col2: 239, 214, 248;\n  --col3: 255, 255, 255;\n  --col4: 270, 153, 138;\n  --col5: 244, 164, 177;\n  --col6: 244, 136, 136;\n  --col7: 243, 136, 94;\n  --col8: 252, 187, 165;\n  --col9: 254, 230, 222;\n  --col10: 247, 197, 161;\n  --col11: 245, 205, 238;\n  --col12: 252, 67, 130;\n  position: relative;\n  background: linear-gradient(\n    65deg,\n    rgba(var(--col1), 0.81) 0%,\n    rgba(var(--col2), 0.81) 11%,\n    rgba(var(--col3), 0.81) 21%,\n    rgba(var(--col3), 0.81) 24%,\n    rgba(var(--col4), 0.5) 37%,\n    rgba(var(--col5), 0.81) 42%,\n    rgba(var(--col6), 0.81) 50%,\n    rgba(var(--col7), 0.9) 58%,\n    rgba(var(--col8), 0.81) 68%,\n    rgba(var(--col9), 0.81) 72%,\n    rgba(var(--col3), 0.81) 78%,\n    rgba(var(--col10), 0.81) 86%,\n    rgba(var(--col11), 0.81) 93%,\n    rgba(var(--col1), 0.81) 98%\n  );\n  background-size: 105%;\n  box-shadow: -10px 10px 0px rgba(var(--col0), 0.005),\n    0px 20px 30px rgba(var(--col0), 0.16),\n    inset 5px 0 20px rgba(var(--col1), 0.5),\n    inset -5px 20px 10px rgba(var(--col4), 0.5),\n    inset 1px 3px 3px rgba(var(--col0), 0.25),\n    inset 0px -5px 1px rgba(var(--col7), 0.5),\n    inset 0px -5px 1px rgba(var(--col2), 0.95),\n    inset 1px 2px 1px rgba(var(--col12), 0.15),\n    inset 5px 5px 1px rgba(var(--col12), 0.35),\n    inset -5px 5px 1px rgba(var(--col12), 0.15),\n    inset 0px -20px 10px rgba(var(--col12), 0.15);\n  cursor: pointer;\n  padding: 1rem 2rem;\n  min-height: 5rem;\n  min-width: 16rem;\n  font-size: 1rem;\n  padding-inline-start: 10%;\n  font-weight: 600;\n  filter: hue-rotate(0deg);\n  color: #505050;\n  border-radius: var(--radius);\n  appearance: none;\n  border: 0;\n  transition: all 3s ease-in-out;\n  z-index: 0;\n}\n.button:hover {\n  color: rgba(var(--col7), 1);\n  text-shadow: 2px 2px 5px rgba(var(--col1), 0.75);\n  background-size: 350%;\n  filter: hue-rotate(125d', colors: '#505050', radii: 'var(--radius),inherit', shadows: '-10px 10px 0px rgba(var(--col0), 0.005),\n    0px 20px 30px rgba(var(--col0), 0.16),\n    inset 5px 0 20px rgba(var(--col1,0,inset 0px 0px 20px rgba(var(--col1), 0.5),\n    0px 0px 1px rgba(var(--col2), 0.95)', techniques: 'glassmorphism,glow-shadow,text-shadow,gradient,clip-path,pseudo-elements'),
const GalaxyComp(id: 'ShrinilDhorda_pink-zebra-4', cat: 'Buttons', author: 'ShrinilDhorda', tags: 'gradient,button,active,modern,blur filter,svg,crush', html: '<button class="crushbtn">\n    crush\n    <div class="heart1">\n\n        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.5" stroke="currentColor" class="">\n            <path stroke-linecap="round" stroke-linejoin="round" d="M21 8.25c0-2.485-2.099-4.5-4.688-4.5-1.935 0-3.597 1.126-4.312 2.733-.715-1.607-2.377-2.733-4.313-2.733C5.1 3.75 3 5.765 3 8.25c0 7.22 9 12 9 12s9-4.78 9-12z"></path>\n        </svg>\n    </div>\n    <div class="heart2">\n\n        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.5" stroke="currentColor" class="">\n            <path stroke-linecap="round" stroke-linejoin="round" d="M21 8.25c0-2.485-2.099-4.5-4.688-4.5-1.935 0-3.597 1.126-4.312 2.733-.715-1.607-2.377-2.733-4.313-2.733C5.1 3.75 3 5.765 3 8.25c0 7.22 9 12 9 12s9-4.78 9-12z"></path>\n        </svg>\n    </div>\n    <div class="heart3">\n\n        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.5" stroke="currentColor" class="">\n            <path stroke-linecap="round" stroke-linejoin="round" d="M21 8.25c0-2.485-2.099-4.5-4.688-4.5-1.935 0-3.597 1.126-4.312 2.733-.715-1.607-2.377-2.733-4.313-2.733C5.1 3.75 3 5.765 3 8.25c0 7.22 9 12 9 12s9-4.78 9-12z"></path>\n        </svg>\n    </div>\n</button>', css: '\n/* From Uiverse.io by ShrinilDhorda - Tags: gradient, button, active, modern, blur filter, svg, crush */\n.crushbtn {\n  font-size: 2rem;\n  padding: 0.7rem 2.4rem;\n  letter-spacing: .3rem;\n  border-radius: 1.5rem;\n  position: relative;\n  background-color: #e8e8e8;\n  color: red;\n  border: none;\n  text-shadow: 0 0 3px #ff6e6e;\n  overflow: hidden;\n  cursor: pointer;\n  transition: 0.7s;\n  z-index: 2;\n}\n\n.heart1 svg {\n  position: absolute;\n  left: 4.5rem;\n  top: 1.8rem;\n  opacity: 0;\n  fill: red;\n  stroke: none;\n  transition: 0.7s;\n  width: 2rem;\n  height: 2rem;\n  animation: move1 5s ease-in-out infinite alternate-reverse;\n}\n\n.heart2 svg {\n  position: absolute;\n  left: 0.8rem;\n  opacity: 0;\n  top: 0.3rem;\n  width: 1.5rem;\n  height: 1.5rem;\n  fill: red;\n  stroke: none;\n  transform: rotate(-20deg );\n  animation: move2 5s ease infinite alternate-reverse;\n}\n\n.heart3 svg {\n  position: absolute;\n  right: 1rem;\n  top: 0.5rem;\n  opacity: 0;\n  width: 1.4rem;\n  height: 1.4rem;\n  transform: rotate(20deg);\n  fill: red;\n  stroke: none;\n  z-index: -1;\n  animation: move3 5s ease infinite alternate-reverse;\n}\n\n@keyframes move1 {\n  0% {\n    top: 2rem;\n  }\n\n  50% {\n    top: 4rem;\n  }\n\n  100% {\n    top: 2rem;\n  }\n}\n\n@keyframes move2 {\n  0% {\n    top: 0.3rem;\n  }\n\n  50% {\n    top: 1.5rem;\n  }\n\n  100% {\n    top: 0.3rem;\n  }\n}\n\n@keyframes move3 {\n  0% {\n    top: 1.5rem;\n  }\n\n  50% {\n    top: .6rem;\n  }\n\n  100% {\n    top: 1.5rem;\n  }\n}\n\n.crushbtn:hover .heart1 svg,\n.crushbtn:hover .heart2 svg,\n.crushbtn:hover .heart3 svg {\n  opacity: 1;\n  filter: drop-shadow(0 0 10px #ff6e6e)\n}\n\n.crushbtn:hover {\n  color: red;\n  box-shadow: 0 0 10px inset #ff6e6e;\n  scale: 105%;\n}\n\n.crushbtn:active {\n  scale: 100%;\n}\n', colors: '#ff6e6e,#e8e8e8', radii: '1.5rem', shadows: '0 0 10px inset #ff6e6e', techniques: '3d-transform,glow-shadow,text-shadow,gradient,animation,svg-icon'),
