\n  width: 2.5em;\n  height: .9em;\n  border-radius: 4px 4px 0 0;\n  background: linear-gradient(\n    -35deg,\n    rgb(25, 102, 218),\n    rgb(109, 165, 249));\n  box-shadow: 0 0 5px rgba(0, 0, 0, .4);\n}\n\n.folder_four {\n  left: 1em;\n  bottom: .3em;\n  width: 1.5em;\n  height: .18em;\n  border-radius: 1em;\n  background-color: rgb(20, 77, 163);\n  box-shadow: 0 0 10px rgba(0, 0, 0, .1);\n}\n\n.active_line {\n  content: \'\';\n  position: absolute;\n  bottom: 0;\n  width: .9em;\n  height: .4em;\n  background-color: #999;\n  bord', colors: '#999,#fff,#666', radii: '3px,.4em,4px 4px 0 0,1em,5px', shadows: '0 0 5px rgba(0, 0, 0, .3),0 1px 5px -2px rgba(0, 0, 0, .5),0 0 5px rgba(0, 0, 0, .4)', techniques: '3d-transform,glow-shadow,text-shadow,gradient,animation,pseudo-elements'),
const GalaxyComp(id: 'Spacious74_tidy-moose-60', cat: 'Buttons', author: 'Spacious74', tags: 'button', html: '<div class="btn-container">\n  <button class="button">\n    <span>Join Today </span>\n    <svg\n      viewBox="0 0 48 48"\n      height="1.2em"\n      width="1.2em"\n      class="svg"\n      xmlns="http://www.w3.org/2000/svg"\n    >\n      <path\n        d="M42 24H6m24-12l12 12l-12 12"\n        stroke-width="4"\n        stroke-linejoin="round"\n        stroke-linecap="round"\n        stroke="currentColor"\n        fill="none"\n      ></path>\n    </svg>\n  </button>\n</div>', css: '\n/* From Uiverse.io by Spacious74  - Tags: button */\n.btn-container {\n  padding: 3px;\n  background: linear-gradient(180deg, #f3aefe, #8d35d3);\n  border-radius: 19px;\n  transform: perspective(850px) rotateX(14deg) rotateY(8deg) rotateZ(-11deg);\n  color: white;\n  box-shadow:\n    -4px 4px 0px #5d2b82,\n    -5px 7px 8px #4d1e7491,\n    -10px 13px 18px #4d1e7450,\n    -20px 20px 40px #4d1e74a8;\n  position: relative;\n  transition: all 0.4s ease;\n}\n\n.btn-container:hover {\n  transform: rotateX(0deg) rotateY(0deg) rotateZ(0deg);\n  box-shadow:\n    0px 4px 5px #5d2b82,\n    0px 7px 8px #4d1e7491,\n    0px 13px 18px #4d1e7450,\n    0px 20px 40px #4d1e74a8;\n}\n.btn-container:active {\n  box-shadow:\n    0px 4px 5px #5c2b82c7,\n    0px 7px 8px #4d1e745b,\n    0px 5px 18px #4d1e7434,\n    0px 10px 40px #4d1e746e;\n}\n.btn-container:active > .button {\n  box-shadow: inset 0px 6px 10px #3114494b;\n}\n\n.button {\n  color: white;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  gap: 5px;\n  padding: 22px 24px;\n  font-size: 1.6rem;\n  font-weight: 600;\n  border-radius: 16px;\n  border: none;\n  background: linear-gradient(180deg, #d28dff, #8533c6);\n  box-shadow: inset 0px -6px 10px #3114494b;\n  text-shadow: -1px 1px 3px #2a0f3fbb;\n  transition: all 0.3s ease;\n}\n.svg {\n  margin-top: 2px;\n  font-weight: bold;\n  filter: drop-shadow(-2px 2px 1px #2a0f3f6c);\n}\n\n', colors: '#3114494b,#4d1e7491,#8533c6,#4d1e746e,#4d1e74a8,#f3aefe,#8d35d3,#d28dff,#4d1e7434,#2a0f3fbb', radii: '19px,16px', shadows: '-4px 4px 0px #5d2b82,\n    -5px 7px 8px #4d1e7491,\n    -10px 13px 18px #4d1e7450,\n    -20px 20px 40px #4d1e74a8,0px 4px 5px #5d2b82,\n    0px 7px 8px #4d1e7491,\n    0px 13px 18px #4d1e7450,\n    0px 20px 40px #4d1e74a8,0px 4px 5px #5c2b82c7,\n    0px 7px 8px #4d1e745b,\n    0px 5px 18px #4d1e7434,\n    0px 10px 40px #4d1e746e', techniques: '3d-transform,text-shadow,gradient,filter-effect,perspective,svg-icon'),
const GalaxyComp(id: 'vikas7754_calm-wombat-35', cat: 'Buttons', author: 'vikas7754', tags: '3d,button,3d button', html: '<button class="box">\n  Button\n</button>', css: '\n/* From Uiverse.io by vikas7754 - Tags: 3d, button, 3d button */\n.box {\n  background: linear-gradient(to right, gold, darkorange);\n  color: white;\n  --width: 200px;\n  --height: calc(var(--width) / 3);\n  width: var(--width);\n  height: var(--height);\n  text-align: center;\n  line-height: var(--height);\n  font-size: calc(var(--height) / 2.5);\n  font-family: sans-serif;\n  letter-spacing: 0.2em;\n  border: 1px solid darkgoldenrod;\n  border-radius: 2em;\n  transform: perspective(500px) rotateY(-15deg);\n  text-shadow: 6px 3px 2px rgba(0, 0, 0, 0.2);\n  box-shadow: 2px 0 0 5px rgba(76, 255, 97, 0.8);\n  transition: 0.5s;\n  position: relative;\n  overflow: hidden;\n  cursor: pointer;\n}\n\n.box:hover {\n  transform: perspective(500px) rotateY(15deg);\n  text-shadow: -6px 3px 2px rgba(0, 0, 0, 0.2);\n  box-shadow: -2px 0 0 5px rgba(35, 255, 218, 0.8);\n}\n\n.box::before {\n  content: \'\';\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  background: linear-gradient(to right, transparent, white, transparent);\n  left: -100%;\n  transition: 0.5s;\n}\n\n.box:hover::before {\n  left: 100%;\n}\n', colors: '', radii: '2em', shadows: '2px 0 0 5px rgba(76, 255, 97, 0.8),-2px 0 0 5px rgba(35, 255, 218, 0.8)', techniques: '3d-transform,glow-shadow,text-shadow,gradient,perspective,pseudo-elements'),
const GalaxyComp(id: 'Wasim-Rana_lazy-fish-83', cat: 'Buttons', author: 'Wasim-Rana', tags: 'button', html: '<div class="btn-container">\n  <button class="glowing-button">\n    click me\n    <span class="arrow">➔</span>\n  </button>\n</div>', css: '\n/* From Uiverse.io by Wasim-Rana  - Tags: button */\n.btn-container {\n  padding: 3px;\n  background: linear-gradient(180deg, #f3aefe, #8d35d3);\n  border-radius: 19px;\n  transform: perspective(850px) rotateX(14deg) rotateY(8deg) rotateZ(-11deg);\n  color: white;\n  box-shadow:\n    -4px 4px 0px #5d2b82,\n    -5px 7px 8px #4d1e7491,\n    -10px 13px 18px #4d1e7450,\n    -20px 20px 40px #4d1e74a8;\n  position: relative;\n  transition: all 0.4s ease;\n}\n\n.btn-container:hover {\n  transform: rotateX(0deg) rotateY(0deg) rotateZ(0deg);\n  box-shadow:\n    0px 4px 5px #5d2b82,\n    0px 7px 8px #4d1e7491,\n    0px 13px 18px #4d1e7450,\n    0px 20px 40px #4d1e74a8;\n}\n\n.btn-container:active {\n  box-shadow:\n    0px 4px 5px #5c2b82c7,\n    0px 7px 8px #4d1e745b,\n    0px 5px 18px #4d1e7434,\n    0px 10px 40px #4d1e746e;\n}\n\n.btn-container:active > .glowing-button {\n  box-shadow: inset 0px 6px 10px #3114494b;\n}\n\n.glowing-button {\n  color: white;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  gap: 5px;\n  padding: 22px 24px;\n  font-size: 1.6rem;\n  font-weight: 600;\n  border-radius: 16px;\n  border: none;\n  background: linear-gradient(180deg, #d28dff, #8533c6);\n  box-shadow: inset 0px -6px 10px #3114494b;\n  text-shadow: -1px 1px 3px #2a0f3fbb;\n  transition: all 0.3s ease;\n}\n\n.glowing-button:hover {\n  background: linear-gradient(180deg, #c17de6, #7328b8);\n  box-shadow:\n    inset 0px -10px 20px #3114498a,\n    0px 8px 15px #5d2b82;\n  transform: translateY(-2px);\n}\n\n.arrow {\n  font-size: 24px;\n  margin-left: 10px;\n  display: inline-block;\n  filter: drop-shadow(-2px 2px 1px #2a0f3f6c);\n  transition:\n    transform 0.3s ease,\n    color 0.3s ease;\n  animation: arrow-pulse 1.5s infinite alternate;\n}\n\n@keyframes arrow-pulse {\n  0% {\n    transform: translateX(0);\n    color: white;\n  }\n  100% {\n    transform: translateX(5px);\n    color: #f3aefe;\n  }\n}\n\n.glowing-button:hover .arrow {\n  transform: translateX(15px);\n  color: #e3a0ff;\n}\n\n', colors: '#3114494b,#4d1e746e,#f3aefe,#4d1e745b,#e3a0ff,#4d1e7450,#2a0f3f6c,#4d1e7491,#8533c6,#4d1e74a8', radii: '19px,16px', shadows: '-4px 4px 0px #5d2b82,\n    -5px 7px 8px #4d1e7491,\n    -10px 13px 18px #4d1e7450,\n    -20px 20px 40px #4d1e74a8,0px 4px 5px #5d2b82,\n    0px 7px 8px #4d1e7491,\n    0px 13px 18px #4d1e7450,\n    0px 20px 40px #4d1e74a8,0px 4px 5px #5c2b82c7,\n    0px 7px 8px #4d1e745b,\n    0px 5px 18px #4d1e7434,\n    0px 10px 40px #4d1e746e', techniques: '3d-transform,text-shadow,gradient,animation,filter-effect,perspective'),
const GalaxyComp(id: 'Yaya12085_serious-snake-25', cat: 'Buttons', author: 'Yaya12085', tags: 'glassmorphism,button,hover,hover effect,challenges', html: '<button class="button">\n  <svg\n    xmlns="http://www.w3.org/2000/svg"\n    fill="none"\n    viewBox="0 0 24 24"\n    class="icon"\n  >\n    <g stroke-width="0" id="SVGRepo_bgCarrier"></g>\n    <g\n      stroke-linejoin="round"\n      stroke-linecap="round"\n      id="SVGRepo_tracerCarrier"\n    ></g>\n    <g id="SVGRepo_iconCarrier">\n      <path\n        fill="#222222"\n        d="M11.5 13.8H10.1299C8.72143 13.8 8.01721 13.8 7.72228 13.3385C7.42735 12.8769 7.72321 12.2379 8.31493 10.9597L11.0463 5.06006C11.4205 4.25182 11.6075 3.8477 11.8038 3.89091C12 3.93413 12 4.37946 12 5.27013V9.7C12 9.9357 12 10.0536 12.0732 10.1268C12.1464 10.2 12.2643 10.2 12.5 10.2H13.8701C15.2786 10.2 15.9828 10.2 16.2777 10.6615C16.5726 11.1231 16.2768 11.7621 15.6851 13.0402L12.9537 18.9399C12.5795 19.7482 12.3925 20.1523 12.1962 20.1091C12 20.0659 12 19.6205 12 18.7299V14.3C12 14.0643 12 13.9464 11.9268 13.8732C11.8536 13.8 11.7357 13.8 11.5 13.8Z"\n      ></path>\n    </g>\n  </svg>\n  <span class="title">Join now</span>\n  <span class="border"></span>\n</button>', css: '\n/* From Uiverse.io by Yaya12085  - Tags: glassmorphism, button, hover, hover effect, challenges */\n.button {\n  --color1: #e3a4fb;\n  --color2: #fca7a6;\n  --color3: #fe986d;\n  --white: rgba(255, 255, 255, 0.9);\n  --white2: rgba(255, 255, 255, 0.6);\n  --white3: rgba(255, 255, 255, 0.4);\n  --white4: rgba(255, 255, 255, 0.2);\n  --white5: rgba(255, 255, 255, 0.1);\n  cursor: pointer;\n  padding: 10px 20px;\n  height: 40px;\n  width: 150px;\n  border-radius: 10px;\n  outline: none;\n  position: relative;\n  box-sizing: border-box;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  gap: 1px;\n  border: none;\n  background: transparent;\n  background-color: transparent;\n  transition: all 235ms ease-in-out;\n}\n\n.button::before,\n.button::after {\n  position: absolute;\n  content: "";\n  width: 120%;\n  height: 150%;\n  border-radius: 16px;\n  background-color: var(--color1);\n  background: linear-gradient(\n    55deg,\n    var(--color1) 10%,\n    var(--color2) 40%,\n    var(--color3) 60%,\n    var(--color1) 80%\n  );\n  transition: all 235ms ease-in-out;\n}\n\n.button::before {\n  filter: blur(2px);\n  z-index: -1;\n  border: 2px solid rgba(255, 255, 255, 0.2);\n  background: radial-gradient(\n      circle at 20% 50%,\n      var(--white2) 8%,\n      transparent 0%\n    ),\n    radial-gradient(circle at 25% 50%, var(--white2) 8%, transparent 0%),\n    radial-gradient(ellipse at 5% 90%, var(--white4) 8%, transparent 0%),\n    radial-gradient(ellipse at 5% 50%, var(--white4) 8%, transparent 0%),\n    radial-gradient(circle at 15% 80%, var(--white3) 3%, transparent 0%),\n    radial-gradient(ellipse at 15% 10%, var(--white2) 14%, transparent 0%),\n    radial-gradient(ellipse at 15% 25%, var(--white3) 10%, transparent 0%),\n    radial-gradient(circle at 50% 50%, var(--white4) 12%, transparent 0%),\n    radial-gradient(circle at 45% 25%, var(--white4) 12%, transparent 0%),\n    radial-gradient(circle at 50% 75%, var(--white4) 12%, transparent 0%),\n    radial-gradient(circle at 70% 50%, var(--white4) 12%, trans', colors: '#fff,#e3a4fb,#fe986d,#fca7a6', radii: '10px,16px,20px', shadows: 'rgba(0, 0, 0, 0.2) 15px 28px 25px -18px,0 0 0 2px rgba(255, 255, 255, 0.3),inset 0 0 0 2px rgba(0, 0, 0, 0.1)', techniques: 'glassmorphism,glow-shadow,gradient,css-mask,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'zebra76966_polite-ape-16', cat: 'Buttons', author: 'zebra76966', tags: 'animation,gradient,button,click animation', html: '<button class="rainbow-btn">\n  <div class="content">\n    <svg\n      viewBox="0 0 16 16"\n      class="bi bi-lightning-charge-fill"\n      fill="currentColor"\n      height="25"\n      width="25"\n      xmlns="http://www.w3.org/2000/svg"\n    >\n      <path\n        d="M11.251.068a.5.5 0 0 1 .227.58L9.677 6.5H13a.5.5 0 0 1 .364.843l-8 8.5a.5.5 0 0 1-.842-.49L6.323 9.5H3a.5.5 0 0 1-.364-.843l8-8.5a.5.5 0 0 1 .615-.09z"\n      ></path>\n    </svg>\n\n    Join now\n  </div>\n</button>', css: '\n/* From Uiverse.io by zebra76966  - Tags: animation, gradient, button, click animation */\n.rainbow-btn {\n  border: 2px;\n  border-radius: 35px;\n  width: 18em;\n  font-size: 2rem;\n  padding: 28px 28px;\n  color: black;\n  background: transparent;\n  position: relative;\n  box-shadow: 0 5px 20px rgba(0, 0, 0, 0.2);\n  transition: all 0.3s ease-in-out;\n  cursor: pointer;\n}\n\n.rainbow-btn::before {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  z-index: -1;\n  content: "";\n  height: 4.3em;\n  border-radius: 35px;\n  width: 18em;\n  filter: blur(1px);\n  background: radial-gradient(\n      at 0% 0%,\n      hsla(312, 66%, 67%, 1) 0px,\n      transparent 50%\n    ),\n    radial-gradient(at 28% 79%, hsla(355, 80%, 64%, 1) 0px, transparent 50%),\n    radial-gradient(at 100% 1%, hsla(279, 96%, 65%, 1) 0px, transparent 50%),\n    radial-gradient(at 5% 91%, hsla(289, 80%, 70%, 1) 0px, transparent 50%),\n    radial-gradient(at 50% 37%, hsla(28, 100%, 74%, 1) 0px, transparent 50%),\n    radial-gradient(at 27% 38%, hsla(189, 0%, 100%, 1) 0px, transparent 50%),\n    radial-gradient(at 0% 50%, hsla(355, 100%, 93%, 1) 0px, transparent 50%),\n    radial-gradient(at 64% 78%, hsla(340, 100%, 76%, 1) 0px, transparent 50%),\n    radial-gradient(at 0% 100%, hsla(22, 100%, 77%, 1) 0px, transparent 50%),\n    radial-gradient(at 72% 55%, hsla(240, 68%, 97%, 1) 0px, transparent 50%),\n    radial-gradient(at 51% 14%, hsla(28, 100%, 74%, 1) 0px, transparent 50%);\n}\n\n.rainbow-btn .content {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  padding: 20px 8px;\n  font-weight: 500;\n  border: 3px solid rgba(255, 255, 255, 0.2);\n  border-radius: 25px;\n  box-shadow: inset 0 0 1px 2px rgba(255, 255, 255, 0.712);\n}\n.rainbow-btn .content::before {\n  content: " ";\n  border: 10px double rgba(247, 201, 232, 0.5);\n  border-radius: 35px;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  width: 17em;\n  height: 3em;\n  padding: 10px 8px;\n  position: absolute;\n  z-index: ', colors: '', radii: '25px,35px', shadows: '0 5px 20px rgba(0, 0, 0, 0.2),inset 0 0 1px 2px rgba(255, 255, 255, 0.712)', techniques: 'glassmorphism,3d-transform,glow-shadow,gradient,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'andrew-demchenk0_perfect-crab-47', cat: 'Cards', author: 'andrew-demchenk0', tags: 'card', html: '<div class="card">\n    <div class="heading">Join the Open-Source <span>Galaxy</span></div>\n    <div class="content">\n        <div class="item item--create">\n            <svg height="24" width="24" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">\n                <path d="M24 12L18.3431 17.6569L16.9289 16.2426L21.1716 12L16.9289 7.75736L18.3431 6.34315L24 12ZM2.82843 12L7.07107 16.2426L5.65685 17.6569L0 12L5.65685 6.34315L7.07107 7.75736L2.82843 12ZM9.78845 21H7.66009L14.2116 3H16.3399L9.78845 21Z" fill="currentColor"></path>\n            </svg>\n            <span>Create</span>\n        </div>\n        <div class="item item--post">\n            <svg height="24" width="24" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">\n                <path d="M4.99958 12.9998C4.99958 7.91186 7.90222 3.56348 11.9996 1.81787C16.0969 3.56348 18.9996 7.91186 18.9996 12.9998C18.9996 13.8227 18.9236 14.6263 18.779 15.4026L20.7194 17.2352C20.8845 17.3911 20.9238 17.6388 20.815 17.8381L18.3196 22.4132C18.1873 22.6556 17.8836 22.7449 17.6412 22.6127C17.5993 22.5898 17.5608 22.5611 17.5271 22.5273L15.2925 20.2927C15.1049 20.1052 14.8506 19.9998 14.5854 19.9998H9.41379C9.14857 19.9998 8.89422 20.1052 8.70668 20.2927L6.47209 22.5273C6.27683 22.7226 5.96025 22.7226 5.76498 22.5273C5.73122 22.4935 5.70246 22.4551 5.67959 22.4132L3.18412 17.8381C3.07537 17.6388 3.11464 17.3911 3.27975 17.2352L5.22014 15.4026C5.07551 14.6263 4.99958 13.8227 4.99958 12.9998ZM6.47542 19.6955L7.29247 18.8785C7.85508 18', css: '\n/* From Uiverse.io by andrew-demchenk0 - Tags: card */\n.card {\n  height: 300px;\n  width: 220px;\n  padding: 15px;\n  position: relative;\n  background: linear-gradient(to top, rgba(0, 0, 0, 0.825), rgba(247, 28, 200, 0.13)),\n  radial-gradient(circle at 0%, rgba(172, 56, 187, 0.329), rgba(121, 21, 179, 0.521) 50%, rgba(37, 26, 26, 0.432) 75%, rgba(33, 10, 54, 0.236) 75%),\n  radial-gradient(circle at 100%, rgba(171, 0, 238, 0.329), rgba(13, 115, 231, 0.514) 50%, rgba(37, 26, 26, 0.432) 75%, rgba(51, 51, 51, 0.315) 75%),\n  radial-gradient(circle at 100% 0%, rgba(5, 5, 5, 0.329), rgb(226, 226, 231) 50%, rgba(37, 26, 26, 0.432) 75%, rgba(51, 51, 51, 0.161) 75%),\n  radial-gradient(circle at 0% 100%, rgba(45, 10, 173, 0.541), rgba(178, 22, 245, 0.805) 50%, rgba(37, 26, 26, 0.432) 75%, rgba(51, 51, 51, 0.315) 75%),\n  radial-gradient(closest-side, #3f87a646, #ebf8e13d, #3cd1f654),\n  linear-gradient(315deg, rgba(212, 212, 207, 0.74) 3%, rgb(11, 12, 12) 38%, rgba(16, 24, 23, 0.301) 68%, rgba(166, 168, 173, 0.942) 98%);\n  background-size: 200% 200%;\n  animation: cosmic 10s ease-in-out infinite;\n  box-sizing: border-box;\n  transform: skewY(-5deg);\n  transition: all 0.3s;\n  display: flex;\n  flex-direction: column;\n  justify-content: flex-end;\n  gap: 50px;\n  align-items: center;\n}\n\n.card::before {\n  content: \'\';\n  width: 10px;\n  height: 300px;\n  background: linear-gradient(to top, rgba(0, 0, 0, 0.825), rgba(247, 28, 200, 0.13)),\n  radial-gradient(circle at 0%, rgba(172, 56, 187, 0.329), rgba(121, 21, 179, 0.521) 50%, rgba(37, 26, 26, 0.432) 75%, rgba(33, 10, 54, 0.236) 75%),\n  radial-gradient(circle at 100%, rgba(171, 0, 238, 0.329), rgba(13, 115, 231, 0.514) 50%, rgba(37, 26, 26, 0.432) 75%, rgba(51, 51, 51, 0.315) 75%),\n  radial-gradient(circle at 100% 0%, rgba(5, 5, 5, 0.329), rgb(226, 226, 231) 50%, rgba(37, 26, 26, 0.432) 75%, rgba(51, 51, 51, 0.161) 75%),\n  radial-gradient(circle at 0% 100%, rgba(45, 10, 173, 0.541), rgba(178, 22, 245, 0.805) 50%, rgba(37, 26, 26, 0.432) 75%, ', colors: '#ebf8e13d,#3f87a646,#cc014d,#db0f5a,#6b043a,#3cd1f654,#fff', radii: '0px 5px 0 5px', shadows: '-310px 315px 6px rgba(36, 4, 41, 0.5)', techniques: '3d-transform,glow-shadow,gradient,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'Aryan-81_rare-rattlesnake-22', cat: 'Cards', author: 'Aryan-81', tags: 'card,black,square,gradient,minimalistic,card,neon,glow,monthly,popular,uiverse', html: '<div class="card">\n  <div>\n    <p class="heading">Popular this month</p>\n    <p>Powered By</p>\n    <p>Uiverse</p>\n  </div>\n\n  <button class="card-button">More Info</button>\n</div>', css: '\n/* From Uiverse.io by Aryan-81  - Tags: card, black, square, gradient, minimalistic, card, neon, glow, monthly, popular, Uiverse */\n.card {\n  position: relative;\n  width: 190px;\n  height: 190px;\n  background-color: #000;\n  display: flex;\n  flex-direction: column;\n  justify-content: end;\n  padding: 12px;\n  gap: 12px;\n  border-radius: 8px;\n  cursor: pointer;\n  color: rgb(255, 255, 255);\n}\n.card > div {\n  margin: auto auto;\n}\n.card::before {\n  content: "";\n  position: absolute;\n  inset: 0;\n  left: -5px;\n  margin: auto;\n  width: 200px;\n  height: 200px;\n  border-radius: 10px;\n  background: linear-gradient(-45deg, #fff01c 0%, #40c9ff 100%);\n  z-index: -10;\n  pointer-events: none;\n  transition: all 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275);\n}\n\n.card::after {\n  content: "";\n  z-index: -1;\n  position: absolute;\n  inset: 0;\n  background: linear-gradient(-45deg, #fff01c 0%, #40c9ff 100%);\n  transform: translate3d(0, 0, 0) scale(0.95);\n  filter: blur(20px);\n}\n\n.heading {\n  font-size: 20px;\n  text-transform: capitalize;\n  font-weight: 700;\n}\n\n.card p:not(.heading) {\n  font-size: 14px;\n}\n\n.card p:last-child {\n  color: #e81cff;\n  font-weight: 600;\n}\n\n.card:hover::after {\n  filter: blur(30px);\n}\n\n.card:hover::before {\n  transform: rotate(-90deg) scaleX(1) scaleY(1);\n}\n\n.card:hover .card-button {\n  transform: translate(-50%, 50%);\n  opacity: 1;\n}\n.card-button {\n  transform: translate(-50%, 125%);\n  width: 60%;\n  border-radius: 1rem;\n  border: none;\n  background: linear-gradient(-45deg, #fc00ff 0%, #00dbde 100%);\n  color: #fff;\n  font-size: 1rem;\n  padding: 0.5rem 1rem;\n  position: absolute;\n  left: 50%;\n  bottom: 0;\n  opacity: 0;\n  transition: 0.3s ease-out;\n}\n\n', colors: '#00dbde,#000,#e81cff,#fff01c,#40c9ff,#fc00ff,#fff', radii: '10px,1rem,8px', shadows: '', techniques: 'glassmorphism,cubic-bezier,3d-transform,gradient,typography-transform,pseudo-elements'),
