ox-shadow: 0px 0px 10px rgba(0, 0, 0, 0.5);\n  margin: 20px;\n  padding: 20px;\n  width: 300px;\n}\n\n@keyframes floatAnimation {\n  0%,\n  100% {\n    transform: translateY(0);\n    filter: drop-shadow(0px 5px 5px rgba(255, 255, 255, 0.5));\n  }\n  50% {\n    transform: translateY(-10px);\n    filter: drop-shadow(0px 20px 15px rgba(255, 255, 255, 0.5));\n  }\n}\n\n.image {\n  width: 200px;\n  height: auto;\n  border-top-left-radius: 8px;\n  border-top-right-radius: 8px;\n  animation: floatAnimation 3s ease-in-out infinite;\n}\n\n.heading {\n  width: 100%;\n  font-size: 22px;\n  margin-bottom: 10px;\n  text-align: center;\n  color: #1b1b1b;\n  font-weight: 600;\n  border-bottom: 2px solid rgba(0, 0, 0, 0.2);\n}\n\n.icons {\n  width: 100%;\n  display: flex;\n  justify-content: space-evenly;\n  border-radius: 5px;\n  padding: 10px 0;\n}\n\n.icons a {\n  color: inherit;\n  text-decoration: none;\n  flex: 1;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n.icons a:hover {\n  transform: scale(1.1);\n  transition: transform 0.2s ease-in-out;\n}\n\n.icons svg {\n  width: 50px;\n  height: 50px;\n  transition: transform 0.2s ease-in-out;\n  color: #fff;\n  border-radius: 50px;\n  padding: 5px;\n  filter: drop-shadow(0 0 10px rgb(255, 255, 255));\n}\n\n', colors: '#1b1b1b,#fff', radii: '50px,5px,8px', shadows: '0px 0px 10px rgba(0, 0, 0, 0.5)', techniques: '3d-transform,glow-shadow,gradient,animation,filter-effect,svg-icon'),
