 0.3;\n}\n\n.card span:nth-child(2) {\n  top: 60%;\n  left: -20%;\n  width: 80px;\n  height: 80px;\n  animation-delay: .2s;\n  opacity: 0.3;\n}\n\n.card span:nth-child(3) {\n  top: 10%;\n  left: 60%;\n  animation-delay: .3s;\n  opacity: 0.6;\n}\n\n.card span:nth-child(4) {\n  top: 70%;\n  left: 50%;\n  width: 90px;\n  height: 90px;\n  animation-delay: .4s;\n  opacity: 0.4;\n}\n\n.card div {\n  backdrop-filter: blur(15px);\n  outline: 1px solid var(--card-color);\n  color: var(--card-color);\n  width: 180px;\n  height: 250px;\n  border-radius: 5%;\n  padding: 1rem;\n  display: flex;\n  flex-direction: column;\n  justify-content: space-between;\n}\n\n.card div .check {\n  fill: var(--card-color);\n  width: 25px;\n  height: 25px;\n  position: absolute;\n  top: 0;\n  right: 0;\n  transform: translate(50%, -50%);\n}\n\n.card div strong {\n  font-size: 1rem;\n  font-weight: 900;\n  text-transform: uppercase;\n}\n\n.card div p {\n  font-size: 0.8rem;\n}\n\n.card div hr {\n  border: none;\n  border-top: 1px solid var(--card-color);\n  opacity: .5;\n}\n\n.card div button {\n  background-color: transparent;\n  color: var(--card-color);\n  border: none;\n  outline: 1px solid var(--card-color);\n  border-radius: 1rem;\n  padding: .5rem 1rem;\n  font-size: 0.8rem;\n  font-weight: 900;\n  transition: .3s;\n  display: flex;\n  align-item', colors: '#0080ff,#52d4eb', radii: '5%,100%,1rem', shadows: '', techniques: 'glassmorphism,3d-transform,gradient,animation,typography-transform,svg-icon'),
