const GalaxyComp(id: 'Li-Deheng_sweet-liger-88', cat: 'Cards', author: '', tags: '', html: '<div class="like-dislike-container">\n	<div class="tool-box">\n		<button class="btn-close">×</button>\n	</div>\n	<p class="text-content">What did you think<br>of this post?</p>				\n	<div class="icons-box">\n		<div class="icons">\n			<label class="btn-label" for="like-checkbox">\n				<span class="like-text-content">123</span>\n				<input class="input-box" id="like-checkbox" type="checkbox">\n				<svg class="svgs" id="icon-like-solid" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512"><path d="M313.4 32.9c26 5.2 42.9 30.5 37.7 56.5l-2.3 11.4c-5.3 26.7-15.1 52.1-28.8 75.2H464c26.5 0 48 21.5 48 48c0 18.5-10.5 34.6-25.9 42.6C497 275.4 504 288.9 504 304c0 23.4-16.8 42.9-38.9 47.1c4.4 7.3 6.9 15.8 6.9 24.9c0 21.3-13.9 39.4-33.1 45.6c.7 3.3 1.1 6.8 1.1 10.4c0 26.5-21.5 48-48 48H294.5c-19 0-37.5-5.6-53.3-16.1l-38.5-25.7C176 420.4 160 390.4 160 358.3V320 272 247.1c0-29.2 13.3-56.7 36-75l7.4-5.9c26.5-21.2 44.6-51 51.2-84.2l2.3-11.4c5.2-26 30.5-42.9 56.5-37.7zM32 192H96c17.7 0 32 14.3 32 32V448c0 17.7-14.3 32-32 32H32c-17.7 0-32-14.3-32-32V224c0-17.7 14.3-32 32-32z"></path></svg>\n				<svg class="svgs" id="icon-like-regular" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512"><path d="M323.8 34.8c-38.2-10.9-78.1 11.2-89 49.4l-5.7 20c-3.7 13-10.4 25-19.5 35l-51.3 56.4c-8.9 9.8-8.2 25 1.6 33.9s25 8.2 33.9-1.6l51.3-56.4c14.1-15.5 24.4-34 30.1-54.1l5.7-20c3.6-12.7 16.9-20.1 29.7-16.5s20.1 16.9 16.5 29.7l-5.7 20c-5.7 19.9-14.7 38.7-26.6 55.5c-5.2 7.3-5.8 16.9-1.7 24.9s12.3 13 21.3 13L448 224', css: '\n/* From Uiverse.io by Li-Deheng - Source: Li-Deheng - Tags: animation, button, card, checkbox, like, dislike, animated, hover effect */\n.like-dislike-container {\n  --dark-grey: #353535;\n  --middle-grey: #767676;\n  --lightest-grey: linear-gradient(#fafafa,#ebebeb);\n  --shadow: 0 5px 15px 0 #00000026;\n  --shadow-active: 0 5px 5px 0 #00000026;\n  --border-radius-main: 10px;\n  --border-radius-icon: 50px;\n  position: relative;\n  display: flex;\n  text-align: center;\n  flex-direction: column;\n  align-items: center;\n  cursor: default;\n  color: var(--dark-grey);\n  opacity: .9;\n  margin: auto;\n  padding: 1.5rem;\n  font-weight: 600;\n  background: var(--lightest-grey);\n  max-width: max-content;\n  border-radius: var(--border-radius-main);\n  box-shadow: var(--shadow);\n  transition: .2s ease all;\n}\n\n.like-dislike-container:hover {\n  box-shadow: var(--shadow-active);\n}\n\n.like-dislike-container .tool-box {\n  position: absolute;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  width: 2.5rem;\n  height: 2.5rem;\n  top: 0;\n  right: 0;\n  border-radius: var(--border-radius-main);\n}\n\n.like-dislike-container .btn-close {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  text-align: center;\n  width: .8rem;\n  height: .8rem;\n  color: transparent;\n  font-size: 0;\n  cursor: pointer;\n  background-color: #ff000080;\n  border: none;\n  border-radius: var(--border-radius-main);\n  transition: .2s ease all;\n}\n\n.like-dislike-container .btn-close:hover {\n  width: 1rem;\n  height: 1rem;\n  font-size: 1rem;\n  color: #ffffff;\n  background-color: #ff0000cc;\n  box-shadow: var(--shadow-active);\n}\n\n.like-dislike-container .btn-close:active {\n  width: .9rem;\n  height: .9rem;\n  font-size: .9rem;\n  color: #ffffffde;\n  --shadow-btn-close: 0 3px 3px 0 #00000026;\n  box-shadow: var(--shadow-btn-close);\n}\n\n.like-dislike-container .text-content {\n  margin-bottom: 1rem;\n  font-size: 18px;\n  line-height: 1.6;\n  cursor: default;\n}\n\n.like-dislike-container .icons-box {\n  display: flex;\n}\n\n', colors: '#0004ff,#00ff40,#00ff2b,#d5ff00,#ff0088,#0091ff,#ff6f00,#000000,#ff008c,#40ff00', radii: 'var(--border-radius-icon),50%,var(--border-radius-main)', shadows: 'var(--shadow),var(--shadow-active),var(--shadow-active)', techniques: '3d-transform,glow-shadow,gradient,animation,checkbox-input