const GalaxyComp(id: 'MuhammadHasann_hot-liger-0', cat: 'Cards', author: '', tags: '', html: '<div class="card_container">\n  <div class="card_hover">\n    <div class="part part-1"></div>\n    <div class="part part-2"></div>\n    <div class="part part-3"></div>\n    <div class="part part-4"></div>\n    <div class="part part-5"></div>\n    <div class="part part-6"></div>\n    <div class="part part-7"></div>\n    <div class="part part-8"></div>\n    <div class="part part-9"></div>\n    <div class="part part-10"></div>\n    <div class="part part-11"></div>\n    <div class="part part-12"></div>\n    <div class="part part-13"></div>\n    <div class="part part-14"></div>\n    <div class="part part-15"></div>\n  </div>\n  <div class="card">\n    <div class="say-hi">\n      <svg\n        xmlns="http://www.w3.org/2000/svg"\n        fill="none"\n        viewBox="0 0 71 74"\n        class="icon_say-hi"\n      >\n        <path\n          fill="black"\n          d="M43.6574 32.6925C46.2318 27.3745 42.4638 8.00882 50.0978 4.62384C53.3046 3.19858 56.1818 5.55916 57.0637 8.98869C58.7918 15.723 56.7074 24.034 54.9793 30.5011C54.712 31.5166 53.8925 33.7525 54.0261 34.7413C58.5781 27.5437 59.4243 18.9209 63.0587 16.3644C65.9894 14.2978 68.9201 15.4647 70.372 18.7339C72.8573 24.3369 65.6776 37.2266 62.4084 41.7963C67.0227 52.1917 65.9538 64.93 54.9347 70.4083C51.7814 71.21 49.0734 71.2813 45.9556 70.2569C45.9378 70.2569 45.6973 70.1767 45.6706 70.1678C41.0741 73.2588 30.358 73.7309 27.4362 72.3502C20.6395 68.8138 18.2522 61.8479 6.11974 55.3273C4.40052 54.4098 1.96868 53.2518 0.721583 51.0159C-2.53869 45.1902 6.164', css: '\n/* From Uiverse.io by MuhammadHasann  - Website: https://twitter.com/greeenyang/status/1756875866863468827 - Name: Greeen Yang - Tags: animation, minimalist, card, card animation */\n.card_container {\n  --X: 0deg;\n  --Y: 0deg;\n  --Z: 0deg;\n  --angleX: 15deg;\n  --angleY: 20deg;\n\n  cursor: pointer;\n\n  position: relative;\n}\n\n.card_hover {\n  position: absolute;\n  z-index: 10;\n  top: 0;\n  left: 0;\n\n  display: flex;\n  flex-wrap: wrap;\n\n  width: 100%;\n  height: 100%;\n}\n\n.card_hover .part {\n  width: 20%;\n  height: calc(100% / 3);\n  background-color: transparent;\n}\n\n.card_container:has(.part-1:hover) {\n  --X: var(--angleX);\n  --Y: calc(var(--angleY) * -1);\n}\n.card_container:has(.part-2:hover) {\n  --X: var(--angleX);\n  --Y: calc((var(--angleY) / 2) * -1);\n}\n.card_container:has(.part-3:hover) {\n  --X: var(--angleX);\n}\n.card_container:has(.part-4:hover) {\n  --X: var(--angleX);\n  --Y: calc(var(--angleY) / 2);\n}\n.card_container:has(.part-5:hover) {\n  --X: var(--angleX);\n  --Y: var(--angleY);\n}\n.card_container:has(.part-6:hover) {\n  --Y: calc(var(--angleY) * -1);\n}\n.card_container:has(.part-7:hover) {\n  --Y: calc((var(--angleY) / 2) * -1);\n}\n.card_container:has(.part-9:hover) {\n  --Y: calc(var(--angleY) / 2);\n}\n.card_container:has(.part-10:hover) {\n  --Y: var(--angleY);\n}\n.card_container:has(.part-11:hover) {\n  --X: calc(var(--angleX) * -1);\n  --Y: calc(var(--angleY) * -1);\n}\n.card_container:has(.part-12:hover) {\n  --X: calc(var(--angleX) * -1);\n  --Y: calc((var(--angleY) / 2) * -1);\n}\n.card_container:has(.part-13:hover) {\n  --X: calc(var(--angleX) * -1);\n}\n.card_container:has(.part-14:hover) {\n  --X: calc(var(--angleX) * -1);\n  --Y: calc(var(--angleY) / 2);\n}\n.card_container:has(.part-15:hover) {\n  --X: calc(var(--angleX) * -1);\n  --Y: var(--angleY);\n}\n\n.card {\n  --light: #d9d9d9;\n  --dark: #1f1f1f;\n\n  position: relative;\n\n  display: flex;\n  flex-direction: column;\n  gap: 0.75rem;\n\n  padding: 1.5rem;\n  width: 15rem;\n  background-color: rgb(172, 250, 233);\n  background-image: line', colors: '#2b2b2b,#1f1f1f,#d9d9d9', radii: '0.5rem', shadows: '', techniques: '3d-transform,gradient,animation,filter-effect,typography-transform,svg-icon'),
const GalaxyComp(id: 'RozheenNM_tough-impala-7', cat: 'Cards', author: 'RozheenNM', tags: 'button,card,day', html: '<div class="one-div"></div>', css: '\n/* From Uiverse.io by RozheenNM - Tags: button, card, day */\n.one-div {\n  width: 200px;\n  height: 200px;\n  position: relative;\n  overflow: hidden;\n  border-radius: 10mm;\n  animation: flip-and-rotate 8s ease-in-out infinite;\n  transform-origin: center;\n  background: linear-gradient(135deg, #f7af6c, #fa8b8b, #f75bea);\n  box-shadow: 0 0 10px rgba(0, 0, 0, 0.3);\n}\n\n.one-div::before,\n.one-div::after {\n  content: "";\n  position: absolute;\n  width: 100px;\n  height: 100px;\n  opacity: 80%;\n  background-color: rgb(255, 193, 122);\n  box-shadow: #33577e;\n  border-radius: 100%;\n  transform: translate(-50%, -80%) rotate(90deg);\n}\n\n.one-div::before {\n  top: 50%;\n  left: 50%;\n}\n\n.one-div::after {\n  bottom: 50%;\n  right: 50%;\n}\n\n.one-div::before,\n.one-div::after {\n  animation: move 1.2s infinite cubic-bezier(0.68, -0.55, 0.265, 1.88);\n}\n\n@keyframes move {\n  0% {\n    transform: translate(50%, 50%) rotate(45deg) scale(0.8);\n  }\n\n  50% {\n    transform: translate(50%, 50%) rotate(45deg) scale(1.2);\n  }\n\n  100% {\n    transform: translate(50%, 50%) rotate(45deg) scale(0.8);\n  }\n}\n\n@keyframes flip-and-rotate {\n  0% {\n    transform: scale(1) rotate(0deg);\n    background: linear-gradient(135deg, #f7af6c, #fa8b8b, #f75bea);\n  }\n\n  10% {\n    transform: scale(1) rotate(10deg);\n    background: linear-gradient(135deg, #7bbbd4, #33577e, #00061b);\n  }\n\n  20% {\n    transform: scale(1) rotate(20deg);\n    background: linear-gradient(135deg, #f7af6c, #fa8b8b, #f75bea);\n  }\n\n  30% {\n    transform: scale(1) rotate(-30deg);\n    background: linear-gradient(135deg, #6cb2ce, #3d93a8, #00061b);\n  }\n\n  40% {\n    transform: scale(1) rotate(40deg);\n    background: linear-gradient(135deg, #f7af6c, #fa8b8b, #f75bea);\n  }\n\n  50% {\n    transform: scale(1) rotate(-5deg);\n    background: linear-gradient(135deg, #64b5d4, #184d85, #00061b);\n  }\n\n  60% {\n    transform: scale(1) rotate(60deg);\n    background: linear-gradient(135deg, #f7af6c, #fa8b8b, #f75bea);\n  }\n\n  70% {\n    transform: scale(1) rotate(70deg);\n    backg', colors: '#184d85,#081c24,#041527,#f7af6c,#7bbbd4,#fa8b8b,#f75bea,#3d93a8,#33577e,#64b5d4', radii: '100%,10mm', shadows: '0 0 10px rgba(0, 0, 0, 0.3),#33577e', techniques: 'cubic-bezier,3d-transform,glow-shadow,gradient,animation,pseudo-elements'),
const GalaxyComp(id: 'Saad3092003_itchy-starfish-99', cat: 'Cards', author: 'Saad3092003', tags: 'animation,card,hover,shadow,animated,hover effect,css effect,box-shadow,one-div', html: '<div class="one-div"></div>', css: '\n/* From Uiverse.io by Saad3092003 - Tags: animation, card, hover, shadow, animated, hover effect, css effect, box-shadow, one-div */\n.one-div {\n  position: relative;\n  height: 250px;\n  width: 200px;\n  background-color: rgb(15, 15, 15);\n  transform-style: preserve-3d;\n  animation: rot 2s infinite ease;\n  border-radius: 20px;\n  box-shadow: 0 0 50px 0px white ,inset 0 0 50px 0px white;\n  transition: 1s;\n}\n\n.one-div::after {\n  content: \'D I V\';\n  font-size: 30px;\n  text-shadow: 5px 5px 1px black;\n  position: absolute;\n  top: 0;\n  left: 0;\n  height: 100%;\n  width: 100%;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  transition: all 0.5s;\n  color: white;\n}\n\n.one-div:hover.one-div::after {\n  font-size: 40px;\n}\n\n.one-div::before {\n  content: \'UIVERSE\';\n  color: white;\n  font-size: 25px;\n  letter-spacing: 7px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  position: absolute;\n  top: -20px;\n  left: 40px;\n  background-color: rgb(25, 25, 25);\n  width: 220px;\n  height: 270px;\n  transform: translateY(50px) translateZ(50px);\n  border-radius: 20px;\n  filter: blur(0px);\n  transition: 0.5s;\n  box-shadow: 0 0 5px 0px black, -3px -3px 10px 3px rgb(25,25,25),inset 0px 0px 40px -20px black;\n}\n\n.one-div:active.one-div::after {\n  text-shadow: 0 0 0 black;\n  transition: 0.5s;\n  transform: translateY(5px) translateZ(5px);\n}\n\n.one-div:hover.one-div::before {\n  font-size: 10px;\n  width: 250px;\n  height: 300px;\n  transform: translateZ(-50px) translateY(50px);\n  box-shadow: 0 0 5px 0px black, -3px -3px 10px 3px rgb(25,25,25),inset 0px 0px 40px -20px;\n}\n\n.one-div:hover {\n  height: 300px;\n  width: 250px;\n  box-shadow: 0 0 5px 0px black,inset -3px -3px 10px 3px rgb(25,25,25),inset 3px 3px 20px 3px black;\n  cursor: pointer;\n}\n\n@keyframes rot {\n  0% {\n    transform: rotateX(-15deg) translateY(0px);\n  }\n\n  50% {\n    transform: rotateX(-15deg) translateY(-10px);\n  }\n\n  100% {\n    transform: rotateX(-15deg) translateY(0px);\n  }\n}\n\n', colors: '', radii: '20px', shadows: '0 0 50px 0px white ,inset 0 0 50px 0px white,0 0 5px 0px black, -3px -3px 10px 3px rgb(25,25,25),inset 0px 0px 40px -20px black,0 0 5px 0px black, -3px -3px 10px 3px rgb(25,25,25),inset 0px 0px 40px -20px', techniques: 'glassmorphism,3d-transform,glow-shadow,text-shadow,animation,pseudo-elements'),
const GalaxyComp(id: 'SelfMadeSystem_swift-bullfrog-34', cat: 'Cards', author: 'SelfMadeSystem', tags: 'animation,card,glow,rainbow', html: '<div class="card">\n      <div class="bg uwu"></div>\n      <div class="bg"></div>\n      <div class="content">\n            <div class="img">\n                  <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path d="M12,4A4,4 0 0,1 16,8A4,4 0 0,1 12,12A4,4 0 0,1 8,8A4,4 0 0,1 12,4M12,14C16.42,14 20,15.79 20,18V20H4V18C4,15.79 7.58,14 12,14Z"></path></svg>\n            </div>\n            <div class="h1">\n                  Johnathon<br>F. Stag\n            </div>\n            <div class="p">\n                  Professional human\n                  <p>\n                        I do human things such as exist, eat foot, and work.\n                  </p>\n            </div>\n      </div>\n</div>', css: '\n/* From Uiverse.io by SelfMadeSystem - Tags: animation, card, glow, rainbow */\n.card {\n  position: relative;\n  width: 190px;\n  color: white;\n  height: 260px;\n  background: #444;\n  border-radius: 14px;\n}\n\n.bg {\n  position: absolute;\n  z-index: -1;\n  inset: -4px;\n  border-radius: 16px;\n  overflow: hidden;\n}\n\n.uwu {\n  filter: blur(8px);\n  transition: filter 0.3s;\n}\n\n.bg::before {\n  content: \'\';\n  position: absolute;\n  aspect-ratio: 1/1;\n  top: 50%;\n  left: 50%;\n  min-width: 150%;\n  min-height: 150%;\n  background-image: conic-gradient(\n    hsl(0, 100%, 50%),\n    hsl(30, 100%, 50%),\n    hsl(60, 100%, 50%),\n    hsl(90, 100%, 50%),\n    hsl(120, 100%, 50%),\n    hsl(150, 100%, 50%),\n    hsl(180, 100%, 50%),\n    hsl(210, 100%, 50%),\n    hsl(240, 100%, 60%),\n    hsl(270, 100%, 50%),\n    hsl(300, 100%, 50%),\n    hsl(330, 100%, 50%),\n    hsl(360, 100%, 50%)\n  );\n  animation: speeen 4s linear infinite;\n  transform-origin: 0% 0%;\n  transform: rotate(0deg) translate(-50%, -50%);\n}\n\n@keyframes speeen {\n  from {\n    transform: rotate(0deg) translate(-50%, -50%);\n  }\n\n  to {\n    transform: rotate(360deg) translate(-50%, -50%);\n  }\n}\n\n.content {\n  position: relative;\n  padding: 14px 16px;\n}\n\n.img {\n  height: 5em;\n  width: 5em;\n  margin: auto;\n  background-color: #fff3;\n  border-radius: 1em;\n}\n\n.img svg {\n  height: 100%;\n  fill: white;\n}\n\n.content div {\n  text-align: center;\n}\n\n.h1 {\n  margin-top: 1em;\n  margin-bottom: 0.5em;\n  font-size: 1em;\n  font-weight: 600;\n}\n\n.p {\n  font-size: 0.75em;\n}\n\n.p p {\n  margin-top: 0.5em;\n  padding: 0.5em;\n  background-color: #0003;\n  border-radius: 1em;\n}\n', colors: '#fff3,#444,#0003', radii: '14px,16px,1em', shadows: '', techniques: 'glassmorphism,3d-transform,gradient,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'Smit-Prajapati_curly-goose-86', cat: 'Cards', author: 'Smit-Prajapati', tags: 'card,sci-fi,cool card,cardhover,card animation,card hover,card design', html: '<div class="card">\n  <div class="boxshadow"></div>\n  <div class="main">\n    <div class="top"></div>\n    <div class="left side"></div>\n    <div class="right side"></div>\n    <div class="title">TITLE</div>\n    <div class="button-container">\n      <button class="button">\n        <svg class="svg" xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" stroke="red" fill="none" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">\n            <rect width="20" height="20" x="2" y="2" rx="5" ry="5"></rect>\n            <path d="M16 11.37A4 4 0 1 1 12.63 8 4 4 0 0 1 16 11.37z"></path>\n            <line x1="17.5" x2="17.51" y1="6.5" y2="6.5"></line>\n        </svg>\n      </button>\n      <button class="button">\n        <svg class="svg twitter" xmlns="http://www.w3.org/2000/svg" height="24" width="24" fill="red" viewBox="0 0 512 512">\n            <path d="M389.2 48h70.6L305.6 224.2 487 464H345L233.7 318.6 106.5 464H35.8L200.7 275.5 26.8 48H172.4L272.9 180.9 389.2 48zM364.4 421.8h39.1L151.1 88h-42L364.4 421.8z">\n            </path>\n        </svg>\n      </button>\n      <button class="button">\n        <svg class="svg" xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="red" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">\n            <path d="M15 22v-4a4.8 4.8 0 0 0-1-3.5c3 0 6-2 6-5.5.08-1.25-.27-2.48-1-3.5.28-1.15.28-2.35 0-3.5 0 0-1 0-3 1.5-2.64-.5-5.36-.5-8 0C6 2 5 2 5 2c-.3 1.15-.3 2.35 0 3.5A5', css: '\n/* From Uiverse.io by Smit-Prajapati - Tags: card, sci-fi, cool card, cardhover , card animation, card hover, card design */\n.card {\n  position: relative;\n  height: 300px;\n  width: 230px;\n}\n\n.card .boxshadow {\n  position: absolute;\n  height: 100%;\n  width: 100%;\n  border: 1p