 --bb8-diameter: 4.375em;\n  --radius: 99em;\n  --transition: 0.4s;\n  --accent: #de7d2f;\n  --bb8-bg: #fff;\n}\n\n.bb8-toggle,\n.bb8-toggle *,\n.bb8-toggle *::before,\n.bb8-toggle *::after {\n  -webkit-box-sizing: border-box;\n  box-sizing: border-box;\n}\n\n.bb8-toggle {\n  cursor: pointer;\n  margin-top: var(--margin-top-for-head);\n  font-size: var(--toggle-size);\n}\n\n.bb8-toggle__checkbox {\n  -webkit-appearance: none;\n  -moz-appearance: none;\n  appearance: none;\n  display: none;\n}\n\n.bb8-toggle__container {\n  width: var(--toggle-width);\n  height: var(--toggle-height);\n  background: var(--toggle-bg);\n  background-size: 100% 11.25em;\n  background-position-y: -5.625em;\n  border-radius: var(--radius);\n  position: relative;\n  -webkit-transition: var(--transition);\n  -o-transition: var(--transition);\n  transition: var(--transition);\n}\n\n.bb8 {\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-orient: vertical;\n  -webkit-box-direction: normal;\n  -ms-flex-direction: column;\n  flex-direction: column;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n  position: absolute;\n  top: calc(var(--toggle-offset) - 1.688em + 0.188em);\n  left: var(--toggle-offset);\n  -webkit-transition: var(--transition);\n  -o-transition: var(--transition);\n  transition: var(--transition);\n  z-index: 2;\n}\n\n.bb8__head-container {\n  position: relative;\n  -webkit-transition: var(--t', colors: '#fefefe,#e0dfdfae,#fff,#ffffffae,#de7d2f,#070e2b,#628cac,#000,#2c4770,#dfdedeae', radii: 'var(--radius) var(--radius) 0 0,50%,var(--radius),inherit', shadows: '0 0 0 0.089em lightgray, 0.563em 0.281em 0 -0.148em,\n    0.563em 0.281em 0 -0.1em var(--bb8-bg), 0.563em 0.281em 0 -0.06,0 0 0 0.089em lightgray, 0.563em 0.281em 0 -0.148em,\n    0.563em 0.281em 0 -0.1em var(--bb8-bg), 0.563em 0.281em 0 -0.06,0.875em 0.938em, 0 -1.25em, 0.875em -2.125em,\n    2.125em -2.125em, 3.063em -1.25em, 3.063em 0, 2.125em 0.938em', techniques: 'glassmorphism,3d-transform,glow-shadow,gradient,checkbox-input,pseudo-elements'),
const GalaxyComp(id: 'JkHuger_itchy-turtle-45', cat: 'Toggle-switches', author: 'JkHuger', tags: 'switch,dark,theme,light,moon,sun,theme-switch', html: '<div class="wrapper">\n<input type="checkbox" name="checkbox" class="switch">\n</div>', css: '\n/* From Uiverse.io by JkHuger - Tags: switch, dark, theme, light, moon, sun, theme-switch */\n.switch {\n  position: relative;\n  width: 130px;\n  height: 50px;\n  margin: 0px;\n  appearance: none;\n  -webkit-appearance: none;\n  background-color: rgb(4,52,73);\n  background-size: cover;\n  background-repeat: no-repeat;\n  border-radius: 25px;\n  transition: background-image .7s ease-in-out;\n  outline: none;\n  cursor: pointer;\n  overflow: hidden;\n}\n\n.switch:checked {\n  background-color: rgb(0, 195, 255);\n  background-size: cover;\n  transition: background-image 1s ease-in-out;\n}\n\n.switch:after {\n  content: \'\';\n  width: 46px;\n  height: 46px;\n  border-radius: 50%;\n  background-color: #fff;\n  position: absolute;\n  left: 2px;\n  top: 2px;\n  transform: translateX(0px);\n  animation: off .7s forwards cubic-bezier(.8, .5, .2, 1.4);\n  box-shadow: inset 5px -5px 4px rgba(53, 53, 53, 0.3);\n}\n\n@keyframes off {\n  0% {\n    transform: translateX(80px);\n    width: 46px;\n  }\n\n  50% {\n    width: 75px;\n    border-radius: 25px;\n  }\n\n  100% {\n    transform: translateX(0px);\n    width: 46px;\n  }\n}\n\n.switch:checked:after {\n  animation: on .7s forwards cubic-bezier(.8, .5, .2, 1.4);\n  box-shadow: inset -5px -5px 4px rgba(53, 53, 53, 0.3);\n}\n\n@keyframes on {\n  0% {\n    transform: translateX(0px);\n    width: 46px;\n  }\n\n  50% {\n    width: 75px;\n    border-radius: 25px;\n  }\n\n  100% {\n    transform: translateX(80px);\n    width: 46px;\n  }\n}\n\n.switch:checked:before {\n  content: \'\';\n  width: 15px;\n  height: 15px;\n  border-radius: 50%;\n  position: absolute;\n  left: 15px;\n  top: 5px;\n  transform-origin: 53px 10px;\n  background-color: transparent;\n  box-shadow: 5px -1px 0px #fff;\n  filter: blur(0px);\n  animation: sun .7s forwards ease;\n}\n\n@keyframes sun {\n  0% {\n    transform: rotate(170deg);\n    background-color: transparent;\n    box-shadow: 5px -1px 0px #fff;\n    filter: blur(0px);\n  }\n\n  50% {\n    background-color: transparent;\n    box-shadow: 5px -1px 0px #fff;\n    filter: blur(0px);\n  }\n\n  90% {\n    backgrou', colors: '#f5deb4,#efd3a3,#fff,#f5daaa', radii: '50%,25px', shadows: 'inset 5px -5px 4px rgba(53, 53, 53, 0.3),inset -5px -5px 4px rgba(53, 53, 53, 0.3),5px -1px 0px #fff', techniques: 'glassmorphism,cubic-bezier,3d-transform,glow-shadow,animation,checkbox-input'),
const GalaxyComp(id: 'Na3ar-17_evil-dragon-24', cat: 'Toggle-switches', author: 'Na3ar-17', tags: 'action,switch,download', html: '<div class="container">\n  <label class="label">\n    <input class="input" type="checkbox" />\n    <span class="circle"\n      ><svg\n        viewBox="0 0 24 24"\n        fill="none"\n        xmlns="http://www.w3.org/2000/svg"\n        aria-hidden="true"\n        class="icon"\n      >\n        <path\n          d="M12 19V5m0 14-4-4m4 4 4-4"\n          stroke-width="1.5"\n          stroke-linejoin="round"\n          stroke-linecap="round"\n          stroke="currentColor"\n        ></path>\n      </svg>\n      <div class="square"></div>\n    </span>\n    <p class="title">Download</p>\n    <p class="title">Open</p>\n  </label>\n</div>', css: '\n/* From Uiverse.io by Na3ar-17  - Tags: action, switch, download */\n.container {\n  padding: 0;\n  margin: 0;\n  box-sizing: border-box;\n  font-family: Arial, Helvetica, sans-serif;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n.label {\n  background-color: transparent;\n  border: 2px solid rgb(91, 91, 240);\n  display: flex;\n  align-items: center;\n  border-radius: 50px;\n  width: 150px;\n  cursor: pointer;\n  transition: all 0.4s ease;\n  padding: 5px;\n  position: relative;\n}\n\n.label::before {\n  content: "";\n  position: absolute;\n  top: 0;\n  bottom: 0;\n  left: 0;\n  right: 0;\n  background-color: #fff;\n  width: 8px;\n  height: 8px;\n  transition: all 0.4s ease;\n  border-radius: 100%;\n  margin: auto;\n  opacity: 0;\n  visibility: hidden;\n}\n\n.label .input {\n  display: none;\n}\n\n.label .title {\n  font-size: 17px;\n  color: #fff;\n  transition: all 0.4s ease;\n  position: absolute;\n  right: 15px;\n  bottom: 14px;\n  text-align: center;\n}\n\n.label .title:last-child {\n  opacity: 0;\n  visibility: hidden;\n}\n\n.label .circle {\n  height: 45px;\n  width: 45px;\n  border-radius: 50%;\n  background-color: rgb(91, 91, 240);\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  transition: all 0.4s ease;\n  position: relative;\n  box-shadow: 0 0 0 0 rgb(255, 255, 255);\n  overflow: hidden;\n}\n\n.label .circle .icon {\n  color: #fff;\n  width: 30px;\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  transition: all 0.4s ease;\n}\n\n.label .circle .square {\n  aspect-ratio: 1;\n  width: 15px;\n  border-radius: 2px;\n  background-color: #fff;\n  opacity: 0;\n  visibility: hidden;\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  transition: all 0.4s ease;\n}\n\n.label .circle::before {\n  content: "";\n  position: absolute;\n  left: 0;\n  top: 0;\n  background-color: #3333a8;\n  width: 100%;\n  height: 0;\n  transition: all 0.4s ease;\n}\n\n.label:has(.input:checked) {\n  width: 57px;\n  animation: installed 0.4s ease 3.5s forwards;\n', colors: '#3333a8,#fff', radii: '50px,50%,100%,2px', shadows: '0 0 0 0 rgb(255, 255, 255),0 0 0 0 rgba(255, 255, 255, 0.7),0 0 0 16px rgba(255, 255, 255, 0)', techniques: '3d-transform,glow-shadow,animation,checkbox-input,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'Nawsome_short-dolphin-98', cat: 'Toggle-switches', author: 'Nawsome', tags: 'skeuomorphism,checkbox,squishy,bubble', html: '<label><input value="on" name="dummy" type="checkbox" class="bubble"></label>', css: '\n/* From Uiverse.io by Nawsome - Tags: skeuomorphism, checkbox, squishy, bubble */\nlabel, .bubble {\n  display: block;\n  -webkit-tap-highlight-color: transparent;\n}\n\nlabel {\n  animation: float74 4s ease-in-out infinite;\n}\n\n.bubble, .bubble:before, .bubble:after {\n  transition-duration: 0.2s;\n}\n\n.bubble, .bubble:after {\n  border-radius: 50%;\n}\n\n.bubble {\n  background-image: radial-gradient(8% 8% at 22% 28%,hsl(0,0%,100%) 45%,hsla(0,0%,100%,0) 50%),\n		radial-gradient(8% 8% at 23% 27%,hsl(0,0%,100%) 45%,hsla(0,0%,100%,0) 50%),\n		radial-gradient(8% 8% at 24% 26%,hsl(0,0%,100%) 45%,hsla(0,0%,100%,0) 50%),\n		radial-gradient(8% 8% at 25% 25%,hsl(0,0%,100%) 45%,hsla(0,0%,100%,0) 50%),\n		radial-gradient(8% 8% at 26% 24%,hsl(0,0%,100%) 45%,hsla(0,0%,100%,0) 50%),\n		radial-gradient(8% 8% at 27% 23%,hsl(0,0%,100%) 45%,hsla(0,0%,100%,0) 50%),\n		radial-gradient(8% 8% at 28% 22%,hsl(0,0%,100%) 45%,hsla(0,0%,100%,0) 50%);\n  box-shadow: 0 -0.06em 0.1em hsl(0,90%,100%) inset,\n		0 -0.15em 0.4em hsl(0,90%,45%) inset,\n		0 0.05em 0.05em hsl(0,90%,45%) inset,\n		0.05em 0 0.1em hsl(0,90%,100%) inset,\n		-0.05em 0 0.1em hsl(0,90%,100%) inset,\n		0 0.1em 0.4em hsl(0,90%,60%) inset;\n  cursor: pointer;\n  position: relative;\n  width: 3em;\n  height: 3em;\n  transform-style: preserve-3d;\n  transition-property: box-shadow, transform, width, height;\n  transition-timing-function: ease-in-out, ease-in-out, var(--bubbleTiming), var(--bubbleTiming);\n  will-change: transform;\n  -webkit-appearance: none;\n  appearance: none;\n  z-index: 0;\n}\n\n.bubble:before, .bubble:after {\n  content: "";\n  display: block;\n  position: absolute;\n  transition-timing-function: var(--bubbleTiming);\n}\n\n.bubble:before {\n  border-radius: 0.75em;\n  box-s