eg);\n}\n\n.slider .b {\n  position: relative;\n  top: -3.3em;\n  transform: rotate(270deg);\n}\n\n.slider .bling_85 {\n  stroke: #fff;\n  stroke-width: 2.5;\n  stroke-linecap: round;\n  stroke-dasharray: 3;\n  stroke-dashoffset: 15;\n  transition: all 0.3s ease;\n}\n\n/* Hide default HTML checkbox */\n.switch input {\n  opacity: 0;\n  width: 0;\n  height: 0;\n}\n\n/* The slider */\n.slider {\n  position: absolute;\n  cursor: pointer;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  transition: .4s;\n  border-radius: 50%;\n  background-color: rgba(116, 115, 115, 0.2);\n  backdrop-filter: blur(5px);\n  -webkit-backdrop-filter: blur(5px);\n  border: 1px solid rgba(255, 255, 255, 0.3);\n}\n\n.chk_85:checked + .slider {\n  animation: tap 0.3s linear forwards;\n}\n\n.chk_85:checked + .slider .bling_85 {\n  animation: bling_8561328 0.3s linear forwards;\n  animation-delay: 0.2s;\n}\n\n.chk_85:checked + .slider {\n  background-color: #FFA133;\n}\n\n.chk_85:focus + .slider {\n  box-shadow: 0 0 1px #FFA133;\n}\n\n@keyframes bling_8561328 {\n  50% {\n    stroke-dasharray: 3;\n    stroke-dashoffset: 12;\n  }\n\n  100% {\n    stroke-dasharray: 3;\n    stroke-dashoffset: 9;\n  }\n}\n\n@keyframes tap {\n  50% {\n    scale: 0.9;\n  }\n\n  100% {\n    scale: 1;\n  }\n}\n', colors: '#fff,#ffa133', radii: '50%', shadows: '0 0 1px #FFA133', techniques: 'glassmorphism,3d-transform,glow-shadow,animation,checkbox-input,svg-icon'),
const GalaxyComp(id: 'shadowfax29_sweet-warthog-93', cat: 'Toggle-switches', author: 'shadowfax29', tags: 'switch,toggle switch,plant,seed', html: '<label class="switch">\n  <input type="checkbox">\n   <span class="slider">\n     <svg class="seed" version="1.1" id="Layer_1" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" viewBox="0 0 512.004 512.004" xml:space="preserve" fill="#000000"><g id="SVGRepo_bgCarrier" stroke-width="0"></g><g id="SVGRepo_tracerCarrier" stroke-linecap="round" stroke-linejoin="round"></g><g id="SVGRepo_iconCarrier"> <g> <path style="fill:#e5c11f;" d="M370.114,157.811C351.523,65.174,307.456,0,256,0c-51.447,0-95.514,65.174-114.114,157.811 c41.057,46.036,72.854,122.827,92.328,199.477C251.065,406.528,256,461.356,256,512c0-50.644,4.935-105.472,21.786-154.712 C297.269,280.638,329.057,203.847,370.114,157.811"></path> <path style="fill:#AF6D2D;" d="M256.002,512.004c0-138.664-77.241-397.241-194.207-397.241 C-19.966,351.668,96.373,512.004,256.002,512.004"></path> <path style="fill:#864D18;" d="M185.347,471.952c-1.121,0-2.26-0.221-3.363-0.671c-31.603-13.065-58.033-34.278-78.539-63.047 c-41.393-58.068-52.515-141.047-31.329-233.657c1.086-4.758,5.826-7.733,10.575-6.63c4.749,1.086,7.724,5.817,6.638,10.567 c-20.047,87.623-9.931,165.57,28.495,219.471c18.556,26.033,42.408,45.197,70.894,56.973c4.511,1.863,6.656,7.027,4.793,11.529 C192.1,469.895,188.816,471.952,185.347,471.952"></path> <path style="fill:#AF6D2D;" d="M256.002,512.004c0-138.664,77.241-397.241,194.207-397.241 C531.97,351.668,415.631,512.004,256.002,512.004"></path> <path style="fill:#B49377;" d="M184.403,141.249c-0.83,0-1.66-0', css: '\n/* From Uiverse.io by shadowfax29 - Tags: switch, toggle switch, plant , seed */\n/* The switch - the box around the slider */\n.switch {\n  font-size: 17px;\n  position: relative;\n  display: inline-block;\n  width: 3.5em;\n  height: 2em;\n  --mud: #8B4513;\n}\n\n/* Hide default HTML checkbox */\n.switch input {\n  opacity: 0;\n  width: 0;\n  height: 0;\n}\n\n/* The slider */\n.slider {\n  position: absolute;\n  cursor: pointer;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  background: linear-gradient(to bottom,skyblue 70%,var(--mud));\n  transition: .4s;\n  border-radius: 30px;\n  border: 2px solid black;\n}\n\n.slider:before {\n  position: absolute;\n  content: "";\n  height: 1.4em;\n  width: 1.4em;\n  border-radius: 20px;\n  left: 0.3em;\n  bottom: 0.3em;\n  transition: .4s;\n}\n\n.plant {\n  position: absolute;\n  bottom: 3px;\n  right: -30px;\n  z-index: 3;\n  opacity: 0;\n}\n\n.seed {\n  position: absolute;\n  content: "";\n  height: 1.4em;\n  width: 1.4em;\n  border-radius: 20px;\n  left: 0.3em;\n  bottom: 0.3em;\n  transition: .4s;\n}\n\n.switch input:checked + .slider {\n  background-color: #156829;\n}\n\n.switch input:focus + .slider {\n  box-shadow: 0 0 1px #156829;\n}\n\n.switch input:checked + .slider:before,\n.switch input:checked + .slider .seed {\n  transform: translateX(1.5em);\n}\n\n.switch input:checked + .slider .seed {\n  opacity: 0;\n}\n\n.switch input:checked + .slider .plant {\n  animation: zoomIn 0.5s forwards;\n}\n\n@keyframes zoomIn {\n  0% {\n    transform: scale(0);\n    opacity: 0;\n  }\n\n  100% {\n    transform: scale(1);\n    opacity: 1;\n  }\n}\n', colors: '#8b4513,#156829', radii: '30px,20px', shadows: '0 0 1px #156829', techniques: '3d-transform,glow-shadow,gradient,animation,checkbox-input,svg-icon'),
