const GalaxyComp(id: 'Yaya12085_cold-insect-20', cat: 'Toggle-switches', author: '', tags: '', html: '<label class="switch">\n  <input type="checkbox">\n  <div class="button">\n    <span class="icon">\n      <svg xml:space="preserve" viewBox="0 0 463 463" xmlns:xlink="http://www.w3.org/1999/xlink" xmlns="http://www.w3.org/2000/svg" id="Capa_1" version="1.1" fill="#000000"><g stroke-width="0" id="SVGRepo_bgCarrier"></g><g stroke-linejoin="round" stroke-linecap="round" id="SVGRepo_tracerCarrier"></g><g id="SVGRepo_iconCarrier"> <g> <path d="M259.476,280.364V247.5c0-12.958-10.542-23.5-23.5-23.5s-23.5,10.542-23.5,23.5v29.672 c0,35.757-13.173,70.087-37.094,96.665l-32.981,36.646c-2.771,3.079-2.521,7.821,0.558,10.593c3.078,2.771,7.82,2.521,10.592-0.558 l32.981-36.646c26.403-29.338,40.944-67.231,40.944-106.7V247.5c0-4.687,3.813-8.5,8.5-8.5s8.5,3.813,8.5,8.5v32.864 c0,44.003-16.301,86.167-45.901,118.727l-32.149,35.364c-2.786,3.064-2.56,7.809,0.505,10.595c1.437,1.307,3.242,1.95,5.042,1.95 c2.04,0,4.072-0.827,5.552-2.455l32.148-35.364C241.789,373.854,259.476,328.106,259.476,280.364z"></path> <path d="M291.476,247.5c0-30.603-24.897-55.5-55.5-55.5s-55.5,24.897-55.5,55.5v29.672c0,27.839-10.256,54.566-28.879,75.258 l-23.447,26.053c-2.771,3.079-2.521,7.821,0.558,10.593c3.079,2.771,7.82,2.519,10.592-0.558l23.447-26.053 c21.106-23.451,32.73-53.742,32.73-85.293V247.5c0-22.332,18.168-40.5,40.5-40.5c22.332,0,40.5,18.168,40.5,40.5v32.864 c0,51.979-19.256,101.789-54.223,140.252l-27.125,29.839c-2.787,3.064-2.561,7.809,0.504,10.595c1.437,1.307,3.242,1.95,5.042,1.95 c2.04,0,4.072-0.827,5.552-2.455l27.126-', css: '\n/* From Uiverse.io by Yaya12085 - Source: https://uiverse.io/Pradeepsaranbishnoi/cuddly-sheep-92 - Tags: animation, 3d, switch, light, svg, fingerprint */\n.switch input {\n  display: none;\n}\n\n.button {\n  position: relative;\n  background-image: linear-gradient(#ffffff 33%,#414751 58%,#837b52,#c5baa1,#c3adaa);\n  border-radius: 50px;\n  padding: 6px;\n  border: none;\n  outline: none;\n  box-shadow: 0.1em 0 0 #2726267f inset, -0.1em 0 0 #27262600 inset, 0 0.1em 0 #afa490 inset, 0 -0.1em 0 #ffffff3f, 0 0.2em 0.5em #0000007f, 0 -0.1em 0 #151616 inset, -0.1em -0.2em 0 #ffffff7f inset;\n  cursor: pointer;\n  width: 4rem;\n  height: 4rem;\n  -webkit-appearance: none;\n  -moz-appearance: none;\n  appearance: none;\n  font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Roboto, Oxygen, Ubuntu, Cantarell, \'Open Sans\', \'Helvetica Neue\', sans-serif;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  transition: .3s ease-in-out;\n}\n\n.button::before {\n  position: absolute;\n  content: "";\n  width: 4.1rem;\n  height: 4.1rem;\n  border-radius: inherit;\n  background-color: #606060;\n  z-index: -1;\n  transition: background-image .3s ease-in-out;\n}\n\n.button .icon {\n  width: 4rem;\n  height: 4rem;\n  display: inline-block;\n}\n\n.button .icon svg {\n  height: 100%;\n  width: 100%;\n  fill: #000000;\n  transition: fill;\n}\n\n.switch input:checked + .button::before {\n  background-image: rgb(77, 124, 255);\n  animation: anime1 .3s linear alternate-reverse infinite;\n}\n\n.switch input:checked + .button {\n  box-shadow: none;\n}\n\n.switch input:checked + .button .icon svg {\n  fill: rgb(77, 124, 255);\n  animation: anime2 .3s linear alternate-reverse infinite;\n}\n\n@keyframes anime1 {\n  to {\n    background-color: rgb(77, 124, 255);\n  }\n}\n\n@keyframes anime2 {\n  to {\n    fill: rgba(77, 124, 255, 0.642);\n  }\n}\n', colors: '#afa490,#837b52,#27262600,#c3adaa,#0000007f,#151616,#414751,#ffffff7f,#ffffff3f,#606060', radii: '50px,inherit', shadows: '0.1em 0 0 #2726267f inset, -0.1em 0 0 #27262600 inset, 0 0.1em 0 #afa490 inset, 0 -0.1em 0 #ffffff3f, 0 0.2em 0.5em #000,none', techniques: 'glow-shadow,gradient,animation,checkbox-input,svg-icon,pseudo-elements'),
