  z-index: -1;\n  filter: blur(1px);\n}\n.white,\n.border,\n.darkBorderBg,\n.glow {\n  max-height: 70px;\n  max-width: 314px;\n  height: 100%;\n  width: 100%;\n  position: absolute;\n  overflow: hidden;\n  z-index: -1;\n  /* Border Radius */\n  border-radius: 12px;\n  filter: blur(3px);\n}\n.input {\n  background-color: #010201;\n  border: none;\n  /* padding:7px; */\n  width: 301px;\n  height: 56px;\n  border-radius: 10px;\n  color: white;\n  padding-inline: 59px;\n  font-size: 18px;\n}\n#poda {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n.input::placeholder {\n  color: #c0b9c0;\n}\n\n.input:focus {\n  outline: none;\n}\n\n#main:focus-within > #input-mask {\n  display: none;\n}\n\n#input-mask {\n  pointer-events: none;\n  width: 100px;\n  height: 20px;\n  position: absolute;\n  background: linear-gradient(90deg, transparent, black);\n  top: 18px;\n  left: 70px;\n}\n#pink-mask {\n  pointer-events: none;\n  width: 30px;\n  height: 20px;\n  position: absolute;\n  background: #cf30aa;\n  top: 10px;\n  left: 5px;\n  filter: blur(20px);\n  opacity: 0.8;\n  //animation:leftright 4s ease-in infinite;\n  transition: all 2s;\n}\n#main:hover > #pink-mask {\n  //animation: rotate 4s linear infinite;\n  opacity: 0;\n}\n\n.white {\n  max-height: 63px;\n  max-width: 307px;\n  border-radius: 10px;\n  filter: blur(2px);\n}\n\n.white::before {\n  content: "";\n  z-index: -2;\n  text-align: center;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%) rotate(83deg);\n  position: absolute;\n  width: 600px;\n  height: 600px;\n  background-repeat: no-repeat;\n  background-position: 0 0;\n  filter: brightness(1.4);\n  background-image: conic-gradient(\n    rgba(0, 0, 0, 0) 0%,\n    #a099d8,\n    rgba(0, 0, 0, 0) 8%,\n    rgba(0', colors: '#a099d8,#402fb5,#1c191c,#c0b9c0,#18116a,#010201,#000,#1d1b4b,#0f0f10,#6e1b60', radii: '10px,12px,11px', shadows: '', techniques: 'glassmorphism,3d-transform,gradient,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'Mythsoul_strange-insect-92', cat: 'Inputs', author: 'Mythsoul', tags: '', html: '<div class="custom-search-container">\n  <div class="custom-search-bar">\n    <div class="custom-icon">\n      <svg\n        class="feather feather-search"\n        stroke-linejoin="round"\n        stroke-linecap="round"\n        stroke-width="2"\n        stroke="currentColor"\n        fill="none"\n        viewBox="0 0 24 24"\n        xmlns="http://www.w3.org/2000/svg"\n      >\n        <circle r="8" cy="11" cx="11"></circle>\n        <line y2="16.65" x2="16.65" y1="21" x1="21"></line>\n      </svg>\n    </div>\n    <input placeholder="Search..." class="custom-search-input" type="text" />\n    <div class="custom-icon">\n      <svg\n        class="feather feather-filter"\n        stroke-linejoin="round"\n        stroke-linecap="round"\n        stroke-width="2"\n        stroke="currentColor"\n        fill="none"\n        viewBox="0 0 24 24"\n        xmlns="http://www.w3.org/2000/svg"\n      >\n        <polygon points="22 3 2 3 10 13 10 19 14 21 14 13 22 3"></polygon>\n      </svg>\n    </div>\n  </div>\n</div>', css: '\n/* From Uiverse.io by Mythsoul  - Tags:  */\n.custom-search-container {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  height: 100%;\n  background-color: #000;\n  background-image: radial-gradient(\n    circle,\n    rgba(255, 0, 255, 0.1),\n    rgba(0, 0, 255, 0.1)\n  );\n  background-size: cover, 10px 10px;\n}\n\n.custom-search-bar {\n  display: flex;\n  align-items: center;\n  background-color: #111;\n  padding: 10px;\n  border-radius: 20px;\n  position: relative;\n  width: 80%;\n  max-width: 400px;\n  box-shadow: 0 0 15px rgba(255, 0, 150, 0.5), 0 0 15px rgba(0, 0, 255, 0.5);\n  transition: width 0.3s;\n}\n\n.custom-icon {\n  color: #fff;\n  margin: 0 10px;\n  display: flex;\n  align-items: center;\n}\n\n.custom-search-input {\n  border: none;\n  outline: none;\n  background: transparent;\n  color: #fff;\n  font-size: 16px;\n  width: 100%;\n}\n\n.custom-search-input::placeholder {\n  color: #aaa;\n}\n\n.custom-search-bar:before {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  border-radius: 20px;\n  background: linear-gradient(\n    90deg,\n    rgba(255, 0, 255, 0.5),\n    rgba(0, 0, 255, 0.5)\n  );\n  z-index: -1;\n  filter: blur(10px);\n  animation: glow 4s infinite alternate;\n}\n\n@keyframes glow {\n  0% {\n    filter: blur(10px);\n    opacity: 0.7;\n    transform: scale(1);\n  }\n  50% {\n    filter: blur(20px);\n    opacity: 1;\n    transform: scale(1.05);\n  }\n  100% {\n    filter: blur(10px);\n    opacity: 0.7;\n    transform: scale(1);\n  }\n}\n\n.custom-icon svg {\n  width: 24px;\n  height: 24px;\n  stroke: currentColor;\n  transition: color 0.3s, transform 0.3s;\n}\n\n.custom-icon:hover svg {\n  color: #ff00ff;\n  cursor: pointer;\n  transform: scale(1.1);\n}\n\n/* Media queries for better responsiveness */\n@media (max-width: 600px) {\n  .custom-search-bar {\n    width: 90%;\n  }\n}\n\n@media (max-width: 400px) {\n  .custom-search-bar {\n    width: 100%;\n  }\n\n  .custom-search-input {\n    font-size: 14px;\n  }\n\n  .custom-icon {\n    margin: 0 5px;\n  }\n\n  .custom-icon svg {\n    width: 20', colors: '#aaa,#000,#ff00ff,#fff,#111', radii: '20px', shadows: '0 0 15px rgba(255, 0, 150, 0.5), 0 0 15px rgba(0, 0, 255, 0.5)', techniques: 'glassmorphism,3d-transform,glow-shadow,gradient,animation,svg-icon'),
