isplay: flex;\n  justify-content: center;\n}\n\n.input-wrapper {\n  isolation: isolate;\n  position: relative;\n  width: 100%;\n  max-width: 340px;\n}\n\n.search-icon {\n  position: absolute;\n  left: 1.5rem;\n  top: 50%;\n  opacity: 0.7;\n  width: 32px;\n  height: 32px;\n  translate: 0 -50%;\n}\n\n.input-wrapper input {\n  padding-top: 1rem;\n  padding-bottom: 1rem;\n  padding-right: 5rem;\n  padding-left: 5rem;\n  outline-style: none;\n  width: 100%;\n  font-size: 1.5rem;\n  line-height: 2rem;\n  background-color: #000000;\n  border: 2px solid rgba(255, 255, 255, 0.1);\n  border-radius: 20px;\n  color: white;\n}\n\n.filter-btn {\n  aspect-ratio: 1/1;\n  display: grid;\n  position: absolute;\n  right: 0.75rem;\n  top: 50%;\n  place-items: center;\n  border-radius: 0.75rem;\n  border-style: solid;\n  transition-property: background-color, border-color, color, fill, stroke,\n    opacity, box-shadow, transform;\n  transition-timing-function: cubic-bezier(0.4, 0, 0.2, 1);\n  transition-duration: 300ms;\n  transition-duration: 300ms;\n  cursor: pointer;\n  border: 2px solid rgba(255, 255, 255, 0.1);\n  width: 48px;\n  height: 48px;\n  background-color: rgba(255, 255, 255, 0.1);\n  translate: 0 -50%;\n}\n\n.filter-btn svg {\n  width: 32px;\n  height: 32px;\n  transition-property: background-color, border-color, color, fill, stroke,\n    opacity, box-shadow, transform;\n  transition-timing-function: cubic-bezier(0.4, 0, 0.2, 1);\n  transition-duration: 300ms;\n  transition-duration: 300ms;\n  opacity: 0.7;\n}\n\n.filter-btn:hover {\n  background-color: white;\n}\n\n.filter-btn:hover svg {\n  stroke: black;\n}\n\n.pink-overlay {\n  position: absolute;\n  left: 0;\n  top: 50%;\n  border-radius: 9999px;\n  width: 5rem;\n  height: 5rem;\n  transition-pro', colors: '#b43598,#000000,#000,#120d57', radii: '50%,9999px,20px,0.75rem', shadows: '0 0 20px 20px #000 inset', techniques: 'glassmorphism,cubic-bezier,glow-shadow,gradient,animation,svg-icon'),
const GalaxyComp(id: 'SelfMadeSystem_ancient-goat-9', cat: 'Inputs', author: 'SelfMadeSystem', tags: '', html: '<input type="checkbox" style="display: none;" id="searched" />\n<div class="outer">\n  <div class="tooltip">\n    <div class="a"></div>\n    <div class="b"></div>\n    <div class="b"></div>\n    <div class="b"></div>\n    <div class="b"></div>\n    <div class="b"></div>\n    <div class="b"></div>\n    <div class="label">\n      <div class="c"></div>\n      <div class="c"></div>\n      <span>Click Search</span>\n    </div>\n  </div>\n  <div class="a"></div>\n  <div class="b"></div>\n  <div class="b"></div>\n  <div class="b"></div>\n  <div class="b"></div>\n  <div class="b"></div>\n  <div class="b"></div>\n  <label for="text-field" class="label">\n    <div class="c"></div>\n    <div class="c"></div>\n    <label for="searched" class="searched-thing">\n      <svg\n        viewBox="0 0 24 24"\n        xmlns="http://www.w3.org/2000/svg"\n        class="search"\n      >\n        <defs>\n          <radialGradient r="1" cy="0" cx="0" id="myGradient">\n            <stop stop-color="white" offset="0%"></stop>\n            <stop stop-color="#928293" offset="100%"></stop>\n          </radialGradient>\n        </defs>\n        <path\n          class="search-path"\n          d="M9.5,3A6.5,6.5 0 0,1 16,9.5C16,11.11 15.41,12.59 14.44,13.73L14.71,14H15.5L20.5,19L19,20.5L14,15.5V14.71L13.73,14.44C12.59,15.41 11.11,16 9.5,16A6.5,6.5 0 0,1 3,9.5A6.5,6.5 0 0,1 9.5,3M9.5,5C7,5 5,7 5,9.5C5,12 7,14 9.5,14C12,14 14,12 14,9.5C14,7 12,5 9.5,5Z"\n        ></path>\n        <path\n          class="chevron-path"\n          d="M7.41,15.41L12,10.83L16.', css: '\n/* From Uiverse.io by SelfMadeSystem  - Tags:  */\n.outer {\n  position: relative;\n  border-radius: 0.75rem;\n  border: 2px solid #242325;\n  width: 17rem;\n  --angle: 155deg;\n  animation: uwu 5s infinite linear paused;\n  height: 3rem;\n  transition: height 1s ease;\n}\n\n.a {\n  position: absolute;\n  inset: -2px;\n  background: linear-gradient(\n    var(--angle),\n    #d8b1d9,\n    #ff00ff 20%,\n    #ff00ff00 30%,\n    #5b49d600 70%,\n    #3863ff 80%,\n    #c2baf8\n  );\n  border-radius: calc(0.75rem + 2px);\n  filter: blur(2px);\n}\n\n.b {\n  position: absolute;\n  inset: 0px;\n  background: linear-gradient(\n    var(--angle),\n    #ff00ff,\n    #ff00ff00,\n    #5b49d600,\n    #3863ff\n  );\n  border-radius: calc(0.75rem + 0px);\n  filter: blur(10px);\n  opacity: 0.3;\n  transition: opacity 0.5s;\n}\n\n.outer:has(input:focus) :is(.b, .c) {\n  opacity: 0.75;\n}\n\n.label {\n  position: absolute;\n  inset: 0;\n  overflow: hidden;\n  background-color: #000;\n  z-index: 10;\n  display: flex;\n  align-items: flex-start;\n  box-sizing: content-box;\n  padding: 0.35rem;\n  border-radius: 0.75rem;\n}\n\n.c {\n  position: absolute;\n  pointer-events: none;\n  z-index: 1;\n  inset: -20px;\n  background: linear-gradient(\n    var(--angle),\n    #ff00ff,\n    #ff00ff00,\n    #5b49d600,\n    #3863ff\n  );\n  filter: blur(30px);\n  opacity: 0.5;\n  transition: opacity 0.5s;\n}\n\n.text-field {\n  background-color: transparent;\n  flex-grow: 1;\n  border: none;\n  outline: 0 !important;\n  color: #fff;\n  height: 2rem;\n  margin: 0 0.5rem;\n  min-width: 0;\n}\n\n.text-field::placeholder {\n  color: #999999;\n}\n\n.search {\n  fill: url(#myGradient);\n}\n\n.searched-thing {\n  display: flex;\n  align-items: center;\n  z-index: 1;\n  margin-left: 0.25rem;\n  width: 2rem;\n  height: 2rem;\n  cursor: pointer;\n}\n\n.searched-thing svg {\n  width: 1.5rem;\n  height: 1.5rem;\n}\n\n.filter {\n  z-index: 1;\n  background: linear-gradient(#100f1e, #413d54, #100f1e);\n  position: relative;\n  border: none;\n  border-radius: 0.5rem;\n  width: 2rem;\n  height: 2rem;\n  cursor: pointer;\n  flex-shrink: 0;', colors: '#3863ff,#100f1e,#1c1a3b,#fff,#0a071e,#d8b1d9,#413d54,#ff00ff44,#6882e3,#242325', radii: 'calc(0.75rem + 0px),calc(0.5rem - 2px),100%,1rem,calc(0.75rem + 2px)', shadows: '', techniques: 'glassmorphism,3