const GalaxyComp(id: 'seyed-mohsen-mousavi_average-elephant-52', cat: 'Inputs', author: 'seyed-mohsen-mousavi', tags: 'input,shadow,gradient', html: '<div class="search-bar">\n  <div class="blob"></div>\n  <svg\n    xmlns="http://www.w3.org/2000/svg"\n    fill="none"\n    viewBox="0 0 24 24"\n    stroke-width="1.5"\n    stroke="currentColor"\n    class="icon"\n  >\n    <path\n      stroke-linecap="round"\n      stroke-linejoin="round"\n      d="m21 21-5.197-5.197m0 0A7.5 7.5 0 1 0 5.196 5.196a7.5 7.5 0 0 0 10.607 10.607Z"\n    ></path>\n  </svg>\n  <input type="text" id="ser" class="inner" placeholder="Search ..." />\n</div>', css: '\n/* From Uiverse.io by seyed-mohsen-mousavi  - Tags: input, shadow, gradient */\n/* Main style for the search bar */\n.search-bar {\n  cursor: text;\n  font-size: 1.6rem;\n  border-radius: 16px;\n  border: none;\n  padding: 2px;\n  background: -webkit-radial-gradient(circle 80px at 80% -10%, #fff, #181b1b);\n  background: -moz-radial-gradient(circle 80px at 80% -10%, #fff, #181b1b);\n  background: radial-gradient(circle 80px at 80% -10%, #fff, #181b1b);\n  position: relative;\n  -webkit-transition: all 0.3s linear;\n  -moz-transition: all 0.3s linear;\n  transition: all 0.3s linear;\n  -webkit-box-shadow: 0 0 5px rgba(0, 0, 0, 0.66);\n  -moz-box-shadow: 0 0 5px rgba(0, 0, 0, 0.66);\n  box-shadow: 0 0 5px rgba(0, 0, 0, 0.66);\n  overflow: hidden;\n}\n\n/* Style for the ::after pseudo-element of the search bar */\n.search-bar::after {\n  cursor: text;\n  content: "";\n  position: absolute;\n  width: 65%;\n  height: 60%;\n  border-radius: 120px;\n  top: 0;\n  right: 0;\n  -webkit-box-shadow: 0 0 20px rgba(255, 255, 255, 0.22);\n  -moz-box-shadow: 0 0 20px rgba(255, 255, 255, 0.22);\n  box-shadow: 0 0 20px rgba(255, 255, 255, 0.22);\n  z-index: -1;\n}\n\n/* Style for the decorative blob */\n.blob {\n  position: absolute;\n  width: 70px;\n  height: 100%;\n  border-radius: 16px;\n  bottom: 0;\n  left: 0;\n  background: -webkit-radial-gradient(\n    circle 60px at 0% 100%,\n    #ff3fcb,\n    rgba(255, 0, 216, 0.5),\n    transparent\n  );\n  background: -moz-radial-gradient(\n    circle 60px at 0% 100%,\n    #ff3fcb,\n    rgba(255, 0, 216, 0.5),\n    transparent\n  );\n  background: radial-gradient(\n    circle 60px at 0% 100%,\n    #ff3fcb,\n    rgba(255, 0, 216, 0.5),\n    transparent\n  );\n  -webkit-box-shadow: -10px 10px 30px rgba(255, 0, 229, 0.18);\n  -moz-box-shadow: -10px 10px 30px rgba(255, 0, 229, 0.18);\n  box-shadow: -10px 10px 30px rgba(255, 0, 229, 0.18);\n}\n\n/* Style for the inner content */\n.inner {\n  padding: 14px 25px;\n  border-radius: 14px;\n  color: #fff;\n  z-index: 3;\n  position: relative;\n  background: -webkit-radial', colors: '#777,#ff3fcb,#181b1b,#fff,#0f1111', radii: '14px,120px,16px', shadows: '0 0 5px rgba(0, 0, 0, 0.66),0 0 5px rgba(0, 0, 0, 0.66),0 0 5px rgba(0, 0, 0, 0.66)', techniques: '3d-transform,glow-shadow,text-shadow,gradient,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'Yaya12085_new-rabbit-37', cat: 'Inputs', author: 'Yaya12085', tags: 'animation,gradient,button,input,focus,challenge,input effect,input', html: '<div class="wrapper">\n  <span class="search">\n    <svg\n      fill="none"\n      color="#000000"\n      height="24"\n      width="24"\n      viewBox="0 0 24 24"\n      xmlns="http://www.w3.org/2000/svg"\n    >\n      <path\n        stroke-linejoin="round"\n        stroke-linecap="round"\n        stroke-width="1.5"\n        stroke="currentColor"\n        d="M17.5 17.5L22 22"\n      ></path>\n      <path\n        stroke-linejoin="round"\n        stroke-width="1.5"\n        stroke="currentColor"\n        d="M20 11C20 6.02944 15.9706 2 11 2C6.02944 2 2 6.02944 2 11C2 15.9706 6.02944 20 11 20C15.9706 20 20 15.9706 20 11Z"\n      ></path></svg\n  ></span>\n\n  <input type="text" name="text" class="input" placeholder="Search..." />\n  <div class="coloredborder"></div>\n\n  <button class="filter">\n    <svg\n      xmlns="http://www.w3.org/2000/svg"\n      viewBox="0 0 24 24"\n      width="24"\n      height="24"\n      color="#000000"\n      fill="none"\n    >\n      <path\n        d="M8.85746 12.5061C6.36901 10.6456 4.59564 8.59915 3.62734 7.44867C3.3276 7.09253 3.22938 6.8319 3.17033 6.3728C2.96811 4.8008 2.86701 4.0148 3.32795 3.5074C3.7889 3 4.60404 3 6.23433 3H17.7657C19.396 3 20.2111 3 20.672 3.5074C21.133 4.0148 21.0319 4.8008 20.8297 6.37281C20.7706 6.83191 20.6724 7.09254 20.3726 7.44867C19.403 8.60062 17.6261 10.6507 15.1326 12.5135C14.907 12.6821 14.7583 12.9567 14.7307 13.2614C14.4837 15.992 14.2559 17.4876 14.1141 18.2442C13.8853 19.4657 12.1532 20.2006 11.226 20.8563C10.6741 21.2466 10.0043 20.782 9.93278 ', css: '\n/* From Uiverse.io by Yaya12085  - Tags: animation, gradient, button, input, focus, challenge, input effect , input */\n.wrapper {\n  --color1: #cc279a;\n  --color2: #4d38de;\n  --color3: #010101;\n  --white: #fff;\n  --radius: 10px;\n  --size: 280px;\n  --icon: 35px;\n  --border-color: rgba(255, 255, 255, 0.3);\n  --line: rgba(114, 114, 114, 0.3);\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  border-radius: var(--radius);\n  background-color: var(--color3);\n  max-width: var(--size);\n  width: 100%;\n  padding: 2px 8px;\n  position: relative;\n  border: 1px solid var(--border-color);\n  transition: 0.2s 0s linear;\n}\n.wrapper:focus-within {\n  box-shadow: -100px 0px 80px -20px var(--color1),\n    100px 0 80px -20px var(--color2), 0px 0px 80px -0px var(--color3);\n}\n.wrapper::after {\n  position: absolute;\n  content: "";\n  inset: -50px;\n  border-radius: var(--radius);\n  z-index: -2;\n  background-color: var(--color3);\n  background-image: linear-gradient(\n      0deg,\n      transparent 24%,\n      var(--line) 25%,\n      var(--line) 26%,\n      transparent 27%,\n      transparent 74%,\n      var(--line) 75%,\n      var(--line) 76%,\n      transparent 77%,\n      transparent\n    ),\n    linear-gradient(\n      90deg,\n      transparent 24%,\n      var(--line) 25%,\n      var(--line) 26%,\n      transparent 27%,\n      transparent 74%,\n      var(--line) 75%,\n      var(--line) 76%,\n      transparent 77%,\n      transparent\n    );\n  background-size: 30px 30px;\n  border: 10px solid rgba(0, 0, 0, 0.6);\n}\n.input {\n  flex: 1;\n  height: 100%;\n  padding: 16px 6px 16px calc(var(--icon) + 6px);\n  outline: none;\n  border: none;\n  background-color: transparent;\n  color: var(--white);\n  font-weight: 400;\n}\n\n.input::placeholder {\n  color: var(--white);\n  font-weight: 400;\n}\n\n.search,\n.filter {\n  width: var(--icon);\n  height: var(--icon);\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  border-radius: var(--radius);\n}\n\n.search svg,\n.filter svg {\n  color: var(--white);\n}\n.s', colors: '#4d38de,#010101,#cc279a,#fff', radii: 'var(--radius),inherit', shadows: '-100px 0px 80px -20px var(--color1),\n    100px 0 80px -20px var(--color2), 0px 0px 80px -0px var(--color3),0