const GalaxyComp(id: 'csemszepp_calm-grasshopper-57', cat: 'Checkboxes', author: '', tags: '', html: '<div class="container">\n      <label>\n        <input class="play-btn" type="checkbox">\n        <div class="play-icon"></div>\n        <div class="pause-icon"></div>\n      </label>\n    </div>', css: '\n/* From Uiverse.io by csemszepp - Source: https://codepen.io/RitikaAgrawal08/pen/eYGXQLz - Tags: checkbox, play, music player */\n.container {\n  width: 120px;\n  height: 120px;\n  position: relative;\n  border-radius: 50%;\n}\n\n.play-btn {\n  position: absolute;\n  appearance: none;\n  width: 100%;\n  height: 100%;\n  border-radius: 50%;\n  background: conic-gradient(#ff6347, #ff6347);\n  cursor: pointer;\n  outline: none;\n}\n\n.play-btn::before {\n  content: "";\n  position: absolute;\n  width: 93%;\n  height: 93%;\n  background-color: #000;\n  border-radius: 50%;\n  left: 50%;\n  top: 50%;\n  transform: translate(-50%, -50%);\n}\n\n.play-btn:checked {\n  animation: borderAnimate 700ms ease-in-out 1;\n  animation-fill-mode: forwards;\n}\n\n@keyframes borderAnimate {\n  0% {\n    transform: rotate(0);\n    background: conic-gradient(#ff6347, transparent 20%);\n  }\n\n  80% {\n    background: conic-gradient(#ff6347, transparent 90%);\n  }\n\n  100% {\n    transform: rotate(360deg);\n    background: conic-gradient(#ff6347, #ff6347);\n  }\n}\n\n.play-icon {\n  position: absolute;\n  width: 40px;\n  height: 40px;\n  left: 60%;\n  top: 50%;\n  background-color: #ff6347;\n  transform: translate(-60%, -50%) rotate(90deg);\n  clip-path: polygon(50% 15%, 0% 100%, 100% 100%);\n  transition: all 400ms ease-in-out;\n  cursor: pointer;\n}\n\n.play-btn:checked + .play-icon {\n  clip-path: polygon(0 100%, 0% 100%, 100% 100%);\n}\n\n.pause-icon {\n  position: absolute;\n  width: 40px;\n  height: 40px;\n  left: 50%;\n  top: 50%;\n  transform: translate(-50%, -50%);\n  cursor: pointer;\n}\n\n.pause-icon::before {\n  content: "";\n  position: absolute;\n  width: 0%;\n  height: 100%;\n  background-color: #ff6347;\n  left: 0;\n}\n\n.pause-icon::after {\n  content: "";\n  position: absolute;\n  width: 0;\n  height: 100%;\n  background-color: #ff6347;\n  right: 0;\n}\n\n.play-btn:checked ~ .pause-icon::before {\n  animation: reveal 300ms ease-in-out 350ms 1;\n  animation-fill-mode: forwards;\n}\n\n.play-btn:checked ~ .pause-icon::after {\n  animation: reveal 300ms ease-in-out 600ms 1;\n', colors: '#ff6347,#000', radii: '50%', shadows: '', techniques: '3d-transform,gradient,animation,clip-path,checkbox-input,pseudo-elements'),
const GalaxyComp(id: 'EddyBel_smart-insect-43', cat: 'Checkboxes', author: 'EddyBel', tags: 'gradient,checkbox', html: '<label class="container">\n  <input checked="checked" type="checkbox">\n  <div class="checkmark"></div>\n</label>', css: '\n/* From Uiverse.io by EddyBel - Tags: gradient, checkbox */\n/* Hide the default checkbox */\n.container input {\n  position: absolute;\n  opacity: 0;\n  cursor: pointer;\n  height: 0;\n  width: 0;\n}\n\n.container {\n  display: block;\n  position: relative;\n  cursor: pointer;\n  font-size: 20px;\n  user-select: none;\n}\n\n.container::before {\n  position: absolute;\n  left: 0;\n  top: 0;\n  content: "";\n  width: 100%;\n  height: 100%;\n  border-radius: 50%;\n  filter: blur(5px);\n  background-color: #b899ff;\n  background-image: radial-gradient(at 6% 13%, hsla(322,81%,60%,1) 0px, transparent 50%),\nradial-gradient(at 9% 59%, hsla(209,65%,71%,1) 0px, transparent 50%),\nradial-gradient(at 39% 16%, hsla(325,93%,79%,1) 0px, transparent 50%);\n}\n\n/* Create a custom checkbox */\n.checkmark {\n  position: relative;\n  top: 0;\n  left: 0;\n  height: 2em;\n  width: 2em;\n  border-radius: 50%;\n  background-color: rgb(255, 255, 255);\n}\n\n/* When the checkbox is checked, add a blue background */\n.container input:checked ~ .checkmark {\n  height: 2em;\n  width: 2em;\n  border-radius: 50%;\n  position: relative;\n}\n\n.container input:checked ~ .checkmark::before {\n  position: absolute;\n  left: 0;\n  top: 0;\n  right: 0;\n  bottom: 0;\n  margin: auto;\n  width: 65%;\n  height: 65%;\n  content: "";\n  border-radius: 50%;\n  background-color: #ff99f0;\n  background-image: radial-gradient(at 86% 29%, hsla(277,65%,76%,1) 0px, transparent 50%),\n  radial-gradient(at 13% 20%, hsla(54,73%,71%,1) 0px, transparent 50%),\n  radial-gradient(at 76% 0%, hsla(145,64%,69%,1) 0px, transparent 50%);\n  animation: animation__checked 600ms normal;\n}\n\n@keyframes animation__checked {\n  0% {\n    opacity: 0;\n    transform: scale(0.8);\n  }\n\n  100% {\n    opacity: 100;\n    transform: scale(1);\n  }\n}\n', colors: '#ff99f0,#b899ff', radii: '50%', shadows: '', techniques: 'glassmorphism,3d-transform,gradient,animation,checkbox-input,pseudo-elements'),
const GalaxyComp(id: 'milegelu_grumpy-wombat-18', cat: 'Checkboxes', author: 'milegelu', tags: 'blue,black,button,active,checkbox,modern,click animation', html: '<label class="container">\n  <input type="checkbox" />\n  <div class="checkmark">\n    <svg xmlns="http://www.w3.org/2000/svg" class="icon No" viewBox="0 0 16 16">\n      <path\n        fill-rule="evenodd"\n        d="M8 0C3.584 0 0 3.584 0 8s3.584 8 8 8c4.408 0 8-3.584 8-8s-3.592-8-8-8zm5.284 3.688a6.802 6.802 0 0 1 1.545 4.251c-.226-.043-2.482-.503-4.755-.217-.052-.112-.096-.234-.148-.355-.139-.33-.295-.668-.451-.99 2.516-1.023 3.662-2.498 3.81-2.69zM8 1.18c1.735 0 3.323.65 4.53 1.718-.122.174-1.155 1.553-3.584 2.464-1.12-2.056-2.36-3.74-2.551-4A6.95 6.95 0 0 1 8 1.18zm-2.907.642A43.123 43.123 0 0 1 7.627 5.77c-3.193.85-6.013.833-6.317.833a6.865 6.865 0 0 1 3.783-4.78zM1.163 8.01V7.8c.295.01 3.61.053 7.02-.971.199.381.381.772.555 1.162l-.27.078c-3.522 1.137-5.396 4.243-5.553 4.504a6.817 6.817 0 0 1-1.752-4.564zM8 14.837a6.785 6.785 0 0 1-4.19-1.44c.12-.252 1.509-2.924 5.361-4.269.018-.009.026-.009.044-.017a28.246 28.246 0 0 1 1.457 5.18A6.722 6.722 0 0 1 8 14.837zm3.81-1.171c-.07-.417-.435-2.412-1.328-4.868 2.143-.338 4.017.217 4.251.295a6.774 6.774 0 0 1-2.924 4.573z"\n      ></path>\n    </svg>\n    <p class="No name">ball</p>\n    <svg\n      viewBox="0 0 16 16"\n      class="icon Yes"\n      xmlns="http://www.w3.org/2000/svg"\n    >\n      <path\n        d="M11.5 6.027a.5.5 0 1 1-1 0 .5.5 0 0 1 1 0zm-1.5 1.5a.5.5 0 1 0 0-1 .5.5 0 0 0 0 1zm2.5-.5a.5.5 0 1 1-1 0 .5.5 0 0 1 1 0zm-1.5 1.5a.5.5 0 1 0 0-1 .5.5 0 0 0 0 1zm-6.5-3h1v1h1v1h-1v1h-1v-1h-1v-1h1v-1z"\n      ></path>\n      <path\n     ', css: '\n/* From Uiverse.io by milegelu  - Tags: blue, black, button, active, checkbox, modern, click animation */\n.container {\n  --UnChacked-color: hsl(0, 0%, 10%);\n  --chacked-color: hsl(216, 100%, 60%);\n  --font-color: white;\n  --chacked-font-color: var(--font-color);\n  --icon-size: 1.5em;\n  --anim-time: 0.2s;\n  --anim-scale: 0.1;\n  --base-radius: 0.8em;\n}\n\n.container {\n  display: flex;\n  align-items: center;\n  position: relative;\n  cursor: pointer;\n  font-size: 20px;\n  user-select: none;\n  fill: var(--font-color);\n  color: var(--font-color);\n}\n\n/* Hide the default checkbox */\n.container input {\n  display: none;\n}\n\n/* Base custom checkbox */\n.checkmark {\n  background: var(--UnChacked-color);\n  border-radius: var(--base-radius);\n\n  display: flex;\n  padding: 0.5em;\n}\n.icon {\n  width: var(--icon-size);\n  height: auto;\n  filter: drop-shadow(0px 2px var(--base-radius) rgba(0, 0, 0, 0.25));\n}\n.name {\n  margin: 0 0.25em;\n}\n.Yes {\n  width: 0;\n}\n.name.Yes {\n  display: none;\n}\n\n/* action custom checkbox */\n.container:hover .checkmark,\n.container:hover .icon,\n.container:hover .name {\n  transform: scale(calc(1 + var(--anim-scale)));\n}\n\n.container:active .checkmark,\n.container:active .icon,\n.container:active .name {\n  transform: scale(calc(1 - var(--anim-scale) / 2));\n  border-radius: calc(var(--base-radius) * 2);\n}\n.checkmark::before {\n  content: "";\n  opacity: 0.5;\n  transform: scale(1);\n  border-radius: var(--base-radius);\n  position: absolute;\n  box-sizing: border-box;\n  left: 0;\n  top: 0;\n  height: 100%;\n  width: 100%;\n}\n.checkmark:hover:before {\n  background-color: hsla(0, 0%, 50%, 0.2);\n}\n.container input:checked + .checkmark:before {\n  animation: boon calc(var(--anim-time)) ease;\n  animation-delay: calc(var(--anim-time) / 2);\n}\n\n/* When the checkbox is checked*/\n.container input:checked + .checkmark {\n  --UnChacked-color: var(--chacked-color);\n  fill: var(--chacked-font-color);\n  color: var(--chacked-font-color);\n}\n\n.container input:checked ~ .checkmark .No {\n  width: 0;\n}\n.c', colors: '', radii: 'var(--base-radius),1em,calc(var(--base-radius) * 2)', shadows: '', techniques: '3d-transform,animation,filter-effect,checkbox-input,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'mnikita7767_purple-swan-7', cat: 'Checkboxes', author: 'mnikita7767', tags: 'checkbox', html: '<section class="container">\n  <label>\n    <input type="checkbox" name="check" />\n    <span></span>\n    <p>N</p>\n  </label>\n</section>', css: '\n/* From Uiverse.io by mnikita7767  - Tags: checkbox */\n.container {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n}\n.container label {\n  cursor: pointer;\n  position: relative;\n  width: 80px;\n  height: 80px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\nlabel input {\n  appearance: none;\n}\nlabel span {\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  background: linear-gradient(#555353, #363535, #303030);\n  border: 2px solid #222;\n  border-top-width: 4px;\n  border-radius: 6px;\n  box-shadow: inset 0 5px 1px rgba(0, 0, 0, 0.23), 0 5px 5px rgba(0, 0, 0, 0.5),\n    0 15px 25px rgba(0, 0, 0, 0.35);\n}\n.container label span::before {\n  content: "";\n  position: absolute;\n  border-top: 1px solid #fff;\n  inset: 5px 3px;\n  filter: blur(5px);\n}\n.container label input:checked ~ span {\n  box-shadow: inset 0 2px 2px rgba(0, 0, 0, 0.35),\n    inset 0 5px 5px rgba(0, 0, 0, 0.5), inset 0 15px 25px rgba(0, 0, 0, 0.35);\n}\nlabel p {\n  position: relative;\n  z-index: 10;\n  font-size: 3rem;\n  color: #111;\n}\n.container label input:checked ~ p {\n  color: #fff;\n  text-shadow: 0 0 5px #219cf3, 0 0 8px #219cf3;\n}\n\n', colors: '#219cf3,#303030,#222,#363535,#fff,#555353,#111', radii: '6px', shadows: 'inset 0 5px 1px rgba(0, 0, 0, 0.23), 0 5px 5px rgba(0, 0, 0, 0.5),\n    0 15px 25px rgba(0, 0, 0, 0.35),inset 0 2px 2px rgba(0, 0, 0, 0.35),\n    inset 0 5px 5px rgba(0, 0, 0, 0.5), inset 0 15px 25px rgba(0, 0, 0, 0.35)', techniques: 'glassmorphism,glow-shadow,text-shadow,gradient,checkbox-input,pseudo-elements'),
const GalaxyComp(id: 'SalladShooter_hot-rattlesnake-30', cat: 'Checkboxes', author: 'SalladShooter', tags: 'icon,button,active,checkbox,like,heart,dark', html: '<div class="like-wrapper">\n  <input class="check" type="checkbox" id="like-toggle" />\n  <label class="container" for="like-toggle">\n    <svg\n      viewBox="0 0 512 512"\n      xmlns="http://www.w3.org/2000/svg"\n      class="icon inactive"\n    >\n      <path\n        d="M225.8 468.2l-2.5-2.3L48.1 303.2C17.4 274.7 0 234.7 0 192.8v-3.3c0-70.4 50-130.8 119.2-144C158.6 37.9 198.9 47 231 69.6c9 6.4 17.4 13.8 25 22.3c4.2-4.8 8.7-9.2 13.5-13.3c3.7-3.2 7.5-6.2 11.5-9c0 0 0 0 0 0C313.1 47 353.4 37.9 392.8 45.4C462 58.6 512 119.1 512 189.5v3.3c0 41.9-17.4 81.9-48.1 110.4L288.7 465.9l-2.5 2.3c-8.2 7.6-19 11.9-30.2 11.9s-22-4.2-30.2-11.9zM239.1 145c-.4-.3-.7-.7-1-1.1l-17.8-20c0 0-.1-.1-.1-.1c0 0 0 0 0 0c-23.1-25.9-58-37.7-92-31.2C81.6 101.5 48 142.1 48 189.5v3.3c0 28.5 11.9 55.8 32.8 75.2L256 430.7 431.2 268c20.9-19.4 32.8-46.7 32.8-75.2v-3.3c0-47.3-33.6-88-80.1-96.9c-34-6.5-69 5.4-92 31.2c0 0 0 0-.1 .1s0 0-.1 .1l-17.8 20c-.3 .4-.7 .7-1 1.1c-4.5 4.5-10.6 7-16.9 7s-12.4-2.5-16.9-7z"\n      ></path>\n    </svg>\n    <svg\n      viewBox="0 0 512 512"\n      xmlns="http://www.w3.org/2000/svg"\n      class="icon active"\n    >\n      <path\n        d="M47.6 300.4L228.3 469.1c7.5 7 17.4 10.9 27.7 10.9s20.2-3.9 27.7-10.9L464.4 300.4c30.4-28.3 47.6-68 47.6-109.5v-5.8c0-69.9-50.5-129.5-119.4-141C347 36.5 300.6 51.4 268 84L256 96 244 84c-32.6-32.6-79-47.5-124.6-39.9C50.5 55.6 0 115.2 0 185.1v5.8c0 41.5 17.2 81.2 47.6 109.5z"\n      ></path>\n    </svg>\n    <div class="checkmark"></div>\n    <span class="like-text', css: '\n/* From Uiverse.io by SalladShooter  - Tags: icon, button, active, checkbox, like, heart, dark */\n.like-wrapper {\n  --gap: 0.5em;\n  --radius: 0.35em;\n  display: flex;\n  align-items: center;\n  text-align: center;\n  justify-content: center;\n  --dot-bg: #212121;\n  --dot-color: #313131;\n  --dot-size: 1px;\n  --dot-space: 22px;\n  background: linear-gradient(\n        90deg,\n        var(--dot-bg) calc(var(--dot-space) - var(--dot-size)),\n        transparent 1%\n      )\n      center / var(--dot-space) var(--dot-space),\n    linear-gradient(\n        var(--dot-bg) calc(var(--dot-space) - var(--dot-size)),\n        transparent 1%\n      )\n      center / var(--dot-space) var(--dot-space),\n    var(--dot-color);\n  border: 0.1em solid #313131;\n  padding: 0.5em;\n  border-radius: var(--radius);\n  box-shadow: 0 0 1em 0.5em rgba(0, 0, 0, 0.1);\n  cursor: pointer;\n}\n\n.check[type="checkbox"] {\n  display: none;\n}\n\n.container {\n  display: flex;\n  align-items: center;\n  cursor: pointer;\n  margin-top: -0.25em;\n  margin-bottom: -0.25em;\n}\n\n.icon {\n  width: 1.5em;\n  height: 1.5em;\n  margin-left: 0.5em;\n  fill: white;\n  transition: opacity 0.3s ease-in-out;\n}\n\n.icon.active {\n  display: none;\n  fill: #f52121;\n}\n\n.check[type="checkbox"]:checked + .container .icon.active {\n  display: inline-block;\n  animation: wiggle 0.5s ease-in-out;\n}\n\n.check[type="checkbox"]:checked + .container .icon.inactive {\n  display: none;\n}\n\n.like-text {\n  margin-left: 0.5em;\n  padding: 0.5em;\n  color: white;\n  font-family: Arial, sans-serif;\n  font-weight: bolder;\n}\n\n@keyframes wiggle {\n  0%,\n  100% {\n    transform: rotate(0deg);\n  }\n  25% {\n    transform: rotate(-10deg);\n  }\n  50% {\n    transform: rotate(10deg);\n  }\n  75% {\n    transform: rotate(-10deg);\n  }\n}\n\n', colors: '#212121,#313131,#f52121', radii: 'var(--radius)', shadows: '0 0 1em 0.5em rgba(0, 0, 0, 0.1)', techniques: '3d-transform,glow-shadow,gradient,animation,checkbox-input,svg-icon'),
const GalaxyComp(id: 'Shoh2008_perfect-mouse-3', cat: 'Checkboxes', author: 'Shoh2008', tags: 'checkbox', html: '<div class="checkbox-wrapper-33">\n  <label class="checkbox">\n    <input type="checkbox" class="checkbox__trigger visuallyhidden">\n    <span class="checkbox__symbol">\n      <svg xmlns="http://www.w3.org/2000/svg" version="1" viewBox="0 0 28 28" height="28px" width="28px" class="icon-checkbox" aria-hidden="true">\n        <path d="M4 14l8 7L24 7"></path>\n      </svg>\n    </span>\n    <p class="checkbox__textwrapper">Checkbox</p>\n  </label>\n</div>', css: '\n/* From Uiverse.io by Shoh2008 - Tags: checkbox */\n.checkbox-wrapper-33 {\n  --s-xsmall: 0.625em;\n  --s-small: 1.2em;\n  --border-width: 1px;\n  --c-primary: #5F11E8;\n  --c-primary-20-percent-opacity: rgb(95 17 232 / 20%);\n  --c-primary-10-percent-opacity: rgb(95 17 232 / 10%);\n  --t-base: 0.4s;\n  --t-fast: 0.2s;\n  --e-in: ease-in;\n  --e-out: cubic-bezier(.11,.29,.18,.98);\n}\n\n.checkbox-wrapper-33 .visuallyhidden {\n  border: 0;\n  clip: rect(0 0 0 0);\n  height: 1px;\n  margin: -1px;\n  overflow: hidden;\n  padding: 0;\n  position: absolute;\n  width: 1px;\n}\n\n.checkbox-wrapper-33 .checkbox {\n  display: flex;\n  align-items: center;\n  justify-content: flex-start;\n}\n\n.checkbox-wrapper-33 .checkbox + .checkbox {\n  margin-top: var(--s-small);\n}\n\n.checkbox-wrapper-33 .checkbox__symbol {\n  display: inline-block;\n  display: flex;\n  margin-right: calc(var(--s-small) * 0.7);\n  border: var(--border-width) solid var(--c-primary);\n  position: relative;\n  border-radius: 0.1em;\n  width: 1.5em;\n  height: 1.5em;\n  transition: box-shadow var(--t-base) var(--e-out), background-color var(--t-base);\n  box-shadow: 0 0 0 0 var(--c-primary-10-percent-opacity);\n}\n\n.checkbox-wrapper-33 .checkbox__symbol:after {\n  content: "";\n  position: absolute;\n  top: 0.5em;\n  left: 0.5em;\n  width: 0.25em;\n  height: 0.25em;\n  background-color: var(--c-primary-20-percent-opacity);\n  opacity: 0;\n  border-radius: 3em;\n  transform: scale(1);\n  transform-origin: 50% 50%;\n}\n\n.checkbox-wrapper-33 .checkbox .icon-checkbox {\n  width: 1em;\n  height: 1em;\n  margin: auto;\n  fill: none;\n  stroke-width: 3;\n  stroke: currentColor;\n  stroke-linecap: round;\n  stroke-linejoin: round;\n  stroke-miterlimit: 10;\n  color: var(--c-primary);\n  display: inline-block;\n}\n\n.checkbox-wrapper-33 .checkbox .icon-checkbox path {\n  transition: stroke-dashoffset var(--t-fast) var(--e-in);\n  stroke-dasharray: 30px, 31px;\n  stroke-dashoffset: 31px;\n}\n\n.checkbox-wrapper-33 .checkbox__textwrapper {\n  margin: 0;\n}\n\n.checkbox-wrapper-33 .checkbox__trigger', colors: '#5f11e8', radii: '3em,0.1em', shadows: '0 0 0 0 var(--c-primary-10-percent-opacity),0 0 0 0.25em var(--c-primary-20-percent-opacity)', techniques: 'cubic-bezier,3d-transform,glow-shadow,animation,checkbox-input,svg-icon'),
const GalaxyComp(id: 'Navarog21_good-newt-78', cat: 'Radio-buttons', author: 'Navarog21', tags: '', html: '<div class="radioContainer">\n\n    <input class="radioButton" type="radio" id="value-1" name="value-radio" value="value-1" checked="">\n    <label class="container" for="value-1">\n      <div class="border"></div>\n      <div class="border2"></div>\n      <div class="circle"></div>\n    </label>\n\n    <input class="radioButton" type="radio" id="value-2" name="value-radio" value="value-2">\n    <label class="container" for="value-2">\n      <div class="border"></div>\n      <div class="border2"></div>\n      <div class="circle"></div>\n    </label>\n\n    <input class="radioButton" type="radio" id="value-3" name="value-radio" value="value-3">\n    <label class="container" for="value-3">\n      <div class="border"></div>\n      <div class="border2"></div>\n      <div class="circle"></div>\n    </label>\n\n\n</div>', css: '\n/* From Uiverse.io by Navarog21 - Tags:  */\n.radioContainer {\n  display: flex;\n  justify-content: space-between;\n  position: relative;\n  width: 220px;\n}\n\n.radioButton {\n  display: none;\n}\n\n.radioContainer .container {\n  display: inline-flex;\n  justify-content: center;\n  align-items: center;\n  position: relative;\n  transition: 0.8s;\n  cursor: pointer;\n  width: 65px;\n  height: 65px;\n  background-image: linear-gradient(to top, #00c6fb 0%, #005bea 100%);\n  clip-path: polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%);\n  box-shadow: 0 0 5px inset white;\n}\n\n.border {\n  position: absolute;\n  background-color: #212121;\n  width: 100%;\n  height: 100%;\n  transform: scale(0.7) rotate(30deg);\n  transition: 0.3s;\n  clip-path: polygon(0% 0%, 0% 100%, 25% 100%, 25% 25%, 75% 25%, 75% 75%, 25% 75%, 25% 100%, 100% 100%, 100% 0%);\n}\n\n.border2 {\n  position: absolute;\n  background-color: #212121;\n  width: 100%;\n  height: 100%;\n  transform: scale(0.45);\n  transition: 0.2s;\n  clip-path: polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%);\n}\n\n.radioContainer input[type="radio"]:checked + .container {\n  filter: hue-rotate(330deg);\n  animation: 2s linear checked;\n}\n\n.radioContainer input[type="radio"]:checked + .container .circle {\n  transform: scale(0.8);\n}\n\n.radioContainer input[type="radio"]:checked + .container .border {\n  animation: 4s linear infinite reverse rotateBorder;\n}\n\n.radioContainer input[type="radio"]:checked + .container .border2 {\n  animation: 2s linear reverse rotateBorder2;\n}\n\n.circle {\n  background-image: linear-gradient(to top, #00c6fb 0%, #005bea 100%);\n  border-radius: 100%;\n  width: 22%;\n  height: 22%;\n  transition: 0.25s;\n  z-index: 2;\n  transform: scale(0);\n}\n\n.radioContainer .container:hover .circle {\n  transform: scale(0.8);\n  box-shadow: 0 20px 20px #00c6fb;\n}\n\n@keyframes checked {\n  0% {\n    transform: rotate(0deg) scale(1);\n  }\n\n  50% {\n    transform: rotate(0deg) scale(1.07);\n  }\n\n  100% {\n    transform: rotate(360deg) scale(1);\n  }\n}\n\n@keyframes rotateBorder {\n  0% {\n    tr', colors: '#212121,#00c6fb,#005bea', radii: '100%', shadows: '0 0 5px inset white,0 20px 20px #00c6fb', techniques: '3d-transform,glow-shadow,gradient,animation,filter-effect,clip-path'),
const GalaxyComp(id: 'Tsiangana_clever-cheetah-40', cat: 'Radio-buttons', author: 'Tsiangana', tags: 'futuristic,animated,futuristic-radio-buttons', html: '<div class="radio-input">\n  <div class="container">\n    <label>\n      <input value="value-1" name="value-radio" checked="" id="value-1" type="radio">\n      <div class="loader"></div>\n    </label>\n    <label>\n      <input value="value-2" name="value-radio" id="value-2" type="radio">\n      <div class="loader"></div>\n    </label>\n    <label>\n      <input value="value-3" name="value-radio" id="value-3" type="radio">\n      <div class="loader"></div>\n    </label>\n </div>\n</div>', css: '\n/* From Uiverse.io by Tsiangana - Tags: futuristic, animated, futuristic-radio-buttons */\n.radio-input label {\n  position: relative;\n  display: flex;\n  border-radius: 99999px;\n  margin: 8px;\n  width: 3em;\n  height: 3em;\n  margin-top: -35px;\n}\n\n.radio-input input {\n  position: absolute;\n  border-radius: 50%;\n  appearance: unset;\n  inset: 0.95em;\n  margin: 0;\n  cursor: pointer;\n  background-color: rgb(74, 156, 233);\n  filter: drop-shadow(0 0 10px rgb(74, 156, 233));\n}\n\n.radio-input input:checked {\n  transition: .9s linear;\n  background-color: #fff;\n  z-index: 500;\n}\n\n.radio-input .container {\n  width: 100%;\n  height: 100%;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.radio-input .container .loader {\n  height: 25px;\n  width: 25px;\n  border-radius: 50%;\n  border: 1px solid;\n  position: absolute;\n  bottom: -25px;\n  left: 10.5px;\n  transform-origin: 50% 60%;\n  transform: perspective(200px) rotateX(66deg);\n  z-index: -1;\n  background: linear-gradient(315deg, #cacaca, #f0f0f0);\n  box-shadow: -6px -6px 11px #c1c1c1,\n             6px 6px 11px #ffffff;\n}\n\n#value-1[type=\'radio\']:checked:after {\n  content: \'\';\n  position: absolute;\n  width: 10px;\n  height: 10px;\n  background: #fff;\n  border-radius: 50%;\n  top: 23px;\n  animation: 2.2s  lua infinite ease-in-out;\n  animation-timing-function: linear;\n}\n\n#value-2[type=\'radio\']:checked:after {\n  content: \'\';\n  position: absolute;\n  width: 10px;\n  height: 10px;\n  background: rgba(19, 219, 226, 0.719);\n  border-radius: 50%;\n  top: 23px;\n  animation: 2.2s  lua infinite ease-in-out;\n  animation-timing-function: linear;\n}\n\n#value-3[type=\'radio\']:checked:after {\n  content: \'\';\n  position: absolute;\n  width: 10px;\n  height: 10px;\n  background: rgba(29, 29, 23, 0.979);\n  border-radius: 50%;\n  top: 23px;\n  animation: 2.2s lua  infinite ease-in-out;\n  animation-timing-function: linear;\n}\n\n@keyframes lua {\n  0% {\n    z-index: 5;\n  }\n\n  50% {\n    transform: translateX(1.5em) translateY(-2.5em);\n  }\n\n  100% {\n    z-index', colors: '#cacaca,#c1c1c1,#f0f0f0,#ffffff,#fff', radii: '99999px,50%', shadows: '-6px -6px 11px #c1c1c1,\n             6px 6px 11px #ffffff', techniques: '3d-transform,glow-shadow,gradient,animation,filter-effect,perspective'),
const GalaxyComp(id: 'WerlynRodriguez_fuzzy-yak-55', cat: 'Radio-buttons', author: 'WerlynRodriguez', tags: 'radio', html: '<div class="radio">\n      <label>\n        <input checked="" value="1" name="radio" type="radio">\n        <span>Cyber Punk</span>\n        <div class="rotor">\n          <span></span>\n          <span></span>\n          <span></span>\n        </div>\n      </label>\n      <label>\n        <input value="2" name="radio" type="radio">\n        <span>Solar Punk</span>\n        <div class="rotor">\n          <span></span>\n          <span></span>\n          <span></span>\n        </div>\n      </label>\n      <label>\n        <input value="3" name="radio" type="radio">\n        <span>Steam Punk</span>\n        <div class="rotor">\n          <span></span>\n          <span></span>\n          <span></span>\n        </div>\n      </label>\n    </div>', css: '\n/* From Uiverse.io by WerlynRodriguez - Tags: radio */\n.radio {\n  --input_size: 1.8em;\n  --rotor_size: calc(var(--input_size) + 0.5em);\n    /* 2em = 0.5em, 4em = 1em, 6em = 1.5em, 8em = 2em*/\n  --rotor_border_size: 0.3em;\n  --theme_color: #000;\n  display: flex;\n  flex-direction: column;\n  justify-content: start;\n}\n\n@media(prefers-color-scheme: dark) {\n  .radio {\n    --theme_color: #fff;\n  }\n}\n\n.radio label {\n  display: flex;\n  flex-direction: row;\n  align-items: center;\n  margin: 5px 0;\n  font-size: calc(var(--input_size) * 0.8);\n}\n\n.radio label span {\n  font-family: monospace;\n  text-transform: uppercase;\n  font-weight: 600;\n  letter-spacing: normal;\n  word-spacing: 0.1em;\n  color: var(--theme_color);\n}\n\n.radio input {\n  z-index: 1;\n  width: var(--input_size);\n  height: var(--input_size);\n  cursor: pointer;\n  transition: all 0.3s ease-out;\n}\n\n/* The rotor is all the circles rotating at the input */\n.radio .rotor {\n  position: absolute;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  width: var(--rotor_size);\n  height: var(--rotor_size);\n  margin: 0 -14px;\n  transform: scale(0.3) rotate(-180deg);\n  opacity: 0;\n  transition: all 0.6s ease-out;\n}\n\n.radio input:checked ~ .rotor {\n  opacity: 1;\n  transform: scale(1) rotate(0deg);\n}\n\n.radio label input ~ span {\n  position: relative;\n  top: 10px;\n  padding: 0.5em 1em;\n  border: calc(var(--rotor_border_size) / 2) solid transparent;\n  clip-path: polygon(25% 0%, 100% 0%, 75% 100%, 0% 100%);\n  transition: all 0.3s ease-out;\n}\n\n.radio input:checked ~ span {\n  border: calc(var(--rotor_border_size) / 2) solid var(--theme_color);\n  background-size: cover;\n  background-blend-mode: difference;\n  font-style: italic;\n  filter: drop-shadow(0px 0px 0.2em #fdfdfd);\n}\n\n.radio .rotor span:first-child {\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  border-radius: 50%;\n  border: var(--rotor_border_size) dashed var(--theme_color);\n  animation: rotate 2s linear infinite;\n  filter: drop-shadow(0px 0px 0.2em #fdfd', colors: '#7d008b,#e600ff,#000,#fdfdfd,#fff,#d303ea', radii: '50%', shadows: '', techniques: 'cubic-bezier,3d-transform,animation,filter-effect,clip-path,typography-transform'),
const GalaxyComp(id: 'gharsh11032000_spotty-zebra-83', cat: 'Tooltips', author: 'gharsh11032000', tags: 'tooltip,animation,hover,bounce', html: '<div class="tooltip-container">\n  <span class="tooltip">Uiverse.io</span>\n  <span class="text">Tooltip 👆</span>\n  <span>Hello! 👋</span>\n</div>', css: '\n/* From Uiverse.io by gharsh11032000  - Tags: tooltip, animation, hover, bounce */\n/* This is an example, feel free to delete this code */\n.tooltip-container {\n  --background: #333333;\n  --color: #e8e8e8;\n  position: relative;\n  cursor: pointer;\n  transition: all 0.4s cubic-bezier(0.23, 1, 0.32, 1);\n  font-size: 18px;\n  font-weight: 600;\n  color: var(--color);\n  padding: 0.7em 1.8em;\n  border-radius: 8px;\n  text-transform: uppercase;\n  height: 60px;\n  width: 180px;\n  display: grid;\n  place-items: center;\n  border: 2px solid var(--color);\n}\n\n.text {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  display: grid;\n  place-items: center;\n  transform-origin: -100%;\n  transform: scale(1);\n  transition: all 0.4s cubic-bezier(0.23, 1, 0.32, 1);\n}\n\n.tooltip-container span:last-child {\n  position: absolute;\n  top: 0%;\n  left: 100%;\n  width: 100%;\n  height: 100%;\n  border-radius: 8px;\n  opacity: 1;\n  background-color: var(--background);\n  z-index: -1;\n  border: 2px solid var(--background);\n  transform: scale(0);\n  transform-origin: 0;\n  transition: all 0.4s cubic-bezier(0.23, 1, 0.32, 1);\n  display: grid;\n  place-items: center;\n}\n\n.tooltip {\n  position: absolute;\n  top: 0;\n  left: 50%;\n  transform: translateX(-50%);\n  padding: 0.3em 0.6em;\n  opacity: 0;\n  pointer-events: none;\n  transition: all 0.4s cubic-bezier(0.23, 1, 0.32, 1);\n  background: var(--background);\n  z-index: -1;\n  border-radius: 8px;\n  scale: 0;\n  transform-origin: 0 0;\n  text-transform: capitalize;\n  font-weight: 400;\n  font-size: 16px;\n  box-shadow: rgba(0, 0, 0, 0.25) 0 8px 15px;\n}\n\n.tooltip::before {\n  position: absolute;\n  content: "";\n  height: 0.6em;\n  width: 0.6em;\n  bottom: -0.2em;\n  left: 50%;\n  transform: translate(-50%) rotate(45deg);\n  background: var(--background);\n}\n\n.tooltip-container:hover .tooltip {\n  top: -100%;\n  opacity: 1;\n  visibility: visible;\n  pointer-events: auto;\n  scale: 1;\n  animation: shake 0.5s ease-in-out both;\n}\n\n.tooltip-container:hover {\n  box-shad', colors: '#e8e8e8,#333333', radii: '8px', shadows: 'rgba(0, 0, 0, 0.25) 0 8px 15px,rgba(0, 0, 0, 0.25) 0 8px 15px', techniques: 'cubic-bezier,3d-transform,glow-shadow,animation,typography-transform,pseudo-elements'),
