const GalaxyComp(id: 'neerajbaniwal_gentle-turkey-54', cat: 'Tooltips', author: 'neerajbaniwal', tags: 'simple,neumorphism,glassmorphism,tooltip,hover,hover effect', html: '<div class="tooltip-container">\n  <span class="tooltip">Uiverse.io</span>\n  <span class="text">@</span>\n</div>', css: '\n/* From Uiverse.io by neerajbaniwal  - Tags: simple, neumorphism, glassmorphism, tooltip, hover, hover effect */\n.tooltip-container {\n  height: 70px;\n  width: 110px;\n  border-radius: 5px;\n  background-color: #fff;\n  background-image: linear-gradient(\n    to left bottom,\n    #f2f5f8,\n    #ecf1f2,\n    #e7eceb,\n    #e3e7e4,\n    #e1e2de\n  );\n  border: 1px solid white;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  cursor: pointer;\n  box-shadow: 0px 10px 10px rgba(0, 0, 0, 0.151);\n  position: relative;\n  transition: transform 0.3s ease;\n  z-index: 1;\n}\n\n.tooltip-container::before {\n  position: absolute;\n  content: "";\n  top: -50%;\n  clip-path: polygon(50% 0, 0 100%, 100% 100%);\n  border-radius: 5px;\n  background-color: fff;\n  background-image: linear-gradient(\n    to left bottom,\n    #1288ff,\n    #e4eaec,\n    #d8dfde,\n    #cdd3cf,\n    #c5c7c1\n  );\n  width: 100%;\n  height: 50%;\n  transform-style: preserve-3d;\n  transform: perspective(1000px) rotateX(-150deg) translateY(-110%);\n  transition: transform 0.3s ease;\n  z-index: -1;\n}\n\n.tooltip-container .text {\n  color: rgb(32, 30, 30);\n  font-weight: bold;\n  font-size: 40px;\n}\n\n.tooltip {\n  position: absolute;\n  top: -20px;\n  opacity: 0;\n  background: linear-gradient(-90deg, rgba(0, 0, 0, 0.05) 1px, white 1px),\n    linear-gradient(rgba(0, 0, 0, 0.05) 1px, white 1px),\n    linear-gradient(-90deg, rgba(0, 0, 0, 0.04) 1px, white 1px),\n    linear-gradient(rgba(0, 0, 0, 0.04) 1px, white 1px),\n    linear-gradient(white 3px, #f2f2f2 3px, #f2f2f2 78px, white 78px),\n    linear-gradient(-90deg, #aaa 1px, white 1px),\n    linear-gradient(-90deg, white 3px, #f2f2f2 3px, #f2f2f2 78px, white 78px),\n    linear-gradient(#aaa 1px, white 1px), #f2f2f2;\n  background-size: 4px 4px, 4px 4px, 80px 80px, 80px 80px, 80px 80px, 80px 80px,\n    80px 80px, 80px 80px;\n  padding: 5px 10px;\n  border: 1px solid rgb(206, 204, 204);\n\n  height: 70px;\n  width: 110px;\n  border-radius: 5px;\n  display: flex;\n  align-items: center;\n  justify-con', colors: '#d8dfde,#aaa,#e1e2de,#1288ff,#e4eaec,#f2f5f8,#cdd3cf,#e3e7e4,#ecf1f2,#e7eceb', radii: '5px', shadows: '0px 10px 10px rgba(0, 0, 0, 0.151)', techniques: '3d-transform,text-shadow,gradient,clip-path,perspective,pseudo-elements'),
const GalaxyComp(id: 'neerajbaniwal_sweet-sloth-99', cat: 'Tooltips', author: 'neerajbaniwal', tags: 'tooltip,animation,social media,animated,svg,buttons,bounce animation', html: '<div class="wrapper">\n  <input type="checkbox" />\n  <div class="btn"></div>\n  <div class="tooltip">\n    <svg></svg>\n    <svg></svg>\n    <svg></svg>\n  </div>\n  <svg></svg>\n</div>\n\n<svg style="display: none;" xmlns="http://www.w3.org/2000/svg">\n  <symbol id="icon-01" viewBox="0 0 26 22" xmlns="http://www.w3.org/2000/svg">\n    <path\n      transform="translate(0 -2)"\n      d="M18.29,5.76l-.7-1.37A2.59,2.59,0,0,0,15.29,3H10.71a2.59,2.59,0,0,0-2.3,1.39l-.7,1.37a2.6,2.6,0,0,1-2.3,1.39H3.58A2.57,2.57,0,0,0,1,9.71V20.44A2.57,2.57,0,0,0,3.58,23H22.42A2.57,2.57,0,0,0,25,20.44V9.71a2.57,2.57,0,0,0-2.58-2.56H20.59A2.6,2.6,0,0,1,18.29,5.76Z"\n    ></path>\n    <ellipse ry="4.49" rx="4.52" cy="12.99" cx="13"></ellipse>\n  </symbol>\n  <symbol id="icon-02" viewBox="0 0 26 22" xmlns="http://www.w3.org/2000/svg">\n    <line y2="9.42" x2="25" y1="12.58" x1="25"></line>\n    <line y2="7.84" x2="21" y1="14.16" x1="21"></line>\n    <line y2="6.26" x2="17" y1="15.74" x1="17"></line>\n    <line y2="1" x2="13" y1="21" x1="13"></line>\n    <line y2="4.68" x2="9" y1="17.32" x1="9"></line>\n    <line y2="8.37" x2="5" y1="13.63" x1="5"></line>\n    <line y2="10.47" x2="1" y1="11.53" x1="1"></line>\n  </symbol>\n  <symbol id="icon-03" viewBox="0 0 26 22" xmlns="http://www.w3.org/2000/svg">\n    <polygon\n      points="8.08 10 1 21 25 21 18.09 12.66 13.78 17.45 8.08 10"\n    ></polygon>\n    <circle r="3" cy="4" cx="8"></circle>\n  </symbol>\n\n  <symbol\n    id="shape-01"\n    viewBox="0 0 300 300"\n    xmlns="http://www.w3.org', css: '\n/* From Uiverse.io by neerajbaniwal  - Tags: tooltip, animation, social media, animated, svg, buttons, bounce animation */\n.wrapper {\n  --background: #62abff;\n  --icon-color: #414856;\n  --shape-color-01: #b8cbee;\n  --shape-color-02: #7691e8;\n  --shape-color-03: #fdd053;\n  --width: 90px;\n  --height: 90px;\n  --border-radius: var(--height);\n  width: var(--width);\n  height: var(--height);\n  position: relative;\n  border-radius: var(--border-radius);\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n.wrapper .btn {\n  background: var(--background);\n  width: var(--width);\n  height: var(--height);\n  position: relative;\n  z-index: 3;\n  border-radius: var(--border-radius);\n  box-shadow: 0 10px 30px rgba(65, 72, 86, 0.05);\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  -webkit-animation: plus-animation-reverse 0.5s ease-out forwards;\n  animation: plus-animation-reverse 0.5s ease-out forwards;\n}\n.wrapper .btn::before,\n.wrapper .btn::after {\n  content: "";\n  display: block;\n  position: absolute;\n  border-radius: 4px;\n  background: #fff;\n}\n.wrapper .btn::before {\n  width: 4px;\n  height: 28px;\n}\n.wrapper .btn::after {\n  width: 28px;\n  height: 4px;\n}\n.wrapper .tooltip {\n  width: 90px;\n  height: 75px;\n  border-radius: 70px;\n  position: absolute;\n  background: #fff;\n  z-index: 2;\n  padding: 0 15px;\n  box-shadow: 0 10px 30px rgba(65, 72, 86, 0.05);\n  opacity: 0;\n  top: 0;\n  display: flex;\n  justify-content: space-around;\n  align-items: center;\n  transition: opacity 0.15s ease-in, top 0.15s ease-in, width 0.15s ease-in;\n}\n.wrapper .tooltip > svg {\n  width: 100%;\n  height: 26px;\n  display: flex;\n  justify-content: space-around;\n  align-items: center;\n  cursor: pointer;\n}\n.wrapper .tooltip > svg .icon {\n  fill: none;\n  stroke: var(--icon-color);\n  stroke-width: 2px;\n  stroke-linecap: round;\n  stroke-linejoin: round;\n  opacity: 0.4;\n  transition: opacity 0.3s ease;\n}\n.wrapper .tooltip > svg:hover .icon {\n  opacity: 1;\n}\n.wrapper .tooltip::after {\n ', colors: '#7691e8,#b8cbee,#62abff,#414856,#fdd053,#fff', radii: '70px,3px,var(--border-radius),4px,var(--height)', shadows: '0 10px 30px rgba(65, 72, 86, 0.05),0 10px 30px rgba(65, 72, 