const GalaxyComp(id: 'JkHuger_tasty-ape-73', cat: 'Notifications', author: 'JkHuger', tags: 'notification', html: '<div class="level-up-notification">\n  <div class="confetti"></div>\n  <div class="level-up-text">Level Up!</div>\n</div>\n\n<div class="confetti-container">\n  <div class="confetti">\n    <i class="square" style="--speed: 10; --bg: yellow"></i>\n    <i class="pentagram" style="--speed: 18; --bg: white"></i>\n    <i class="rectangle" style="--speed: 29; --bg: green"></i>\n    <i class="hexagram" style="--speed: 17; --bg: blue"></i>\n    <i class="pentagram" style="--speed: 33; --bg: red"></i>\n    <i class="dodecagram" style="--speed: 26; --bg: yellow"></i>\n    <i class="wavy-line" style="--speed: 24; --bg: pink"> </i>\n    <i class="wavy-line" style="--speed: 5; --bg: blue"></i>\n    <i class="square" style="--speed: 40; --bg: white"></i>\n    <i class="rectangle" style="--speed: 17; --bg: green"></i>\n    <i class="square" style="--speed: 25; --bg: white"></i>\n    <i class="rectangle" style="--speed: 18; --bg: green"></i>\n    <i class="wavy-line" style="--speed: 15; --bg: yellow"> </i>\n    <i class="pentagram" style="--speed: 32; --bg: yellow"></i>\n    <i class="square" style="--speed: 25; --bg: white"></i>\n    <i class="rectangle" style="--speed: 18; --bg: green"></i>\n    <i class="dodecagram" style="--speed: 37; --bg: yellow"></i>\n    <i class="wavy-line" style="--speed: 23; --bg: pink"></i>\n    <i class="dodecagram" style="--speed: 37; --bg: red"></i>\n    <i class="wavy-line" style="--speed: 37; --bg: pink"></i>\n    <i class="hexagram" style="--speed: 36; --bg: white"></i>\n    <i class=', css: '\n/* From Uiverse.io by JkHuger - Tags: notification */\n.level-up-notification {\n  justify-content: center;\n  align-items: center;\n  flex-direction: column;\n  background-color: #FDD835;\n  border-radius: 10px;\n  font-weight: bold;\n  font-family: "Courier New", monospace;\n  box-shadow: 0 0 10px rgba(0, 0, 0, 0.5);\n  opacity: 0;\n  animation: scale-up 1.5s ease-in-out forwards, fade-out 0.5s ease-in-out forwards 21.5s;\n}\n\n.level-up-text {\n  text-align: center;\n  color: #fff;\n  font-size: 30px;\n  padding: 12px 20px;\n  font-weight: bold;\n  text-shadow: 2px 2px #000;\n}\n\n@keyframes confetti {\n  0% {\n    transform: translateY(-50%);\n  }\n\n  100% {\n    transform: translateY(100%);\n  }\n}\n\n@keyframes scale-up {\n  0% {\n    transform: scale(0);\n    opacity: 0;\n  }\n\n  100% {\n    transform: scale(1);\n    opacity: 1;\n  }\n}\n\n.level-up-notification:hover {\n  animation: none;\n}\n\n.level-up-notification:hover .confetti {\n  animation: confetti 0.5s ease-in-out forwards;\n}\n\n/* asd */\n\n.confetti-container {\n  user-select: none;\n  z-index: 10;\n}\n\n.confetti {\n  position: absolute;\n  left: 0;\n  right: 0;\n  display: flex;\n  /* width: 600px; */\n  /* height: 600px; */\n  /* overflow: hidden; */\n}\n\n.confetti .square {\n  width: 1rem;\n  height: 1rem;\n  background-color: var(--bg);\n  transform: rotate(-140deg);\n}\n\n.confetti .rectangle {\n  width: 1rem;\n  height: 0.5rem;\n  background-color: var(--bg);\n}\n\n.confetti .hexagram {\n  width: 0;\n  height: 0;\n  border-left: 0.5rem solid transparent;\n  border-right: 0.5rem solid transparent;\n  border-bottom: 1rem solid var(--bg);\n  position: relative;\n}\n\n.confetti .hexagram:after {\n  content: "";\n  width: 0;\n  height: 0;\n  border-left: 0.5rem solid transparent;\n  border-right: 0.5rem solid transparent;\n  border-top: 1rem solid var(--bg);\n  position: absolute;\n  top: 0.33rem;\n  left: -0.5rem;\n}\n\n.confetti .pentagram {\n  width: 0rem;\n  height: 0rem;\n  display: block;\n  margin: 0.5rem 0;\n  border-right: 1rem solid transparent;\n  border-bottom: 0.7rem solid var(--bg);\n', colors: '#000,#fdd835,#fff', radii: '10px', shadows: '0 0 10px rgba(0, 0, 0, 0.5)', techniques: '3d-transform,glow-shadow,text-shadow,gradient,animation,pseudo-elements'),
const GalaxyComp(id: '0xnihilism_helpless-rattlesnake-54', cat: 'Buttons', author: '0xnihilism', tags: 'button,microsoft,animated,brutalism,brutalist,glare effect', html: '<a href="/" class="brutalist-button">\n  <div class="content-wrapper">\n    <div class="claude-logo">\n      <span class="starburst">✷</span>\n    </div>\n    <div class="button-text">\n      <span>Powered By</span>\n      <span>Claude 3.5</span>\n    </div>\n  </div>\n</a>', css: '\n/* From Uiverse.io by 0xnihilism  - Tags: button, microsoft, animated, brutalism, brutalist, glare effect */\n.brutalist-button {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  background-color: #e3d19c;\n  border: 3px solid #000000;\n  border-radius: 8px;\n  padding: 20px;\n  text-decoration: none;\n  color: #000000;\n  font-weight: bold;\n  position: relative;\n  box-shadow: 4px 4px 0px #000000;\n  overflow: hidden;\n  transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);\n  width: 166px;\n  height: 150px;\n}\n\n.brutalist-button:hover {\n  transform: translate(-2px, -2px);\n  box-shadow: 6px 6px 0px #000000;\n}\n\n.brutalist-button:active {\n  transform: translate(2px, 2px);\n  box-shadow: 2px 2px 0px #000000;\n}\n\n.content-wrapper {\n  position: relative;\n  z-index: 2;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);\n  transition-delay: 0.8s;\n}\n\n.claude-logo {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  width: 80px;\n  height: 80px;\n  border-radius: 50%;\n  background-color: #eb6c22;\n  transition: transform 0.3s cubic-bezier(0.25, 0.8, 0.25, 1),\n    margin-bottom 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);\n  transition-delay: 0.8s;\n  transform: rotate(0deg) scale(1);\n}\n\n.starburst {\n  font-size: 48px;\n  color: #ffffff;\n  line-height: 1;\n  transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);\n  transition-delay: 0.8s;\n}\n\n.button-text {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  line-height: 1.2;\n  text-align: center;\n  opacity: 0;\n  max-height: 0;\n  overflow: hidden;\n  transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);\n  transition-delay: 0.8s;\n}\n\n.button-text span:first-child {\n  font-size: 14px;\n  font-weight: normal;\n}\n\n.button-text span:last-child {\n  font-size: 18px;\n  font-weight: 700;\n  text-transform: uppercase;\n  letter-spacing: 0.5px;\n}\n\n.brutalist-button:hover .content-wrapper {\n  transform: translateY(-10px', colors: '#eb6c22,#000000,#4e432d,#ffffff,#e3d19c', radii: '50%,8px', shadows: '4px 4px 0px #000000,6px 6px 0px #000000,2px 2px 0px #000000', techniques: 'cubic-bezier,3d-transform,animation,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'adamgiebl_pink-chicken-70', cat: 'Buttons', author: 'adamgiebl', tags: 'icon,button,code', html: '<button class="cssbuttons-io">\n  <span><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24"><path fill="none" d="M0 0h24v24H0z"></path><path fill="currentColor" d="M24 12l-5.657 5.657-1.414-1.414L21.172 12l-4.243-4.243 1.414-1.414L24 12zM2.828 12l4.243 4.243-1.414 1.414L0 12l5.657-5.657L7.07 7.757 2.828 12zm6.96 9H7.66l6.552-18h2.128L9.788 21z"></path></svg> Code</span>\n</button>', css: '\n/* From Uiverse.io by adamgiebl - Tags: icon, button, code */\n.cssbuttons-io {\n  position: relative;\n  font-family: inherit;\n  font-weight: 500;\n  font-size: 18px;\n  letter-spacing: 0.05em;\n  border-radius: 0.8em;\n  border: none;\n  background: linear-gradient(to right, #8e2de2, #4a00e0);\n  color: ghostwhite;\n  overflow: hidden;\n}\n\n.cssbuttons-io svg {\n  width: 1.2em;\n  height: 1.2em;\n  margin-right: 0.5em;\n}\n\n.cssbuttons-io span {\n  position: relative;\n  z-index: 10;\n  transition: color 0.4s;\n  display: inline-flex;\n  align-items: center;\n  padding: 0.8em 1.2em 0.8em 1.05em;\n}\n\n.cssbuttons-io::before,\n.cssbuttons-io::after {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  z-index: 0;\n}\n\n.cssbuttons-io::before {\n  content: "";\n  background: #000;\n  width: 120%;\n  left: -10%;\n  transform: skew(30deg);\n  transition: transform 0.4s cubic-bezier(0.3, 1, 0.8, 1);\n}\n\n.cssbuttons-io:hover::before {\n  transform: translate3d(100%, 0, 0);\n}\n\n.cssbuttons-io:active {\n  transform: scale(0.95);\n}\n\n', colors: '#8e2de2,#000,#4a00e0', radii: '0.8em', shadows: '', techniques: 'cubic-bezier,3d-transform,gradient,svg-icon,pseudo-elements'),
