const GalaxyComp(id: 'Admin12121_lovely-cat-86', cat: 'Buttons', author: 'Admin12121', tags: 'delete,animated,3d button', html: '<button class="bin">🗑</button>\n<div class="div">\n  <small>\n    <i></i>\n  </small>\n</div>', css: '\n/* From Uiverse.io by Admin12121 - Tags: delete, animated, 3d button */\n.bin {\n  --black: #000000;\n  --binbg: #e6e6e6;\n  --width: 40px;\n  --height: 50px;\n  background-image: repeating-linear-gradient(to right, transparent, transparent 5px, var(--black) 5px, var(--black) 7px, transparent 7px);\n  background-size: 11px calc(var(--height) / 2);\n  background-position: 2px center;\n  background-repeat: repeat-x;\n  margin: auto;\n  position: relative;\n  background-color: var(--binbg);\n  border: 0;\n  color: transparent;\n  width: var(--width);\n  height: var(--height);\n  border: 2px solid var(--black);\n  border-radius: 0 0 6px 6px;\n}\n\n.bin::after, .bin::before {\n  content: "";\n  position: absolute;\n  transform-origin: left bottom;\n  transition: 200ms ease-in-out;\n  border-width: 2px;\n  border-style: solid;\n  margin: auto;\n  right: 0;\n}\n\n.bin::after {\n  left: -4px;\n  top: -5px;\n  height: 7px;\n  width: var(--width);\n  border: 2px solid var(--black);\n  background-color: var(--binbg);\n  border-radius: 5px 5px 0 0;\n}\n\n.bin::before {\n  top: -8px;\n  height: 2px;\n  width: 10px;\n  border-color: var(--black) var(--black) transparent var(--black);\n  left: 0;\n}\n\n.bin:focus, .bin:active {\n  outline: none;\n  cursor: none;\n}\n\n.bin:focus::before, .bin:focus::after, .bin:active::before, .bin:active::after {\n  transform-origin: left bottom;\n  transform: rotate(-45deg);\n}\n\n.bin:focus::before, .bin:active::before {\n  top: -18px;\n  left: -23px;\n  right: 3px;\n}\n\n.bin:focus ~ .div, .bin:active ~ .div {\n  cursor: none;\n  z-index: 1;\n}\n\n.bin:focus ~ .div:hover, .bin:active ~ .div:hover {\n  cursor: none;\n}\n\n.bin:focus ~ .overlay, .bin:active ~ .overlay {\n  pointer-events: inherit;\n  z-index: 2;\n  cursor: none;\n}\n\n.bin:focus ~ .div > small, .bin:active ~ .div > small {\n  opacity: 1;\n  animation: throw 300ms 30ms cubic-bezier(0.215, 0.61, 0.355, 0.3) forwards;\n}\n\n.div:focus, .div:active, .div:hover {\n  z-index: 1;\n  cursor: none;\n}\n\n.div > small {\n  position: absolute;\n  width: 20px;\n  height: 16px;\n  le', colors: '#000000,#e6e6e6', radii: '0 0 6px 6px,5px 5px 0 0', shadows: '', techniques: 'cubic-bezier,3d-transform,gradient,animation,pseudo-elements'),
