in: 0 auto;\n  border-radius: 2rem;\n  filter: blur(8px);\n  z-index: -9;\n  opacity: 0;\n  transition: opacity .4s;\n}\n\n.text {\n  position: relative;\n  z-index: 10;\n}\n\nbutton svg {\n  position: absolute;\n  inset: 0;\n  margin: auto;\n  pointer-events: none;\n  transition: .6s;\n  opacity: 0;\n}\n\nsvg.star {\n  width: 18px;\n  transform: translate(-25px, -6px) rotate(55deg);\n  filter: blur(.4px);\n  color: hsl(210, 40%, 47%);\n}\n\nsvg.moon {\n  width: 18px;\n  transform: translate(7px, -14) rotate(80deg);\n  filter: blur(.5px);\n  color: hsl(210, 40%, 47%);\n}\n\nsvg.meteor {\n  width: 16px;\n  transform: translate(34px, -4px) rotate(-45deg);\n  filter: blur(.4px);\n  color: hsl(210, 40%, 47%);\n}\n\nbutton:active {\n  color: #ffffff;\n  transform: scale(1.2);\n}\n\nbutton:hover::after {\n  opacity: 1;\n}\n\nbutton:hover {\n  transform: scale(1.3);\n}\n\nbutton:hover svg {\n  opacity: 1;\n}\n\nbutton:hover svg.star {\n  transform: translate(-55px, -20px) rotate(55deg) scale(1.8);\n}\n\nbutton:hover svg.moon {\n  transform: translate(50px, -32px) rotate(0deg) scale(1.4);\n}\n\nbutton:hover svg.meteor {\n  transform: translate(28px, 30px) rotate(260deg) scale(2);\n}\n', colors: '#ffffff,#6a92ef', radii: '2rem', shadows: '', techniques: 'glassmorphism,3d-transform,gradient,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'albertofanini-prog_hard-wasp-8', cat: 'Buttons', author: 'albertofanini-prog', tags: 'button', html: '<div id="pulsa" class="pulsa">\n  <button id="cta" class="cta">\n    Spatial button<div class="star a"></div>\n  <div class="star b"></div>\n  <div class="star c"></div>\n  <div class="star d"></div>\n  <div class="star e"></div>\n  <div class="star f"></div>\n  <div class="star g"></div>\n  <svg version="1.1" viewBox="0 0 1024 1024" width="24px" class="rocket"><path fill="#3A7EB9" d="M662.72 462.784l136.448 169.408v173.248l-136.448-48.32zM342.72 457.344L206.272 626.816v173.248l136.448-48.384z"></path><path fill="#D48171" d="M570.688 418.688l-142.848 1.152a266.496 266.496 0 0 1-20.288-0.576l3.712 448.64c0.256 28.928 94.272 130.048 94.272 130.048s93.888-102.656 93.632-131.584l-3.712-448.96a344.64 344.64 0 0 1-24.768 1.28z"></path><path fill="#E9DF92" d="M531.456 599.296l-63.04 0.576c-3.008 0-5.952-0.064-8.96-0.384l2.176 257.792c0.128 16.64 41.728 74.816 41.728 74.816s41.344-58.944 41.28-75.52l-2.176-257.92c-3.648 0.384-7.296 0.64-11.008 0.64z"></path><path fill="#B5D5EB" d="M554.304 93.568a324.352 324.352 0 0 0-110.592 1.728L342.72 240.768v584.512c13.824-0.96 27.968-1.536 42.368-1.536h245.248c11.84 0 23.36 0.384 34.816 1.024V253.312L554.304 93.568z"></path><path fill="#3A7EB9" d="M541.44 94.144L500.416 35.008l-45.696 59.136v29.504h89.024v-29.504zM459.456 288.64h88.96v88.896h-88.96zM459.456 467.456h88.96v88.96h-88.96zM459.456 634.176h88.96v88.896h-88.96zM364.928 788.736h277.76v44.352h-277.76z"></path></svg>\n  </button>\n  \n</div>', css: '\n/* From Uiverse.io by albertofanini-prog - Tags: button */\n.pulsa {\n  animation: pulsa 1.4s infinite;\n  min-width: 200px;\n  width: fit-content;\n  border-radius: 9999px;\n  /* overflow: hidden; */\n}\n\n.cta {\n  width: 100%;\n  height: 100%;\n  border: none;\n  outline: none;\n  background-color: none;\n  border-radius: 9999px;\n  padding: 8px 16px;\n  color: white;\n  font-size: 15px;\n  background: linear-gradient(109.6deg, #090979 11.2%, #9006A1 53.7%, #090979 100.2%);\n  letter-spacing: 0.08em;\n  font-weight: 800;\n  position: relative;\n}\n\n.cta:active {\n  animation: pulsa-active .4s infinite;\n}\n\n.star {\n  width: 2px;\n  height: 2px;\n  background-color: white;\n  border-radius: 50%;\n  position: absolute;\n  animation: pulsa-stella 1.8s infinite;\n  transition: all .8s ease-in-out;\n}\n\n.star.a {\n  top: 8px;\n  left: 6px;\n}\n\n.star.b {\n  top: 2px;\n  left: 16px;\n}\n\n.star.c {\n  top: 18px;\n  left: 8px;\n}\n\n.star.d {\n  top: 14px;\n  left: 20px;\n}\n\n.star.e {\n  top: 30px;\n  left: 8px;\n}\n\n.star.f {\n  top: 24px;\n  left: 24px;\n}\n\n.star.g {\n  top: 10px;\n  left: 32px;\n}\n\n.pulsa:hover .star.a {\n  transform: translate3d(0px, 8px, 0);\n}\n\n.pulsa:hover .star.b {\n  transform: translate3d(-4px, 6px, 0);\n}\n\n.pulsa:hover .star.c {\n  transform: translate3d(14px, -8px, 0);\n}\n\n.pulsa:hover .star.d {\n  transform: translate3d(16px, -2px, 0);\n}\n\n.pulsa:hover .star.e {\n  transform: translate3d(58px, -20px, 0);\n}\n\n.pulsa:hover .star.f {\n  transform: translate3d(34px, 2px, 0);\n}\n\n.pulsa:hover .star.g {\n  transform: translate3d(10px, 16px, 0);\n}\n\n.rocket {\n  position: absolute;\n  top: 8px;\n  right: 16px;\n  z-index: -1;\n  transform: rotate(180deg);\n  transition: all .3s ease-in-out;\n}\n\n.pulsa:hover .rocket {\n  z-index: auto;\n  animation: muovi-razzo 1.8s linear;\n  transform: rotate(0deg);\n}\n\n@keyframes pulsa {\n  0% {\n    box-shadow: 0 0 0 0 #9006A1;\n  }\n\n  100% {\n    box-shadow: 0 0 0 8px #fbb32f01;\n  }\n}\n\n@keyframes pulsa-stella {\n  0% {\n    box-shadow: 0 0 0 0 #ffffff;\n  }\n\n  100% {\n    box-shadow: 0 0 0 4px #fbb32f0', colors: '#ffffff,#090979,#9006a1,#fbb32f01', radii: '50%,9999px', shadows: '0 0 0 0 #9006A1,0 0 0 8px #fbb32f01,0 0 0 0 #ffffff', techniques: '3d-transform,glow-shadow,gradient,animation,svg-icon'),
const GalaxyComp(id: 'Amir10Amir_big-dolphin-56', cat: 'Buttons', author: 'Amir10Amir', tags: 'gradient,button', html: '<button class="bn">Hover!</button>', css: '\n/* From Uiverse.io by Amir10Amir - Tags: gradient, button */\nbutton {\n  --border-radius: 25px;\n  --border-width: 7px;\n  appearance: none;\n  position: relative;\n  padding: 1em 2em;\n  border: 0;\n  background-color: #212121;\n  font-family: "Roboto", Arial, "Segoe UI", sans-serif;\n  font-size: 18px;\n  font-weight: 500;\n  color: #ffff;\n  z-index: 2;\n}\n\nbutton::after {\n  --m-i: linear-gradient(#000, #000);\n  --m-o: content-box, padding-box;\n  content: "";\n  position: absolute;\n  left: 0;\n  top: 0;\n  width: 100%;\n  height: 100%;\n  padding: var(--border-width);\n  background-image: conic-gradient(\n		#ff0080,\n		#ff0080,\n		#ff0080,\n		#ff0080,\n		#ff0080,\n		#ff0080,\n		#ff0080\n	);\n  -webkit-mask-image: var(--m-i), var(--m-i);\n  mask-image: var(--m-i), var(--m-i);\n  -webkit-mask-origin: var(--m-o);\n  mask-origin: var(--m-o);\n  mask-clip: var(--m-o);\n  mask-composite: exclude;\n  -webkit-mask-composite: destination-out;\n  filter: hue-rotate(0);\n  animation: rotate-hue634 linear 500ms infinite;\n  animation-play-state: paused;\n  border-radius: 20px;\n  border-color: #000;\n}\n\nbutton:hover::after {\n  animation-play-state: running;\n  border-radius: 10px;\n}\n\n@keyframes rotate-hue634 {\n  to {\n    filter: hue-rotate(1turn);\n  }\n}\n\nbutton,\nbutton::after {\n  box-sizing: border-box;\n  border-radius: 20px;\n}\n\nbutton:active {\n  --border-width: 5px;\n}\n\n.bn {\n  padding: 0.9em 1.6em;\n  border: none;\n  outline: none;\n  color: #FFF;\n  font-family: inherit;\n  font-weight: 500;\n  font-size: 17px;\n  cursor: pointer;\n  position: relative;\n  z-index: 0;\n  border-radius: 32px;\n}\n\n.bn::after {\n  content: "";\n  z-index: -1;\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  background-color: rgb(46, 46, 46);\n  left: 0;\n  top: 0;\n  border-radius: 10px;\n}\n\n.bn::before {\n  content: "";\n  background: linear-gradient(\n    45deg,\n    #07d888, #e40851, #2f00ff, #00ff37,\n      #ec0808, #2600ff, #0bd157, #2f00ff\n);\n  position: absolute;\n  top: -2px;\n  left: -2px;\n  background-size: 600%;\n  z-index: -1;\n  width: c', colors: '#212121,#ff0080,#e40851,#2600ff,#00ff37,#000,#2f00ff,#ec0808,#0bd157,#ffff', radii: '10px,32px,25px,20px', shadows: '', techniques: 'glassmorphism,gradient,animation,css-mask,pseudo-elements'),
const GalaxyComp(id: 'anushkaps_nasty-mouse-56', cat: 'Buttons', author: 'anushkaps', tags: 'animation,alert,gradient,button,code,svg,arrow,2d button', html: '<button class="button">\n  <div class="in">\n    <div class="image">\n      <svg\n        fill="#000000"\n        width="25px"\n        height="25px"\n        viewBox="0 0 24 24"\n        xmlns="http://www.w3.org/2000/svg"\n        transform="rotate(-45)"\n      >\n        <g id="SVGRepo_bgCarrier" stroke-width="0"></g>\n        <g\n          id="SVGRepo_tracerCarrier"\n          stroke-linecap="round"\n          stroke-linejoin="round"\n        ></g>\n        <g id="SVGRepo_iconCarrier">\n          <path\n            d="M20.34,9.32l-14-7a3,3,0,0,0-4.08,3.9l2.4,5.37h0a1.06,1.06,0,0,1,0,.82l-2.4,5.37A3,3,0,0,0,5,22a3.14,3.14,0,0,0,1.35-.32l14-7a3,3,0,0,0,0-5.36Zm-.89,3.57-14,7a1,1,0,0,1-1.35-1.3l2.39-5.37A2,2,0,0,0,6.57,13h6.89a1,1,0,0,0,0-2H6.57a2,2,0,0,0-.08-.22L4.1,5.41a1,1,0,0,1,1.35-1.3l14,7a1,1,0,0,1,0,1.78Z"\n          ></path>\n        </g>\n      </svg>\n    </div>\n    <div class="text">Send Message</div>\n  </div>\n</button>', css: '\n/* From Uiverse.io by anushkaps  - Tags: animation, alert, gradient, button, code, svg, arrow, 2d button */\n.button {\n  cursor: pointer;\n  height: 6em;\n  width: 18em;\n  border-radius: 1em;\n  border-top: 0.2em solid #b0b1b0;\n  border-bottom: 0.2em solid #50504f;\n  border-left: 0.2em solid #848584;\n  border-right: 0.2em solid #848584;\n  box-shadow: 0.3em 0.3em 0.5em #a9aaa9;\n  background: linear-gradient(to bottom, #fbfcfb, #ecedec);\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  position: relative;\n  overflow: hidden;\n}\n\n.button::before {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  border-radius: inherit;\n  padding: 0.2em;\n  background: linear-gradient(135deg, #b0b1b0, #848584, #50504f);\n  z-index: -1;\n}\n\n.in {\n  display: flex;\n  justify-content: space-around;\n  align-items: center;\n  height: 4.8em;\n  width: 16.9em;\n  border-radius: 2em;\n  background: linear-gradient(to bottom, #eceeec, #ffffff);\n  transition: background 2s, transform 2s ease;\n}\n\n.text {\n  font-size: 21px;\n  font-weight: bold;\n  width: 9em;\n  color: #252625;\n  transition: transform 0.6s ease-in-out;\n}\n\n.image {\n  padding-left: 1.2em;\n  transition: transform 0.3s ease-in-out;\n}\n\n.image svg {\n  transition: transform 0.6s ease-in-out; /* Smooth rotation */\n}\n\n.button:hover .in {\n  background: linear-gradient(to bottom, #ffffff, #eceeec);\n  transform: scale(1.05);\n}\n\n.button:hover .image {\n  animation: fly-1 0.6s ease-in-out infinite alternate;\n}\n\n.button:hover svg {\n  transform: translateX(6.5em) rotate(2deg);\n}\n\n.button:hover .text {\n  transform: translateX(9em);\n}\n\n.button:active {\n  transform: scale(0.95);\n}\n\n@keyframes fly-1 {\n  from {\n    transform: translateY(0.1em);\n  }\n  to {\n    transform: translateY(-0.1em);\n  }\n}\n\n', colors: '#fbfcfb,#848584,#eceeec,#b0b1b0,#252625,#50504f,#ecedec,#ffffff,#a9aaa9', radii: '2em,inherit,1em', shadows: '0.3em 0.3em 0.5em #a9aaa9', techniques: '3d-transform,gradient,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'AqFox_fat-ladybug-84', cat: 'Buttons', author: 'AqFox', tags: '3d,blue,button,glossy', html: '<button>BUTTON</button>', css: '\n/* From Uiverse.io by AqFox - Tags: 3d, blue, button, glossy */\nbutton {\n  --c: #fff;\n /* text color */\n  background: linear-gradient(90deg, #0000 33%, #fff5, #0000 67%) var(--_p,100%)/300% no-repeat,\n    #004dff;\n /* background color */\n  color: #0000;\n  border: none;\n  transform: perspective(500px) rotateY(calc(20deg*var(--_i,-1)));\n  text-shadow: calc(var(--_i,-1)* 0.08em) -.01em 0   var(--c),\n    calc(var(--_i,-1)*-0.08em)  .01em 2px #0004;\n  outline-offset: .1em;\n  transition: 0.3s;\n}\n\nbutton:hover,\nbutton:focus-visible {\n  --_p: 0%;\n  --_i: 1;\n}\n\nbutton:active {\n  text-shadow: none;\n  color: var(--c);\n  box-shadow: inset 0 0 9e9q #0005;\n  transition: 0s;\n}\n\nbutton {\n  font-family: system-ui, sans-serif;\n  font-weight: bold;\n  font-size: 2rem;\n  margin: 0;\n  cursor: pointer;\n  padding: .1em .3em;\n}\n', colors: '#004dff,#0004,#0000,#fff5,#fff,#0005', radii: '', shadows: 'inset 0 0 9e9q #0005', techniques: '3d-transform,glow-shadow,text-shadow,gradient,perspective'),
const GalaxyComp(id: 'AyuuLima_modern-wasp-21', cat: 'Buttons', author: 'AyuuLima', tags: 'simple,material design,neumorphism,animation,gradient,button', html: '<button class="button">Button</button>', css: '\n/* From Uiverse.io by AyuuLima  - Tags: simple, material design, neumorphism, animation, gradient, button */\n.button {\n  position: relative;\n  width: 120px;\n  height: 40px;\n  background-color: rgb(0, 0, 0);\n  display: flex;\n  align-items: center;\n  color: rgb(255, 255, 255);\n  flex-direction: column;\n  justify-content: center;\n  border: none;\n  padding: 20px;\n  gap: 120px;\n  border-radius: 10px;\n  cursor: pointer;\n}\n\n.button::before {\n  content: "";\n  position: absolute;\n  inset: 0;\n  left: 3px;\n  top: -4px;\n  margin: auto;\n  width: -128px;\n  height: -48px;\n  border-radius: 10px;\n  background: linear-gradient(-45deg, #10d32a 0%, rgb(119, 235, 235) 100%);\n  z-index: -10;\n  pointer-events: visiblePainted;\n  transition: all 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275);\n}\n\n.button::after {\n  content: "";\n  z-index: -1;\n  position: absolute;\n  inset: 0;\n  background: linear-gradient(-45deg, #00ff22 0%, rgb(0, 250, 250) 100%);\n  transform: translate3d(0, 0, 0) scale(0.95);\n  filter: blur(15px);\n}\n\n.button:hover::after {\n  filter: blur(40px);\n}\n\n.button:hover::before {\n  transform: rotate(-180deg);\n}\n\n.button:active::before {\n  scale: 0.7;\n}\n\n', colors: '#10d32a,#00ff22', radii: '10px', shadows: '', techniques: 'glassmorphism,cubic-bezier,3d-transform,gradient,pseudo-elements'),
const GalaxyComp(id: 'Balthasar42_evil-grasshopper-45', cat: 'Buttons', author: 'Balthasar42', tags: 'button', html: '<button class="btn btn--primary">\n\n  <span class="btn-inner">\n    <span class="btn-label">\n      to the galaxy\n    </span>\n    <span class="btn-blur" aria-hidden=""></span>\n  </span>\n  \n</button>', css: '\n/* From Uiverse.io by Balthasar42 - Tags: button */\n.btn {\n  --btn-gradient: var(--btn-gradient-from),var(--btn-gradient-to);\n  border: 0 none;\n  appearance: none;\n  border-radius: 9999px;\n  background-color: var(--btn-bg);\n  box-shadow: 0 0 2px 2px var(--btn-shadow), 0 0 4px 4px var(--btn-shadow), 0 0 8px 8px var(--btn-shadow);\n}\n\n.btn,\n.btn * {\n  box-sizing: border-box;\n}\n\n.btn-inner {\n  position: relative;\n  border-radius: inherit;\n  border: 1px solid transparent;\n  font-size: 1rem;\n  display: flex;\n  align-items: center;\n  min-width: 10rem;\n  padding: 1.5rem 2rem;\n  overflow: hidden;\n  color: var(--btn-text-color);\n}\n\n.btn-label {\n  position: absolute;\n  bottom: 1px;\n  left: 1px;\n  right: 1px;\n  top: 1px;\n  border-radius: inherit;\n  z-index: 10;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  background-color: var(--btn-bg);\n  background-image: linear-gradient(to bottom,var(--btn-gradient));\n}\n\n.btn-blur {\n  position: absolute;\n  bottom: 1px;\n  left: 1px;\n  right: 1px;\n  top: 1px;\n  z-index: 0;\n  transform: scaleX(3.5);\n  filter: blur(6px);\n}\n\n.btn-blur:before {\n  --gradient: var(--btn-color-from), var(--btn-color), var(--btn-color-to);\n  --transition: 5s;\n  content: "";\n  position: absolute;\n  z-index: 0;\n  top: 50%;\n  bottom: 0;\n  left: 0;\n  right: 0;\n  background-image: conic-gradient(var(--gradient));\n  animation: turn var(--transition) linear infinite;\n}\n\n.btn:hover,\n.btn:active {\n  transition: transform .5s ease-in-out 0s;\n  transform: translateY(-1px);\n}\n\n.btn:active .btn-blur:before {\n  --transition: 2s;\n}\n\n.btn--primary {\n  --btn-bg: #111111;\n  --btn-gradient-from: #111111;\n  --btn-gradient-to: rgba(255, 255, 255, 0.1);\n  --btn-text-color: #ffffff;\n  --btn-color: #5f17d4;\n  --btn-color-from: #c6a3ff;\n  --btn-color-to: #966ed8;\n  --btn-shadow: #5f17d42d;\n}\n\n@keyframes turn {\n  0% {\n    transform: translateY(-50%) rotate(0deg)\n  }\n\n  to {\n    transform: translateY(-50%) rotate(1turn)\n  }\n}\n', colors: '#966ed8,#5f17d4,#5f17d42d,#111111,#ffffff,#c6a3ff', radii: 'inherit,9999px', shadows: '0 0 2px 2px var(--btn-shadow), 0 0 4px 4px var(--btn-shadow), 0 0 8px 8px var(--btn-shadow)', techniques: 'glassmorphism,3d-transform,glow-shadow,gradient,animation'),
const GalaxyComp(id: 'barisdogansutcu_lovely-walrus-42', cat: 'Buttons', author: 'barisdogansutcu', tags: 'button', html: '<button>\n    <svg class="css-i6dzq1" stroke-linejoin="round" stroke-linecap="round" fill="none" stroke-width="2" stroke="#FFFFFF" height="24" width="24" viewBox="0 0 24 24">\n        <path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path>\n    </svg>\n    Edit\n</button>', css: '\n/* From Uiverse.io by barisdogansutcu - Tags: button */\nbutton {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  gap: 10px;\n  background-image: linear-gradient(to top, #30cfd0 0%, #330867 100%);\n  border: solid 3px transparent;\n  background-clip: padding-box;\n  box-shadow: 0px 0px 0px 3px #ffffff00;\n  color: white;\n  min-height: 43px;\n  padding: 0 13px 0 13px;\n  border-radius: 50px;\n  text-transform: uppercase;\n  letter-spacing: 2px;\n  transition: all .5s ease;\n}\n\nbutton:active {\n  transform: scale(.9);\n  transition: all 100ms ease;\n}\n\nbutton:hover {\n  box-shadow: 0px 0px 0px 3px #30a1b8;\n}\n\nbutton svg {\n  width: 16px;\n}\n', colors: '#30a1b8,#ffffff00,#330867,#30cfd0', radii: '50px', shadows: '0px 0px 0px 3px #ffffff00,0px 0px 0px 3px #30a1b8', techniques: '3d-transform,glow-shadow,gradient,typography-transform,svg-icon'),
const GalaxyComp(id: 'barisdogansutcu_yellow-husky-22', cat: 'Buttons', author: 'barisdogansutcu', tags: 'button', html: '<div class="plane-button">\n    <input type="checkbox" name="checkbox" id="checkbox">\n    <button>\n        <div class="plane">\n            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24">\n                <path fill="none" d="M0 0h24v24H0V0z"></path>\n                <path style="fill: #091607;stroke-width: 1px;stroke: hsl(0deg 0% 100%);" d="M21 14.58c0-.36-.19-.69-.49-.89L13 9V3.5c0-.83-.67-1.5-1.5-1.5S10 2.67 10 3.5V9l-7.51 4.69c-.3.19-.49.53-.49.89 0 .7.68 1.21 1.36 1L10 13.5V19l-1.8 1.35c-.13.09-.2.24-.2.4v.59c0 .33.32.57.64.48L11.5 21l2.86.82c.32.09.64-.15.64-.48v-.59c0-.16-.07-.31-.2-.4L13 19v-5.5l6.64 2.08c.68.21 1.36-.3 1.36-1z"></path>\n            </svg>\n        </div>\n        <span class="loading"> <i></i> <i></i> <i></i></span>\n        <span class="title">Buy a ticket</span>\n        <span class="approved">Approved</span>\n    </button>\n</div>', css: '\n/* From Uiverse.io by barisdogansutcu - Tags: button */\nbutton {\n  width: 180px;\n  height: 55px;\n  border-radius: 50px;\n  border: solid 4px rgba(255, 255, 255, 0);\n  background-clip: padding-box;\n  box-shadow: 0 4px 20px -2px rgba(39, 94, 254, 0.5);\n  background-color: hsl(241deg 44% 49%);\n  font-size: 20px;\n  letter-spacing: 1px;\n  font-weight: 100;\n  position: relative;\n  cursor: pointer;\n  color: white;\n}\n\n.loading {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%,-50%);\n  width: 100%;\n  height: 100%;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  gap: 7px;\n  z-index: 0;\n}\n\n.loading i {\n  width: 5px;\n  height: 5px;\n  background-color: white;\n  display: inline-flex;\n  border-radius: 100%;\n  animation-name: loading5234;\n  animation-iteration-count: infinite;\n  animation-duration: 1s;\n}\n\n@keyframes loading5234 {\n  100% {\n    opacity: 0;\n  }\n}\n\ninput:checked + button {\n  transition-delay: 4s;\n  background-color: #31cb20;\n  box-shadow: 0 4px 20px -2px rgb(49 203 32);\n}\n\n.title, .approved {\n  position: absolute;\n  left: 50%;\n  top: 50%;\n  transform: translate(-50%,-50%);\n  width: 100%;\n  display: block;\n  font-size: 15px;\n}\n\nbutton .title {\n  background-color: hsl(241deg 44% 49%);\n  width: 90%;\n}\n\ninput:checked + button .approved {\n  transition-delay: 4s;\n  visibility: visible;\n  opacity: 1;\n  background-color: #31cb20;\n  width: 90%;\n}\n\ninput:checked + button .title {\n  visibility: hidden;\n  opacity: 0;\n  transition: all .5s ease;\n}\n\ninput:not(:checked) + button .approved {\n  visibility: hidden;\n  opacity: 1;\n}\n\ninput {\n  position: absolute;\n  left: 50%;\n  top: 50%;\n  transform: translate(-50%,-50%);\n  z-index: 999;\n  outline: none;\n  width: 210px;\n  height: 60px;\n  border-radius: 50px;\n  margin: 0;\n  opacity: 0;\n  cursor: pointer;\n}\n\n.plane {\n  width: 55px;\n  height: 55px;\n  border-radius: 100%;\n  position: absolute;\n  left: 0;\n  z-index: 9;\n  top: 0;\n  transition: none;\n  background-color: transparent;\n  opacity: 0;\n}', colors: '#31cb20,#3c4a57', radii: '50px,100%', shadows: '0 4px 20px -2px rgba(39, 94, 254, 0.5),0 4px 20px -2px rgb(49 203 32)', techniques: 'cubic-bezier,3d-transform,animation,checkbox-input,svg-icon'),
const GalaxyComp(id: 'Boosterrohit_smooth-swan-20', cat: 'Buttons', author: 'Boosterrohit', tags: 'active,about me', html: '<button class="box">\n  <p class="text-button">Button</p>\n</button>', css: '\n/* From Uiverse.io by Boosterrohit - Tags: active, about me */\n.box {\n  position: relative;\n  width: 120px;\n  height: 45px;\n  overflow: hidden;\n  border: none;\n  background-color: rgb(218, 203, 177);\n  font-family: \'Segoe UI\', Tahoma, Geneva, Verdana, sans-serif;\n  border-top-left-radius: 20px;\n  cursor: pointer;\n  border-bottom-right-radius: 20px;\n  box-shadow: 0 0 10px rgb(104, 134, 218);\n}\n\n.box::before {\n  content: "";\n  position: absolute;\n  width: 15px;\n  height: 200px;\n  margin-top: -92px;\n  background: linear-gradient(#00ccff,#d400d4);\n  animation: amm 4s linear infinite;\n}\n\n@keyframes amm {\n  0% {\n    transform: rotate(0deg);\n  }\n\n  100% {\n    transform: rotate(360deg);\n  }\n}\n\n.text-button {\n  position: relative;\n  font-size: 1.2rem;\n  font-weight: bold;\n  z-index: 1;\n}\n\n.box::after {\n  content: "";\n  position: absolute;\n  inset: 4px;\n  background-color: rgb(218, 203, 177);\n  border-top-left-radius: 20px;\n  border-bottom-right-radius: 20px;\n}\n', colors: '#d400d4,#00ccff', radii: '', shadows: '0 0 10px rgb(104, 134, 218)', techniques: '3d-transform,glow-shadow,gradient,animation,pseudo-elements'),
const GalaxyComp(id: 'boryanakrasteva_splendid-goose-38', cat: 'Buttons', author: 'boryanakrasteva', tags: 'button', html: '<button class="btn">\n  See more \n  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" height="15px" width="15px" class="icon">\n<path stroke-linejoin="round" stroke-linecap="round" stroke-miterlimit="10" stroke-width="1.5" stroke="#292D32" d="M8.91016 19.9201L15.4302 13.4001C16.2002 12.6301 16.2002 11.3701 15.4302 10.6001L8.91016 4.08008"></path>\n</svg>\n</button>', css: '\n/* From Uiverse.io by boryanakrasteva - Tags: button */\n.btn {\n  width: 140px;\n  height: 40px;\n  display: flex;\n  align-items: center;\n  justify-content: space-evenly;\n  text-transform: uppercase;\n  letter-spacing: 1px;\n  border: none;\n  position: relative;\n  background-color: transparent;\n  transition: .2s cubic-bezier(0.19, 1, 0.22, 1);\n  opacity: 0.6;\n}\n\n.btn::after {\n  content: \'\';\n  border-bottom: 3px double rgb(214, 207, 113);\n  width: 0;\n  height: 100%;\n  position: absolute;\n  margin-top: -5px;\n  top: 0;\n  left: 5px;\n  visibility: hidden;\n  opacity: 1;\n  transition: .2s linear;\n}\n\n.btn .icon {\n  transform: translateX(0%);\n  transition: .2s linear;\n  animation: attention 1.2s linear infinite;\n}\n\n.btn:hover::after {\n  visibility: visible;\n  opacity: 0.7;\n  width: 90%;\n}\n\n.btn:hover {\n  letter-spacing: 2px;\n  opacity: 1;\n}\n\n.btn:hover > .icon {\n  transform: translateX(30%);\n  animation: none;\n}\n\n@keyframes attention {\n  0% {\n    transform: translateX(0%);\n  }\n\n  50% {\n    transform: translateX(30%);\n  }\n}\n\n', colors: '', radii: '', shadows: '', techniques: 'cubic-bezier,animation,typography-transform,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'BurgiSimon_strange-hound-0', cat: 'Buttons', author: 'BurgiSimon', tags: 'flashy,3d,white,gradient,button,hover,smooth,neon', html: '<div class="div">\n  <button class="button">\n    <span class="span"> HOVER ME </span>\n  </button>\n</div>', css: '\n/* From Uiverse.io by BurgiSimon  - Tags: flashy, 3d, white, gradient, button, hover, smooth, neon */\n.button {\n  cursor: pointer;\n  padding: 10px 20px;\n  border-radius: 20px;\n  background-color: #e8e8e8;\n  border: 1.6px solid #e2e2e2;\n  box-shadow: 6px 6px 10px #c5c5c5, -6px -6px 12px #ffffff;\n  transform: skewX(-5deg);\n  position: relative;\n  overflow: hidden;\n}\n\n.button::before {\n  content: "";\n  position: absolute;\n  top: -4px;\n  left: -4px;\n  right: -4px;\n  bottom: -4px;\n  z-index: -1;\n  background: linear-gradient(90deg, #03a9f4, #f441a5, #ffeb3b, #03a9f4);\n  background-size: 400%;\n  border-radius: 30px;\n  opacity: 0;\n  transition: opacity 0.5s, filter 0.5s;\n}\n\n.button:hover::before {\n  filter: blur(10px);\n  opacity: 1;\n  animation: animateBorder 8s linear infinite;\n  border: 4px solid rgb(255, 255, 255);\n}\n\n@keyframes animateBorder {\n  0% {\n    background-position: 0%;\n  }\n  100% {\n    background-position: 400%;\n  }\n}\n\n.span {\n  color: black;\n  letter-spacing: 3px;\n  font-size: 18px;\n}\n\n.button:active {\n  box-shadow: 5px 5px 12px #cfcece, -4px -4px 12px #fcfcfc;\n}\n\n', colors: '#f441a5,#fcfcfc,#c5c5c5,#ffeb3b,#cfcece,#03a9f4,#e2e2e2,#ffffff,#e8e8e8', radii: '30px,20px', shadows: '6px 6px 10px #c5c5c5, -6px -6px 12px #ffffff,5px 5px 12px #cfcece, -4px -4px 12px #fcfcfc', techniques: 'glassmorphism,3d-transform,gradient,animation,pseudo-elements'),
const GalaxyComp(id: 'ChanduOffl_helpless-chipmunk-35', cat: 'Buttons', author: 'ChanduOffl', tags: 'icon,animation,white,button,message,btn,buttons,hover button', html: '<button class="button">\n  <svg\n    viewBox="0 0 24 24"\n    height="48"\n    width="48"\n    xmlns="http://www.w3.org/2000/svg"\n    class="send-icon"\n  >\n    <path\n      d="m16.066 10.184l-3.89-1.795c-2.154-.994-3.231-1.491-3.725-.982c-.493.509.038 1.572 1.101 3.698c.22.44.33.659.33.895s-.11.456-.33.895c-1.063 2.126-1.594 3.19-1.1 3.698c.493.51 1.57.012 3.725-.982l3.889-1.795c1.698-.784 2.548-1.176 2.548-1.816c0-.64-.85-1.032-2.549-1.816"\n      fill-opacity="0.4"\n      fill="currentColor"\n    ></path>\n    <path\n      d="M8.895 11.684L8.174 9.52a1 1 0 0 0-.707-.654l-1.78-.445a.8.8 0 0 0-.91 1.134l1.111 2.22a.5.5 0 0 1 0 .448l-1.11 2.22a.8.8 0 0 0 .91 1.134l1.78-.445a1 1 0 0 0 .706-.654l.72-2.163a1 1 0 0 0 0-.632"\n      fill="currentColor"\n    ></path>\n  </svg>\n  Send Message\n</button>', css: '\n/* From Uiverse.io by ChanduOffl  - Tags: icon, animation, white, button, message, btn, buttons, hover button */\n.button {\n  display: inline-flex;\n  align-items: center;\n  padding: 10px 20px;\n  background-color: #fefefe;\n  border: 1px solid #dcdcdc;\n  border-radius: 12px;\n\n  font-family: "Ubuntu", sans-serif;\n  font-size: 16px;\n  font-weight: bold;\n  color: #333;\n  cursor: pointer;\n  text-decoration: none;\n  transition: all 0.3s ease;\n  position: relative;\n  overflow: hidden;\n  z-index: 0;\n  outline: 2px solid #fafafa;\n  box-shadow: 9px 9px 44px #cecece3a, -9px -9px 44px #d3d3d33d,\n    inset 0 0 0 2px rgba(192, 192, 192, 0.25);\n}\n\n.button::before {\n  content: "";\n  position: absolute;\n  top: 3px;\n  left: 3px;\n  right: 3px;\n  bottom: 3px;\n  border-radius: 30px;\n  background: linear-gradient(\n    0deg,\n    #fbfbfb 0%,\n    #fafafa 5%,\n    #f7f7f7 72%,\n    #f2f2f2 86%,\n    #f0f0f0 100%\n  );\n  box-shadow: inset 0 2px 7px rgba(143, 143, 143, 0.16);\n  transition: all 0.3s ease;\n  z-index: -1;\n  margin: 2px;\n}\n\n.button:hover::before {\n  top: 1px;\n  left: 1px;\n  right: 1px;\n  bottom: 1px;\n  margin: 5px;\n}\n\n.button:focus {\n  outline: 2px solid #fefefe;\n  box-shadow: 9px 9px 44px #cecece3a, -9px -9px 44px #d3d3d33d,\n    inset 0 0 0 2px rgba(192, 192, 192, 0.5);\n}\n\n.send-icon {\n  margin-right: 5px;\n  transition: transform 0.3s ease;\n}\n\n.button:hover .send-icon {\n  transform: translateX(7px);\n}\n\n.button:focus .send-icon {\n  transform: rotate(-40deg);\n}\n\n', colors: '#fefefe,#dcdcdc,#f7f7f7,#f0f0f0,#fbfbfb,#d3d3d33d,#333,#cecece3a,#fafafa,#f2f2f2', radii: '30px,12px', shadows: '9px 9px 44px #cecece3a, -9px -9px 44px #d3d3d33d,\n    inset 0 0 0 2px rgba(192, 192, 192, 0.25),inset 0 2px 7px rgba(143, 143, 143, 0.16),9px 9px 44px #cecece3a, -9px -9px 44px #d3d3d33d,\n    inset 0 0 0 2px rgba(192, 192, 192, 0.5)', techniques: '3d-transform,glow-shadow,gradient,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'csemszepp_purple-treefrog-92', cat: 'Buttons', author: '', tags: '', html: '<div class="container">\n		<div class="btn"><a href="#">Read more</a></div>\n	</div>', css: '\n/* From Uiverse.io by csemszepp - Source: https://codepen.io/katarzynamarta/pen/rNdbbVq - Tags: simple, button, #button */\n.container {\n  width: 1000px;\n  display: flex;\n  flex-wrap: wrap;\n  justify-content: space-around;\n}\n\n.container .btn {\n  position: relative;\n  top: 0;\n  left: 0;\n  width: 250px;\n  height: 50px;\n  margin: 0;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n.container .btn a {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  background: rgba(255, 255, 255, 0.05);\n  box-shadow: 0 15px 15px rgba(0, 0, 0, 0.3);\n  border-bottom: 1px solid rgba(255, 255, 255, 0.1);\n  border-top: 1px solid rgba(255, 255, 255, 0.1);\n  border-radius: 30px;\n  padding: 10px;\n  letter-spacing: 1px;\n  text-decoration: none;\n  overflow: hidden;\n  color: #fff;\n  font-weight: 400px;\n  z-index: 1;\n  transition: 0.5s;\n  backdrop-filter: blur(15px);\n}\n\n.container .btn:hover a {\n  letter-spacing: 3px;\n}\n\n.container .btn a::before {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 50%;\n  height: 100%;\n  background: linear-gradient(to left, rgba(255, 255, 255, 0.15), transparent);\n  transform: skewX(45deg) translate(0);\n  transition: 0.5s;\n  filter: blur(0px);\n}\n\n.container .btn:hover a::before {\n  transform: skewX(45deg) translate(200px);\n}\n\n.container .btn::before {\n  content: "";\n  position: absolute;\n  left: 50%;\n  transform: translatex(-50%);\n  bottom: -5px;\n  width: 30px;\n  height: 10px;\n  background: #f00;\n  border-radius: 10px;\n  transition: 0.5s;\n  transition-delay: 0.5;\n}\n\n.container .btn:hover::before /*lightup button*/ {\n  bottom: 0;\n  height: 50%;\n  width: 80%;\n  border-radius: 30px;\n}\n\n.container .btn::after {\n  content: "";\n  position: absolute;\n  left: 50%;\n  transform: translatex(-50%);\n  top: -5px;\n  width: 30px;\n  height: 10px;\n  background: #f00;\n  border-radius: 10px;\n  transition: 0.5s;\n  transition-delay: 0.5;\n}\n\n.container .btn:', colors: '#2db2ff,#f00,#fff', radii: '30px,10px', shadows: '0 15px 15px rgba(0, 0, 0, 0.3),0 0 5px #2db2ff, 0 0 15px #2db2ff, 0 0 30px #2db2ff,\n		0 0 60px #2db2ff', techniques: 'glassmorphism,3d-transform,glow-shadow,gradient,pseudo-elements'),
const GalaxyComp(id: 'cssbuttons-io_purple-gecko-91', cat: 'Buttons', author: 'cssbuttons-io', tags: 'button', html: '<div class="wrapper">\n  <button> Button\n  </button>\n</div>', css: '\n/* From Uiverse.io by cssbuttons-io - Tags: button */\n.wrapper {\n perspective: 500px;\n transform: rotatex(10deg);\n animation: rotateAngle 6s linear infinite;\n margin: auto;\n width: auto;\n}\n\nbutton {\n display: block;\n position: relative;\n margin: 0.5em 0;\n padding: 0.8em 2.2em;\n cursor: pointer;\n background: #FFFFFF;\n border: none;\n border-radius: 0.4em;\n text-transform: uppercase;\n font-size: 19px;\n font-family: "Work Sans", sans-serif;\n font-weight: 500;\n letter-spacing: 0.04em;\n mix-blend-mode: color-dodge;\n perspective: 500px;\n transform-style: preserve-3d;\n}\n\nbutton:before, button:after {\n --z: 0px;\n position: absolute;\n top: 0;\n left: 0;\n display: block;\n content: "";\n width: 100%;\n height: 100%;\n opacity: 0;\n mix-blend-mode: inherit;\n border-radius: inherit;\n transform-style: preserve-3d;\n transform: translate3d(calc(var(--z) * 0px), calc(var(--z) * 0px), calc(var(--z) * 0px));\n}\n\nbutton span {\n mix-blend-mode: none;\n display: block;\n}\n\nbutton:after {\n background-color: #5D00FF;\n}\n\nbutton:before {\n background-color: #FF1731;\n}\n\nbutton:hover {\n background-color: #FFF65B;\n transition: background 0.3s 0.1s;\n}\n\nbutton:hover:before {\n --z: 0.04;\n animation: translateWobble 2.2s ease forwards;\n}\n\nbutton:hover:after {\n --z: -0.06;\n animation: translateWobble 2.2s ease forwards;\n}\n\n@keyframes rotateAngle {\n 0% {\n  transform: rotateY(0deg) rotateX(10deg);\n  -webkit-animation-timing-function: cubic-bezier(0.61, 1, 0.88, 1);\n  animation-timing-function: cubic-bezier(0.61, 1, 0.88, 1);\n }\n\n 25% {\n  transform: rotateY(20deg) rotateX(10deg);\n }\n\n 50% {\n  transform: rotateY(0deg) rotateX(10deg);\n  -webkit-animation-timing-function: cubic-bezier(0.61, 1, 0.88, 1);\n  animation-timing-function: cubic-bezier(0.61, 1, 0.88, 1);\n }\n\n 75% {\n  transform: rotateY(-20deg) rotateX(10deg);\n }\n\n 100% {\n  transform: rotateY(0deg) rotateX(10deg);\n }\n}\n\n@keyframes translateWobble {\n 0% {\n  opacity: 0;\n  transform: translate3d(calc(var(--z) * 0px), calc(var(--z) * 0px), calc(var(--z) * 0px)', colors: '#ff1731,#ffffff,#5d00ff,#fff65b', radii: '0.4em,inherit', shadows: '', techniques: 'cubic-bezier,3d-transform,animation,perspective,typography-transform'),
const GalaxyComp(id: 'd3uceY_dry-gecko-28', cat: 'Buttons', author: 'd3uceY', tags: 'animation,button,shadow,animated,svg,button hover effect,christmas', html: '<button>\n  <div class="overflow">\n    <div class="text-container">Merry Christmas</div>\n    <svg\n      id="christmas-tree"\n      viewBox="0 0 512 512"\n      data-name="Layer 1"\n      xmlns="http://www.w3.org/2000/svg"\n      class="christmas-tree christmas-tree-1"\n    >\n      <path\n        d="M285 406.03v88.47a10.004 10.004 0 0 1-10 10h-38a10.004 10.004 0 0 1-10-10v-88.47Z"\n        fill="#d88a55"\n      ></path>\n      <path d="M285 406.03v69.46l-58-59.1v-10.36h58z" fill="#c57a44"></path>\n      <circle fill="#fed402" r="22.5" cy="468" cx="370"></circle>\n      <path\n        d="M383.398 449.925a22.5 22.5 0 0 1-34.796 25.032 22.5 22.5 0 1 0 34.796-25.032Z"\n        fill="#fac600"\n      ></path>\n      <circle fill="#fed402" r="22.5" cy="468" cx="142"></circle>\n      <path\n        d="M436.67 396.93a819.475 819.475 0 0 1-178.17 20.09 820.131 820.131 0 0 1-164.76-16.15c-6.41-1.29-12.56-2.62-18.45-3.95a8.538 8.538 0 0 1-4.1-2.15 5.655 5.655 0 0 1-.42-.43c0-.01 0-.01-.01-.01a7.541 7.541 0 0 1-.69-.94 9.171 9.171 0 0 1-.52-1.04c-.08-.22-.15-.43-.21-.65a.076.076 0 0 0-.01-.04c-.04-.18-.08-.37-.11-.56a.22.22 0 0 1-.01-.08c-.02-.14-.04-.28-.05-.42a6.602 6.602 0 0 1 0-.89 6.22 6.22 0 0 1 1.75-3.86l.84-.9L240.5 204.21l8.92-9.55a7.823 7.823 0 0 1 .66-.63 9.555 9.555 0 0 1 11.84 0 7.832 7.832 0 0 1 .66.63l106.03 113.56 10.32 11.05 62.16 66.58c3.69 3.96 1.36 9.77-4.42 11.08Z"\n        fill="#46cc8d"\n      ></path>\n      <path\n        d="M436.67 396.93a819.475 819.475 0 0 1-178.17 20.09 820.131 820.', css: '\n/* From Uiverse.io by d3uceY  - Tags: animation, button, shadow, animated, svg, button hover effect , Christmas */\n:root {\n  --red: #dc3d2a;\n  --blue: #87ceeb;\n}\n\n.overflow {\n  overflow: hidden;\n  position: relative;\n  width: 100%;\n  height: 100%;\n  z-index: 10;\n  border-radius: 12px;\n}\n\nbutton {\n  position: relative;\n  width: 190px;\n  height: 50px;\n  border: 0px solid;\n  outline: 0px solid;\n  cursor: pointer;\n  background: var(--blue);\n  border-radius: 12px;\n  font-family: "Franklin Gothic Medium", "Arial Narrow", Arial, sans-serif;\n}\n\n.santa {\n  width: 45px;\n  position: absolute;\n  z-index: -1;\n  top: 0px;\n  transition: 250ms;\n}\n\n.christmas-tree {\n  width: 30px;\n  position: absolute;\n  transform: translateY(30px);\n  transition: 300ms;\n  transition-delay: 500ms;\n}\n\n.christmas-tree-1 {\n  left: 0px;\n  top: 20px;\n}\n\n.christmas-tree-2 {\n  right: 0px;\n  top: 20px;\n}\n\n.cloud-container {\n  position: absolute;\n  width: 100%;\n  transform: translateY(-40px);\n  transition: 250ms;\n  transition-delay: 250ms;\n}\n\n.cloud {\n  fill: #fff;\n  position: absolute;\n}\n\n.cloud:nth-child(1) {\n  left: 30px;\n  top: 3px;\n  animation-name: cloud;\n  animation-duration: 4s;\n  animation-iteration-count: infinite;\n  animation-timing-function: ease-in-out;\n  animation-fill-mode: backwards;\n}\n\n.cloud:nth-child(2) {\n  right: 30px;\n  top: 14px;\n  animation-name: cloud;\n  animation-duration: 4s;\n  animation-iteration-count: infinite;\n  animation-timing-function: ease-in-out;\n  animation-fill-mode: backwards;\n}\n\n@keyframes cloud {\n  0% {\n    transform: translateX(0px);\n  }\n\n  50% {\n    transform: translateX(-4px);\n  }\n\n  100% {\n    transform: translateX(4px);\n  }\n}\n\n.snowflake {\n  position: absolute;\n  z-index: -1;\n  opacity: 0;\n}\n\n.snowflake:nth-child(1) {\n  transition: 0.8s;\n  filter: drop-shadow(0 0 10px #fffdef);\n  width: 30px;\n  height: 30px;\n  inset: 0;\n}\n\n.snowflake:nth-child(2) {\n  transition: 0.8s;\n  filter: drop-shadow(0 0 10px #fffdef);\n  width: 20px;\n  height: 20px;\n  inset: 0;\n}\n\n.snowflake', colors: '#dc3d2a,#fffdef,#fff,#87ceeb', radii: '12px', shadows: '0 0 25px var(--blue)', techniques: '3d-transform,glow-shadow,animation,filter-effect,svg-icon'),
