#fff;\n  border-radius: 50%;\n  margin: 10px;\n  width: 50px;\n  height: 50px;\n  font-size: 18px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  flex-direction: column;\n  box-shadow: 0 10px 10px rgba(0, 0, 0, 0.1);\n  cursor: pointer;\n  transition: all 0.2s cubic-bezier(0.68, -0.55, 0.265, 1.55);\n}\n\n.wrapper .tooltip {\n  position: absolute;\n  top: 0;\n  font-size: 14px;\n  background: #fff;\n  color: #fff;\n  padding: 5px 8px;\n  border-radius: 5px;\n  box-shadow: 0 10px 10px rgba(0, 0, 0, 0.1);\n  opacity: 0;\n  pointer-events: none;\n  transition: all 0.3s cubic-bezier(0.68, -0.55, 0.265, 1.55);\n}\n\n.wrapper .tooltip::before {\n  position: absolute;\n  content: "";\n  height: 8px;\n  width: 8px;\n  background: #fff;\n  bottom: -3px;\n  left: 50%;\n  transform: translate(-50%) rotate(45deg);\n  transition: all 0.3s cubic-bezier(0.68, -0.55, 0.265, 1.55);\n}\n\n.wrapper .icon:hover .tooltip {\n  top: -45px;\n  opacity: 1;\n  visibility: visible;\n  pointer-events: auto;\n}\n\n.wrapper .icon:hover span,\n.wrapper .icon:hover .tooltip {\n  text-shadow: 0px -1px 0px rgba(0, 0, 0, 0.1);\n}\n\n.wrapper .facebook:hover,\n.wrapper .facebook:hover .tooltip,\n.wrapper .facebook:hover .tooltip::before {\n  background: #1877f2;\n  color: #fff;\n}\n\n.wrapper .twitter:hover,\n.wrapper .twitter:hover .tooltip,\n.wrapper .twitter:hover .tooltip::before {\n  background: #1da1f2;\n  color: #fff;\n}\n\n.wrapper .instagram:hover,\n.wrapper .instagram:hover .tooltip,\n.wrapper .instagram:hover .tooltip::before {\n  background: #e4405f;\n  color: #fff;\n}\n\n', colors: '#1da1f2,#1877f2,#fff,#e4405f', radii: '50%,5px', shadows: '0 10px 10px rgba(0, 0, 0, 0.1),0 10px 10px rgba(0, 0, 0, 0.1)', techniques: 'cubic-bezier,3d-transform,text-shadow,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'DevVaradPatil_terrible-frog-3', cat: 'Buttons', author: 'DevVaradPatil', tags: 'button', html: '<button>\n  Button\n</button>', css: '\n/* From Uiverse.io by DevVaradPatil - Tags: button */\nbutton {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%,-50%);\n  width: 130px;\n  height: 45px;\n  text-align: center;\n  line-height: 45px;\n  color: #fff;\n  font-size: 15px;\n  text-transform: uppercase;\n  text-decoration: none;\n  font-family: sans-serif;\n  box-sizing: border-box;\n  background: linear-gradient(90deg,#03a9f4,#ffeb3b,#f441af,#03a9f4);\n  background-size: 400%;\n  border-radius: 30px;\n  z-index: 1;\n  border: none;\n  outline: none;\n}\n\nbutton:hover {\n  animation: animate 6s linear infinite;\n}\n\n@keyframes animate {\n  0% {\n    background-position: 0%;\n  }\n\n  100% {\n    background-position: 400%;\n  }\n}\n\nbutton::before {\n  content: \'\';\n  position: absolute;\n  top: -5px;\n  left: -5px;\n  right: -5px;\n  bottom: -5px;\n  z-index: -1;\n  background: linear-gradient(90deg,#03a9f4,#ffeb3b,#f441af,#03a9f4);\n  border-radius: 40px;\n  filter: blur(20px);\n  opacity: 0;\n  transition: 0.5s;\n}\n\nbutton:hover::before {\n  filter: blur(20px);\n  opacity: 1;\n  animation: animate 6s linear infinite;\n}\n', colors: '#f441af,#ffeb3b,#fff,#03a9f4', radii: '30px,40px', shadows: '', techniques: 'glassmorphism,gradient,animation,typography-transform,pseudo-elements'),
