9:after {\n  left: 100%;\n  transform: translateX(var(--progress, 0)) rotate(180deg);\n  z-index: -1;\n}\n\n.btn-9:hover:before {\n  --progress: 100%;\n}\n\n.btn-9:hover:after {\n  --progress: -100%;\n}\n\n', colors: '#000,#fff', radii: '99rem', shadows: '', techniques: '3d-transform,gradient,clip-path,css-mask,typography-transform'),
const GalaxyComp(id: 'dvirpro_stupid-impala-26', cat: 'Buttons', author: 'dvirpro', tags: 'simple,icon,red,button,like', html: '<button class="like-button"></button>', css: '\n/* From Uiverse.io by dvirpro  - Tags: simple, icon, red, button, like */\n.like-button {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  padding: 20px;\n  border: none;\n  border-radius: 50%;\n  background: linear-gradient(145deg, #ff5252, #d50000);\n  box-shadow: 0 8px 15px rgba(0, 0, 0, 0.25);\n  color: #fff;\n  font-family: "Arial", sans-serif;\n  text-transform: uppercase;\n  cursor: pointer;\n  transition: transform 0.4s cubic-bezier(0.25, 0.1, 0.25, 1);\n  width: 90px;\n  height: 90px;\n  position: relative;\n  overflow: hidden;\n}\n\n.like-button:before {\n  content: "\\2764"; /* Heart Icon */\n  font-size: 50px;\n  color: #fff;\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%) scale(0);\n  transition: transform 0.3s ease-in-out;\n}\n\n.like-button:hover {\n  animation: heartBeat 0.6s infinite;\n}\n\n.like-button:hover:before {\n  transform: translate(-50%, -50%) scale(1);\n}\n\n.like-button:active:after {\n  transform: translate(-50%, -50%) scale(1);\n  opacity: 1;\n}\n\n@keyframes heartBeat {\n  from {\n    transform: scale(1);\n  }\n  50% {\n    transform: scale(1.1);\n  }\n  to {\n    transform: scale(1);\n  }\n}\n\n', colors: '#d50000,#ff5252,#fff', radii: '50%', shadows: '0 8px 15px rgba(0, 0, 0, 0.25)', techniques: 'cubic-bezier,3d-transform,gradient,animation,typography-transform'),
const GalaxyComp(id: 'elijahgummer_purple-sloth-17', cat: 'Buttons', author: 'elijahgummer', tags: 'yellow,gradient,button,glow,modern,upload,hover effect,upload button', html: '<button class="button">\n  <svg\n    id="UploadToCloud"\n    viewBox="0 0 24 24"\n    xmlns="http://www.w3.org/2000/svg"\n    height="16px"\n    width="16px"\n    class="icon"\n  >\n    <path d="M0 0h24v24H0V0z" fill="none"></path>\n    <path\n      class="color000000 svgShape"\n      fill="#000000"\n      d="M19.35 10.04C18.67 6.59 15.64 4 12 4 9.11 4 6.6 5.64 5.35 8.04 2.34 8.36 0 10.91 0 14c0 3.31 2.69 6 6 6h13c2.76 0 5-2.24 5-5 0-2.64-2.05-4.78-4.65-4.96zM14 13v4h-4v-4H7l4.65-4.65c.2-.2.51-.2.71 0L17 13h-3z"\n    ></path>\n  </svg>\n  Upload CV\n</button>', css: '\n/* From Uiverse.io by elijahgummer  - Tags: yellow, gradient, button, glow, modern, upload, hover effect, upload button */\n.button {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  cursor: pointer;\n  background: linear-gradient(45deg, #ffc75d, #ffc708);\n  box-shadow: 0 0 24px #ffb20861;\n  border: 2px solid #ffe825;\n  border-radius: 100px;\n  transition: background-color 0.3s ease, box-shadow 0.3s ease,\n    text-shadow 0.3s ease;\n  padding: 10px 20px;\n  color: #09090b;\n  font-weight: bold;\n  text-shadow: 2px 2px 5px rgba(0, 0, 0, 0.3); /* Text drop shadow */\n}\n\n.button:hover {\n  background-color: #ffc75d !important;\n  box-shadow: 0 0 34px #ffb20861 !important;\n  text-shadow: 0 0 4px #ffe825; /* Hover text shadow */\n  border-color: #ffe825 !important;\n}\n\n.icon {\n  margin-right: 5px;\n  filter: drop-shadow(2px 2px 5px rgba(0, 0, 0, 0.3)); /* Icon drop shadow */\n}\n\n', colors: '#ffc708,#09090b,#ffe825,#ffb20861,#ffc75d', radii: '100px', shadows: '0 0 24px #ffb20861,0 0 34px #ffb20861 !important', techniques: 'glow-shadow,text-shadow,gradient,filter-effect,svg-icon'),
const GalaxyComp(id: 'elijahgummer_slippery-dragonfly-100', cat: 'Buttons', author: 'elijahgummer', tags: 'icon,animation,button,hover,gradients,colorful,transition,hover effect', html: '<ul>\n  <li style="--i:#a955ff;--j:#ea51ff;">\n    <span class="icon">🏠</span>\n    <span class="title">Home</span>\n  </li>\n</ul>', css: '\n/* From Uiverse.io by elijahgummer  - Tags: icon, animation, button, hover, gradients, colorful, transition, hover effect */\nul {\n  position: relative;\n  display: flex;\n  gap: 25px;\n}\n\nul li {\n  position: relative;\n  list-style: none;\n  width: 60px;\n  height: 60px;\n  background: #fff;\n  border-radius: 60px;\n  cursor: pointer;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  box-shadow: 0 10px 25px rgba(0, 0, 0, 0.1);\n  transition: 0.5s;\n}\n\nul li:hover {\n  width: 180px;\n  box-shadow: 0 10px 25px rgba(0, 0, 0, 0);\n}\n\nul li::before {\n  content: "";\n  position: absolute;\n  inset: 0;\n  border-radius: 60px;\n  background: linear-gradient(45deg, var(--i), var(--j));\n  opacity: 0;\n  transition: 0.5s;\n}\n\nul li:hover::before {\n  opacity: 1;\n}\n\nul li::after {\n  content: "";\n  position: absolute;\n  top: 10px;\n  width: 100%;\n  height: 100%;\n  border-radius: 60px;\n  background: linear-gradient(45deg, var(--i), var(--j));\n  transition: 0.5s;\n  filter: blur(15px);\n  z-index: -1;\n  opacity: 0;\n}\n\nul li:hover::after {\n  opacity: 0.5;\n}\n\nul li .icon {\n  color: #777;\n  font-size: 1.75em;\n  transition: 0.5s;\n  transition-delay: 0.25s;\n}\n\nul li:hover .icon {\n  transform: scale(0);\n  color: #fff;\n  transition-delay: 0s;\n}\n\nul li span {\n  position: absolute;\n}\n\nul li .title {\n  color: #fff;\n  font-size: 1.1em;\n  text-transform: uppercase;\n  letter-spacing: 0.1em;\n  transform: scale(0);\n  transition: 0.5s;\n  transition-delay: 0s;\n}\n\nul li:hover .title {\n  transform: scale(1);\n  transition-delay: 0.25s;\n}\n\n', colors: '#777,#fff', radii: '60px', shadows: '0 10px 25px rgba(0, 0, 0, 0.1),0 10px 25px rgba(0, 0, 0, 0)', techniques: 'glassmorphism,3d-transform,gradient,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'ercnersoy_swift-bullfrog-99', cat: 'Buttons', author: 'ercnersoy', tags: 'button', html: '<button>\n  click me\n</button>', css: '\n/* From Uiverse.io by ercnersoy - Tags: button */\nbutton {\n  padding: 0.5rem 2.5rem 0.5rem 2.5rem;\n  box-shadow: 0px 0px 0px 3px black;\n  border: 0;\n  border-radius: 0.5rem;\n  font-size: 1rem;\n  background-color: #ffc83d;\n  color: black;\n  font-weight: bolder;\n  font-family: Verdana, Geneva, Tahoma, sans-serif;\n  position: relative;\n  transition: all .9s ease-in-out;\n  letter-spacing: 0.1rem;\n  text-transform: uppercase;\n}\n\nbutton:hover {\n  background-color: #f03a17;\n  color: white;\n}\n\nbutton::before {\n  content: "😍";\n  position: absolute;\n  left: -0rem;\n  top: 0rem;\n  opacity: 1;\n  font-size: 1.55rem;\n  transition: all .9s ease-in-out;\n  transform: rotate(0deg);\n}\n\nbutton:hover::before {\n  content: "😘";\n  opacity: 1;\n  visibility: visible;\n  transform: rotate(40deg);\n  font-size: 2.5rem;\n  top: -0.75rem;\n  transition: all .9s ease-in-out;\n  animation: rightRun 2s forwards;\n}\n\nbutton:active::before {\n  content: "🥰";\n}\n\n@keyframes rightRun {\n  100% {\n    transform: translateX(140px);\n  }\n}\n', colors: '#f03a17,#ffc83d', radii: '0.5rem', shadows: '0px 0px 0px 3px black', techniques: '3d-transform,glow-shadow,animation,typography-transform,pseudo-elements'),
