.button:hover .icon {\n  transform: translateX(-7px) rotate(45deg);\n}\n.button::after {\n  content: "";\n  position: absolute;\n  width: 97%;\n  height: 90%;\n  z-index: -2;\n  border-radius: 15px;\n  background: linear-gradient(\n    rgb(255, 255, 255),\n    rgba(253, 253, 253, 0.589) 75%\n  );\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n}\n\n', colors: '#1c1c1c18,#b4b4b473,#1c1c1c48,#ffffff8f,#1c1c1c44,#d8d6d686,#faf9f9,#1c1c1c2c,#1c1c1c33,#4e4d4df8', radii: '15px,25px', shadows: '0px 2px 4px #1c1c1c48, 0px 30px 100px #1c1c1c33,\n    0px 15px 30px #1c1c1c2c, 0px 12px 6px #1c1c1c18,0 -1px rgba(0, 0, 0, 0.171),none', techniques: '3d-transform,text-shadow,gradient,svg-icon,pseudo-elements'),
