 span:nth-child(3) {\n  top: calc(50% - 2px);\n  right: -50px;\n  transform-origin: right;\n}\n\n.button:hover span:nth-child(3) {\n  right: 50%;\n}\n\n.button span:nth-child(2) {\n  left: calc(50% - 2px);\n  top: -50px;\n  transform-origin: top;\n}\n\n.button:hover span:nth-child(2) {\n  top: 50%;\n}\n\n.button span:nth-child(4) {\n  left: c', colors: '#fff,#1e9bff', radii: '4px,2px', shadows: '0 0 0px #1e9bff,0 0 10px #1e9bff,\n    0 0 30px #1e9bff,\n    0 0 60px #1e9bff,0 0 10px #1e9bff,\n    0 0 20px #1e9bff,\n    0 0 30px #1e9bff,\n    0 0 50px #1e9bff,\n    0 0 100px #1e9bff', techniques: '3d-transform,glow-shadow,text-shadow,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'gharsh11032000_ancient-elephant-87', cat: 'Buttons', author: 'gharsh11032000', tags: 'button,hover effect,hoverme', html: '<button class="button">\n  <span>Hover me</span>\n</button>', css: '\n/* From Uiverse.io by gharsh11032000 - Tags: button, hover effect, hoverme */\n.button {\n  text-decoration: none;\n  color: white;\n  font-weight: 600;\n  font-size: 20px;\n  text-transform: uppercase;\n  letter-spacing: 2px;\n  padding: 15px 30px;\n  display: block;\n  background-color: transparent;\n  border: none;\n  position: relative;\n  cursor: pointer;\n  transition: all 0.6s cubic-bezier(0.23, 1, 0.320, 1);\n}\n\n.button span {\n  background: linear-gradient(-45deg, #63A4FF 0%, #83EAF1 100% );\n  background-clip: text;\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n}\n\n.button:hover span {\n  -webkit-text-fill-color: white;\n}\n\n.button::before {\n  position: absolute;\n  content: "";\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  transform: scaleY(2);\n  border: 3px solid;\n  border-image: linear-gradient(-45deg, #63A4FF 0%, #83EAF1 100% );\n  border-image-slice: 1;\n  border-width: 2px 0 2px 0;\n  opacity: 0;\n  pointer-events: none;\n  transition: all 0.6s cubic-bezier(0.23, 1, 0.320, 1);\n  z-index: -1;\n}\n\n.button:hover::before {\n  transform: scaleY(0);\n  opacity: 1;\n}\n\n.button::after {\n  position: absolute;\n  content: "";\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  background: linear-gradient(-45deg, #63A4FF 0%, #83EAF1 100% );\n  transform: scale(0);\n  pointer-events: none;\n  transition: all 0.6s cubic-bezier(0.23, 1, 0.320, 1);\n  z-index: -1;\n}\n\n.button:hover::after {\n  transform: scaleY(1);\n}\n\n.button:active {\n  scale: 0.90;\n}\n\n\n', colors: '#63a4ff,#83eaf1', radii: '', shadows: '', techniques: 'cubic-bezier,3d-transform,gradient,typography-transform,pseudo-elements'),
