'0 10px 20px rgba(0, 0, 0, 0.2),none', techniques: 'cubic-bezier,3d-transform,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'hssqrshi_light-rattlesnake-90', cat: 'Buttons', author: 'hssqrshi', tags: 'button', html: '<button class="button">Join Now<span class="arrow">&gt;</span></button>', css: '\n/* From Uiverse.io by hssqrshi  - Tags: button */\n.button {\n  background-color: #c47dfb;\n  background-image: linear-gradient(to bottom, #d992ff, #c47dfb);\n  border: none;\n  color: white;\n  padding: 15px 32px;\n  text-align: center;\n  text-decoration: none;\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 16px;\n  margin: 4px 2px;\n  cursor: pointer;\n  border-radius: 12px;\n  position: relative;\n  overflow: hidden;\n  transition:\n    transform 0.2s ease,\n    box-shadow 0.2s ease,\n    background-color 0.3s ease;\n  transform: perspective(500px) rotateX(0deg);\n}\n\n.button:hover {\n  background-color: #b46cea;\n  transform: perspective(500px) rotateX(5deg);\n  animation: glow 1.5s infinite alternate;\n}\n\n.button:focus {\n  outline: none;\n  box-shadow: 0 0 0 4px rgba(196, 125, 251, 0.5);\n}\n\n.button:active {\n  transform: perspective(500px) rotateX(-5deg) translateY(2px);\n  box-shadow:\n    0 4px 8px rgba(0, 0, 0, 0.2),\n    0 10px 15px rgba(0, 0, 0, 0.2);\n}\n\n@keyframes glow {\n  0% {\n    box-shadow:\n      0 0 10px rgba(196, 125, 251, 0.5),\n      0 0 20px rgba(196, 125, 251, 0.5),\n      0 0 30px rgba(196, 125, 251, 0.5);\n  }\n  100% {\n    box-shadow:\n      0 0 20px rgba(196, 125, 251, 0.8),\n      0 0 30px rgba(196, 125, 251, 0.8),\n      0 0 40px rgba(196, 125, 251, 0.8);\n  }\n}\n\n.button .text {\n  transition:\n    transform 0.3s ease,\n    color 0.3s ease,\n    font-size 0.3s ease;\n}\n\n.button:hover .text {\n  transform: scale(1.2);\n  font-size: 18px;\n  color: #e0bbff;\n}\n\n.arrow {\n  display: inline-block;\n  margin-left: 8px;\n  transition: transform 0.3s ease;\n  font-size: 16px;\n}\n\n.button:hover .arrow {\n  transform: translateX(5px);\n}\n\n', colors: '#d992ff,#b46cea,#e0bbff,#c47dfb', radii: '12px', shadows: '0 0 0 4px rgba(196, 125, 251, 0.5),0 4px 8px rgba(0, 0, 0, 0.2),\n    0 10px 15px rgba(0, 0, 0, 0.2),0 0 10px rgba(196, 125, 251, 0.5),\n      0 0 20px rgba(196, 125, 251, 0.5),\n      0 0 30px rgba(196, 125, 251, 0.5)', techniques: '3d-transform,glow-shadow,gradient,animation,perspective'),
const GalaxyComp(id: 'JkHuger_tough-skunk-14', cat: 'Buttons', author: 'JkHuger', tags: 'button', html: '<nav class="menu">\n   <input type="checkbox" href="#" class="menu-open" name="menu-open" id="menu-open">\n   <label class="menu-open-button" for="menu-open">\n    <span class="lines line-1"></span>\n    <span class="lines line-2"></span>\n    <span class="lines line-3"></span>\n  </label>\n\n   <a href="#" class="menu-item blue"> <i class="fa fa-anchor"></i> </a>\n   <a href="#" class="menu-item green"> <i class="fa fa-coffee"></i> </a>\n   <a href="#" class="menu-item red"> <i class="fa fa-heart"></i> </a>\n   <a href="#" class="menu-item purple"> <i class="fa fa-microphone"></i> </a>\n   <a href="#" class="menu-item orange"> <i class="fa fa-star"></i> </a>\n   <a href="#" class="menu-item lightblue"> <i class="fa fa-diamond"></i> </a>\n</nav>', css: '\n/* From Uiverse.io by JkHuger - Tags: button */\n.menu-item,\n.menu-open-button {\n  background: #EEEEEE;\n  border-radius: 100%;\n  width: 80px;\n  height: 80px;\n  margin-left: -40px;\n  position: absolute;\n  color: #FFFFFF;\n  text-align: center;\n  line-height: 80px;\n  -webkit-transform: translate3d(0, 0, 0);\n  transform: translate3d(0, 0, 0);\n  -webkit-transition: -webkit-transform ease-out 200ms;\n  transition: -webkit-transform ease-out 200ms;\n  transition: transform ease-out 200ms;\n}\n\n.menu-open {\n  display: none;\n}\n\n.lines {\n  width: 25px;\n  height: 3px;\n  background: #596778;\n  display: block;\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  margin-left: -12.5px;\n  margin-top: -1.5px;\n  -webkit-transition: -webkit-transform 200ms;\n  transition: -webkit-transform 200ms;\n  transition: transform 200ms;\n}\n\n.line-1 {\n  -webkit-transform: translate3d(0, -8px, 0);\n  transform: translate3d(0, -8px, 0);\n}\n\n.line-2 {\n  -webkit-transform: translate3d(0, 0, 0);\n  transform: translate3d(0, 0, 0);\n}\n\n.line-3 {\n  -webkit-transform: translate3d(0, 8px, 0);\n  transform: translate3d(0, 8px, 0);\n}\n\n.menu-open:checked + .menu-open-button .line-1 {\n  -webkit-transform: translate3d(0, 0, 0) rotate(45deg);\n  transform: translate3d(0, 0, 0) rotate(45deg);\n}\n\n.menu-open:checked + .menu-open-button .line-2 {\n  -webkit-transform: translate3d(0, 0, 0) scale(0.1, 1);\n  transform: translate3d(0, 0, 0) scale(0.1, 1);\n}\n\n.menu-open:checked + .menu-open-button .line-3 {\n  -webkit-transform: translate3d(0, 0, 0) rotate(-45deg);\n  transform: translate3d(0, 0, 0) rotate(-45deg);\n}\n\n.menu {\n  margin: auto;\n  position: absolute;\n  top: 0;\n  bottom: 0;\n  left: 0;\n  right: 0;\n  width: 80px;\n  height: 80px;\n  text-align: center;\n  box-sizing: border-box;\n  font-size: 26px;\n}\n\n\n/* .menu-item {\n   transition: all 0.1s ease 0s;\n} */\n\n.menu-item:hover {\n  background: #EEEEEE;\n  color: #3290B1;\n}\n\n.menu-item:nth-child(3) {\n  -webkit-transition-duration: 180ms;\n  transition-duration: 180ms;\n}\n\n.menu-item:nth-chi', colors: '#70cc72,#669ae1,#fe4365,#fc913a,#3290b1,#62c2e4,#c49cde,#596778,#ffffff,#eeeeee', radii: '100%', shadows: '3px 3px 0 0 rgba(0, 0, 0, 0.14),3px 3px 0 0 rgba(0, 0, 0, 0.14),3px 3px 0 0 rgba(0, 0, 0, 0.14)', techniques: 'cubic-bezier,3d-transform,glow-shadow,text-shadow,checkbox-input'),
const GalaxyComp(id: 'joe-herbert_quick-jellyfish-81', cat: 'Buttons', author: 'joe-herbert', tags: 'animation,button,hover,challenge', html: '<button class="button">\n  <div class="button-inner-wrap">\n    <div class="button-content">\n      <svg\n        id="svg1"\n        version="1.1"\n        fill="none"\n        viewBox="0 0 17.191999 17.915001"\n        height="17.915001"\n        width="17.191999"\n      >\n        <path\n          id="path1"\n          stroke-linejoin="round"\n          stroke-linecap="round"\n          stroke-width="1.5"\n          stroke="#000000"\n          d="M 9.3223611,8.9119975 H 3.5673455 m -0.17238,0.7972 -1.3313244,3.0014005 c -0.8349111,2.493962 0.031033,4.403741 3.26073,2.9505 l 8.8532949,-4.5605 c 1.64001,-0.785228 1.659708,-3.5011752 0,-4.3772505 l -8.8707749,-4.56832 c -2.6423685,-1.18905255 -4.1290723,0.3343707 -3.26268,2.94464 l 1.3527044,3.09163 c 0.0935,0.2817 0.14026,0.4226 0.15871,0.5666 0.01638,0.1279 0.01621,0.2573 -4.9e-4,0.3851 -0.01883,0.144 -0.06594,0.2847 -0.16017,0.5662 z"\n        ></path>\n      </svg>\n\n      <span>Send Message</span>\n    </div>\n  </div>\n</button>', css: '\n/* From Uiverse.io by joe-herbert  - Tags: animation, button, hover, challenge */\n.button {\n  cursor: pointer;\n  padding: 20px 15px;\n  font-weight: 600;\n  font-size: 17px;\n  font-family: sans-serif;\n  border-radius: 15px;\n  position: relative;\n  background-clip: padding-box;\n  border: solid 3px transparent;\n  width: 185px;\n  height: 65px;\n  box-shadow: 5px 5px 20px -5px #aaa;\n  transition: transform 0.3s;\n}\n.button span {\n  transition: opacity 0.3s 0.3s;\n  margin-left: 5px;\n}\n.button:before {\n  content: "";\n  position: absolute;\n  top: 0;\n  right: 0;\n  bottom: 0;\n  left: 0;\n  z-index: -1;\n  margin: -3px;\n  border-radius: inherit;\n  background: linear-gradient(to bottom, #ccc, #666);\n}\n.button:after {\n  content: "";\n  position: absolute;\n  top: 0;\n  right: 0;\n  bottom: 0;\n  left: 0;\n  background: linear-gradient(to bottom, #eee, #ddd);\n  border-radius: 15px;\n}\n.button-content {\n  position: absolute;\n  top: 50%;\n  left: 0;\n  right: 0;\n  z-index: 1;\n  transform: translateY(-50%);\n}\n.button-content:before {\n  content: "";\n  position: absolute;\n  z-index: -1;\n  top: calc(-50% - 2.5px);\n  right: 5px;\n  bottom: 5px;\n  left: 5px;\n  background: linear-gradient(to bottom, #dfdfdf, #efefef);\n  border-radius: 500px;\n  height: 50px;\n  transition: opacity 0.3s 0.3s;\n  filter: blur(1px);\n}\n.button svg {\n  position: relative;\n  left: 0;\n  width: 20px;\n  transform: rotate(-45deg);\n  transition: left 0.3s 0s, transform 0.3s 0s;\n}\n\n.button:hover .button-content:before,\n.button:hover span {\n  opacity: 0;\n  transition: opacity 0.3s;\n}\n.button:hover svg {\n  transition: left 0.6s 0.3s, transform 0.6s 0.3s;\n  left: calc(50% - 17.5px);\n  transform: translate(-50%, 2px) rotate(270deg) scale(1.5);\n}\n.button:active {\n  transform: scale(0.9);\n}\n.button:active svg {\n  animation: spin 0.4s ease-in-out 0.3s 1;\n}\n\n@keyframes spin {\n  from {\n    transform: translate(-50%, 2px) rotate(270deg) scale(1.5);\n  }\n  to {\n    transform: translate(-50%, 2px) rotate(630deg) scale(1.5);\n  }\n}\n\n', colors: '#efefef,#aaa,#ccc,#eee,#666,#ddd,#dfdfdf', radii: '500px,15px,inherit', shadows: '5px 5px 20px -5px #aaa', techniques: 'glassmorphism,3d-transform,gradient,animation,svg-icon'),
const GalaxyComp(id: 'John-CFO_green-rabbit-93', cat: 'Buttons', author: 'John-CFO', tags: 'button,glow,reflection', html: '<button class="btn">\n  <span class="text">Button</span>\n</button>', css: '\n/* From Uiverse.io by John-CFO - Tags: button, glow, reflection */\n.btn {\n  height: 3.5rem;\n  width: 13.2rem;\n  border-radius: 5px;\n  border: 5px solid rgb(255, 255, 255);\n  cursor: pointer;\n  filter: drop-shadow(0px 0px 10px rgb(255, 255, 255));\n  animation: flickering 2s linear infinite both;\n  text-transform: uppercase;\n  background-color: rgb(83, 82, 82);\n  color: rgb(234, 234, 234);\n  font-weight: 700;\n  transition: 0.6s;\n  box-shadow: 0px 0px 60px #1f4c65;\n  -webkit-box-reflect: below 10px linear-gradient(to bottom, rgba(0,0,0,0.0), rgba(0,0,0,0.4));\n}\n\n@keyframes flickering {\n  0%,\n  100% {\n    opacity: 1;\n  }\n\n  41.99% {\n    opacity: 1;\n  }\n\n  42% {\n    opacity: 0;\n  }\n\n  43% {\n    opacity: 0;\n  }\n\n  43.01% {\n    opacity: 1;\n  }\n\n  47.99% {\n    opacity: 1;\n  }\n\n  48% {\n    opacity: 0;\n  }\n\n  49% {\n    opacity: 0;\n  }\n\n  49.01% {\n    opacity: 1;\n  }\n}\n\n.text {\n  font-size: 1.8rem;\n  font-family: Arial, Helvetica, sans-serif;\n}\n\n.btn:hover {\n  background-color: black;\n  border-radius: 0;\n}\n\n\n\n\n\n\n', colors: '#1f4c65', radii: '0,5px', shadows: '0px 0px 60px #1f4c65', techniques: 'glow-shadow,gradient,animation,filter-effect,typography-transform'),
const GalaxyComp(id: 'KhaledMatalkah_odd-gecko-75', cat: 'Buttons', author: 'KhaledMatalkah', tags: 'button,hover,animated', html: '<button class="button">HOVER ME!</button>', css: '\n/* From Uiverse.io by KhaledMatalkah - Tags: button, hover, animated */\n@keyframes glowing-pulse {\n  0% {\n    box-shadow: 0 0 0 0 rgba(255, 255, 255, 0.7);\n  }\n\n  70% {\n    box-shadow: 0 0 0 30px rgba(255, 255, 255, 0);\n  }\n\n  100% {\n    box-shadow: 0 0 0 0 rgba(255, 255, 255, 0);\n  }\n}\n\n.button {\n  position: relative;\n  display: inline-block;\n  background: linear-gradient(to right, #FFB900, #FF7730);\n  border: none;\n  border-radius: 25px;\n  color: white;\n  padding: 10px 20px;\n  font-size: 18px;\n  text-transform: uppercase;\n  box-shadow: 0 0 0 0 rgba(255, 255, 255, 0.7);\n  animation: glowing-pulse 2s infinite;\n}\n\n.button::before {\n  content: "";\n  position: absolute;\n  top: -5px;\n  left: -5px;\n  right: -5px;\n  bottom: -5px;\n  border-radius: 30px;\n  box-shadow: 0 0 20px #FF7730;\n  opacity: 0;\n  pointer-events: none;\n  transition: opacity 0.3s ease;\n}\n\n.button:hover::before {\n  opacity: 1;\n}\n\n', colors: '#ffb900,#ff7730', radii: '30px,25px', shadows: '0 0 0 0 rgba(255, 255, 255, 0.7),0 0 0 30px rgba(255, 255, 255, 0),0 0 0 0 rgba(255, 255, 255, 0)', techniques: 'glow-shadow,gradient,animation,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'KhaledMatalkah_selfish-rabbit-36', cat: 'Buttons', author: 'KhaledMatalkah', tags: 'material design,button,custom,hover button', html: '<button class="realistic-button">\n  Button\n</button>', css: '\n/* From Uiverse.io by KhaledMatalkah - Tags: material design, button, custom, hover button */\n.realistic-button {\n  display: inline-block;\n  position: relative;\n  padding: 15px 30px;\n  font-size: 18px;\n  font-weight: bold;\n  text-transform: uppercase;\n  color: #fff;\n  background: linear-gradient(to bottom, #3498db, #2980b9);\n  border: 1px solid #2980b9;\n  border-radius: 5px;\n  box-shadow: 0px 4px 6px rgba(0, 0, 0, 0.1), inset 0px 2px 4px rgba(255, 255, 255, 0.2);\n  text-shadow: 0px 2px 2px rgba(0, 0, 0, 0.3);\n  cursor: pointer;\n  overflow: hidden;\n  transition: background-color 0.3s, transform 0.3s;\n}\n\n.realistic-button::before,\n        .realistic-button::after {\n  content: \'\';\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  background: inherit;\n  z-index: -1;\n  transition: transform 0.3s;\n}\n\n.realistic-button::before {\n  top: 0;\n  left: -100%;\n  transform: skewX(-45deg);\n}\n\n.realistic-button::after {\n  bottom: 0;\n  right: -100%;\n  transform: skewX(45deg);\n}\n\n.realistic-button:hover {\n  background: linear-gradient(to bottom, #042b46, #0a525cd8);\n  transform: translateY(-2px);\n  box-shadow: 0px 6px 8px rgba(0, 195, 255, 0.2), inset 0px 2px 4px rgba(255, 255, 255, 0.1);\n}\n\n.realistic-button:hover::before {\n  transform: translateX(100%);\n}\n\n.realistic-button:hover::after {\n  transform: translateX(-100%);\n}\n', colors: '#3498db,#042b46,#2980b9,#0a525cd8,#fff', radii: '5px', shadows: '0px 4px 6px rgba(0, 0, 0, 0.1), inset 0px 2px 4px rgba(255, 255, 255, 0.2),0px 6px 8px rgba(0, 195, 255, 0.2), inset 0px 2px 4px rgba(255, 255, 255, 0.1)', techniques: '3d-transform,text-shadow,gradient,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'KitoC_curly-cheetah-59', cat: 'Buttons', author: 'KitoC', tags: 'button', html: '<button>\n  <div class="blackhole">\n    <span class="rocket-path">\n      <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg" class="rocket"> <g> <path d="M0 0h24v24H0z" fill="none"></path> <path d="M8.498 20h7.004A6.523 6.523 0 0 1 12 23.502 6.523 6.523 0 0 1 8.498 20zM18 14.805l2 2.268V19H4v-1.927l2-2.268V9c0-3.483 2.504-6.447 6-7.545C15.496 2.553 18 5.517 18 9v5.805zM12 11a2 2 0 1 0 0-4 2 2 0 0 0 0 4z"></path> </g> </svg>\n    </span>\n    <span class="ring">\n      <span class="block"></span>\n    </span>\n  </div>\n  <span class="text">Don\'t get lost</span>\n</button>', css: '\n/* From Uiverse.io by KitoC - Tags: button */\nbutton {\n  --black-hole-color-2: rgb(242, 122, 42);\n  --black-hole-color: rgb(230, 148, 93);\n  font-size: 17px;\n  position: relative;\n  background: #212121;\n  padding: 0.5em;\n  border: 2px solid var(--black-hole-color);\n  border-radius: 8px;\n}\n\nbutton:hover {\n  border: 2px solid var(--black-hole-color-2);\n  animation: alert 1s alternate infinite linear;\n}\n\n.blackhole {\n  padding: 3em;\n  background-color: black;\n  color: var(--black-hole-color);\n  position: absolute;\n  animation: wiggle 3s alternate-reverse infinite linear;\n  top: -1em;\n  left: -8em;\n}\n\n.blackhole, .blackhole::after, .blackhole::before, .blackhole .ring, .blackhole .ring::after {\n  content: "";\n  border: 2px solid var(--black-hole-color);\n  border-radius: 50%;\n  box-shadow: 0 0 3em,\n              0 0 1em;\n}\n\n.blackhole::after, .blackhole::before {\n  animation: writhe 3s alternate-reverse infinite linear;\n}\n\n.blackhole::before {\n  position: absolute;\n  width: calc(100% + 0.5em);\n  height: calc(100% + 0.5em);\n  top: -9px;\n  left: -7px;\n}\n\n.blackhole::after {\n  position: absolute;\n  width: calc(100% + 8px);\n  height: calc(100% + 8px);\n  top: -6px;\n  left: -5px;\n}\n\n.blackhole .ring, .blackhole .ring::after {\n  content: "";\n  position: absolute;\n  left: -50%;\n  width: 200%;\n  border-top: none;\n  height: 2em;\n  border-width: 5px;\n  box-shadow: 0px 5px 10px var(--black-hole-color);\n}\n\n.blackhole .ring, .blackhole .ring::after {\n  animation: ring-writhe 3s alternate-reverse infinite linear;\n}\n\n.blackhole .block {\n  position: absolute;\n  z-index: 90;\n  content: "";\n  background-color: black;\n  top: -20%;\n  left: 25%;\n  width: 50%;\n  height: 10px;\n}\n\n.blackhole .ring::after {\n  width: 110%;\n  left: -8%;\n}\n\n.blackhole .rocket {\n  fill: white;\n  height: 30px;\n  transform: rotate(-140deg);\n  animation: idle 1s alternate-reverse infinite linear;\n}\n\n.blackhole .rocket-path {\n  position: absolute;\n  top: -60px;\n  right: -60px;\n}\n\nbutton:hover .rocket-path, button:focus ', colors: '#212121', radii: '50%,8px', shadows: '0 0 3em,\n              0 0 1em,0px 5px 10px var(--black-hole-color),0 0 0 var(--black-hole-color)', techniques: '3d-transform,glow-shadow,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'kleenpulse_dangerous-horse-41', cat: 'Buttons', author: 'kleenpulse', tags: 'gradient,button', html: '<button class="btn">\n    Button\n</button>', css: '\n/* From Uiverse.io by kleenpulse - Tags: gradient, button */\n.btn {\n  --border-color: linear-gradient(-45deg, #ffae00, #7e03aa, #00fffb);\n  --border-width: .125em;\n  --curve-size: .5em;\n  --blur: 30px;\n  --bg: #080312;\n  --color: #afffff;\n  color: var(--color);\n    /* use position: relative; so that BG is only for .btn */\n  position: relative;\n  isolation: isolate;\n  display: inline-grid;\n  place-content: center;\n  padding: .5em 1.5em;\n  font-size: 17px;\n  border: 0;\n  text-transform: uppercase;\n  box-shadow: 10px 10px 20px rgba(0, 0, 0, .6);\n  clip-path: polygon(\n            /* Top-left */\n            0% var(--curve-size),\n\n            var(--curve-size) 0,\n            /* top-right */\n            100% 0,\n            100% calc(100% - var(--curve-size)),\n\n            /* bottom-right 1 */\n            calc(100% - var(--curve-size)) 100%,\n            /* bottom-right 2 */\n            0 100%);\n  transition: color 250ms;\n}\n\n.btn::after,\n.btn::before {\n  content: \'\';\n  position: absolute;\n  inset: 0;\n}\n\n.btn::before {\n  background: var(--border-color);\n  background-size: 300% 300%;\n  animation: move-bg7234 5s ease infinite;\n  z-index: -2;\n}\n\n@keyframes move-bg7234 {\n  0% {\n    background-position: 31% 0%\n  }\n\n  50% {\n    background-position: 70% 100%\n  }\n\n  100% {\n    background-position: 31% 0%\n  }\n}\n\n.btn::after {\n  background: var(--bg);\n  z-index: -1;\n  clip-path: polygon(\n            /* Top-left */\n            var(--border-width) \n            calc(var(--curve-size) + var(--border-width) * .5),\n\n            calc(var(--curve-size) + var(--border-width) * .5) var(--border-width),\n\n            /* top-right */\n            calc(100% - var(--border-width)) \n            var(--border-width),\n\n            calc(100% - var(--border-width)) \n            calc(100% - calc(var(--curve-size) + var(--border-width) * .5)),\n\n            /* bottom-right 1 */\n            calc(100% - calc(var(--curve-size) + var(--border-width) * .5)) calc(100% - var(--border-width)),\n            /* bottom-r', colors: '#afffff,#ffae00,#00fffb,#080312,#7e03aa,#fff', radii: '', shadows: '10px 10px 20px rgba(0, 0, 0, .6)', techniques: 'gradient,animation,clip-path,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'KSAplay_strong-panther-58', cat: 'Buttons', author: 'KSAplay', tags: 'button', html: '<button class="btn">\n  <span class="text">Play</span>\n</button>', css: '\n/* From Uiverse.io by KSAplay - Tags: button */\n.btn {\n  position: relative;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  overflow: hidden;\n  padding: 1em 2em;\n  font-size: 15px;\n  font-weight: bold;\n  border-width: 0;\n  border-radius: 1.5em;\n  text-transform: uppercase;\n  transition: .2s ease;\n}\n\n.text {\n  font-size: 1.2em;\n  color: white;\n  z-index: 1;\n}\n\n.btn::before {\n  position: absolute;\n  content: \'\';\n  width: 120%;\n  height: 260%;\n  background-image: linear-gradient(135deg, rgba(0,5,255,1) 0%, rgba(255,0,159,1) 100%);\n}\n\n.btn::after {\n  position: absolute;\n  content: \'\';\n  width: 88%;\n  height: 80%;\n  border-width: 0;\n  border-radius: 1.2em;\n  background-color: black;\n  opacity: .7;\n  transition: 100ms ease;\n}\n\n.btn:hover.btn {\n  transform: scale(1.1);\n}\n\n.btn:hover.btn::after {\n  opacity: .5;\n}\n\n.btn:hover.btn::before {\n  animation: turn_4810 .4s infinite linear;\n}\n\n.btn:active.btn {\n  transform: scale(1.05);\n}\n\n.btn:active.btn::before {\n  transform: scale(1.05);\n  animation: turn_4810 .2s infinite linear;\n}\n\n@keyframes turn_4810 {\n  0% {\n    transform: rotate(0deg);\n  }\n\n  100% {\n    transform: rotate(360deg);\n  }\n}\n\n\n', colors: '', radii: '1.5em,1.2em', shadows: '', techniques: '3d-transform,gradient,animation,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'mrhyddenn_brown-penguin-10', cat: 'Buttons', author: 'mrhyddenn', tags: 'tooltip,button', html: '<div class="uiverse">\n    <span class="tooltip">uiverse.io</span>\n    <span>\n        Tooltip\n    </span>\n</div>', css: '\n/* From Uiverse.io by mrhyddenn - Tags: tooltip, button */\n.uiverse {\n  position: relative;\n  background: #ffffff;\n  color: #000;\n  padding: 15px;\n  margin: 10px;\n  border-radius: 10px;\n  width: 150px;\n  height: 50px;\n  font-size: 17px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  flex-direction: column;\n  box-shadow: 0 10px 10px rgba(0, 0, 0, 0.1);\n  cursor: pointer;\n  transition: all 0.2s cubic-bezier(0.68, -0.55, 0.265, 1.55);\n}\n\n.tooltip {\n  position: absolute;\n  top: 0;\n  font-size: 14px;\n  background: #ffffff;\n  color: #ffffff;\n  padding: 5px 8px;\n  border-radius: 5px;\n  box-shadow: 0 10px 10px rgba(0, 0, 0, 0.1);\n  opacity: 0;\n  pointer-events: none;\n  transition: all 0.3s cubic-bezier(0.68, -0.55, 0.265, 1.55);\n}\n\n.tooltip::before {\n  position: absolute;\n  content: "";\n  height: 8px;\n  width: 8px;\n  background: #ffffff;\n  bottom: -3px;\n  left: 50%;\n  transform: translate(-50%) rotate(45deg);\n  transition: all 0.3s cubic-bezier(0.68, -0.55, 0.265, 1.55);\n}\n\n.uiverse:hover .tooltip {\n  top: -45px;\n  opacity: 1;\n  visibility: visible;\n  pointer-events: auto;\n}\n\nsvg:hover span,\nsvg:hover .tooltip {\n  text-shadow: 0px -1px 0px rgba(0, 0, 0, 0.1);\n}\n\n.uiverse:hover,\n.uiverse:hover .tooltip,\n.uiverse:hover .tooltip::before {\n  background: linear-gradient(320deg, rgb(3, 77, 146), rgb(0, 60, 255));\n  color: #ffffff;\n}\n', colors: '#ffffff,#000', radii: '10px,5px', shadows: '0 10px 10px rgba(0, 0, 0, 0.1),0 10px 10px rgba(0, 0, 0, 0.1)', techniques: 'cubic-bezier,3d-transform,text-shadow,gradient,pseudo-elements'),
const GalaxyComp(id: 'MuhammadHasann_quick-goose-5', cat: 'Buttons', author: 'MuhammadHasann', tags: 'complex,3d,button,hover', html: '<div class="container-button">\n  <div class="hover bt-1"></div>\n  <div class="hover bt-2"></div>\n  <div class="hover bt-3"></div>\n  <div class="hover bt-4"></div>\n  <div class="hover bt-5"></div>\n  <div class="hover bt-6"></div>\n  <button></button>\n</div>', css: '\n/* From Uiverse.io by MuhammadHasann - Tags: complex, 3d, button, hover */\n.container-button {\n  display: grid;\n  grid-template-columns: 1fr 1fr 1fr;\n  grid-template-rows: 1fr 1fr;\n  grid-template-areas: "bt-1 bt-2 bt-3"\n    "bt-4 bt-5 bt-6";\n  position: relative;\n  perspective: 800;\n  padding: 0;\n  width: 135px;\n  height: 47px;\n  transition: all 0.3s ease-in-out;\n}\n\n.container-button:active {\n  transform: scale(0.95);\n}\n\n.hover {\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  z-index: 200;\n}\n\n.bt-1 {\n  grid-area: bt-1;\n}\n\n.bt-2 {\n  grid-area: bt-2;\n}\n\n.bt-3 {\n  grid-area: bt-3;\n}\n\n.bt-4 {\n  grid-area: bt-4;\n}\n\n.bt-5 {\n  grid-area: bt-5;\n}\n\n.bt-6 {\n  grid-area: bt-6;\n}\n\n.bt-1:hover ~ button {\n  transform: rotateX(15deg) rotateY(-15deg) rotateZ(0deg);\n  box-shadow: -2px -2px #18181888;\n}\n\n.bt-1:hover ~ button::after {\n  animation: shake 0.5s ease-in-out 0.3s;\n  text-shadow: -2px -2px #18181888;\n}\n\n.bt-3:hover ~ button {\n  transform: rotateX(15deg) rotateY(15deg) rotateZ(0deg);\n  box-shadow: 2px -2px #18181888;\n}\n\n.bt-3:hover ~ button::after {\n  animation: shake 0.5s ease-in-out 0.3s;\n  text-shadow: 2px -2px #18181888;\n}\n\n.bt-4:hover ~ button {\n  transform: rotateX(-15deg) rotateY(-15deg) rotateZ(0deg);\n  box-shadow: -2px 2px #18181888;\n}\n\n.bt-4:hover ~ button::after {\n  animation: shake 0.5s ease-in-out 0.3s;\n  text-shadow: -2px 2px #18181888;\n}\n\n.bt-6:hover ~ button {\n  transform: rotateX(-15deg) rotateY(15deg) rotateZ(0deg);\n  box-shadow: 2px 2px #18181888;\n}\n\n.bt-6:hover ~ button::after {\n  animation: shake 0.5s ease-in-out 0.3s;\n  text-shadow: 2px 2px #18181888;\n}\n\n.hover:hover ~ button::before {\n  background: transparent;\n}\n\n.hover:hover ~ button::after {\n  content: "Click";\n  top: -150%;\n  transform: translate(-50%, 0);\n  font-size: 34px;\n  color: #f19c2b;\n}\n\nbutton {\n  position: absolute;\n  padding: 0;\n  width: 135px;\n  height: 47px;\n  background: transparent;\n  font-size: 17px;\n  font-weight: 900;\n  border: 3px solid #f39923;\n  border-radius: 12px;\n ', colors: '#f5ae51,#18181888,#f19c2b,#f39923,#ffffff', radii: '12px', shadows: '-2px -2px #18181888,2px -2px #18181888,-2px 2px #18181888', techniques: '3d-transform,text-shadow,animation,perspective,pseudo-elements'),
const GalaxyComp(id: 'MuhammadHasann_tough-tiger-78', cat: 'Buttons', author: 'MuhammadHasann', tags: 'simple,glassmorphism,blue,button,shadow', html: '<div class="button-cont">\n  <button class="button">Light Button</button>\n</div>', css: '\n/* From Uiverse.io by MuhammadHasann  - Tags: simple, glassmorphism, blue, button, shadow */\n.button-cont {\n  position: relative;\n  width: fit-content;\n  height: fit-content;\n  border-radius: 9999px;\n}\n\n.button-cont::before {\n  content: "";\n  position: absolute;\n  top: 0%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  width: 0;\n  height: 0;\n  background: #06b5d4;\n  border-radius: 50%;\n  filter: blur(30px);\n  opacity: 0.8;\n  transition: all 0.6s cubic-bezier(1, 0, 0, 1);\n}\n\n.button-cont:hover::before {\n  width: 100%;\n  height: 25px;\n}\n\n.button {\n  cursor: pointer;\n  position: relative;\n  padding: 20px 48px;\n  background-color: #083344;\n  font-size: 16px;\n  color: #fefefe;\n  font-weight: 500;\n  border: none;\n  border-radius: 9999px;\n  backdrop-filter: blur(4px);\n  box-shadow: inset 0px 1px 1px #67e8f9;\n  transition: all 0.3s ease-in-out, box-shadow 0.1s ease-in-out;\n}\n\n.button::before {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: 50%;\n  transform: translate(-50%, 0%);\n  width: 0;\n  height: 0;\n  border-radius: 50%;\n  box-shadow: 0px 0px 25px 3px #67e8f97e;\n  transition: all 0.5s cubic-bezier(1, 0, 0, 1);\n}\n\n.button::after {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: 50%;\n  transform: translate(-50%, 0%);\n  width: 0;\n  height: 0;\n  background-image: linear-gradient(\n    to right,\n    #06b5d400,\n    #4ec4db00,\n    #72d0e200,\n    #90ddea3d,\n    #ace9f277,\n    #ace9f2,\n    #ace9f2,\n    #ace9f277,\n    #90ddea3d,\n    #72d0e200,\n    #4ec3db00,\n    #06b6d400\n  );\n  border-radius: 0 0 50% 50%;\n  opacity: 0.8;\n  filter: drop-shadow(0px 0px 30px #06b6d4);\n  transition: all 0.5s cubic-bezier(1, 0, 0, 1);\n}\n\n.button-cont:hover .button {\n  background: #18181898;\n  box-shadow: inset 0px 0px 0px #fefefe;\n}\n\n.button-cont:hover .button::before {\n  width: 30%;\n  height: 2px;\n}\n\n.button-cont:hover .button::after {\n  width: 100%;\n  height: 2px;\n}\n\n', colors: '#fefefe,#67e8f9,#06b5d400,#67e8f97e,#90ddea3d,#18181898,#72d0e200,#06b5d4,#ace9f277,#4ec3db00', radii: '50%,0 0 50% 50%,9999px', shadows: 'inset 0px 1px 1px #67e8f9,0px 0px 25px 3px #67e8f97e,inset 0px 0px 0px #fefefe', techniques: 'glassmorphism,cubic-bezier,glow-shadow,gradient,pseudo-elements'),
