\n  width: 100%;\n  height: 100%;\n  position: absolute;\n  top: -90%;\n  left: -90%;\n  filter: blur(20px);\n  background: #a11ee3;\n}\n\nbutton:after {\n  content: "";\n  width: 100%;\n  height: 100%;\n  position: absolute;\n  bottom: -90%;\n  right: -90%;\n  filter: blur(20px);\n  background: #51eafd;\n}\n\nbutton .icon {\n  transform: scale(0.07);\n  width: 20px;\n  height: 20px;\n  position: absolute;\n  left: 14px;\n  top: 2px;\n  transition: all ease-in-out .5s;\n  z-index: 9;\n  rotate: 45deg\n}\n\nbutton .icon path {\n  fill: #fff;\n}\n\nbutton .launch {\n  background: fff;\n  background: #fff;\n  width: 300px;\n  height: 300px;\n  rotate: 45deg;\n  position: absolute;\n  left: -9px;\n  top: 550%;\n  z-index: 0;\n  transform: translateX(-56%);\n  transition: all ease-in-out 1s;\n}\n\nbutton .text {\n  z-index: 9;\n  transition: all ease-in-out .3s;\n}\n\nbutton:hover .icon {\n  transform: scale(0.07);\n  animation: shake_341 2s infinite;\n  top: 5px;\n  left: 8px;\n  rotate: 0deg;\n}\n\nbutton:active {\n  transform: scale(0.7);\n}\n\nbutton:hover {\n  box-shadow: 0px 0px 0px 10px #00000017;\n}\n\nbutton:focus {\n  color: #464646;\n}\n\nbutton:focus .icon {\n  transform: scale(0.07);\n  animation: launch_341 2s alternate;\n}\n\nbutton:focus .icon path {\n  animation: fill_341 2s linear;\n  animation-fill-mode: forwards;\n}\n\nbutton:focus .launch {\n  top: -90%;\n}\n\n@keyframes shake_341 {\n  10%, 90% {\n    transform: scale(0.07) translate3d(-6px, 0, 0);\n  }\n\n  20%, 80% {\n    transform: scale(0.07)  translate3d(7px, 0, 0);\n  }\n\n  30%, 50%, 70% {\n    transform: scale(0.07)  translate3d(-9px, 0, 0);\n  }\n\n  40%, 60% {\n    transform: scale(0.07)  translate3d(9px, 0, 0);\n  }\n}\n\n@keyframes ', colors: '#00000017,#464646,#ffffff56,#51eafd,#181c35,#a11ee3,#fff', radii: '30px', shadows: '#51eafd 0px 0px 50px -15px,0px 0px 0px 10px #00000017', techniques: 'glassmorphism,3d-transform,glow-shadow,animation,svg-icon'),
const GalaxyComp(id: 'Peary74_loud-bear-3', cat: 'Buttons', author: 'Peary74', tags: 'button', html: '<button>Hover me\n  <div class="star-1">\n    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512" width="25" height="25">\n  <path fill="#fd1853" d="M427.313,88.686c-47.803-47.803-125.213-47.803-173.016,0l-17.087,17.087l-17.087-17.087\n    c-47.803-47.803-125.213-47.803-173.016,0c-47.803,47.803-47.803,125.213,0,173.016l190.103,190.103\n    c4.88,4.88,11.316,7.322,17.752,7.322c6.435,0,13.871-2.442,18.751-7.322l190.103-190.103\n    C475.116,213.899,475.116,136.489,427.313,88.686z"></path>\n</svg>\n\n\n  </div>\n  <div class="star-2">\n    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512" width="20" height="20">\n  <path fill="#fd1853" d="M427.313,88.686c-47.803-47.803-125.213-47.803-173.016,0l-17.087,17.087l-17.087-17.087\n    c-47.803-47.803-125.213-47.803-173.016,0c-47.803,47.803-47.803,125.213,0,173.016l190.103,190.103\n    c4.88,4.88,11.316,7.322,17.752,7.322c6.435,0,13.871-2.442,18.751-7.322l190.103-190.103\n    C475.116,213.899,475.116,136.489,427.313,88.686z"></path>\n</svg>\n\n  </div>\n  <div class="star-3">\n    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512" width="9" height="9">\n  <path fill="#fd1853" d="M427.313,88.686c-47.803-47.803-125.213-47.803-173.016,0l-17.087,17.087l-17.087-17.087\n    c-47.803-47.803-125.213-47.803-173.016,0c-47.803,47.803-47.803,125.213,0,173.016l190.103,190.103\n    c4.88,4.88,11.316,7.322,17.752,7.322c6.435,0,13.871-2.442,18.751-7.322l190.103-190.103\n    C475.116,213.899,475.116,136.489,427.313,88.686z"></path>\n</svg>\n\n  </d', css: '\n/* From Uiverse.io by Peary74 - Tags: button */\nbutton {\n  background: linear-gradient(45deg, transparent 27%, #fd1853 5%, #fd1853 73%, transparent 27%);\n  box-shadow: 6px 0px 0px #00e6f6;\n  position: relative;\n  padding: 12px 35px;\n  font-size: 20px;\n  font-weight: 500;\n  color: white;\n  border: 3px solid #00e6f6;\n  border-radius: 8px;\n  box-shadow: 0 0 0 #fec1958c;\n  transition: all .3s ease-in-out;\n}\n\n.star-1 {\n  position: absolute;\n  top: 20%;\n  left: 20%;\n  width: 25px;\n  height: auto;\n  filter: drop-shadow(0 0 0 #fd1853);\n  z-index: -5;\n  transition: all 1s cubic-bezier(0.05, 0.83, 0.43, 0.96);\n}\n\n.star-2 {\n  position: absolute;\n  top: 45%;\n  left: 45%;\n  width: 15px;\n  height: auto;\n  filter: drop-shadow(0 0 0 #fd1853);\n  z-index: -5;\n  transition: all 1s cubic-bezier(0, 0.4, 0, 1.01);\n}\n\n.star-3 {\n  position: absolute;\n  top: 40%;\n  left: 40%;\n  width: 5px;\n  height: auto;\n  filter: drop-shadow(0 0 0 #fd1853);\n  z-index: -5;\n  transition: all 1s cubic-bezier(0, 0.4, 0, 1.01);\n}\n\n.star-4 {\n  position: absolute;\n  top: 20%;\n  left: 40%;\n  width: 8px;\n  height: auto;\n  filter: drop-shadow(0 0 0 #fd1853);\n  z-index: -5;\n  transition: all .8s cubic-bezier(0, 0.4, 0, 1.01);\n}\n\n.star-5 {\n  position: absolute;\n  top: 25%;\n  left: 45%;\n  width: 15px;\n  height: auto;\n  filter: drop-shadow(0 0 0 #fd1853);\n  z-index: -5;\n  transition: all .6s cubic-bezier(0, 0.4, 0, 1.01);\n}\n\n.star-6 {\n  position: absolute;\n  top: 5%;\n  left: 50%;\n  width: 5px;\n  height: auto;\n  filter: drop-shadow(0 0 0 #fd1853);\n  z-index: -5;\n  transition: all .8s ease;\n}\n\nbutton:hover {\n  background: transparent;\n  color: #00e6f6;\n  box-shadow: 0 0 50px #fd1853;\n}\n\nbutton:hover .star-1 {\n  position: absolute;\n  top: -80%;\n  left: -30%;\n  width: 25px;\n  height: auto;\n  filter: drop-shadow(0 0 10px #fd1853);\n  z-index: 2;\n}\n\nbutton:hover .star-2 {\n  position: absolute;\n  top: -25%;\n  left: 10%;\n  width: 15px;\n  height: auto;\n  filter: drop-shadow(0 0 10px #fd1853);\n  z-index: 2;\n}\n\nbutton:hover .star', colors: '#fd1853,#00e6f6,#fec1958c', radii: '8px', shadows: '6px 0px 0px #00e6f6,0 0 0 #fec1958c,0 0 50px #fd1853', techniques: 'cubic-bezier,glow-shadow,gradient,filter-effect,svg-icon'),
const GalaxyComp(id: 'PozDevill_hard-cow-33', cat: 'Buttons', author: 'PozDevill', tags: 'button', html: '<button>Button</button>', css: '\n/* From Uiverse.io by PozDevill - Tags: button */\nbutton {\n  position: relative;\n  font-family: \'Heebo\', sans-serif;\n  padding: 12px 40px;\n  border: 0;\n  background: rgb(148, 1, 1);\n  color: #ffffff;\n  font-weight: 500;\n  font-size: 1em;\n  border-radius: 8px;\n  overflow: hidden;\n  cursor: pointer;\n  transition: 0.3s ease-in-out;\n}\n\nbutton:hover {\n  text-shadow: 0px 5px 10px rgba(0, 0, 0, 0.562);\n  transform: scale(1.01);\n  box-shadow: inset 0px 0px 10px rgba(255, 0, 0, 0.575);\n}\n\nbutton::after {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: -100px;\n  width: 50%;\n  height: 100%;\n  transform: rotate(80deg);\n  background: #ffffff77;\n  filter: blur(10px);\n  transition: 0.6s ease-in-out;\n}\n\nbutton:hover::after {\n  left: 100%;\n}\n', colors: '#ffffff77,#ffffff', radii: '8px', shadows: 'inset 0px 0px 10px rgba(255, 0, 0, 0.575)', techniques: 'glassmorphism,3d-transform,glow-shadow,text-shadow,pseudo-elements'),
const GalaxyComp(id: 'reyvaxreecded_fat-rabbit-45', cat: 'Buttons', author: 'reyvaxreecded', tags: 'animation,button,space', html: '<button>\n  <span>\n    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 128 128"><circle cx="64" cy="64" r="60" fill="#FCE5AC"></circle><path fill="#F1C688" d="M62.34 8.58c-.02 1.36-3.4 2.23-7.38 2.6c-3.98.37-7.3.11-7.65-1.2c-.35-1.31 2.69-3.26 7.03-3.68s8.01.92 8 2.28zm57.03 50.89c-.01-.4.01-.8.08-1.21c1.22-7.23 1.8-14-6.32-18.14c-.89-.46-1.87-.83-2.55-1.57c-1.25-1.35-1.14-3.41-1.46-5.22c-.97-5.54-7.24-9.51-12.66-8.01c-1.78.49-3.64 1.47-5.35.8c-1.38-.54-2.16-1.97-2.94-3.23c-2.21-3.58-5.6-6.76-9.77-7.34c-4.17-.59-8.91 2.3-9.17 6.5c-.11 1.83.2 3.99 1.6 5.18c5.88 5.01 9.52 1.32 12.25 3.91c3.17 3.01-3.41 3.82-2.32 11.47c.55 3.82 4.34 7.4 8.19 7.08c1.71-.15 4.31-.24 5.26 1.19c.75 1.12.56 2.19.56 4.03c0 4.54.5 8.11 4.92 9.14c.57.13 1.19.2 1.72-.03c1.17-.51 1.16-2.08 1.08-3.36c-.35-5.62-4.31-6.76-5.03-9.85c-.91-3.94 4.47-9.27 8.87-7.78c3.5 1.19.65 5.25 3.21 9.94c1.69 3.11 5.01 4.54 6.24 7.08c1.23 2.54.09 4.3.69 5.91c.93 2.52 2.41 2.56 3.24 1.67c.91-.97.61-2.96.39-4.12c-.24-1.35-.69-2.67-.73-4.04zm-95.13 42.57c.11-.16.99-.39 2.01.57c1.02.95 4.03 3.79 5.23 4.88c1.2 1.09.03 2.01-.97 1.83c-4.8-.84-7.42-5.61-6.27-7.28zm17.8 12.38c.05-.19.79-.71 2.08-.19s5.12 2.11 6.63 2.7c1.51.59.74 1.86-.25 2.06c-4.8.92-8.94-2.6-8.46-4.57zm6.26-3.58c.6.47 1.21 1.21.93 1.91c-.26.64-1.08.81-1.77.83c-2.28.07-4.56-.51-6.55-1.6c-1.4-.77-5.07-3.14-4.55-5.13c.74-2.82 10.4 2.8 11.94 3.99zM97.71 106c-.22-.13-.6-1.22.58-2.57c1.18-1.35 4.68-5.33 6.01-6.92s2.66-.18 2.52 1.09c-.7 6.11-6.79 9.73-9.11 8.4zm11.3-11', css: '\n/* From Uiverse.io by reyvaxreecded  - Tags: animation, button, space */\nbutton {\n  all: unset;\n  position: relative;\n  width: 10em;\n  height: 10em;\n  border-radius: 100%;\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-pack: center;\n  -ms-flex-pack: center;\n  justify-content: center;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n  overflow: visible;\n}\n\nbutton>span>svg {\n  width: 8.5em;\n  height: 8.5em;\n}\n\nbutton>span {\n  position: relative;\n  -webkit-box-sizing: border-box;\n  box-sizing: border-box;\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-pack: center;\n  -ms-flex-pack: center;\n  justify-content: center;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n}\n\nbutton:before {\n  content: \'\';\n  display: block;\n  position: absolute;\n  top: 0;\n  left: 0;\n  z-index: -1;\n  background: radial-gradient(circle, rgba(255,255,255,0.52) 0%, rgba(255,255,255,0) 100%);\n  width: 100%;\n  height: 100%;\n  border-radius: 100%;\n  -webkit-animation: pulse 1s ease-in-out infinite;\n  animation: pulse 1s ease-in-out infinite;\n  -webkit-transition: all 0.15s ease-in;\n  transition: all 0.15s ease-in;\n}\n\nbutton>span {\n  overflow: hidden;\n  -webkit-clip-path: circle(50% at 50% 50%);\n  clip-path: circle(50% at 50% 50%);\n  -webkit-transition: -webkit-transform 0.15s ease-in;\n  transition: -webkit-transform 0.15s ease-in;\n  transition: transform 0.15s ease-in;\n  transition: transform 0.15s ease-in, -webkit-transform 0.15s ease-in;\n}\n\nbutton > span:after {\n  content: \'\';\n  -webkit-clip-path: circle(50% at 50% 50%);\n  clip-path: circle(50% at 50% 50%);\n  width: 94.5%;\n  height: 94.5%;\n  position: absolute;\n  top: 0.27em;\n  z-index: 2;\n  background-color: #00000000;\n  border-radius: 100%;\n  background: radial-gradient(circle, rgba(254,123,0,0.52) 0%, rgba(191,0,0,0.9612219887955182) 100%);\n  -webkit-transition: all 0.25s ease-in;\n  transition: all 0.25s ease-in;\n  background', colors: '#00000000', radii: '100%', shadows: '', techniques: '3d-transform,gradient,animation,clip-path,svg-icon'),
const GalaxyComp(id: 'roroland_brave-moth-43', cat: 'Buttons', author: 'roroland', tags: 'flat design,button,flip,animated,two side', html: '<div class="flip-button">\n  <button class="button button-front">\n    <span class="text-front">Label one</span>\n    <span class="text-back">Back can be longer</span>\n  </button>\n</div>', css: '\n/* From Uiverse.io by roroland - Tags: flat design, button, flip, animated, two side */\n.flip-button {\n  --col1: #4CAF50;\n  --col2: #4f16ac;\n  --col3: #d8d1e4;\n  position: relative;\n  min-width: 10rem;\n  min-height: 3rem;\n  perspective: 500px;\n}\n\n.flip-button .button {\n  appearance: none;\n  position: absolute;\n  inset: 0;\n  height: 100%;\n  border-radius: 30px;\n  font-size: .75em;\n  font-weight: bold;\n  color: #fff;\n  text-transform: uppercase;\n  background-color: var(--col1);\n  border: none;\n  box-shadow: 0px 4px 6px rgba(0, 0, 0, 0.1);\n  transition: all 1s ease-out .5s;\n  transform-style: preserve-3d;\n  width: 100%;\n}\n\n.flip-button:hover .button {\n  background-color: var(--col2);\n  cursor: pointer;\n  transform: rotateY(180deg) scale(1.5);\n  transition: all .3s ease-out;\n}\n\n.flip-button:hover .button:active {\n  background-color: rgba(81, 23, 173, 0.75);\n  transform: rotateY(180deg) scale(1.45);\n  outline: 10px solid var(--col3);\n  transition: all .1s ease-out;\n}\n\n.flip-button .button::after {\n  content: \'\';\n  box-shadow: 0px 0px 60px 5px rgba(0, 0, 0, 0.25);\n  display: block;\n  border-radius: 30px;\n  height: 100%;\n  width: 100%;\n  transition: all .3s ease-out .95s;\n}\n\n.flip-button:hover .button::after {\n  box-shadow: 0px 0px 1px 10px rgba(160, 29, 149, 0.15);\n  transition: all .3s ease-out;\n}\n\n.flip-button .text-front,\n.flip-button .text-back {\n  display: block;\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  padding: 0 1.5em;\n  transform: translate(-50%, -50%);\n  backface-visibility: hidden;\n  width: 100%;\n}\n\n.flip-button .text-back {\n  transform: translate(-50%, -50%) rotateY(180deg);\n}\n\n\n', colors: '#4caf50,#4f16ac,#d8d1e4,#fff', radii: '30px', shadows: '0px 4px 6px rgba(0, 0, 0, 0.1),0px 0px 60px 5px rgba(0, 0, 0, 0.25),0px 0px 1px 10px rgba(160, 29, 149, 0.15)', techniques: '3d-transform,glow-shadow,perspective,typography-transform,pseudo-elements'),
