solid var(--col1);\n  transform: scale(1.25) rotate(0deg);\n  animation: blink 1.5s ease-out 1s infinite alternate;\n}\n\nbutton:hover > span {\n  filter: contrast(150%);\n}\n\n@keyframes blink {\n  0% {\n    transform: scale(1, 1) skewX(0deg);\n    opac', colors: '', radii: '50%,6px,50% 0%', shadows: 'inset -2px 1px 1px var(--col2),\n    inset 2px 1px 1px var(--col2),inset -2px 1px 1px var(--col2),\n    inset 2px 1px 1px var(--col2),\n    inset 0px -2px 20px var(--col4),\n    0px 20px 30p,inset 1px 1px var(--col2)', techniques: '3d-transform,text-shadow,animation,filter-effect,pseudo-elements'),
const GalaxyComp(id: 'SelfMadeSystem_lucky-cougar-76', cat: 'Buttons', author: 'SelfMadeSystem', tags: 'simple,neumorphism,skeuomorphism,icon,animation,gradient,button', html: '<button class="border">\n  <div class="outer">\n    <div class="inner">\n      <svg\n        xmlns="http://www.w3.org/2000/svg"\n        fill="none"\n        viewBox="0 0 24 24"\n        height="1.125rem"\n        width="1.125rem"\n      >\n        <path\n          fill="#000000"\n          d="M14.2199 21.63C13.0399 21.63 11.3699 20.8 10.0499 16.83L9.32988 14.67L7.16988 13.95C3.20988 12.63 2.37988 10.96 2.37988 9.78001C2.37988 8.61001 3.20988 6.93001 7.16988 5.60001L15.6599 2.77001C17.7799 2.06001 19.5499 2.27001 20.6399 3.35001C21.7299 4.43001 21.9399 6.21001 21.2299 8.33001L18.3999 16.82C17.0699 20.8 15.3999 21.63 14.2199 21.63ZM7.63988 7.03001C4.85988 7.96001 3.86988 9.06001 3.86988 9.78001C3.86988 10.5 4.85988 11.6 7.63988 12.52L10.1599 13.36C10.3799 13.43 10.5599 13.61 10.6299 13.83L11.4699 16.35C12.3899 19.13 13.4999 20.12 14.2199 20.12C14.9399 20.12 16.0399 19.13 16.9699 16.35L19.7999 7.86001C20.3099 6.32001 20.2199 5.06001 19.5699 4.41001C18.9199 3.76001 17.6599 3.68001 16.1299 4.19001L7.63988 7.03001Z"\n        ></path>\n        <path\n          fill="#000000"\n          d="M10.11 14.4C9.92005 14.4 9.73005 14.33 9.58005 14.18C9.29005 13.89 9.29005 13.41 9.58005 13.12L13.16 9.53C13.45 9.24 13.93 9.24 14.22 9.53C14.51 9.82 14.51 10.3 14.22 10.59L10.64 14.18C10.5 14.33 10.3 14.4 10.11 14.4Z"\n        ></path>\n      </svg>\n      Send Message\n    </div>\n  </div>\n</button>', css: '\n/* From Uiverse.io by SelfMadeSystem  - Tags: simple, neumorphism, skeuomorphism, icon, animation, gradient, button */\n:focus {\n  outline: none;\n}\n::-moz-focus-inner {\n  border: 0;\n}\n\n.border {\n  position: relative;\n  cursor: pointer;\n  padding: 3px;\n  border-radius: calc(6pt + 3px);\n  appearance: none;\n  font-weight: 600;\n  background: linear-gradient(#dfe1e0, #7f8180);\n  border: 1pt solid #e9ebea;\n  border-top-width: 0;\n  box-shadow: 0px 5px 15px 0px #0004;\n  transition: all 0.4s;\n}\n\n.border::before {\n  content: "";\n  position: absolute;\n  bottom: 0px;\n  left: 0;\n  right: 0;\n  height: 50%;\n  transition: inherit;\n}\n\n.border:hover {\n  transform: translateY(-5px);\n  box-shadow: 0px 10px 15px 0px #0004;\n}\n\n.border:hover:not(:active)::before {\n  bottom: -6px;\n}\n\n.border:active {\n  transform: translateY(0px);\n  box-shadow: 0px 5px 15px 0px #0000;\n  transition: all 0.3s;\n}\n\n.outer {\n  padding: 4pt;\n  background: linear-gradient(#fdfffe, #eceeed, #fdfffe);\n  border-radius: 6pt;\n}\n\n.inner {\n  background: linear-gradient(#eef0ef, #fafcfb, #eef0ef);\n  padding: 8pt;\n  border-radius: 9999px;\n  display: flex;\n  align-items: center;\n  gap: 4pt;\n  text-shadow: 0px 1px 1px #0004;\n}\n\n.inner svg {\n  filter: drop-shadow(0px 1px 0px #0007);\n}\n\n:is(.inner, .outer) {\n  background-size: 100% 200%;\n  transition: background-position-y 0.5s;\n}\n\n:active :is(.inner, .outer) {\n  background-position-y: 100%;\n}\n\n', colors: '#e9ebea,#fdfffe,#eceeed,#0007,#eef0ef,#dfe1e0,#0004,#0000,#fafcfb,#7f8180', radii: '6pt,calc(6pt + 3px),9999px', shadows: '0px 5px 15px 0px #0004,0px 10px 15px 0px #0004,0px 5px 15px 0px #0000', techniques: 'text-shadow,gradient,filter-effect,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'SevenAJJY_wet-owl-54', cat: 'Buttons', author: 'SevenAJJY', tags: 'button,hover,code,click', html: '<button class="btn">\n  Click Me\n</button>', css: '\n/* From Uiverse.io by SevenAJJY - Tags: button, hover, code, click */\n.btn {\n  --main-color: #ffce06;\n  --main-alt-color: #fff696;\n  height: 44px;\n  font-size: 16px!important;\n  line-height: 44px;\n  font-weight: 700;\n  color: #3f5cc3;\n  text-shadow: 0 1px 1px #fff8c4;\n  text-transform: uppercase;\n  text-align: center;\n  -webkit-box-shadow: rgb(99 121 133 / 14%) 0 0 0 4px;\n  box-shadow: rgb(99 121 133 / 14%) 0 0 0 4px;\n  border-radius: 4px;\n  border: none;\n  border-top: 1px solid var(--main-alt-color);\n  border-bottom: 1px solid var(--main-color);\n  background-color: var(--main-color);\n  outline: 0;\n  cursor: pointer;\n  margin: 0 0 5px 4px;\n  padding: 0 20px;\n  transition: transform .3s ease;\n}\n\n.btn:hover {\n  border-top-color: var(--main-alt-color);\n  border-bottom-color: var(--main-color);\n  background: -webkit-gradient(linear, left top, left bottom, from(#fae811), to(#f5d604));\n}\n\n.btn:active {\n  transform: scale(0.7);\n}\n\n', colors: '#f5d604,#fae811,#fff8c4,#fff696,#3f5cc3,#ffce06', radii: '4px', shadows: 'rgb(99 121 133 / 14%) 0 0 0 4px,rgb(99 121 133 / 14%) 0 0 0 4px', techniques: '3d-transform,glow-shadow,text-shadow,gradient,typography-transform'),
const GalaxyComp(id: 'ShadowShahriar_nervous-goat-3', cat: 'Buttons', author: 'ShadowShahriar', tags: 'gradient,button', html: '<button>Hover me!</button>', css: '\n/* From Uiverse.io by ShadowShahriar - Tags: gradient, button */\nbutton {\n --border-radius: 15px;\n --border-width: 4px;\n appearance: none;\n position: relative;\n padding: 1em 2em;\n border: 0;\n background-color: #212121;\n font-family: "Roboto", Arial, "Segoe UI", sans-serif;\n font-size: 18px;\n font-weight: 500;\n color: #fff;\n z-index: 2;\n}\n\nbutton::after {\n --m-i: linear-gradient(#000, #000);\n --m-o: content-box, padding-box;\n content: "";\n position: absolute;\n left: 0;\n top: 0;\n width: 100%;\n height: 100%;\n padding: var(--border-width);\n border-radius: var(--border-radius);\n background-image: conic-gradient(\n		#488cfb,\n		#29dbbc,\n		#ddf505,\n		#ff9f0e,\n		#e440bb,\n		#655adc,\n		#488cfb\n	);\n -webkit-mask-image: var(--m-i), var(--m-i);\n mask-image: var(--m-i), var(--m-i);\n -webkit-mask-origin: var(--m-o);\n mask-origin: var(--m-o);\n -webkit-mask-clip: var(--m-o);\n mask-composite: exclude;\n -webkit-mask-composite: destination-out;\n filter: hue-rotate(0);\n animation: rotate-hue linear 500ms infinite;\n animation-play-state: paused;\n}\n\nbutton:hover::after {\n animation-play-state: running;\n}\n\n@keyframes rotate-hue {\n to {\n  filter: hue-rotate(1turn);\n }\n}\n\nbutton,\nbutton::after {\n box-sizing: border-box;\n}\n\nbutton:active {\n --border-width: 5px;\n}\n', colors: '#212121,#655adc,#ddf505,#488cfb,#000,#29dbbc,#e440bb,#ff9f0e,#fff', radii: '15px,var(--border-radius)', shadows: '', techniques: 'gradient,animation,filter-effect,css-mask,pseudo-elements'),
const GalaxyComp(id: 'SharpTH_swift-bullfrog-75', cat: 'Buttons', author: 'SharpTH', tags: 'icon,social,button,share', html: '<button class="btn-cssbuttons">\n<span>Button</span><span>\n  <svg height="18" width="18" xmlns="http://www.w3.org/2000/svg" version="1.1" viewBox="0 0 1024 1024" class="icon">\n    <path fill="#ffffff" d="M767.99994 585.142857q75.995429 0 129.462857 53.394286t53.394286 129.462857-53.394286 129.462857-129.462857 53.394286-129.462857-53.394286-53.394286-129.462857q0-6.875429 1.170286-19.456l-205.677714-102.838857q-52.589714 49.152-124.562286 49.152-75.995429 0-129.462857-53.394286t-53.394286-129.462857 53.394286-129.462857 129.462857-53.394286q71.972571 0 124.562286 49.152l205.677714-102.838857q-1.170286-12.580571-1.170286-19.456 0-75.995429 53.394286-129.462857t129.462857-53.394286 129.462857 53.394286 53.394286 129.462857-53.394286 129.462857-129.462857 53.394286q-71.972571 0-124.562286-49.152l-205.677714 102.838857q1.170286 12.580571 1.170286 19.456t-1.170286 19.456l205.677714 102.838857q52.589714-49.152 124.562286-49.152z"></path>\n  </svg>\n</span>\n<ul>\n<li>\n  <a href="https://twitter.com/SumethWrrn"><svg height="18" width="18" xmlns="http://www.w3.org/2000/svg" version="1.1" viewBox="0 0 1024 1024" class="icon">\n  <path fill="white" d="M962.267429 233.179429q-38.253714 56.027429-92.598857 95.451429 0.585143 7.972571 0.585143 23.990857 0 74.313143-21.723429 148.260571t-65.974857 141.970286-105.398857 120.32-147.456 83.456-184.539429 31.158857q-154.843429 0-283.428571-82.870857 19.968 2.267429 44.544 2.267429 128.585143 0 229.156571-78.848-59.977143-1.170286-107.446857-36.864t-', css: '\n/* From Uiverse.io by SharpTH - Tags: icon, social, button, share */\n.btn-cssbuttons {\n --btn-color: #275efe;\n position: relative;\n padding: 16px 32px;\n font-family: Roboto, sans-serif;\n font-weight: 500;\n font-size: 16px;\n line-height: 1;\n color: white;\n background: none;\n border: none;\n outline: none;\n overflow: hidden;\n cursor: pointer;\n filter: drop-shadow(0 2px 8px rgba(39, 94, 254, 0.32));\n transition: 0.3s cubic-bezier(0.215, 0.61, 0.355, 1);\n}\n\n.btn-cssbuttons::before {\n position: absolute;\n content: "";\n top: 0;\n left: 0;\n z-index: -1;\n width: 100%;\n height: 100%;\n background: var(--btn-color);\n border-radius: 24px;\n transition: 0.3s cubic-bezier(0.215, 0.61, 0.355, 1);\n}\n\n.btn-cssbuttons span,\n.btn-cssbuttons span span {\n display: inline-flex;\n vertical-align: middle;\n transition: 0.3s cubic-bezier(0.215, 0.61, 0.355, 1);\n}\n\n.btn-cssbuttons span {\n transition-delay: 0.05s;\n}\n\n.btn-cssbuttons span:first-child {\n padding-right: 7px;\n}\n\n.btn-cssbuttons span span {\n margin-left: 8px;\n transition-delay: 0.1s;\n}\n\n.btn-cssbuttons ul {\n position: absolute;\n top: 50%;\n left: 0;\n right: 0;\n display: flex;\n margin: 0;\n padding: 0;\n list-style-type: none;\n transform: translateY(-50%);\n}\n\n.btn-cssbuttons ul li {\n flex: 1;\n}\n\n.btn-cssbuttons ul li a {\n display: inline-flex;\n vertical-align: middle;\n transform: translateY(55px);\n transition: 0.3s cubic-bezier(0.215, 0.61, 0.355, 1);\n}\n\n.btn-cssbuttons ul li a:hover {\n opacity: 0.5;\n}\n\n.btn-cssbuttons:hover::before {\n transform: scale(1.2);\n}\n\n.btn-cssbuttons:hover span,\n.btn-cssbuttons:hover span span {\n transform: translateY(-55px);\n}\n\n.btn-cssbuttons:hover ul li a {\n transform: translateY(0);\n}\n\n.btn-cssbuttons:hover ul li:nth-child(1) a {\n transition-delay: 0.15s;\n}\n\n.btn-cssbuttons:hover ul li:nth-child(2) a {\n transition-delay: 0.2s;\n}\n\n.btn-cssbuttons:hover ul li:nth-child(3) a {\n transition-delay: 0.25s;\n}\n', colors: '#275efe', radii: '24px', shadows: '', techniques: 'cubic-bezier,3d-transform,filter-effect,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'Smit-Prajapati_chatty-pug-36', cat: 'Buttons', author: 'Smit-Prajapati', tags: 'gradient,button,hover effect,glass button', html: '<button class="button">\n  <div class="bloom-container">\n    <div class="button-container-main">\n      <div class="button-inner">\n        <div class="back"></div>\n        <div class="front">\n          <svg viewBox="0 0 512 512" class="svg" xmlns="http://www.w3.org/2000/svg"><path d="M459.37 151.716c.325 4.548.325 9.097.325 13.645 0 138.72-105.583 298.558-298.558 298.558-59.452 0-114.68-17.219-161.137-47.106 8.447.974 16.568 1.299 25.34 1.299 49.055 0 94.213-16.568 130.274-44.832-46.132-.975-84.792-31.188-98.112-72.772 6.498.974 12.995 1.624 19.818 1.624 9.421 0 18.843-1.3 27.614-3.573-48.081-9.747-84.143-51.98-84.143-102.985v-1.299c13.969 7.797 30.214 12.67 47.431 13.319-28.264-18.843-46.781-51.005-46.781-87.391 0-19.492 5.197-37.36 14.294-52.954 51.655 63.675 129.3 105.258 216.365 109.807-1.624-7.797-2.599-15.918-2.599-24.04 0-57.828 46.782-104.934 104.934-104.934 30.213 0 57.502 12.67 76.67 33.137 23.715-4.548 46.456-13.32 66.599-25.34-7.798 24.366-24.366 44.833-46.132 57.827 21.117-2.273 41.584-8.122 60.426-16.243-14.292 20.791-32.161 39.308-52.628 54.253z"></path></svg>\n        </div>\n      </div>\n      <div class="button-glass">\n        <div class="back"></div>\n        <div class="front"></div>\n      </div>\n    </div>\n    <div class="bloom bloom1"></div>\n    <div class="bloom bloom2">\n  </div>\n  </div></button>', css: '\n/* From Uiverse.io by Smit-Prajapati - Tags: gradient, button, hover effect, glass button */\n.button {\n  background: none;\n  border: none;\n}\n\n.button .bloom-container {\n  position: relative;\n  transition: all 0.2s ease-in-out;\n  border: none;\n  background: none;\n}\n\n.button .bloom-container .button-container-main {\n  width: 110px;\n  aspect-ratio: 1;\n  border-radius: 50%;\n  overflow: hidden;\n  position: relative;\n  display: grid;\n  place-content: center;\n  border-right: 5px solid white;\n  border-left: 5px solid rgba(128, 128, 128, 0.147);\n  transform: rotate(-45deg);\n  transition: all 0.5s ease-in-out;\n}\n\n.button .bloom-container .button-container-main .button-inner {\n  height: 60px;\n  aspect-ratio: 1;\n  border-radius: 50%;\n  position: relative;\n  box-shadow: rgba(100, 100, 111, 0.5) -10px 5px 10px 0px;\n  transition: all 0.5s ease-in-out;\n}\n\n.button .bloom-container .button-container-main .button-inner .back {\n  position: absolute;\n  inset: 0;\n  border-radius: 50%;\n  background: linear-gradient(60deg, rgb(1, 85, 103) 0%, rgb(147, 245, 255) 100%);\n}\n\n.button .bloom-container .button-container-main .button-inner .front {\n  position: absolute;\n  inset: 5px;\n  border-radius: 50%;\n  background: linear-gradient(60deg, rgb(0, 103, 140) 0%, rgb(58, 209, 233) 100%);\n  display: grid;\n  place-content: center;\n}\n\n.button .bloom-container .button-container-main .button-inner .front .svg {\n  fill: #ffffff;\n  opacity: 0.5;\n  width: 30px;\n  aspect-ratio: 1;\n  transform: rotate(45deg);\n  transition: all 0.2s ease-in;\n}\n\n.button .bloom-container .button-container-main .button-glass {\n  position: absolute;\n  inset: 0;\n  background: linear-gradient(90deg, rgba(255, 255, 255, 0) 0%, rgba(255, 255, 255, 0.888) 100%);\n  transform: translate(0%, -50%) rotate(0deg);\n  transform-origin: bottom center;\n  transition: all 0.5s ease-in-out;\n}\n\n.button .bloom-container .bloom {\n  height: 1px;\n  width: 1px;\n  position: absolute;\n  background: white;\n}\n\n.button .bloom-container .bloom1 {\n  top: 10px', colors: '#ffffff', radii: '50%', shadows: 'rgba(100, 100, 111, 0.5) -10px 5px 10px 0px,rgb(255, 255, 255) 0px 0px 10px 10px, rgb(255, 255, 255) 0px 0px 20px 20px,rgba(255, 255, 255, 0.5) 0px 0px 10px 10px, rgba(255, 255, 255, 0.5) 0px 0px 30px 20px', techniques: '3d-transform,glow-shadow,gradient,filter-effect,svg-icon'),
const GalaxyComp(id: 'TaniaDou_witty-rabbit-59', cat: 'Buttons', author: 'TaniaDou', tags: 'gradient,button,modern,neon', html: '<div class="button">\n  Button<span class="button-border"></span>\n</div>', css: '\n/* From Uiverse.io by TaniaDou - Tags: gradient, button, modern, neon */\n.button {\n  padding: 1rem 2rem;\n  border-radius: .5rem;\n  border: none;\n  font-size: 1rem;\n  font-weight: 400;\n  color: #f4f0ff;\n  text-align: center;\n  backdrop-filter: blur(10px);\n  cursor: pointer;\n}\n\n.button::before {\n  content: "";\n  display: block;\n  position: absolute;\n  left: 0;\n  top: 0;\n  height: 100%;\n  width: 100%;\n  border-radius: .5rem;\n  background: linear-gradient(180deg, rgba(8, 77, 126, 0) 0%, rgba(8, 77, 126, 0.42) 100%),rgba(47,255,255,.24);\n  box-shadow: inset 0 0 12px rgba(151,200,255,.44);\n  z-index: -1;\n}\n\n.button::after {\n  content: "";\n  display: block;\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  background: linear-gradient(180deg, rgba(8, 77, 126, 0) 0%, rgba(8, 77, 126, 0.42) 100%),rgba(47,255,255,.24);\n  box-shadow: inset 0 0 12px rgba(151,200,255,.44);\n  border-radius: .5rem;\n  opacity: 0;\n  z-index: -1;\n  transition: all .3s ease-in;\n}\n\n.button:hover::after {\n  opacity: 1;\n}\n\n.button-border {\n  position: absolute;\n  top: 0;\n  left: 0;\n  height: 100%;\n  width: 100%;\n  border-radius: .5rem;\n  z-index: -1;\n}\n\n.button-border::before {\n  content: "";\n  position: absolute;\n  border-radius: .5rem;\n  padding: 1px;\n  inset: 0;\n  background: linear-gradient(180deg, rgba(184, 238, 255, 0.24) 0%, rgba(184, 238, 255, 0) 100%),linear-gradient(0deg, rgba(184, 238, 255, 0.32), rgba(184, 238, 255, 0.32));\n  -webkit-mask: linear-gradient(#fff 0 0) content-box,linear-gradient(#fff 0 0);\n  -webkit-mask-composite: xor;\n  pointer-events: none;\n}\n', colors: '#f4f0ff,#fff', radii: '.5rem', shadows: 'inset 0 0 12px rgba(151,200,255,.44),inset 0 0 12px rgba(151,200,255,.44)', techniques: 'glassmorphism,glow-shadow,gradient,css-mask,pseudo-elements'),
const GalaxyComp(id: 'tarantino421_nasty-wolverine-40', cat: 'Buttons', author: 'tarantino421', tags: 'button,space,hover button', html: '<div class="box">\n  <button class="button">SPACE</button>\n  <div class="space">\n    <span style="--i: 31" class="star"></span>\n    <span style="--i: 12" class="star"></span>\n    <span style="--i: 57" class="star"></span>\n    <span style="--i: 93" class="star"></span>\n    <span style="--i: 23" class="star"></span>\n    <span style="--i: 70" class="star"></span>\n    <span style="--i: 6" class="star"></span>\n  </div>\n</div>', css: '\n/* From Uiverse.io by tarantino421 - Tags: button, space, hover button */\n.box {\n  --clr-shadow__border: #d9a1ff;\n  --clr-text: #F6F4EB;\n  --clr-space: #120e1e;\n  --clr-space-gr: #271950;\n  --clr-star: #E9F8F9;\n  --size: 3rem;\n  position: relative;\n  outline: 1px solid var(--clr-shadow__border);\n}\n\n.button {\n  font-weight: 600;\n  font-size: 1.5rem;\n  letter-spacing: 0.2rem;\n  background: transparent;\n  padding: calc(var(--size) / 3) var(--size);\n  border: none;\n  cursor: pointer;\n  color: var(--clr-text);\n  text-shadow: 2px 0px var(--clr-shadow__border), 0px 2px var(--clr-shadow__border),\n  -2px 0px var(--clr-shadow__border), 0px -2px var(--clr-shadow__border);\n}\n\n.space {\n  width: 100%;\n  height: 100%;\n  bottom: 0%;\n  gap: 1.5rem;\n  transition: 0.5s ease-in-out;\n  z-index: -1;\n  opacity: 0;\n  overflow: hidden;\n  position: absolute;\n  display: flex;\n  background: linear-gradient( 160deg, var(--clr-space), var(--clr-space-gr));\n}\n\n.box:hover .space {\n  opacity: 1;\n}\n\n.star {\n  height: 4rem;\n  width: 0.3rem;\n  transition: 0.5s;\n  border-radius: 50px;\n  clip-path: polygon(50% 0%, 100% 100%, 0% 100%);\n  position: relative;\n  background-color: var(--clr-star);\n  animation: space-animation calc(0.1s * var(--i)) linear infinite;\n}\n\n@keyframes space-animation {\n  0% {\n    transform: rotate(-30deg) translateY(calc(-52% * var(--i)));\n  }\n\n  100% {\n    transform: rotate(-30deg) translateY(calc(52% * var(--i)));\n  }\n}\n\n\n\n\n\n\n\n\n', colors: '#d9a1ff,#e9f8f9,#f6f4eb,#271950,#120e1e', radii: '50px', shadows: '', techniques: '3d-transform,text-shadow,gradient,animation,clip-path'),
const GalaxyComp(id: 'VashonG_mean-mayfly-77', cat: 'Buttons', author: 'VashonG', tags: 'button,ios,uiverse,multicolor', html: '<button class="uiverse">\n    <div class="wrapper">\n        <span>UIVERSE</span>\n        <div class="circle circle-12"></div>\n        <div class="circle circle-11"></div>\n        <div class="circle circle-10"></div>\n        <div class="circle circle-9"></div>\n        <div class="circle circle-8"></div>\n        <div class="circle circle-7"></div>\n        <div class="circle circle-6"></div>\n        <div class="circle circle-5"></div>\n        <div class="circle circle-4"></div>\n        <div class="circle circle-3"></div>\n        <div class="circle circle-2"></div>\n        <div class="circle circle-1"></div>\n    </div>\n</button>', css: '\n/* From Uiverse.io by VashonG - Tags: button, ios, uiverse, multicolor */\n.uiverse {\n  --duration: 7s;\n  --easing: linear;\n  --c-color-1: rgba(255, 163, 26, .7);\n  --c-color-2: #1a23ff;\n  --c-color-3: #e21bda;\n  --c-color-4: rgba(255, 232, 26, .7);\n  --c-shadow: rgba(255, 223, 87, .5);\n  --c-shadow-inset-top: rgba(255, 223, 52, .9);\n  --c-shadow-inset-bottom: rgba(255, 250, 215, .8);\n  --c-radial-inner: #ffd215;\n  --c-radial-outer: #fff172;\n  --c-color: #fff;\n  -webkit-tap-highlight-color: transparent;\n  -webkit-appearance: none;\n  outline: none;\n  position: relative;\n  cursor: pointer;\n  border: none;\n  display: table;\n  border-radius: 24px;\n  padding: 0;\n  margin: 0;\n  text-align: center;\n  font-weight: 600;\n  font-size: 16px;\n  letter-spacing: 0.02em;\n  line-height: 1.5;\n  color: var(--c-color);\n  background: radial-gradient(circle, var(--c-radial-inner), var(--c-radial-outer) 80%);\n  box-shadow: 0 0 14px var(--c-shadow);\n}\n\n.uiverse:before {\n  content: \'\';\n  pointer-events: none;\n  position: absolute;\n  z-index: 3;\n  left: 0;\n  top: 0;\n  right: 0;\n  bottom: 0;\n  border-radius: 24px;\n  box-shadow: inset 0 3px 12px var(--c-shadow-inset-top), inset 0 -3px 4px var(--c-shadow-inset-bottom);\n}\n\n.uiverse .wrapper {\n  -webkit-mask-image: -webkit-radial-gradient(white, black);\n  overflow: hidden;\n  border-radius: 24px;\n  min-width: 132px;\n  padding: 12px 0;\n}\n\n.uiverse .wrapper span {\n  display: inline-block;\n  position: relative;\n  z-index: 1;\n}\n\n.uiverse .wrapper .circle {\n  position: absolute;\n  left: 0;\n  top: 0;\n  width: 40px;\n  height: 40px;\n  border-radius: 50%;\n  filter: blur(var(--blur, 8px));\n  background: var(--background, transparent);\n  transform: translate(var(--x, 0), var(--y, 0)) translateZ(0);\n  animation: var(--animation, none) var(--duration) var(--easing) infinite;\n}\n\n.uiverse .wrapper .circle.circle-1, .uiverse .wrapper .circle.circle-9, .uiverse .wrapper .circle.circle-10 {\n  --background: var(--c-color-4);\n}\n\n.uiverse .wrapper .circle.circle-3, .u', colors: '#e21bda,#ffd215,#1a23ff,#fff172,#fff', radii: '24px,50%', shadows: '0 0 14px var(--c-shadow),inset 0 3px 12px var(--c-shadow-inset-top), inset 0 -3px 4px var(--c-shadow-inset-bottom)', techniques: 'glassmorphism,glow-shadow,gradient,animation,css-mask'),
const GalaxyComp(id: 'vinodjangid07_neat-seahorse-99', cat: 'Buttons', author: 'vinodjangid07', tags: 'gradient,button,submit,hover effect', html: '<button class="submitBtn">\n  Submit\n  <svg fill="white" viewBox="0 0 448 512" height="1em" class="arrow"><path d="M438.6 278.6c12.5-12.5 12.5-32.8 0-45.3l-160-160c-12.5-12.5-32.8-12.5-45.3 0s-12.5 32.8 0 45.3L338.8 224 32 224c-17.7 0-32 14.3-32 32s14.3 32 32 32l306.7 0L233.4 393.4c-12.5 12.5-12.5 32.8 0 45.3s32.8 12.5 45.3 0l160-160z"></path></svg>\n</button>', css: '\n/* From Uiverse.io by vinodjangid07 - Tags: gradient, button, submit, hover effect */\n.submitBtn {\n  width: 120px;\n  height: 40px;\n  border-radius: 30px;\n  border: none;\n  box-shadow: 2px 2px 10px rgba(0, 0, 0, 0.13);\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  gap: 8px;\n  font-weight: 600;\n  cursor: pointer;\n  color: white;\n  background: linear-gradient(to left,rgb(230, 35, 0),rgb(255, 174, 0));\n  letter-spacing: 0.7px;\n}\n\n.submitBtn:hover .arrow {\n  animation: slide-in-left 0.6s cubic-bezier(0.250, 0.460, 0.450, 0.940) both;\n}\n\n@keyframes slide-in-left {\n  0% {\n    transform: translateX(-10px);\n    opacity: 0;\n  }\n\n  100% {\n    transform: translateX(0px);\n    opacity: 1;\n  }\n}\n\n.submitBtn:active {\n  transform: scale(0.97);\n}\n', colors: '', radii: '30px', shadows: '2px 2px 10px rgba(0, 0, 0, 0.13)', techniques: 'cubic-bezier,3d-transform,gradient,animation,svg-icon'),
