1.2px;\n  padding-left: 0.8rem;\n  padding-right: 0.6rem;\n  font-weight: 600;\n}\n\nbutton:hover {\n  background: linear-gradient(-45deg, #1b2164, #6a33a8, #1b2164, #2ba6f5);\n  background-size: 400% 400%;\n  -webkit-transform: scale(1.01);\n  -ms-transform: scale(1.01);\n  transform: scale(1.01);\n  -webkit-animation: scaling-and-gradient 10s ease infinite;\n  animation: scaling-and-gradient 10s ease infinite;\n}\n\nbutton svg {\n  text-shadow: 0px 7px rgba(81,67,21,0.8), \n	  -3px 0px 7px rgba(81,67,21,0.8), \n	  0px 4px 7px rgba(81,67,21,0.8);\n  -webkit-animation: slide-in 1.6s ease-out both;\n  animation: slide-in 1.6s ease-out both;\n}\n\nbutton:active svg {\n  -webkit-animation: slide-out 0.4s ease-in forwards;\n  animation: slide-out 0.4s ease-in forwards;\n}\n\n@-webkit-keyframes slide-out {\n  0% {\n    -webkit-transform: translateY(0) translateX(0) rotate(-35);\n    transform: translateY(0) translateX(0) rotate(-35);\n    opacity: 1;\n  }\n\n  100% {\n    -webkit-transform: translateY(-300px) translateX(-300px);\n    transform: translateY(-300px) translateX(-300px);\n    opacity: 0;\n  }\n}\n\n@keyframes slide-out {\n  0% {\n    -webkit-transform: translateY(0) translateX(0) rotate(-35);\n    transform: translateY(0) translateX(0) rotate(-35);\n    opacity: 1;\n  }\n\n  100% {\n    -webkit-transform: translateY(-300px) translateX(-300px);\n    transform: translateY(-300px) translateX(-300px);\n    opacity: 0;\n  }\n}\n\n@-webkit-keyframes slide-in {\n  0% {\n    -webkit-transform: translateY(300px) translateX(300px);\n    transform: translateY(300px) translateX(300px);\n    opacity: 0;\n  }\n\n  100% {\n    -webkit-transform: translateY(0) translateX(0) rotate(-35);\n    t', colors: '#2ba6f5,#1b2164,#fff,#6a33a8', radii: '8px', shadows: '', techniques: '3d-transform,text-shadow,gradient,animation,svg-icon'),
const GalaxyComp(id: 'zanina-yassine_perfect-penguin-77', cat: 'Buttons', author: 'zanina-yassine', tags: 'blue,minimalist,gradient,button,hover,rounded,dark,glow', html: '<button class="button">Sign Up</button>', css: '\n/* From Uiverse.io by zanina-yassine  - Tags: blue, minimalist, gradient, button, hover, rounded, dark, glow */\n.button {\n  min-width: 120px;\n\n  position: relative;\n  cursor: pointer;\n\n  padding: 12px 17px;\n  border: 0;\n  border-radius: 7px;\n\n  box-shadow: inset 0 0 0 1px rgba(255, 255, 255, 0.1);\n  background: radial-gradient(\n    ellipse at bottom,\n    rgba(71, 81, 92, 1) 0%,\n    rgba(11, 21, 30, 1) 45%\n  );\n\n  color: rgb(255, 255, 255, 0.66);\n\n  transition: all 1s cubic-bezier(0.15, 0.83, 0.66, 1);\n}\n\n.button::before {\n  content: "";\n  width: 70%;\n  height: 1px;\n\n  position: absolute;\n  bottom: 0;\n  left: 15%;\n\n  background: rgb(255, 255, 255);\n  background: linear-gradient(\n    90deg,\n    rgba(255, 255, 255, 0) 0%,\n    rgba(255, 255, 255, 1) 50%,\n    rgba(255, 255, 255, 0) 100%\n  );\n  opacity: 0.2;\n\n  transition: all 1s cubic-bezier(0.15, 0.83, 0.66, 1);\n}\n\n.button:hover {\n  color: rgb(255, 255, 255, 1);\n  transform: scale(1.1) translateY(-3px);\n}\n\n.button:hover::before {\n  opacity: 1;\n}\n\n', colors: '', radii: '7px', shadows: 'inset 0 0 0 1px rgba(255, 255, 255, 0.1)', techniques: 'cubic-bezier,3d-transform,glow-shadow,gradient,pseudo-elements'),
const GalaxyComp(id: 'Admin12121_little-catfish-39', cat: 'Cards', author: 'Admin12121', tags: 'card,hover effect,card animation,card hover', html: '<div class="section_our_solution">\n  <div class="row">\n    <div class="col-lg-12 col-md-12 col-sm-12">\n      <div class="our_solution_category">\n        <div class="solution_cards_box">\n          <div class="solution_card">\n            <div class="hover_color_bubble"></div>\n            <div class="so_top_icon">\n              <svg xmlns="http://www.w3.org/2000/svg" width="40" viewBox="0 0 512 512" height="50" id="Layer_1">\n                <g>\n                  <g>\n                    <g>\n                      <g>\n                        <path fill="#fae19e" d="m47.478 452.317 295.441 19.76c5.511.369 10.277-3.8 10.645-9.31l28.393-424.517c.369-5.511-3.8-10.276-9.31-10.645l-295.441-19.76c-5.511-.369-10.276 3.8-10.645 9.31l-28.394 424.517c-.368 5.511 3.8 10.277 9.311 10.645z"></path>\n                      </g>\n                      <g>\n                        <g>\n                          <g>\n                            <g>\n                              <g>\n                                <path fill="#fff9e9" d="m17.5 504.177h226.14l79.96-79.605v-355.86c0-5.523-4.477-10-10-10h-296.1c-5.523 0-10 4.477-10 10v425.466c0 5.522 4.477 9.999 10 9.999z"></path>\n                              </g>\n                              <path fill="#fff4d6" d="m313.601 58.712h-40c5.523 0 10 4.477 10 10v355.861l-.258 40.078 40.258-40.078v-355.861c0-5.523-4.477-10-10-10z"></path>\n                            </g>\n                          </g>\n                        </g>\n                        <path fi', css: '\n/* From Uiverse.io by Admin12121 - Tags: card, hover effect, card animation, card hover */\n.section_our_solution .row {\n  align-items: center;\n}\n\n.our_solution_category {\n  display: flex;\n  flex-direction: row;\n  flex-wrap: wrap;\n}\n\n.our_solution_category .solution_cards_box {\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n}\n\n.solution_cards_box .solution_card {\n  flex: 0 50%;\n  background: #fff;\n  box-shadow: 0 2px 4px 0 rgba(136, 144, 195, 0.2),\n    0 5px 15px 0 rgba(37, 44, 97, 0.15);\n  border-radius: 15px;\n  margin: 8px;\n  padding: 10px 15px;\n  position: relative;\n  z-index: 1;\n  overflow: hidden;\n  min-height: 265px;\n  transition: 0.7s;\n}\n\n.solution_cards_box .solution_card:hover {\n  background: #309df0;\n  color: #fff;\n  transform: scale(1.1);\n  z-index: 9;\n}\n\n.solution_cards_box .solution_card:hover::before {\n  background: rgb(85 108 214 / 10%);\n}\n\n.solution_cards_box .solution_card:hover .solu_title h3,\n.solution_cards_box .solution_card:hover .solu_description p {\n  color: #fff;\n}\n\n.solution_cards_box .solution_card:before {\n  content: "";\n  position: absolute;\n  background: rgb(85 108 214 / 5%);\n  width: 170px;\n  height: 400px;\n  z-index: -1;\n  transform: rotate(42deg);\n  right: -56px;\n  top: -23px;\n  border-radius: 35px;\n}\n\n.solution_cards_box .solution_card:hover .solu_description button {\n  background: #fff !important;\n  color: #309df0;\n}\n\n.solution_card .so_top_icon {\n}\n\n.solution_card .solu_title div {\n  color: #212121;\n  font-size: 1.3rem;\n  margin-top: 13px;\n  margin-bottom: 13px;\n}\n\n.solution_card .solu_description p {\n  font-size: 15px;\n  margin-bottom: 15px;\n}\n\n.solution_card .solu_description button {\n  border: 0;\n  border-radius: 15px;\n  background: linear-gradient(\n    140deg,\n    #42c3ca 0%,\n    #42c3ca 50%,\n    #42c3cac7 75%\n  ) !important;\n  color: #fff;\n  font-weight: 500;\n  font-size: 1rem;\n  padding: 5px 16px;\n}\n\n.our_solution_content div {\n  text-transform: capitalize;\n  margin-bottom: 1rem;\n  font-size: 2.5rem;\n}', colors: '#212121,#309df0,#42c3cac7,#fff,#42c3ca', radii: '15px,50%,35px', shadows: '0 2px 4px 0 rgba(136, 144, 195, 0.2),\n    0 5px 15px 0 rgba(37, 44, 97, 0.15)', techniques: '3d-transform,gradient,typography-t