const GalaxyComp(id: 'Admin12121_plastic-goose-38', cat: 'Cards', author: 'Admin12121', tags: 'payment card,animated,hover effect,card animation', html: '<div class="container">\n <div class="left-side">\n  <div class="card">\n   <div class="card-line"></div>\n   <div class="buttons"></div>\n  </div>\n  <div class="post">\n   <div class="post-line"></div>\n   <div class="screen">\n    <div class="dollar">\$</div>\n   </div>\n   <div class="numbers"></div>\n   <div class="numbers-line2"></div>\n  </div>\n </div>\n <div class="right-side">\n  <div class="new">New Transaction</div>\n  \n   <svg viewBox="0 0 451.846 451.847" height="512" width="512" xmlns="http://www.w3.org/2000/svg" class="arrow"><path fill="#cfcfcf" data-old_color="#000000" class="active-path" data-original="#000000" d="M345.441 248.292L151.154 442.573c-12.359 12.365-32.397 12.365-44.75 0-12.354-12.354-12.354-32.391 0-44.744L278.318 225.92 106.409 54.017c-12.354-12.359-12.354-32.394 0-44.748 12.354-12.359 32.391-12.359 44.75 0l194.287 194.284c6.177 6.18 9.262 14.271 9.262 22.366 0 8.099-3.091 16.196-9.267 22.373z"></path></svg>\n \n </div>\n</div>', css: '\n/* From Uiverse.io by Admin12121 - Tags: payment card, animated, hover effect, card animation */\n.container {\n  background-color: #ffffff;\n  display: flex;\n  width: 460px;\n  height: 120px;\n  position: relative;\n  border-radius: 6px;\n  transition: 0.3s ease-in-out;\n}\n\n.container:hover {\n  transform: scale(1.03);\n  width: 220px;\n}\n\n.container:hover .left-side {\n  width: 100%;\n}\n\n.left-side {\n  background-color: #5de2a3;\n  width: 130px;\n  height: 120px;\n  border-radius: 4px;\n  position: relative;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  cursor: pointer;\n  transition: 0.3s;\n  flex-shrink: 0;\n  overflow: hidden;\n}\n\n.right-side {\n  width: calc(100% - 130px);\n  display: flex;\n  align-items: center;\n  overflow: hidden;\n  cursor: pointer;\n  justify-content: space-between;\n  white-space: nowrap;\n  transition: 0.3s;\n}\n\n.right-side:hover {\n  background-color: #f9f7f9;\n}\n\n.arrow {\n  width: 20px;\n  height: 20px;\n  margin-right: 20px;\n}\n\n.new {\n  font-size: 23px;\n  font-family: "Lexend Deca", sans-serif;\n  margin-left: 20px;\n}\n\n.card {\n  width: 70px;\n  height: 46px;\n  background-color: #c7ffbc;\n  border-radius: 6px;\n  position: absolute;\n  display: flex;\n  z-index: 10;\n  flex-direction: column;\n  align-items: center;\n  -webkit-box-shadow: 9px 9px 9px -2px rgba(77, 200, 143, 0.72);\n  -moz-box-shadow: 9px 9px 9px -2px rgba(77, 200, 143, 0.72);\n  -webkit-box-shadow: 9px 9px 9px -2px rgba(77, 200, 143, 0.72);\n}\n\n.card-line {\n  width: 65px;\n  height: 13px;\n  background-color: #80ea69;\n  border-radius: 2px;\n  margin-top: 7px;\n}\n\n@media only screen and (max-width: 480px) {\n  .container {\n    transform: scale(0.7);\n  }\n\n  .container:hover {\n    transform: scale(0.74);\n  }\n\n  .new {\n    font-size: 18px;\n  }\n}\n\n.buttons {\n  width: 8px;\n  height: 8px;\n  background-color: #379e1f;\n  box-shadow: 0 -10px 0 0 #26850e, 0 10px 0 0 #56be3e;\n  border-radius: 50%;\n  margin-top: 5px;\n  transform: rotate(90deg);\n  margin: 10px 0 0 -30px;\n}\n\n.container:hover .card {\n  animat', colors: '#379e1f,#56be3e,#c7ffbc,#26850e,#dddde0,#aaa9ab,#5de2a3,#80ea69,#757375,#f9f7f9', radii: '50%,3px,4px,2px,6px', shadows: '9px 9px 9px -2px rgba(77, 200, 143, 0.72),9px 9px 9px -2px rgba(77, 200, 143, 0.72),9px 9px 9px -2px rgba(77, 200, 143, 0.72)', techniques: 'cubic-bezier,3d-transform,glow-shadow,animation,svg-icon'),
const GalaxyComp(id: 'Adrwaan_dry-bullfrog-78', cat: 'Cards', author: 'Adrwaan', tags: 'icon,animation,card,hover,glow,svg,border,color', html: '<div class="card">\n  <svg viewBox="0 0 512 512" class="paperplane">\n    <path\n      d="M498.1 5.6c10.1 7 15.4 19.1 13.5 31.2l-64 416c-1.5 9.7-7.4 18.2-16 23s-18.9 5.4-28 1.6L284 427.7l-68.5 74.1c-8.9 9.7-22.9 12.9-35.2 8.1S160 493.2 160 480V396.4c0-4 1.5-7.8 4.2-10.7L331.8 202.8c5.8-6.3 5.6-16-.4-22s-15.7-6.4-22-.7L106 360.8 17.7 316.6C7.1 311.3 .3 300.7 0 288.9s5.9-22.8 16.1-28.7l448-256c10.7-6.1 23.9-5.5 34 1.4z"\n    ></path>\n  </svg>\n</div>', css: '\n/* From Uiverse.io by Adrwaan  - Tags: icon, animation, card, hover, glow, svg, border, color */\n.card {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  position: relative;\n  width: 190px;\n  height: 254px;\n  background: #434343;\n  border-radius: 10px;\n}\n\n.card::before {\n  content: "";\n  position: absolute;\n  width: 190px;\n  height: 254px;\n  background-color: tomato;\n  border-radius: 10px;\n  z-index: -1;\n  transition: all 0.4s;\n  animation: animate 5s linear infinite;\n}\n\n.card:hover::before {\n  width: 197px;\n  height: 259px;\n}\n\n.card:hover .paperplane {\n  transform: scale(1.07) translateY(-10%) rotate(18deg);\n}\n\n.paperplane {\n  fill: #888;\n  width: 70px;\n  transition: 0.4s all;\n}\n\n@keyframes animate {\n  50% {\n    filter: hue-rotate(350deg);\n  }\n}\n\n', colors: '#434343,#888', radii: '10px', shadows: '', techniques: '3d-transform,animation,filter-effect,svg-icon,pseudo-elements'),
