acity 0.25s;\n  z-index: 2;\n  cursor: pointer;\n}\n\n.card .social-link1,.card .social-link2,.card .social-link3,.card .social-link4 {\n  position: relative;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  width: 25%;\n  color: whitesmoke;\n  font-size: 24px;\n  text-decoration: none;\n  transition: 0.25s;\n  border-radius: 50px;\n}\n\n.card svg {\n  transform: scale(1);\n}\n\n.card .social-link1:hover {\n  background: #f09433;\n  background: -moz-linear-gradient(45deg, #f09433 0%, #e6683c 25%, #dc2743 50%, #cc2366 75%, #bc1888 100%);\n  background: -webkit-linear-gradient(45deg, #f09433 0%,#e6683c 25%,#dc2743 50%,#cc2366 75%,#bc1888 100%);\n  background: linear-gradient(45deg, #f09433 0%,#e6683c 25%,#dc2743 50%,#cc2366 75%,#bc1888 100%);\n  filter: progid:DXImageTransform.Microsoft.gradient( startColorstr=\'#f09433\', endColorstr=\'#bc1888\',GradientType=1 );\n  animation: bounce_613 0.4s linear;\n}\n\n.card .social-link2:hover {\n  background-color: #00ccff;\n  animation: bounce_613 0.4s linear;\n}\n\n.card .social-link3:hover {\n  background-color: #5865f2;\n  animation: bounce_613 0.4s linear;\n}\n\n.card .social-link4:hover {\n  background-color: #12a50b;\n  animation: bounce_613 0.4s linear;\n}\n\n@keyframes bounce_613 {\n  40% {\n    transform: scale(1.4);\n  }\n\n  60% {\n    transform: scale(0.8);\n  }\n\n  80% {\n    transform: scale(1.2);\n  }\n\n  100% {\n    transform: scale(1);\n  }\n}\n', colors: '#bc1888,#e6683c,#f09433,#cc2366,#dc2743,#00ccff,#5865f2,#12a50b', radii: '50px', shadows: '', techniques: '3d-transform,gradient,animation,filter-effect,svg-icon'),
const GalaxyComp(id: 'AmIt-DasIT_quick-frog-32', cat: 'Cards', author: 'AmIt-DasIT', tags: 'card', html: '<div class="card">\n    <div class="heading">Join the Open-Source <span>Galaxy</span></div>\n    <div class="content">\n        <div class="item item--create">\n            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="24" height="24">\n                <path fill="currentColor" d="M24 12L18.3431 17.6569L16.9289 16.2426L21.1716 12L16.9289 7.75736L18.3431 6.34315L24 12ZM2.82843 12L7.07107 16.2426L5.65685 17.6569L0 12L5.65685 6.34315L7.07107 7.75736L2.82843 12ZM9.78845 21H7.66009L14.2116 3H16.3399L9.78845 21Z"></path>\n            </svg>\n            <span>Create</span>\n        </div>\n        <div class="item item--post">\n            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="24" height="24">\n                <path fill="currentColor" d="M4.99958 12.9998C4.99958 7.91186 7.90222 3.56348 11.9996 1.81787C16.0969 3.56348 18.9996 7.91186 18.9996 12.9998C18.9996 13.8227 18.9236 14.6263 18.779 15.4026L20.7194 17.2352C20.8845 17.3911 20.9238 17.6388 20.815 17.8381L18.3196 22.4132C18.1873 22.6556 17.8836 22.7449 17.6412 22.6127C17.5993 22.5898 17.5608 22.5611 17.5271 22.5273L15.2925 20.2927C15.1049 20.1052 14.8506 19.9998 14.5854 19.9998H9.41379C9.14857 19.9998 8.89422 20.1052 8.70668 20.2927L6.47209 22.5273C6.27683 22.7226 5.96025 22.7226 5.76498 22.5273C5.73122 22.4935 5.70246 22.4551 5.67959 22.4132L3.18412 17.8381C3.07537 17.6388 3.11464 17.3911 3.27975 17.2352L5.22014 15.4026C5.07551 14.6263 4.99958 13.8227 4.99958 12.9998ZM6.47542 19.6955L7.2924', css: '\n/* From Uiverse.io by AmIt-DasIT - Tags: card */\n.card {\n  width: 310px;\n  height: 330px;\n  display: flex;\n  flex-flow: column;\n  justify-content: space-around;\n  align-items: center;\n  border-radius: 15px;\n  padding: 5px;\n  color: white;\n  z-index: 1030;\n  transition: 0.4s;\n  overflow: hidden;\n  position: relative;\n  animation: shadow 3s linear infinite;\n}\n\n.card::before {\n  content: "";\n  position: absolute;\n  top: -27%;\n  width: 550px;\n  height: 550px;\n  z-index: -1;\n  background-image: conic-gradient(transparent, transparent, transparent, crimson);\n  animation: rotate 3s linear infinite;\n  /* animation-delay: 1.5s; */\n}\n\n.card::after {\n  content: "";\n  position: absolute;\n  bottom: -30%;\n  width: 550px;\n  height: 550px;\n  transform: rotate(180deg);\n  background-image: conic-gradient(transparent, transparent, transparent, yellow);\n  z-index: -1;\n  animation: rotate1 3s linear infinite;\n}\n\n@keyframes rotate {\n  0% {\n    transform: rotate(0deg);\n  }\n\n  100% {\n    transform: rotate(360deg);\n  }\n}\n\n@keyframes rotate1 {\n  0% {\n    transform: rotate(180deg);\n  }\n\n  0% {\n    transform: rotate(-180deg);\n  }\n}\n\n@keyframes shadow {\n  0% {\n    box-shadow: 6px 6px 15px rgba(255, 194, 80, 0.25),\n  -6px -6px 20px rgba(255, 0, 0, 0.25);\n  }\n\n  50% {\n    box-shadow: -6px -6px 15px rgba(255, 194, 80, 0.25),\n  6px 6px 20px rgba(255, 0, 0, 0.25);\n  }\n\n  100% {\n    box-shadow: 6px 6px 15px rgba(255, 194, 80, 0.25),\n  -6px -6px 20px rgba(255, 0, 0, 0.25);\n  }\n}\n\n.card .heading {\n  font-size: 18px;\n  font-weight: 800;\n  background-size: 300% 300%;\n  background-image: linear-gradient(to right, #d52643, yellow, yellowgreen);\n  background-clip: text;\n  -webkit-background-clip: text;\n  color: transparent;\n  z-index: 1000;\n  animation: AnimateBG 4s ease infinite;\n}\n\n@keyframes AnimateBG {\n  0% {\n    background-position: 0% 50%;\n  }\n\n  50% {\n    background-position: 100% 50%;\n  }\n\n  100% {\n    background-position: 0% 50%;\n  }\n}\n\n.card .content {\n  display: flex;\n  width: 301px;\n  height: 3', colors: '#26d526,#4bff4b,#d52643', radii: '15px,10px,20px', shadows: '6px 6px 15px rgba(255, 194, 80, 0.25),\n  -6px -6px 20px rgba(255, 0, 0, 0.25),-6px -6px 15px rgba(255, 194, 80, 0.25),\n  6px 6px 20px rgba(255, 0, 0, 0.25),6px 6px 15px rgba(255, 194, 80, 0.25),\n  -6px -6px 20px rgba(255, 0, 0, 0.25)', techniques: '3d-transform,gradient,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'andrew-demchenk0_quick-seahorse-69', cat: 'Cards', author: 'andrew-demchenk0', tags: 'card,product,price,img,description,hover effect,buy now,title,product card', html: '<div class="card">\n    <div class="card-img"><div class="img"></div></div>\n    <div class="card-title">Product title</div>\n    <div class="card-subtitle">Product description. Lorem ipsum dolor sit amet, consectetur adipisicing elit.</div>\n    <hr class="card-divider">\n    <div class="card-footer">\n        <div class="card-price"><span>\$</span> 123.45</div>\n        <button class="card-btn">\n          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512"><path d="m397.78 316h-205.13a15 15 0 0 1 -14.65-11.67l-34.54-150.48a15 15 0 0 1 14.62-18.36h274.27a15 15 0 0 1 14.65 18.36l-34.6 150.48a15 15 0 0 1 -14.62 11.67zm-193.19-30h181.25l27.67-120.48h-236.6z"></path><path d="m222 450a57.48 57.48 0 1 1 57.48-57.48 57.54 57.54 0 0 1 -57.48 57.48zm0-84.95a27.48 27.48 0 1 0 27.48 27.47 27.5 27.5 0 0 0 -27.48-27.47z"></path><path d="m368.42 450a57.48 57.48 0 1 1 57.48-57.48 57.54 57.54 0 0 1 -57.48 57.48zm0-84.95a27.48 27.48 0 1 0 27.48 27.47 27.5 27.5 0 0 0 -27.48-27.47z"></path><path d="m158.08 165.49a15 15 0 0 1 -14.23-10.26l-25.71-77.23h-47.44a15 15 0 1 1 0-30h58.3a15 15 0 0 1 14.23 10.26l29.13 87.49a15 15 0 0 1 -14.23 19.74z"></path></svg>\n        </button>\n    </div>\n</div>', css: '\n/* From Uiverse.io by andrew-demchenk0 - Tags: card, product, price, img, description, hover effect, buy now, title, product card */\n/* before adding the img to the div with the \n"card-img" class, remove css styles \n.card-img .img::before and .card-img .img::after,\nthen set the desired styles for .card-img. */\n.card {\n  --font-color: #323232;\n  --font-color-sub: #666;\n  --bg-color: #fff;\n  --main-color: #323232;\n  --main-focus: #2d8cf0;\n  width: 230px;\n  height: 300px;\n  background: var(--bg-color);\n  border: 2px solid var(--main-color);\n  box-shadow: 4px 4px var(--main-color);\n  border-radius: 5px;\n  display: flex;\n  flex-direction: column;\n  justify-content: flex-start;\n  padding: 20px;\n  gap: 10px;\n  font-family: system-ui, -apple-system, BlinkMacSystemFont, \'Segoe UI\', Roboto, Oxygen, Ubuntu, Cantarell, \'Open Sans\', \'Helvetica Neue\', sans-serif;\n}\n\n.card:last-child {\n  justify-content: flex-end;\n}\n\n.card-img {\n    /* clear and add new css */\n  transition: all 0.5s;\n  display: flex;\n  justify-content: center;\n}\n\n.card-img .img {\n /* delete */\n  transform: scale(1);\n  position: relative;\n  box-sizing: border-box;\n  width: 100px;\n  height: 100px;\n  border-top-left-radius: 80px 50px;\n  border-top-right-radius: 80px 50px;\n  border: 2px solid black;\n  background-color: #228b22;\n  background-image: linear-gradient(to top,transparent 10px,rgba(0,0,0,0.3) 10px,rgba(0,0,0,0.3) 13px,transparent 13px);\n}\n\n.card-img .img::before {\n /* delete */\n  content: \'\';\n  position: absolute;\n  width: 65px;\n  height: 110px;\n  margin-left: -32.5px;\n  left: 50%;\n  bottom: -4px;\n  background-repeat: no-repeat;\n  background-image: radial-gradient(ellipse at center,rgba(0,0,0,0.7) 30%,transparent 30%),linear-gradient(to top,transparent 17px,rgba(0,0,0,0.3) 17px,rgba(0,0,0,0.3) 20px,transparent 20px),linear-gradient(to right,black 2px,transparent 2px),linear-gradient(to left,black 2px,transparent 2px),linear-gradient(to top,black 2px,#228b22 2px);\n  background-size: 60% 10%,100% 100%,100% 65', colors: '#ffc0cb,#323232,#228b22,#2d8cf0,#666,#ffa6b6,#fff', radii: '50px,0 0 4px 4px,5px', shadows: '4px 4px var(--main-color)', techniques: '3d-transform,glow-shadow,gradient,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'andrew-demchenk0_sweet-eel-60', cat: 'Cards', author: 'andrew-demchenk0', tags: 'gradient,spinner,animated,uiverse,transition,spin,ui,points,creator points', html: '<div class="one-div"></div>', css: '\n/* From Uiverse.io by andrew-demchenk0 - Tags: gradient, spinner, animated, uiverse, transition, spin, ui, points, creator points */\n.one-div {\n  cursor: help;\n  position: relative;\n  width: 185px;\n  height: 30px;\n  border-radius: 10px;\n  background: linear-gradient(120deg,\n    #BF66FF 0%, \n    #6248FF 3%,\n    #00DDEB 95%\n    );\n  animation: spin 4s linear infinite;\n  transform: translateY(100px);\n  box-shadow: 0px 10px 25px -10px #4E67FB;\n  transform-style: preserve-3d;\n  transition: all 0.4s;\n}\n\n.one-div::before {\n  content: \'U\';\n  font-family: \'Segoe UI\', Tahoma, Geneva, Verdana, sans-serif;\n  font-weight: 900;\n  font-size: 200px;\n  display: inline-block;\n  background-image: linear-gradient(140deg,\n    #BF66FF 10%, \n    #6248FF 70%,\n    #00DDEB 100%\n    );\n  background-clip: text;\n  -webkit-background-clip: text;\n  color: transparent;\n  position: absolute;\n  bottom: 10px;\n  left: -10px;\n}\n\n.one-div::after {\n  display: block;\n  content: \'\';\n  width: 35px;\n  height: 147px;\n  border-radius: 0 0 10px 10px;\n  background: linear-gradient(140deg,\n    #BF66FF -100%, \n    #6248FF 40%,\n    #00DDEB 100%\n    );\n  position: absolute;\n  bottom: 50px;\n  right: 0;\n}\n\n@keyframes spin {\n  0% {\n    transform: rotateY(0deg) translateY(100%);\n  }\n\n  100% {\n    transform: rotateY(360deg) translateY(100%);\n  }\n}\n\n@keyframes spin2 {\n  0% {\n    transform: translateY(-20%) rotateY(0);\n  }\n\n  100% {\n    transform: translateY(-20%) rotateY(360deg);\n  }\n}\n\n.one-div:active {\n  cursor: wait;\n  width: 100px;\n  height: 100px;\n  border-radius: 200px;\n  animation: spin2 2.5s linear infinite;\n  background: linear-gradient(145deg,\n    #BF66FF 10%, \n    #6248FF 50%,\n    #00DDEB 100%\n  );\n}\n\n.one-div:active::before {\n  font-size: 0px;\n  left: 10px;\n  top: 10px;\n  width: 80px;\n  height: 80px;\n  border-radius: 50%;\n  /* background: #e8e8e8; */\n  background: #212121;\n}\n\n.one-div:active::after {\n  width: 20px;\n  height: 20px;\n  background: transparent;\n  transform: rotate(45deg);\n  border: 10px solid;\n  ', colors: '#212121,#4e67fb,#00ddeb,#bf66ff,#6248ff,#e8e8e8', radii: '50%,0,0 0 10px 10px,10px,200px', shadows: '0px 10px 25px -10px #4E67FB', techniques: '3d-transform,glow-shadow,gradient,animation,pseudo-elements'),
const GalaxyComp(id: 'bociKond_shaggy-pug-39', cat: 'Cards', author: 'bociKond', tags: 'animation,card,clock,pulse,box-shadow,am/pm,wrist,watch', html: '<div class="one-div"></div>', css: '\n/* From Uiverse.io by bociKond - Tags: animation, card, clock, pulse, box-shadow, AM/PM, wrist, watch */\n.one-div {\n  --white: rgb(200,200,200);\n  --black: rgb(50,50,50);\n  --clr: #7BF1A8;\n  --clr1: #b4facf;\n  --clr2: #3E363F;\n  background-color: var(--clr2);\n  width: 190px;\n  height: 190px;\n  border-radius: 50%;\n  position: relative;\n  transition: all 300ms;\n  animation: shadow 1.5s infinite linear;\n}\n\n.one-div:hover {\n  background-color: var(--clr);\n  box-shadow: 0 0 100px var(--clr);\n  border-radius: 1rem;\n  border: 10px solid var(--clr1);\n}\n\n.one-div:hover::before {\n  border-radius: 1rem;\n  color: var(--clr2);\n  font-weight: 900;\n  clip-path: polygon(0% 0%, 100.1% 0%, 91% 50%, 100.1% 100.3%, 0% 100.3%);\n}\n\n.one-div:hover::after {\n  animation-play-state: running;\n}\n\n.one-div::before {\n  content: \'14:30pm\';\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  position: absolute;\n  background-color: transparent;\n  width: 250px;\n  height: 250px;\n  border-radius: 50%;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%,-50%);\n  z-index: 1;\n  border: 10px solid var(--clr2);\n  font-size: 2rem;\n  color: var(--clr);\n  transition: all 300ms;\n}\n\n.one-div::after {\n  content: \'\';\n  position: absolute;\n  background-image: repeating-linear-gradient(0deg, var(--black), var(--black) 4px, transparent 4px, transparent);\n  background-size: 16px 16px;\n  background-position: center;\n  background-color: var(--white);\n  width: 140px;\n  height: 450px;\n  border-radius: 2rem;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%,-50%);\n  z-index: -2;\n  border-left: 10px solid var(--clr2);\n  border-right: 10px solid var(--clr2);\n  transition: all 300ms;\n  animation: height 1.5s infinite linear;\n  animation-play-state: paused;\n}\n\n@keyframes height {\n  from {\n    height: 450px;\n  }\n\n  50% {\n    height: 400px;\n  }\n\n  to {\n    height: 450px;\n  }\n}\n\n@keyframes shadow {\n  from {\n    box-shadow: 0 0 100px var(--clr);\n  }\n\n  50% {\n    box-shadow: 0 0 100p', colors: '#7bf1a8,#3e363f,#b4facf', radii: '50%,1rem,2rem', shadows: '0 0 100px var(--clr),0 0 100px var(--clr),0 0 100px 50px var(--clr)', techniques: 'glow-shadow,gradient,animation,clip-path,pseudo-elements'),
const GalaxyComp(id: 'boryanakrasteva_strong-cat-50', cat: 'Cards', author: 'boryanakrasteva', tags: 'glassmorphism,card', html: '<div class="container">\n  <div class="card">\n    hover\n  </div>\n</div>', css: '\n/* From Uiverse.io by boryanakrasteva - Tags: glassmorphism, card */\n.container {\n  width: 190px;\n  height: 254px;\n  background: transparent;\n  position: relative;\n  box-shadow: 0px 0px 5px rgba(0, 0, 0, 0.438);\n  overflow: hidden;\n  border-radius: 10px;\n}\n\n.card {\n  cursor: default;\n  width: 100%;\n  height: 100%;\n  position: relative;\n  z-index: 2;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 34px;\n  text-transform: uppercase;\n  letter-spacing: 2px;\n  color: #212121;\n  background-color: rgba(255, 255, 255, 0.074);\n  border: 1px solid rgba(255, 255, 255, 0.222);\n  -webkit-backdrop-filter: blur(20px);\n  backdrop-filter: blur(20px);\n  border-radius: 10px;\n  transition: all ease .3s;\n}\n\n.container::after,\n.container::before {\n  width: 100px;\n  height: 100px;\n  content: \'\';\n  position: absolute;\n  border-radius: 50%;\n  transition: .5s linear;\n}\n\n.container::after {\n  top: -20px;\n  left: -20px;\n  background-color: rgba(125, 214, 66, 0.603);\n  animation: animFirst 5s linear infinite;\n}\n\n.container::before {\n  background-color: rgb(226, 223, 54);\n  top: 70%;\n  left: 70%;\n  animation: animSecond 5s linear infinite;\n  animation-delay: 3s;\n}\n\n.container:hover {\n  box-shadow: 0px 0px 10px rgba(0, 77, 32, 0.432)\n}\n\n.container:hover::after {\n  left: 80px;\n  transform: scale(1.2);\n}\n\n.container:hover::before {\n  left: -10px;\n  transform: scale(1.2);\n}\n', colors: '#212121', radii: '10px,50%', shadows: '0px 0px 5px rgba(0, 0, 0, 0.438),0px 0px 10px rgba(0, 77, 32, 0.432)\n}\n\n.container:hover::after {\n  left: 80px', techniques: 'glassmorphism,3d-transform,glow-shadow,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'Clenio21_stale-sloth-57', cat: 'Cards', author: 'Clenio21', tags: 'card', html: '<div class="card"></div>', css: '\n/* From Uiverse.io by Clenio21 - Tags: card */\n.card {\n width: 190px;\n height: 254px;\n --border-radius: 15px;\n --border-width: 4px;\n appearance: none;\n position: relative;\n padding: 1em 2em;\n border: 0;\n background: rgb(5, 5, 22);\n font-size: 18px;\n font-weight: 500;\n color: #fff;\n z-index: 2;\n border-radius: 15px;\n}\n\n.card::after {\n --m-i: linear-gradient(#000, #000);\n --m-o: content-box, padding-box;\n content: "";\n position: absolute;\n left: 0;\n top: 0;\n width: 100%;\n height: 100%;\n padding: var(--border-width);\n border-radius: var(--border-radius);\n background-image: conic-gradient(\n		#488cfb,\n		#29dbbc,\n		#ddf505,\n		#ff9f0e,\n		#e440bb,\n		#655adc,\n		#488cfb\n	);\n -webkit-mask-image: var(--m-i), var(--m-i);\n mask-image: var(--m-i), var(--m-i);\n -webkit-mask-origin: var(--m-o);\n mask-origin: var(--m-o);\n -webkit-mask-clip: var(--m-o);\n mask-composite: exclude;\n -webkit-mask-composite: destination-out;\n filter: hue-rotate(0);\n animation: rotate-hue linear 500ms infinite;\n animation-play-state: paused;\n}\n\n.card:hover::after {\n animation-play-state: running;\n}\n\n@keyframes rotate-hue {\n to {\n  filter: hue-rotate(1turn);\n }\n}\n\n.card,\n.card::after {\n box-sizing: border-box;\n}\n\n.card:active {\n --border-width: 5px;\n}\n', colors: '#655adc,#ddf505,#488cfb,#000,#29dbbc,#e440bb,#ff9f0e,#fff', radii: '15px,var(--border-radius)', shadows: '', techniques: 'gradient,animation,filter-effect,css-mask,pseudo-elements'),
const GalaxyComp(id: 'codebykay101_ugly-lion-23', cat: 'Cards', author: 'codebykay101', tags: 'simple,card,hover,clean,card template,cool card,card hover', html: '<div class="container">\n  <div data-text="Github" style="--r:-15;" class="glass">\n    <svg viewBox="0 0 496 512" height="1em" xmlns="http://www.w3.org/2000/svg">\n      <path\n        d="M165.9 397.4c0 2-2.3 3.6-5.2 3.6-3.3.3-5.6-1.3-5.6-3.6 0-2 2.3-3.6 5.2-3.6 3-.3 5.6 1.3 5.6 3.6zm-31.1-4.5c-.7 2 1.3 4.3 4.3 4.9 2.6 1 5.6 0 6.2-2s-1.3-4.3-4.3-5.2c-2.6-.7-5.5.3-6.2 2.3zm44.2-1.7c-2.9.7-4.9 2.6-4.6 4.9.3 2 2.9 3.3 5.9 2.6 2.9-.7 4.9-2.6 4.6-4.6-.3-1.9-3-3.2-5.9-2.9zM244.8 8C106.1 8 0 113.3 0 252c0 110.9 69.8 205.8 169.5 239.2 12.8 2.3 17.3-5.6 17.3-12.1 0-6.2-.3-40.4-.3-61.4 0 0-70 15-84.7-29.8 0 0-11.4-29.1-27.8-36.6 0 0-22.9-15.7 1.6-15.4 0 0 24.9 2 38.6 25.8 21.9 38.6 58.6 27.5 72.9 20.9 2.3-16 8.8-27.1 16-33.7-55.9-6.2-112.3-14.3-112.3-110.5 0-27.5 7.6-41.3 23.6-58.9-2.6-6.5-11.1-33.3 2.6-67.9 20.9-6.5 69 27 69 27 20-5.6 41.5-8.5 62.8-8.5s42.8 2.9 62.8 8.5c0 0 48.1-33.6 69-27 13.7 34.7 5.2 61.4 2.6 67.9 16 17.7 25.8 31.5 25.8 58.9 0 96.5-58.9 104.2-114.8 110.5 9.2 7.9 17 22.9 17 46.4 0 33.7-.3 75.4-.3 83.6 0 6.5 4.6 14.4 17.3 12.1C428.2 457.8 496 362.9 496 252 496 113.3 383.5 8 244.8 8zM97.2 352.9c-1.3 1-1 3.3.7 5.2 1.6 1.6 3.9 2.3 5.2 1 1.3-1 1-3.3-.7-5.2-1.6-1.6-3.9-2.3-5.2-1zm-10.8-8.1c-.7 1.3.3 2.9 2.3 3.9 1.6 1 3.6.7 4.3-.7.7-1.3-.3-2.9-2.3-3.9-2-.6-3.6-.3-4.3.7zm32.4 35.6c-1.6 1.3-1 4.3 1.3 6.2 2.3 2.3 5.2 2.6 6.5 1 1.3-1.3.7-4.3-1.3-6.2-2.2-2.3-5.2-2.6-6.5-1zm-11.4-14.7c-1.6 1-1.6 3.6 0 5.9 1.6 2.3 4.3 3.3 5.6 2.3 1.6-1.3 1.6-3.9 0-6.2-1.4-2.3-4-3.3-5.6-2z"\n      ></', css: '\n/* From Uiverse.io by codebykay101  - Tags: simple, card, hover, clean, card template, cool card, card hover */\n.container {\n  position: relative;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n.container .glass {\n  position: relative;\n  width: 180px;\n  height: 200px;\n  background: linear-gradient(#fff2, transparent);\n  border: 1px solid rgba(255, 255, 255, 0.1);\n  box-shadow: 0 25px 25px rgba(0, 0, 0, 0.25);\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  transition: 0.5s;\n  border-radius: 10px;\n  margin: 0 -45px;\n  backdrop-filter: blur(10px);\n  transform: rotate(calc(var(--r) * 1deg));\n}\n\n.container:hover .glass {\n  transform: rotate(0deg);\n  margin: 0 10px;\n}\n\n.container .glass::before {\n  content: attr(data-text);\n  position: absolute;\n  bottom: 0;\n  width: 100%;\n  height: 40px;\n  background: rgba(255, 255, 255, 0.05);\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  color: #fff;\n}\n.container .glass svg {\n  font-size: 2.5em;\n  fill: #fff;\n}\n\n', colors: '#fff2,#fff', radii: '10px', shadows: '0 25px 25px rgba(0, 0, 0, 0.25)', techniques: 'glassmorphism,3d-transform,gradient,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'Creatlydev_friendly-fish-0', cat: 'Cards', author: 'Creatlydev', tags: 'card', html: '<div class="card">\n  <div class="card__body">\n    <div class="card__icon">\n      <svg\n        height="32"\n        width="32"\n        stroke="currentColor"\n        stroke-width="1.5"\n        viewBox="0 0 24 24"\n        fill="none"\n        xmlns="http://www.w3.org/2000/svg"\n      >\n        <path\n          d="M9 17.25v1.007a3 3 0 01-.879 2.122L7.5 21h9l-.621-.621A3 3 0 0115 18.257V17.25m6-12V15a2.25 2.25 0 01-2.25 2.25H5.25A2.25 2.25 0 013 15V5.25m18 0A2.25 2.25 0 0018.75 3H5.25A2.25 2.25 0 003 5.25m18 0V12a2.25 2.25 0 01-2.25 2.25H5.25A2.25 2.25 0 013 12V5.25"\n          stroke-linejoin="round"\n          stroke-linecap="round"\n        ></path>\n      </svg>\n    </div>\n\n    <p class="card__title">Abstract Design</p>\n    <p class="card__paragraph">\n      Lorem ipsum dolor sit amet consectetur, adipisicing elit. Ducimus\n      perferendis eaque dolore repellat numquam. Dolores.\n    </p>\n  </div>\n\n  <div class="card__ribbon">\n    <label class="card__ribbon-label">01</label>\n  </div>\n</div>', css: '\n/* From Uiverse.io by Creatlydev  - Tags: card */\n.card {\n  width: min(300px, 100%);\n  margin: auto;\n  background-color: #f4f5f2;\n  text-align: center;\n  border-top-left-radius: 4rem;\n  border: 2px solid #fff;\n  position: relative;\n}\n\n.card::before {\n  content: "";\n  position: absolute;\n  height: 30px;\n  width: 120px;\n  background-color: #393e7f;\n  top: 32px;\n  right: -2.5px;\n  -webkit-clip-path: polygon(10% 0, 100% 0, 100% 100%, 0 100%);\n  clip-path: polygon(10% 0, 100% 0, 100% 100%, 0 100%);\n}\n\n.card__body {\n  padding: 2rem 1.5rem;\n  max-width: 25ch;\n  margin: auto;\n}\n\n.card__title {\n  font-weight: 800;\n  color: #121513;\n  font-size: 1.25rem;\n  margin-block: 1.5rem 0.75rem;\n}\n\n.card__paragraph {\n  color: #303830;\n  font-size: 0.875rem;\n}\n\n.card__ribbon {\n  margin-top: 1.5rem;\n  display: grid;\n  place-items: center;\n  height: 50px;\n  background-color: #393e7f;\n  position: relative;\n  width: 110%;\n  left: -5%;\n  top: 10px;\n  position: relative;\n  border-radius: 0 0 2rem 2rem;\n}\n\n.card__ribbon::after,\n.card__ribbon::before {\n  content: "";\n  position: absolute;\n  width: 20px;\n  aspect-ratio: 1/1;\n  bottom: 100%;\n  z-index: -2;\n  background-color: #191c39;\n}\n\n.card__ribbon::before {\n  left: 0;\n  transform-origin: left bottom;\n  transform: rotate(45deg);\n}\n\n.card__ribbon::after {\n  right: 0;\n  transform-origin: right bottom;\n  transform: rotate(-45deg);\n}\n\n.card__ribbon-label {\n  display: block;\n  width: 84px;\n  aspect-ratio: 1/1;\n  background-color: #fff;\n  position: relative;\n  transform: translateY(-50%);\n  border-radius: 50%;\n  border: 8px solid #393e7f;\n  display: grid;\n  place-items: center;\n  font-weight: 900;\n  line-height: 1;\n  font-size: 1.5rem;\n}\n\n.card__ribbon-label::before,\n.card__ribbon-label::after {\n  content: "";\n  position: absolute;\n  width: 25px;\n  height: 25px;\n  bottom: 50%;\n}\n\n.card__ribbon-label::before {\n  right: calc(100% + 4px);\n  border-bottom-right-radius: 20px;\n  box-shadow: 5px 5px 0 #393e7f;\n}\n\n.card__ribbon-label::after {\n  left: calc(', colors: '#121513,#f4f5f2,#191c39,#303830,#fff,#393e7f', radii: '0 0 2rem 2rem,50%', shadows: '5px 5px 0 #393e7f,-5px 5px 0 #393e7f', techniques: '3d-transform,glow-shadow,clip-path,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'david-mohseni_black-bobcat-14', cat: 'Cards', author: 'david-mohseni', tags: 'card', html: '<div class="flip">\n    <div class="content">\n        <div class="front">\n            <h2>Front</h2>\n            <p>Front Description</p>\n        </div>\n        <div class="back">\n            <h2>Back</h2>\n            <p>Back Description</p>\n        </div>\n    </div>\n</div>', css: '\n/* From Uiverse.io by david-mohseni - Tags: card */\n.flip {\n  box-shadow: 0 0 10px rgba(128, 128, 128, 0.5);\n  padding: 1em;\n  width: 190px;\n  height: 254px;\n  transform-style: preserve-3d;\n  transition: 3s ease;\n}\n\n.flip:hover {\n  transform: rotateY(180deg);\n}\n/* Content */\n.flip .content {\n  transform-style: preserve-3d;\n}\n\n.flip .back, .flip .front {\n  transform-style: preserve-3d;\n  backface-visibility: hidden;\n  display: flex;\n  flex-direction: column;\n}\n\n.flip .back {\n  transform: rotateY(180deg);\n  position: absolute;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n}\n\n.flip h2,\n.flip p {\n  transform: translateZ(90px);\n  text-shadow: 0 0 3px black;\n  text-align: center;\n}\n\n.flip h2 {\n  font-size: 3em;\n  color: #fff;\n  letter-spacing: 1px;\n}\n\n.flip p {\n  font-size: 1em;\n  color: #eee;\n  line-height: 1.6em;\n}\n\n.flip::before,\n.flip::after {\n  content: "";\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  position: absolute;\n  background-image: linear-gradient(purple, red);\n  background-position: center center;\n  background-repeat: no-repeat;\n  background-size: cover;\n  transform: rotateY(180deg)translateZ(1px);\n}\n\n.flip::before {\n  transform: none;\n  background-image: linear-gradient(violet, orange);\n  background-position: center center;\n  background-repeat: no-repeat;\n  background-size: cover;\n}\n', colors: '#eee,#fff', radii: '', shadows: '0 0 10px rgba(128, 128, 128, 0.5)', techniques: '3d-transform,glow-shadow,text-shadow,gradient,pseudo-elements'),
const GalaxyComp(id: 'dzoshi_bad-warthog-50', cat: 'Cards', author: 'dzoshi', tags: 'dark,card,neon,futuristic,hover', html: '<div class="card">\n  <img src="https://uiverse.io/logo-png.png" class="logoUI" alt="UI" />\n</div>', css: '\n/* From Uiverse.io by dzoshi  - Tags: dark, card, neon, futuristic, hover */\n.card {\n  width: 200px;\n  height: 200px;\n  color: #67676b05;\n\n  background: linear-gradient(-45deg, #111111 0%, #080808 100%);\n  display: flex;\n  flex-direction: column;\n  justify-content: flex-end;\n  padding: 25px;\n  border-radius: 30px;\n  cursor: pointer;\n  box-shadow: 0px 20px 40px 0px #020202d8,\n    0px 60px 80px 0px rgba(0, 0, 0, 0.678),\n    0px 20px 95px 0px rgba(13, 33, 94, 0);\n  border-top: 3px solid #a3a1a78f;\n  outline: 3px solid #27127436;\n\n  transition: all 0.6s ease-out;\n}\n\n.card:hover {\n  color: #928b8b;\n  background-color: 482fb8;\n  box-shadow: 0px 10px 40px 0px rgba(0, 0, 0, 0.945),\n    0px 10px 20px 0px rgba(29, 9, 143, 0.856), 0px 0px 180px 0px rgb(47, 4, 202);\n  outline: 3px solid #500bf0;\n  outline: 3px solid #5518e4;\n\n  transform: scale(0.97);\n  transition: transform 0.4s, box-shadow 0.6s outline 0.8s ease-in;\n}\n\n.logoUI {\n  filter: grayscale(60%);\n  margin-top: 20px;\n  width: 60%;\n  opacity: 10%;\n  transition: all 0.6s ease-in-out;\n  position: relative;\n  z-index: 1;\n}\n\n.card:hover .logoUI {\n  filter: contrast(180%);\n  backdrop-filter: grayscale(0%);\n\n  opacity: 100%;\n  transition: all 1s ease-out;\n}\n\n', colors: '#27127436,#080808,#a3a1a78f,#020202d8,#67676b05,#928b8b,#5518e4,#500bf0,#111111', radii: '30px', shadows: '0px 20px 40px 0px #020202d8,\n    0px 60px 80px 0px rgba(0, 0, 0, 0.678),\n    0px 20px 95px 0px rgba(13, 33, 94, 0),0px 10px 40px 0px rgba(0, 0, 0, 0.945),\n    0px 10px 20px 0px rgba(29, 9, 143, 0.856), 0px 0px 180px 0px rgb(47, 4, 202)', techniques: 'glassmorphism,3d-transform,glow-shadow,gradient,filter-effect'),
const GalaxyComp(id: 'G4b413l_good-crab-75', cat: 'Cards', author: 'G4b413l', tags: 'glassmorphism,card,hover', html: '<div class="card">\n    <div class="circle"></div>\n    <div class="circle"></div>\n    <div class="card-inner"></div>\n</div>', css: '\n/* From Uiverse.io by G4b413l - Tags: glassmorphism, card, hover */\n.card {\n  width: 190px;\n  height: 254px;\n  transition: all 0.2s;\n  position: relative;\n  cursor: pointer;\n}\n\n.card-inner {\n  width: inherit;\n  height: inherit;\n  background: rgba(255,255,255,.05);\n  box-shadow: 0 0 10px rgba(0,0,0,0.25);\n  backdrop-filter: blur(10px);\n  border-radius: 8px;\n}\n\n.card:hover {\n  transform: scale(1.04) rotate(1deg);\n}\n\n.circle {\n  width: 100px;\n  height: 100px;\n  background: radial-gradient(#b0e633, #53ef7d);\n  border-radius: 50%;\n  position: absolute;\n  animation: move-up6 2s ease-in infinite alternate-reverse;\n}\n\n.circle:nth-child(1) {\n  top: -25px;\n  left: -25px;\n}\n\n.circle:nth-child(2) {\n  bottom: -25px;\n  right: -25px;\n  animation-name: move-down1;\n}\n\n@keyframes move-up6 {\n  to {\n    transform: translateY(-10px);\n  }\n}\n\n@keyframes move-down1 {\n  to {\n    transform: translateY(10px);\n  }\n}\n', colors: '#b0e633,#53ef7d', radii: '50%,8px', shadows: '0 0 10px rgba(0,0,0,0.25)', techniques: 'glassmorphism,3d-transform,glow-shadow,gradient,animation'),
const GalaxyComp(id: 'Galahhad_breezy-insect-49', cat: 'Cards', author: 'Galahhad', tags: 'card,gold,ticket', html: '<div class="one-div"></div>', css: '\n/* From Uiverse.io by Galahhad - Tags: card, gold, ticket */\n.one-div {\n  --circle-color: #212121;\n  width: 300px;\n  height: 150px;\n  position: relative;\n}\n\n.one-div::before {\n  content: "Golden Ticket";\n  color: transparent;\n  text-shadow: -55px 0 #2E2205;\n  text-transform: uppercase;\n  font-family: "Anton", Impact, sans-serif;\n  font-size: 1.6rem;\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n  -webkit-box-pack: center;\n  -ms-flex-pack: center;\n  justify-content: center;\n  position: absolute;\n  inset: 0;\n  background-image: -o-linear-gradient(transparent, transparent 15px, #2E2205 15px, #2E2205 17px, transparent 17px),\n      -o-linear-gradient(transparent, transparent 15px, #2E2205 15px, #2E2205 17px, transparent 17px),\n      -o-linear-gradient(transparent, transparent 15px, #2E2205 15px, #2E2205 27px, transparent 27px),\n      -o-linear-gradient(transparent, transparent 15px, #2E2205 15px, #2E2205 27px, transparent 27px),\n      -o-linear-gradient(transparent, transparent 15px, #2E2205 15px, #2E2205 27px, transparent 27px),\n      -o-linear-gradient(transparent, transparent 15px, #2E2205 15px, #2E2205 27px, transparent 27px),\n      -o-linear-gradient(transparent, transparent 15px, #2E2205 15px, #2E2205 27px, transparent 27px),\n      -o-linear-gradient(transparent, transparent 15px, #2E2205 15px, #2E2205 27px, transparent 27px),\n      -o-linear-gradient(transparent, transparent 15px, #2E2205 15px, #2E2205 27px, transparent 27px),\n      -o-linear-gradient(transparent, transparent 15px, #2E2205 15px, #2E2205 17px, transparent 17px),\n      -o-linear-gradient(transparent, transparent 15px, #2E2205 15px, #2E2205 20px, transparent 20px),\n      -o-linear-gradient(transparent, transparent 15px, #2E2205 15px, #2E2205 17px, transparent 17px),\n      -o-linear-gradient(transparent, transparent 15px, #2E2205 15px, #2E2205 18px, transparent 18px),\n      -o-linear-gradient(transparent,', colors: '#212121,#fdb931,#ffffac,#5d4a1f,#2e2205,#d1b464,#fedb37,#ffffff,#8a6e2f,#9f7928', radii: '', shadows: '', techniques: '3d-transform,text-shadow,gradient,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'gharsh11032000_heavy-snake-69', cat: 'Cards', author: 'gharsh11032000', tags: 'animation,card,hover effect,css effect,cool card,cardhover,card animation,card hover', html: '<div class="card">\n  <div class="content">\n    <p class="heading">Card</p>\n    <p class="para">\n      Lorem ipsum dolor sit amet, consectetur adipisicing elit. Modi laboriosam\n      at voluptas minus culpa deserunt delectus sapiente inventore pariatur\n    </p>\n  </div>\n</div>', css: '\n/* From Uiverse.io by gharsh11032000  - Tags: animation, card, hover effect, css effect, cool card, cardhover , card animation, card hover */\n.card {\n  position: relative;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  width: 320px;\n  padding: 2px;\n  border-radius: 24px;\n  overflow: hidden;\n  line-height: 1.6;\n  transition: all 0.48s cubic-bezier(0.23, 1, 0.32, 1);\n}\n\n.content {\n  display: flex;\n  flex-direction: column;\n  align-items: flex-start;\n  gap: 24px;\n  padding: 34px;\n  border-radius: 22px;\n  color: #ffffff;\n  overflow: hidden;\n  background: #ffffff;\n  transition: all 0.48s cubic-bezier(0.23, 1, 0.32, 1);\n}\n\n.content .heading {\n  font-weight: 700;\n  font-size: 36px;\n  line-height: 1.3;\n  z-index: 1;\n  transition: all 0.48s cubic-bezier(0.23, 1, 0.32, 1);\n}\n\n.content .para {\n  z-index: 1;\n  opacity: 0.8;\n  font-size: 18px;\n  transition: all 0.48s cubic-bezier(0.23, 1, 0.32, 1);\n}\n\n.card::before {\n  content: "";\n  position: absolute;\n  height: 160%;\n  width: 160%;\n  border-radius: inherit;\n  background: #0a3cff;\n  background: linear-gradient(to right, #0a3cff, #0a3cff);\n  transform-origin: center;\n  animation: moving 4.8s linear infinite paused;\n  transition: all 0.88s cubic-bezier(0.23, 1, 0.32, 1);\n}\n\n.card:hover::before {\n  animation-play-state: running;\n  z-index: -1;\n  width: 20%;\n}\n\n.card:hover .content .heading,\n.card:hover .content .para {\n  color: #000000;\n}\n\n.card:hover {\n  box-shadow: 0rem 6px 13px rgba(10, 60, 255, 0.1),\n    0rem 24px 24px rgba(10, 60, 255, 0.09),\n    0rem 55px 33px rgba(10, 60, 255, 0.05),\n    0rem 97px 39px rgba(10, 60, 255, 0.01), 0rem 152px 43px rgba(10, 60, 255, 0);\n  scale: 1.05;\n  color: #000000;\n}\n\n@keyframes moving {\n  0% {\n    transform: rotate(0);\n  }\n\n  100% {\n    transform: rotate(360deg);\n  }\n}\n\n', colors: '#000000,#ffffff,#0a3cff', radii: '24px,22px,inherit', shadows: '0rem 6px 13px rgba(10, 60, 255, 0.1),\n    0rem 24px 24px rgba(10, 60, 255, 0.09),\n    0rem 55px 33px rgba(10, 60, 255, 0', techniques: 'cubic-bezier,3d-transform,gradient,animation,pseudo-elements'),
const GalaxyComp(id: 'gharsh11032000_perfect-ladybug-87', cat: 'Cards', author: 'gharsh11032000', tags: 'card,hover effect,cardhover', html: '<div class="card">\n  <p class="heading">Card Hover</p>\n  <p class="para">Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod.\n  </p><div class="overlay"></div>\n  <button class="card-btn">Click</button>\n</div>', css: '\n/* From Uiverse.io by gharsh11032000 - Tags: card, hover effect, cardhover  */\n.card {\n  position: relative;\n  width: 350px;\n  height: 250px;\n  background-image: linear-gradient(-45deg, #f89b29 0%, #ff0f7b 100% );\n  border-radius: 10px;\n  display: flex;\n  padding: 10px 30px;\n  flex-direction: column;\n  gap: 10px;\n  align-items: center;\n  justify-content: center;\n  overflow: hidden;\n  box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);\n}\n\n.heading {\n  font-size: 24px;\n  font-weight: 700;\n  color: #ffffff;\n}\n\n.para {\n  text-align: center;\n  color: #ffffff;\n  opacity: 0.7;\n  line-height: 1.4;\n}\n\n.overlay {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  opacity: 0;\n  background-color: rgba(0, 0, 0, 0.6);\n  transition: opacity 0.3s ease;\n  pointer-events: none;\n}\n\n.card:hover .overlay {\n  opacity: 1;\n  pointer-events: auto;\n}\n\n.card .card-btn {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  font-weight: 600;\n  padding: 10px 20px;\n  font-size: 16px;\n  transform: translate(-50%, -50%);\n  background-color: #ffffff;\n  border-radius: 50px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  cursor: pointer;\n  z-index: 999;\n  border: none;\n  opacity: 0;\n  scale: 0;\n  transform-origin: 0 0;\n  box-shadow: 0 0 10px 10px rgba(0, 0, 0, 0.15);\n  transition: all 0.6s cubic-bezier(0.23, 1, 0.320, 1);\n}\n\n.card:hover .card-btn {\n  opacity: 1;\n  scale: 1;\n}\n\n.card .card-btn:hover {\n  box-shadow: 0 0 0px 5px rgba(0, 0, 0, 0.3);\n}\n\n.card .card-btn:active {\n  scale: 0.95;\n}\n\n.overlay::after {\n  content: "";\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%) scale(0);\n  width: 100%;\n  height: 100%;\n  background-image: linear-gradient(-45deg, #f89b2980 0%, #ff0f7b80 100% );\n  transition: transform 0.5s ease;\n}\n\n.card:hover .overlay::after {\n  transform: translate(-50%, -50%) scale(2);\n}\n\n', colors: '#ff0f7b80,#ff0f7b,#f89b29,#f89b2980,#ffffff', radii: '50px,10px', shadows: '0 0 10px rgba(0, 0, 0, 0.2),0 0 10px 10px rgba(0, 0, 0, 0.15),0 0 0px 5px rgba(0, 0, 0, 0.3)', techniques: 'cubic-bezier,3d-transform,glow-shadow,gradient,pseudo-elements'),
const GalaxyComp(id: 'gharsh11032000_rare-bobcat-17', cat: 'Cards', author: 'gharsh11032000', tags: 'gradient,card,hover,hover effect', html: '<div class="card">\n  <div class="card-content">\n    <p class="card-title">hover effect\n    </p><p class="card-para">Lorem ipsum dolor sit amet, consectetur adipiscing elit.</p>\n  </div>\n</div>', css: '\n/* From Uiverse.io by gharsh11032000 - Tags: gradient, card, hover, hover effect */\n.card {\n  width: 300px;\n  height: 200px;\n  background-color: #FF3CAC;\n  background-image: linear-gradient(225deg, #FF3CAC 0%, #784BA0 50%, #2B86C5 100%);\n  color: white;\n  border-radius: 8px;\n  overflow: hidden;\n  position: relative;\n  perspective: 1000px;\n  transition: all 0.5s cubic-bezier(0.23, 1, 0.320, 1);\n  cursor: pointer;\n}\n\n.card-content {\n  padding: 20px;\n  position: relative;\n  z-index: 1;\n}\n\n.card:hover {\n  transform: scale(1.05);\n  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);\n}\n\n.card:before {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 60%;\n  background-color: rgba(0, 0, 0, 0.1);\n  opacity: 0;\n  transition: all 0.5s cubic-bezier(0.23, 1, 0.320, 1);\n  z-index: 1;\n}\n\n.card:hover:before {\n  opacity: 1;\n}\n\n.card .card-title {\n  font-size: 24px;\n  font-weight: 700;\n  margin-bottom: 8px;\n  text-transform: capitalize;\n}\n\n.card .card-para {\n  font-size: 16px;\n  opacity: 0.8;\n}\n\n.card-content {\n  transform: translateY(50%);\n  transition: all 0.5s cubic-bezier(0.23, 1, 0.320, 1);\n}\n\n.card:hover .card-content {\n  transform: translateY(0%);\n}\n\n', colors: '#ff3cac,#784ba0,#2b86c5', radii: '8px', shadows: '0 10px 20px rgba(0, 0, 0, 0.2)', techniques: 'cubic-bezier,3d-transform,gradient,perspective,typography-transform'),
