t-weight: 700;\n}\n\n.card:hover svg {\n  scale: 0;\n}\n\n.card__description {\n  margin: 10px 0 0;\n  font-size: 14px;\n  color: #777;\n  line-height: 1.4;\n}\n\n', colors: '#ffffff80,#777,#333,#f2f2f2', radii: '10px', shadows: '0 0 0 5px #ffffff80,0 8px 16px rgba(255, 255, 255, 0.2)', techniques: 'cubic-bezier,3d-transform,glow-shadow,perspective,svg-icon'),
