 font-size: 24px;\n  color: #333;\n  font-weight: 700;\n}\n\n.card__description {\n  margin: 10px 0 0;\n  font-size: 14px;\n  color: #777;\n  line-height: 1.4;\n}\n\n.card:hover svg {\n  scale: 0;\n  transform: rotate(-45deg);\n}\n\n', colors: '#777,#f89b29,#333,#ff0f7b,#fff', radii: '10px', shadows: '0 10px 20px rgba(0, 0, 0, 0.2)', techniques: 'cubic-bezier,3d-transform,glow-shadow,gradient,svg-icon'),
const GalaxyComp(id: 'Hoseinnaqvi_terrible-hound-31', cat: 'Cards', author: 'Hoseinnaqvi', tags: 'logo,one-div,fruit', html: '<div class="one-div"></div>', css: '\n/* From Uiverse.io by Hoseinnaqvi - Tags: logo, one-div, fruit */\n.one-div {\n  margin-top: 40px;\n  width: 300px;\n  height: 300px;\n  background-image: linear-gradient(to right,red,orange);\n  border-radius: 40%;\n  box-shadow: 0px 0px 10px black;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  flex-direction: row;\n}\n\n.one-div::before {\n  content: \'\';\n  height: 90px;\n  width: 90px;\n  border-radius: 0 40% 0 60%;\n  background-color: green;\n  position: absolute;\n  top: 5%;\n  left: 42%;\n  box-shadow: 0px -3px 6px rgba(4, 4, 4, 0.695);\n  z-index: -1;\n}\n\n.one-div::after {\n  content: \'😋\';\n  filter: hue-rotate(130deg);\n  font-size: 10em;\n  font-family: \'Gill Sans\', \'Gill Sans MT\', Calibri, \'Trebuchet MS\', sans-serif;\n  border-radius: 0 40% 0 60%;\n  text-align: center;\n  top: 33%;\n  left: 37%;\n  animation: txt 1s infinite alternate;\n}\n\n@keyframes txt {\n  0% {\n    opacity: 0.1;\n  }\n\n  100% {\n    opacity: 1;\n  }\n}\n\n@keyframes intro {\n  0% {\n    top: -100px;\n  }\n\n  50% {\n    top: -50px;\n  }\n\n  100% {\n    top: 0px;\n  }\n}\n\n', colors: '', radii: '0 40% 0 60%,40%', shadows: '0px 0px 10px black,0px -3px 6px rgba(4, 4, 4, 0.695)', techniques: 'glow-shadow,gradient,animation,filter-effect,pseudo-elements'),
const GalaxyComp(id: 'htwarriors108_clever-swan-80', cat: 'Cards', author: 'htwarriors108', tags: 'hover effect,hoverme,multicolor,blur,animation,gradient,card,shadow,blur filter,colorful', html: '<div class="card">\n        <div class="txt">Hover Me :)</div>\n        <div class="shadow"></div>\n    </div>', css: '\n/* From Uiverse.io by htwarriors108 - Tags: hover effect, hoverme, multicolor, blur, animation, gradient, card, shadow, blur filter, colorful */\n.card {\n  position: absolute;\n  width: 190px;\n  height: 254px;\n  border: 4px solid rgba(255, 255, 255, 0.3);\n  border-radius: 0.8em;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  cursor: pointer;\n  transition: 0.5s;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n}\n\n.card:hover {\n  scale: 1.05;\n  rotate: 3deg;\n}\n\n.card::after {\n  content: \'\';\n  width: 93%;\n  height: 95%;\n  position: absolute;\n  border-radius: 0.7em;\n  background-color: rgba(255, 255, 255, 0.1);\n  z-index: 0;\n}\n\n.shadow {\n  width: 100%;\n  height: 100%;\n  background: linear-gradient(315deg, #03a9f4, #ff0058);\n  z-index: -1;\n  filter: blur(25px);\n}\n\n.txt {\n  position: absolute;\n  font-weight: 800;\n  font-size: 1.6em;\n  color: #fff;\n}\n\n.card:hover .shadow {\n  animation: rotate 3s linear infinite;\n}\n\n@keyframes rotate {\n  0% {\n    rotate: 0deg;\n    background: linear-gradient(315deg, #03a9f4, #ff0058);\n  }\n\n  50% {\n    rotate: 180deg;\n    background: linear-gradient(45deg, #ffbc00, #ff0058);\n  }\n\n  100% {\n    rotate: 360deg;\n    background: linear-gradient(315deg, #4dff03, #00d0ff);\n  }\n}\n', colors: '#4dff03,#ff0058,#ffbc00,#03a9f4,#00d0ff,#fff', radii: '0.7em,0.8em', shadows: '', techniques: 'glassmorphism,3d-transform,gradient,animation,pseudo-elements'),
