4px;\n}\n.wrap {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n  position: relative;\n  z-index: 10;\n  border: 0.5px solid #525252;\n  border-radius: 8px;\n  overflow: hidden;\n}\n.terminal {\n  display: flex;\n  flex-direction: column;\n\n  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas,\n    "Liberation Mono", "Courier New", monospace;\n}\n.head {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  overflow: hidden;\n  min-height: 40px;\n  padding-inline: 12px;\n  border-top-left-radius: 8px;\n  border-top-right-radius: 8px;\n  background-color: #202425;\n}\n.title {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  height: 2.5rem;\n  user-select: none;\n  font-weight: 600;\n  overflow: hidden;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n  color: #8e8e8e;\n}\n.title > svg {\n  height: 18px;\n  width: 18px;\n  margin-top: 2px;\n  color: #006adc;\n}\n.copy_toggle {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  padding: 0.25rem;\n  border: 0.65px solid #c1c2c5;\n  margin-left: auto;\n  border-radius: 6px;\n  background-color: #202425;\n  color: #8e8e8e;\n  cursor: pointer;\n}\n.copy_toggle > svg {\n  width: 20px;\n  height: 20px;\n}\n.copy_toggle:active > svg > path,\n.copy_toggle:focus-within > svg > path {\n  animation: clipboard-check 500ms linear forwards;\n}\n.body {\n  display: flex;\n  flex-direction: column;\n  position: relative;\n  border-bottom-right-radius: 8px;\n  border-bottom-left-radius: 8px;\n  overflow-x: auto;\n  padding: 1rem;\n  line-height: 19px;\n  color: white;\n  background-color: black;\n  white-space: nowrap;\n}\n.pre {\n  display: flex;\n  flex-direction: row;\n  align-items: center;\n  text-wrap: nowrap;\n  white-space: pre;\n  background-c', colors: '#e34ba9,#525252,#8e8e8e,#575757,#c5c5c5,#c1c2c5,#d9d9d92f,#202425,#006adc,#fff', radii: '6px,12px,8px', shadows: '', techniques: 'glassmorphism,3d-transform,animation,svg-icon,pseudo-elements'),
