const GalaxyComp(id: 'Javierrocadev_wonderful-bobcat-57', cat: 'Cards', author: 'Javierrocadev', tags: 'card,star,rotate,hover effect,trophy,winner', html: '<div class="container">\n   <svg class="svg-icon" height="100" preserveAspectRatio="xMidYMid meet" viewBox="0 0 100 100" width="100" x="0" xmlns="http://www.w3.org/2000/svg" y="0">\n    <path d="M62.11,53.93c22.582-3.125,22.304-23.471,18.152-29.929-4.166-6.444-10.36-2.153-10.36-2.153v-4.166H30.099v4.166s-6.194-4.291-10.36,2.153c-4.152,6.458-4.43,26.804,18.152,29.929l5.236,7.777v8.249s-.944,4.597-4.833,4.986c-3.903,.389-7.791,4.028-7.791,7.374h38.997c0-3.347-3.889-6.986-7.791-7.374-3.889-.389-4.833-4.986-4.833-4.986v-8.249l5.236-7.777Zm7.388-24.818s2.833-3.097,5.111-1.347c2.292,1.75,2.292,15.86-8.999,18.138l3.889-16.791Zm-44.108-1.347c2.278-1.75,5.111,1.347,5.111,1.347l3.889,16.791c-11.291-2.278-11.291-16.388-8.999-18.138Z">\n    </path>\n  </svg>  \n  <div class="container__star">\n     \n    <div class="star-eight"></div>\n  </div>\n  \n<div></div></div>', css: '\n/* From Uiverse.io by Javierrocadev - Tags: card, star, rotate, hover effect, trophy, winner */\n.container {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  font-size: 5em;\n  font-weight: 900;\n  color: #e10600;\n  position: relative;\n  transition: all 1s ease;\n  text-align: center;\n}\n\n.container__star {\n  transition: all .7s ease-in-out;\n}\n\n.first {\n  position: absolute;\n  top: 20px;\n  left: 50px;\n  transition: all .7s ease-in-out;\n}\n\n.svg-icon {\n  position: absolute;\n  fill: #e94822;\n  z-index: 1;\n}\n\n.star-eight {\n  background: #efd510;\n  width: 150px;\n  height: 150px;\n  position: relative;\n  text-align: center;\n  animation: rot 3s  infinite;\n}\n\n.star-eight::before {\n  content: \'\';\n  position: absolute;\n  top: 0;\n  left: 0;\n  height: 150px;\n  width: 150px;\n  background: #efd510;\n  transform: rotate(135deg);\n}\n\n.container:hover .container__star {\n  transform: rotateX(70deg) translateY(250px);\n  box-shadow: 0px 0px 120px -100px #e4e727;\n}\n\n.container:hover .svg-icon {\n  animation: grow 1s linear infinite;\n}\n\n@keyframes rot {\n  0% {\n    transform: rotate(0deg);\n  }\n\n  50% {\n    transform: rotate(340deg);\n  }\n\n  100% {\n    transform: rotate(0deg);\n  }\n}\n\n@keyframes grow {\n  0% {\n    transform: rotate(0deg);\n  }\n\n  25% {\n    transform: rotate(-5deg);\n  }\n\n  75% {\n    transform: rotate(5deg);\n  }\n\n  100% {\n    transform: scale(1) rotate(0deg);\n  }\n}\n', colors: '#e4e727,#efd510,#e94822,#e10600', radii: '', shadows: '0px 0px 120px -100px #e4e727', techniques: '3d-transform,glow-shadow,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'JkHuger_nice-walrus-27', cat: 'Cards', author: 'JkHuger', tags: 'card', html: '<div class="card">\n    <div class="heading">Join the Open-Source <span>Galaxy</span></div>\n    <div class="content">\n        <div class="item item--create">\n            <svg height="24" width="24" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">\n                <path d="M24 12L18.3431 17.6569L16.9289 16.2426L21.1716 12L16.9289 7.75736L18.3431 6.34315L24 12ZM2.82843 12L7.07107 16.2426L5.65685 17.6569L0 12L5.65685 6.34315L7.07107 7.75736L2.82843 12ZM9.78845 21H7.66009L14.2116 3H16.3399L9.78845 21Z" fill="currentColor"></path>\n            </svg>\n            <span>Create</span>\n        </div>\n        <div class="item item--post">\n            <svg height="24" width="24" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">\n                <path d="M4.99958 12.9998C4.99958 7.91186 7.90222 3.56348 11.9996 1.81787C16.0969 3.56348 18.9996 7.91186 18.9996 12.9998C18.9996 13.8227 18.9236 14.6263 18.779 15.4026L20.7194 17.2352C20.8845 17.3911 20.9238 17.6388 20.815 17.8381L18.3196 22.4132C18.1873 22.6556 17.8836 22.7449 17.6412 22.6127C17.5993 22.5898 17.5608 22.5611 17.5271 22.5273L15.2925 20.2927C15.1049 20.1052 14.8506 19.9998 14.5854 19.9998H9.41379C9.14857 19.9998 8.89422 20.1052 8.70668 20.2927L6.47209 22.5273C6.27683 22.7226 5.96025 22.7226 5.76498 22.5273C5.73122 22.4935 5.70246 22.4551 5.67959 22.4132L3.18412 17.8381C3.07537 17.6388 3.11464 17.3911 3.27975 17.2352L5.22014 15.4026C5.07551 14.6263 4.99958 13.8227 4.99958 12.9998ZM6.47542 19.6955L7.29247 18.8785C7.85508 18', css: '\n/* From Uiverse.io by JkHuger - Tags: card */\n.card {\n  background-color: #191c27;\n  border-radius: 15px;\n  box-shadow: 0 0 10px rgba(255, 255, 255, 0.2);\n  display: flex;\n  flex-direction: column;\n  justify-content: space-between;\n  color: white;\n  height: 210px;\n  width: 350px;\n}\n\n.heading {\n  color: #ffffff;\n  font-family: \'Orbitron\', sans-serif;\n  font-size: 28px;\n  margin: 20px;\n  text-shadow: 0 0 5px #ffffff;\n}\n\n.content {\n  display: flex;\n  flex-direction: row;\n  justify-content: space-around;\n  margin-bottom: 20px;\n}\n\n.item {\n  align-items: center;\n  background-color: #343a4b;\n  border-radius: 10px;\n  display: flex;\n  flex-direction: column;\n  height: 80px;\n  justify-content: center;\n  width: 100px;\n  transition: transform 0.2s ease-in-out;\n  margin: 10px;\n}\n\n.item:hover {\n  transform: translateY(-10px);\n}\n\n.item svg {\n  fill: #ffffff;\n  height: 40px;\n  margin-bottom: 10px;\n  width: 40px;\n}\n\n.item--create svg {\n  animation: spin 2s linear infinite;\n}\n\n.item--post svg {\n  animation: upDown 2s ease-in-out infinite alternate;\n}\n\n.item--inspire svg {\n  animation: flash 1.2s linear infinite;\n}\n\n@keyframes spin {\n  100% {\n    transform: rotate(360deg);\n  }\n}\n\n@keyframes upDown {\n  0% {\n    transform: translateY(1.8px);\n  }\n\n  100% {\n    transform: translateY(-1.8px);\n  }\n}\n\n@keyframes flash {\n  0% {\n    opacity: 1;\n  }\n\n  50% {\n    opacity: 0;\n  }\n\n  100% {\n    opacity: 1;\n  }\n}\n\n.item span {\n  color: #ffffff;\n  font-family: \'Orbitron\', sans-serif;\n  font-size: 18px;\n  text-shadow: 0 0 5px #ffffff;\n}\n\n.item--create:hover {\n  background-color: #6d9eeb;\n  transition: transform .35s ease-in-out;\n}\n\n.item--post:hover {\n  background-color: #f4b41a;\n  transition: transform .35s ease-in-out;\n}\n\n.item--inspire:hover {\n  background-color: #eb6d6d;\n  transition: transform .35s ease-in-out;\n}\n\nbutton {\n  background-color: #2E4057;\n  border: none;\n  border-radius: 5px;\n  color: white;\n  cursor: pointer;\n  font-size: 16px;\n  font-weight: bold;\n  padding: 10px 20px;\n  transiti', colors: '#f4b41a,#3e5368,#343a4b,#6d9eeb,#eb6d6d,#2e4057,#ffffff,#191c27', radii: '15px,10px,5px', shadows: '0 0 10px rgba(255, 255, 255, 0.2),2px 2px 5px rgba(0, 0, 0, 0.3)', techniques: '3d-transform,glow-shadow,text-shadow,animation,svg-icon')