const GalaxyComp(id: 'joe-watson-sbf_wise-quail-35', cat: 'Cards', author: 'joe-watson-sbf', tags: 'summary,card,hover,card template,cardhover,card animation,card hover', html: '<div class="card">\n    <div class="header">\n        <div class="img-box">\n            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">\n                <path fill="none" d="M0 0h24v24H0z"></path>\n                <path d="M20.083 15.2l1.202.721a.5.5 0 0 1 0 .858l-8.77 5.262a1 1 0 0 1-1.03 0l-8.77-5.262a.5.5 0 0 1 0-.858l1.202-.721L12 20.05l8.083-4.85zm0-4.7l1.202.721a.5.5 0 0 1 0 .858L12 17.65l-9.285-5.571a.5.5 0 0 1 0-.858l1.202-.721L12 15.35l8.083-4.85zm-7.569-9.191l8.771 5.262a.5.5 0 0 1 0 .858L12 13 2.715 7.429a.5.5 0 0 1 0-.858l8.77-5.262a1 1 0 0 1 1.03 0zM12 3.332L5.887 7 12 10.668 18.113 7 12 3.332z" fill="rgba(66,193,110,1)"></path>\n            </svg>\n        </div>\n        <span class="title">Features\n    </span></div>\n\n    <div class="content">\n        <p>\n            Lorem ipsum dolor sit tali amet, consectus uy\n            adipiscing it amet it...\n        </p>\n\n        <a class="btn-link">Read More...</a>\n    </div>\n</div>', css: '\n/* From Uiverse.io by joe-watson-sbf - Tags: summary, card, hover, card template, cardhover , card animation, card hover */\n.card {\n  width: 190px;\n  height: 120px;\n  transition: all .5s;\n  box-shadow: 15px 15px 30px rgba(25, 25, 25, 0.11),\n             -15px -15px 30px rgba(60, 60, 60, 0.082);\n  text-align: center;\n  overflow: hidden;\n}\n\n.card:hover {\n  height: 260px;\n  background: linear-gradient(360deg, #edededc5 60%, hsla(0, 0%, 13%, 1) 70%);\n}\n\n.card .header {\n  padding: 20px;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  background: #212121;\n  margin-bottom: 16px;\n}\n\n.card .header .img-box {\n  width: 50px;\n}\n\n.card .header .title {\n  font-size: 1em;\n  letter-spacing: .1em;\n  font-weight: 900;\n  text-transform: uppercase;\n  padding: 4px 0 14px 0;\n  transition: all .5s;\n  color: #edededc5;\n}\n\n.card:hover .header {\n  clip-path: polygon(0 0, 100% 0, 100% 100%, 0 96%);\n}\n\n.card:hover .card .header .title {\n  padding: 0;\n}\n\n.card .content {\n  display: block;\n  text-align: left;\n  color: #212121;\n  margin: 0 18px;\n}\n\n.card .content p {\n  transition: all .5s;\n  font-size: .8em;\n  margin-bottom: 8px;\n}\n\n.card .content a {\n  color: #1d8122;\n  cursor: pointer;\n  transition: all .5s;\n  font-size: .7rem;\n  font-weight: 700;\n  text-transform: uppercase;\n}\n\n.card .content .btn-link:hover {\n  border-bottom: 1px solid #1d8122;\n}\n', colors: '#212121,#1d8122,#edededc5', radii: '', shadows: '15px 15px 30px rgba(25, 25, 25, 0.11),\n             -15px -15px 30px rgba(60, 60, 60, 0.082)', techniques: 'glow-shadow,gradient,clip-path,typography-transform,svg-icon'),
