n;\n  box-shadow: 0 4px 10px rgba(0, 0, 0, 0.1);\n  position: relative;\n  box-sizing: border-box;\n  overflow: hidden;\n  cursor: pointer;\n}\n\n.cls-1 {\n  fill: #fff;\n}\n\n.title {\n  font-size: 36px;\n  font-weight: 600;\n  color: #ffffff;\n  margin-bottom: 12px;\n}\n\n.label {\n  font-size: 18px;\n  color: #ffffff;\n  opacity: 0.8;\n  line-height: 1.4;\n  font-weight: 300;\n}\n\n.ico {\n  position: absolute;\n  bottom: 16px;\n  left: 92px;\n  display: flex;\n  gap: 32px;\n  opacity: 0;\n  transition: left 0.3s ease, opacity 0.3s ease;\n}\n\n.card::before {\n  content: "";\n  position: absolute;\n  left: 0;\n  top: 0;\n  bottom: 0;\n  width: 5px;\n  background-image: linear-gradient(to bottom, #0085d7, #5cc9ff);\n  border-radius: 8px 0 0 8px;\n  transition: width 0.3s ease;\n}\n\n.card:hover::before {\n  width: 10px;\n}\n\n.card:hover {\n  border-left-width: 10px;\n}\n\n.title,\n.label {\n  transition: transform 0.3s ease;\n}\n\n.card:hover .title,\n.card:hover .label {\n  transform: translateX(20px);\n}\n\n.card:hover .ico {\n  left: 52px;\n  opacity: 0.3;\n}\n\n.gradient {\n  position: absolute;\n  top: -200px;\n  left: -200px;\n  width: 600px;\n  height: 600px;\n  background: #ffffff;\n  border-radius: 50%;\n  filter: blur(200px);\n  opacity: 0;\n  transition: opacity 0.3s ease;\n}\n\n.card:hover .gradient {\n  opacity: 0.04;\n}\n\n', colors: '#0085d7,#5cc9ff,#ffffff,#fff', radii: '50%,8px 0 0 8px,8px', shadows: '0 4px 10px rgba(0, 0, 0, 0.1)', techniques: 'glassmorphism,glow-shadow,gradient,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'KareemTolan_funny-pug-52', cat: 'Cards', author: 'KareemTolan', tags: 'card', html: '<div class="card">\n    <div class="heading">Join the Open-Source <span>Galaxy</span></div>\n    <div class="content">\n        <div class="item item--create">\n            <svg height="24" width="24" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">\n                <path d="M24 12L18.3431 17.6569L16.9289 16.2426L21.1716 12L16.9289 7.75736L18.3431 6.34315L24 12ZM2.82843 12L7.07107 16.2426L5.65685 17.6569L0 12L5.65685 6.34315L7.07107 7.75736L2.82843 12ZM9.78845 21H7.66009L14.2116 3H16.3399L9.78845 21Z" fill="currentColor"></path>\n            </svg>\n            <span>Create</span>\n        </div>\n        <div class="item item--post">\n            <svg height="24" width="24" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">\n                <path d="M4.99958 12.9998C4.99958 7.91186 7.90222 3.56348 11.9996 1.81787C16.0969 3.56348 18.9996 7.91186 18.9996 12.9998C18.9996 13.8227 18.9236 14.6263 18.779 15.4026L20.7194 17.2352C20.8845 17.3911 20.9238 17.6388 20.815 17.8381L18.3196 22.4132C18.1873 22.6556 17.8836 22.7449 17.6412 22.6127C17.5993 22.5898 17.5608 22.5611 17.5271 22.5273L15.2925 20.2927C15.1049 20.1052 14.8506 19.9998 14.5854 19.9998H9.41379C9.14857 19.9998 8.89422 20.1052 8.70668 20.2927L6.47209 22.5273C6.27683 22.7226 5.96025 22.7226 5.76498 22.5273C5.73122 22.4935 5.70246 22.4551 5.67959 22.4132L3.18412 17.8381C3.07537 17.6388 3.11464 17.3911 3.27975 17.2352L5.22014 15.4026C5.07551 14.6263 4.99958 13.8227 4.99958 12.9998ZM6.47542 19.6955L7.29247 18.8785C7.85508 18', css: '\n/* From Uiverse.io by KareemTolan - Tags: card */\n.card {\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  align-items: center;\n  background-color: rgba(0, 0, 0, 0.7);\n  border-radius: 10px;\n  box-shadow: 0px 4px 10px rgba(0, 0, 0, 0.2);\n  padding: 40px 20px;\n  color: #fff;\n  font-size: 1.2rem;\n}\n\n.heading {\n  font-size: 2rem;\n  font-weight: bold;\n  margin-bottom: 20px;\n  text-align: center;\n  text-transform: uppercase;\n}\n\n.heading span {\n  color: #03DAC6;\n}\n\n.content {\n  display: flex;\n  flex-wrap: wrap;\n  justify-content: center;\n  align-items: center;\n  margin-bottom: 30px;\n}\n\n.item {\n  display: flex;\n  align-items: center;\n  margin: 0 20px;\n  color: #fff;\n  font-size: 1.2rem;\n  text-transform: uppercase;\n  transition: all 0.2s ease-in-out;\n  cursor: pointer;\n}\n\n.item:hover {\n  transform: scale(1.05);\n  color: #03DAC6;\n  text-shadow: 0px 0px 20px #03DAC6;\n}\n\n.item svg {\n  width: 30px;\n  height: 30px;\n  margin-right: 10px;\n}\n\n.item--create svg path {\n  fill: #03DAC6;\n}\n\n.item--post svg path {\n  fill: #BB86FC;\n}\n\n.item--inspire svg path {\n  fill: #FF9800;\n}\n\nbutton {\n  background-color: #03DAC6;\n  border: none;\n  border-radius: 5px;\n  color: #212121;\n  font-size: 1.2rem;\n  font-weight: bold;\n  padding: 10px 20px;\n  cursor: pointer;\n  transition: all 0.2s ease-in-out;\n}\n\nbutton:hover {\n  background-color: #BB86FC;\n  box-shadow: 0px 0px 20px #BB86FC, 0px 0px 40px #BB86FC, 0px 0px 60px #BB86FC;\n}\n', colors: '#212121,#ff9800,#bb86fc,#fff,#03dac6', radii: '10px,5px', shadows: '0px 4px 10px rgba(0, 0, 0, 0.2),0px 0px 20px #BB86FC, 0px 0px 40px #BB86FC, 0px 0px 60px #BB86FC', techniques: '3d-transform,glow-shadow,text-shadow,typography-transform,svg-icon'),
const GalaxyComp(id: 'kennyotsu_witty-deer-12', cat: 'Cards', author: 'kennyotsu', tags: 'complex,3d,card', html: '<div class="container noselect">\n  <div class="canvas">\n    <div class="tracker tr-1"></div>\n    <div class="tracker tr-2"></div>\n    <div class="tracker tr-3"></div>\n    <div class="tracker tr-4"></div>\n    <div class="tracker tr-5"></div>\n    <div class="tracker tr-6"></div>\n    <div class="tracker tr-7"></div>\n    <div class="tracker tr-8"></div>\n    <div class="tracker tr-9"></div>\n    <div class="tracker tr-10"></div>\n    <div class="tracker tr-11"></div>\n    <div class="tracker tr-12"></div>\n    <div class="tracker tr-13"></div>\n    <div class="tracker tr-14"></div>\n    <div class="tracker tr-15"></div>\n    <div class="tracker tr-16"></div>\n    <div class="tracker tr-17"></div>\n    <div class="tracker tr-18"></div>\n    <div class="tracker tr-19"></div>\n    <div class="tracker tr-20"></div>\n    <div class="tracker tr-21"></div>\n    <div class="tracker tr-22"></div>\n    <div class="tracker tr-23"></div>\n    <div class="tracker tr-24"></div>\n    <div class="tracker tr-25"></div>\n    <div id="card">\n    <p id="prompt">HOVER OVER :D</p>\n      <div class="title">look mom,<br>no JS</div>\n      <div class="subtitle">\n        mouse hover tracker\n      </div>\n      \n    </div>\n  </div>\n</div>', css: '\n/* From Uiverse.io by kennyotsu - Tags: complex, 3d, card */\n/*works janky on mobile :<*/\n.container {\n  position: relative;\n  width: 190px;\n  height: 254px;\n  transition: 200ms;\n}\n\n.container:active {\n  width: 180px;\n  height: 245px;\n}\n\n#card {\n  position: absolute;\n  inset: 0;\n  z-index: 0;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  border-radius: 20px;\n  transition: 700ms;\n  background: linear-gradient(43deg, rgb(65, 88, 208) 0%, rgb(200, 80, 192) 46%, rgb(255, 204, 112) 100%);\n}\n\n.subtitle {\n  transform: translateY(160px);\n  color: rgb(134, 110, 221);\n  text-align: center;\n  width: 100%;\n}\n\n.title {\n  opacity: 0;\n  transition-duration: 300ms;\n  transition-timing-function: ease-in-out-out;\n  transition-delay: 100ms;\n  position: absolute;\n  font-size: x-large;\n  font-weight: bold;\n  color: white;\n}\n\n.tracker:hover ~ #card .title {\n  opacity: 1;\n}\n\n#prompt {\n  bottom: 8px;\n  left: 12px;\n  z-index: 20;\n  font-size: 20px;\n  font-weight: bold;\n  transition: 300ms ease-in-out-out;\n  position: absolute;\n  max-width: 110px;\n  color: rgb(255, 255, 255);\n}\n\n.tracker {\n  position: absolute;\n  z-index: 200;\n  width: 100%;\n  height: 100%;\n}\n\n.tracker:hover {\n  cursor: pointer;\n}\n\n.tracker:hover ~ #card #prompt {\n  opacity: 0;\n}\n\n.tracker:hover ~ #card {\n  transition: 300ms;\n  filter: brightness(1.1);\n}\n\n.container:hover #card::before {\n  transition: 200ms;\n  content: \'\';\n  opacity: 80%;\n}\n\n.canvas {\n  perspective: 800px;\n  inset: 0;\n  z-index: 200;\n  position: absolute;\n  display: grid;\n  grid-template-columns: 1fr 1fr 1fr 1fr 1fr;\n  grid-template-rows: 1fr 1fr 1fr 1fr 1fr;\n  gap: 0px 0px;\n  grid-template-areas: "tr-1 tr-2 tr-3 tr-4 tr-5"\n    "tr-6 tr-7 tr-8 tr-9 tr-10"\n    "tr-11 tr-12 tr-13 tr-14 tr-15"\n    "tr-16 tr-17 tr-18 tr-19 tr-20"\n    "tr-21 tr-22 tr-23 tr-24 tr-25";\n}\n\n#card::before {\n  content: \'\';\n  background: linear-gradient(43deg, rgb(65, 88, 208) 0%, rgb(200, 80, 192) 46%, rgb(255, 204, 112) 100%);\n  filter: blur(2rem);\n  opacity: 3', colors: '', radii: '20px', shadows: '', techniques: 'glassmorphism,3d-transform,gradient,perspective,pseudo-elements'),
const GalaxyComp(id: 'KhaledMatalkah_fuzzy-bullfrog-8', cat: 'Cards', author: 'KhaledMatalkah', tags: 'animation,card,hover,cube', html: '<div class="cube-container">\n  <div class="cube">\n    <div class="face front">Front</div>\n    <div class="face back">Back</div>\n    <div class="face right">Right</div>\n    <div class="face left">Left</div>\n    <div class="face top">Top</div>\n    <div class="face bottom">Bottom</div>\n  </div>\n</div>', css: '\n/* From Uiverse.io by KhaledMatalkah - Tags: animation, card, hover, cube */\n.cube-container {\n  width: 200px;\n  height: 200px;\n  perspective: 800px;\n  margin: 50px auto;\n}\n\n.cube {\n  position: relative;\n  width: 100%;\n  height: 100%;\n  transform-style: preserve-3d;\n  animation: rotate 8s infinite linear;\n}\n\n.face {\n  position: absolute;\n  width: 200px;\n  height: 200px;\n  color: rgb(214, 21, 21);\n  font-size: 18px;\n  text-align: center;\n  line-height: 200px;\n  background: transparent;\n  opacity: 0.9;\n  border: 2px solid;\n  border-image: linear-gradient(to right, #ff6b6b, #355c7d, #557d35, #cfcf16, #a51f1f) 1;\n  box-shadow: 0 0 100px rgba(245, 8, 8, 0.8);\n}\n\n.front {\n  transform: translateZ(100px);\n}\n\n.back {\n  transform: rotateY(180deg) translateZ(100px);\n}\n\n.right {\n  transform: rotateY(90deg) translateZ(100px);\n}\n\n.left {\n  transform: rotateY(-90deg) translateZ(100px);\n}\n\n.top {\n  transform: rotateX(90deg) translateZ(100px);\n}\n\n.bottom {\n  transform: rotateX(-90deg) translateZ(100px);\n}\n\n.cube-container:hover .cube {\n  animation-play-state: paused;\n}\n\n@keyframes rotate {\n  0% {\n    transform: rotateX(0) rotateY(0) rotateZ(0);\n  }\n\n  100% {\n    transform: rotateX(360deg) rotateY(360deg) rotateZ(360deg);\n  }\n}\n\n', colors: '#ff6b6b,#557d35,#cfcf16,#a51f1f,#355c7d', radii: '', shadows: '0 0 100px rgba(245, 8, 8, 0.8)', techniques: '3d-transform,glow-shadow,gradient,animation,perspective'),
const GalaxyComp(id: 'Lmickk2_wonderful-robin-20', cat: 'Cards', author: 'Lmickk2', tags: 'card,space,creative,inset', html: '<div class="card">\n    <div class="heading">Join the Open-Source <span>Galaxy</span></div>\n    <div class="content">\n        <div class="item item--create">\n            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="24" height="24">\n                <path fill="currentColor" d="M24 12L18.3431 17.6569L16.9289 16.2426L21.1716 12L16.9289 7.75736L18.3431 6.34315L24 12ZM2.82843 12L7.07107 16.2426L5.65685 17.6569L0 12L5.65685 6.34315L7.07107 7.75736L2.82843 12ZM9.78845 21H7.66009L14.2116 3H16.3399L9.78845 21Z"></path>\n            </svg>\n            <span>Create</span>\n        </div>\n        <div class="item item--post">\n            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="24" height="24">\n                <path fill="currentColor" d="M4.99958 12.9998C4.99958 7.91186 7.90222 3.56348 11.9996 1.81787C16.0969 3.56348 18.9996 7.91186 18.9996 12.9998C18.9996 13.8227 18.9236 14.6263 18.779 15.4026L20.7194 17.2352C20.8845 17.3911 20.9238 17.6388 20.815 17.8381L18.3196 22.4132C18.1873 22.6556 17.8836 22.7449 17.6412 22.6127C17.5993 22.5898 17.5608 22.5611 17.5271 22.5273L15.2925 20.2927C15.1049 20.1052 14.8506 19.9998 14.5854 19.9998H9.41379C9.14857 19.9998 8.89422 20.1052 8.70668 20.2927L6.47209 22.5273C6.27683 22.7226 5.96025 22.7226 5.76498 22.5273C5.73122 22.4935 5.70246 22.4551 5.67959 22.4132L3.18412 17.8381C3.07537 17.6388 3.11464 17.3911 3.27975 17.2352L5.22014 15.4026C5.07551 14.6263 4.99958 13.8227 4.99958 12.9998ZM6.47542 19.6955L7.2924', css: '\n/* From Uiverse.io by Lmickk2 - Tags: card, space, creative, inset */\n.card {\n  border-radius: 1em;\n  padding: 2em;\n  color: white;\n  box-shadow: inset 3px 3px 10px black;\n}\n\n.heading {\n  font-weight: bold;\n}\n\n.item {\n  margin-top: 1em;\n  text-align: center;\n}\n\n.item span {\n  display: block;\n}\n\n.item--create svg:hover {\n  filter: drop-shadow(0px 0px 3px #ffffff);\n  font-weight: bold;\n}\n\n.item--post svg:hover {\n  filter: drop-shadow(0px 0px 3px #ff09f3);\n}\n\n.item--inspire svg:hover {\n  filter: drop-shadow(0px 0px 3px #efff0a);\n}\n\nbutton {\n  margin: auto;\n  display: block;\n  margin-top: 2em;\n  padding: 0.8em;\n  border-radius: 0.5em;\n  border: none;\n  background: transparent;\n  box-shadow: inset 2px 2px 5px black;\n  color: white;\n  transition: background 0.4s;\n  font-weight: 600;\n}\n\nbutton:hover {\n  animation: bg-change 5s infinite;\n  box-shadow: inset 3px 3px 4px black;\n  background: linear-gradient(0deg, rgb(97, 4, 55), rgb(148, 31, 128), rgb(40, 10, 88));\n  background-size: 400% 400%;\n}\n\n@keyframes bg-change {\n  0% {\n    background-position: 50% 0%\n  }\n\n  50% {\n    background-position: 50% 100%\n  }\n\n  100% {\n    background-position: 50% 0%\n  }\n}\n', colors: '#efff0a,#ffffff,#ff09f3', radii: '0.5em,1em', shadows: 'inset 3px 3px 10px black,inset 2px 2px 5px black,inset 3px 3px 4px black', techniques: 'glow-shadow,gradient,animation,filter-effect,svg-icon'),
const GalaxyComp(id: 'Madflows_great-chipmunk-4', cat: 'Cards', author: 'Madflows', tags: 'card', html: '<div class="card">\n<header class="card-header">\n  <p>May 3rd 2023</p>\n  <span class="title">A Tale of Two Divs</span>\n</header>\n<div class="card-author">\n  <a class="author-avatar" href="#">\n    <span>\n  </span></a>\n  <svg class="half-circle" viewBox="0 0 106 57">\n    <path d="M102 4c0 27.1-21.9 49-49 49S4 31.1 4 4"></path>\n  </svg>\n  <div class="author-name">\n    <div class="author-name-prefix">Author</div> Folarin Lawal\n    </div>\n  </div>\n  <div class="tags">\n    <a href="#">html</a>\n    <a href="#">css</a>\n    <a href="#">web-dev</a>\n  </div>\n</div>', css: '\n/* From Uiverse.io by Madflows - Tags: card */\n.card {\n  display: flex;\n  position: relative;\n  flex-direction: column;\n  height: 350px;\n  width: 190px;\n  min-width: 250px;\n  padding: 1rem;\n  border-radius: 16px;\n  background: #17141d;\n  box-shadow: -1rem 0 3rem #00000067;\n  transition: .2s;\n  font-family: \'Inter\', sans-serif;\n}\n\n.card:hover {\n  transform: translateY(-0.4rem);\n}\n\n.card-author {\n  position: relative;\n  display: grid;\n  grid-template-columns: 75px 1fr;\n  align-items: center;\n  margin: 3rem 0 0;\n}\n\n.author-name {\n  color: #7a7a8c;\n}\n\n.author-name-prefix {\n  color: #e52e71;\n  font-weight: 600;\n}\n\n.author-avatar span {\n  display: block;\n  width: 40px;\n  height: 40px;\n  border-radius: 50%;\n  background: #f2f2f2;\n  margin: 16px 10px;\n}\n\n.half-circle {\n  position: absolute;\n  bottom: 0;\n  left: 0;\n  width: 60px;\n  height: 48px;\n  fill: none;\n  stroke: #ff8a00;\n  stroke-width: 8;\n  stroke-linecap: round;\n}\n\n.card-header {\n  margin-bottom: auto;\n  color: #7a7a8c;\n}\n\n.card-header p {\n  font-size: 14px;\n  margin: 0 0 1rem;\n  color: #7a7a8c;\n}\n\n.card-header .title {\n  font-size: 25px;\n  margin: .25rem 0 auto;\n  cursor: pointer;\n  font-family: \'Arial Black\', sans-serif;\n}\n\n.card-header .title:hover {\n  background: linear-gradient(90deg,#ff8a00,#e52e71);\n  text-shadow: none;\n  background-clip: text;\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n}\n\n.tags {\n  margin: 1rem 0 2rem;\n  padding: .5rem 0 1rem;\n  line-height: 2;\n  margin-bottom: 0;\n}\n\n.tags a {\n  font-style: normal;\n  font-weight: 700;\n  color: #7a7a8c;\n  text-transform: uppercase;\n  font-size: .66rem;\n  border: 3px solid #28242f;\n  border-radius: 2rem;\n  padding: .2rem .85rem .25rem;\n  position: relative;\n}\n\n.tags a:hover {\n  background: linear-gradient(90deg,#ff8a00,#e52e71);\n  text-shadow: none;\n  -webkit-text-fill-color: transparent;\n  -webkit-background-clip: text;\n  -webkit-box-decoration-break: clone;\n  box-decoration-break: clone;\n  background-clip: text;\n  border-color:', colors: '#ff8a00,#e52e71,#7a7a8c,#00000067,#17141d,#28242f,#f2f2f2', radii: '50%,16px,2rem', shadows: '-1rem 0 3rem #00000067', techniques: 'glow-shadow,text-shadow,gradient,typography-transform,svg-icon'),
const GalaxyComp(id: 'MijailVillegas_smooth-firefox-47', cat: 'Cards', author: 'MijailVillegas', tags: 'card', html: '<div class="card">\n    <div class="heading">Join the Open-Source <span>Galaxy</span></div>\n    <div class="content">\n        <div class="item item--create">\n            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="24" height="24">\n                <path fill="currentColor" d="M24 12L18.3431 17.6569L16.9289 16.2426L21.1716 12L16.9289 7.75736L18.3431 6.34315L24 12ZM2.82843 12L7.07107 16.2426L5.65685 17.6569L0 12L5.65685 6.34315L7.07107 7.75736L2.82843 12ZM9.78845 21H7.66009L14.2116 3H16.3399L9.78845 21Z"></path>\n            </svg>\n            <span>Create</span>\n        </div>\n        <div class="item item--post">\n            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="24" height="24">\n                <path fill="currentColor" d="M4.99958 12.9998C4.99958 7.91186 7.90222 3.56348 11.9996 1.81787C16.0969 3.56348 18.9996 7.91186 18.9996 12.9998C18.9996 13.8227 18.9236 14.6263 18.779 15.4026L20.7194 17.2352C20.8845 17.3911 20.9238 17.6388 20.815 17.8381L18.3196 22.4132C18.1873 22.6556 17.8836 22.7449 17.6412 22.6127C17.5993 22.5898 17.5608 22.5611 17.5271 22.5273L15.2925 20.2927C15.1049 20.1052 14.8506 19.9998 14.5854 19.9998H9.41379C9.14857 19.9998 8.89422 20.1052 8.70668 20.2927L6.47209 22.5273C6.27683 22.7226 5.96025 22.7226 5.76498 22.5273C5.73122 22.4935 5.70246 22.4551 5.67959 22.4132L3.18412 17.8381C3.07537 17.6388 3.11464 17.3911 3.27975 17.2352L5.22014 15.4026C5.07551 14.6263 4.99958 13.8227 4.99958 12.9998ZM6.47542 19.6955L7.2924', css: '\n/* From Uiverse.io by MijailVillegas - Tags: card */\n.card {\n  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;\n  font-weight: bolder;\n  color: hsla(0, 0%, 0%, 0.3);\n  z-index: 1;\n  width: 280px;\n  height: 400px;\n  display: grid;\n  justify-items: center;\n  align-items: center;\n  align-content: space-around;\n  text-align: center;\n  grid-template-rows: 0.25fr 0.5fr 0.25fr;\n  padding: 1em;\n  border-radius: 3em;\n  border: solid 0.5em #fafafa;\n  background: #fafafa;\n  background-image: url("data:image/svg+xml;base64,', colors: '#4fd1c4,#5ef8e9,#ffffff,#e0fff8,#afafaf,#57e9db,#d5d5d5,#48beb3,#68ffff,#47bfb4', radii: '3em,1em,5em', shadows: '5px 5px 7px hsla(0, 0%, 84%, 0.447), -3px -4px 7px rgba(255, 255, 255, 0.3843137255),3px 3px 5px #48beb3, -3px -3px 5px #68ffff,inset 3px 3px 5px #47bfb4, inset -3px -3px 5px #67ffff', techniques: 'glassmorphism,text-shadow,gradient,animation,svg-icon'),
const GalaxyComp(id: 'MikeAndrewDesigner_fast-octopus-78', cat: 'Cards', author: 'MikeAndrewDesigner', tags: 'animation,card,colorful,wave,cool card', html: '<div class="e-card playing">\n  <div class="image"></div>\n  \n  <div class="wave"></div>\n  <div class="wave"></div>\n  <div class="wave"></div>\n  \n\n      <div class="infotop">\n\n    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" class="icon">\n  <path fill="currentColor" d="M19.4133 4.89862L14.5863 2.17544C12.9911 1.27485 11.0089 1.27485 9.41368 2.17544L4.58674\n  4.89862C2.99153 5.7992 2 7.47596 2 9.2763V14.7235C2 16.5238 2.99153 18.2014 4.58674 19.1012L9.41368\n  21.8252C10.2079 22.2734 11.105 22.5 12.0046 22.5C12.6952 22.5 13.3874 22.3657 14.0349 22.0954C14.2204\n  22.018 14.4059 21.9273 14.5872 21.8252L19.4141 19.1012C19.9765 18.7831 20.4655 18.3728 20.8651\n  17.8825C21.597 16.9894 22 15.8671 22 14.7243V9.27713C22 7.47678 21.0085 5.7992 19.4133 4.89862ZM4.10784\n  14.7235V9.2763C4.10784 8.20928 4.6955 7.21559 5.64066 6.68166L10.4676 3.95848C10.9398 3.69152 11.4701\n  3.55804 11.9996 3.55804C12.5291 3.55804 13.0594 3.69152 13.5324 3.95848L18.3593 6.68166C19.3045 7.21476\n  19.8922 8.20928 19.8922 9.2763V9.75997C19.1426 9.60836 18.377 9.53091 17.6022 9.53091C14.7929 9.53091\n  12.1041 10.5501 10.0309 12.3999C8.36735 13.8847 7.21142 15.8012 6.68783 17.9081L5.63981 17.3165C4.69466\n  16.7834 4.10699 15.7897 4.10699 14.7235H4.10784ZM10.4676 20.0413L8.60933 18.9924C8.94996 17.0479 9.94402\n  15.2665 11.4515 13.921C13.1353 12.4181 15.3198 11.5908 17.6022 11.5908C18.3804 11.5908 19.1477 11.6864\n  19.8922 11.8742V14.7235C19.8922 15.2278 19.7589 15.7254 19.5119 16.1662C1', css: '\n/* From Uiverse.io by MikeAndrewDesigner - Tags: animation, card, colorful, wave, cool card */\n.e-card {\n  margin: 100px auto;\n  background: transparent;\n  box-shadow: 0px 8px 28px -9px rgba(0,0,0,0.45);\n  position: relative;\n  width: 240px;\n  height: 330px;\n  border-radius: 16px;\n  overflow: hidden;\n}\n\n.wave {\n  position: absolute;\n  width: 540px;\n  height: 700px;\n  opacity: 0.6;\n  left: 0;\n  top: 0;\n  margin-left: -50%;\n  margin-top: -70%;\n  background: linear-gradient(744deg,#af40ff,#5b42f3 60%,#00ddeb);\n}\n\n.icon {\n  width: 3em;\n  margin-top: -1em;\n  padding-bottom: 1em;\n}\n\n.infotop {\n  text-align: center;\n  font-size: 20px;\n  position: absolute;\n  top: 5.6em;\n  left: 0;\n  right: 0;\n  color: rgb(255, 255, 255);\n  font-weight: 600;\n}\n\n.name {\n  font-size: 14px;\n  font-weight: 100;\n  position: relative;\n  top: 1em;\n  text-transform: lowercase;\n}\n\n.wave:nth-child(2),\n.wave:nth-child(3) {\n  top: 210px;\n}\n\n.playing .wave {\n  border-radius: 40%;\n  animation: wave 3000ms infinite linear;\n}\n\n.wave {\n  border-radius: 40%;\n  animation: wave 55s infinite linear;\n}\n\n.playing .wave:nth-child(2) {\n  animation-duration: 4000ms;\n}\n\n.wave:nth-child(2) {\n  animation-duration: 50s;\n}\n\n.playing .wave:nth-child(3) {\n  animation-duration: 5000ms;\n}\n\n.wave:nth-child(3) {\n  animation-duration: 45s;\n}\n\n@keyframes wave {\n  0% {\n    transform: rotate(0deg);\n  }\n\n  100% {\n    transform: rotate(360deg);\n  }\n}\n', colors: '#af40ff,#00ddeb,#5b42f3', radii: '16px,40%', shadows: '0px 8px 28px -9px rgba(0,0,0,0.45)', techniques: '3d-transform,gradient,animation,typography-transform,svg-icon'),
const GalaxyComp(id: 'milegelu_evil-panda-93', cat: 'Cards', author: 'milegelu', tags: 'card,modern,click,hover effect,click effect,card template,cardhover,card hover', html: '<div class="group">\n  <div class="card-box">\n    <div id="Hegel" class="card">\n      <div class="content">\n        <p class="some">\n          A film – also called a movie, motion picture, moving picture, picture,\n          photoplay or (slang) flick – is a work of visual art that simulates\n          experiences and otherwise communicates ideas, stories, perceptions,\n          feelings, beauty, or atmosphere through the use of moving images.\n          These images are generally accompanied by sound and, more rarely,\n          other sensory stimulations.[1] The word "cinema", short for\n          cinematography, is often used to refer to filmmaking and the film\n          industry, and the art form that is the result of it.\n        </p>\n      </div>\n      <div class="thumb">\n        <svg\n          viewBox="0 0 16 16"\n          class="bi bi-camera-reels"\n          fill="currentColor"\n          height="16"\n          width="16"\n          xmlns="http://www.w3.org/2000/svg"\n        >\n          <path\n            d="M6 3a3 3 0 1 1-6 0 3 3 0 0 1 6 0zM1 3a2 2 0 1 0 4 0 2 2 0 0 0-4 0z"\n          ></path>\n          <path\n            d="M9 6h.5a2 2 0 0 1 1.983 1.738l3.11-1.382A1 1 0 0 1 16 7.269v7.462a1 1 0 0 1-1.406.913l-3.111-1.382A2 2 0 0 1 9.5 16H2a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h7zm6 8.73V7.27l-3.5 1.555v4.35l3.5 1.556zM1 8v6a1 1 0 0 0 1 1h7.5a1 1 0 0 0 1-1V8a1 1 0 0 0-1-1H2a1 1 0 0 0-1 1z"\n          ></path>\n          <path\n            d="M9 6a3 3 0 1 0 0-6 3 3 0 0 0 0 6zM7 3a2 2 0 1 1 4', css: '\n/* From Uiverse.io by milegelu  - Tags: card, modern, click, hover effect, click effect, card template, cardhover , card hover */\n.card {\n  --card-width: 20em;\n  --primer-color: hsl(241, 100%, 70%);\n  --text-color: hsl(0, 0%, 100%);\n  --text-color-L2: hsl(0, 0%, 60%);\n  --transition: all 0.2s cubic-bezier(0.13, 0.78, 0.3, 0.99);\n  background: hsl(0, 0%, 10%);\n\n  font-size: 12px;\n  line-height: 2;\n\n  border-radius: 1em;\n  padding-bottom: 0.5em;\n  z-index: 20;\n  overflow: hidden;\n  display: flex;\n  flex-direction: column;\n\n  transition: all 0.2s ease-in;\n}\n.detial {\n  width: var(--card-width);\n  padding: 01em 1em;\n  color: var(--text-color);\n  transition: all 0.2s ease-in;\n\n  z-index: 1;\n}\n.name {\n  font-size: 2em;\n  font-weight: bold;\n}\n\n.title {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  margin: 0.5em 0;\n}\n\n.content {\n  color: var(--text-color);\n  width: var(--card-width);\n  position: absolute;\n  transform: rotate3D(0.4, 1, 0.4, 0deg) scale(0.4);\n  padding: 2em;\n  opacity: 0;\n  height: 20em;\n  overflow: hidden;\n}\n\n.thumb {\n  width: var(--card-width);\n  height: 20em;\n  overflow: hidden;\n  transition: var(--transition);\n\n  z-index: 0;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n.thumb svg {\n  transform: scale(7);\n  color: hsla(0, 0%, 100%, 0.2);\n}\n\n.card:hover {\n  background-color: hsl(0, 0%, 15%);\n  box-shadow: 0px 20px 40px hsl(40, 60%, 0%, 0.4),\n    inset 1px 2px 4px rgba(255, 255, 255, 0.1);\n  transform: scale(1.1);\n}\n.card:hover .detial {\n  padding: 1em 2em;\n}\n\n.card:hover .thumb {\n  opacity: 0.2;\n  filter: blur(20px);\n  transform: scale(1.5);\n}\n.card:hover .content {\n  transform: none;\n  opacity: 1;\n  transition: var(--transition);\n}\n\n.infomation {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n}\n.propertion {\n  font-size: 0.8em;\n  color: var(--text-color-L2);\n}\n\n.action {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  height: 3em;\n  padding: 0 0.5e', colors: '', radii: '0.5em,1em', shadows: '0px 20px 40px hsl(40, 60%, 0%, 0.4),\n    inset 1px 2px 4px rgba(255, 255, 255, 0.1),2px 4px 16px rgba(0, 0, 0, 0.6),\n    inset 0.5px