const GalaxyComp(id: 'MRez321_slippery-owl-0', cat: 'Cards', author: 'MRez321', tags: 'hover,animated,floating,div,eye', html: '<div class="one-div"></div>', css: '\n/* From Uiverse.io by MRez321 - Tags: hover, animated, floating, div, eye */\n.one-div {\n  background-color: #322e2e;\n  width: 20rem;\n  height: 15rem;\n  position: relative;\n  border: solid 1.2rem #dacfcf;\n  border-radius: 50% 50% 44% 44% / 55% 55% 40% 40%;\n}\n\n.one-div::before,\n.one-div::after {\n  content: \'\';\n  width: 6rem;\n  height: 6rem;\n  position: absolute;\n  top: 35%;\n  background-image: repeating-linear-gradient(0deg, #474bff, #474bff 3.5px, transparent 3.5px, transparent);\n  background-size: .4rem .4rem;\n  background-color: #31abd1;\n  border: solid 2px #00adcc;\n  filter: drop-shadow(0 1px 6px #04d9ff);\n}\n\n.one-div::before {\n  left: 1.4rem;\n  border-radius: 25% 75% 25% 75% / 25% 75% 25% 75%;\n}\n\n.one-div::after {\n  right: 1.4rem;\n  border-radius: 75% 25% 75% 25% / 75% 25% 75% 25%;\n}\n\n.one-div:hover {\n  animation: float 2s infinite;\n}\n\n.one-div:hover::before,\n.one-div:hover::after {\n  animation: blink 2.5s infinite;\n}\n\n@keyframes float {\n  0% {\n    bottom: 0;\n  }\n\n  50% {\n    bottom: -.4rem;\n  }\n\n  100% {\n    bottom: 0;\n  }\n}\n\n@keyframes blink {\n  90% {\n    transform: none;\n    animation-timing-function: ease-in;\n  }\n\n  93% {\n    transform: translateY(15px) scaleY(0)\n  }\n\n  100% {\n    animation-timing-function: ease-out;\n  }\n}\n', colors: '#474bff,#04d9ff,#dacfcf,#00adcc,#322e2e,#31abd1', radii: '25% 75% 25% 75% / 25% 75% 25% 75%,50% 50% 44% 44% / 55% 55% 40% 40%,75% 25% 75% 25% / 75% 25% 75% 25%', shadows: '', techniques: '3d-transform,gradient,animation,filter-effect,pseudo-elements'),
