ition: relative;\n  text-align: center;\n  content: "Code Planet";\n  color: white;\n  border-radius: 50%;\n  top: 3.4em;\n  left: 0.85em;\n  font-weight: 600;\n}\n\n.card .heading {\n  opacity: 0;\n  transition: .1s ease-in-out;\n}\n\n.card .heading span {\n  transition: .4s ease-in-out;\n}\n\n.card button {\n  opacity: 0;\n  transition: .001s ease-in-out;\n}\n\n.card .heading:hover {\n  background: linear-gradient(to right, #fff 20%,orange 40%,yellow 60%, skyblue 80%, #ffe4f2 100%);\n  background-size: 200% auto;\n  -webkit-background-clip: text;\n  background-clip: text;\n  -webkit-text-fill-color: transparent;\n  animation: gradient_6346 5s linear infinite;\n  letter-spacing: 1px;\n  scale: 1.01;\n}\n\n@keyframes gradient_6346 {\n  to {\n    background-position: 200% center;\n  }\n}\n\n.card .content {\n  opacity: 0;\n  transition: .1s ease-in-out;\n}\n\n.card:hover {\n  cursor: pointer;\n  display: flex;\n  flex-direction: column;\n  width: 15.4em;\n  height: 22.9em;\n  padding-top: .4em;\n  padding-bottom: 1.5em;\n  background-color: #171717;\n  border-radius: 20px;\n  box-shadow: rgba(0, 0, 0, 0.4) 0px 2px 2px, rgba(0, 0, 0, 0.3) 0px 7px 13px -3px, rgba(0, 0, 0, 0.2) 0px -1px 0px inset;\n  background: linear-gradient(270deg, #ce68d9, #45c6db, #45db79);\n  background-size: 800% 800%;\n  -webkit-animation: AnimationName 3s ease infinite;\n  -moz-animation: AnimationName 3s ease infinite;\n  animation: AnimationName 3s ease infinite;\n  transition: .4s ease-in-out;\n}\n\n.card:hover .heading {\n  opacity: 1;\n  transition: .8s ease-in-out;\n}\n\n.card:hover .content {\n  opacity: 1;\n  transition: .8s ease-in-out;\n}\n\n.card:hover button {\n  opacity: 1;\n  transition: .4s ease-in-out;\n}\n\n.card:hover::before {', colors: '#45db79,#e54ed0,#ce68d9,#ae47c2,#171717,#9f45b0,#a73dbd,#ffe4f2,#fff,#45c6db', radii: '50%,16px,15px,10px,20px', shadows: 'inset -25px -25px 0px #a73dbd, 10px 10px 10px rgba(0,0,0,0.2),rgba(0, 0, 0, 0.4) 0px 2px 2px, rgba(0, 0, 0, 0.3) 0px 7px 13px -3px, rgba(0, 0, 0, 0.2) 0px -1px 0px inset,rgba(0, 0, 0, 0.4) 0px 2px 4px, rgba(0, 0, 0, 0.3) 0px 7px 13px -3px, rgba(0, 0, 0, 0.2) 0px -3px 0px inset', techniques: 'glassmorphism,gradient,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'shadowfax29_wicked-baboon-62', cat: 'Cards', author: 'shadowfax29', tags: 'card,cloud,hover effect', html: '<div class="card">\n<div class="cloud">\n</div>\n<div class="shadow"></div>\n</div>', css: '\n/* From Uiverse.io by shadowfax29 - Tags: card, cloud, hover effect */\n.card {\n  width: 190px;\n  height: 254px;\n  background-color: #66D0FF;\n  padding: 20px;\n  border-radius: 8px;\n  transition: all .3s;\n  border: 3px solid #66D0FF;\n  box-shadow: 0 0 10px white;\n}\n\n.cloud {\n  width: 150px;\n  height: 70px;\n  background: #ECEFF1;\n  box-shadow: 10px 10px rgba(0,0,0,0.2);\n  border-radius: 70px;\n}\n\n.cloud::after, .cloud::before {\n  content: "";\n  position: relative;\n  display: inline-block;\n  background: inherit;\n  border-radius: inherit;\n}\n\n.cloud::after {\n  width: 50px;\n  height: 50px;\n  top: -30px;\n  left: -55px;\n}\n\n.cloud::before {\n  width: 70px;\n  height: 70px;\n  top: -20px;\n  left: 60px;\n}\n\n.cloud {\n  animation: float 1.8s infinite alternate;\n}\n\n@keyframes float {\n  0% {\n    transform: translateY(15px);\n  }\n\n  100% {\n    transform: translateY(0);\n  }\n}\n\n.shadow {\n  width: 150px;\n  height: 24px;\n  background-color: rgba(0,0,0,0.2);\n  margin-top: 100px;\n  border-radius: 50%;\n  filter: blur(7px);\n  animation: sha 1.8s infinite alternate;\n}\n\n@keyframes sha {\n  0% {\n    transform: scale(1,1);\n  }\n\n  100% {\n    transform: scale(.85,.85);\n  }\n}\n\n.card:hover {\n  width: 200px;\n  height: 264px;\n  transform: scale(0.9);\n  padding: 20px;\n  border: 5px solid black;\n}\n', colors: '#eceff1,#66d0ff', radii: '70px,50%,inherit,8px', shadows: '0 0 10px white,10px 10px rgba(0,0,0,0.2)', techniques: 'glassmorphism,3d-transform,glow-shadow,animation,pseudo-elements'),
const GalaxyComp(id: 'Shoh2008_serious-badger-45', cat: 'Cards', author: 'Shoh2008', tags: 'card', html: '<div class="container">\n  <div class="card">\n     <div class="card__image-container">\n    </div>\n      \n      <svg class="card__svg" viewBox="0 0 800 500">\n\n        <path d="M 0 100 Q 50 200 100 250 Q 250 400 350 300 C 400 250 550 150 650 300 Q 750 450 800 400 L 800 500 L 0 500" stroke="transparent" fill="#333"></path>\n        <path class="card__line" d="M 0 100 Q 50 200 100 250 Q 250 400 350 300 C 400 250 550 150 650 300 Q 750 450 800 400" stroke="pink" stroke-width="3" fill="transparent"></path>\n      </svg>\n    \n     <div class="card__content">\n       <p class="card__title">Lorem ipsum</p>\n     <p>Soluta dolor praesentium at quod autem omnis, amet earum nesciunt porro.</p>\n    </div>\n  </div>\n</div>', css: '\n/* From Uiverse.io by Shoh2008 - Tags: card */\n.container {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  height: 350px;\n  background: #444;\n  border-radius: 10px;\n}\n\n.card {\n  position: relative;\n  background: #333;\n  width: 250px;\n  height: 350px;\n  border-radius: 10px;\n  padding: 2rem;\n  color: #aaa;\n  box-shadow: 0 .25rem .25rem rgba(0,0,0,0.2),\n    0 0 1rem rgba(0,0,0,0.2);\n  overflow: hidden;\n}\n\n.card__image-container {\n  margin: -2rem -2rem 1rem -2rem;\n}\n\n.card__line {\n  opacity: 0;\n  animation: LineFadeIn .8s .8s forwards ease-in;\n}\n\n.card__image {\n  opacity: 0;\n  animation: ImageFadeIn .8s 1.4s forwards;\n}\n\n.card__title {\n  color: white;\n  margin-top: 35px;\n  margin-bottom: 10px;\n  font-weight: 800;\n  letter-spacing: 0.01em;\n}\n\n.card__content {\n  margin-top: -1rem;\n  opacity: 0;\n  animation: ContentFadeIn .8s 1.6s forwards;\n}\n\n.card__svg {\n  position: absolute;\n  left: 0;\n  top: 115px;\n}\n\n@keyframes LineFadeIn {\n  0% {\n    opacity: 0;\n    d: path("M 0 300 Q 0 300 0 300 Q 0 300 0 300 C 0 300 0 300 0 300 Q 0 300 0 300 ");\n    stroke: #fff;\n  }\n\n  50% {\n    opacity: 1;\n    d: path("M 0 300 Q 50 300 100 300 Q 250 300 350 300 C 350 300 500 300 650 300 Q 750 300 800 300");\n    stroke: #888BFF;\n  }\n\n  100% {\n    opacity: 1;\n    d: path("M -2 100 Q 50 200 100 250 Q 250 400 350 300 C 400 250 550 150 650 300 Q 750 450 802 400");\n    stroke: #545581;\n  }\n}\n\n@keyframes ContentFadeIn {\n  0% {\n    transform: translateY(-1rem);\n    opacity: 0;\n  }\n\n  100% {\n    transform: translateY(0);\n    opacity: 1;\n  }\n}\n\n@keyframes ImageFadeIn {\n  0% {\n    transform: translate(-.5rem, -.5rem) scale(1.05);\n    opacity: 0;\n    filter: blur(2px);\n  }\n\n  50% {\n    opacity: 1;\n    filter: blur(2px);\n  }\n\n  100% {\n    transform: translateY(0) scale(1.0);\n    opacity: 1;\n    filter: blur(0);\n  }\n}\n', colors: '#aaa,#888bff,#545581,#333,#444,#fff', radii: '10px', shadows: '0 .25rem .25rem rgba(0,0,0,0.2),\n    0 0 1rem rgba(0,0,0,0.2)', techniques: 'glassmorphism,3d-transform,glow-shadow,animation,svg-icon'),
