und: #0f0c29;\n  background: linear-gradient(to right bottom, #443e89, #0f0c29);\n  padding: 20px 20px;\n  border-radius: 10px;\n  gap: 10px;\n  font-family: Arial, Helvetica, sans-serif;\n  box-shadow: 0px 10px 10px rgba(0, 0, 0, 0.058);\n}\n.text-wrapper {\n  width: 100%;\n  height: fit-content;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  gap: 5px;\n}\n.text-primary {\n  color: white;\n  font-size: 15px;\n  font-weight: 600;\n  letter-spacing: 0.5px;\n}\n.text-secondary {\n  color: #cccccc;\n  font-size: 10px;\n  font-weight: 400;\n  letter-spacing: 0.5px;\n}\n.rating-stars-container {\n  width: 100%;\n  height: 30px;\n  display: flex;\n  flex-direction: row-reverse;\n  align-items: center;\n  justify-content: center;\n}\n.star-label svg {\n  fill: rgb(210, 210, 210);\n  width: 20px;\n  height: auto;\n}\n.rating-stars-container input {\n  appearance: unset;\n}\n.rating-stars-container input:hover ~ .star-label svg {\n  fill: rgb(255, 204, 185);\n}\n.rating-stars-container input:checked ~ .star-label svg {\n  fill: rgb(255, 102, 47);\n  animation: slide-in-fwd-center 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94) both;\n}\n@keyframes slide-in-fwd-center {\n  0% {\n    transform: scale(1.6);\n  }\n  100% {\n    transform: scale(1);\n  }\n}\n\n.socials-container {\n  width: 50%;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  gap: 10px;\n  padding-top: 20px;\n  border-top: 1px solid rgb(150, 150, 150);\n}\n.social-button {\n  text-decoration: none;\n}\n.social-button svg {\n  width: 15px;\n  fill: rgb(228, 228, 228);\n}\n.social-button:hover svg {\n  fill: rgb(255, 102, 47);\n}\n\n', colors: '#443e89,#0f0c29,#cccccc', radii: '10px', shadows: '0px 10px 10px rgba(0, 0, 0, 0.058)', techniques: 'cubic-bezier,3d-transform,gradient,animation,svg-icon'),
