const GalaxyComp(id: 'Smit-Prajapati_tricky-turtle-16', cat: 'loaders', author: 'Smit-Prajapati', tags: 'loader,dark,animated,loader,black,minimalist,circle,modern,symbol,geometric,ripple', html: '<div class="loader">\n  <div class="box">\n    <div class="logo">\n      <svg\n        class="svg"\n        viewBox="0 0 94 94"\n        fill="none"\n        xmlns="http://www.w3.org/2000/svg"\n      >\n        <path\n          d="M38.0481 4.82927C38.0481 2.16214 40.018 0 42.4481 0H51.2391C53.6692 0 55.6391 2.16214 55.6391 4.82927V40.1401C55.6391 48.8912 53.2343 55.6657 48.4248 60.4636C43.6153 65.2277 36.7304 67.6098 27.7701 67.6098C18.8099 67.6098 11.925 65.2953 7.11548 60.6663C2.37183 56.0036 3.8147e-06 49.2967 3.8147e-06 40.5456V4.82927C3.8147e-06 2.16213 1.96995 0 4.4 0H13.2405C15.6705 0 17.6405 2.16214 17.6405 4.82927V39.1265C17.6405 43.7892 18.4805 47.2018 20.1605 49.3642C21.8735 51.5267 24.4759 52.6079 27.9678 52.6079C31.4596 52.6079 34.0127 51.5436 35.6268 49.4149C37.241 47.2863 38.0481 43.8399 38.0481 39.0758V4.82927Z"\n        ></path>\n        <path\n          d="M86.9 61.8682C86.9 64.5353 84.9301 66.6975 82.5 66.6975H73.6595C71.2295 66.6975 69.2595 64.5353 69.2595 61.8682V4.82927C69.2595 2.16214 71.2295 0 73.6595 0H82.5C84.9301 0 86.9 2.16214 86.9 4.82927V61.8682Z"\n        ></path>\n        <path\n          d="M2.86102e-06 83.2195C2.86102e-06 80.5524 1.96995 78.3902 4.4 78.3902H83.6C86.0301 78.3902 88 80.5524 88 83.2195V89.1707C88 91.8379 86.0301 94 83.6 94H4.4C1.96995 94 0 91.8379 0 89.1707L2.86102e-06 83.2195Z"\n        ></path>\n      </svg>\n    </div>\n  </div>\n  <div class="box"></div>\n  <div class="box"></div>\n  <div class="box"></div>\n  <div class="box"></div>\n</div>', css: '\n/* From Uiverse.io by Smit-Prajapati  - Tags: loader, dark, animated, loader, black, minimalist, circle, modern, symbol, geometric, ripple */\n.loader {\n  --size: 250px;\n  --duration: 2s;\n  --logo-color: grey;\n  --background: linear-gradient(\n    0deg,\n    rgba(50, 50, 50, 0.2) 0%,\n    rgba(100, 100, 100, 0.2) 100%\n  );\n  height: var(--size);\n  aspect-ratio: 1;\n  background: black;\n  position: relative;\n}\n\n.loader .box {\n  position: absolute;\n  background: rgba(100, 100, 100, 0.15);\n  background: var(--background);\n  border-radius: 50%;\n  border-top: 1px solid rgba(100, 100, 100, 1);\n  box-shadow: rgba(0, 0, 0, 0.3) 0px 10px 10px -0px;\n  backdrop-filter: blur(5px);\n  animation: ripple var(--duration) infinite ease-in-out;\n}\n\n.loader .box:nth-child(1) {\n  inset: 40%;\n  z-index: 99;\n}\n\n.loader .box:nth-child(2) {\n  inset: 30%;\n  z-index: 98;\n  border-color: rgba(100, 100, 100, 0.8);\n  animation-delay: 0.2s;\n}\n\n.loader .box:nth-child(3) {\n  inset: 20%;\n  z-index: 97;\n  border-color: rgba(100, 100, 100, 0.6);\n  animation-delay: 0.4s;\n}\n\n.loader .box:nth-child(4) {\n  inset: 10%;\n  z-index: 96;\n  border-color: rgba(100, 100, 100, 0.4);\n  animation-delay: 0.6s;\n}\n\n.loader .box:nth-child(5) {\n  inset: 0%;\n  z-index: 95;\n  border-color: rgba(100, 100, 100, 0.2);\n  animation-delay: 0.8s;\n}\n\n.loader .logo {\n  position: absolute;\n  inset: 0;\n  display: grid;\n  place-content: center;\n  padding: 30%;\n}\n\n.loader .logo svg {\n  fill: var(--logo-color);\n  width: 100%;\n  animation: color-change var(--duration) infinite ease-in-out;\n}\n\n@keyframes ripple {\n  0% {\n    transform: scale(1);\n    box-shadow: rgba(0, 0, 0, 0.3) 0px 10px 10px -0px;\n  }\n  50% {\n    transform: scale(1.3);\n    box-shadow: rgba(0, 0, 0, 0.3) 0px 30px 20px -0px;\n  }\n  100% {\n    transform: scale(1);\n    box-shadow: rgba(0, 0, 0, 0.3) 0px 10px 10px -0px;\n  }\n}\n\n@keyframes color-change {\n  0% {\n    fill: var(--logo-color);\n  }\n  50% {\n    fill: white;\n  }\n  100% {\n    fill: var(--logo-color);\n  }\n}\n\n', colors: '', radii: '50%', shadows: 'rgba(0, 0, 0, 0.3) 0px 10px 10px -0px,rgba(0, 0, 0, 0.3) 0px 10px 10px -0px,rgba(0, 0, 0, 0.3) 0px 30px 20px -0px', techniques: 'glassmorphism,3d-transform,gradient,animation,svg-icon'),
const GalaxyComp(id: 'Subaashbala_tender-baboon-47', cat: 'loaders', author: 'Subaashbala', tags: 'loader,game,animated,bounce animation', html: '<div class="loader">\n  <svg\n    width="115"\n    height="81"\n    viewBox="0 0 115 81"\n    fill="none"\n    xmlns="http://www.w3.org/2000/svg"\n    id="bird"\n  >\n    <rect x="41" y="47" width="20" height="7" fill="#FFEB3B"></rect>\n    <rect x="35" y="67" width="33" height="7" fill="#FFC107"></rect>\n    <rect x="21" y="54" width="40" height="14" fill="#FFC107"></rect>\n    <rect x="48" y="40" width="20" height="7" fill="#FFEB3B"></rect>\n    <rect x="48" y="33" width="20" height="7" fill="#FFEB3B"></rect>\n    <rect x="41" y="27" width="20" height="7" fill="#FFEB3B"></rect>\n    <rect x="34" y="20" width="20" height="7" fill="#FFEB3B"></rect>\n    <rect x="28" y="14" width="20" height="7" fill="#FFEB3B"></rect>\n    <rect x="40" y="7" width="21" height="7" fill="#FFEB3B"></rect>\n    <rect x="41" y="34" width="7" height="13" fill="black"></rect>\n    <rect x="21" y="14" width="7" height="7" fill="black"></rect>\n    <rect x="41" width="40" height="7" fill="black"></rect>\n    <rect x="28" y="7" width="13" height="7" fill="black"></rect>\n    <rect x="7" y="27" width="34" height="27" fill="#FFFFCC"></rect>\n    <rect x="61" y="12" width="34" height="28" fill="white"></rect>\n    <rect x="7" y="20" width="27" height="7" fill="black"></rect>\n    <rect x="34" y="27" width="7" height="7" fill="black"></rect>\n    <rect x="7" y="40" width="7" height="7" fill="#FFEB3B"></rect>\n    <rect x="34" y="40" width="7" height="7" fill="#FFEB3B"></rect>\n    <rect x="48" y="14" width="7" height="7" fill="#FFEB3B', css: '\n/* From Uiverse.io by Subaashbala  - Tags: loader, game, animated, bounce animation */\n.loader {\n  position: relative;\n  width: 18rem; /* Reposition the obstacles and the bird if the width is changed */\n  aspect-ratio: 1;\n  overflow: hidden;\n  border-radius: 50%;\n  background: linear-gradient(to bottom, #6ccee7 60%, white);\n}\n#bird {\n  position: absolute;\n  left: 50%;\n  top: 50%;\n  transform: translate(-80%, -50%);\n  width: 3rem;\n  height: auto;\n  animation: flap 500ms linear infinite;\n}\n.flappyBirdScene,\n.flappyBirdSceneBottom {\n  display: flex;\n  width: 20rem;\n  top: -23%;\n  position: relative;\n}\n.sceneTop {\n  display: flex;\n  width: fit-content;\n  animation: flow 5s linear infinite;\n}\n.sceneBottom {\n  display: flex;\n  width: fit-content;\n  animation: flowBottom 5s linear infinite;\n}\n#birdObstacle {\n  height: 8rem;\n  width: 2rem;\n  background: linear-gradient(\n    to right,\n    #9de558 0px,\n    #9de558 3px,\n    #e7ff8d 3px,\n    #e7ff8d 5px,\n    #9de858 5px,\n    #9de858 10px,\n    #74c029 10px,\n    #74c029 13px,\n    #9de558 13px,\n    #9de558 15px,\n    #74c029 22px,\n    #74c029 28px,\n    #59811a 28px,\n    #59811a 100%\n  );\n  border: solid;\n  position: relative;\n}\n.flappyBirdSceneBottom {\n  bottom: -25%;\n  left: 0;\n}\n#birdObstacle::after {\n  content: "";\n  position: absolute;\n  width: 135%;\n  height: 1.25rem;\n  top: 100%;\n  left: 50%;\n  border: solid;\n  transform: translate(-50%, 0);\n  background: linear-gradient(\n    to right,\n    #9de558 0px,\n    #9de558 3px,\n    #e7ff8d 3px,\n    #e7ff8d 5px,\n    #9de858 5px,\n    #9de858 10px,\n    #74c029 10px,\n    #74c029 13px,\n    #9de558 13px,\n    #9de558 15px,\n    #74c029 22px,\n    #74c029 28px,\n    #59811a 28px,\n    #59811a 100%\n  );\n}\n.birdObs2 {\n  transform: translate(0%, 15%);\n  left: 15%;\n}\n.birdObs3 {\n  transform: translate(0, 18%);\n  left: 30%;\n}\n.birdObs4 {\n  transform: translate(0, 15%);\n  left: 45%;\n}\n@keyframes flap {\n  from {\n    transform: translate(-80%, -50%);\n  }\n  25% {\n    transform: translate(-80%, -50%) rota', colors: '#59811a,#e7ff8d,#74c029,#6ccee7,#9de558,#9de858', radii: '50%', shadows: '', techniques: '3d-transform,gradient,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'VashonG_spicy-crab-68', cat: 'loaders', author: 'VashonG', tags: 'blue,loader,diamond', html: '<figure>\n  <div style="--i: 1"></div>\n  <div style="--i: 2"></div>\n  <div style="--i: 3"></div>\n  <div style="--i: 4"></div>\n  <div style="--i: 5"></div>\n  <div style="--i: 6"></div>\n  <div style="--i: 7"></div>\n  <div style="--i: 8"></div>\n  <div style="--i: 9"></div>\n  <div style="--i: 10"></div>\n  <div style="--i: 11"></div>\n  <div style="--i: 12"></div>\n</figure>', css: '\n/* From Uiverse.io by VashonG - Tags: blue, loader, diamond */\n@media (prefers-reduced-motion) {\n}\n\nfigure {\n  --size: 15vmin;\n  --duration: 4s;\n  --direction: 1;\n  --pull: -1.25;\n  perspective: 30rem;\n  display: grid;\n  grid-template-areas: "figure";\n  place-items: center;\n  inline-size: var(--size);\n  aspect-ratio: 1;\n  animation: spin var(--duration) ease-in-out infinite;\n}\n\nfigure > * {\n  --radius: calc(var(--size) / 2);\n  --deg: calc(var(--i) * (360deg / 12));\n  --hs: 225 100%;\n  --transform-start: translate3d(\n      calc(cos(var(--deg)) * var(--radius)),\n      calc(sin(var(--deg)) * var(--radius)),\n      0\n    )\n    rotate(calc(var(--deg)));\n  grid-area: figure;\n  background-color: hsl(var(--hs) var(--l, 60%));\n  inline-size: calc(var(--size) / 4);\n  aspect-ratio: 1;\n  clip-path: polygon(25% 25%, 100% 50%, 25% 75%, 0% 50%);\n  transform: var(--transform-start);\n  transform-style: preserve-3d;\n  animation: diamonds var(--duration) cubic-bezier(0.87, 0, 0.13, 1) infinite;\n}\n\nfigure:nth-child(2) {\n  --size: 30vmin;\n  --direction: -1;\n  --l: 70%;\n}\n\nfigure:nth-child(3) {\n  --size: 55vmin;\n  --pull: -1.125;\n  --l: 80%;\n}\n\n@keyframes spin {\n  0%,\n  25% {\n    transform: scaleX(var(--direction)) rotate(0);\n  }\n\n  75%,\n  100% {\n    transform: scaleX(var(--direction)) rotate(1turn);\n  }\n}\n\n@keyframes diamonds {\n  0%,\n  20% {\n    transform: var(--transform-start);\n  }\n\n  50% {\n    clip-path: polygon(75% 25%, 100% 50%, 75% 75%, 0% 50%);\n    transform: translate3d(\n        calc(cos(var(--deg)) * var(--radius) * var(--pull)),\n        calc(sin(var(--deg)) * var(--radius) * var(--pull)),\n        5rem\n      )\n      rotate(calc(var(--deg) + 90deg));\n  }\n}\n\n', colors: '', radii: '', shadows: '', techniques: 'cubic-bezier,3d-transform,animation,clip-path,perspective'),
