display: flex;\n  align-items: center;\n  justify-content: center;\n  scale: 0.8;\n  opacity: 0;\n}\n\n.switch .sun .dot {\n  positon: relative;\n  display: block;\n  width: 3px;\n  height: 3px;\n  border-radius: 50%;\n  background: var(--color-dark);\n  background: white;\n  z-index: 1;\n  box-shadow: 11px 0px 0px var(--shadow-color),\n    10.3px 0px 0px var(--shadow-color), -11px 0px 0px var(--shadow-color),\n    -10.3px 0px 0px var(--shadow-color), 0px -11px 0px var(--shadow-color),\n    0px -10.3px 0px var(--shadow-color), 0px 11px 0px var(--shadow-color),\n    0px 10.3px 0px var(--shadow-color), 8px 8px 0px var(--shadow-color),\n    7.3px 7.3px 0px var(--shadow-color), 8px -8px 0px var(--shadow-color),\n    7.3px -7.3px 0px var(--shadow-color), -8px -8px 0px var(--shadow-color),\n    -7.3px -7.3px 0px var(--shadow-color), -8px 8px 0px var(--shadow-color),\n    -7.3px 7.3px 0px var(--shadow-color);\n}\n\n.switch .sun .dot::before {\n  content: "";\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  width: 10px;\n  ', colors: '#21262e,#0c0f14,#cecece,#52555a', radii: '30px,50%', shadows: '11px 0px 0px var(--shadow-color),\n    10.3px 0px 0px var(--shadow-color), -11px 0px 0px var(--shadow-color),\n    -10.3px,1px 1px 20px 3px var(--color-darkGray),1px 1px 30px 12px white', techniques: '3d-transform,glow-shadow,checkbox-input,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'andrew-demchenk0_honest-stingray-90', cat: 'Toggle-switches', author: 'andrew-demchenk0', tags: 'switch,dark,light,theme-switch', html: '<label class="switch">\n  <span class="sun"><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24"><g fill="#ffd43b"><circle r="5" cy="12" cx="12"></circle><path d="m21 13h-1a1 1 0 0 1 0-2h1a1 1 0 0 1 0 2zm-17 0h-1a1 1 0 0 1 0-2h1a1 1 0 0 1 0 2zm13.66-5.66a1 1 0 0 1 -.66-.29 1 1 0 0 1 0-1.41l.71-.71a1 1 0 1 1 1.41 1.41l-.71.71a1 1 0 0 1 -.75.29zm-12.02 12.02a1 1 0 0 1 -.71-.29 1 1 0 0 1 0-1.41l.71-.66a1 1 0 0 1 1.41 1.41l-.71.71a1 1 0 0 1 -.7.24zm6.36-14.36a1 1 0 0 1 -1-1v-1a1 1 0 0 1 2 0v1a1 1 0 0 1 -1 1zm0 17a1 1 0 0 1 -1-1v-1a1 1 0 0 1 2 0v1a1 1 0 0 1 -1 1zm-5.66-14.66a1 1 0 0 1 -.7-.29l-.71-.71a1 1 0 0 1 1.41-1.41l.71.71a1 1 0 0 1 0 1.41 1 1 0 0 1 -.71.29zm12.02 12.02a1 1 0 0 1 -.7-.29l-.66-.71a1 1 0 0 1 1.36-1.36l.71.71a1 1 0 0 1 0 1.41 1 1 0 0 1 -.71.24z"></path></g></svg></span>\n  <span class="moon"><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 384 512"><path d="m223.5 32c-123.5 0-223.5 100.3-223.5 224s100 224 223.5 224c60.6 0 115.5-24.2 155.8-63.4 5-4.9 6.3-12.5 3.1-18.7s-10.1-9.7-17-8.5c-9.8 1.7-19.8 2.6-30.1 2.6-96.9 0-175.5-78.8-175.5-176 0-65.8 36-123.1 89.3-153.3 6.1-3.5 9.2-10.5 7.7-17.3s-7.3-11.9-14.3-12.5c-6.3-.5-12.6-.8-19-.8z"></path></svg></span>   \n  <input type="checkbox" class="input">\n  <span class="slider"></span>\n</label>', css: '\n/* From Uiverse.io by andrew-demchenk0 - Tags: switch, dark, light, theme-switch */\n.switch {\n  font-size: 17px;\n  position: relative;\n  display: inline-block;\n  width: 64px;\n  height: 34px;\n}\n\n.switch input {\n  opacity: 0;\n  width: 0;\n  height: 0;\n}\n\n.slider {\n  position: absolute;\n  cursor: pointer;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  background-color: #73C0FC;\n  transition: .4s;\n  border-radius: 30px;\n}\n\n.slider:before {\n  position: absolute;\n  content: "";\n  height: 30px;\n  width: 30px;\n  border-radius: 20px;\n  left: 2px;\n  bottom: 2px;\n  z-index: 2;\n  background-color: #e8e8e8;\n  transition: .4s;\n}\n\n.sun svg {\n  position: absolute;\n  top: 6px;\n  left: 36px;\n  z-index: 1;\n  width: 24px;\n  height: 24px;\n}\n\n.moon svg {\n  fill: #73C0FC;\n  position: absolute;\n  top: 5px;\n  left: 5px;\n  z-index: 1;\n  width: 24px;\n  height: 24px;\n}\n\n/* .switch:hover */.sun svg {\n  animation: rotate 15s linear infinite;\n}\n\n@keyframes rotate {\n \n  0% {\n    transform: rotate(0);\n  }\n\n  100% {\n    transform: rotate(360deg);\n  }\n}\n\n/* .switch:hover */.moon svg {\n  animation: tilt 5s linear infinite;\n}\n\n@keyframes tilt {\n \n  0% {\n    transform: rotate(0deg);\n  }\n\n  25% {\n    transform: rotate(-10deg);\n  }\n\n  75% {\n    transform: rotate(10deg);\n  }\n\n  100% {\n    transform: rotate(0deg);\n  }\n}\n\n.input:checked + .slider {\n  background-color: #183153;\n}\n\n.input:focus + .slider {\n  box-shadow: 0 0 1px #183153;\n}\n\n.input:checked + .slider:before {\n  transform: translateX(30px);\n}\n', colors: '#183153,#73c0fc,#e8e8e8', radii: '30px,20px', shadows: '0 0 1px #183153', techniques: '3d-transform,glow-shadow,animation,checkbox-input,svg-icon'),
const GalaxyComp(id: 'barisdogansutcu_tender-dingo-64', cat: 'Toggle-switches', author: 'barisdogansutcu', tags: 'complex,switch,heart', html: '<div class="love">\n  <input id="switch" type="checkbox">\n  <label class="love-heart" for="switch">\n    <i class="left"></i>\n    <i class="right"></i>\n    <i class="bottom"></i>\n    <div class="round"></div>\n  </label>\n</div>', css: '\n/* From Uiverse.io by barisdogansutcu - Tags: complex, switch, heart */\n.love-heart:before,#switch {\n display: none;\n}\n\n.love-heart, .love-heart::after {\n border-color: hsl(231deg 28% 86%);\n border: 1px solid;\n border-top-left-radius: 100px;\n border-top-right-radius: 100px;\n width: 10px;\n height: 8px;\n border-bottom: 0\n}\n\n.round {\n position: absolute;\n z-index: 1;\n width: 8px;\n height: 8px;\n background: hsl(0deg 0% 100%);\n box-shadow: rgb(0 0 0 / 24%) 0px 0px 4px 0px;\n border-radius: 100%;\n left: 0px;\n bottom: -1px;\n transition: all .5s ease;\n animation: check-animation2 .5s forwards;\n}\n\ninput:checked + label .round {\n transform: translate(0px, 0px);\n animation: check-animation .5s forwards;\n background-color: hsl(0deg 0% 100%);\n}\n\n@keyframes check-animation {\n 0% {\n  transform: translate(0px, 0px);\n }\n\n 50% {\n  transform: translate(0px, 7px);\n }\n\n 100% {\n  transform: translate(7px, 7px);\n }\n}\n\n@keyframes check-animation2 {\n 0% {\n  transform: translate(7px, 7px);\n }\n\n 50% {\n  transform: translate(0px, 7px);\n }\n\n 100% {\n  transform: translate(0px, 0px);\n }\n}\n\n.love-heart {\n box-sizing: border-box;\n position: relative;\n transform: rotate(-45deg) translate(-50%, -33px) scale(4);\n display: block;\n border-color: hsl(231deg 28% 86%);\n cursor: pointer;\n top: 0;\n}\n\ninput:checked + .love-heart, input:checked + .love-heart::after, input:checked + .love-heart .bottom {\n border-color: hsl(347deg 81% 61%);\n box-shadow: inset 6px -5px 0px 2px hsl(347deg 99% 72%);\n}\n\n.love-heart::after, .love-heart .bottom {\n content: "";\n display: block;\n box-sizing: border-box;\n position: absolute;\n border-color: hsl(231deg 28% 86%);\n}\n\n.love-heart::after {\n right: -9px;\n transform: rotate(90deg);\n top: 7px;\n}\n\n.love-heart .bottom {\n width: 11px;\n height: 11px;\n border-left: 1px solid;\n border-bottom: 1px solid;\n border-color: hsl(231deg 28% 86%);\n left: -1px;\n top: 5px;\n border-radius: 0px 0px 0px 5px;\n}\n\n', colors: '', radii: '0px 0px 0px 5px,100%', shadows: 'rgb(0 0 0 / 24%) 0px 0px 4px 0px,inset 6px -5px 0px 2px hsl(347deg 99% 72%)', techniques: '3d-transform,glow-shadow,animation,checkbox-input,pseudo-elements'),
const GalaxyComp(id: 'csemszepp_witty-fly-56', cat: 'Toggle-switches', author: '', tags: '', html: '<div class="container">\n<label class="switch">\n  <input class="togglesw" type="checkbox" checked="">\n  <div class="indicator left"></div>\n  <div class="indicator right"></div>\n  <div class="button"></div>\n</label>\n</div>', css: '\n/* From Uiverse.io by csemszepp - Source: codepen.io/ykadosh/pen/jOwjmJe - Tags: neumorphism, skeuomorphism, switch, toggle switch */\n.container {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  --hue: 220deg;\n  --width: 15rem;\n  --accent-hue: 22deg;\n  --duration: 0.6s;\n  --easing: cubic-bezier(1, 0, 1, 1);\n}\n\n.togglesw {\n  display: none;\n}\n\n.switch {\n  --shadow-offset: calc(var(--width) / 20);\n  position: relative;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  width: var(--width);\n  height: calc(var(--width) / 2.5);\n  border-radius: var(--width);\n  box-shadow: inset 10px 10px 10px hsl(var(--hue) 20% 80%),\n    inset -10px -10px 10px hsl(var(--hue) 20% 93%);\n}\n\n.indicator {\n  content: \'\';\n  position: absolute;\n  width: 40%;\n  height: 60%;\n  transition: all var(--duration) var(--easing);\n  box-shadow: inset 0 0 2px hsl(var(--hue) 20% 15% / 60%),\n    inset 0 0 3px 2px hsl(var(--hue) 20% 15% / 60%),\n    inset 0 0 5px 2px hsl(var(--hue) 20% 45% / 60%);\n}\n\n.indicator.left {\n  --hue: var(--accent-hue);\n  overflow: hidden;\n  left: 10%;\n  border-radius: 100px 0 0 100px;\n  background: linear-gradient(180deg, hsl(calc(var(--accent-hue) + 20deg) 95% 80%) 10%, hsl(calc(var(--accent-hue) + 20deg) 100% 60%) 30%, hsl(var(--accent-hue) 90% 50%) 60%, hsl(var(--accent-hue) 90% 60%) 75%, hsl(var(--accent-hue) 90% 50%));\n}\n\n.indicator.left::after {\n  content: \'\';\n  position: absolute;\n  opacity: 0.6;\n  width: 100%;\n  height: 100%;\n}\n\n.indicator.right {\n  right: 10%;\n  border-radius: 0 100px 100px 0;\n  background-image: linear-gradient(180deg, hsl(var(--hue) 20% 95%), hsl(var(--hue) 20% 65%) 60%, hsl(var(--hue) 20% 70%) 70%, hsl(var(--hue) 20% 65%));\n}\n\n.button {\n  position: absolute;\n  z-index: 1;\n  width: 55%;\n  height: 80%;\n  left: 5%;\n  border-radius: 100px;\n  background-image: linear-gradient(160deg, hsl(var(--hue) 20% 95%) 40%, hsl(var(--hue) 20% 65%) 70%);\n  transition: all var(--duration) var(--easing);\n  box-shadow: 2px 2px 3px hsl(var(--hue)', colors: '', radii: '100px 0 0 100px,0 100px 100px 0,100%,var(--width),100px', shadows: 'inset 10px 10px 10px hsl(var(--hue) 20% 80%),\n    inset -10px -10px 10px hsl(var(--hue) 20% 93%),inset 0 0 2px hsl(var(--hue) 20% 15% / 60%),\n    inset 0 0 3px 2px hsl(var(--hue) 20% 15% / 60%),\n    inset 0 0 5px 2px ,2px 2px 3px hsl(var(--hue) 18% 50% / 80%),\n    2px 2px 6px hsl(var(--hue) 18% 50% / 40%),\n    10px 20px 10px hsl(var(--h', techniques: 'cubic-bezier,glow-shadow,gradient,checkbox-input,pseudo-elements'),
const GalaxyComp(id: 'Custyyyy_strange-zebra-89', cat: 'Toggle-switches', author: 'Custyyyy', tags: 'switch', html: '<div class="check">\n  <input id="check" type="checkbox">\n  <label for="check"></label>\n</div>', css: '\n/* From Uiverse.io by Custyyyy - Tags: switch */\n.check {\n position: relative;\n background: linear-gradient(90deg, #f19af3, #f099b5);\n line-height: 0;\n font-size: 25px;\n}\n\n.check input[type="checkbox"],\n.check label,\n.check label::before,\n.check label::after {\n appearance: none;\n display: inline-block;\n font-size: inherit;\n border-radius: 1em;\n border: 0;\n transition: .35s ease-in-out;\n box-sizing: border-box;\n cursor: pointer;\n}\n\n.check {\n appearance: none;\n display: inline-block;\n border-radius: 1em;\n border: 0;\n transition: .35s ease-in-out;\n box-sizing: border-box;\n cursor: pointer;\n}\n\n.check label {\n width: 2.2em;\n height: 1em;\n background: #d7d7d7;\n overflow: hidden;\n}\n\n.check input[type="checkbox"] {\n position: absolute;\n z-index: 1;\n width: .8em;\n height: .8em;\n top: .1em;\n left: .1em;\n background: linear-gradient(45deg, #dedede, #ffffff);\n box-shadow: 0 6px 7px rgba(0,0,0,0.3);\n outline: none;\n}\n\n.check input[type="checkbox"]:checked {\n left: 1.3em;\n}\n\n.check input[type="checkbox"]:checked + label {\n background: transparent;\n}\n\n.check label::before,\n.check label::after {\n content: "· ·";\n position: absolute;\n overflow: hidden;\n left: .50em;\n top: .5em;\n height: 1em;\n letter-spacing: -.04em;\n color: #9b9b9b;\n font-family: "Times New Roman", serif;\n z-index: 2;\n font-size: .6em;\n border-radius: 0;\n transform-origin: 0 0 -.5em;\n backface-visibility: hidden;\n}\n\n.check label::after {\n content: "?";\n top: .65em;\n left: .6em;\n height: .1em;\n width: .35em;\n font-size: .2em;\n transform-origin: 0 0 -.4em;\n}\n\n.check input[type="checkbox"]:checked + label::before,\n.check input[type="checkbox"]:checked + label::after {\n left: 2.55em;\n top: .4em;\n line-height: .1em;\n transform: rotateY(360deg);\n}\n\n.check input[type="checkbox"]:checked + label::after {\n height: .16em;\n top: .55em;\n left: 2.6em;\n font-size: .6em;\n line-height: 0;\n}\n\n', colors: '#d7d7d7,#dedede,#f099b5,#9b9b9b,#f19af3,#ffffff', radii: '0,1em', shadows: '0 6px 7px rgba(0,0,0,0.3)', techniques: '3d-transform,glow-shadow,gradient,checkbox-input,pseudo-elements'),
const GalaxyComp(id: 'Galahhad_modern-quail-75', cat: 'Toggle-switches', author: 'Galahhad', tags: 'switch,checkbox,bubble', html: '<label class="switch">\n    <input checked="" type="checkbox">\n    <div class="slider">\n        <div class="circle">\n            <svg class="cross" xml:space="preserve" style="enable-background:new 0 0 512 512" viewBox="0 0 365.696 365.696" y="0" x="0" height="6" width="6" xmlns:xlink="http://www.w3.org/1999/xlink" version="1.1" xmlns="http://www.w3.org/2000/svg">\n                <g>\n                    <path data-original="#000000" fill="currentColor" d="M243.188 182.86 356.32 69.726c12.5-12.5 12.5-32.766 0-45.247L341.238 9.398c-12.504-12.503-32.77-12.503-45.25 0L182.86 122.528 69.727 9.374c-12.5-12.5-32.766-12.5-45.247 0L9.375 24.457c-12.5 12.504-12.5 32.77 0 45.25l113.152 113.152L9.398 295.99c-12.503 12.503-12.503 32.769 0 45.25L24.48 356.32c12.5 12.5 32.766 12.5 45.247 0l113.132-113.132L295.99 356.32c12.503 12.5 32.769 12.5 45.25 0l15.081-15.082c12.5-12.504 12.5-32.77 0-45.25zm0 0"></path>\n                </g>\n            </svg>\n            <svg class="checkmark" xml:space="preserve" style="enable-background:new 0 0 512 512" viewBox="0 0 24 24" y="0" x="0" height="10" width="10" xmlns:xlink="http://www.w3.org/1999/xlink" version="1.1" xmlns="http://www.w3.org/2000/svg">\n                <g>\n                    <path class="" data-original="#000000" fill="currentColor" d="M9.707 19.121a.997.997 0 0 1-1.414 0l-5.646-5.647a1.5 1.5 0 0 1 0-2.121l.707-.707a1.5 1.5 0 0 1 2.121 0L9 14.171l9.525-9.525a1.5 1.5 0 0 1 2.121 0l.707.707a1.5 1.5 0 0 1 0 2.121z"></path>\n                </', css: '\n/* From Uiverse.io by Galahhad - Tags: switch, checkbox, bubble */\n.switch {\n  /* switch */\n  --switch-width: 46px;\n  --switch-height: 24px;\n  --switch-bg: rgb(131, 131, 131);\n  --switch-checked-bg: rgb(0, 218, 80);\n  --switch-offset: calc((var(--switch-height) - var(--circle-diameter)) / 2);\n  --switch-transition: all .2s cubic-bezier(0.27, 0.2, 0.25, 1.51);\n  /* circle */\n  --circle-diameter: 18px;\n  --circle-bg: #fff;\n  --circle-shadow: 1px 1px 2px rgba(146, 146, 146, 0.45);\n  --circle-checked-shadow: -1px 1px 2px rgba(163, 163, 163, 0.45);\n  --circle-transition: var(--switch-transition);\n  /* icon */\n  --icon-transition: all .2s cubic-bezier(0.27, 0.2, 0.25, 1.51);\n  --icon-cross-color: var(--switch-bg);\n  --icon-cross-size: 6px;\n  --icon-checkmark-color: var(--switch-checked-bg);\n  --icon-checkmark-size: 10px;\n  /* effect line */\n  --effect-width: calc(var(--circle-diameter) / 2);\n  --effect-height: calc(var(--effect-width) / 2 - 1px);\n  --effect-bg: var(--circle-bg);\n  --effect-border-radius: 1px;\n  --effect-transition: all .2s ease-in-out;\n}\n\n.switch input {\n  display: none;\n}\n\n.switch {\n  display: inline-block;\n}\n\n.switch svg {\n  -webkit-transition: var(--icon-transition);\n  -o-transition: var(--icon-transition);\n  transition: var(--icon-transition);\n  position: absolute;\n  height: auto;\n}\n\n.switch .checkmark {\n  width: var(--icon-checkmark-size);\n  color: var(--icon-checkmark-color);\n  -webkit-transform: scale(0);\n  -ms-transform: scale(0);\n  transform: scale(0);\n}\n\n.switch .cross {\n  width: var(--icon-cross-size);\n  color: var(--icon-cross-color);\n}\n\n.slider {\n  -webkit-box-sizing: border-box;\n  box-sizing: border-box;\n  width: var(--switch-width);\n  height: var(--switch-height);\n  background: var(--switch-bg);\n  border-radius: 999px;\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n  position: relative;\n  -webkit-transition: var(--switch-transition);\n  -o-transi', colors: '#fff', radii: 'var(--effect-border-radius),999px,1px,inherit', shadows: 'var(--circle-shadow),var(--circle-shadow),var(--circle-checked-shadow)', techniques: 'cubic-bezier,3d-transform,checkbox-input,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'Galahhad_tame-moth-5', cat: 'Toggle-switches', author: 'Galahhad', tags: 'gradient,switch', html: '<label class="switch">\n  <input type="checkbox">\n  <span class="slider">\n    <span class="circle">\n      <svg xmlns="http://www.w3.org/2000/svg" version="1.1" xmlns:xlink="http://www.w3.org/1999/xlink" width="22" height="22" x="0" y="0" viewBox="0 0 32 32" style="enable-background:new 0 0 512 512" xml:space="preserve" class="sun">\n          <g>\n            <circle cx="16" cy="16" r="8.312" fill="currentColor" data-original="#000000"></circle>\n            <path d="M31.72 16.706a1.03 1.03 0 0 0 0-1.413l-2.816-3.023a1.037 1.037 0 0 1-.28-.831l.509-4.104c.072-.54-.291-1.05-.832-1.153l-4.062-.78a1.035 1.035 0 0 1-.707-.519l-1.994-3.616a1.037 1.037 0 0 0-1.35-.436l-3.751 1.756c-.27.125-.603.125-.873-.01L11.814.83a1.037 1.037 0 0 0-1.351.436L8.468 4.883c-.146.27-.406.457-.707.52L3.7 6.182c-.54.104-.904.613-.831 1.153l.509 4.104c.03.301-.063.602-.28.831L.28 15.293a1.03 1.03 0 0 0 0 1.413l2.815 3.024c.218.228.312.53.28.831l-.508 4.104c-.073.54.29 1.05.83 1.153l4.063.78c.301.062.561.249.707.519l1.994 3.615c.27.478.863.676 1.351.437l3.75-1.756c.27-.125.603-.125.873.01l3.751 1.746c.488.239 1.08.041 1.35-.437l1.995-3.615c.146-.27.406-.457.707-.52l4.062-.779c.54-.104.904-.613.832-1.153l-.51-4.104a1.037 1.037 0 0 1 .28-.831l2.816-3.023zM16 26.39c-5.725 0-10.39-4.665-10.39-10.39S10.275 5.61 16 5.61 26.39 10.275 26.39 16 21.725 26.39 16 26.39z" fill="currentColor" data-original="#000000"></path>\n          </g>\n        </svg>\n      <svg xmlns="http://www.w3.org/2000/svg" fill="currentColor" vi', css: '\n/* From Uiverse.io by Galahhad - Tags: gradient, switch */\n/* checkbox settings 👇 */\n\n.switch {\n  /* global */\n  --total_transition_duration: .3s;\n  /* switch */\n  --slider_width: 2.875em;\n  --slider_height: 1.5em;\n  --slider_light_bg: linear-gradient(90deg, #f32a85 0%, #f19d36 100%);\n  --slider_night_bg: linear-gradient(90deg, #1701a1 0%, #af0693 75%);\n  --slider_offset: calc((var(--slider_height) - var(--circle_diameter)) / 2);\n  --slider_radius: calc(var(--slider_height) / 2);\n  /* circle */\n  --circle_diameter: 1.125em;\n  --circle_rotation: 360deg;\n  /* svg */\n  --svg_width: var(--circle_diameter);\n  --sun-color: #fff;\n  --moon-color: #fff;\n}\n\n.switch input {\n  display: none;\n}\n\n.slider svg {\n  position: absolute;\n  height: auto;\n  color: var(--svg-color);\n  transition: var(--total_transition_duration) ease;\n  width: 100%;\n}\n\n.circle svg.sun {\n  transform: scale(1);\n  color: var(--sun-color);\n}\n\n.circle svg.moon {\n  transform: scale(0);\n  color: var(--moon-color);\n  width: calc(100% - 2px);\n}\n\n.slider {\n  display: inline-block;\n  width: var(--slider_width);\n  height: var(--slider_height);\n  border-radius: var(--slider_radius);\n  position: relative;\n  cursor: pointer;\n  transition: var(--total_transition_duration) ease;\n  overflow: hidden;\n}\n\n.slider::before,\n.slider::after {\n  content: "";\n  position: absolute;\n  inset: 0;\n  transition: var(--total_transition_duration) ease;\n}\n\n/* ::before and ::after backgrounds are needed for smooth \ntransition of gradients otherwise there is no way :\\ */\n.slider::before {\n  opacity: 0;\n  background: var(--slider_night_bg);\n}\n\n.slider::after {\n  opacity: 1;\n  background: var(--slider_light_bg);\n}\n\n/* ------------ */\n\n.circle {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  width: var(--circle_diameter);\n  height: var(--circle_diameter);\n  position: absolute;\n  top: var(--slider_offset);\n  left: var(--slider_offset);\n  transition: var(--total_transition_duration) ease;\n  z-index: 10;\n}\n\n/* actions */\n\n.sw', colors: '#af0693,#1701a1,#f19d36,#fff,#f32a85', radii: 'var(--slider_radius)', shadows: '', techniques: '3d-transform,gradient,checkbox-input,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'javierBarroso_sharp-shrimp-7', cat: 'Toggle-switches', author: 'javierBarroso', tags: 'animation,switch,toggle', html: '<div class="container">\n  <label class="switch">\n    <input type="checkbox">\n    <span class="slider"></span>\n  </label>\n</div>', css: '\n/* From Uiverse.io by javierBarroso - Tags: animation, switch, toggle */\n/* The switch - the box around the slider */\n.switch {\n  font-size: 17px;\n  position: relative;\n  display: inline-block;\n  width: 3.5em;\n  height: 2em;\n}\n\n.container {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  width: 80px;\n  height: 80px;\n  border-radius: 80px;\n  box-shadow: 0px 5px 20px #11111166;\n  background: linear-gradient(to top, #cfd9df 0%, #e2ebf0 100%);\n}\n\n/* Hide default HTML checkbox */\n.switch input {\n  opacity: 0;\n  width: 0;\n  height: 0;\n}\n\n/* The slider */\n.slider {\n  position: absolute;\n  cursor: pointer;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  background-color: #ccc;\n  transition: .4s;\n  border-radius: 30px;\n  transform: rotate(-90deg);\n}\n\n.slider:before {\n  position: absolute;\n  content: "";\n  height: 1.4em;\n  width: 1.4em;\n  border-radius: 20px;\n  left: 0.3em;\n  bottom: 0.3em;\n  background-color: white;\n  transition: .4s cubic-bezier(0.19, 1, 0.22, 1);\n  transition-delay: .2s;\n}\n\n.switch input:checked + .slider {\n  background-color: #2196F3;\n  transform: rotate(90deg);\n}\n\n.switch input:focus + .slider {\n  box-shadow: 0 0 1px #2196F3;\n}\n\n.switch input:checked + .slider:before {\n  transition-delay: .2s;\n  transform: translateX(1.5em);\n}\n', colors: '#cfd9df,#ccc,#2196f3,#11111166,#e2ebf0', radii: '80px,30px,20px', shadows: '0px 5px 20px #11111166,0 0 1px #2196F3', techniques: 'cubic-bezier,3d-transform,glow-shadow,gradient,checkbox-input'),
const GalaxyComp(id: 'JaydipPrajapati1910_average-shrimp-57', cat: 'Toggle-switches', author: 'JaydipPrajapati1910', tags: 'switch,toggle switch,light switch', html: '<div class="fx-block">\n	<div class="toggle">\n		<div>\n			<input type="checkbox" id="toggles">\n			<div data-unchecked="On" data-checked="Off">\n			</div>\n		</div>\n	</div>\n</div>', css: '\n/* From Uiverse.io by JaydipPrajapati1910 - Tags: switch, toggle switch, light switch */\n.toggle > div {\n  position: relative;\n  padding: 10px;\n  width: 150px;\n  height: 75px;\n  border-radius: 50px;\n  box-shadow: 0 -1px 1px 0 rgba(0, 0, 0, .5), 0px 1px 1px 0 rgba(255, 255, 255, 1);\n  background: rgb(189, 191, 193);\n  background: linear-gradient(to bottom, rgba(189, 191, 193, 1) 0%, rgba(249, 251, 254, 1) 100%);\n}\n\n.toggle > div > input[type=checkbox] {\n  position: absolute;\n  opacity: 0;\n  top: -3px;\n  left: 17px;\n  width: 130px;\n  height: 55px;\n  z-index: 5;\n}\n\n.toggle > div > input[type=checkbox] ~ div {\n  width: 130px;\n  height: 55px;\n  border-radius: 50px;\n  border: 1px solid #979797;\n  box-shadow: inset 5px 0 0 0 rgba(0, 0, 0, .1), inset -5px 0 0 0 rgba(0, 0, 0, .1), inset -6px 0 0 0 rgba(255, 255, 255, .5), inset -4px 6px 11px -5px rgba(0, 0, 0, .2), inset 1px 1px 0 0 rgba(255, 255, 255, 1), -6px 4px 11px -7px rgba(0, 0, 0, .5);\n  background: rgb(253, 252, 251);\n  background: linear-gradient(to right, rgba(253, 252, 251, 1) 37%, rgba(229, 229, 229, 1) 61%);\n}\n\n.toggle > div > input[type=checkbox]:checked ~ div {\n  box-shadow: inset -5px 0 0 0 rgba(0, 0, 0, .1), inset 5px 0 0 0 rgba(0, 0, 0, .1), inset 6px 0 0 0 rgba(255, 255, 255, .5), inset -4px 6px 11px -5px rgba(0, 0, 0, .2), inset 1px 1px 0 0 rgba(255, 255, 255, 1), -6px 4px 11px -7px rgba(0, 0, 0, .5);\n  background: rgb(229, 229, 229);\n  background: linear-gradient(to right, rgba(229, 229, 229, 1) 39%, rgba(253, 252, 251, 1) 63%);\n}\n\n.toggle > div > input[type=checkbox] ~ div:before {\n  content: attr(data-unchecked);\n  display: block;\n  position: absolute;\n  border-radius: 10px;\n  top: 27px;\n  left: 30px;\n}\n\n.toggle > div > input[type=checkbox] ~ div:after {\n  content: attr(data-checked);\n  color: #df0000;\n  text-shadow: 0 1px 0 #fff, 0px 0 7px #df0000;\n  filter: dropshadow(color=#df0000, offx=0, offy=0);\n  display: block;\n  position: absolute;\n  border-radius: 10px;\n  top: 27px;\n  left: 100px;\n}\n\n.toggl', colors: '#979797,#119400,#000,#df0000,#007a08,#fff', radii: '50px,10px', shadows: '0 -1px 1px 0 rgba(0, 0, 0, .5), 0px 1px 1px 0 rgba(255, 255, 255, 1),inset 5px 0 0 0 rgba(0, 0, 0, .1), inset -5px 0 0 0 rgba(0, 0, 0, .1), inset -6px 0 0 0 rgba(255, 255, 255, .5), inset -,inset -5px 0 0 0 rgba(0, 0, 0, .1), inset 5px 0 0 0 rgba(0, 0, 0, .1), inset 6px 0 0 0 rgba(255, 255, 255, .5), inset -4', techniques: 'glow-shadow,text-shadow,gradient,filter-effect,checkbox-input'),
const GalaxyComp(id: 'mrhyddenn_silly-starfish-53', cat: 'Toggle-switches', author: 'mrhyddenn', tags: 'skeuomorphism,switch', html: '<label class="switch">\n    <div class="round"><input name="onoff" id="onoff" type="checkbox">\n        <div class="back"><label for="onoff" class="but"><span class="on">0</span><span class="off">I</span></label></div>\n    </div>\n</label>', css: '\n/* From Uiverse.io by mrhyddenn - Tags: skeuomorphism, switch */\ninput {\n  display: none\n}\n\n.on,.off {\n  position: absolute;\n  text-align: center;\n  text-shadow: inset 1px 1px 1px black;\n  width: 100%;\n}\n\n.on {\n  color: #fff;\n  top: 10px;\n  transition: all 0.1s;\n  font-family: sans-serif\n}\n\n.off {\n  color: #636161;\n  bottom: 5px;\n  transition: all 0.1s;\n  transform: scaleY(0.85);\n}\n\n.but {\n  background-color: #000;\n  border-radius: 400px 400px 400px 400px / 400px 400px 300px 300px;\n  border-bottom-width: 0px;\n  box-shadow: inset 8px 6px 5px -7px rgba(0,0,0,1)\n    ,inset -8px 6px 5px -7px rgba(0,0,0,1)\n    ,inset 0 -3px 2px -2px rgba(200,200,200,.5)\n    ,0 3px 3px -2px rgba(0,0,0,1)\n    ,inset 0 -230px 60px -200px rgba(255,255,255,.2)\n    ,inset 0 220px 40px -200px rgba(0,0,0,.3);\n  display: block;\n  font-size: 17px;\n  height: 60px;\n  position: relative;\n  transition: all 0.2s;\n  width: 40px;\n}\n\n.back {\n  background-color: #000;\n  background-image: -webkit-linear-gradient(0deg, transparent 30%, transparent 65%)\n    ,-webkit-linear-gradient(0deg, rgba(245, 245, 245, 0) 30%, rgba(150,150,150,.1) 50%, rgba(150,150,150,0) 70%);\n  border-radius: 115px;\n  box-sizing: border-box;\n  height: 85px;\n  padding: 4px 4px;\n  transition: all 0.2s;\n  width: 50px;\n}\n\ninput:checked + .back .on,input:checked + .back .off {\n  text-shadow: inset 1px 1px 1px black;\n}\n\ninput:checked + .back .on {\n  color: rgb(141, 141, 141);\n  top: 10px;\n  transform: scaleY(0.85);\n}\n\ninput:checked + .back .off {\n  color: #fff;\n  bottom: 5px;\n  transform: scaleY(1);\n}\n\ninput:checked + .back .but {\n  background: #232323;\n  background-image: -webkit-radial-gradient(55% 18%,circle closest-corner,rgba(0,0,0,.3) ,rgba(0,0,0,0));\n  border-radius: 410px 410px 410px 410px / 310px 310px 410px 410px;\n  box-shadow: inset 8px -4px 5px -7px rgba(0,0,0,1)\n    ,inset -8px -4px 5px -7px rgba(0,0,0,1)\n    , 0 -3px 8px -4px rgba(250,250,250,.4)\n    ,inset 0 3px 4px -2px rgba(10,10,10,1)\n    ,inset 0 280px 40px -200px rgba(0,', colors: '#636161,#000,#fff,#232323', radii: '115px,410px 410px 410px 410px / 310px 310px 410px 410px,400px 400px 400px 400px / 400px 400px 300px 300px', shadows: 'inset 8px 6px 5px -7px rgba(0,0,0,1)\n    ,inset -8px 6px 5px -7px rgba(0,0,0,1)\n    ,inset 0 -3px 2px -2px rgba(200,200,,inset 8px -4px 5px -7px rgba(0,0,0,1)\n    ,inset -8px -4px 5px -7px rgba(0,0,0,1)\n    , 0 -3px 8px -4px rgba(250,250,250,28px 28px 28px -28px rgba(0,0,0,.1)\n    ,-28px 28px 28px -22px rgba(0,0,0,.1)\n    ,0 30px 30px 0px rgba(0,0,0,.2)\n    ,i', techniques: '3d-transform,glow-shadow,text-shadow,gradient,checkbox-input'),
const GalaxyComp(id: 'Na3ar-17_fast-fireant-25', cat: 'Toggle-switches', author: 'Na3ar-17', tags: 'simple,animation,action,switch,dark,modern,click,toggle switch', html: '<label class="switch">\n  <input type="checkbox" />\n  <span class="slider">\n    <span class="yolk"> </span>\n    <span class="back"> </span>\n  </span>\n</label>', css: '\n/* From Uiverse.io by Na3ar-17  - Tags: simple, animation, action, switch, dark, modern, click, toggle switch */\n/* The switch - the box around the slider */\n.switch {\n  font-size: 17px;\n  position: relative;\n  display: inline-block;\n  width: 95px;\n  height: 50px;\n  background-color: #2a2a2a;\n  border-radius: 30px;\n  cursor: pointer;\n}\n\n/* Hide default HTML checkbox */\n.switch input {\n  opacity: 0;\n  width: 0;\n  height: 0;\n}\n\n/* The slider */\n.slider {\n  position: absolute;\n  top: 50%;\n  left: 26%;\n  transform: translate(-50%, -50%);\n  height: 40px;\n  width: 40px;\n  border-radius: 50%;\n  background-color: white;\n  transition: 0.3s cubic-bezier(0.68, -0.25, 0.265, 1.1);\n  overflow: hidden;\n}\n\n.slider .yolk {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  width: 25px;\n  aspect-ratio: 1/1;\n  background-color: #f2a828;\n  border-radius: 50%;\n  -webkit-box-shadow: inset -2px -2px 43px -35px rgba(255, 255, 255, 1);\n  -moz-box-shadow: inset -2px -2px 43px -35px rgba(255, 255, 255, 1);\n  box-shadow: inset -2px -2px 43px -35px rgba(255, 255, 255, 1);\n}\n\n.slider .yolk::before {\n  content: "";\n  position: absolute;\n  top: 50%;\n  left: -22px;\n  transform: translate(-50%, -50%);\n  width: 30px;\n  height: 30px;\n  background-color: #cabea8;\n  border-radius: 50%;\n}\n\n.slider .yolk::after {\n  content: "";\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%) rotate(45deg);\n  width: 16px;\n  height: 16px;\n  background-color: transparent;\n  border-left: 6px solid #fff;\n  clip-path: circle(50% at 50% 50%);\n}\n\n.slider .back {\n  position: absolute;\n  top: 50%;\n  left: -50%;\n  transform: translate(-50%, -50%);\n  height: 40px;\n  width: 40px;\n  border-radius: 50%;\n  background-color: #cabea8;\n  transition: 0.3s cubic-bezier(0, 0, 0.265, 1.1);\n  overflow: hidden;\n}\n\n.slider .back::before {\n  content: "";\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  width: 25px;\n  aspect-ratio: 1/1;\n  backgr', colors: '#eec076,#cabea8,#f2a828,#2a2a2a,#fff', radii: '30px,50%', shadows: 'inset -2px -2px 43px -35px rgba(255, 255, 255, 1),inset -2px -2px 43px -35px rgba(255, 255, 255, 1),inset -2px -2px 43px -35px rgba(255, 255, 255, 1)', techniques: 'cubic-bezier,3d-transform,clip-path,checkbox-input,pseudo-elements'),
const GalaxyComp(id: 'Nawsome_green-turkey-32', cat: 'Toggle-switches', author: 'Nawsome', tags: 'switch', html: '<div id="app">\n  <label class="checker">\n    <input type="checkbox" class="checkbox">\n    <div class="check-bg"></div>\n    <div class="checkmark">\n      <svg viewBox="0 0 100 100">\n        <path stroke-linejoin="round" stroke-linecap="round" stroke-width="15" stroke="#FFF" fill="none" d="M20,55 L40,75 L77,27"></path>\n      </svg>\n    </div>\n  </label>\n</div>', css: '\n/* From Uiverse.io by Nawsome - Tags: switch */\n.checker {\n  display: block;\n  font-size: 25px;\n  height: 1em;\n  width: 2.5em;\n  box-sizing: content-box;\n  padding: 0.15em;\n  border-radius: 0.25em;\n  cursor: pointer;\n}\n\n.checkmark {\n  width: 1em;\n  height: 1em;\n  transform: translateX(-0.4em);\n  z-index: 5;\n}\n\n.checkmark svg {\n  display: block;\n  background: #e5e5e5;\n  transform: translateX(0.4em);\n  border-radius: 0.15em;\n  transition: background-color var(--duration) ease, transform calc(var(--duration) * 1.5) ease;\n}\n\n.checkmark svg path {\n  stroke-dasharray: 90 90;\n  stroke-dashoffset: 90;\n  transition: stroke-dashoffset calc(var(--duration) / 3) linear calc(var(--duration) / 3);\n}\n\n.checkbox {\n  position: absolute;\n  top: 0;\n  left: 0;\n  opacity: 0.4;\n  visibility: hidden;\n}\n\n.checkbox:checked ~ .checkmark {\n  transform: translate(1.9em);\n}\n\n.checkbox:checked ~ .checkmark svg {\n  background: #77c44c;\n  transform: translate(-0.4em);\n}\n\n.checkbox:checked ~ .checkmark svg path {\n  stroke-dashoffset: 0;\n}\n\n.check-bg {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  border-radius: inherit;\n  background: white;\n  z-index: 2;\n}\n\n.check-bg:before, .check-bg:after {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: 0;\n  height: 100%;\n  width: 100%;\n  border-radius: inherit;\n}\n\n.check-bg:after {\n  background: white;\n}\n\n.check-bg:before {\n  transform: translateY(30%);\n  transform-origin: bottom center;\n  background: black;\n  filter: blur(0.25em);\n  opacity: 0.2;\n  z-index: -1;\n}\n\n.checker.checker:active {\n  transform: scale(0.85);\n  transition-duration: calc(var(--duration) / 2);\n}\n\n.checker.checker:active .check-bg::before {\n  transform: translateY(0) scale(0.8);\n  opacity: 0.2;\n}\n\n*,\n*::before,\n*::after {\n  box-sizing: border-box;\n  position: relative;\n}\n\nhtml {\n  height: 100%;\n}\n\nbody {\n  background-color: #f2f2f2;\n  height: 100%;\n  width: 100%;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n', colors: '#e5e5e5,#77c44c,#f2f2f2', radii: 'inherit,0.25em,0.15em', shadows: '', techniques: 'glassmorphism,3d-transform,checkbox-input,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'PriyanshuGupta28_little-grasshopper-46', cat: 'Toggle-switches', author: 'PriyanshuGupta28', tags: 'switch,toggle switch,cool switch', html: '<div class="checkbox-wrapper">\n  <label class="toggleButton">\n    <input type="checkbox">\n    <div>\n      <svg viewBox="0 0 44 44">\n        <path transform="translate(-2.000000, -2.000000)" d="M14,24 L21,31 L39.7428882,11.5937758 C35.2809627,6.53125861 30.0333333,4 24,4 C12.95,4 4,12.95 4,24 C4,35.05 12.95,44 24,44 C35.05,44 44,35.05 44,24 C44,19.3 42.5809627,15.1645919 39.7428882,11.5937758"></path>\n      </svg>\n    </div>\n  </label>\n</div>', css: '\n/* From Uiverse.io by PriyanshuGupta28 - Tags: switch, toggle switch, cool switch */\n.checkbox-wrapper input[type="checkbox"] {\n  display: none;\n  visibility: hidden;\n}\n\n.checkbox-wrapper *,\n  .checkbox-wrapper *::before,\n  .checkbox-wrapper *::after {\n  box-sizing: border-box;\n}\n\n.checkbox-wrapper .toggleButton {\n  cursor: pointer;\n  display: block;\n  transform-origin: 50% 50%;\n  transform-style: preserve-3d;\n  transition: transform 0.14s ease;\n}\n\n.checkbox-wrapper .toggleButton:active {\n  transform: rotateX(30deg);\n}\n\n.checkbox-wrapper .toggleButton input + div {\n  border: 3px solid rgba(0, 89, 255, 0.288);\n  border-radius: 50%;\n  position: relative;\n  width: 44px;\n  height: 44px;\n}\n\n.checkbox-wrapper .toggleButton input + div svg {\n  fill: none;\n  stroke-width: 3.6;\n  stroke: rgb(0, 0, 0);\n  stroke-linecap: round;\n  stroke-linejoin: round;\n  width: 44px;\n  height: 44px;\n  display: block;\n  position: absolute;\n  left: -3px;\n  top: -3px;\n  right: -3px;\n  bottom: -3px;\n  z-index: 1;\n  stroke-dashoffset: 124.6;\n  stroke-dasharray: 0 162.6 133 29.6;\n  transition: all 0.4s ease 0s;\n}\n\n.checkbox-wrapper .toggleButton input + div:before,\n  .checkbox-wrapper .toggleButton input + div:after {\n  content: "";\n  width: 3px;\n  height: 16px;\n  background: #000;\n  position: absolute;\n  left: 50%;\n  top: 50%;\n  border-radius: 5px;\n}\n\n.checkbox-wrapper .toggleButton input + div:before {\n  opacity: 0;\n  transform: scale(0.3) translate(-50%, -50%) rotate(45deg);\n  -webkit-animation: bounceInBefore-44 0.3s linear forwards 0.3s;\n  animation: bounceInBefore-44 0.3s linear forwards 0.3s;\n}\n\n.checkbox-wrapper .toggleButton input + div:after {\n  opacity: 0;\n  transform: scale(0.3) translate(-50%, -50%) rotate(-45deg);\n  -webkit-animation: bounceInAfter-44 0.3s linear forwards 0.3s;\n  animation: bounceInAfter-44 0.3s linear forwards 0.3s;\n}\n\n.checkbox-wrapper .toggleButton input:checked + div svg {\n  stroke-dashoffset: 162.6;\n  stroke-dasharray: 0 162.6 28 134.6;\n  transition: all 0.4s ea', colors: '#000', radii: '50%,5px', shadows: '', techniques: '3d-transform,animation,checkbox-input,svg-icon,pseudo-elements'),
