center;\n  transform-origin: left;\n  transform: rotateX(10deg) rotateY(-45deg);\n  transform-style: preserve-3d;\n  transition: all 150ms;\n}\n\n.right::before {\n  position: absolute;\n  content: "";\n  width: 100%;\n  height: 100%;\n  background-color: rgb(206, 206, 206);\n  transform-origin: center right;\n  transform: rotateY(-90deg);\n}\n\n.right::after {\n  position: absolute;\n  content: "";\n  width: 100%;\n  heigh', colors: '#373737,#f3f3f3,#487bdb', radii: '.1em', shadows: '-.3em 0 0 0 #373737,-.3em .3em 0 0 #373737,.3em 0 0 0 #373737,.3em .3em 0 0 #373737,0 .3em 0 0 #373737', techniques: '3d-transform,glow-shadow,typography-transform,checkbox-input,pseudo-elements'),
const GalaxyComp(id: 'Subaashbala_quiet-ape-66', cat: 'Toggle-switches', author: 'Subaashbala', tags: 'switch', html: '<label class="switch">\n  <input type="checkbox" />\n  <span class="slider"></span>\n</label>', css: '\n/* From Uiverse.io by Subaashbala  - Tags: switch */\n/* The switch - the box around the slider */\n.switch {\n  --INITIAL-SWITCH-TRACK-COLOR: #fffbeb;\n  --INITIAL-THUMB-COLOR: #ff5722;\n  --OVERALL-TRANSITION-DURATION: 500ms; /* Overall transition speed */\n  font-size: 17px;\n  position: relative;\n  display: inline-block;\n  width: 3.75em;\n  height: 2em;\n}\n\n/* Hide default HTML checkbox */\n.switch input {\n  opacity: 0;\n  width: 0;\n  height: 0;\n}\n\n/* The slider */\n.slider {\n  position: absolute;\n  cursor: pointer;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  background-color: var(--INITIAL-SWITCH-TRACK-COLOR);\n  transition: var(--OVERALL-TRANSITION-DURATION);\n  border-radius: 30px;\n  overflow: hidden;\n}\n\n/* Thumb */\n.slider:before {\n  position: absolute;\n  content: "";\n  height: 100%;\n  aspect-ratio: 1;\n  border-radius: 20px;\n  left: 0;\n  bottom: 0;\n  background-color: var(--INITIAL-THUMB-COLOR);\n  transition: var(--OVERALL-TRANSITION-DURATION);\n}\n\n.switch input:checked + .slider {\n  background-color: var(--INITIAL-THUMB-COLOR);\n}\n\n/* Actions to be performed when the switch is TOGGLED ON */\n.switch input:checked + .slider::before {\n  transform-origin: left;\n  background-color: var(--INITIAL-SWITCH-TRACK-COLOR);\n  animation: wobble var(--OVERALL-TRANSITION-DURATION)\n    cubic-bezier(0.075, 0.82, 0.165, 1);\n  transform: scale(1, 1) translateX(2rem);\n}\n\n/* Actions to be performed when the switch is TOGGLED OFF */\n.switch input:not(:checked) + .slider::before {\n  transform-origin: right;\n  animation: reverse-wobble var(--OVERALL-TRANSITION-DURATION)\n    cubic-bezier(0.075, 0.82, 0.165, 1);\n}\n\n@keyframes wobble {\n  0% {\n    transform: scale(1, 1);\n  }\n  50% {\n    transform: scale(3, 1);\n  }\n  100% {\n    transform: scale(1, 1) translateX(2rem);\n  }\n}\n\n@keyframes reverse-wobble {\n  0% {\n    transform: scale(1, 1) translateX(2rem);\n  }\n  50% {\n    transform: scale(3, 1);\n  }\n  100% {\n    transform: scale(1, 1) translateX(0);\n  }\n}\n\n', colors: '#ff5722,#fffbeb', radii: '30px,20px', shadows: '', techniques: 'cubic-bezier,3d-transform,animation,checkbox-input,pseudo-elements'),
const GalaxyComp(id: 'Type-Delta_happy-mule-45', cat: 'Toggle-switches', author: 'Type-Delta', tags: 'animation,minimalist,theme-switch,light&dark,toggle switch', html: '<label\n  for="themeToggle"\n  class="themeToggle st-sunMoonThemeToggleBtn"\n  type="checkbox"\n>\n  <input type="checkbox" id="themeToggle" class="themeToggleInput" />\n  <svg\n    width="18"\n    height="18"\n    viewBox="0 0 20 20"\n    fill="currentColor"\n    stroke="none"\n  >\n    <mask id="moon-mask">\n      <rect x="0" y="0" width="20" height="20" fill="white"></rect>\n      <circle cx="11" cy="3" r="8" fill="black"></circle>\n    </mask>\n    <circle\n      class="sunMoon"\n      cx="10"\n      cy="10"\n      r="8"\n      mask="url(#moon-mask)"\n    ></circle>\n    <g>\n      <circle class="sunRay sunRay1" cx="18" cy="10" r="1.5"></circle>\n      <circle class="sunRay sunRay2" cx="14" cy="16.928" r="1.5"></circle>\n      <circle class="sunRay sunRay3" cx="6" cy="16.928" r="1.5"></circle>\n      <circle class="sunRay sunRay4" cx="2" cy="10" r="1.5"></circle>\n      <circle class="sunRay sunRay5" cx="6" cy="3.1718" r="1.5"></circle>\n      <circle class="sunRay sunRay6" cx="14" cy="3.1718" r="1.5"></circle>\n    </g>\n  </svg>\n</label>', css: '\n/* From Uiverse.io by Type-Delta  - Tags: animation, minimalist, theme-switch, light&dark, toggle switch */\n/* a clone from joshwcomeau.com \n * but this version runs on pure CSS\n */\n\n.themeToggle {\n  color: #bbb;\n  width: 3em;\n}\n\n.st-sunMoonThemeToggleBtn {\n  position: relative;\n  cursor: pointer;\n}\n\n.st-sunMoonThemeToggleBtn .themeToggleInput {\n  opacity: 0;\n  width: 100%;\n  aspect-ratio: 1;\n}\n\n.st-sunMoonThemeToggleBtn svg {\n  position: absolute;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  transition: transform 0.4s ease;\n  transform: rotate(40deg);\n}\n\n.st-sunMoonThemeToggleBtn svg .sunMoon {\n  transform-origin: center center;\n  transition: inherit;\n  transform: scale(1);\n}\n\n.st-sunMoonThemeToggleBtn svg .sunRay {\n  transform-origin: center center;\n  transform: scale(0);\n}\n\n.st-sunMoonThemeToggleBtn svg mask > circle {\n  transition: transform 0.64s cubic-bezier(0.41, 0.64, 0.32, 1.575);\n  transform: translate(0px, 0px);\n}\n\n.st-sunMoonThemeToggleBtn svg .sunRay2 {\n  animation-delay: 0.05s !important;\n}\n.st-sunMoonThemeToggleBtn svg .sunRay3 {\n  animation-delay: 0.1s !important;\n}\n.st-sunMoonThemeToggleBtn svg .sunRay4 {\n  animation-delay: 0.17s !important;\n}\n.st-sunMoonThemeToggleBtn svg .sunRay5 {\n  animation-delay: 0.25s !important;\n}\n.st-sunMoonThemeToggleBtn svg .sunRay5 {\n  animation-delay: 0.29s !important;\n}\n\n.st-sunMoonThemeToggleBtn .themeToggleInput:checked + svg {\n  transform: rotate(90deg);\n}\n.st-sunMoonThemeToggleBtn .themeToggleInput:checked + svg mask > circle {\n  transform: translate(16px, -3px);\n}\n.st-sunMoonThemeToggleBtn .themeToggleInput:checked + svg .sunMoon {\n  transform: scale(0.55);\n}\n.st-sunMoonThemeToggleBtn .themeToggleInput:checked + svg .sunRay {\n  animation: showRay1832 0.4s ease 0s 1 forwards;\n}\n\n@keyframes showRay1832 {\n  0% {\n    transform: scale(0);\n  }\n  100% {\n    transform: scale(1);\n  }\n}\n\n', colors: '#bbb', radii: '', shadows: '', techniques: 'cubic-bezier,3d-transform,animation,checkbox-input,svg-icon'),
const GalaxyComp(id: 'Yaya12085_lovely-firefox-94', cat: 'Toggle-switches', author: 'Yaya12085', tags: 'neumorphism,skeuomorphism,icon,3d,button,switch,realistic,toggle', html: '<div class="container">\n  <input id="checkbox" type="checkbox">\n   <label class="button" for="checkbox">\n    <span class="icon">\n     <svg viewBox="0 0 24 24" fill="" xmlns="http://www.w3.org/2000/svg"><g id="SVGRepo_bgCarrier" stroke-width="0"></g><g id="SVGRepo_tracerCarrier" stroke-linecap="round" stroke-linejoin="round"></g><g id="SVGRepo_iconCarrier"> <path d="M17.35 12.7901C17.1686 12.7907 16.9935 12.7229 16.86 12.6001C15.5322 11.411 13.8124 10.7534 12.03 10.7534C10.2476 10.7534 8.52779 11.411 7.19999 12.6001C7.12649 12.6658 7.04075 12.7164 6.94767 12.749C6.85459 12.7816 6.756 12.7955 6.65755 12.7899C6.55909 12.7843 6.4627 12.7594 6.37389 12.7165C6.28508 12.6736 6.2056 12.6137 6.13999 12.5401C6.0109 12.3892 5.94595 12.1939 5.95904 11.9958C5.97212 11.7977 6.06219 11.6126 6.20999 11.4801C7.80752 10.0423 9.88072 9.2467 12.03 9.2467C14.1793 9.2467 16.2525 10.0423 17.85 11.4801C17.9978 11.6126 18.0879 11.7977 18.1009 11.9958C18.114 12.1939 18.0491 12.3892 17.92 12.5401C17.8469 12.6181 17.7586 12.6806 17.6606 12.7236C17.5627 12.7665 17.457 12.7892 17.35 12.7901Z" fill=""></path> <path d="M20 10C19.811 9.99907 19.6292 9.92777 19.49 9.80002C17.4685 7.87306 14.7828 6.79812 11.99 6.79812C9.19719 6.79812 6.51153 7.87306 4.48999 9.80002C4.42116 9.88186 4.33563 9.94804 4.23912 9.99411C4.14262 10.0402 4.03738 10.0651 3.93046 10.0672C3.82354 10.0692 3.71742 10.0484 3.61921 10.0061C3.521 9.96375 3.43298 9.90092 3.36105 9.82179C3.28911 9.74267 3.23493 9.64907 3.20214 9.54729C3.16934 9.4', css: '\n/* From Uiverse.io by Yaya12085 - Tags: neumorphism, skeuomorphism, icon, 3d, button, switch, realistic, toggle */\n.container {\n  width: 7em;\n  height: 7em;\n  position: relative;\n}\n\n.button {\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  border-radius: 50%;\n  border: 4px solid #090909;\n  background-color: transparent;\n  background-image: linear-gradient(145deg, #171717, #444245);\n  box-sizing: border-box;\n  box-shadow: inset 2px 2px 0 #7d7c7e, inset -2px -2px 0px #1c1c1c;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.container input {\n  display: none;\n}\n\n.button::before {\n  position: absolute;\n  content: "";\n  width: 7.25em;\n  height: 7.25em;\n  border-radius: inherit;\n  background-color: transparent;\n  background-image: linear-gradient(145deg, #262626, #606060);\n  z-index: -1;\n  box-shadow: 11px 11px 22px #141414, -11px -11px 22px #525252;\n}\n\n.button .icon {\n  width: 60px;\n  height: 60px;\n  display: inline-block;\n}\n\n.button .icon svg {\n  height: 100%;\n  width: 100%;\n  fill: #a5a5a5;\n}\n\n.container  input:checked + .button {\n  box-shadow: inset -2px -2px 0 #5e5e5e,inset 2px 2px 0 #1c1c1c;\n  border: 4px solid rgba(77, 124, 255, 0.281);\n  animation: animeBorder .3s linear alternate-reverse infinite;\n}\n\n.container input:checked + .button .icon svg {\n  fill: rgb(77, 124, 255);\n  animation: animeFill .3s linear alternate-reverse infinite;\n}\n\n@keyframes animeFill {\n  to {\n    fill: rgba(77, 124, 255, 0.642);\n  }\n}\n\n@keyframes animeBorder {\n  to {\n    border-color: rgba(77, 124, 255, 0.137);\n  }\n}\n', colors: '#444245,#090909,#171717,#1c1c1c,#262626,#606060,#525252,#5e5e5e,#141414,#a5a5a5', radii: '50%,inherit', shadows: 'inset 2px 2px 0 #7d7c7e, inset -2px -2px 0px #1c1c1c,11px 11px 22px #141414, -11px -11px 22px #525252,inset -2px -2px 0 #5e5e5e,inset 2px 2px 0 #1c1c1c', techniques: 'gradient,animation,checkbox-input,svg-icon,pseudo-elements'),
const GalaxyComp(id: '0xnihilism_silly-quail-9', cat: 'Inputs', author: '0xnihilism', tags: '', html: '<div class="input-container">\n  <input\n    class="input"\n    name="text"\n    type="text"\n    placeholder="Search the internet..."\n  />\n</div>', css: '\n/* From Uiverse.io by 0xnihilism  - Tags:  */\n.input {\n  width: 100%;\n  max-width: 270px;\n  height: 60px;\n  padding: 12px;\n  font-size: 18px;\n  font-family: "Courier New", monospace;\n  color: #000;\n  background-color: #fff;\n  border: 4px solid #000;\n  border-radius: 0;\n  outline: none;\n  transition: all 0.3s ease;\n  box-shadow: 8px 8px 0 #000;\n}\n\n.input::placeholder {\n  color: #888;\n}\n\n.input:hover {\n  transform: translate(-4px, -4px);\n  box-shadow: 12px 12px 0 #000;\n}\n\n.input:focus {\n  background-color: #000;\n  color: #fff;\n  border-color: #ffffff;\n}\n\n.input:focus::placeholder {\n  color: #fff;\n}\n\n@keyframes typing {\n  from {\n    width: 0;\n  }\n  to {\n    width: 100%;\n  }\n}\n\n@keyframes blink {\n  50% {\n    border-color: transparent;\n  }\n}\n\n.input:focus::after {\n  content: "|";\n  position: absolute;\n  right: 10px;\n  animation: blink 0.7s step-end infinite;\n}\n\n.input:valid {\n  animation: typing 2s steps(30, end);\n}\n.input-container {\n  position: relative;\n  width: 100%;\n  max-width: 270px;\n}\n\n.input {\n  width: 100%;\n  height: 60px;\n  padding: 12px;\n  font-size: 18px;\n  font-family: "Courier New", monospace;\n  color: #000;\n  background-color: #fff;\n  border: 4px solid #000;\n  border-radius: 0;\n  outline: none;\n  transition: all 0.3s ease;\n  box-shadow: 8px 8px 0 #000;\n}\n\n.input::placeholder {\n  color: #888;\n}\n\n.input:hover {\n  transform: translate(-4px, -4px);\n  box-shadow: 12px 12px 0 #000;\n}\n\n.input:focus {\n  background-color: #010101;\n  color: #fff;\n  border-color: #d6d9dd;\n}\n\n.input:focus::placeholder {\n  color: #fff;\n}\n\n@keyframes shake {\n  0% {\n    transform: translateX(0);\n  }\n  25% {\n    transform: translateX(-5px) rotate(-5deg);\n  }\n  50% {\n    transform: translateX(5px) rotate(5deg);\n  }\n  75% {\n    transform: translateX(-5px) rotate(-5deg);\n  }\n  100% {\n    transform: translateX(0);\n  }\n}\n\n.input:focus {\n  animation: shake 0.5s ease-in-out;\n}\n\n@keyframes glitch {\n  0% {\n    transform: none;\n    opacity: 1;\n  }\n  7% {\n    transform: skew(-0.5deg, -0.9deg);\n   ', colors: '#010101,#000,#888,#d6d9dd,#ffffff,#fff', radii: '0', shadows: '8px 8px 0 #000,12px 12px 0 #000,8px 8px 0 #000', techniques: '3d-transform,glow-shadow,text-shadow,animation,pseudo-elements'),
const GalaxyComp(id: 'Cobp_lazy-frog-59', cat: 'Inputs', author: 'Cobp', tags: 'material design,blue,pink,input,search,shadow,html,css', html: '<div class="container">\n  <div class="shadow-container"></div>\n  <label class="search-bar" for="text">\n    <i class="icon">\n      <svg viewBox="0 0 512 512">\n        <path\n          d="M221.09 64a157.09 157.09 0 1 0 157.09 157.09A157.1 157.1 0 0 0 221.09 64Z"\n          stroke-width="32"\n          stroke-miterlimit="10"\n          stroke="currentColor"\n          fill="none"\n        ></path>\n        <path\n          d="M338.29 338.29L448 448"\n          stroke-width="32"\n          stroke-miterlimit="10"\n          stroke-linecap="round"\n          stroke="currentColor"\n          fill="none"\n        ></path>\n      </svg>\n    </i>\n    <input\n      placeholder="Search..."\n      class="input"\n      name="text"\n      type="text"\n      id="text"\n    />\n    <button class="icon filter" type="button">\n      <svg viewBox="0 0 24 24">\n        <path\n          color="currentColor"\n          d="M8.857 12.506C6.37 10.646 4.596 8.6 3.627 7.45c-.3-.356-.398-.617-.457-1.076c-.202-1.572-.303-2.358.158-2.866S4.604 3 6.234 3h11.532c1.63 0 2.445 0 2.906.507c.461.508.36 1.294.158 2.866c-.06.459-.158.72-.457 1.076c-.97 1.152-2.747 3.202-5.24 5.065a1.05 1.05 0 0 0-.402.747c-.247 2.731-.475 4.227-.617 4.983c-.229 1.222-1.96 1.957-2.888 2.612c-.552.39-1.222-.074-1.293-.678a196 196 0 0 1-.674-6.917a1.05 1.05 0 0 0-.402-.755"\n          stroke-width="1.5"\n          stroke-linejoin="round"\n          stroke-linecap="round"\n          stroke="currentColor"\n          fill="none"\n        ></path>\n      </svg>\n    </bu', css: '\n/* From Uiverse.io by Cobp  - Tags: material design, blue, pink, input, search, shadow, html, css */\n.container {\n  --foreground-color-1: rgba(225, 225, 225, 0.5);\n  --foreground-color-3: rgba(98, 98, 98, 0.3);\n  --foreground-color-2: #ffffff;\n  --background-color-1: #070807;\n  position: relative;\n  padding: 2px;\n  border-radius: 16px;\n  background-image: linear-gradient(\n    325deg,\n    #4d3acd 0%,\n    #4d3acd 10%,\n    rgba(98, 98, 98, 0.3) 25%,\n    rgba(98, 98, 98, 0.3) 50%,\n    rgba(98, 98, 98, 0.3) 75%,\n    #cd3aad 90%,\n    #cd3aad 100%\n  );\n}\n.container::after {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: 0;\n  background-color: #ffffff;\n  width: 60px;\n  height: 30px;\n  border-radius: 14px 50% 0 10px;\n  z-index: -1;\n  box-shadow: 0 0 4px #ffffff, 0 0 50px 1px #ffffff, 0 0 50px 10px #cd3aad;\n}\n.container::before {\n  content: "";\n  position: absolute;\n  bottom: 0;\n  right: 0;\n  background-color: #ffffff;\n  width: 60px;\n  height: 30px;\n  border-radius: 0 10px 14px 50%;\n  z-index: -1;\n  box-shadow: 0 0 4px #ffffff, 0 0 10px 1px #ffffff, 0 0 50px 10px #4d3acd;\n}\n.shadow-container {\n  position: absolute;\n  border-radius: 16px;\n  background-image: linear-gradient(\n    325deg,\n    #3b82f6 0%,\n    #3b82f6 20%,\n    transparent 25%,\n    transparent 50%,\n    transparent 75%,\n    #cd3aad 80%,\n    #cd3aad 100%\n  );\n  filter: blur(40px);\n  inset: 0;\n  transition: all 0.3s ease-in-out;\n  z-index: -1;\n}\n.search-bar {\n  padding: 8px;\n  background-color: var(--background-color-1);\n  color: var(--foreground-color-1);\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  border-radius: 14px;\n  cursor: text;\n}\n.icon {\n  width: 32px;\n  height: 32px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n.icon svg {\n  padding: 4px;\n}\n.icon.filter {\n  border: 2px solid transparent;\n  background-image: linear-gradient(\n    to top,\n    #5b5b5b 0%,\n    #070807 40%,\n    #070807 60%,\n    #5b5b5b 100%\n  );\n  border-radius: 8px;\n  color: var(--foregroun', colors: '#ffffff,#424242,#5b5b5b,#cd3aad,#3b82f6,#070807,#4d3acd', radii: '14px 50% 0 10px,16px,14px,0 10px 14px 50%,8px', shadows: '0 0 4px #ffffff, 0 0 50px 1px #ffffff, 0 0 50px 10px #cd3aad,0 0 4px #ffffff, 0 0 10px 1px #ffffff, 0 0 50px 10px #4d3acd,inset 0 3px 3px -2px #424242, inset 0 -3px 3px -2px #424242', techniques: 'glassmorphism,glow-shadow,gradient,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'EddyBel_rare-baboon-42', cat: 'Inputs', author: 'EddyBel', tags: 'input', html: '<div class="input__container">\n  <div class="shadow__input"></div>\n  <button class="input__button__shadow">\n    <svg fill="none" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" height="20px" width="20px">\n      <path d="M4 9a5 5 0 1110 0A5 5 0 014 9zm5-7a7 7 0 104.2 12.6.999.999 0 00.093.107l3 3a1 1 0 001.414-1.414l-3-3a.999.999 0 00-.107-.093A7 7 0 009 2z" fill-rule="evenodd" fill="#17202A"></path>\n    </svg>\n  </button>\n  <input type="text" name="text" class="input__search" placeholder="What do you want to search?">\n</div>', css: '\n/* From Uiverse.io by EddyBel - Tags: input */\n.input__container {\n  position: relative;\n  background: rgba(255, 255, 255, 0.664);\n  padding: 10px 15px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  gap: 5px;\n  border-radius: 22px;\n  max-width: 300px;\n  transition: transform 400ms;\n  transform-style: preserve-3d;\n  transform: rotateX(15deg) rotateY(-20deg);\n  perspective: 500px;\n}\n\n.shadow__input {\n  content: "";\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  left: 0;\n  bottom: 0;\n  z-index: -1;\n  filter: blur(30px);\n  border-radius: 20px;\n  background-color: #999cff;\n  background-image: radial-gradient(at 85% 51%, hsla(60,60%,61%,1) 0px, transparent 50%),\n    radial-gradient(at 74% 68%, hsla(235,69%,77%,1) 0px, transparent 50%),\n    radial-gradient(at 64% 79%, hsla(284,72%,73%,1) 0px, transparent 50%),\n    radial-gradient(at 75% 16%, hsla(283,60%,72%,1) 0px, transparent 50%),\n    radial-gradient(at 90% 65%, hsla(153,70%,64%,1) 0px, transparent 50%),\n    radial-gradient(at 91% 83%, hsla(283,74%,69%,1) 0px, transparent 50%),\n    radial-gradient(at 72% 91%, hsla(213,75%,75%,1) 0px, transparent 50%);\n}\n\n.input__button__shadow {\n  cursor: pointer;\n  border: none;\n  background: none;\n  transition: transform 400ms, background 400ms;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  border-radius: 12px;\n  padding: 5px;\n}\n\n.input__button__shadow:hover {\n  background: rgba(255, 255, 255, 0.411);\n}\n\n.input__search {\n  width: 100%;\n  border-radius: 20px;\n  outline: none;\n  border: none;\n  padding: 8px;\n  position: relative;\n}\n', colors: '#999cff', radii: '12px,22px,20px', shadows: '', techniques: 'glassmorphism,3d-transform,gradient,perspective,svg-icon'),
const GalaxyComp(id: 'JaydipPrajapati1910_black-impala-70', cat: 'Inputs', author: 'JaydipPrajapati1910', tags: 'animation,input,input effect', html: '<input class="input" name="text" type="text" placeholder="Name">', css: '\n/* From Uiverse.io by JaydipPrajapati1910 - Tags: animation, input, input effect  */\n.input {\n  max-width: 190px;\n  border: none;\n  outline: none;\n  background: none;\n  font-size: 18px;\n  color: #fff;\n  padding: 15px 5px 10px 20px;\n  background-image: linear-gradient(to right, rgba(0, 0, 0, 0.8), rgba(0, 0, 0, 0)),\n    linear-gradient(to bottom, rgba(0, 0, 0, 0.8), rgba(0, 0, 0, 0));\n  background-position: bottom right, bottom right;\n  background-size: 100% 100%, 100% 100%;\n  background-repeat: no-repeat;\n  box-shadow: inset -4px -10px 0px rgba(255, 255, 255, 0.4),\n    inset -4px -8px 0px rgba(0, 0, 0, 0.3),\n    0px 2px 1px rgba(0, 0, 0, 0.3),\n    0px 2px 1px rgba(255, 255, 255, 0.1);\n  transform: perspective(70px) rotateX(5deg) rotateY(0deg);\n  border-radius: 10px;\n}\n\n.input::before {\n  background-image: linear-gradient(to right, rgba(0, 0, 0, 0.8), rgba(0, 0, 0, 0)),\n    linear-gradient(to bottom, rgba(0, 0, 0, 0.8), rgba(0, 0, 0, 0));\n  background-position: bottom right, bottom right;\n  background-size: 100% 100%, 100% 100%;\n  background-repeat: no-repeat;\n  z-index: -1;\n  border-radius: 15px;\n  transition: all .1s ease-in-out 0s;\n}\n\n.input:focus {\n  border: 2px solid #c3c6ce;\n}\n\n.input::placeholder {\n  color: #fff;\n  transition: all 0.3s ease;\n}\n\n.input:focus::placeholder {\n  color: #999;\n}\n\n\n\n', colors: '#999,#fff,#c3c6ce', radii: '10px,15px', shadows: 'inset -4px -10px 0px rgba(255, 255, 255, 0.4),\n    inset -4px -8px 0px rgba(0, 0, 0, 0.3),\n    0px 2px 1px rgba(0, 0, 0,', techniques: '3d-transform,glow-shadow,gradient,perspective,pseudo-elements'),
const GalaxyComp(id: 'andrew-demchenk0_afraid-cougar-9', cat: 'Forms', author: 'andrew-demchenk0', tags: '3d,form,sign-up,toggle,animated,login form,toggle switch,log in,sign up form,click animation', html: '<div class="wrapper">\n        <div class="card-switch">\n            <label class="switch">\n               <input type="checkbox" class="toggle">\n               <span class="slider"></span>\n               <span class="card-side"></span>\n               <div class="flip-card__inner">\n                  <div class="flip-card__front">\n                     <div class="title">Log in</div>\n                     <form class="flip-card__form" action="">\n                        <input class="flip-card__input" name="email" placeholder="Email" type="email">\n                        <input class="flip-card__input" name="password" placeholder="Password" type="password">\n                        <button class="flip-card__btn">Let`s go!</button>\n                     </form>\n                  </div>\n                  <div class="flip-card__back">\n                     <div class="title">Sign up</div>\n                     <form class="flip-card__form" action="">\n                        <input class="flip-card__input" placeholder="Name" type="name">\n                        <input class="flip-card__input" name="email" placeholder="Email" type="email">\n                        <input class="flip-card__input" name="password" placeholder="Password" type="password">\n                        <button class="flip-card__btn">Confirm!</button>\n                     </form>\n                  </div>\n               </div>\n            </label>\n        </div>   \n   </div>', css: '\n/* From Uiverse.io by andrew-demchenk0 - Tags: 3d, form, sign-up, toggle, animated, login form, toggle switch, log in, sign up form, click animation */\n.wrapper {\n  --input-focus: #2d8cf0;\n  --font-color: #323232;\n  --font-color-sub: #666;\n  --bg-color: #fff;\n  --bg-color-alt: #666;\n  --main-color: #323232;\n    /* display: flex; */\n    /* flex-direction: column; */\n    /* align-items: center; */\n}\n/* switch card */\n.switch {\n  transform: translateY(-200px);\n  position: relative;\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  align-items: center;\n  gap: 30px;\n  width: 50px;\n  height: 20px;\n}\n\n.card-side::before {\n  position: absolute;\n  content: \'Log in\';\n  left: -70px;\n  top: 0;\n  width: 100px;\n  text-decoration: underline;\n  color: var(--font-color);\n  font-weight: 600;\n}\n\n.card-side::after {\n  position: absolute;\n  content: \'Sign up\';\n  left: 70px;\n  top: 0;\n  width: 100px;\n  text-decoration: none;\n  color: var(--font-color);\n  font-weight: 600;\n}\n\n.toggle {\n  opacity: 0;\n  width: 0;\n  height: 0;\n}\n\n.slider {\n  box-sizing: border-box;\n  border-radius: 5px;\n  border: 2px solid var(--main-color);\n  box-shadow: 4px 4px var(--main-color);\n  position: absolute;\n  cursor: pointer;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  background-color: var(--bg-colorcolor);\n  transition: 0.3s;\n}\n\n.slider:before {\n  box-sizing: border-box;\n  position: absolute;\n  content: "";\n  height: 20px;\n  width: 20px;\n  border: 2px solid var(--main-color);\n  border-radius: 5px;\n  left: -2px;\n  bottom: 2px;\n  background-color: var(--bg-color);\n  box-shadow: 0 3px 0 var(--main-color);\n  transition: 0.3s;\n}\n\n.toggle:checked + .slider {\n  background-color: var(--input-focus);\n}\n\n.toggle:checked + .slider:before {\n  transform: translateX(30px);\n}\n\n.toggle:checked ~ .card-side:before {\n  text-decoration: none;\n}\n\n.toggle:checked ~ .card-side:after {\n  text-decoration: underline;\n}\n\n/* card */ \n\n.flip-card__inner {\n  width: 300px;\n  height: 350px;\n  position: relative;\n ', colors: '#323232,#2d8cf0,#fff,#666', radii: '5px', shadows: '4px 4px var(--main-color),0 3px 0 var(--main-color),none', techniques: '3d-transform,glow-shadow,perspective,checkbox-input,pseudo-elements'),
const GalaxyComp(id: 'SelfMadeSystem_pretty-snake-70', cat: 'Forms', author: 'SelfMadeSystem', tags: 'simple,animation,login,purple,form,card,sign-up', html: '<div class="form-container">\n  <input checked="" type="checkbox" id="switch" />\n  <div class="sign-up-container">\n    <span class="form-title">Sign Up</span>\n    <label for="switch" class="switch-label">Already have an account?</label>\n    <form class="sign-up-form">\n      <label for="username-sign-up">Username</label>\n      <input\n        class="input"\n        placeholder="Jonathon"\n        id="username-sign-up"\n        name="Username"\n        type="text"\n      />\n      <label for="email-sign-up">Email</label>\n      <input\n        class="input"\n        placeholder="jonny_doe@example.com"\n        id="email-sign-up"\n        name="Email"\n        type="email"\n      />\n      <label for="pwd-sign-up">Password</label>\n      <input\n        class="input"\n        placeholder="••••••••"\n        id="pwd-sign-up"\n        name="Password"\n        type="password"\n      />\n      <label for="confirm-pwd-sign-up">Confirm Password</label>\n      <input\n        class="input"\n        placeholder="••••••••"\n        id="confirm-pwd-sign-up"\n        name="Password"\n        type="password"\n      />\n      <button>Sign Up</button>\n    </form>\n  </div>\n  <div class="log-in-container">\n    <span class="form-title">Login</span>\n    <label for="switch" class="switch-label">Don\'t have an account?</label>\n    <form class="log-in-form">\n      <label for="email-log-in">Email</label>\n      <input\n        class="input"\n        placeholder="jonny_doe@example.com"\n        id="email-log-in"\n        name="Email"\n    ', css: '\n/* From Uiverse.io by SelfMadeSystem  - Tags: simple, animation, login, purple, form, card, sign-up */\n.form-container {\n  position: relative;\n  perspective: 50rem;\n  width: 50rem;\n  height: 50rem;\n}\n\n#switch {\n  display: none;\n}\n\n.sign-up-form,\n.log-in-form {\n  display: flex;\n  flex-direction: column;\n  height: 100%;\n}\n\n.sign-up-container,\n.log-in-container {\n  position: absolute;\n  display: flex;\n  flex-direction: column;\n  inset: 0;\n  margin: auto;\n  width: 20rem;\n  height: 20rem;\n  background: #2c164f;\n  color: #fff;\n  padding: 1rem;\n  border-radius: 0.5rem;\n}\n\n.switch-label {\n  font-size: x-small;\n  text-decoration: underline;\n  cursor: pointer;\n}\n\n.form-title {\n  font-size: x-large;\n  font-weight: bold;\n}\n\n:where(.sign-up-form, .log-in-form) label {\n  font-size: x-small;\n  padding-top: 0.5rem;\n  padding-left: 0.25rem;\n}\n\n:where(.sign-up-form, .log-in-form) input {\n  background-color: #fff2;\n  box-sizing: border-box;\n  color: white;\n  border: 0;\n  border-bottom: 2px solid #cfb2ff;\n  padding: 0.25rem;\n  border-top-left-radius: 0.25rem;\n  border-top-right-radius: 0.25rem;\n}\n\n:where(.sign-up-form, .log-in-form) input:focus-visible {\n  outline: none;\n  border: 1px solid white;\n  border-bottom: 2px solid #cfb2ff;\n}\n\n:where(.sign-up-form, .log-in-form) button {\n  margin-top: auto;\n  background-color: #ffffff4b;\n  color: white;\n  border: 0;\n  padding: 0.25rem;\n  border-radius: 0.25rem;\n  cursor: pointer;\n}\n\n.forgot-pwd {\n  font-size: x-small;\n  text-decoration: underline;\n  margin-left: auto;\n  cursor: pointer;\n}\n\n/* Social yoinked from uiverse.io/Yaya12085/short-panda-24 */\n\n.social-message {\n  display: flex;\n  align-items: center;\n  padding-top: 1rem;\n}\n\n.line {\n  height: 1px;\n  flex: 1 1 0%;\n  background-color: #cfb2ff;\n}\n\n.social-message .message {\n  padding-left: 0.75rem;\n  padding-right: 0.75rem;\n  font-size: 0.875rem;\n  line-height: 1.25rem;\n  color: #fff;\n}\n\n.social-icons {\n  display: flex;\n  justify-content: center;\n}\n\n.social-icons .icon {\n  border-radius: ', colors: '#ffffff4b,#cfb2ff,#2c164f,#fff2,#fff', radii: '0.25rem,0.5rem,0.125rem', shadows: '', techniques: '3d-transform,animation,perspective,checkbox-input,svg-icon'),
const GalaxyComp(id: 'zanina-yassine_light-dragonfly-12', cat: 'Forms', author: 'zanina-yassine', tags: 'login,sign-in,form', html: '<form class="form_container">\n  <div class="logo_container"></div>\n  <div class="title_container">\n    <p class="title">Login to your Account</p>\n    <span class="subtitle">Get started with our app, just create an account and enjoy the experience.</span>\n  </div>\n  <br>\n  <div class="input_container">\n    <label class="input_label" for="email_field">Email</label>\n    <svg fill="none" viewBox="0 0 24 24" height="24" width="24" xmlns="http://www.w3.org/2000/svg" class="icon">\n      <path stroke-linejoin="round" stroke-linecap="round" stroke-width="1.5" stroke="#141B34" d="M7 8.5L9.94202 10.2394C11.6572 11.2535 12.3428 11.2535 14.058 10.2394L17 8.5"></path>\n      <path stroke-linejoin="round" stroke-width="1.5" stroke="#141B34" d="M2.01577 13.4756C2.08114 16.5412 2.11383 18.0739 3.24496 19.2094C4.37608 20.3448 5.95033 20.3843 9.09883 20.4634C11.0393 20.5122 12.9607 20.5122 14.9012 20.4634C18.0497 20.3843 19.6239 20.3448 20.7551 19.2094C21.8862 18.0739 21.9189 16.5412 21.9842 13.4756C22.0053 12.4899 22.0053 11.5101 21.9842 10.5244C21.9189 7.45886 21.8862 5.92609 20.7551 4.79066C19.6239 3.65523 18.0497 3.61568 14.9012 3.53657C12.9607 3.48781 11.0393 3.48781 9.09882 3.53656C5.95033 3.61566 4.37608 3.65521 3.24495 4.79065C2.11382 5.92608 2.08114 7.45885 2.01576 10.5244C1.99474 11.5101 1.99475 12.4899 2.01577 13.4756Z"></path>\n    </svg>\n    <input placeholder="name@mail.com" title="Inpit title" name="input-name" type="text" class="input_field" id="email_field">\n  </div>\n  <div class', css: '\n/* From Uiverse.io by zanina-yassine - Tags: login, sign-in, form */\n.form_container {\n  width: fit-content;\n  height: fit-content;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  gap: 15px;\n  padding: 50px 40px 20px 40px;\n  background-color: #ffffff;\n  box-shadow: 0px 106px 42px rgba(0, 0, 0, 0.01),\n    0px 59px 36px rgba(0, 0, 0, 0.05), 0px 26px 26px rgba(0, 0, 0, 0.09),\n    0px 7px 15px rgba(0, 0, 0, 0.1), 0px 0px 0px rgba(0, 0, 0, 0.1);\n  border-radius: 11px;\n  font-family: "Inter", sans-serif;\n}\n\n.logo_container {\n  box-sizing: border-box;\n  width: 80px;\n  height: 80px;\n  background: linear-gradient(180deg, rgba(248, 248, 248, 0) 50%, #F8F8F888 100%);\n  border: 1px solid #F7F7F8;\n  filter: drop-shadow(0px 0.5px 0.5px #EFEFEF) drop-shadow(0px 1px 0.5px rgba(239, 239, 239, 0.5));\n  border-radius: 11px;\n}\n\n.title_container {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  gap: 10px;\n}\n\n.title {\n  margin: 0;\n  font-size: 1.25rem;\n  font-weight: 700;\n  color: #212121;\n}\n\n.subtitle {\n  font-size: 0.725rem;\n  max-width: 80%;\n  text-align: center;\n  line-height: 1.1rem;\n  color: #8B8E98\n}\n\n.input_container {\n  width: 100%;\n  height: fit-content;\n  position: relative;\n  display: flex;\n  flex-direction: column;\n  gap: 5px;\n}\n\n.icon {\n  width: 20px;\n  position: absolute;\n  z-index: 99;\n  left: 12px;\n  bottom: 9px;\n}\n\n.input_label {\n  font-size: 0.75rem;\n  color: #8B8E98;\n  font-weight: 600;\n}\n\n.input_field {\n  width: auto;\n  height: 40px;\n  padding: 0 0 0 40px;\n  border-radius: 7px;\n  outline: none;\n  border: 1px solid #e5e5e5;\n  filter: drop-shadow(0px 1px 0px #efefef)\n    drop-shadow(0px 1px 0.5px rgba(239, 239, 239, 0.5));\n  transition: all 0.3s cubic-bezier(0.15, 0.83, 0.66, 1);\n}\n\n.input_field:focus {\n  border: 1px solid transparent;\n  box-shadow: 0px 0px 0px 2px #242424;\n  background-color: transparent;\n}\n\n.sign-in_btn {\n  width: 100%;\n  height: 40px;\n  border: 0;\n  backgr', colors: '#efefef,#212121,#e5e5e5,#8b8e98,#242424,#f8f8f888,#115dfc,#ffffff,#e8e8e8,#f7f7f8', radii: '7px,11px', shadows: '0px 106px 42px rgba(0, 0, 0, 0.01),\n    0px 59px 36px rgba(0, 0, 0, 0.05), 0px 26px 26px rgba(0, 0, 0, 0.09),\n    0px 7p,0px 0px 0px 2px #242424', techniques: 'cubic-bezier,glow-shadow,gradient,filter-effect,svg-icon'),
const GalaxyComp(id: 'zanina-yassine_quiet-turkey-90', cat: 'Forms', author: 'zanina-yassine', tags: 'form', html: '<div class="card">\n  <span class="title">Comments</span>\n  <div class="comments">\n    <div class="comment-react">\n      <button>\n        <svg fill="none" viewBox="0 0 24 24" height="16" width="16" xmlns="http://www.w3.org/2000/svg">\n          <path fill="#707277" stroke-linecap="round" stroke-width="2" stroke="#707277" d="M19.4626 3.99415C16.7809 2.34923 14.4404 3.01211 13.0344 4.06801C12.4578 4.50096 12.1696 4.71743 12 4.71743C11.8304 4.71743 11.5422 4.50096 10.9656 4.06801C9.55962 3.01211 7.21909 2.34923 4.53744 3.99415C1.01807 6.15294 0.221721 13.2749 8.33953 19.2834C9.88572 20.4278 10.6588 21 12 21C13.3412 21 14.1143 20.4278 15.6605 19.2834C23.7783 13.2749 22.9819 6.15294 19.4626 3.99415Z"></path>\n        </svg>\n      </button>\n      <hr>\n      <span>14</span>\n    </div>\n    <div class="comment-container">\n      <div class="user">\n        <div class="user-pic">\n          <svg fill="none" viewBox="0 0 24 24" height="20" width="20" xmlns="http://www.w3.org/2000/svg">\n            <path stroke-linejoin="round" fill="#707277" stroke-linecap="round" stroke-width="2" stroke="#707277" d="M6.57757 15.4816C5.1628 16.324 1.45336 18.0441 3.71266 20.1966C4.81631 21.248 6.04549 22 7.59087 22H16.4091C17.9545 22 19.1837 21.248 20.2873 20.1966C22.5466 18.0441 18.8372 16.324 17.4224 15.4816C14.1048 13.5061 9.89519 13.5061 6.57757 15.4816Z"></path>\n            <path stroke-width="2" fill="#707277" stroke="#707277" d="M16.5 6.5C16.5 8.98528 14.4853 11 12 11C9.51472 11 7.5 8.98528 7.5 6.5C7.5', css: '\n/* From Uiverse.io by zanina-yassine - Tags: form */\n.card {\n  width: 450px;\n  height: fit-content;\n  background-color: white;\n  box-shadow: 0px 187px 75px rgba(0, 0, 0, 0.01), 0px 105px 63px rgba(0, 0, 0, 0.05), 0px 47px 47px rgba(0, 0, 0, 0.09), 0px 12px 26px rgba(0, 0, 0, 0.1), 0px 0px 0px rgba(0, 0, 0, 0.1);\n  border-radius: 17px 17px 27px 27px;\n}\n\n.title {\n  width: 100%;\n  height: 50px;\n  position: relative;\n  display: flex;\n  align-items: center;\n  padding-left: 20px;\n  border-bottom: 1px solid #f1f1f1;\n  font-weight: 700;\n  font-size: 13px;\n  color: #47484b;\n}\n\n.title::after {\n  content: \'\';\n  width: 8ch;\n  height: 1px;\n  position: absolute;\n  bottom: -1px;\n  background-color: #47484b;\n}\n\n.comments {\n  display: grid;\n  grid-template-columns: 35px 1fr;\n  gap: 20px;\n  padding: 20px;\n}\n\n.comment-react {\n  width: 35px;\n  height: fit-content;\n  display: grid;\n  grid-template-columns: auto;\n  margin: 0;\n  background-color: #f1f1f1;\n  border-radius: 5px;\n}\n\n.comment-react button {\n  width: 35px;\n  height: 35px;\n  position: relative;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  background-color: transparent;\n  border: 0;\n  outline: none;\n}\n\n.comment-react button:after {\n  content: \'\';\n  width: 40px;\n  height: 40px;\n  position: absolute;\n  left: -2.5px;\n  top: -2.5px;\n  background-color: #f5356e;\n  border-radius: 50%;\n  z-index: 0;\n  transform: scale(0);\n}\n\n.comment-react button svg {\n  position: relative;\n  z-index: 9;\n}\n\n.comment-react button:hover:after {\n  animation: ripple 0.6s ease-in-out forwards;\n}\n\n.comment-react button:hover svg {\n  fill: #f5356e;\n}\n\n.comment-react button:hover svg path {\n  stroke: #f5356e;\n  fill: #f5356e;\n}\n\n.comment-react hr {\n  width: 80%;\n  height: 1px;\n  background-color: #dfe1e6;\n  margin: auto;\n  border: 0;\n}\n\n.comment-react span {\n  height: 35px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  margin: auto;\n  font-size: 13px;\n  font-weight: 600;\n  color: #707277;\n}\n\n.comment-container {\n', colors: '#47484b,#0a84ff,#0fc45a,#f1f1f1,#5f6064,#707277,#acaeb4,#f5356e,#dfe1e6,#ffffff', radii: '50%,8px 8px 21px 21px,6px,17px 17px 27px 27px,5px', shadows: '0px 187px 75px rgba(0, 0, 0, 0.01), 0px 105px 63px rgba(0, 0, 0, 0.05), 0px 47px 47px rgba(0, 0, 0, 0.09), 0px 12px 26px', techniques: '3d-transform,glow-shadow,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'AIVIIID_hungry-robin-21', cat: 'Checkboxes', author: 'AIVIIID', tags: 'checkbox', html: '<label class="container">\n		<input type="checkbox" checked="checked">\n		<div class="checkmark"></div>\n	</label>', css: '\n/* From Uiverse.io by AIVIIID - Tags: checkbox */\n/* Hide the default checkbox */\n.container input {\n  position: absolute;\n  opacity: 0;\n  cursor: pointer;\n  height: 0;\n  width: 0;\n}\n\n.container {\n  display: block;\n  position: relative;\n  cursor: pointer;\n  font-size: 25px;\n  user-select: none;\n}\n\n/* Create a custom checkbox */\n.checkmark {\n  position: relative;\n  top: 0;\n  left: 0;\n  height: 1.3em;\n  width: 1.3em;\n  background: black;\n  border-radius: 50px;\n  transition: all 0.7s;\n  --spread: 20px;\n}\n\n/* When the checkbox is checked, add a blue background */\n.container input:checked ~ .checkmark {\n  background: black;\n  box-shadow: -10px -10px var(--spread) 0px #FFD700, 0 -10px var(--spread) 0px #FFD700, 10px -10px var(--spread) 0px #FFD700, 10px 0 var(--spread) 0px #FFD700, 10px 10px var(--spread) 0px #FFD700, 0 10px var(--spread) 0px #FFD700, -10px 10px var(--spread) 0px #FFD700;\n}\n\n/* Create the checkmark/indicator (hidden when not checked) */\n.checkmark:after {\n  content: "";\n  position: absolute;\n  display: none;\n}\n\n/* Show the checkmark when checked */\n.container input:checked ~ .checkmark:after {\n  display: block;\n  animation: checkmark 0.3s cubic-bezier(0.25, 0.1, 0.25, 1) forwards;\n}\n\n/* Style the checkmark/indicator */\n.container .checkmark:after {\n  left: 0.45em;\n  top: 0.25em;\n  width: 0.25em;\n  height: 0.5em;\n  border: solid #FFD700;\n  border-width: 0 0.15em 0.15em 0;\n  transform: rotate(45deg);\n}\n\n/* Add animation for checkmark */\n@keyframes checkmark {\n  from {\n    transform: rotate(-45deg) scale(0);\n  }\n\n  to {\n    transform: rotate(45deg) scale(1);\n  }\n}\n\n/* Style the label text */\n.container span {\n  margin-left: 2em;\n  color: black;\n  font-weight: bold;\n}\n\n', colors: '#ffd700', radii: '50px', shadows: '-10px -10px var(--spread) 0px #FFD700, 0 -10px var(--spread) 0px #FFD700, 10px -10px var(--spread) 0px #FFD700, 10px 0 v', techniques: 'cubic-bezier,3d-transform,glow-shadow,animation,checkbox-input'),
const GalaxyComp(id: 'Bodyhc_afraid-octopus-70', cat: 'Checkboxes', author: 'Bodyhc', tags: 'checkbox,cool checkbox,circle-checkbox', html: '<div class="checkbox-wrapper-16">\n  <label class="checkbox-wrapper">\n    <input class="checkbox-input" type="checkbox">\n    <span class="checkbox-tile">\n      <span class="checkbox-icon">\n        <svg viewBox="0 0 256 256" fill="currentColor" height="192" width="192" xmlns="http://www.w3.org/2000/svg">\n          <rect fill="none" height="256" width="256"></rect>\n          <polygon stroke-width="12" stroke-linejoin="round" stroke-linecap="round" stroke="currentColor" fill="none" points="72 40 184 40 240 104 128 224 16 104 72 40"></polygon>\n          <polygon stroke-width="12" stroke-linejoin="round" stroke-linecap="round" stroke="currentColor" fill="none" points="177.091 104 128 224 78.909 104 128 40 177.091 104"></polygon>\n          <line stroke-width="12" stroke-linejoin="round" stroke-linecap="round" stroke="currentColor" fill="none" y2="104" x2="240" y1="104" x1="16"></line>\n        </svg>\n      </span>\n      <span class="checkbox-label">Sketch</span>\n    </span>\n  </label>\n</div>', css: '\n/* From Uiverse.io by Bodyhc - Tags: checkbox, cool checkbox, circle-checkbox */\n.checkbox-wrapper-16 *,\n  .checkbox-wrapper-16 *:after,\n  .checkbox-wrapper-16 *:before {\n  box-sizing: border-box;\n}\n\n.checkbox-wrapper-16 .checkbox-input {\n  clip: rect(0 0 0 0);\n  -webkit-clip-path: inset(100%);\n  clip-path: inset(100%);\n  height: 1px;\n  overflow: hidden;\n  position: absolute;\n  white-space: nowrap;\n  width: 1px;\n}\n\n.checkbox-wrapper-16 .checkbox-input:checked + .checkbox-tile {\n  border-color: #2260ff;\n  box-shadow: 0 5px 10px rgba(0, 0, 0, 0.1);\n  color: #2260ff;\n}\n\n.checkbox-wrapper-16 .checkbox-input:checked + .checkbox-tile:before {\n  transform: scale(1);\n  opacity: 1;\n  background-color: #2260ff;\n  border-color: #2260ff;\n}\n\n.checkbox-wrapper-16 .checkbox-input:checked + .checkbox-tile .checkbox-icon,\n  .checkbox-wrapper-16 .checkbox-input:checked + .checkbox-tile .checkbox-label {\n  color: #2260ff;\n}\n\n.checkbox-wrapper-16 .checkbox-input:focus + .checkbox-tile {\n  border-color: #2260ff;\n  box-shadow: 0 5px 10px rgba(0, 0, 0, 0.1), 0 0 0 4px #b5c9fc;\n}\n\n.checkbox-wrapper-16 .checkbox-input:focus + .checkbox-tile:before {\n  transform: scale(1);\n  opacity: 1;\n}\n\n.checkbox-wrapper-16 .checkbox-tile {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  width: 7rem;\n  min-height: 7rem;\n  border-radius: 0.5rem;\n  border: 2px solid #b5bfd9;\n  background-color: #fff;\n  box-shadow: 0 5px 10px rgba(0, 0, 0, 0.1);\n  transition: 0.15s ease;\n  cursor: pointer;\n  position: relative;\n}\n\n.checkbox-wrapper-16 .checkbox-tile:before {\n  content: "";\n  position: absolute;\n  display: block;\n  width: 1.25rem;\n  height: 1.25rem;\n  border: 2px solid #b5bfd9;\n  background-color: #fff;\n  border-radius: 50%;\n  top: 0.25rem;\n  left: 0.25rem;\n  opacity: 0;\n  transform: scale(0);\n  transition: 0.25s ease;\n  background-image: url("data:image/svg+xml,%3Csvg xmlns=\'://www.w3.org/2000/svg\' width=\'192\' height=\'192\' fill=\'%23FFFFFF\' viewBox=\'0 0 256 256\'', colors: '#494949,#b5bfd9,#2260ff,#b5c9fc,#fff,#707070', radii: '50%,0.5rem', shadows: '0 5px 10px rgba(0, 0, 0, 0.1),0 5px 10px rgba(0, 0, 0, 0.1), 0 0 0 4px #b5c9fc,0 5px 10px rgba(0, 0, 0, 0.1)', techniques: '3d-transform,glow-shadow,clip-path,checkbox-input,svg-icon'),
const GalaxyComp(id: 'catraco_plastic-moth-91', cat: 'Checkboxes', author: 'catraco', tags: 'checkbox,like,heart,hover effect', html: '<div class="heart-container" title="Like">\n            <input type="checkbox" class="checkbox" id="Give-It-An-Id">\n            <div class="svg-container">\n                <svg viewBox="0 0 24 24" class="svg-outline" xmlns="http://www.w3.org/2000/svg">\n                    <path d="M17.5,1.917a6.4,6.4,0,0,0-5.5,3.3,6.4,6.4,0,0,0-5.5-3.3A6.8,6.8,0,0,0,0,8.967c0,4.547,4.786,9.513,8.8,12.88a4.974,4.974,0,0,0,6.4,0C19.214,18.48,24,13.514,24,8.967A6.8,6.8,0,0,0,17.5,1.917Zm-3.585,18.4a2.973,2.973,0,0,1-3.83,0C4.947,16.006,2,11.87,2,8.967a4.8,4.8,0,0,1,4.5-5.05A4.8,4.8,0,0,1,11,8.967a1,1,0,0,0,2,0,4.8,4.8,0,0,1,4.5-5.05A4.8,4.8,0,0,1,22,8.967C22,11.87,19.053,16.006,13.915,20.313Z">\n                    </path>\n                </svg>\n                <svg viewBox="0 0 24 24" class="svg-filled" xmlns="http://www.w3.org/2000/svg">\n                    <path d="M17.5,1.917a6.4,6.4,0,0,0-5.5,3.3,6.4,6.4,0,0,0-5.5-3.3A6.8,6.8,0,0,0,0,8.967c0,4.547,4.786,9.513,8.8,12.88a4.974,4.974,0,0,0,6.4,0C19.214,18.48,24,13.514,24,8.967A6.8,6.8,0,0,0,17.5,1.917Z">\n                    </path>\n                </svg>\n                <svg class="svg-celebrate" width="100" height="100" xmlns="http://www.w3.org/2000/svg">\n                    <polygon points="10,10 20,20"></polygon>\n                    <polygon points="10,50 20,50"></polygon>\n                    <polygon points="20,80 30,70"></polygon>\n                    <polygon points="90,10 80,20"></polygon>\n                    <polygon points="90,50 80,50">', css: '\n/* From Uiverse.io by catraco - Tags: checkbox, like, heart, hover effect */\n.heart-container {\n  --heart-color: rgb(255, 91, 137);\n  position: relative;\n  width: 50px;\n  height: 50px;\n  transition: .3s;\n}\n\n.heart-container .checkbox {\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  opacity: 0;\n  z-index: 20;\n  cursor: pointer;\n}\n\n.heart-container .svg-container {\n  width: 100%;\n  height: 100%;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n.heart-container .svg-outline,\n        .heart-container .svg-filled {\n  fill: var(--heart-color);\n  position: absolute;\n}\n\n.heart-container .svg-filled {\n  animation: keyframes-svg-filled 1s;\n  display: none;\n}\n\n.heart-container .svg-celebrate {\n  position: absolute;\n  animation: keyframes-svg-celebrate .5s;\n  animation-fill-mode: forwards;\n  display: none;\n  stroke: var(--heart-color);\n  fill: var(--heart-color);\n  stroke-width: 2px;\n}\n\n.heart-container .checkbox:checked~.svg-container .svg-filled {\n  display: block\n}\n\n.heart-container .checkbox:checked~.svg-container .svg-celebrate {\n  display: block\n}\n\n@keyframes keyframes-svg-filled {\n  0% {\n    transform: scale(0);\n  }\n\n  25% {\n    transform: scale(1.2);\n  }\n\n  50% {\n    transform: scale(1);\n    filter: brightness(1.5);\n  }\n}\n\n@keyframes keyframes-svg-celebrate {\n  0% {\n    transform: scale(0);\n  }\n\n  50% {\n    opacity: 1;\n    filter: brightness(1.5);\n  }\n\n  100% {\n    transform: scale(1.4);\n    opacity: 0;\n    display: none;\n  }\n}\n', colors: '', radii: '', shadows: '', techniques: '3d-transform,animation,filter-effect,checkbox-input,svg-icon'),
const GalaxyComp(id: 'elijahgummer_stale-bobcat-64', cat: 'Checkboxes', author: 'elijahgummer', tags: 'simple,animation,blue,checkbox,modern,transition,click effect,click animation', html: '<div class="checkbox">\n  <input type="checkbox" id="cbx" />\n  <label for="cbx" class="cbx">\n    <div class="flip">\n      <div class="front"></div>\n      <div class="back">\n        <svg viewBox="0 0 16 14" height="14" width="16">\n          <path d="M2 8.5L6 12.5L14 1.5"></path>\n        </svg>\n      </div>\n    </div>\n  </label>\n</div>', css: '\n/* From Uiverse.io by elijahgummer  - Tags: simple, animation, blue, checkbox, modern, transition, click effect, click animation */\n.checkbox {\n  position: relative;\n}\n\n.checkbox input[type="checkbox"] {\n  display: none;\n  visibility: hidden;\n}\n\n.checkbox .cbx {\n  -webkit-perspective: 20;\n  perspective: 20;\n  display: inline-block;\n  border: 2px solid #e8e8eb;\n  background: #e8e8eb;\n  border-radius: 4px;\n  transform: translate3d(0, 0, 0);\n  cursor: pointer;\n  transition: all 0.3s ease;\n}\n\n.checkbox .cbx:hover {\n  border-color: #0b76ef;\n}\n\n.checkbox .flip {\n  display: block;\n  transition: all 0.4s ease;\n  transform-style: preserve-3d;\n  position: relative;\n  width: 20px;\n  height: 20px;\n}\n\n.checkbox input[type="checkbox"]:checked + .cbx {\n  border-color: #0b76ef;\n}\n\n.checkbox input[type="checkbox"]:checked + .cbx .flip {\n  transform: rotateY(180deg);\n}\n\n.checkbox .front,\n.checkbox .back {\n  backface-visibility: hidden;\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 20px;\n  height: 20px;\n  border-radius: 2px;\n}\n\n.checkbox .front {\n  background: #fff;\n  z-index: 1;\n}\n\n.checkbox .back {\n  transform: rotateY(180deg);\n  background: #0b76ef;\n  text-align: center;\n  color: #fff;\n  line-height: 20px;\n  box-shadow: 0 0 0 1px #0b76ef;\n}\n\n.checkbox .back svg {\n  margin-top: 3px;\n  fill: none;\n}\n\n.checkbox .back svg path {\n  stroke: #fff;\n  stroke-width: 2.5;\n  stroke-linecap: round;\n  stroke-linejoin: round;\n}\n\n', colors: '#e8e8eb,#0b76ef,#fff', radii: '4px,2px', shadows: '0 0 0 1px #0b76ef', techniques: '3d-transform,glow-shadow,perspective,checkbox-input,svg-icon'),
const GalaxyComp(id: 'gagan-gv_wonderful-monkey-77', cat: 'Checkboxes', author: 'gagan-gv', tags: 'checkbox', html: '<label class="container">\n  <input checked="checked" type="checkbox">\n  <div class="checkmark"></div>\n</label>', css: '\n/* From Uiverse.io by gagan-gv - Tags: checkbox */\n/* Hide the default checkbox */\n.container input {\n position: absolute;\n opacity: 0;\n cursor: pointer;\n height: 0;\n width: 0;\n}\n\n.container {\n display: block;\n position: relative;\n cursor: pointer;\n font-size: 20px;\n user-select: none;\n}\n\n/* Create a custom checkbox */\n.checkmark {\n position: relative;\n top: 0;\n left: 0;\n height: 1.3em;\n width: 1.3em;\n background-color: #343434;\n border-radius: 5px;\n transition: all 0.5s;\n}\n\n/* When the checkbox is checked, add a blue background */\n.container input:checked ~ .checkmark {\n background-color: #f0f0f0;\n border: 2px solid #343434;\n}\n\n/* Create the checkmark/indicator (hidden when not checked) */\n.checkmark:after {\n content: "";\n position: absolute;\n display: none;\n filter: drop-shadow(0 0 10px #888);\n}\n\n/* Show the checkmark when checked */\n.container input:checked ~ .checkmark:after {\n display: block;\n}\n\n/* Style the checkmark/indicator */\n.container .checkmark:after {\n left: 0.3em;\n top: 0.05em;\n width: 0.3em;\n height: 0.65em;\n border: solid #343434;\n border-width: 0 0.2em 0.2em 0;\n border-radius: 4px;\n transform: rotate(45deg);\n animation: bounceFadeIn 0.5s cubic-bezier(0.165, 0.84, 0.44, 1);\n}\n\n@keyframes bounceFadeIn {\n from {\n  transform: translate(0, -10px) rotate(45deg);\n  opacity: 0;\n }\n\n to {\n  transform: translate(0, 0) rotate(45deg);\n  opacity: 1;\n }\n}\n', colors: '#f0f0f0,#343434,#888', radii: '4px,5px', shadows: '', techniques: 'cubic-bezier,3d-transform,animation,filter-effect,checkbox-input'),
const GalaxyComp(id: 'Galahhad_sweet-ape-100', cat: 'Checkboxes', author: '', tags: '', html: '<input type="checkbox" class="ui-checkbox">', css: '\n/* From Uiverse.io by Galahhad - Source: https://ant.design/components/checkbox - Tags: checkbox, click animation, antd */\n/* checkbox settings 👇 */\n\n.ui-checkbox {\n  --primary-color: #1677ff;\n  --secondary-color: #fff;\n  --primary-hover-color: #4096ff;\n  /* checkbox */\n  --checkbox-diameter: 20px;\n  --checkbox-border-radius: 5px;\n  --checkbox-border-color: #d9d9d9;\n  --checkbox-border-width: 1px;\n  --checkbox-border-style: solid;\n  /* checkmark */\n  --checkmark-size: 1.2;\n}\n\n.ui-checkbox, \n.ui-checkbox *, \n.ui-checkbox *::before, \n.ui-checkbox *::after {\n  -webkit-box-sizing: border-box;\n  box-sizing: border-box;\n}\n\n.ui-checkbox {\n  -webkit-appearance: none;\n  -moz-appearance: none;\n  appearance: none;\n  width: var(--checkbox-diameter);\n  height: var(--checkbox-diameter);\n  border-radius: var(--checkbox-border-radius);\n  background: var(--secondary-color);\n  border: var(--checkbox-border-width) var(--checkbox-border-style) var(--checkbox-border-color);\n  -webkit-transition: all 0.3s;\n  -o-transition: all 0.3s;\n  transition: all 0.3s;\n  cursor: pointer;\n  position: relative;\n}\n\n.ui-checkbox::after {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  -webkit-box-shadow: 0 0 0 calc(var(--checkbox-diameter) / 2.5) var(--primary-color);\n  box-shadow: 0 0 0 calc(var(--checkbox-diameter) / 2.5) var(--primary-color);\n  border-radius: inherit;\n  opacity: 0;\n  -webkit-transition: all 0.5s cubic-bezier(0.12, 0.4, 0.29, 1.46);\n  -o-transition: all 0.5s cubic-bezier(0.12, 0.4, 0.29, 1.46);\n  transition: all 0.5s cubic-bezier(0.12, 0.4, 0.29, 1.46);\n}\n\n.ui-checkbox::before {\n  top: 40%;\n  left: 50%;\n  content: "";\n  position: absolute;\n  width: 4px;\n  height: 7px;\n  border-right: 2px solid var(--secondary-color);\n  border-bottom: 2px solid var(--secondary-color);\n  -webkit-transform: translate(-50%, -50%) rotate(45deg) scale(0);\n  -ms-transform: translate(-50%, -50%) rotate(45deg) scale(0);\n  transform: translate(-50%, -50%) rotate(45deg) scale', colors: '#4096ff,#1677ff,#fff,#d9d9d9', radii: 'var(--checkbox-border-radius),inherit,5px', shadows: '0 0 0 calc(var(--checkbox-diameter) / 2.5) var(--primary-color),0 0 0 calc(var(--checkbox-diameter) / 2.5) var(--primary-color),none', techniques: 'cubic-bezier,3d-transform,glow-shadow,checkbox-input,pseudo-elements'),
const GalaxyComp(id: 'gharsh11032000_nasty-panda-23', cat: 'Checkboxes', author: 'gharsh11032000', tags: 'gradient,checkbox,toggle,click effect', html: '<label class="container">\n  <input checked="checked" type="checkbox">\n  <div class="checkmark"></div>\n</label>', css: '\n/* From Uiverse.io by gharsh11032000 - Tags: gradient, checkbox, toggle, click effect */\n/* Hide the default checkbox */\n.container input {\n  position: absolute;\n  opacity: 0;\n  cursor: pointer;\n  height: 0;\n  width: 0;\n}\n\n.container {\n  display: block;\n  position: relative;\n  cursor: pointer;\n  font-size: 20px;\n  user-select: none;\n  overflow: hidden;\n}\n\n/* Create a custom checkbox */\n.checkmark {\n  position: relative;\n  top: 0;\n  left: 0;\n  height: 1.3em;\n  width: 1.3em;\n  border: 2px solid #414141;\n  transition: all 0.4s cubic-bezier(0.23, 1, 0.320, 1);\n}\n\n/* When the checkbox is checked */\n.container input:checked ~ .checkmark {\n  border-image: linear-gradient(-45deg, #f89b29 0%, #ff0f7b 100% );\n  border-image-slice: 1;\n}\n\n/* Create the checkmark/indicator (hidden when not checked) */\n.checkmark:after {\n  content: "";\n  position: absolute;\n}\n\n/* Style the checkmark/indicator */\n.container .checkmark:after {\n  left: 0.45em;\n  top: -2em;\n  width: 0.25em;\n  height: 0.5em;\n  border: solid white;\n  border-width: 0 0.15em 0.15em 0;\n  transform: rotate(45deg);\n  transition: all 0.6s cubic-bezier(0.23, 1, 0.320, 1);\n}\n\n.container .checkmark::before {\n  left: 0.45em;\n  top: 2em;\n  width: 0.25em;\n  height: 0.5em;\n  border: solid white;\n  border-width: 0 0.15em 0.15em 0;\n  transform: rotate(45deg);\n}\n\n/* Show the checkmark when checked */\n.container input:checked ~ .checkmark:after {\n  top: 0.25em;\n}\n\n', colors: '#414141,#ff0f7b,#f89b29', radii: '', shadows: '', techniques: 'cubic-bezier,3d-transform,gradient,checkbox-input,pseudo-elements'),
const GalaxyComp(id: 'JkHuger_warm-panther-74', cat: 'Checkboxes', author: 'JkHuger', tags: 'checkbox,todo', html: '<div id="checklist">\n  <input checked="" value="1" name="r" type="checkbox" id="01">\n  <label for="01">Bread</label>\n  <input value="2" name="r" type="checkbox" id="02">\n  <label for="02">Cheese</label>\n  <input value="3" name="r" type="checkbox" id="03">\n  <label for="03">Coffee</label>\n</div>', css: '\n/* From Uiverse.io by JkHuger - Tags: checkbox, todo */\n#checklist {\n  --background: #fff;\n  --text: #414856;\n  --check: #4f29f0;\n  --disabled: #c3c8de;\n  --width: 100px;\n  --height: 180px;\n  --border-radius: 10px;\n  background: var(--background);\n  width: var(--width);\n  height: var(--height);\n  border-radius: var(--border-radius);\n  position: relative;\n  box-shadow: 0 10px 30px rgba(65, 72, 86, 0.05);\n  padding: 30px 85px;\n  display: grid;\n  grid-template-columns: 30px auto;\n  align-items: center;\n  justify-content: center;\n}\n\n#checklist label {\n  color: var(--text);\n  position: relative;\n  cursor: pointer;\n  display: grid;\n  align-items: center;\n  width: fit-content;\n  transition: color 0.3s ease;\n  margin-right: 20px;\n}\n\n#checklist label::before, #checklist label::after {\n  content: "";\n  position: absolute;\n}\n\n#checklist label::before {\n  height: 2px;\n  width: 8px;\n  left: -27px;\n  background: var(--check);\n  border-radius: 2px;\n  transition: background 0.3s ease;\n}\n\n#checklist label:after {\n  height: 4px;\n  width: 4px;\n  top: 8px;\n  left: -25px;\n  border-radius: 50%;\n}\n\n#checklist input[type="checkbox"] {\n  -webkit-appearance: none;\n  -moz-appearance: none;\n  position: relative;\n  height: 15px;\n  width: 15px;\n  outline: none;\n  border: 0;\n  margin: 0 15px 0 0;\n  cursor: pointer;\n  background: var(--background);\n  display: grid;\n  align-items: center;\n  margin-right: 20px;\n}\n\n#checklist input[type="checkbox"]::before, #checklist input[type="checkbox"]::after {\n  content: "";\n  position: absolute;\n  height: 2px;\n  top: auto;\n  background: var(--check);\n  border-radius: 2px;\n}\n\n#checklist input[type="checkbox"]::before {\n  width: 0px;\n  right: 60%;\n  transform-origin: right bottom;\n}\n\n#checklist input[type="checkbox"]::after {\n  width: 0px;\n  left: 40%;\n  transform-origin: left bottom;\n}\n\n#checklist input[type="checkbox"]:checked::before {\n  animation: check-01 0.4s ease forwards;\n}\n\n#checklist input[type="checkbox"]:checked::after {\n  animation: check-02 0.4s e', colors: '#c3c8de,#4f29f0,#fff,#414856', radii: '10px,var(--border-radius),50%,2px', shadows: '0 10px 30px rgba(65, 72, 86, 0.05),0 0 0 -2px #4f29f0, 0 0 0 -2px #4f29f0, 0 0 0 -2px #4f29f0, 0 0 0 -2px #4f29f0, 0 0 0 -2px #4f29f0, 0 0 0 -2px #4f29f0,0 -15px 0 0px #4f29f0, 14px -8px 0 0px #4f29f0, 14px 8px 0 0px #4f29f0, 0 15px 0 0px #4f29f0, -14px 8px 0 0px #4f29f0, -', techniques: '3d-transform,glow-shadow,animation,checkbox-input,pseudo-elements'),
