const GalaxyComp(id: 'John-CFO_quiet-puma-22', cat: 'Notifications', author: 'John-CFO', tags: 'notification', html: '<div class="card">\n      <svg height="180px" width="200px" version="1.1" id="Layer_1" viewBox="0 0 512 512" xml:space="preserve" class="metal">\n        <path style="fill: #ffc61b" d="M256,512c-76.231,0-138.249-62.018-138.249-138.249c0-76.232,62.018-138.25,138.249-138.25\n	c23.8,0,47.273,6.151,67.886,17.79c7.033,3.971,9.515,12.892,5.544,19.927c-3.971,7.033-12.896,9.515-19.927,5.544\n	c-16.232-9.166-34.733-14.009-53.503-14.009c-60.102,0-108.999,48.898-108.999,109S195.899,482.751,256,482.751\n	s108.999-48.896,108.999-108.999c0-8.077,6.549-14.625,14.625-14.625c8.076,0,14.625,6.548,14.625,14.625\n	C394.249,449.982,332.231,512,256,512z"></path>\n        <path style="fill: #fee187" d="M256,424.249c-27.845,0-50.498-22.653-50.498-50.498s22.653-50.499,50.498-50.499\n	s50.498,22.654,50.498,50.499C306.498,401.596,283.845,424.249,256,424.249z"></path>\n        <g>\n          <path style="fill: #ffc61b" d="M256,438.874c-35.909,0-65.123-29.214-65.123-65.123s29.215-65.125,65.123-65.125\n		s65.123,29.215,65.123,65.124S291.908,438.874,256,438.874z M256,337.877c-19.781,0-35.873,16.092-35.873,35.874\n		c0,19.781,16.092,35.873,35.873,35.873s35.873-16.092,35.873-35.873C291.873,353.969,275.781,337.877,256,337.877z"></path>\n          <path style="fill: #ffc61b" d="M316.661,280.679c-2.437,0-4.905-0.61-7.178-1.893c-16.262-9.182-34.757-14.036-53.483-14.036\n		s-37.221,4.853-53.483,14.036c-6.986,3.943-15.846,1.525-19.857-5.423l-58.24-100.876c-4.039-6.995-1.642-15.94,5.353-19.978\n		c6.995-4.038,15.94-1.642,19.978,5', css: '\n/* From Uiverse.io by John-CFO - Tags: notification */\n.card {\n  color: #090909;\n  height: 12rem;\n  width: 20rem;\n  border-radius: 1rem;\n  background: rgb(63, 94, 251);\n  background: radial-gradient(\n    circle,\n    rgba(63, 94, 251, 1) 0%,\n    rgba(252, 70, 223, 1) 100%\n  );\n  border: 1px solid #e8e8e8;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: flex-end;\n}\n\n.text-1 {\n  margin: 0;\n  font-family: fantasy;\n  font-size: 35px;\n  padding-bottom: 5px;\n  color: transparent;\n  -webkit-text-stroke: 1px #fff;\n}\n\n.text-2 {\n  margin: 0;\n  padding-bottom: 2rem;\n  font-family: fantasy;\n  font-size: 25px;\n  color: #fff;\n}\n\n.text-1,\n.text-2 {\n  animation: scaling 5s infinite;\n}\n\n@keyframes scaling {\n  0% {\n    transform: scale(1);\n    opacity: 1.8;\n  }\n\n  50% {\n    transform: scale(1.1);\n    opacity: 0.8;\n  }\n}\n\n.metal {\n  margin-top: 10px;\n  width: 60px;\n  animation: spin 5.4s cubic-bezier(0, 0.2, 0.8, 1) infinite;\n}\n\n@keyframes spin {\n  0% {\n    transform: rotateY(0deg);\n  }\n\n  100% {\n    transform: rotateY(1800deg);\n    animation-timing-function: cubic-bezier(0, 0.5, 0.5, 1);\n  }\n}\n', colors: '#090909,#fff,#e8e8e8', radii: '1rem', shadows: '', techniques: 'cubic-bezier,3d-transform,gradient,animation,svg-icon'),
const GalaxyComp(id: 'MijailVillegas_swift-fireant-79', cat: 'Notifications', author: 'MijailVillegas', tags: 'notification', html: '<div class="level-up-content">\n    <div class="level-up-content">\n        <div class="level-up">\n            <span class="leyend">Level Up!</span>\n        </div>\n        <div class="progress-bar">\n            <div class="progress"></div>\n        </div>\n        <span class="world">world 1-1</span>\n\n        \n        <div class="suggestion">\n            <span>Reload or click ↓</span>\n        </div>\n        \n    </div>\n</div>', css: '\n/* From Uiverse.io by MijailVillegas - Tags: notification */\n/*Mijail Villegas - Bear\nMe gusta  la estética retro de los level ups*/\n\n.level-up-content {\n  display: grid;\n  width: 200px;\n  height: 70px;\n  padding: 10px;\n  align-items: center;\n  justify-items: center;\n  align-content: center;\n  font-weight: bold;\n  font-family: "Lucida Console", "Courier New", monospace;\n  margin: auto;\n}\n\n.progress-bar {\n  background-color: #ddd;\n  height: 20px;\n  margin: 10px 0;\n  overflow: hidden;\n  width: 100%;\n  display: flex;\n  text-align: center;\n  font-size: 1em;\n}\n\n.progress {\n  animation: progress-animation 2s ease-out forwards;\n  background-color: #000000;\n  height: 100%;\n  width: 0%;\n  z-index: 1;\n}\n\n.progress::before {\n  content: "";\n  display: block;\n  color: #ddd;\n  padding-top: 3px;\n  height: 20px;\n  animation: progress-xp 2.1s ease-out forwards;\n}\n\n.progress::after {\n  content: "+220xp";\n  display: block;\n  color: rgb(0, 255, 0);\n  position: absolute;\n  padding-top: 3px;\n  z-index: 999;\n  opacity: 0;\n  animation: add-xp 2s cubic-bezier(0, 0.92, 0.05, 1.07) forwards;\n}\n\n.span-content::before {\n  display: block;\n  color: #ddd;\n  margin-left: auto;\n  height: 20px;\n}\n\n.level-up {\n  color: white;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  width: 100%;\n  height: 100%;\n}\n\n.level-up .leyend {\n  font-size: 1.2em;\n  animation: level-up-animation 1s cubic-bezier(0, 0.62, 0, 0.97) forwards 2s;\n  opacity: 0;\n  transform: translateY(100%);\n  filter: drop-shadow(4px 4px 0px black);\n}\n\n.level-up-content:hover {\n  cursor: pointer;\n}\n\n.level-up-content:hover .leyend {\n  opacity: 1;\n  transform: translateY(100%);\n  background: #a11a1a;\n  animation: grow-up 1s ease-in-out forwards infinite;\n}\n\n.leyend::before {\n  content: "lvl 5";\n  display: block;\n  color: #ddd;\n  padding-top: 3px;\n  font-size: 0.5em;\n  height: 10px;\n}\n\n.level-up-content .world {\n  font-weight: 900;\n  animation: blink 1s cubic-bezier(0.68, -0.55, 0.27, 1.55) infinite;\n}\n\n@keyframes add-xp {\n ', colors: '#9b9b9b,#000000,#a11a1a,#ddd', radii: '', shadows: '', techniques: 'cubic-bezier,3d-transform,animation,filter-effect,pseudo-elements'),
const GalaxyComp(id: 'Sameer2244_white-eagle-79', cat: 'Notifications', author: 'Sameer2244', tags: 'notification', html: '<div class="notification">\n  <div class="shinner">\n    <div class="mover"></div>\n    <div class="mover2"></div>\n  </div>\n  <svg version="1.1" xml:space="preserve" xmlns="http://www.w3.org/2000/svg" height="121.46" width="122.88" class="wing">\n <g>\n  <g id="svg_1">\n   <path class="st0" d="m12.35,121.46c-8.01,-9.72 -11.92,-19.29 -12.31,-28.71c-0.82,-19.74 10.88,-34.47 28.26,-45.08c18.28,-11.16 37.08,-13.93 55.36,-22.25c9.13,-4.15 20.02,-10.95 38.14,-25.42c5.92,15.69 -12.92,40.9 -43.52,54.23c9.48,0.37 19.69,-2.54 30.85,-9.74c-0.76,19.94 -16.46,32.21 -51.3,36.95c7.33,2.45 16.09,2.58 27.27,-0.58c-10.77,35.95 -55.2,10.2 -72.75,40.6l0,0z" fill-rule="evenodd" clip-rule="evenodd" id="svg_2" fill="#fff"></path>\n  </g>\n </g>\n</svg>\n\n<svg version="1.1" xml:space="preserve" xmlns="http://www.w3.org/2000/svg" height="121.46" width="122.88" class="wing1">\n <g>\n  <g id="svg_1">\n   <path class="st0" d="m12.35,121.46c-8.01,-9.72 -11.92,-19.29 -12.31,-28.71c-0.82,-19.74 10.88,-34.47 28.26,-45.08c18.28,-11.16 37.08,-13.93 55.36,-22.25c9.13,-4.15 20.02,-10.95 38.14,-25.42c5.92,15.69 -12.92,40.9 -43.52,54.23c9.48,0.37 19.69,-2.54 30.85,-9.74c-0.76,19.94 -16.46,32.21 -51.3,36.95c7.33,2.45 16.09,2.58 27.27,-0.58c-10.77,35.95 -55.2,10.2 -72.75,40.6l0,0z" fill-rule="evenodd" clip-rule="evenodd" id="svg_2" fill="#fff"></path>\n  </g>\n </g>\n</svg>\n  <div></div>\n  <p class="levelup">LEVEL UP!</p>\n  <p class="congrats">Congratulations!</p>\n  <div class="bg"></div>\n    \n</div>', css: '\n/* From Uiverse.io by Sameer2244 - Tags: notification */\n.notification {\n  width: 250px;\n  height: 60px;\n  background: rgb(255, 255, 255);\n  border-radius: 14px;\n  position: relative;\n  border: 1px solid rgba(0, 0, 0, 0.377);\n}\n\n.shinner {\n  position: absolute;\n  width: 250px;\n  height: 60px;\n  overflow: hidden;\n  top: 0;\n  left: 0;\n  border-radius: 0.5rem;\n}\n\n.mover {\n  position: absolute;\n  border-top: 60px solid rgba(255, 255, 255, 0.4);\n  border-right: 30px solid transparent;\n  left: 50px;\n  filter: blur( 4px );\n  animation: shine 2s infinite ease-in-out;\n}\n\n.mover2 {\n  content: "";\n  position: absolute;\n  border-top: 60px solid rgba(255, 255, 255, 0.4);\n  border-left: 30px solid transparent;\n  transform: scaleY(-1);\n  left: 20px;\n  filter: blur( 4px );\n  animation: shine2 2s infinite ease-in-out;\n}\n\n.levelup {\n  color: rgb(18, 175, 4);\n  text-align: center;\n  padding-top: 0.6rem;\n  font-weight: bolder;\n  font-size: 1.8rem;\n  z-index: 3;\n}\n\n.congrats {\n  font-family: cursive;\n  font-size: 1.5rem;\n  color: rgb(240, 240, 240);\n  text-align: center;\n  padding-top: 1rem;\n  text-shadow: 1px 4px 7px rgb(7, 7, 7);\n}\n\n.wing {\n  transform: translate(150px,-100px);\n  position: absolute;\n  z-index: -1;\n  animation: winganime 2s ease-in-out infinite;\n}\n\n.wing1 {\n  transform: translate(-30px,-100px) scaleX(-1);\n  position: absolute;\n  z-index: -1;\n  animation: winganime2 2s ease-in-out infinite;\n}\n\n.bg {\n  background: rgb(223, 223, 105);\n  width: 130px;\n  height: 130px;\n  position: absolute;\n  top: 50%;\n  right: 50%;\n  transform: translate(50%,-50%);\n  z-index: -2;\n  border-radius: 50%;\n  box-shadow: rgb(252, 255, 54,0.7) 0px 4px 105px, rgb(252, 255, 54,0.7) 0px -24px 130px, rgb(252, 255, 54,0.7) 0px 4px 446px, rgb(252, 255, 54,0.7) 0px 12px 13px, rgb(252, 255, 54,0.7) 0px -3px 5px;\n  animation: rot 2.5s infinite ease-in-out;\n  transform-origin: center;\n}\n\n@keyframes rot {\n  0% {\n    transform: translate(50%,-50%) rotate(0deg);\n  }\n\n  100% {\n    transform: translate(50%,-50', colors: '', radii: '14px,50%,0.5rem', shadows: 'rgb(252, 255, 54,0.7) 0px 4px 105px, rgb(252, 255, 54,0.7) 0px -24px 130px, rgb(252, 255, 54,0.7) 0px 4px 446px, rgb(252', techniques: 'glassmorphism,3d-transform,text-shadow,animation,svg-icon'),
const GalaxyComp(id: 'yaroslavas2001_stupid-shrimp-89', cat: 'Notifications', author: 'yaroslavas2001', tags: 'notification', html: '<div class="notification">\n  <div class="mirrow">\n    <svg class="fragment fragment1" viewBox="0 0 137 108" fill="none" xmlns="http://www.w3.org/2000/svg">\n      <path d="M0 0H95L137 107.5L0 78V0Z"></path>\n    </svg>\n    <svg class="fragment fragment2" width="137" height="107" viewBox="0 0 137 107" fill="none" xmlns="http://www.w3.org/2000/svg">\n      <path d="M0 0L136.5 27.5L91 107H0V0Z"></path>\n    </svg>\n    <svg class="fragment fragment3" width="108" height="103" viewBox="0 0 108 103" fill="none" xmlns="http://www.w3.org/2000/svg">\n      <path d="M0 0H108L96 52L37.5 103L0 0Z"></path>\n    </svg>\n    <svg class="fragment fragment4" width="140" height="110" viewBox="0 0 140 110" fill="none" xmlns="http://www.w3.org/2000/svg">\n      <path d="M69 0H140V99L0 110L60.5 52L69 0Z"></path>\n    </svg>\n    <svg class="fragment fragment5" width="184" height="86" viewBox="0 0 184 86" fill="none" xmlns="http://www.w3.org/2000/svg">\n      <path d="M38 10L184 0V86H0L38 10Z"></path>\n    </svg>\n    <div class="level">\n      <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" class="star star1">\n        <path d="m12 17.328-5.403 3.286a.75.75 0 0 1-1.12-.813l1.456-6.155-4.796-4.123a.75.75 0 0 1 .428-1.316l6.303-.517 2.44-5.835a.75.75 0 0 1 1.384 0l2.44 5.835 6.303.517a.75.75 0 0 1 .427 1.316l-4.795 4.123 1.456 6.155a.75.75 0 0 1-1.12.813L12 17.328z"></path>\n      </svg>\n      <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" class="star star2">\n       ', css: '\n/* From Uiverse.io by yaroslavas2001 - Tags: notification */\n.notification {\n  height: 12em;\n  width: 19em;\n}\n\n.mirrow {\n  height: 12em;\n  width: 19em;\n  position: relative;\n  background: linear-gradient(45deg, #6720D9, #0062FF, #0085FF, #009CFF, #00AED3, #00BD9B);\n  background-size: 400% 400%;\n  animation: gradient 15s ease infinite;\n}\n\n.fragment {\n  position: absolute;\n  filter: blur(5px);\n  fill: rgba(252, 252, 252, 0.7);\n  transition: all 2s ease-in-out;\n}\n\n.mirrow:hover .fragment {\n  height: 0em;\n  width: 0em;\n  filter: blur(10px);\n}\n\n.fragment1 {\n  width: 9.5em;\n  height: 7.5em;\n}\n\n.mirrow:hover .fragment1 {\n  transform: translate(-15px, -15px);\n}\n\n.fragment2 {\n  width: 8em;\n  height: 6.5em;\n  bottom: 0px;\n  left: 0px;\n}\n\n.mirrow:hover .fragment2 {\n  transform: translate(-15px, 15px);\n}\n\n.fragment3 {\n  width: 7em;\n  height: 7em;\n  top: 0px;\n  right: 25%;\n  left: 40%;\n}\n\n.mirrow:hover .fragment3 {\n  transform: translate(0px, -15px);\n}\n\n.fragment4 {\n  width: 8em;\n  height: 7em;\n  top: 0px;\n  right: 0px\n}\n\n.mirrow:hover .fragment4 {\n  transform: translate(15px, -15px);\n}\n\n.fragment5 {\n  width: 12em;\n  height: 6em;\n  bottom: 0px;\n  right: 0px;\n}\n\n.mirrow:hover .fragment5 {\n  transform: translate(15px, 15px);\n}\n\n.level {\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  align-items: center;\n  height: 100%;\n}\n\n.btn_block {\n  display: flex;\n}\n\n.level_text {\n  font-weight: bold;\n  font-size: 22px;\n  color: #fff;\n  margin: 0px 0px 5px 0px;\n}\n\n.level_sub_text {\n  font-size: 13px;\n  color: #fff;\n  margin: 0px 0px 10px 0px;\n}\n\n.btn {\n  background: transparent;\n  border: 1px solid #fff;\n  border-radius: 14px;\n  cursor: pointer;\n  margin: 0px 2px;\n  color: #fff;\n  font-size: 12px;\n  transition: all 1s ease-in-out;\n  padding: 2px 6px;\n}\n\n.btn:hover {\n  background: #fff;\n  color: #000;\n}\n\n@keyframes gradient {\n  0% {\n    background-position: 0% 50%;\n  }\n\n  50% {\n    background-position: 100% 50%;\n  }\n\n  100% {\n    background-position: 0% 50%;\n  }\n}\n\n.st', colors: '#0085ff,#6720d9,#000,#0062ff,#00bd9b,#00aed3,#fff,#009cff', radii: '14px', shadows: '', techniques: 'glassmorphism,3d-transform,gradient,animation,svg-icon'),
const GalaxyComp(id: '1osm_rude-panda-79', cat: 'Buttons', author: '1osm', tags: 'button', html: '<button>\n  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="24" height="24"><path fill="none" d="M0 0h24v24H0z"></path><path fill="currentColor" d="M5 13c0-5.088 2.903-9.436 7-11.182C16.097 3.564 19 7.912 19 13c0 .823-.076 1.626-.22 2.403l1.94 1.832a.5.5 0 0 1 .095.603l-2.495 4.575a.5.5 0 0 1-.793.114l-2.234-2.234a1 1 0 0 0-.707-.293H9.414a1 1 0 0 0-.707.293l-2.234 2.234a.5.5 0 0 1-.793-.114l-2.495-4.575a.5.5 0 0 1 .095-.603l1.94-1.832C5.077 14.626 5 13.823 5 13zm1.476 6.696l.817-.817A3 3 0 0 1 9.414 18h5.172a3 3 0 0 1 2.121.879l.817.817.982-1.8-1.1-1.04a2 2 0 0 1-.593-1.82c.124-.664.187-1.345.187-2.036 0-3.87-1.995-7.3-5-8.96C8.995 5.7 7 9.13 7 13c0 .691.063 1.372.187 2.037a2 2 0 0 1-.593 1.82l-1.1 1.039.982 1.8zM12 13a2 2 0 1 1 0-4 2 2 0 0 1 0 4z"></path></svg>\n  <p class="Click">Click</p>\n  <p class="OnHover">Thanks</p>\n\n</button>', css: '\n/* From Uiverse.io by 1osm - Tags: button */\nbutton {\n  width: 130px;\n  height: 45px;\n  color: white;\n  font-weight: bold;\n  font-size: 20px;\n  border-width: 10px;\n  background: linear-gradient(to right, #5f6d7c, #456b8b, #49a6fc);\n  border: none;\n  letter-spacing: 0.05em;\n  border-radius: 10px;\n}\n\nbutton svg {\n  height: 40px;\n  width: 60px;\n  transform: translate(-30px,3px) rotate(90deg);\n  transition: transform 0.3s cubic-bezier(0.76, 0, 0.24, 1)\n}\n\nbutton .Click {\n  transform: translate(20px,-33px);\n  font-size: 20px;\n  transition: 0.3s cubic-bezier(0.76, 0, 0.24, 1)\n}\n\nbutton .OnHover {\n  transform: translate(-15px,-56px);\n  font-size: 20px;\n  opacity: 0%;\n  transition: 0.3s cubic-bezier(0.76, 0, 0.24, 1)\n}\n\nbutton:hover svg {\n  transform: translate(40px,3px) rotate(90deg);\n}\n\nbutton:hover .Click {\n  opacity: 0%;\n}\n\nbutton:hover .OnHover {\n  opacity: 100%;\n}\n', colors: '#456b8b,#5f6d7c,#49a6fc', radii: '10px', shadows: '', techniques: 'cubic-bezier,3d-transform,gradient,svg-icon'),
const GalaxyComp(id: '212004ALJI_fat-eagle-24', cat: 'Buttons', author: '212004ALJI', tags: 'button,glitch', html: '<button>\n  GLITCH\n</button>', css: '\n/* From Uiverse.io by 212004ALJI - Tags: button, glitch */\nbutton,button::after {\n  padding: 10px 50px;\n  font-size: 20px;\n  border: none;\n  border-radius: 5px;\n  color: white;\n  background-color: transparent;\n  position: relative;\n}\n\nbutton::after {\n  --move1: inset(50% 50% 50% 50%);\n  --move2: inset(31% 0 40% 0);\n  --move3: inset(39% 0 15% 0);\n  --move4: inset(45% 0 40% 0);\n  --move5: inset(45% 0 6% 0);\n  --move6: inset(14% 0 61% 0);\n  clip-path: var(--move1);\n  content: \'GLITCH\';\n  position: absolute;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  display: block;\n}\n\nbutton:hover::after {\n  animation: glitch_4011 1s;\n  text-shadow: 10 10px 10px black;\n  animation-timing-function: steps(2, end);\n  text-shadow: -3px -3px 0px #1df2f0, 3px 3px 0px #E94BE8;\n  background-color: transparent;\n  border: 3px solid rgb(0, 255, 213);\n}\n\nbutton:hover {\n  text-shadow: -1px -1px 0px #1df2f0, 1px 1px 0px #E94BE8;\n}\n\nbutton:hover {\n  background-color: transparent;\n  border: 1px solid rgb(0, 255, 213);\n  box-shadow: 0px 10px 10px -10px rgb(0, 255, 213);\n}\n\n@keyframes glitch_4011 {\n  0% {\n    clip-path: var(--move1);\n    transform: translate(0px,-10px);\n  }\n\n  10% {\n    clip-path: var(--move2);\n    transform: translate(-10px,10px);\n  }\n\n  20% {\n    clip-path: var(--move3);\n    transform: translate(10px,0px);\n  }\n\n  30% {\n    clip-path: var(--move4);\n    transform: translate(-10px,10px);\n  }\n\n  40% {\n    clip-path: var(--move5);\n    transform: translate(10px,-10px);\n  }\n\n  50% {\n    clip-path: var(--move6);\n    transform: translate(-10px,10px);\n  }\n\n  60% {\n    clip-path: var(--move1);\n    transform: translate(10px,-10px);\n  }\n\n  70% {\n    clip-path: var(--move3);\n    transform: translate(-10px,10px);\n  }\n\n  80% {\n    clip-path: var(--move2);\n    transform: translate(10px,-10px);\n  }\n\n  90% {\n    clip-path: var(--move4);\n    transform: translate(-10px,10px);\n  }\n\n  100% {\n    clip-path: var(--move1);\n    transform: translate(0);\n  }\n}\n\n\n', colors: '#e94be8,#1df2f0', radii: '5px', shadows: '0px 10px 10px -10px rgb(0, 255, 213)', techniques: 'text-shadow,animation,clip-path,pseudo-elements'),
const GalaxyComp(id: 'aaronross1_kind-bobcat-81', cat: 'Buttons', author: 'aaronross1', tags: 'button,edit', html: '<button class="edit-button">\n  <svg class="edit-svgIcon" viewBox="0 0 512 512">\n                    <path d="M410.3 231l11.3-11.3-33.9-33.9-62.1-62.1L291.7 89.8l-11.3 11.3-22.6 22.6L58.6 322.9c-10.4 10.4-18 23.3-22.2 37.4L1 480.7c-2.5 8.4-.2 17.5 6.1 23.7s15.3 8.5 23.7 6.1l120.3-35.4c14.1-4.2 27-11.8 37.4-22.2L387.7 253.7 410.3 231zM160 399.4l-9.1 22.7c-4 3.1-8.5 5.4-13.3 6.9L59.4 452l23-78.1c1.4-4.9 3.8-9.4 6.9-13.3l22.7-9.1v32c0 8.8 7.2 16 16 16h32zM362.7 18.7L348.3 33.2 325.7 55.8 314.3 67.1l33.9 33.9 62.1 62.1 33.9 33.9 11.3-11.3 22.6-22.6 14.5-14.5c25-25 25-65.5 0-90.5L453.3 18.7c-25-25-65.5-25-90.5 0zm-47.4 168l-144 144c-6.2 6.2-16.4 6.2-22.6 0s-6.2-16.4 0-22.6l144-144c6.2-6.2 16.4-6.2 22.6 0s6.2 16.4 0 22.6z"></path>\n                  </svg>\n</button>', css: '\n/* From Uiverse.io by aaronross1 - Tags: button, edit */\n.edit-button {\n  width: 40px;\n  height: 40px;\n  border-radius: 50%;\n  background-color: rgb(20, 20, 20);\n  border: none;\n  font-weight: 600;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  box-shadow: 0px 0px 20px rgba(0, 0, 0, 0.164);\n  cursor: pointer;\n  transition-duration: 0.3s;\n  overflow: hidden;\n  position: relative;\n  text-decoration: none !important;\n}\n\n.edit-svgIcon {\n  width: 17px;\n  transition-duration: 0.3s;\n}\n\n.edit-svgIcon path {\n  fill: white;\n}\n\n.edit-button:hover {\n  width: 120px;\n  border-radius: 50px;\n  transition-duration: 0.3s;\n  background-color: rgb(255, 69, 69);\n  align-items: center;\n}\n\n.edit-button:hover .edit-svgIcon {\n  width: 20px;\n  transition-duration: 0.3s;\n  transform: translateY(60%);\n  -webkit-transform: rotate(360deg);\n  -moz-transform: rotate(360deg);\n  -o-transform: rotate(360deg);\n  -ms-transform: rotate(360deg);\n  transform: rotate(360deg);\n}\n\n.edit-button::before {\n  display: none;\n  content: "Edit";\n  color: white;\n  transition-duration: 0.3s;\n  font-size: 2px;\n}\n\n.edit-button:hover::before {\n  display: block;\n  padding-right: 10px;\n  font-size: 13px;\n  opacity: 1;\n  transform: translateY(0px);\n  transition-duration: 0.3s;\n}\n\n', colors: '', radii: '50px,50%', shadows: '0px 0px 20px rgba(0, 0, 0, 0.164)', techniques: '3d-transform,glow-shadow,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'abhayexe_heavy-crab-27', cat: 'Buttons', author: 'abhayexe', tags: 'button', html: '<button class="join-button">\n  Join Today\n  <span class="arrow">\n    <svg\n      fill="#000000"\n      xml:space="preserve"\n      viewBox="0 0 32.00 32.00"\n      id="Layer_1"\n      version="1.1"\n    >\n      <g stroke-width="0" id="SVGRepo_bgCarrier"></g>\n      <g\n        stroke-linejoin="round"\n        stroke-linecap="round"\n        id="SVGRepo_tracerCarrier"\n      ></g>\n      <g id="SVGRepo_iconCarrier">\n        <line\n          y2="16"\n          x2="4"\n          y1="16"\n          x1="26"\n          stroke-miterlimit="10"\n          stroke-width="2.848"\n          stroke="#f3bff3"\n          fill="none"\n        ></line>\n        <polyline\n          points="18,7.5 26.5,16 18,24.5"\n          stroke-miterlimit="10"\n          stroke-width="2.848"\n          stroke="#f3bff3"\n          fill="none"\n        ></polyline>\n      </g>\n    </svg>\n  </span>\n</button>', css: '\n/* From Uiverse.io by abhayexe  - Tags: button */\n.join-button {\n  background: rgb(226, 136, 243);\n  background: linear-gradient(\n    180deg,\n    rgba(226, 136, 243, 1) 5%,\n    rgba(143, 76, 215, 1) 71%,\n    rgb(136, 37, 193) 93%,\n    rgb(98, 29, 176) 100%\n  );\n  border-top: 3px solid rgb(248, 205, 247);\n  border-bottom: 3px solid rgb(179, 64, 250);\n  border-left: 3px solid rgb(240, 162, 250);\n  border-right: 3px solid rgb(240, 162, 250);\n  color: rgba(244, 221, 249, 0.888);\n  text-shadow: 0px 1.5px #5000753d;\n  height: 70px;\n  border-radius: 20px;\n  padding: 15px 30px;\n  font-size: 18px;\n  font-weight: bold;\n  cursor: pointer;\n  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);\n  transition: all 0.7s ease;\n  box-shadow:\n    -25px 25px 15px rgba(55, 1, 181, 0.272),\n    -5px 5px 2px rgb(91, 1, 126),\n    -15px 15px 10px rgba(116, 1, 126, 0.555);\n}\n.join-button svg {\n  height: 30px;\n  margin-bottom: -9px;\n  margin-left: 5px;\n  filter: drop-shadow(1px 1px 2px rgba(0, 0, 0, 0.256));\n}\n.join-button:hover {\n  transform: translateY(5px);\n  box-shadow: -5px 5px 5px rgb(66, 1, 94);\n  background: rgb(91, 37, 193);\n  background: linear-gradient(\n    180deg,\n    rgba(91, 37, 193, 1) 5%,\n    rgba(143, 76, 215, 1) 57%,\n    rgba(226, 136, 243, 1) 100%\n  );\n}\n.join-button:active {\n  transition: transform 50ms ease-out;\n  box-shadow: -3px 3px 0px rgb(21, 0, 30);\n  transform: translateY(19px);\n}\n\n', colors: '#5000753d', radii: '20px', shadows: '0 4px 6px rgba(0, 0, 0, 0.1),-25px 25px 15px rgba(55, 1, 181, 0.272),\n    -5px 5px 2px rgb(91, 1, 126),\n    -15px 15px 10px rgba(116, 1, 126, 0.555),-5px 5px 5px rgb(66, 1, 94)', techniques: 'text-shadow,gradient,filter-effect,svg-icon'),
const GalaxyComp(id: 'adamgiebl_fluffy-liger-17', cat: 'Buttons', author: 'adamgiebl', tags: 'button', html: '<button> Button\n</button>', css: '\n/* From Uiverse.io by adamgiebl - Tags: button */\nbutton {\n  background: linear-gradient(-45deg, #3f00b5, #9f69fe, #27c8b7, #3f00b5);\n  background-size: 800% 400%;\n  padding: 1em 2em;\n  display: inline-block;\n  border: none;\n  border-radius: 10px;\n  font-size: 17px;\n  font-weight: 700;\n  color: white;\n  transition: all .5s ease-in-out;\n  animation: gradient 10s infinite cubic-bezier(.62, .28, .23, .99) both;\n}\n\nbutton:hover {\n  animation: gradient 3s infinite;\n  transform: scale(1.05);\n}\n\nbutton:active {\n  animation: gradient 3s infinite;\n  transform: scale(0.8);\n}\n\n@keyframes gradient {\n  0% {\n    background-position: 0% 50%;\n  }\n\n  50% {\n    background-position: 100% 50%;\n  }\n\n  100% {\n    background-position: 0% 50%;\n  }\n}\n', colors: '#3f00b5,#27c8b7,#9f69fe', radii: '10px', shadows: '', techniques: 'cubic-bezier,3d-transform,gradient,animation'),
const GalaxyComp(id: 'AlimurtuzaCodes_average-liger-0', cat: 'Buttons', author: 'AlimurtuzaCodes', tags: 'gradient,button,stars,css effect,css button,generate', html: '<button class="btn">\n    <svg height="24" width="24" fill="#FFFFFF" viewBox="0 0 24 24" data-name="Layer 1" id="Layer_1" class="sparkle">\n        <path d="M10,21.236,6.755,14.745.264,11.5,6.755,8.255,10,1.764l3.245,6.491L19.736,11.5l-6.491,3.245ZM18,21l1.5,3L21,21l3-1.5L21,18l-1.5-3L18,18l-3,1.5ZM19.333,4.667,20.5,7l1.167-2.333L24,3.5,21.667,2.333,20.5,0,19.333,2.333,17,3.5Z"></path>\n    </svg>\n\n    <span class="text">Generate</span>\n</button>', css: '\n/* From Uiverse.io by AlimurtuzaCodes - Tags: gradient, button, stars, css effect, css button, generate */\n.btn {\n  border: none;\n  width: 15em;\n  height: 5em;\n  border-radius: 3em;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  gap: 12px;\n  background: #1C1A1C;\n  cursor: pointer;\n  transition: all 450ms ease-in-out;\n}\n\n.sparkle {\n  fill: #AAAAAA;\n  transition: all 800ms ease;\n}\n\n.text {\n  font-weight: 600;\n  color: #AAAAAA;\n  font-size: medium;\n}\n\n.btn:hover {\n  background: linear-gradient(0deg,#A47CF3,#683FEA);\n  box-shadow: inset 0px 1px 0px 0px rgba(255, 255, 255, 0.4),\n  inset 0px -4px 0px 0px rgba(0, 0, 0, 0.2),\n  0px 0px 0px 4px rgba(255, 255, 255, 0.2),\n  0px 0px 180px 0px #9917FF;\n  transform: translateY(-2px);\n}\n\n.btn:hover .text {\n  color: white;\n}\n\n.btn:hover .sparkle {\n  fill: white;\n  transform: scale(1.2);\n} \n', colors: '#a47cf3,#683fea,#aaaaaa,#1c1a1c,#9917ff', radii: '3em', shadows: 'inset 0px 1px 0px 0px rgba(255, 255, 255, 0.4),\n  inset 0px -4px 0px 0px rgba(0, 0, 0, 0.2),\n  0px 0px 0px 4px rgba(255,', techniques: '3d-transform,glow-shadow,gradient,svg-icon'),
const GalaxyComp(id: 'ArturCodeCraft_big-chipmunk-22', cat: 'Buttons', author: 'ArturCodeCraft', tags: 'icon,button,theme,theme-switch,menu,menuicon,menu button', html: '<div class="background">\n  <button class="change-theme__icon">\n    <span class="icon-sun-moon"></span>\n    <span class="sun-rays">\n      <span></span>\n      <span></span>\n      <span></span>\n      <span></span>\n      <span></span>\n      <span></span>\n      <span></span>\n      <span></span>\n    </span>\n  </button>\n</div>', css: '\n/* From Uiverse.io by ArturCodeCraft - Tags: icon, button, theme, theme-switch, menu, menuicon, menu button  */\n/* <reset-style> ============================ */\nbutton {\n  border: none;\n  background: none;\n  padding: 0;\n  margin: 0;\n  cursor: pointer;\n  font-family: inherit;\n}\n/* ============================ */\n/* <style for bg> ======== */\n.background {\n  border-radius: 16px;\n  border: 1px solid #1a1a1a;\n  background: rgba(74, 74, 74, 0.39);\n  mix-blend-mode: luminosity;\n  box-shadow: 0px 0px 0px 1px rgba(0, 0, 0, 0.20);\n  backdrop-filter: blur(15px);\n  width: 65px;\n  height: 65px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n/* <style for change-theme__icon> ======== */\n.change-theme__icon {\n  width: 32px;\n  height: 32px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  position: relative;\n  overflow: hidden;\n}\n\n/* .icon-sun-moon */\n.change-theme__icon .icon-sun-moon {\n  width: 11.5px;\n  height: 11.5px;\n  border-radius: 100%;\n  background-color: rgb(28, 28, 30);\n  animation: ease reverse-change-theme .6s forwards;\n  transition: background-color .4s;\n  z-index: 10;\n}\n\n.change-theme__icon:hover .icon-sun-moon {\n  animation: change-theme .4s forwards;\n  background-color: #fff;\n}\n\n@keyframes change-theme {\n  0% {\n    width: 11.5px;\n    height: 11.5px;\n  }\n\n  100% {\n    width: 20px;\n    height: 20px;\n  }\n}\n\n@keyframes reverse-change-theme {\n  0% {\n    width: 20px;\n    height: 20px;\n  }\n\n  50% {\n    width: 10px;\n    height: 10px;\n  }\n\n  100% {\n    width: 11.5px;\n    height: 11.5px;\n  }\n}\n\n/* .icon-sun-moon:before */\n.change-theme__icon .icon-sun-moon:before {\n  content: \'\';\n  width: 20px;\n  height: 20px;\n  border-radius: 100%;\n  background-color: rgb(49,49,49);\n  position: absolute;\n  top: 2px;\n  right: -2px;\n  transform: translateX(100%) scale(.2);\n  transition: transform .4s;\n}\n\n.change-theme__icon:hover .icon-sun-moon:before {\n  transform: scale(1);\n  transition: transform .4s .12s;\n}\n\n/* sun-rays */\n.sun-rays {\n  width: ', colors: '#fff,#1a1a1a', radii: '100%,16px,2px', shadows: '0px 0px 0px 1px rgba(0, 0, 0, 0.20)', techniques: 'glassmorphism,3d-transform,glow-shadow,animation'),
const GalaxyComp(id: 'ArturCodeCraft_silly-firefox-72', cat: 'Buttons', author: 'ArturCodeCraft', tags: 'icon,apple,button,menuicon,menu button,hamburger menu', html: '<button class="menu__icon">\n  <span></span>\n  <span></span>\n</button>', css: '\n/* From Uiverse.io by ArturCodeCraft - Tags: icon, apple, button, menuicon, menu button , hamburger menu */\n/* <reset-style> ============================ */\nbutton {\n  border: none;\n  background: none;\n  padding: 0;\n  margin: 0;\n  cursor: pointer;\n  font-family: inherit;\n}\n/* <main-style> ============================ */\n.menu__icon {\n  width: 2rem;\n  height: 2rem;\n  padding: .25rem;\n  background-color: rgb(29, 29, 31, .7);\n  backdrop-filter: saturate(180%) blur(20px);\n  border: solid 1px rgba(66,66,69,0.7);\n  position: relative;\n}\n\n.menu__icon span {\n  width: 1.5rem;\n  height: 1.5rem;\n  position: absolute;\n  top: calc(.25rem - 1px);\n  left: calc(.25rem - 1px);\n  transition: transform .1806s cubic-bezier(.04,.04,.12,.96);\n}\n\n.menu__icon span:before {\n  content: \'\';\n  width: 1.5rem;\n  height: .125rem;\n  background-color: #fff;\n  position: absolute;\n  left: 0;\n  transition: transform .1596s cubic-bezier(.52,.16,.52,.84) .1008s;\n}\n\n.menu__icon span:nth-child(1)::before {\n  top: .625rem;\n  transform: translateY(-3px);\n}\n\n.menu__icon span:nth-child(2)::before {\n  bottom: .625rem;\n  transform: translateY(3px);\n}\n\n.menu__icon:hover :nth-child(1),\n.menu__icon:hover :nth-child(2) {\n  transition: transform .3192s cubic-bezier(.04,.04,.12,.96) .1008s;\n}\n\n.menu__icon:hover :nth-child(1)::before,\n.menu__icon:hover :nth-child(2)::before {\n  transform: none;\n  transition: transform .1806s cubic-bezier(.04,.04,.12,.96);\n}\n\n.menu__icon:hover :nth-child(1) {\n  transform: rotate(45deg) translateY(1px);\n}\n\n.menu__icon:hover :nth-child(2) {\n  transform: rotate(-45deg) translateY(-1px);\n}\n', colors: '#fff', radii: '', shadows: '', techniques: 'glassmorphism,cubic-bezier,3d-transform,pseudo-elements'),
const GalaxyComp(id: 'asgardOP_light-shrimp-73', cat: 'Buttons', author: 'asgardOP', tags: 'simple,animation,white,button,message,modern,btn,click animation', html: '<button class="button">\n  <div>\n    <svg\n      viewBox="0 0 24 24"\n      fill="none"\n      height="24"\n      width="24"\n      xmlns="http://www.w3.org/2000/svg"\n      aria-hidden="true"\n      class="w-6 h-6 text-gray-800 dark:text-white"\n    >\n      <path\n        d="m12 18-7 3 7-18 7 18-7-3Zm0 0v-5"\n        stroke-width="2"\n        stroke-linejoin="round"\n        stroke-linecap="round"\n        stroke="currentColor"\n      ></path>\n    </svg>\n    Send Message\n  </div>\n</button>', css: '\n/* From Uiverse.io by asgardOP  - Tags: simple, animation, white, button, message, modern, btn, click animation */\n.button {\n  width: 170px;\n  height: 55px;\n  border-radius: 10px;\n  border: 1px solid gray;\n  border-bottom: 2px solid rgb(77, 77, 77);\n  display: flex;\n  box-shadow: 0px 5px 10px rgba(0, 0, 0, 0.349);\n  align-items: center;\n  justify-content: center;\n  cursor: pointer;\n  position: relative;\n  transition: 0.4s;\n  background: linear-gradient(140deg, white, rgb(214, 214, 214));\n}\n\n.button:hover {\n  box-shadow: none;\n  transform: scaleY(0.6);\n  border-bottom: 2px solid rgb(77, 77, 77);\n  background: linear-gradient(160deg, white, rgb(214, 214, 214));\n}\n\n.button:active {\n  margin-top: 20px;\n  transition: 0.05s;\n}\n\n.button::before {\n  content: "";\n  position: absolute;\n  left: -1px;\n  bottom: 0px;\n  width: 170px;\n  height: 0px;\n  background: rgb(194, 194, 194);\n  border-top: 0px solid black;\n  border-bottom: 0px solid black;\n  transition: height 0.4s, bottom 0.4s, opacity 0s 0.35s;\n  opacity: 0;\n  box-shadow: inset 0px -10px 10px rgba(167, 167, 167, 0.719);\n  border-bottom-left-radius: 5px;\n  border-bottom-right-radius: 5px;\n}\n\n.button:hover::before {\n  height: 35px;\n  bottom: -27px;\n  opacity: 1;\n  border-bottom: 1px solid black;\n  transition: height 0.4s, bottom 0.4s;\n}\n\n.button:active::before {\n  height: 18px;\n  bottom: -9px;\n  transition: height 0.05s, bottom 0.05s, opacity 0s 0s;\n}\n\n.button div {\n  width: 150px;\n  height: 40px;\n  background: linear-gradient(180deg, rgba(212, 212, 212, 0.925), white);\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  border-radius: 20px;\n  font-weight: 900;\n}\n\n.button div svg {\n  width: 20px;\n  transform: rotate(40deg);\n  margin-right: 5px;\n}\n\n', colors: '', radii: '10px,20px', shadows: '0px 5px 10px rgba(0, 0, 0, 0.349),none,inset 0px -10px 10px rgba(167, 167, 167, 0.719)', techniques: '3d-transform,gradient,svg-icon,pseudo-elements'),
