sition: all 0.5s ease;\n  -o-transition: all 0.5s ease;\n  -ms-transition: all 0.5s ease;\n  transition: all 0.5s ease;\n}\n\n.button a, b {\n  -webkit-border-radius: 10px;\n  -moz-border-radius: 10px;\n  border-radius: 10px;\n  -webkit-box-shadow: 2px 2px 8px rgba(0,0,0,0.2);\n  -moz-box-shadow: 2px 2px 8px rgba(0,0,0,0.2);\n  box-sha', colors: '#00b7ea,#222,#009ec3,#fff', radii: '10px,5px', shadows: '2px 2px 8px rgba(0,0,0,0.2),2px 2px 8px rgba(0,0,0,0.2),2px 2px 8px rgba(0,0,0,0.2)', techniques: 'glow-shadow,gradient,filter-effect,typography-transform'),
const GalaxyComp(id: 'barisdogansutcu_big-moose-69', cat: 'Buttons', author: 'barisdogansutcu', tags: 'button,game,among us', html: '<button>\n    <svg height="36px" width="36px" viewBox="0 0 36 36" xmlns="http://www.w3.org/2000/svg">\n        <rect fill="#fdd835" y="0" x="0" height="36" width="36"></rect>\n        <path d="M38.67,42H11.52C11.27,40.62,11,38.57,11,36c0-5,0-11,0-11s1.44-7.39,3.22-9.59 c1.67-2.06,2.76-3.48,6.78-4.41c3-0.7,7.13-0.23,9,1c2.15,1.42,3.37,6.67,3.81,11.29c1.49-0.3,5.21,0.2,5.5,1.28 C40.89,30.29,39.48,38.31,38.67,42z" fill="#e53935"></path>\n        <path d="M39.02,42H11.99c-0.22-2.67-0.48-7.05-0.49-12.72c0.83,4.18,1.63,9.59,6.98,9.79 c3.48,0.12,8.27,0.55,9.83-2.45c1.57-3,3.72-8.95,3.51-15.62c-0.19-5.84-1.75-8.2-2.13-8.7c0.59,0.66,3.74,4.49,4.01,11.7 c0.03,0.83,0.06,1.72,0.08,2.66c4.21-0.15,5.93,1.5,6.07,2.35C40.68,33.85,39.8,38.9,39.02,42z" fill="#b71c1c"></path>\n        <path d="M35,27.17c0,3.67-0.28,11.2-0.42,14.83h-2C32.72,38.42,33,30.83,33,27.17 c0-5.54-1.46-12.65-3.55-14.02c-1.65-1.08-5.49-1.48-8.23-0.85c-3.62,0.83-4.57,1.99-6.14,3.92L15,16.32 c-1.31,1.6-2.59,6.92-3,8.96v10.8c0,2.58,0.28,4.61,0.54,5.92H10.5c-0.25-1.41-0.5-3.42-0.5-5.92l0.02-11.09 c0.15-0.77,1.55-7.63,3.43-9.94l0.08-0.09c1.65-2.03,2.96-3.63,7.25-4.61c3.28-0.76,7.67-0.25,9.77,1.13 C33.79,13.6,35,22.23,35,27.17z" fill="#212121"></path>\n        <path d="M17.165,17.283c5.217-0.055,9.391,0.283,9,6.011c-0.391,5.728-8.478,5.533-9.391,5.337 c-0.913-0.196-7.826-0.043-7.696-5.337C9.209,18,13.645,17.32,17.165,17.283z" fill="#01579b"></path>\n        <path d="M40.739,37.38c-0.28,1.99-0.69,3.53-1.22,4.62h-2.43c0.25-0.19,1.13-1.1', css: '\n/* From Uiverse.io by barisdogansutcu - Tags: button, game, among us */\nbutton {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  gap: 10px;\n  padding: 0 10px;\n  color: white;\n  text-shadow: 2px 2px rgb(116, 116, 116);\n  text-transform: uppercase;\n  border: solid 2px black;\n  letter-spacing: 1px;\n  font-weight: 600;\n  font-size: 17px;\n  background-color: hsl(49deg 98% 60%);\n  border-radius: 50px;\n  position: relative;\n  overflow: hidden;\n  transition: all .5s ease;\n}\n\nbutton:active {\n  transform: scale(.9);\n  transition: all 100ms ease;\n}\n\nbutton svg {\n  transition: all .5s ease;\n  z-index: 2;\n}\n\n.play {\n  transition: all .5s ease;\n  transition-delay: 300ms;\n}\n\nbutton:hover svg {\n  transform: scale(3) translate(50%);\n}\n\n.now {\n  position: absolute;\n  left: 0;\n  transform: translateX(-100%);\n  transition: all .5s ease;\n  z-index: 2;\n}\n\nbutton:hover .now {\n  transform: translateX(10px);\n  transition-delay: 300ms;\n}\n\nbutton:hover .play {\n  transform: translateX(200%);\n  transition-delay: 300ms;\n}\n', colors: '', radii: '50px', shadows: '', techniques: '3d-transform,text-shadow,typography-transform,svg-icon'),
const GalaxyComp(id: 'Bastiennnn_strong-lionfish-94', cat: 'Buttons', author: 'Bastiennnn', tags: 'simple,animation,button,message,svg', html: '<button class="button">\n  <svg\n    xmlns="http://www.w3.org/2000/svg"\n    class="svg"\n    height="25px"\n    viewBox="0 0 24 24"\n    fill="none"\n  >\n    <path\n      d="M14.2199 21.63C13.0399 21.63 11.3699 20.8 10.0499 16.83L9.32988 14.67L7.16988 13.95C3.20988 12.63 2.37988 10.96 2.37988 9.78001C2.37988 8.61001 3.20988 6.93001 7.16988 5.60001L15.6599 2.77001C17.7799 2.06001 19.5499 2.27001 20.6399 3.35001C21.7299 4.43001 21.9399 6.21001 21.2299 8.33001L18.3999 16.82C17.0699 20.8 15.3999 21.63 14.2199 21.63ZM7.63988 7.03001C4.85988 7.96001 3.86988 9.06001 3.86988 9.78001C3.86988 10.5 4.85988 11.6 7.63988 12.52L10.1599 13.36C10.3799 13.43 10.5599 13.61 10.6299 13.83L11.4699 16.35C12.3899 19.13 13.4999 20.12 14.2199 20.12C14.9399 20.12 16.0399 19.13 16.9699 16.35L19.7999 7.86001C20.3099 6.32001 20.2199 5.06001 19.5699 4.41001C18.9199 3.76001 17.6599 3.68001 16.1299 4.19001L7.63988 7.03001Z"\n      fill="#000000"\n    ></path>\n    <path\n      d="M10.11 14.4C9.92005 14.4 9.73005 14.33 9.58005 14.18C9.29005 13.89 9.29005 13.41 9.58005 13.12L13.16 9.53C13.45 9.24 13.93 9.24 14.22 9.53C14.51 9.82 14.51 10.3 14.22 10.59L10.64 14.18C10.5 14.33 10.3 14.4 10.11 14.4Z"\n      fill="#000000"\n    ></path>\n  </svg>\n  Send Message\n</button>', css: '\n/* From Uiverse.io by Bastiennnn  - Tags: simple, animation, button, message, svg */\n.button {\n  cursor: pointer;\n  width: 200px;\n  height: 60px;\n  background-color: white;\n  font-size: medium;\n  font-weight: bold;\n  box-shadow: 0 5px 10px rgb(122, 122, 122);\n  border-radius: 10px;\n  border: 2px solid gray;\n  transition: all 0.7s cubic-bezier(0.4, 0, 0.2, 1);\n  position: relative;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.button:hover {\n  box-shadow: 0 5px 10px rgb(58, 58, 58);\n  transform: translateY(-10px);\n}\n\n.button:active {\n  transform: scale(0.95);\n  box-shadow: 0px 2px 5px rgba(0, 0, 0, 0.2);\n}\n\n.svg {\n  padding-right: 8px;\n  fill: none;\n  height: 25px;\n  transition: transform 1s cubic-bezier(0.4, 0, 0.2, 1);\n}\n\n.button:hover .svg {\n  animation: flyAround 6s cubic-bezier(0.4, 0, 0.2, 1) infinite;\n}\n\n@keyframes flyAround {\n  0% {\n    transform: translate(0, 0) rotate(0deg) scale(1);\n  }\n  50% {\n    transform: translate(20px, -100px) rotate(-300deg) scale(1);\n  }\n  100% {\n    transform: translate(0, 0) rotate(0deg) scale(1);\n  }\n}\n\n', colors: '', radii: '10px', shadows: '0 5px 10px rgb(122, 122, 122),0 5px 10px rgb(58, 58, 58),0px 2px 5px rgba(0, 0, 0, 0.2)', techniques: 'cubic-bezier,3d-transform,animation,svg-icon'),
const GalaxyComp(id: 'boryanakrasteva_tidy-falcon-17', cat: 'Buttons', author: 'boryanakrasteva', tags: 'button,delete', html: '<button class="btn">\n  <svg viewBox="0 0 15 17.5" height="17.5" width="15" xmlns="http://www.w3.org/2000/svg" class="icon">\n  <path transform="translate(-2.5 -1.25)" d="M15,18.75H5A1.251,1.251,0,0,1,3.75,17.5V5H2.5V3.75h15V5H16.25V17.5A1.251,1.251,0,0,1,15,18.75ZM5,5V17.5H15V5Zm7.5,10H11.25V7.5H12.5V15ZM8.75,15H7.5V7.5H8.75V15ZM12.5,2.5h-5V1.25h5V2.5Z" id="Fill"></path>\n</svg>\n</button>', css: '\n/* From Uiverse.io by boryanakrasteva - Tags: button, delete */\n.btn {\n  background-color: transparent;\n  position: relative;\n  border: none;\n}\n\n.btn::after {\n  content: \'delete\';\n  position: absolute;\n  top: -130%;\n  left: 50%;\n  transform: translateX(-50%);\n  width: fit-content;\n  height: fit-content;\n  background-color: rgb(168, 7, 7);\n  padding: 4px 8px;\n  border-radius: 5px;\n  transition: .2s linear;\n  transition-delay: .2s;\n  color: white;\n  text-transform: uppercase;\n  font-size: 12px;\n  opacity: 0;\n  visibility: hidden;\n}\n\n.icon {\n  transform: scale(1.2);\n  transition: .2s linear;\n}\n\n.btn:hover > .icon {\n  transform: scale(1.5);\n}\n\n.btn:hover > .icon path {\n  fill: rgb(168, 7, 7);\n}\n\n.btn:hover::after {\n  visibility: visible;\n  opacity: 1;\n  top: -160%;\n}\n\n', colors: '', radii: '5px', shadows: '', techniques: '3d-transform,typography-transform,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'catraco_blue-bulldog-58', cat: 'Buttons', author: 'catraco', tags: 'button,click,light&dark,startbutton', html: '<button class="btn">\n  <div>GET STARTED</div>\n  <svg fill="none" viewBox="0 0 24 24" height="25px" width="25px" xmlns="http://www.w3.org/2000/svg">\n<path stroke-linejoin="round" stroke-linecap="round" stroke-miterlimit="10" stroke-width="2" stroke="white" d="M11.6801 14.62L14.2401 12.06L11.6801 9.5"></path>\n<path stroke-linejoin="round" stroke-linecap="round" stroke-miterlimit="10" stroke-width="2" stroke="white" d="M4 12.0601H14.17"></path>\n<path stroke-linejoin="round" stroke-linecap="round" stroke-miterlimit="10" stroke-width="2" stroke="white" d="M12 4C16.42 4 20 7 20 12C20 17 16.42 20 12 20"></path>\n</svg>\n</button>', css: '\n/* From Uiverse.io by catraco - Tags: button, click, light&dark, startbutton  */\n.btn {\n  --color: #de5c9d;\n  position: relative;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  transition: all .5s;\n  border: none;\n  background-color: transparent;\n}\n\n.btn div {\n  letter-spacing: 2px;\n  font-weight: bold;\n  background: var(--color);\n  border-radius: 2rem;\n  color: white;\n  padding: 1rem;\n}\n\n.btn::before {\n  content: \'\';\n  z-index: -1;\n  background-color: var(--color);\n  border: 2px solid white;\n  border-radius: 2rem;\n  width: 110%;\n  height: 100%;\n  position: absolute;\n  transform: rotate(10deg);\n  transition: .5s;\n  opacity: 0.2;\n}\n\n.btn:hover {\n  cursor: pointer;\n  filter: brightness(1.2);\n  transform: scale(1.1);\n}\n\n.btn:hover::before {\n  transform: rotate(0deg);\n  opacity: 1;\n}\n\n.btn svg {\n  transform: translateX(-200%);\n  transition: .5s;\n  width: 0;\n  opacity: 0;\n}\n\n.btn:hover svg {\n  width: 25px;\n  transform: translateX(0%);\n  opacity: 1;\n}\n\n.btn:active {\n  filter: brightness(1.4);\n}\n', colors: '#de5c9d', radii: '2rem', shadows: '', techniques: '3d-transform,filter-effect,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'catraco_friendly-snake-37', cat: 'Buttons', author: 'catraco', tags: 'button,ring,next,hover effect,startbutton,variables', html: '<button class="btn-class-name">\n  <span>Next</span>\n  <svg viewBox="0 0 320 512" height="1em" xmlns="http://www.w3.org/2000/svg">\n    <path d="M310.6 233.4c12.5 12.5 12.5 32.8 0 45.3l-192 192c-12.5 12.5-32.8 12.5-45.3 0s-12.5-32.8 0-45.3L242.7 256 73.4 86.6c-12.5-12.5-12.5-32.8 0-45.3s32.8-12.5 45.3 0l192 192z">\n  </path>\n  </svg>\n</button>', css: '\n/* From Uiverse.io by catraco - Tags: button, ring, next, hover effect, startbutton , variables */\n.btn-class-name {\n  --color: 180,255, 100;\n  border-radius: .5em;\n  transition: .3s;\n  background-color: rgba(var(--color), .2);\n  color: rgb(var(--color));\n  fill: rgb(var(--color));\n  font-family: monospace;\n  font-weight: bolder;\n  font-size: x-large;\n  text-transform: uppercase;\n  letter-spacing: 0.1em;\n  cursor: pointer;\n  border: 2px solid rgb(var(--color));\n  box-shadow: 0 0 10px rgba(var(--color), .4);\n  outline: none;\n  display: flex;\n  align-items: center;\n  padding: .5em 1em;\n}\n\n.btn-class-name:hover {\n  box-shadow: 0 0 0 5px rgba(var(--color), .5);\n}\n\n.btn-class-name span {\n  transform: scale(.8);\n  transition: .3s;\n}\n\n.btn-class-name:hover span {\n  transform: scale(1);\n}\n\n.btn-class-name svg {\n  font-size: 0;\n  transform: scale(0.5) translateX(0%) rotate(-180deg);\n  transition: .3s;\n}\n\n.btn-class-name:hover svg {\n  font-size: 20px;\n  transform: scale(1) translateX(20%) rotate(0deg);\n}\n\n.btn-class-name:active {\n  transition: 0s;\n  box-shadow: 0 0 0 5px rgb(var(--color));\n}\n', colors: '', radii: '.5em', shadows: '0 0 10px rgba(var(--color), .4),0 0 0 5px rgba(var(--color), .5),0 0 0 5px rgb(var(--color))', techniques: '3d-transform,glow-shadow,typography-transform,svg-icon'),
const GalaxyComp(id: 'Codecite_angry-bullfrog-58', cat: 'Buttons', author: 'Codecite', tags: 'gradient,button,round', html: '<button class="btn">\n  <span>Get started</span>\n</button>', css: '\n/* From Uiverse.io by Codecite - Tags: gradient, button, round */\n.btn {\n  --fancy-button-gradient-0: #8d49fd;\n  --fancy-button-gradient-50: #7f56f3;\n  --fancy-button-gradient-100: #5691f3;\n  --fancy-button-inner-shadow-top: rgba(233, 209, 255, 0.2);\n  --fancy-button-inner-shadow-top-lg: rgba(9, 12, 60, 0.1);\n  --fancy-button-inner-shadow-bottom: rgba(137, 222, 246, 0.3);\n  --fancy-button-shine-top: #e9d1ff;\n  --fancy-button-shine-bottom: #adfff9;\n  font-family: \'Poppins\';\n  font-weight: 500;\n  font-size: 15px;\n  line-height: 21px;\n  text-shadow: 0px 0.5px 0.5px rgba(0, 0, 0, 0.2);\n  padding: 0;\n  margin: 0;\n  appearance: none;\n  border: none;\n  outline: none;\n  overflow: hidden;\n  position: relative;\n  cursor: pointer;\n  z-index: 1;\n  border-radius: 25px;\n  color: #fff;\n  background-image: linear-gradient(to bottom, var(--fancy-button-gradient-0) 0%, var(--fancy-button-gradient-50) 50%, var(--fancy-button-gradient-100) 100%);\n  box-shadow: 0px 4px 12px rgba(9, 12, 60, 0.15), 0px 2px 8px rgba(9, 12, 60, 0.15), 0px 1px 3px var(--fancy-button-inner-shadow-top-lg), inset 0px 1px 1px var(--fancy-button-inner-shadow-top), inset 0px -1px 3px var(--fancy-button-inner-shadow-bottom);\n}\n\n.btn:before, .btn:after {\n  content: \'\';\n  position: absolute;\n  border-radius: inherit;\n  will-change: transform;\n}\n\n.btn:before {\n  left: 50%;\n  transform: translateX(-50%);\n  background-color: var(--fancy-button-shine-top);\n  width: 96px;\n  height: 6px;\n  top: -3px;\n  opacity: 0.6;\n  filter: blur(6px);\n  transition: opacity 0.25s;\n}\n\n.btn:after {\n  inset: 0;\n  background-size: cover;\n  z-index: 2;\n  opacity: 0.3;\n  mix-blend-mode: overlay;\n  pointer-events: none;\n}\n\n.btn span {\n  display: block;\n  padding: 12px 24px;\n  border-radius: inherit;\n  overflow: hidden;\n  position: relative;\n  background-image: linear-gradient(to bottom, var(--fancy-button-shine-top), transparent 8px);\n  background-position: 0 -6px;\n  background-repeat: no-repeat;\n  z-index: 1;\n}\n\n.btn span:before, .btn span:aft', colors: '#8d49fd,#5691f3,#7f56f3,#e9d1ff,#fff,#adfff9', radii: '50%,inherit,25px', shadows: '0px 4px 12px rgba(9, 12, 60, 0.15), 0px 2px 8px rgba(9, 12, 60, 0.15), 0px 1px 3px var(--fancy-button-inner-shadow-top-l', techniques: 'glassmorphism,3d-transform,text-shadow,gradient'),
const GalaxyComp(id: 'Cornerstone-04_helpless-cheetah-32', cat: 'Buttons', author: 'Cornerstone-04', tags: 'button', html: '<button><span>Hover</span></button>', css: '\n/* From Uiverse.io by Cornerstone-04 - Tags: button */\nbutton {\n  cursor: pointer;\n  background: transparent;\n  position: relative;\n  display: inline-block;\n  padding: 15px 30px;\n  outline: none;\n  border: 2px solid #0f0;\n  margin: 40px;\n  width: 150px;\n  height: 60px;\n  text-transform: uppercase;\n  font-weight: 900;\n  text-decoration: none;\n  letter-spacing: 2px;\n  color: #fff;\n  -webkit-box-reflect: below 0px linear-gradient(transparent, #0002);\n  transition: 0.45s;\n  transition-delay: 0s;\n}\n\nbutton:hover {\n  transition-delay: 1.5s;\n  color: #000;\n  box-shadow: 0 0 10px #0f0,\n                0 0 20px #0f0,\n                0 0 40px #0f0, \n                0 0 80px #0f0, \n                0 0 100px #0f0;\n}\n\nbutton span {\n  position: relative;\n  z-index: 100;\n}\n\nbutton::before {\n  content: "";\n  position: absolute;\n  left: -20px;\n  top: 50%;\n  transform: translateY(-50%);\n  width: 20px;\n  height: 2px;\n  background: #0f0;\n  box-shadow: 5px -8px 0 #0f0, \n              5px 8px 0 #0f0;\n  transition: width 0.5s, \n              left 0.5s, \n              height 0.5s, \n              box-shadow 0.5s;\n  transition-delay: 1s, 0.5s, 0s, 0s;\n}\n\nbutton:hover::before {\n  width: 60%;\n  height: 100%;\n  /* right: -2px; */\n  left: -2px;\n  box-shadow: 5px 0 0 #0f0, \n              5px 0 0 #0f0;\n  transition-delay: 0s, 0.5s, 1s, 1s;\n}\n\nbutton::after {\n  content: "";\n  position: absolute;\n  right: -20px;\n  top: 50%;\n  transform: translateY(-50%);\n  width: 20px;\n  height: 2px;\n  background: #0f0;\n  box-shadow: -5px -8px 0 #0f0, \n              -5px 8px 0 #0f0;\n  transition: width 0.5s, right 0.5s, height 0.5s, box-shadow 0.5s;\n  transition-delay: 1s, 0.5s, 0s, 0s;\n}\n\nbutton:hover::after {\n  width: 60%;\n  height: 102%;\n  right: -2px;\n  box-shadow: -5px 0 0 #0f0, -5px 0 0 #0f0;\n  transition-delay: 0s, 0.5s, 1s, 1s;\n}\n\n', colors: '#0002,#000,#0f0,#fff', radii: '', shadows: '0 0 10px #0f0,\n                0 0 20px #0f0,\n                0 0 40px #0f0, \n                0 0 80px #0f0, \n          ,5px -8px 0 #0f0, \n              5px 8px 0 #0f0,5px 0 0 #0f0, \n              5px 0 0 #0f0', techniques: 'glow-shadow,gradient,typography-transform,pseudo-elements'),
