const GalaxyComp(id: 'cybrejon_old-termite-43', cat: 'Buttons', author: 'cybrejon', tags: 'glassmorphism,button,download', html: '<a\n  ><svg\n    viewBox="0 0 256 256"\n    height="32"\n    width="38"\n    xmlns="http://www.w3.org/2000/svg"\n  >\n    <path\n      d="M74.34 85.66a8 8 0 0 1 11.32-11.32L120 108.69V24a8 8 0 0 1 16 0v84.69l34.34-34.35a8 8 0 0 1 11.32 11.32l-48 48a8 8 0 0 1-11.32 0ZM240 136v64a16 16 0 0 1-16 16H32a16 16 0 0 1-16-16v-64a16 16 0 0 1 16-16h52.4a4 4 0 0 1 2.83 1.17L111 145a24 24 0 0 0 34 0l23.8-23.8a4 4 0 0 1 2.8-1.2H224a16 16 0 0 1 16 16m-40 32a12 12 0 1 0-12 12a12 12 0 0 0 12-12"\n      fill="currentColor"\n    ></path></svg\n></a>', css: '\n/* From Uiverse.io by cybrejon  - Tags: glassmorphism, button, download */\na {\n  color: rgba(255, 255, 255, 0.692);\n  padding: 10px 15px;\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  text-shadow: 0 0 20px rgba(255, 255, 255, 0.397);\n  background: rgba(255, 255, 255, 0.068);\n  overflow: hidden;\n  font-size: 0.9rem;\n  font-weight: 600;\n  gap: 8px;\n  border-radius: 5px;\n  margin: 0 5px;\n  transition: 0.2s;\n  border: 1px solid transparent;\n}\n\na:hover {\n  border-color: rgba(255, 255, 255, 0.623);\n  background: linear-gradient(\n    to bottom,\n    rgba(255, 255, 255, 0.144),\n    rgba(255, 255, 255, 0.247),\n    rgba(255, 255, 255, 0.39)\n  );\n  box-shadow: 0 6px rgba(255, 255, 255, 0.623);\n  transform: translateY(-6px);\n}\n\na:active {\n  transform: translateY(2px);\n  box-shadow: none;\n}\n\n', colors: '', radii: '5px', shadows: '0 6px rgba(255, 255, 255, 0.623),none', techniques: 'glow-shadow,text-shadow,gradient,svg-icon'),
const GalaxyComp(id: 'Dashrath-Sharma_chatty-tiger-70', cat: 'Buttons', author: 'Dashrath-Sharma', tags: 'glassmorphism,flashy,button,shadow,glow,border,box-shadow,buttons', html: '<button class="button">Button</button>', css: '\n/* From Uiverse.io by Dashrath-Sharma  - Tags: glassmorphism, flashy, button, shadow, glow, border, box-shadow, buttons */\nbutton {\n  cursor: pointer;\n  padding: 1em 2em;\n  font-weight: bold;\n  font-size: 20px;\n  color: #fff;\n  position: relative;\n  overflow: hidden;\n  background: rgba(60, 73, 203, 0.35);\n  box-shadow: 0 0px 32px 0 rgba(31, 38, 135, 0.37);\n  backdrop-filter: blur(14.5px);\n  border: 1px solid rgba(255, 255, 255, 0.18);\n  -webkit-backdrop-filter: blur(14.5px);\n}\n\nbutton:hover {\n  box-shadow: 0px 0 32px 0 rgba(31, 38, 135, 0.37),\n    0px 0 32px 0 rgba(31, 38, 135, 0.37), 0 0 42px 0px rgba(31, 38, 135, 0.37),\n    0 0 52px 0 rgba(31, 38, 135, 0.37);\n  border: 1px solid rgba(255, 255, 255, 0.58);\n}\n\nbutton,\nbutton::before {\n  display: grid;\n  place-items: center;\n  border-radius: 10px;\n  box-shadow: 0 0px 32px 0 rgba(31, 38, 135, 0.37);\n}\n\nbutton::before {\n  content: "Button";\n  position: absolute;\n  background: blue;\n  width: 90%;\n  height: 80%;\n  background: rgba(26, 18, 241, 0.25);\n  backdrop-filter: blur(18.5px);\n  -webkit-backdrop-filter: blur(18.5px);\n  border: 1px solid rgba(255, 255, 255, 0.18);\n  transition: 0.4s;\n}\n\nbutton:hover::before {\n  background: rgba(51, 57, 236, 0.4);\n  box-shadow: 1px 1px 2px 0 rgba(31, 38, 135, 0.37),\n    2px 2px 2px 0 rgba(31, 38, 135, 0.37), 0 0px 32px 0 rgba(31, 38, 135, 0.37),\n    0 0px 32px 1px rgba(31, 38, 135, 0.37), 0 0px 32px 0 rgba(31, 38, 135, 0.37);\n  backdrop-filter: blur(5.5px);\n  -webkit-backdrop-filter: blur(5.5px);\n  border-radius: 10px;\n  border: 1px solid rgba(255, 255, 255, 0.18);\n}\nbutton:active::before {\n  transform: scale(0.67);\n}\n\n', colors: '#fff', radii: '10px', shadows: '0 0px 32px 0 rgba(31, 38, 135, 0.37),0px 0 32px 0 rgba(31, 38, 135, 0.37),\n    0px 0 32px 0 rgba(31, 38, 135, 0.37), 0 0 42px 0px rgba(31, 38, 135, 0.37),\n  ,0 0px 32px 0 rgba(31, 38, 135, 0.37)', techniques: 'glassmorphism,3d-transform,glow-shadow,pseudo-elements'),
const GalaxyComp(id: 'Dashrath-Sharma_popular-cobra-99', cat: 'Buttons', author: 'Dashrath-Sharma', tags: 'button,active,neon,futuristic,animated,border,advanced,transparent', html: '<button class="button">\n  Button\n  <span></span>\n  <span></span>\n</button>', css: '\n/* From Uiverse.io by Dashrath-Sharma  - Tags: button, active, neon, futuristic, animated, border, advanced, transparent */\n.button {\n  position: relative;\n  font-size: 17px;\n  font-weight: 800;\n  color: #c77dff;\n  padding: 1em 2em;\n  border: none;\n  background: none;\n  clip-path: polygon(0 0, 67% 0, 100% 100%, 33% 100%);\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  overflow: hidden;\n  transition: 0.3s 0.3s;\n}\n\nbutton:hover {\n  text-shadow: 1px 1px 20px #e0aaff, 1px 1px 60px #e0aaff;\n}\n\nbutton:active {\n  transform: scale(0.89);\n}\n\n.button::before,\n.button::after {\n  content: "";\n  position: absolute;\n  width: 0;\n  height: 2px;\n  background: #c77dff;\n  transition: width 0.3s 0.6s;\n}\n\n.button::before {\n  top: 0;\n  left: 0;\n  transform-origin: top;\n}\n\n.button::after {\n  bottom: 0;\n  right: 0;\n  transform-origin: bottom;\n}\n\n.button:hover::before,\n.button:hover::after {\n  width: 65%;\n}\n\n.button span {\n  position: absolute;\n  width: 0;\n  height: 2px;\n  background: #c77dff;\n  transition: width 0.3s, transform 0.3s 0.3s;\n  transform: rotate(22.3deg);\n}\n\n.button span:nth-child(1) {\n  top: 0;\n  left: 0;\n  transform-origin: left;\n}\n\n.button span:nth-child(2) {\n  bottom: 0;\n  right: 0;\n  transform-origin: right;\n}\n\n.button:hover span {\n  width: 55%;\n  transform: rotate(50deg);\n}\n\n', colors: '#c77dff,#e0aaff', radii: '', shadows: '', techniques: '3d-transform,text-shadow,clip-path,pseudo-elements'),
const GalaxyComp(id: 'Dashrath-Sharma_thin-mole-87', cat: 'Buttons', author: 'Dashrath-Sharma', tags: 'material design,animation,3d,white,black,button,simple button', html: '<button class="button">\n  <svg\n    xml:space="preserve"\n    viewBox="0 0 256 256"\n    height="256"\n    width="256"\n    version="1.1"\n    xmlns:xlink="http://www.w3.org/1999/xlink"\n    xmlns="http://www.w3.org/2000/svg"\n  >\n    <defs></defs>\n    <g\n      transform="translate(1.4065934065934016 1.4065934065934016) scale(2.81 2.81)"\n      style="stroke: none; stroke-width: 0; stroke-dasharray: none; stroke-linecap: butt; stroke-linejoin: miter; stroke-miterlimit: 10; fill: none; fill-rule: nonzero; opacity: 1;"\n    >\n      <path\n        stroke-linecap="round"\n        transform="matrix(1 0 0 1 0 0)"\n        style="stroke: none; stroke-width: 1; stroke-dasharray: none; stroke-linecap: butt; stroke-linejoin: miter; stroke-miterlimit: 10; fill: rgb(0,0,0); fill-rule: nonzero; opacity: 1;"\n        d="M 71.79 34.614 c -0.334 -0.497 -0.926 -0.745 -1.513 -0.63 l -18.311 3.528 l 3.718 -35.877 c 0.071 -0.682 -0.332 -1.32 -0.979 -1.55 c -0.648 -0.229 -1.362 0.011 -1.738 0.585 L 18.202 53.746 c -0.328 0.5 -0.325 1.144 0.008 1.639 c 0.33 0.493 0.922 0.742 1.513 0.632 l 18.312 -3.529 l -3.718 35.876 c -0.071 0.684 0.332 1.322 0.979 1.551 C 35.455 89.971 35.622 90 35.792 90 c 0.502 0 0.965 -0.251 1.241 -0.67 l 34.765 -53.076 C 72.126 35.754 72.122 35.11 71.79 34.614 z"\n      ></path>\n    </g>\n  </svg>\n  Join Now\n</button>', css: '\n/* From Uiverse.io by Dashrath-Sharma  - Tags: material design, animation, 3d, white, black, button, simple button */\n.button {\n  box-shadow: -5px -5px 15px #444, 5px 5px 15px #222, inset 5px 5px 15px #444,\n    inset -5px -5px 15px #222;\n}\n\n.button {\n  cursor: pointer;\n  position: relative;\n  font-size: 17px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  padding: 1.5em 4.5em;\n  border-radius: 15px;\n  border: none;\n  font-weight: bold;\n  transition: 0.5s;\n  z-index: 1;\n}\n.button:active {\n  transform: scale(0.8);\n}\n.button:active::before {\n  transform: translateY(-10px);\n}\n\n.button > svg {\n  width: 15px;\n  height: 15px;\n  margin-right: 5px;\n}\n\n.button::before,\n.button::after {\n  content: "";\n  position: absolute;\n  transition: 0.2s;\n  border-radius: 15px;\n  background: rgba(255, 255, 255, 0.1);\n  box-shadow: 0 8px 32px 0 rgba(31, 38, 135, 0.37);\n  backdrop-filter: blur(2.5px);\n  -webkit-backdrop-filter: blur(2.5px);\n  border: 1px solid rgba(255, 255, 255, 0.58);\n  z-index: -1;\n}\n\n.button::after {\n  width: 90%;\n  height: 68%;\n}\n\n.button::before {\n  width: 99%;\n  height: 90%;\n}\n\n', colors: '#222,#444', radii: '15px', shadows: '-5px -5px 15px #444, 5px 5px 15px #222, inset 5px 5px 15px #444,\n    inset -5px -5px 15px #222,0 8px 32px 0 rgba(31, 38, 135, 0.37)', techniques: 'glassmorphism,3d-transform,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'david-mohseni_green-gecko-20', cat: 'Buttons', author: 'david-mohseni', tags: 'button', html: '<div class="wrap">\n    <button class="btn">\n        <span class="text">Volume</span>\n    </button>\n</div>', css: '\n/* From Uiverse.io by david-mohseni - Tags: button */\n.wrap {\n  text-align: center;\n  margin: 20px 0;\n}\n\n.btn {\n  width: 100px;\n  height: 100px;\n  background: repeating-radial-gradient(circle at 50% 50%, rgba(200,200,200,.2) 0%, rgba(200,200,200,.2) 2%, transparent 2%, transparent 3%, rgba(200,200,200,.2) 3%, transparent 3%), conic-gradient(white 0%, silver 10%, white 35%, silver 45%, white 60%, silver 70%, white 80%, silver 95%, white 100%);\n  border-radius: 50%;\n  box-shadow: 0 0px 20px #0005, 0 -0px 20px #fff2;\n  outline: 1px solid #fff;\n  outline-offset: -2px;\n  transition: 1s;\n}\n\n.text {\n  font-size: 20px;\n  font-weight: 700;\n  color: #aaa;\n  text-align: center;\n  text-shadow: 1px 1px 1px #fff;\n}\n\n.btn:hover {\n  transform: rotate(90deg);\n}\n', colors: '#fff2,#aaa,#fff,#0005', radii: '50%', shadows: '0 0px 20px #0005, 0 -0px 20px #fff2', techniques: '3d-transform,glow-shadow,text-shadow,gradient'),
const GalaxyComp(id: 'Deri-Kurniawan_helpless-insect-19', cat: 'Buttons', author: 'Deri-Kurniawan', tags: 'button,hover,click,slide,hover effect,hover button,button hover effect', html: '<button class="button">\n  hover me!\n</button>', css: '\n/* From Uiverse.io by Deri-Kurniawan - Tags: button, hover, click, slide, hover effect, hover button, button hover effect  */\n.button {\n  position: relative;\n  padding: 12px 32px;\n  font-size: 16px;\n  font-weight: 700;\n  text-transform: uppercase;\n  color: #000;\n  background-color: #fff;\n  border: none;\n  border-radius: 50px;\n  overflow: hidden;\n  z-index: 1;\n  transition: all 0.3s ease-in-out;\n  box-shadow: 0 6px 10px rgba(0, 0, 0, 0.1);\n  cursor: pointer;\n}\n\n.button:hover {\n  transform: scale(1.05);\n  color: #fff;\n  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);\n}\n\n.button:active {\n  transform: scale(0.9);\n}\n\n.button::before {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: -100%;\n  width: 100%;\n  height: 100%;\n  background: linear-gradient(to right, #007bff, #00bfff);\n  transition: all 0.4s ease-in-out;\n  z-index: -1;\n  border-radius: 50px;\n}\n\n.button:hover::before {\n  left: 0;\n}\n', colors: '#007bff,#00bfff,#000,#fff', radii: '50px', shadows: '0 6px 10px rgba(0, 0, 0, 0.1),0 10px 20px rgba(0, 0, 0, 0.2)', techniques: '3d-transform,gradient,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'Deri-Kurniawan_moody-cat-79', cat: 'Buttons', author: 'Deri-Kurniawan', tags: 'blue,button,hover,smooth,hover effect,hoverme,hover button,button hover effect', html: '<button class="button">\n  <span class="button-content">Wavy Button</span>\n</button>', css: '\n/* From Uiverse.io by Deri-Kurniawan  - Tags: blue, button, hover, smooth, hover effect, hoverme, hover button, button hover effect  */\n.button {\n  position: relative;\n  display: inline-block;\n  padding: 16px 32px;\n  border-radius: 14px;\n  overflow: hidden;\n  z-index: 1;\n  border: 1px solid rgb(221, 218, 218);\n  background: white;\n  font-weight: bold;\n  font-size: 16px;\n  color: #1993e4;\n  transition: all 1.2s linear;\n  cursor: pointer;\n}\n\n.button::after {\n  content: "";\n  position: absolute;\n  background: linear-gradient(to right, #1993e4, #1993e456);\n  border-radius: 30%;\n  height: 96px;\n  width: 96px;\n  animation: spin infinite linear 1.8s;\n  animation-delay: 0;\n  bottom: -38px;\n  right: -112px;\n  transition: all 1.2s linear;\n  z-index: 0;\n}\n\n.button:hover {\n  color: #fff;\n  transition-duration: 1.2s;\n}\n\n.button:hover::after {\n  right: -60px;\n  bottom: -92px;\n  width: 256px;\n  height: 256px;\n}\n\n.button > .button-content {\n  position: relative;\n  z-index: 2;\n}\n\n@keyframes spin {\n  0% {\n    transform: rotate(0deg);\n  }\n  100% {\n    transform: rotate(360deg);\n  }\n}\n\n', colors: '#1993e4,#fff,#1993e456', radii: '14px,30%', shadows: '', techniques: '3d-transform,gradient,animation,pseudo-elements'),
const GalaxyComp(id: 'devkatyall_fuzzy-warthog-26', cat: 'Buttons', author: '', tags: '', html: '<label class="popup">\n  <input type="checkbox" />\n  <div tabindex="0" class="burger">\n    <svg\n      viewBox="0 0 24 24"\n      fill="white"\n      height="20"\n      width="20"\n      xmlns="http://www.w3.org/2000/svg"\n    >\n      <path\n        d="M12 2c2.757 0 5 2.243 5 5.001 0 2.756-2.243 5-5 5s-5-2.244-5-5c0-2.758 2.243-5.001 5-5.001zm0-2c-3.866 0-7 3.134-7 7.001 0 3.865 3.134 7 7 7s7-3.135 7-7c0-3.867-3.134-7.001-7-7.001zm6.369 13.353c-.497.498-1.057.931-1.658 1.302 2.872 1.874 4.378 5.083 4.972 7.346h-19.387c.572-2.29 2.058-5.503 4.973-7.358-.603-.374-1.162-.811-1.658-1.312-4.258 3.072-5.611 8.506-5.611 10.669h24c0-2.142-1.44-7.557-5.631-10.647z"\n      ></path>\n    </svg>\n  </div>\n  <nav class="popup-window">\n    <legend>Quick Start</legend>\n    <ul>\n      <li>\n        <button>\n          <svg\n            width="14"\n            height="14"\n            viewBox="0 0 24 24"\n            fill="none"\n            stroke="currentColor"\n            stroke-width="1.2"\n            stroke-linecap="round"\n            xmlns="http://www.w3.org/2000/svg"\n          >\n            <path\n              d="M19 4v6.406l-3.753 3.741-6.463-6.462 3.7-3.685h6.516zm2-2h-12.388l1.497 1.5-4.171 4.167 9.291 9.291 4.161-4.193 1.61 1.623v-12.388zm-5 4c.552 0 1 .449 1 1s-.448 1-1 1-1-.449-1-1 .448-1 1-1zm0-1c-1.104 0-2 .896-2 2s.896 2 2 2 2-.896 2-2-.896-2-2-2zm6.708.292l-.708.708v3.097l2-2.065-1.292-1.74zm-12.675 9.294l-1.414 1.414h-2.619v2h-2v2h-2v-2.17l5.636-5.626-1.417-1.407-6.219 6.203v5h6v-2h2v-2h2l1.7', css: '\n/* From Uiverse.io by devkatyall  - Website: https://uiverse.io/Galahhad/old-falcon-43 - Tags: login, button, sign-up, dropdown */\n/* The design is inspired from Galahhad*/\n\n.popup {\n  --burger-line-width: 1.125em;\n  --burger-line-height: 0.125em;\n  --burger-offset: 0.625em;\n  --burger-bg: #00bf63;\n  --burger-color: #333;\n  --burger-line-border-radiu