 var(--thickness) * 2);\n  left: var(--thickness);\n  top: var(--thickness);\n  width: calc(100% - var(--thickness) * 2);\n}\n\n.btn-25:hover:after,\n.btn-25:hover:before {\n  -webkit-clip-path: polygon(\n    0 50%,\n    var(--tilt) 0,\n    calc(100% - var(--tilt)) 0,\n    100', colors: '#000,#fff', radii: '', shadows: '', techniques: 'gradient,clip-path,css-mask,typography-transform'),
