-play-state: running;\n  opacity: 1;\n}\n\n.btn-11:active:before {\n  background-color: #fff;\n}\n\n@-webkit-keyframes bg-scroll {\n  0% {\n    transform: translateX(0);\n  }\n\n  to {\n    transform: translateX(33%);\n  }\n}\n\n@keyframes bg-scroll {\n  0% {\n    transform: translateX(0);\n  }\n\n', colors: '#000,#fff', radii: '99rem', shadows: '', techniques: 'gradient,animation,css-mask,typography-transform'),
const GalaxyComp(id: 'elijahgummer_proud-goat-69', cat: 'Buttons', author: 'elijahgummer', tags: 'icon,animation,3d,button,hover,modern,play,cyan', html: '<button class="button-with-icon">\n  <svg\n    class="icon"\n    id="Play"\n    viewBox="0 0 48 48"\n    xmlns="http://www.w3.org/2000/svg"\n  >\n    <path\n      class="color000000 svgShape"\n      fill="#ffffff"\n      d="M12 39c-.549 0-1.095-.15-1.578-.447A3.008 3.008 0 0 1 9 36V12c0-1.041.54-2.007 1.422-2.553a3.014 3.014 0 0 1 2.919-.132l24 12a3.003 3.003 0 0 1 0 5.37l-24 12c-.42.21-.885.315-1.341.315z"\n    ></path>\n  </svg>\n  <span class="text">Play</span>\n</button>', css: '\n/* From Uiverse.io by elijahgummer  - Tags: icon, animation, 3d, button, hover, modern, play, cyan */\n.button-with-icon {\n  overflow: hidden;\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  border: 1px solid #0f988e;\n  font-family: "Istok Web", sans-serif;\n  letter-spacing: 1px;\n  padding: 0 12px;\n  text-align: center;\n  width: 120px;\n  height: 40px;\n  font-size: 14px;\n  text-transform: uppercase;\n  font-weight: normal;\n  border-radius: 3px;\n  outline: none;\n  user-select: none;\n  cursor: pointer;\n  transform: translateY(0px);\n  position: relative;\n  box-shadow:\n    inset 0 30px 30px -15px rgba(255, 255, 255, 0.1),\n    inset 0 0 0 1px rgba(255, 255, 255, 0.3),\n    inset 0 1px 20px rgba(0, 0, 0, 0),\n    0 3px 0 #0f988e,\n    0 3px 2px rgba(0, 0, 0, 0.2),\n    0 5px 10px rgba(0, 0, 0, 0.1),\n    0 10px 20px rgba(0, 0, 0, 0.1);\n  background: #15ccbe;\n  color: white;\n  text-shadow: 0 1px 0 rgba(0, 0, 0, 0.3);\n  transition: 150ms all ease-in-out;\n}\n\n.button-with-icon .icon {\n  margin-right: 8px;\n  width: 24px;\n  height: 24px;\n  transition: all 0.5s ease-in-out;\n}\n\n.button-with-icon:active {\n  transform: translateY(3px);\n  box-shadow:\n    inset 0 16px 2px -15px rgba(0, 0, 0, 0),\n    inset 0 0 0 1px rgba(255, 255, 255, 0.15),\n    inset 0 1px 20px rgba(0, 0, 0, 0.1),\n    0 0 0 #0f988e,\n    0 0 0 2px rgba(255, 255, 255, 0.5),\n    0 0 0 rgba(0, 0, 0, 0),\n    0 0 0 rgba(0, 0, 0, 0);\n}\n\n.button-with-icon:hover .text {\n  transform: translateX(80px);\n}\n.button-with-icon:hover .icon {\n  transform: translate(23px);\n}\n\n.text {\n  transition: all 0.5s ease-in-out;\n}\n\n', colors: '#0f988e,#15ccbe', radii: '3px', shadows: 'inset 0 30px 30px -15px rgba(255, 255, 255, 0.1),\n    inset 0 0 0 1px rgba(255, 255, 255, 0.3),\n    inset 0 1px 20px rgb,inset 0 16px 2px -15px rgba(0, 0, 0, 0),\n    inset 0 0 0 1px rgba(255, 255, 255, 0.15),\n    inset 0 1px 20px rgba(0, 0, ', techniques: 'glow-shadow,text-shadow,typography-transform,svg-icon'),
const GalaxyComp(id: 'EmmaxPlay_rude-yak-98', cat: 'Buttons', author: 'EmmaxPlay', tags: 'button', html: '<button class="btn">Hover Me!</button>', css: '\n/* From Uiverse.io by EmmaxPlay - Tags: button */\n.btn {\n padding: 0.9em 1.6em;\n border: none;\n outline: none;\n color: #FFF;\n font-family: inherit;\n font-weight: 500;\n font-size: 17px;\n cursor: pointer;\n position: relative;\n z-index: 0;\n border-radius: 12px;\n}\n\n.btn::after {\n content: "";\n z-index: -1;\n position: absolute;\n width: 100%;\n height: 100%;\n background-color: rgb(46, 46, 46);\n left: 0;\n top: 0;\n border-radius: 10px;\n}\n/* glow */\n.btn::before {\n content: "";\n background: linear-gradient(\n    45deg,\n    #FF0000, #002BFF, #FF00C8, #002BFF,\n      #FF0000, #002BFF, #FF00C8, #002BFF\n);\n position: absolute;\n top: -2px;\n left: -2px;\n background-size: 600%;\n z-index: -1;\n width: calc(100% + 4px);\n height: calc(100% + 4px);\n filter: blur(8px);\n animation: glowing 20s linear infinite;\n transition: opacity .3s ease-in-out;\n border-radius: 10px;\n opacity: 0;\n}\n\n@keyframes glowing {\n 0% {\n  background-position: 0 0;\n }\n\n 50% {\n  background-position: 400% 0;\n }\n\n 100% {\n  background-position: 0 0;\n }\n}\n\n/* hover */\n.btn:hover::before {\n opacity: 1;\n}\n\n.btn:active:after {\n background: transparent;\n}\n\n.btn:active {\n color: #000;\n font-weight: bold;\n}\n', colors: '#ff0000,#000,#ff00c8,#002bff,#fff', radii: '10px,12px', shadows: '', techniques: 'glassmorphism,gradient,animation,pseudo-elements'),
const GalaxyComp(id: 'ercnersoy_nasty-panda-71', cat: 'Buttons', author: 'ercnersoy', tags: 'button,anime', html: '<button class="button">\n    <span class="text">HOVER ME</span>\n    <div class="wave"></div>\n</button>', css: '\n/* From Uiverse.io by ercnersoy - Tags: button, anime */\n.button {\n  width: 200px;\n  padding: 20px 40px;\n  position: relative;\n  display: block;\n  text-decoration: none;\n  overflow: hidden;\n  border: 0;\n  cursor: pointer;\n  border-radius: 2rem;\n  box-shadow: 0 0 5px 0px rgba(0, 0, 0, 0.5);\n}\n\n.button:hover .wave {\n  top: -120px;\n}\n\n.text {\n  position: relative;\n  z-index: 1;\n  color: white;\n  font-size: 15px;\n  letter-spacing: 3px;\n  font-weight: 600;\n}\n\n.wave {\n  width: 200px;\n  height: 200px;\n  background-color: #27a9ff;\n  box-shadow: inset 0 0 50px rgba(0, 0, 0, 0.5);\n  position: absolute;\n  left: 0;\n  top: -70px;\n  transition: 0.4s;\n}\n\n.wave::before, a .wave::after {\n  width: 200%;\n  height: 200%;\n  content: "";\n  position: absolute;\n  top: 0;\n  left: 50%;\n  transform: translate(-50%, -75%);\n}\n\n.wave::before {\n  border-radius: 45%;\n  background-color: #0581b3;\n  animation: wave 5s linear infinite;\n}\n\n.wave::after {\n  border-radius: 40%;\n  background-color: rgba(20, 20, 20, 0.5);\n  animation: wave 10s linear infinite;\n}\n\n@keyframes wave {\n  0% {\n    transform: translate(-50%, -75%) rotate(0deg);\n  }\n\n  100% {\n    transform: translate(-50%, -75%) rotate(300deg);\n  }\n}\n', colors: '#27a9ff,#0581b3', radii: '40%,45%,2rem', shadows: '0 0 5px 0px rgba(0, 0, 0, 0.5),inset 0 0 50px rgba(0, 0, 0, 0.5)', techniques: '3d-transform,glow-shadow,animation,pseudo-elements'),
const GalaxyComp(id: 'escannord_lovely-gecko-23', cat: 'Buttons', author: 'escannord', tags: 'icon,button,hover,text animation', html: '<div class="button">\n  <span class="text">hover me</span>\n  <span class="arrow"></span>\n</div>', css: '\n/* From Uiverse.io by escannord  - Tags: icon, button, hover, text animation */\n.button {\n  --color: rgb(56, 55, 100);\n  padding: 1rem 2rem;\n  background-color: transparent;\n  color: var(--color);\n  font-weight: bolder;\n  text-transform: uppercase;\n  display: flex;\n  justify-content: space-around;\n  align-items: center;\n  cursor: pointer;\n  position: relative;\n  border-radius: 5px;\n}\n\n.arrow {\n  display: inline-flex;\n  position: relative;\n  width: 30px;\n  height: 15px;\n  margin-left: 0.5rem;\n}\n\n.arrow::after,\n.arrow::before {\n  content: "";\n  display: inline-block;\n  position: absolute;\n  border-color: var(--color);\n}\n\n.arrow::after {\n  width: 10px;\n  height: 0;\n  border: 2px solid var(--color);\n  top: 50%;\n  left: 0;\n  transform: translateY(-50%);\n}\n\n.arrow::before {\n  width: 10px;\n  height: 10px;\n  border-top: 4px solid var(--color);\n  border-right: 4px solid var(--color);\n  left: 3px;\n  top: 50%;\n  transform: translateY(-50%) rotate(45deg);\n}\n\n.button:hover {\n  background-color: var(--color);\n  color: white;\n}\n\n.button:hover .arrow {\n  transform: translateX(10px);\n}\n\n.button:hover .text {\n  transform: translateX(10px);\n}\n\n.button:hover .arrow::after {\n  width: 25px;\n  border-color: white;\n}\n\n.button:hover .arrow::before {\n  left: 15px;\n  border-color: white;\n}\n\n.button,\n.text,\n.arrow,\n.arrow::after,\n.arrow::before,\n.button::before,\n.button::after {\n  transition: all 0.3s, box-shadow 0.2s;\n}\n\n.button::before {\n  content: "";\n  position: absolute;\n  height: 100%;\n  width: 10px;\n  border-radius: 5px;\n  border: solid 3px var(--color);\n  border-right-color: transparent;\n  background-color: transparent;\n  left: 0;\n  top: 50%;\n  transform: translateY(-50%);\n}\n\n.button::after {\n  content: "";\n  position: absolute;\n  height: 100%;\n  width: 10px;\n  border-radius: 5px;\n  border: solid 3px var(--color);\n  border-left-color: transparent;\n  background-color: transparent;\n  right: 0;\n  top: 50%;\n  transform: translateY(-50%);\n}\n\n.button:hover:before,\n.button:hover:after {\n  wi', colors: '', radii: '5px', shadows: '0px 0px 0px 7px rgba(79, 78, 105, 0.295)', techniques: '3d-transform,glow-shadow,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'Galahhad_kind-cheetah-52', cat: 'Buttons', author: 'Galahhad', tags: 'icon,button,copy,clipboard', html: '<button class="copy">\n  <span data-text-end="Copied!" data-text-initial="Copy to clipboard" class="tooltip"></span>\n  <span>\n    <svg xml:space="preserve" style="enable-background:new 0 0 512 512" viewBox="0 0 6.35 6.35" y="0" x="0" height="20" width="20" xmlns:xlink="http://www.w3.org/1999/xlink" version="1.1" xmlns="http://www.w3.org/2000/svg" class="clipboard">\n      <g>\n        <path fill="currentColor" d="M2.43.265c-.3 0-.548.236-.573.53h-.328a.74.74 0 0 0-.735.734v3.822a.74.74 0 0 0 .735.734H4.82a.74.74 0 0 0 .735-.734V1.529a.74.74 0 0 0-.735-.735h-.328a.58.58 0 0 0-.573-.53zm0 .529h1.49c.032 0 .049.017.049.049v.431c0 .032-.017.049-.049.049H2.43c-.032 0-.05-.017-.05-.049V.843c0-.032.018-.05.05-.05zm-.901.53h.328c.026.292.274.528.573.528h1.49a.58.58 0 0 0 .573-.529h.328a.2.2 0 0 1 .206.206v3.822a.2.2 0 0 1-.206.205H1.53a.2.2 0 0 1-.206-.205V1.529a.2.2 0 0 1 .206-.206z"></path>\n      </g>\n    </svg>\n    <svg xml:space="preserve" style="enable-background:new 0 0 512 512" viewBox="0 0 24 24" y="0" x="0" height="18" width="18" xmlns:xlink="http://www.w3.org/1999/xlink" version="1.1" xmlns="http://www.w3.org/2000/svg" class="checkmark">\n      <g>\n        <path data-original="#000000" fill="currentColor" d="M9.707 19.121a.997.997 0 0 1-1.414 0l-5.646-5.647a1.5 1.5 0 0 1 0-2.121l.707-.707a1.5 1.5 0 0 1 2.121 0L9 14.171l9.525-9.525a1.5 1.5 0 0 1 2.121 0l.707.707a1.5 1.5 0 0 1 0 2.121z"></path>\n      </g>\n    </svg>\n  </span>\n</button>', css: '\n/* From Uiverse.io by Galahhad - Tags: icon, button, copy, clipboard */\n/* tooltip settings 👇 */\n\n.copy {\n  /* button */\n  --button-bg: #353434;\n  --button-hover-bg: #464646;\n  --button-text-color: #CCCCCC;\n  --button-hover-text-color: #8bb9fe;\n  --button-border-radius: 10px;\n  --button-diameter: 36px;\n  --button-outline-width: 1px;\n  --button-outline-color: rgb(141, 141, 141);\n  /* tooltip */\n  --tooltip-bg: #f4f3f3;\n  --toolptip-border-radius: 4px;\n  --tooltip-font-family: Menlo, Roboto Mono, monospace;\n  /* 👆 this field should not be empty */\n  --tooltip-font-size: 12px;\n  /* 👆 this field should not be empty */\n  --tootip-text-color: rgb(50, 50, 50);\n  --tooltip-padding-x: 7px;\n  --tooltip-padding-y: 7px;\n  --tooltip-offset: 8px;\n  /* --tooltip-transition-duration: 0.3s; */\n  /* 👆 if you need a transition, \n  just remove the comment,\n  but I didn\'t like the transition :| */\n}\n\n.copy {\n  box-sizing: border-box;\n  width: var(--button-diameter);\n  height: var(--button-diameter);\n  border-radius: var(--button-border-radius);\n  background-color: var(--button-bg);\n  color: var(--button-text-color);\n  border: none;\n  cursor: pointer;\n  position: relative;\n  outline: none;\n}\n\n.tooltip {\n  position: absolute;\n  opacity: 0;\n  visibility: 0;\n  top: 0;\n  left: 50%;\n  transform: translateX(-50%);\n  white-space: nowrap;\n  font: var(--tooltip-font-size) var(--tooltip-font-family);\n  color: var(--tootip-text-color);\n  background: var(--tooltip-bg);\n  padding: var(--tooltip-padding-y) var(--tooltip-padding-x);\n  border-radius: var(--toolptip-border-radius);\n  pointer-events: none;\n  transition: all var(--tooltip-transition-duration) cubic-bezier(0.68, -0.55, 0.265, 1.55);\n}\n\n.tooltip::before {\n  content: attr(data-text-initial);\n}\n\n.tooltip::after {\n  content: "";\n  position: absolute;\n  bottom: calc(var(--tooltip-padding-y) / 2 * -1);\n  width: var(--tooltip-padding-y);\n  height: var(--tooltip-padding-y);\n  background: inherit;\n  left: 50%;\n  transform: translateX(-50%) rotate(4', colors: '#8bb9fe,#464646,#353434,#f4f3f3,#cccccc', radii: 'var(--button-border-radius),10px,4px,var(--toolptip-border-radius)', shadows: '', techniques: 'cubic-bezier,3d-transform,svg-icon,pseudo-elements'),
