mation: shake 0.2s linear 1;\n}\n\n.button:hover::before {\n  translate: 0 0;\n}\n\n.button:hover svg {\n  fill: #e8e8e8;\n}\n\n@keyframes shake {\n  0% {\n    rotate: 0deg;\n  }\n\n  33% {\n    rotate: 10deg;\n  }\n\n  66% {\n    rotate: -10deg;\n  }\n\n  100% {\n    rotate: 10deg;\n  }\n}\n\n', colors: '#212121,#f53844,#e8e8e8', radii: '50px', shadows: '', techniques: 'cubic-bezier,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'gharsh11032000_loud-chicken-53', cat: 'Buttons', author: 'gharsh11032000', tags: 'button,hover,active,animated,arrow,hover effect,click animation,pill', html: '<button class="animated-button">\n  <svg viewBox="0 0 24 24" class="arr-2" xmlns="http://www.w3.org/2000/svg">\n    <path\n      d="M16.1716 10.9999L10.8076 5.63589L12.2218 4.22168L20 11.9999L12.2218 19.778L10.8076 18.3638L16.1716 12.9999H4V10.9999H16.1716Z"\n    ></path>\n  </svg>\n  <span class="text">Modern Button</span>\n  <span class="circle"></span>\n  <svg viewBox="0 0 24 24" class="arr-1" xmlns="http://www.w3.org/2000/svg">\n    <path\n      d="M16.1716 10.9999L10.8076 5.63589L12.2218 4.22168L20 11.9999L12.2218 19.778L10.8076 18.3638L16.1716 12.9999H4V10.9999H16.1716Z"\n    ></path>\n  </svg>\n</button>', css: '\n/* From Uiverse.io by gharsh11032000  - Tags: button, hover, active, animated, arrow, hover effect, click animation, pill */\n.animated-button {\n  position: relative;\n  display: flex;\n  align-items: center;\n  gap: 4px;\n  padding: 16px 36px;\n  border: 4px solid;\n  border-color: transparent;\n  font-size: 16px;\n  background-color: inherit;\n  border-radius: 100px;\n  font-weight: 600;\n  color: greenyellow;\n  box-shadow: 0 0 0 2px greenyellow;\n  cursor: pointer;\n  overflow: hidden;\n  transition: all 0.6s cubic-bezier(0.23, 1, 0.32, 1);\n}\n\n.animated-button svg {\n  position: absolute;\n  width: 24px;\n  fill: greenyellow;\n  z-index: 9;\n  transition: all 0.8s cubic-bezier(0.23, 1, 0.32, 1);\n}\n\n.animated-button .arr-1 {\n  right: 16px;\n}\n\n.animated-button .arr-2 {\n  left: -25%;\n}\n\n.animated-button .circle {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  width: 20px;\n  height: 20px;\n  background-color: greenyellow;\n  border-radius: 50%;\n  opacity: 0;\n  transition: all 0.8s cubic-bezier(0.23, 1, 0.32, 1);\n}\n\n.animated-button .text {\n  position: relative;\n  z-index: 1;\n  transform: translateX(-12px);\n  transition: all 0.8s cubic-bezier(0.23, 1, 0.32, 1);\n}\n\n.animated-button:hover {\n  box-shadow: 0 0 0 12px transparent;\n  color: #212121;\n  border-radius: 12px;\n}\n\n.animated-button:hover .arr-1 {\n  right: -25%;\n}\n\n.animated-button:hover .arr-2 {\n  left: 16px;\n}\n\n.animated-button:hover .text {\n  transform: translateX(12px);\n}\n\n.animated-button:hover svg {\n  fill: #212121;\n}\n\n.animated-button:active {\n  scale: 0.95;\n  box-shadow: 0 0 0 4px greenyellow;\n}\n\n.animated-button:hover .circle {\n  width: 220px;\n  height: 220px;\n  opacity: 1;\n}\n\n', colors: '#212121', radii: '50%,100px,12px', shadows: '0 0 0 2px greenyellow,0 0 0 12px transparent,0 0 0 4px greenyellow', techniques: 'cubic-bezier,3d-transform,glow-shadow,svg-icon'),
const GalaxyComp(id: 'gharsh11032000_massive-gecko-17', cat: 'Buttons', author: 'gharsh11032000', tags: 'button,hover effect', html: '<button class="animated-button">\n  <span>Hover me</span>\n</button>', css: '\n/* From Uiverse.io by gharsh11032000 - Tags: button, hover effect */\n.animated-button {\n  position: relative;\n  display: inline-block;\n  padding: 16px 32px;\n  border: none;\n  background-color: #2196F3;\n  color: #fff;\n  font-size: 16px;\n  text-transform: uppercase;\n  font-weight: 600;\n  cursor: pointer;\n  border-radius: 8px;\n  overflow: hidden;\n  transition: all 0.8s cubic-bezier(0.23, 1, 0.320, 1);\n}\n\n.animated-button:before {\n  content: "";\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  width: 120%;\n  height: 120%;\n  background-color: #fff;\n  opacity: 0;\n  transition: all 0.8s cubic-bezier(0.23, 1, 0.320, 1);\n}\n\n.animated-button span {\n  position: relative;\n  z-index: 1;\n}\n\n.animated-button:hover {\n  color: #2196F3;\n  background-color: #fff;\n  box-shadow: 0 0 20px hsla(263, 77%, 31%, 0);\n}\n\n.animated-button:active {\n  scale: 0.9;\n}\n\n.animated-button:hover:before {\n  transform: translate(-50%, -50%) rotate(45deg);\n  opacity: 1;\n}\n\n\n\n\n\n', colors: '#fff,#2196f3', radii: '8px', shadows: '0 0 20px hsla(263, 77%, 31%, 0)', techniques: 'cubic-bezier,3d-transform,glow-shadow,typography-transform'),
const GalaxyComp(id: 'gharsh11032000_neat-treefrog-57', cat: 'Buttons', author: 'gharsh11032000', tags: 'gradient,button,hover effect', html: '<button class="button">\n  <span>Contact</span>\n</button>', css: '\n/* From Uiverse.io by gharsh11032000 - Tags: gradient, button, hover effect */\n.button {\n  position: relative;\n  text-decoration: none;\n  color: #e8e8e8;\n  padding: 15px 30px;\n  width: 170px;\n  height: 60px;\n  font-weight: 600;\n  font-size: 18px;\n  cursor: pointer;\n  border: none;\n  overflow: hidden;\n  background: linear-gradient(-45deg, #f89b29 0%, #ff0f7b 100% );\n  transition: all 0.3s cubic-bezier(0.215, 0.610, 0.355, 1);\n}\n\n.button span , .button span::before {\n  position: absolute;\n  top: 0%;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  display: flex;\n  align-items: center;\n  pointer-events: none;\n  justify-content: center;\n  transition: all 0.3s cubic-bezier(0.215, 0.610, 0.355, 1);\n}\n\n.button span::before {\n  content: \'Hello!\';\n  top: -100%;\n}\n\n.button:before {\n  top: 0;\n  left: 0;\n  border-top: 2px solid #e8e8e8;\n  border-left: 2px solid #e8e8e8;\n}\n\n.button:after {\n  bottom: 0;\n  right: 0;\n  border-bottom: 2px solid #e8e8e8;\n  border-right: 2px solid #e8e8e8;\n}\n\n.button:after,\n.button:before {\n  content: "";\n  position: absolute;\n  width: 24px;\n  height: 24px;\n  pointer-events: none;\n  transition: all 0.3s cubic-bezier(0.215, 0.610, 0.355, 1);\n}\n\n.button:hover {\n  box-shadow: 0 0 30px rgba(248 ,155, 41,0.4),\n  0 0 30px rgba(255, 15, 123,0.4);\n  ;\n}\n\n.button:hover:before,\n.button:hover:after {\n  width: 100%;\n  height: 100%;\n}\n\n.button:hover span {\n  top: 100%;\n}\n\n.button:active {\n  scale: 0.95;\n  box-shadow: 0 0 10px rgba(248 ,155, 41,0.4),\n  0 0 10px rgba(255, 15, 123,0.4);\n  ;\n}\n\n\n', colors: '#ff0f7b,#f89b29,#e8e8e8', radii: '', shadows: '0 0 30px rgba(248 ,155, 41,0.4),\n  0 0 30px rgba(255, 15, 123,0.4),0 0 10px rgba(248 ,155, 41,0.4),\n  0 0 10px rgba(255, 15, 123,0.4)', techniques: 'cubic-bezier,glow-shadow,gradient,pseudo-elements'),
const GalaxyComp(id: 'Github-Suriya_chilly-wasp-20', cat: 'Buttons', author: 'Github-Suriya', tags: 'material design,white,button,smooth,message', html: '<button>\n  <div class="svg-name-con">\n    <div class="svg-wrapper-1">\n      <div class="svg-wrapper">\n        <svg\n          height="24"\n          width="24"\n          viewBox="0 0 24 24"\n          xmlns="http://www.w3.org/2000/svg"\n        >\n          <path d="M0 0h24v24H0z" fill="none"></path>\n          <path\n            d="M1.946 9.315c-.522-.174-.527-.455.01-.634l19.087-6.362c.529-.176.832.12.684.638l-5.454 19.086c-.15.529-.455.547-.679.045L12 14l6-8-8 6-8.054-2.685z"\n            fill="currentColor"\n          ></path>\n        </svg>\n      </div>\n    </div>\n    <span>Send Message</span>\n  </div>\n</button>', css: '\n/* From Uiverse.io by Github-Suriya  - Tags: material design, white, button, smooth, message */\nbutton {\n  font-family: inherit;\n  font-size: 20px;\n  background: #eef0ee;\n  padding: 0.3em;\n  border: none;\n  border-radius: 15px;\n  overflow: hidden;\n  transition: all 0.2s;\n  cursor: pointer;\n  box-shadow: 0px 0px 6px #c5c5c5;\n}\n\nbutton span {\n  display: block;\n  margin-left: 0.3em;\n  font-weight: 600;\n  transition: all 0.3s ease-in-out;\n}\n\nbutton svg {\n  display: block;\n  transform-origin: center center;\n  transition: transform 0.3s ease-in-out;\n}\n\nbutton .svg-name-con {\n  background: #fcfdfc;\n  border-radius: 25px;\n  display: flex;\n  align-items: center;\n  padding: 0.7em 1em;\n}\n\nbutton:hover .svg-wrapper {\n  animation: fly-1 0.6s ease-in-out infinite alternate;\n}\n\nbutton:hover svg {\n  transform: translateX(4.2em) rotate(45deg) scale(1.1);\n}\n\nbutton:hover span {\n  transform: translateX(9em);\n}\n\nbutton:active {\n  transform: scale(0.95);\n}\n\n@keyframes fly-1 {\n  from {\n    transform: translateY(0.1em);\n  }\n\n  to {\n    transform: translateY(-0.1em);\n  }\n}\n\n', colors: '#c5c5c5,#fcfdfc,#eef0ee', radii: '15px,25px', shadows: '0px 0px 6px #c5c5c5', techniques: '3d-transform,glow-shadow,animation,svg-icon'),
const GalaxyComp(id: 'guilhermeyohan_pretty-liger-37', cat: 'Buttons', author: 'guilhermeyohan', tags: 'button', html: '<button class="container moon-container">\n  <div class="moon">\n    <div class="mancha2"></div>\n    </div>\n		 <div class="moon-text">To the Moon</div>\n</button>', css: '\n/* From Uiverse.io by guilhermeyohan - Tags: button */\n.moon-container {\n  width: 170px;\n  height: 50px;\n  background: linear-gradient(0, #120c56, #000000);\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 7px;\n  border-radius: 20px;\n  border-color: transparent;\n}\n\n.moon-container:hover {\n  transform: scale(1.2);\n  border-radius: 62px;\n  box-shadow: 1px 0px 100px #ece1bd60;\n  transition: all 1.4s;\n}\n\n.moon-text {\n  position: relative;\n  font-size: 15px;\n  font-weight: bold;\n  color: #fff;\n}\n\n.moon {\n  position: relative;\n  border-color: transparent;\n  width: 75px;\n  height: 75px;\n  border-radius: 50%;\n  background-color: #F0EAD6;\n  box-shadow: 0px 0px 10px #F0EAD6;\n}\n\n.moon::before {\n  content: "";\n  display: block;\n  position: absolute;\n  top: 22%;\n  left: 45%;\n  transform: translateX(-50%);\n  width: 12px;\n  height: 12px;\n  border-radius: 50%;\n  background-color: #333;\n  opacity: 0.4;\n}\n\n.moon::after {\n  content: "";\n  position: absolute;\n  top: 67%;\n  left: 30%;\n  transform: translateX(-50%);\n  width: 10px;\n  height: 10px;\n  border-radius: 50%;\n  background-color: #333;\n  opacity: 0.3;\n}\n\n.mancha2 {\n  content: "";\n  width: 10px;\n  height: 10px;\n  background-color: rgba(51, 51, 51, 0.583);\n  border-radius: 50%;\n  position: absolute;\n  top: 47%;\n  left: 75%;\n  transform: translate(-50%, -50%);\n}\n\n.moon:hover {\n  box-shadow: 0px 0px 100px #F0EAD6;\n  transition: all 1.4s;\n}\n\n.moon:active {\n  transform: scale(1.5);\n  transition: all 1.4s;\n}\n\n', colors: '#120c56,#f0ead6,#ece1bd60,#000000,#333,#fff', radii: '50%,62px,20px', shadows: '1px 0px 100px #ece1bd60,0px 0px 10px #F0EAD6,0px 0px 100px #F0EAD6', techniques: '3d-transform,glow-shadow,gradient,pseudo-elements'),
const GalaxyComp(id: 'Gumpack_jolly-zebra-42', cat: 'Buttons', author: 'Gumpack', tags: 'button', html: '<button class="btn"> Button\n</button>', css: '\n/* From Uiverse.io by Gumpack - Tags: button */\n.btn {\n background-image: linear-gradient(45deg, #FF512F 0%, #F09819  51%, #FF512F  100%)\n}\n\n.btn {\n margin: 10px;\n padding: 15px 30px;\n text-align: center;\n text-transform: uppercase;\n transition: 0.5s;\n background-size: 200% auto;\n color: white;\n border-radius: 10px;\n display: block;\n border: 0px;\n font-weight: 700;\n box-shadow: 0px 0px 14px -7px #f09819;\n}\n\n.btn:hover {\n background-position: right center;\n /* change the direction of the change here */\n color: #fff;\n text-decoration: none;\n}\n\n.btn:active {\n transform: scale(0.95);\n}\n', colors: '#ff512f,#fff,#f09819', radii: '10px', shadows: '0px 0px 14px -7px #f09819', techniques: '3d-transform,glow-shadow,gradient,typography-transform'),
const GalaxyComp(id: 'HauNTH_dull-donkey-56', cat: 'Buttons', author: '', tags: '', html: '<ul class="social">\n  <li class="social-item">\n    <a class="social-link" href="/">\n      <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">\n        <path d="M9.19795 21.5H13.198V13.4901H16.8021L17.198 9.50977H13.198V7.5C13.198 6.94772 13.6457 6.5 14.198 6.5H17.198V2.5H14.198C11.4365 2.5 9.19795 4.73858 9.19795 7.5V9.50977H7.19795L6.80206 13.4901H9.19795V21.5Z" fill="currentColor"></path>\n      </svg>\n    </a>\n  </li>\n  <li class="social-item">\n    <a class="social-link" href="/">\n      <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">\n        <path fill-rule="evenodd" clip-rule="evenodd" d="M8 3C9.10457 3 10 3.89543 10 5V8H16C17.1046 8 18 8.89543 18 10C18 11.1046 17.1046 12 16 12H10V14C10 15.6569 11.3431 17 13 17H16C17.1046 17 18 17.8954 18 19C18 20.1046 17.1046 21 16 21H13C9.13401 21 6 17.866 6 14V5C6 3.89543 6.89543 3 8 3Z" fill="currentColor"></path>\n      </svg>\n    </a>\n  </li>\n  <li class="social-item">\n    <a class="social-link" href="/">\n      <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">\n        <path d="M6 12C6 15.3137 8.68629 18 12 18C14.6124 18 16.8349 16.3304 17.6586 14H12V10H21.8047V14H21.8C20.8734 18.5645 16.8379 22 12 22C6.47715 22 2 17.5228 2 12C2 6.47715 6.47715 2 12 2C15.445 2 18.4831 3.742 20.2815 6.39318L17.0039 8.68815C15.9296 7.06812 14.0895 6 12 6C8.68629 6 6 8.68629 6 12Z" fill="currentColor"></path>\n      </svg', css: '\n/* From Uiverse.io by HauNTH - Source: https://www.youtube.com/@OnlineTutorialsYT - Tags: social, social media, social lincks */\n.social {\n  margin: 0;\n  list-style: none;\n  padding-left: 0;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  height: 100%;\n}\n\n.social .social-item {\n  margin: 0 30px;\n  width: 40px;\n  height: 40px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n.social .social-item .social-link {\n  position: relative;\n  width: 100%;\n  height: 100%;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  background: #fff;\n  text-align: center;\n  transform: perspective(1000px) rotate(-30deg) skew(25deg)\n    translate(0, 0);\n  transition: all 0.4s ease;\n}\n\n.social .social-item .social-link::before {\n  content: "";\n  position: absolute;\n  top: 5px;\n  left: -10px;\n  height: 100%;\n  width: 10px;\n  background: #b1b1b1;\n  transition: all 0.4s ease;\n  transform: rotate(0deg) skewY(-45deg);\n}\n\n.social .social-item .social-link::after {\n  content: "";\n  position: absolute;\n  top: 40px;\n  left: -5px;\n  height: 10px;\n  width: 100%;\n  background: #b1b1b1;\n  transition: all 0.4s ease;\n  transform: rotate(0deg) skewX(-45deg);\n}\n\n.social .social-item .social-link:hover {\n  transform: perspective(1000px) rotate(-30deg) skew(25deg) translate(5px, -5px);\n  box-shadow: -20px 20px 10px rgba(0, 0, 0, 0.5);\n}\n\n.social .social-item:nth-child(1) a {\n  color: #3b5999;\n}\n\n.social .social-item:nth-child(1):hover a {\n  background: #3b5999;\n}\n\n.social .social-item:nth-child(1):hover a::before {\n  background: #3b5999;\n}\n\n.social .social-item:nth-child(1):hover a::after {\n  background: #3b5999;\n}\n\n.social .social-item:nth-child(2) a {\n  color: #55acee;\n}\n\n.social .social-item:nth-child(2):hover a {\n  background: #55acee;\n}\n\n.social .social-item:nth-child(2):hover a::before {\n  background: #55acee;\n}\n\n.social .social-item:nth-child(2):hover a::after {\n  background: #55acee;\n}\n\n.social .social-item:nth-child(3) a {\n  color: #dd4b39;', colors: '#b1b1b1,#e4405f,#dd4b39,#55acee,#3b5999,#ffffff,#fff', radii: '', shadows: '-20px 20px 10px rgba(0, 0, 0, 0.5)', techniques: '3d-transform,perspective,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'hnguyentrung20_slimy-dingo-46', cat: 'Buttons', author: 'hnguyentrung20', tags: 'button', html: '<button>\n  <div class="progress">\n     <div class="progress-bar"> </div>\n  </div>\n  \n  <p class="before-scan">Find aliens</p>\n  <p class="scaning">Scanning</p>\n  <p class="complete">No aliens found</p>\n</button>', css: '\n/* From Uiverse.io by hnguyentrung20 - Tags: button */\n@keyframes MoveBackground {\n  0% {\n    background-position-x: 0;\n  }\n\n  100% {\n    background-position-x: -165px;\n  }\n}\n\n@keyframes Scaning {\n  0% {\n    width: 0%;\n  }\n\n  30% {\n    width: 10%;\n  }\n\n  70% {\n    width: 40%;\n  }\n\n  100% {\n    width: 100%;\n  }\n}\n\nbutton {\n  background: none;\n  font-size: 20px;\n  font-weight: 700;\n  color: black;\n  text-transform: uppercase;\n  padding: 10px 30px;\n  position: relative;\n  background-color: white;\n  border-radius: 10px;\n  overflow: hidden;\n  transition-duration: 300ms;\n  border: none;\n  max-width: 1370px;\n  width: fit-content;\n}\n\nbutton:hover {\n  color: white;\n  border: 4px black solid;\n  max-width: 170px;\n  padding: 5px 30px;\n}\n\nbutton:active {\n  background: none;\n  color: white;\n  border: 4px #1F8A70 solid;\n  background-color: #1F8A70;\n  max-width: 170px;\n}\n\nbutton .progress {\n  display: none;\n}\n\nbutton:active .progress .progress-bar {\n  display: none;\n}\n\nbutton:hover .progress {\n /* background-image: repeating-linear-gradient(-28deg, transparent, transparent 31px, #DC0000 19px, #DC000010 70px); */\n  display: block;\n  user-select: none;\n  width: 100%;\n  height: 100%;\n  position: absolute;\n  top: 0;\n  left: 0;\n  pointer-events: none;\n  transition-duration: 600ms;\n  overflow: hidden;\n  animation: Scaning 3s linear;\n}\n\n.progress .progress-bar {\n  width: 165px;\n  height: 100%;\n  background-image: repeating-linear-gradient(-25deg, transparent, transparent 31px, #000000 19px, #000000ee 70px);\n  animation: MoveBackground 2s linear infinite reverse;\n}\n\nbutton::before {\n  /* content: "<d"; */\n  background-color: white;\n  height: 100%;\n  width: 100%;\n}\n\nbutton:hover .before-scan,\n .complete, .scaning {\n  display: none;\n}\n\nbutton:hover .scaning {\n  display: block;\n  mix-blend-mode: difference;\n  padding: 0px 0px;\n}\n\nbutton:active .scaning {\n  display: none;\n}\n\nbutton:active .complete {\n  display: block;\n}\n', colors: '#dc0000,#000000,#dc000010,#1f8a70,#000000ee', radii: '10px', shadows: '', techniques: 'gradient,animation,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'htwarriors108_lazy-owl-9', cat: 'Buttons', author: 'htwarriors108', tags: 'gradient,button,animated,colorful,hover effect,click effect,click animation,box-shadow,multicolor', html: '<button class="button">\n  <div class="display">\n    <div id="msg">Click Me</div>\n  </div>\n  \n  <span></span>\n  <span></span>\n</button>', css: '\n/* From Uiverse.io by htwarriors108 - Tags: gradient, button, animated, colorful, hover effect, click effect, click animation, box-shadow, multicolor */\n.button {\n  height: 50px;\n  width: 180px;\n  background: linear-gradient(135deg, #14ffe9, #ffeb3b, #ff00e0);\n  border-radius: 25px;\n  animation: animate 1.5s linear infinite;\n  border: none;\n  cursor: pointer;\n}\n\n.button, .display, #msg {\n  transition: 0.3s;\n}\n\n.button:active .display {\n  background: rgba(255, 255, 255, 0.5);\n}\n\n.button:active .display #msg {\n  -webkit-text-fill-color: #1b1b1b;\n}\n\n.button:hover {\n  scale: 1.15;\n  animation: animate 0.7s linear infinite;\n  transform: translateY(-15px);\n}\n\n.button .display, .button span {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n}\n\n.button .display {\n  z-index: 1;\n  background-color: #1b1b1b;\n  height: 42.5px;\n  width: 172.5px;\n  border-radius: 20px;\n  text-align: center;\n}\n\n.button .display #msg {\n  line-height: 42.5px;\n  font-size: 25px;\n  font-weight: 800;\n  letter-spacing: 3px;\n  background: linear-gradient(135deg, #14ffe9, #ffeb3b, #ff00e0);\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n}\n\n@keyframes animate {\n  100% {\n    filter: hue-rotate(360deg);\n  }\n}\n\n.button span {\n  height: 100%;\n  width: 100%;\n  background: inherit;\n  border-radius: 25px;\n}\n\n.button span:first-child {\n  filter: blur(15px);\n}\n\n.button span:last-child {\n  filter: blur(15px);\n  transition: 0.3s;\n}\n\n.button:hover span:last-child {\n  width: 110%;\n  height: 120%;\n}\n', colors: '#14ffe9,#ffeb3b,#1b1b1b,#ff00e0', radii: '25px,20px', shadows: '', techniques: 'glassmorphism,3d-transform,gradient,animation'),
const GalaxyComp(id: 'JaydipPrajapati1910_lazy-mouse-44', cat: 'Buttons', author: 'JaydipPrajapati1910', tags: 'gradient,button,gradients,css', html: '<button class="button">\n  <div class="button-overlay"></div>\n  <span>Gradient Button</span>  \n</button>', css: '\n/* From Uiverse.io by JaydipPrajapati1910 - Tags: gradient, button, gradients, css */\n.button {\n  font-size: 19px;\n  border-radius: 12px;\n  background: linear-gradient(180deg, rgb(56, 56, 56) 0%, rgb(36, 36, 36) 66%, rgb(41, 41, 41) 100%);\n  color: rgb(218, 218, 218);\n  border: none;\n  padding: 2px;\n  font-weight: 800;\n  cursor: pointer;\n  position: relative;\n  overflow: hidden;\n}\n\n.button span {\n  border-radius: 10px;\n  padding: 0.8em 1.3em;\n  padding-right: 1.2em;\n  text-shadow: 0px 0px 20px #4b4b4b;\n  width: 100%;\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  transition: all 0.3s;\n  background-image: linear-gradient(to right, #00F260, #f79dee, #0575E6, #64f38c,#e9e93e);\n  -webkit-background-clip: text;\n  color: transparent;\n  background-size: 300%;\n  background-position: -100%;\n  animation: animatedText 3s infinite alternate-reverse;\n}\n\n.button-overlay {\n  position: absolute;\n  inset: 0;\n  pointer-events: none;\n  background: repeating-conic-gradient(rgb(48, 47, 47) 0.0000001%, rgb(51, 51, 51) 0.000104%) 60% 60%/600% 600%;\n  filter: opacity(10%) contrast(105%);\n  -webkit-filter: opacity(10%) contrast(105%);\n}\n\n@keyframes animatedText {\n  to {\n    background-position: 100%;\n  }\n}\n', colors: '#4b4b4b,#f79dee,#0575e6,#64f38c,#e9e93e,#00f260', radii: '10px,12px', shadows: '', techniques: 'text-shadow,gradient,animation,filter-effect'),
const GalaxyComp(id: 'kevkevkevin_tall-horse-10', cat: 'Buttons', author: 'kevkevkevin', tags: 'button,creative', html: '<button class="button">\n  Hover me 🥹\n</button>', css: '\n/* From Uiverse.io by kevkevkevin - Tags: button, creative */\n.button {\n  font-size: 16px;\n  font-weight: 700;\n  color: #292930;\n  background: #ffdc60;\n  height: 60px;\n  line-height: 60px;\n  text-align: center;\n  padding: 0 50px;\n  position: relative;\n  z-index: 1;\n  overflow: hidden;\n  border-radius: 10px;\n  text-transform: capitalize;\n  cursor: pointer;\n  border: none;\n  box-shadow: 0px 0px 77px 12px rgba(0,0,0,0.13);\n  -webkit-box-shadow: 0px 0px 77px 12px rgba(0,0,0,0.13);\n  -moz-box-shadow: 0px 0px 77px 12px rgba(0,0,0,0.13);\n}\n\nbutton:before, button:after {\n  content: "";\n  background: #5956e9;\n  height: 50%;\n  width: 0;\n  position: absolute;\n  transition: .3s cubic-bezier(.785,.135,.15,.86);\n  -webkit-transition: .3s cubic-bezier(.785,.135,.15,.86);\n  z-index: -1;\n}\n\nbutton::before {\n  top: 0;\n  left: 0;\n  right: auto;\n}\n\nbutton:after {\n  bottom: 0;\n  right: 0;\n  left: auto;\n}\n\nbutton:hover {\n  color: #fff;\n  background-color: #57c9da;\n}\n\nbutton:hover:before {\n  width: 100%;\n  right: 0;\n  left: auto;\n}\n\nbutton:hover::after {\n  width: 100%;\n  left: 0;\n  right: auto;\n}\n\n', colors: '#292930,#5956e9,#57c9da,#fff,#ffdc60', radii: '10px', shadows: '0px 0px 77px 12px rgba(0,0,0,0.13),0px 0px 77px 12px rgba(0,0,0,0.13),0px 0px 77px 12px rgba(0,0,0,0.13)', techniques: 'cubic-bezier,glow-shadow,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'KINGFRESS_young-dragon-73', cat: 'Buttons', author: 'KINGFRESS', tags: 'button,progress bar', html: '<button>\n  <span class="txt">submit</span>\n  <span class="txt2">sent!</span>\n  <span class="loader-container">\n    <span class="loader"></span>\n  </span>\n</button>', css: '\n/* From Uiverse.io by KINGFRESS - Tags: button, progress bar */\nbutton {\n  background-color: transparent;\n  width: 13em;\n  height: 3.3em;\n  border: 2px solid #1abc9c;\n  border-radius: 25px;\n  font-weight: bold;\n  text-transform: uppercase;\n  color: #1abc9c;\n  padding: 2px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  position: relative;\n  overflow: hidden;\n  cursor: pointer;\n}\n\nbutton .txt {\n  transition: .4s ease-in-out;\n  position: absolute;\n}\n\nbutton .txt2 {\n  transform: translateY(1em) scale(0);\n  color: #212121;\n  position: absolute;\n}\n\nbutton .loader-container {\n  height: 100%;\n  width: 100%;\n  background-color: transparent;\n  border-radius: inherit;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  z-index: -1;\n  overflow: hidden;\n}\n\nbutton .loader-container .loader {\n  height: 100%;\n  width: 100%;\n  background-color: #1abc9c;\n  border-radius: inherit;\n  transform: translateX(-13em);\n}\n\nbutton:focus {\n  transition: .4s ease-in-out .4s;\n  animation: scaling 1.5s ease-in-out 0s 1 both;\n}\n\nbutton:focus .txt {\n  position: absolute;\n  transform: translateY(-5em);\n  transition: .4s ease-in-out;\n}\n\nbutton:focus .txt2 {\n  transform: translateY(0) scale(1);\n  transition: .3s ease-in-out 1.7s;\n}\n\nbutton:focus .loader {\n  display: block;\n  transform: translate(0);\n  transition: .8s cubic-bezier(0,.4,1,.28) .4s;\n  animation: loading;\n}\n\n@keyframes scaling {\n  20% {\n    height: 1.5em;\n  }\n\n  80% {\n    height: 1.5em;\n  }\n\n  100% {\n    height: 3.3em;\n  }\n}\n', colors: '#212121,#1abc9c', radii: 'inherit,25px', shadows: '', techniques: 'cubic-bezier,3d-transform,animation,typography-transform'),
const GalaxyComp(id: 'KingHendrie_heavy-wombat-40', cat: 'Buttons', author: 'KingHendrie', tags: 'simple,icon,animation,action,button,rounded,social media,button hover effect', html: '<input type="checkbox" id="send-checkbox" class="send-checkbox" />\n<label for="send-checkbox" class="send-button">\n  <svg\n    class="svg-style"\n    xmlns="http://www.w3.org/2000/svg"\n    fill="none"\n    viewBox="0 0 24 24"\n    height="20px"\n    width="20px"\n  >\n    <path\n      stroke-linejoin="round"\n      stroke-linecap="round"\n      stroke-width="1.5"\n      stroke="#292D32"\n      d="M7.39999 6.32003L15.89 3.49003C19.7 2.22003 21.77 4.30003 20.51 8.11003L17.68 16.6C15.78 22.31 12.66 22.31 10.76 16.6L9.91999 14.08L7.39999 13.24C1.68999 11.34 1.68999 8.23003 7.39999 6.32003Z"\n    ></path>\n    <path\n      stroke-linejoin="round"\n      stroke-linecap="round"\n      stroke-width="1.5"\n      stroke="#292D32"\n      d="M10.11 13.6501L13.69 10.0601"\n    ></path>\n  </svg>\n  <span class="message">Send Message</span>\n  <span class="message-sent">Message Sent</span>\n</label>', css: '\n/* From Uiverse.io by KingHendrie  - Tags: simple, icon, animation, action, button, rounded, social media, button hover effect  */\n.send-checkbox {\n  display: none;\n}\n\n.send-button {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  padding: 10px 20px;\n  border: 2px solid #ddd;\n  border-radius: 15px;\n  background-color: #f9f9f9;\n  color: #2c2c2c;\n  font-family: Arial, sans-serif;\n  font-size: 16px;\n  font-weight: 500;\n  cursor: pointer;\n  box-shadow: inset 2px 2px 5px rgba(0, 0, 0, 0.1),\n    2px 2px 5px rgba(0, 0, 0, 0.1);\n  transition: background-color 0.3s, box-shadow 0.3s, transform 0.3s;\n  position: relative;\n  overflow: hidden;\n  white-space: nowrap;\n}\n\n.send-checkbox:checked + .send-button .message {\n  opacity: 0;\n}\n\n.send-checkbox:checked + .send-button .message-sent {\n  animation: fadeIn 3s forwards;\n}\n\n.send-checkbox:checked + .send-button svg {\n  animation: send 1s forwards;\n}\n\n@keyframes rotate-hover {\n  0% {\n    transform: rotate(0);\n  }\n  100% {\n    transform: rotate(40deg);\n  }\n}\n\n@keyframes send {\n  0% {\n    transform: translateX(0) rotate(40deg);\n  }\n  100% {\n    transform: translateX(150px) rotate(40deg);\n  }\n}\n\n@keyframes fadeIn {\n  0% {\n    opacity: 0;\n  }\n  100% {\n    opacity: 1;\n  }\n}\n\n.send-button .message-sent {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  opacity: 0;\n  color: #125b96;\n}\n\n.send-button:hover {\n  background-color: #e0e0e0;\n  box-shadow: inset -2px -2px 5px rgba(0, 0, 0, 0.1),\n    3px 3px 7px rgba(0, 0, 0, 0.15);\n  transform: translateY(-2px);\n}\n\n.send-button:hover svg {\n  animation: rotate-hover 0.2s;\n  transform: rotate(40deg);\n}\n\n', colors: '#f9f9f9,#e0e0e0,#2c2c2c,#125b96,#ddd', radii: '15px', shadows: 'inset 2px 2px 5px rgba(0, 0, 0, 0.1),\n    2px 2px 5px rgba(0, 0, 0, 0.1),inset -2px -2px 5px rgba(0, 0, 0, 0.1),\n    3px 3px 7px rgba(0, 0, 0, 0.15)', techniques: '3d-transform,animation,checkbox-input,svg-icon'),
const GalaxyComp(id: 'Lucaasbre_happy-elephant-36', cat: 'Buttons', author: 'Lucaasbre', tags: 'button,animated,gradients,svg,css effect,multicolor,button hover effect,2d button', html: '<div class="container">\n  <span class="span-text">\n    <svg\n      height="20pt"\n      width="20pt"\n      viewBox="0 0 20 20"\n      style="isolation:isolate"\n      xmlns:xlink="http://www.w3.org/1999/xlink"\n      xmlns="http://www.w3.org/2000/svg"\n    >\n      <defs>\n        <clipPath id="_clipPath_bC9TwUVn0M3ipVC8aHmmX7RNkfzJwdgL">\n          <rect height="20" width="20"></rect>\n        </clipPath>\n      </defs>\n      <g clip-path="url(#_clipPath_bC9TwUVn0M3ipVC8aHmmX7RNkfzJwdgL)">\n        <rect\n          fill-opacity="0"\n          style="fill:rgb(1,0,1)"\n          height="20"\n          width="20"\n        ></rect>\n        <path\n          stroke-miterlimit="3"\n          stroke-linecap="round"\n          stroke-linejoin="round"\n          stroke="rgb(0,0,0)"\n          stroke-width="1"\n          fill="rgb(0,0,0)"\n          d="M 10 1 L 10 9 L 15 9 L 10 19 L 10 12 L 5 12 L 10 1 Z"\n        ></path>\n      </g>\n    </svg>\n    Join now\n  </span>\n  <button class="button">\n    <span class="span-outside"> </span>\n    <div class="circles">\n      <span class="circle"> </span>\n      <span class="circle"> </span>\n      <span class="circle"> </span>\n      <span class="circle"> </span>\n      <span class="circle"> </span>\n      <span class="circle"> </span>\n      <span class="circle"> </span>\n      <span class="circle"> </span>\n      <span class="circle"> </span>\n      <span class="circle"> </span>\n      <span class="circle"> </span>\n      <span class="circle"> </span>\n      <span class="circle"> <', css: '\n/* From Uiverse.io by Lucaasbre  - Tags: button, animated, gradients, svg, css effect, multicolor, button hover effect , 2d button */\n.container {\n  position: relative;\n  width: 300px;\n  height: 100px;\n  border-radius: 30px;\n  overflow: hidden;\n  cursor: pointer;\n}\n\n.button {\n  border: none;\n  width: 200%;\n  height: 100%;\n  background: linear-gradient(\n      75deg,\n      rgb(170, 55, 200) 10%,\n      rgb(235, 100, 130) 20%,\n      rgb(245, 95, 90) 40%,\n      rgb(245, 110, 30) 60%,\n      rgb(235, 100, 130) 80%,\n      rgb(170, 55, 200) 90%\n    ),\n    linear-gradient(\n      75deg,\n      rgb(170, 55, 200) 0%,\n      rgb(235, 100, 130) 20%,\n      rgb(245, 95, 90) 40%,\n      rgb(245, 110, 30) 60%,\n      rgb(235, 100, 130) 80%,\n      rgb(170, 55, 200) 100%\n    );\n  background-size: 50% 100%;\n  animation: moveGradient 3s linear infinite paused;\n}\n\n.container:hover .button {\n  animation-play-state: running;\n}\n\n.container:active {\n  scale: 0.95;\n}\n\n@keyframes moveGradient {\n  0% {\n    background-position: 0 0;\n  }\n  100% {\n    background-position: 100% 0;\n  }\n}\n\n.span-text {\n  position: absolute;\n  z-index: 3;\n  width: 100%;\n  height: 100%;\n  text-align: center;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.span-outside {\n  width: 300px;\n  height: 95px;\n  justify-content: center;\n  align-items: center;\n  display: flex;\n  border-radius: 30px;\n  border: 2px solid rgba(255, 255, 255, 0.7);\n  background-color: #ffffff10;\n  filter: blur(1px);\n  z-index: 3;\n}\n\n.span-text > svg {\n  position: relative;\n  width: 25px;\n  height: 25px;\n  margin-right: 5px;\n}\n\n.circles .circle {\n  position: absolute;\n  background-color: #fff;\n  width: 200px;\n  height: 200px;\n  border-radius: 50%;\n}\n\n.circles .circle:nth-child(1) {\n  position: absolute;\n  background-color: rgba(255, 255, 255, 0.2);\n  filter: blur(20px);\n  top: -80px;\n  left: 180px;\n}\n\n.circles .circle:nth-child(2) {\n  position: absolute;\n  background-color: rgba(255, 255, 255, 0.3);\n  border-radius: 0;\n  filter: blu', colors: '#ffffff10,#fff', radii: '50%,0,10px 80px 80px 40px,0 0 80px 40px,30px', shadows: '', techniques: 'glassmorphism,gradient,animation,svg-ic