const GalaxyComp(id: 'mateusneves_stupid-husky-53', cat: 'Buttons', author: 'mateusneves', tags: 'button', html: '<button>\n  <span class="label">Next</span>\n  <span class="icon">\n    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="24" height="24"><path fill="none" d="M0 0h24v24H0z"></path><path fill="currentColor" d="M16.172 11l-5.364-5.364 1.414-1.414L20 12l-7.778 7.778-1.414-1.414L16.172 13H4v-2z"></path></svg>\n  </span>\n</button>', css: '\n/* From Uiverse.io by mateusneves - Tags: button */\nbutton {\n position: relative;\n font-size: 14px;\n letter-spacing: 3px;\n height: 3em;\n padding: 0 3em;\n border: none;\n background-color: #c41b54;\n color: #fff;\n text-transform: uppercase;\n overflow: hidden;\n border-radius: 5px\n}\n\nbutton::before {\n content: \'\';\n display: block;\n position: absolute;\n z-index: 0;\n bottom: 0;\n left: 0;\n height: 0px;\n width: 100%;\n background: rgb(196,27,84);\n background: linear-gradient(90deg, rgba(196,27,84,1) 20%, rgba(124,7,46,1) 100%);\n transition: 0.2s;\n}\n\nbutton .label {\n position: relative;\n}\n\nbutton .icon {\n display: flex;\n align-items: center;\n justify-content: center;\n height: 3em;\n width: 3em;\n position: absolute;\n top: 3em;\n right: 0;\n opacity: 0;\n transition: 0.4s;\n}\n\nbutton:hover::before {\n height: 100%;\n}\n\nbutton:hover .icon {\n top: 0;\n opacity: 1;\n}\n', colors: '#c41b54,#fff', radii: '5px\n}\n\nbutton::before {\n content: \'\'', shadows: '', techniques: 'gradient,typography-transform,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'mi-series_terrible-sheep-85', cat: 'Buttons', author: 'mi-series', tags: 'minimalist,button,minimal', html: '<button>\n  Hover Me\n</button>', css: '\n/* From Uiverse.io by mi-series - Tags: minimalist, button, minimal */\nbutton {\n  width: 160px;\n  line-height: 40px;\n  font-weight: 500px;\n  font-size: 17px;\n  letter-spacing: 2px;\n  text-decoration: none;\n  text-transform: uppercase;\n  padding: 0;\n  background: #FBEAEB;\n  position: relative;\n  z-index: 2;\n  color: #FBEAEB;\n  perspective: 300px;\n  transform-style: preserve-3d;\n  border-radius: 6px;\n  border: none;\n}\n\nbutton:hover {\n  color: #2F3C7E;\n}\n\nbutton::after {\n  position: absolute;\n  content: "";\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  font-weight: 500px;\n  background: #2F3C7E;\n  border-radius: 6px;\n  z-index: -1;\n  transform-origin: center bottom;\n  transform: rotateX(0);\n  transition: all 0.3s ease;\n}\n\nbutton:hover::after {\n  transform: rotateX(-180deg);\n}\n', colors: '#fbeaeb,#2f3c7e', radii: '6px', shadows: '', techniques: '3d-transform,perspective,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'Mike11jr_white-emu-65', cat: 'Buttons', author: 'Mike11jr', tags: 'button', html: '<button class="btn"> Hover Me!\n</button>', css: '\n/* From Uiverse.io by Mike11jr - Tags: button */\n.btn {\n padding: 0.9em 1.9em;\n font-size: 16px;\n border: none;\n background: #6285f8;\n color: white;\n cursor: pointer;\n position: relative;\n z-index: 1;\n}\n\n.btn:hover {\n color: rgb(255, 255, 255);\n}\n\n.btn::before,.btn::after {\n content: "";\n position: absolute;\n top: 0%;\n left: 0%;\n width: 100%;\n height: 100%;\n background: rgba(128, 128, 128, 0.096);\n backdrop-filter: blur(10px);\n z-index: -1;\n transition: all 0.4s;\n}\n\n.btn::after {\n z-index: -2;\n transition: all 0.4s;\n}\n\n.btn:hover::before {\n background: rgb(0, 0, 0, 0.315);\n border-radius: 10px;\n}\n\n.btn:hover::after {\n background: linear-gradient(to right, #cb6ce6, #38b6ff);\n border-radius: 10px;\n transform: scale(1.07, 1.2) rotateX(180deg);\n}\n', colors: '#38b6ff,#6285f8,#cb6ce6', radii: '10px', shadows: '', techniques: 'glassmorphism,3d-transform,gradient,pseudo-elements'),
const GalaxyComp(id: 'Mohsinech_tidy-yak-66', cat: 'Buttons', author: 'Mohsinech', tags: 'black,button,click', html: '<div class="btn"><span data-text="Click me">Click me</span></div>', css: '\n/* From Uiverse.io by Mohsinech  - Tags: black, button, click */\n.btn {\n  background: transparent;\n  border: 1px solid #141414;\n  outline: none;\n  padding: 12px 40px;\n  height: 60px;\n  border-radius: 100px;\n  overflow: hidden;\n  transform: scaleX(1);\n  transition: transform 0.5s cubic-bezier(0.4, 0, 0, 1);\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  cursor: pointer;\n}\n\n.btn:hover {\n  animation: animate-scaleX 0.6s cubic-bezier(0.4, 0, 0, 1);\n  background: transparent;\n}\n\n.btn::after {\n  content: "";\n  position: absolute;\n  left: 0;\n  bottom: 0;\n  background: black;\n  transition: transform 0.5s cubic-bezier(0.4, 0, 0, 1),\n    border-radius 0.5s cubic-bezier(0.4, 0, 0, 1);\n  width: 100%;\n  height: 100%;\n  border-radius: 50% 50% 0 0;\n  transform: translateY(100%);\n}\n\n.btn:hover::after {\n  transform: translateY(0%);\n  border-radius: 0;\n}\n\n.btn span {\n  font-size: 20px;\n  font-weight: 500;\n  overflow: hidden;\n  position: relative;\n  color: black;\n}\n\n.btn span:after {\n  width: 100%;\n  height: 100%;\n  transition: transform 0.5s cubic-bezier(0.4, 0, 0, 1);\n  content: attr(data-text);\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  position: absolute;\n  left: 50%;\n  bottom: 0;\n  z-index: 1;\n  transform: translate(-50%, 100%);\n  color: white;\n}\n.btn:hover span:after {\n  transform: translate(-50%, 0);\n}\n\n.btn:focus {\n  outline: none;\n}\n\n@keyframes animate-scaleX {\n  0% {\n    transform: scaleX(1);\n  }\n  50% {\n    transform: scaleX(1.05);\n  }\n  100% {\n    transform: scaleX(1);\n  }\n}\n\n', colors: '#141414', radii: '50% 50% 0 0,0,100px', shadows: '', techniques: 'cubic-bezier,3d-transform,animation,pseudo-elements'),
