const GalaxyComp(id: 'Navarog21_orange-vampirebat-22', cat: 'Buttons', author: 'Navarog21', tags: 'button', html: '<button>\n\n<div class="state" id="moon">Send</div>\n<div class="state" id="sun">Send</div>\n<span class="lightRotation"></span>\n<span class="lightRotation2"></span>\n<span class="lightRotation3"></span>\n<span class="lightRotation4"></span>\n</button>', css: '\n/* From Uiverse.io by Navarog21 - Tags: button */\nbutton {\n  --sunGradient: linear-gradient(60deg, #3d3393 0%, #2b76b9 37%, #2cacd1 65%, #35eb93 100%);\n  --moonGradient: linear-gradient(to top, #cc208e 0%, #6713d2 100%);\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  position: relative;\n  width: 140px;\n  height: 60px;\n  color: white;\n  font-size: 1em;\n  font-weight: bold;\n  text-transform: uppercase;\n  border-radius: 15px;\n  background-color: transparent;\n  transition: 0.5s;\n  overflow: hidden;\n  border: 4px solid black;\n}\n\nbutton:hover {\n  box-shadow: -15px -15px 500px white;\n  transition: 0.2s;\n}\n\nbutton:hover span {\n  background: var(--sunGradient);\n}\n\n.state {\n  position: absolute;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  border-radius: inherit;\n  transition: 0.4s;\n  width: 85%;\n  height: 82%;\n  border: 4px solid black;\n}\n\n#sun {\n  display: none;\n  background-color: #212121;\n  opacity: 0.85;\n}\n\n#moon {\n  background-color: #212121;\n  opacity: 0.85;\n}\n\nbutton:hover #sun {\n  display: flex;\n}\n\nbutton:hover #moon {\n  display: none;\n}\n\nbutton:hover .lightRotation {\n  animation: 1s linear reverse infinite rotation413;\n}\n\nbutton:hover .lightRotation2 {\n  animation: 2s linear infinite rotation_413;\n}\n\nbutton:hover .lightRotation3 {\n  animation: 10s linear reverse infinite rotation_413;\n}\n\nbutton:hover .lightRotation4 {\n  animation: 3s linear infinite rotation_413;\n}\n\n.lightRotation {\n  position: absolute;\n  transition: 0.4s;\n  z-index: -1;\n  width: 60px;\n  height: 500px;\n  transform: rotate(50deg);\n  border-radius: inherit;\n  background: var(--moonGradient);\n}\n\n.lightRotation2 {\n  position: absolute;\n  transition: 0.4s;\n  z-index: -1;\n  width: 75px;\n  height: 500px;\n  transform: rotate(110deg);\n  border-radius: inherit;\n  background: var(--moonGradient);\n}\n\n.lightRotation3 {\n  position: absolute;\n  transition: 0.4s;\n  z-index: -1;\n  width: 40px;\n  height: 260px;\n  border-radius: inherit;\n  background: var(--moonGradient)', colors: '#212121,#2cacd1,#2b76b9,#3d3393,#cc208e,#6713d2,#35eb93', radii: '15px,inherit', shadows: '-15px -15px 500px white', techniques: '3d-transform,gradient,animation,typography-transform'),
const GalaxyComp(id: 'Navarog21_ordinary-rat-19', cat: 'Buttons', author: 'Navarog21', tags: 'button', html: '<button>\n    P L A Y\n    <div id="clip">\n        <div id="leftTop" class="corner"></div>\n        <div id="rightBottom" class="corner"></div>\n        <div id="rightTop" class="corner"></div>\n        <div id="leftBottom" class="corner"></div>\n    </div>\n    <span id="rightArrow" class="arrow"></span>\n    <span id="leftArrow" class="arrow"></span>\n</button>', css: '\n/* From Uiverse.io by Navarog21 - Tags: button */\nbutton {\n  position: relative;\n  width: 11em;\n  height: 4em;\n  outline: none;\n  transition: 0.1s;\n  background-color: transparent;\n  border: none;\n  font-size: 13px;\n  font-weight: bold;\n  color: #ddebf0;\n}\n\n#clip {\n  --color: #2761c3;\n  position: absolute;\n  top: 0;\n  overflow: hidden;\n  width: 100%;\n  height: 100%;\n  border: 5px double var(--color);\n  box-shadow: inset 0px 0px 15px #195480;\n  -webkit-clip-path: polygon(30% 0%, 70% 0%, 100% 30%, 100% 70%, 70% 100%, 30% 100%, 0% 70%, 0% 30%);\n}\n\n.arrow {\n  position: absolute;\n  transition: 0.2s;\n  background-color: #2761c3;\n  top: 35%;\n  width: 11%;\n  height: 30%;\n}\n\n#leftArrow {\n  left: -13.5%;\n  -webkit-clip-path: polygon(100% 0, 100% 100%, 0 50%);\n}\n\n#rightArrow {\n  -webkit-clip-path: polygon(100% 49%, 0 0, 0 100%);\n  left: 102%;\n}\n\nbutton:hover #rightArrow {\n  background-color: #27c39f;\n  left: -15%;\n  animation: 0.6s ease-in-out both infinite alternate rightArrow8;\n}\n\nbutton:hover #leftArrow {\n  background-color: #27c39f;\n  left: 103%;\n  animation: 0.6s ease-in-out both infinite alternate leftArrow8;\n}\n\n.corner {\n  position: absolute;\n  width: 4em;\n  height: 4em;\n  background-color: #2761c3;\n  box-shadow: inset 1px 1px 8px #2781c3;\n  transform: scale(1) rotate(45deg);\n  transition: 0.2s;\n}\n\n#rightTop {\n  top: -1.98em;\n  left: 91%;\n}\n\n#leftTop {\n  top: -1.96em;\n  left: -3.0em;\n}\n\n#leftBottom {\n  top: 2.10em;\n  left: -2.15em;\n}\n\n#rightBottom {\n  top: 45%;\n  left: 88%;\n}\n\nbutton:hover #leftTop {\n  animation: 0.1s ease-in-out 0.05s both changeColor8,\n  0.2s linear 0.4s both lightEffect8;\n}\n\nbutton:hover #rightTop {\n  animation: 0.1s ease-in-out 0.15s both changeColor8,\n  0.2s linear 0.4s both lightEffect8;\n}\n\nbutton:hover #rightBottom {\n  animation: 0.1s ease-in-out 0.25s both changeColor8,\n  0.2s linear 0.4s both lightEffect8;\n}\n\nbutton:hover #leftBottom {\n  animation: 0.1s ease-in-out 0.35s both changeColor8,\n  0.2s linear 0.4s both lightEffect8;\n}\n\nbutton:hover ', colors: '#ddebf0,#2781c3,#195480,#27c39f,#2761c3', radii: '', shadows: 'inset 0px 0px 15px #195480,inset 1px 1px 8px #2781c3,1px 1px 5px #27c39f', techniques: '3d-transform,glow-shadow,animation,clip-path'),
const GalaxyComp(id: 'neerajbaniwal_old-cobra-77', cat: 'Buttons', author: 'neerajbaniwal', tags: 'button,hover button,button hover effect,2d button', html: '<div class="container">\n  <input name="power" id="power" type="checkbox" />\n  <label class="power" for="power">\n    <span class="icon-off"></span>\n    <span class="light"></span>\n  </label>\n</div>', css: '\n/* From Uiverse.io by neerajbaniwal  - Tags: button, hover button, button hover effect , 2d button */\n.container {\n  width: 150px;\n  height: 130px;\n  padding-top: 20px;\n  margin: 50px auto;\n}\n\n#power {\n  position: absolute;\n  left: -9999px;\n}\n\nlabel {\n  display: block;\n  width: 100px;\n  height: 100px;\n  border-radius: 50%;\n  position: relative;\n  margin: auto;\n  border: 4px solid #636679;\n  background: -webkit-radial-gradient(\n    center,\n    ellipse cover,\n    #efefef 0%,\n    #eee 80%,\n    #fff 100%\n  );\n  background: -moz-radial-gradient(\n    center,\n    ellipse cover,\n    #efefef 0%,\n    #eee 80%,\n    #fff 100%\n  );\n  background: radial-gradient(\n    center,\n    ellipse cover,\n    #fefefe 0%,\n    #eee 80%,\n    #fff 100%\n  );\n  box-shadow: inset 0 -5px 10px 0 #d0d5eb, inset 0 5px 10px 0 #fff,\n    0 0 0 1px #333;\n  cursor: pointer;\n  text-align: center;\n  font-size: 40px;\n  color: #0f0;\n  line-height: 100px;\n  text-shadow: -1px -1px 0px #fff, 1px 1px 0px #fff;\n  transition: all 0.1s ease-in-out;\n}\n\nlabel:after,\nlabel:before {\n  display: block;\n  content: "";\n  position: absolute;\n}\n\nlabel:before {\n  width: 150px;\n  height: 150px;\n  border-radius: 20px;\n  background: -webkit-linear-gradient(\n    top,\n    #fefefe 0%,\n    #eee 30%,\n    #ddd 82%,\n    #ddd 100%\n  );\n  background: -moz-linear-gradient(\n    top,\n    #fefefe 0%,\n    #eee 30%,\n    #ddd 82%,\n    #ddd 100%\n  );\n  background: linear-gradient(top, #fefefe 0%, #eee 30%, #ddd 82%, #ddd 100%);\n  box-shadow: 0 10px 30px 0 #000;\n  top: -25px;\n  left: -25px;\n  z-index: -2;\n}\n\nlabel:after {\n  width: 130px;\n  height: 130px;\n  border-radius: 50%;\n  background: #fff;\n  top: -15px;\n  left: -15px;\n  z-index: -1;\n  box-shadow: 0 -2px 5px 0px #fefefe, 0 2px 5px 0 #ccc;\n  background: rgb(210, 215, 237);\n  background: -webkit-linear-gradient(\n    top,\n    #ddd 0%,\n    #ddd 30%,\n    #eee 82%,\n    #efefef 100%\n  );\n  background: -moz-linear-gradient(\n    top,\n    #ddd 0%,\n    #ddd 30%,\n    #eee 82%,\n    #efefef 100%\n  );\n  back', colors: '#efefef,#fefefe,#999,#636679,#fcc,#333,#fff,#aaa,#777,#bade32', radii: '50%,10px,20px', shadows: 'inset 0 -5px 10px 0 #d0d5eb, inset 0 5px 10px 0 #fff,\n    0 0 0 1px #333,0 10px 30px 0 #000,0 -2px 5px 0px #fefefe, 0 2px 5px 0 #ccc', techniques: 'glow-shadow,text-shadow,gradient,checkbox-input'),
const GalaxyComp(id: 'nikk7007_nasty-wasp-56', cat: 'Buttons', author: 'nikk7007', tags: 'button', html: '<button class="btn"> Button\n</button>', css: '\n/* From Uiverse.io by nikk7007 - Tags: button */\n.btn {\n --color: #00A97F;\n --color2: rgb(10, 25, 30);\n padding: 0.8em 1.75em;\n background-color: transparent;\n border-radius: 6px;\n border: .3px solid var(--color);\n transition: .5s;\n position: relative;\n overflow: hidden;\n cursor: pointer;\n z-index: 1;\n font-weight: 300;\n font-size: 17px;\n font-family: \'Roboto\', \'Segoe UI\', sans-serif;\n text-transform: uppercase;\n color: var(--color);\n}\n\n.btn::after, .btn::before {\n content: \'\';\n display: block;\n height: 100%;\n width: 100%;\n transform: skew(90deg) translate(-50%, -50%);\n position: absolute;\n inset: 50%;\n left: 25%;\n z-index: -1;\n transition: .5s ease-out;\n background-color: var(--color);\n}\n\n.btn::before {\n top: -50%;\n left: -25%;\n transform: skew(90deg) rotate(180deg) translate(-50%, -50%);\n}\n\n.btn:hover::before {\n transform: skew(45deg) rotate(180deg) translate(-50%, -50%);\n}\n\n.btn:hover::after {\n transform: skew(45deg) translate(-50%, -50%);\n}\n\n.btn:hover {\n color: var(--color2);\n}\n\n.btn:active {\n filter: brightness(.7);\n transform: scale(.98);\n}\n', colors: '#00a97f', radii: '6px', shadows: '', techniques: '3d-transform,filter-effect,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'njesenberger_thin-owl-11', cat: 'Buttons', author: 'njesenberger', tags: 'skeuomorphism,3d,button,active,css,btn', html: '<button type="button" class="button">\n  <div class="button-top">3D Button</div>\n  <div class="button-bottom"></div>\n  <div class="button-base"></div>\n</button>', css: '\n/* From Uiverse.io by njesenberger - Tags: skeuomorphism, 3d, button, active, css, btn */\n.button {\n  -webkit-appearance: none;\n  appearance: none;\n  position: relative;\n  border-width: 0;\n  padding: 0 8px 12px;\n  min-width: 10em;\n  box-sizing: border-box;\n  background: transparent;\n  font: inherit;\n  cursor: pointer;\n}\n\n.button-top {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  position: relative;\n  z-index: 0;\n  padding: 8px 16px;\n  transform: translateY(0);\n  text-align: center;\n  color: #fff;\n  text-shadow: 0 -1px rgba(0, 0, 0, .25);\n  transition-property: transform;\n  transition-duration: .2s;\n  -webkit-user-select: none;\n  user-select: none;\n}\n\n.button:active .button-top {\n  transform: translateY(6px);\n}\n\n.button-top::after {\n  content: \'\';\n  position: absolute;\n  z-index: -1;\n  border-radius: 4px;\n  width: 100%;\n  height: 100%;\n  box-sizing: content-box;\n  background-image: radial-gradient(#cd3f64, #9d3656);\n  text-align: center;\n  color: #fff;\n  box-shadow: inset 0 0 0px 1px rgba(255, 255, 255, .2), 0 1px 2px 1px rgba(255, 255, 255, .2);\n  transition-property: border-radius, padding, width, transform;\n  transition-duration: .2s;\n}\n\n.button:active .button-top::after {\n  border-radius: 6px;\n  padding: 0 2px;\n}\n\n.button-bottom {\n  position: absolute;\n  z-index: -1;\n  bottom: 4px;\n  left: 4px;\n  border-radius: 8px / 16px 16px 8px 8px;\n  padding-top: 6px;\n  width: calc(100% - 8px);\n  height: calc(100% - 10px);\n  box-sizing: content-box;\n  background-color: #803;\n  background-image: radial-gradient(4px 8px at 4px calc(100% - 8px), rgba(255, 255, 255, .25), transparent), radial-gradient(4px 8px at calc(100% - 4px) calc(100% - 8px), rgba(255, 255, 255, .25), transparent), radial-gradient(16px at -4px 0, white, transparent), radial-gradient(16px at calc(100% + 4px) 0, white, transparent);\n  box-shadow: 0px 2px 3px 0px rgba(0, 0, 0, 0.5), inset 0 -1px 3px 3px rgba(0, 0, 0, .4);\n  transition-property: border-radius, padding-top;\n  transition-du', colors: '#803,#cd3f64,#9d3656,#fff', radii: '12px,8px / 16px 16px 8px 8px,10px 10px 8px 8px / 8px,4px,6px', shadows: 'inset 0 0 0px 1px rgba(255, 255, 255, .2), 0 1px 2px 1px rgba(255, 255, 255, .2),0px 2px 3px 0px rgba(0, 0, 0, 0.5), inset 0 -1px 3px 3px rgba(0, 0, 0, .4),0 1px 1px 0 rgba(255, 255, 255, .75), inset 0 2px 2px rgba(0, 0, 0, .25)', techniques: 'glow-shadow,text-shadow,gradient,pseudo-elements'),
const GalaxyComp(id: 'ozgeozkaraa01_plastic-elephant-49', cat: 'Buttons', author: 'ozgeozkaraa01', tags: 'button', html: '<button>\n  Hover\n</button>', css: '\n/* From Uiverse.io by ozgeozkaraa01 - Tags: button */\nbutton {\n  border: none;\n  padding: 0.8em 2.5em;\n  outline: none;\n  color: white;\n  font-style: 1.2em;\n  position: relative;\n  z-index: 1;\n  cursor: pointer;\n  background: none;\n  text-shadow: 3px 3px 10px rgba(0, 0, 0, 0.45);\n}\n\nbutton::before,\nbutton::after {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  border-radius: 10em;\n  -webkit-transform: translateX(-50%) translateY(-50%);\n  transform: translateX(-50%) translateY(-50%);\n  width: 105%;\n  height: 105%;\n  content: "";\n  z-index: -2;\n  background-size: 400% 400%;\n  background: linear-gradient(\n    100deg,\n    #f79533,\n    #f37055,\n    #ef4e7b,\n    #a166ab,\n    #5073b8,\n    #1098ad,\n    #07b39b,\n    #6fba82\n  );\n}\n\nbutton::before {\n  -webkit-filter: blur(7px);\n  filter: blur(7px);\n  -webkit-transition: all 0.25s ease;\n  transition: all 0.25s ease;\n  -webkit-animation: pulse 10s infinite ease;\n  animation: pulse 10s infinite ease;\n}\n\nbutton::after {\n  -webkit-filter: blur(0.3px);\n  filter: blur(0.3px);\n}\n\nbutton:hover::before {\n  width: 115%;\n  height: 115%;\n}\n', colors: '#5073b8,#f79533,#a166ab,#f37055,#07b39b,#6fba82,#ef4e7b,#1098ad', radii: '10em', shadows: '', techniques: 'glassmorphism,text-shadow,gradient,pseudo-elements'),
const GalaxyComp(id: 'Phelix652_perfect-hound-11', cat: 'Buttons', author: 'Phelix652', tags: 'button', html: '<button class="btn btn--primary">\n\n  <span class="btn-inner">\n    <span class="btn-label">\n      Button \n    </span>\n  </span>\n  \n</button>', css: '\n/* From Uiverse.io by Phelix652 - Tags: button */\n.btn {\n  --btn-gradient: var(--btn-gradient-from),var(--btn-gradient-to);\n  border: 0 none;\n  appearance: none;\n  transition: all .3s;\n  border-radius: 10px;\n  background-color: var(--btn-bg);\n  box-shadow: 0 0 2px 2px var(--btn-shadow), 0 0 4px 4px var(--btn-shadow), 0 0 8px 8px var(--btn-shadow);\n}\n\n.btn,\n.btn * {\n  box-sizing: border-box;\n}\n\n.btn-inner {\n  position: relative;\n  border-radius: inherit;\n  border: 1px solid transparent;\n  font-size: 1rem;\n  display: flex;\n  align-items: center;\n  min-width: 10rem;\n  padding: 1.5rem 2rem;\n  overflow: hidden;\n  color: var(--btn-text-color);\n}\n\n.btn-label {\n  position: absolute;\n  bottom: 1px;\n  left: 1px;\n  right: 1px;\n  top: 1px;\n  border-radius: inherit;\n  z-index: 10;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  background-color: var(--btn-bg);\n  background-image: linear-gradient(to bottom,var(--btn-gradient));\n}\n\n.btn:hover {\n  transform: translateY(-5px);\n  letter-spacing: 3px;\n  box-shadow: rgba(0, 131, 253, 0.596) 0px 1px 80px 40px;\n}\n\n.btn:active {\n  border-radius: 40px;\n  transform: translateY(4px);\n  transition: 0.1s;\n  letter-spacing: 3px;\n  box-shadow: rgb(0, 131, 253) 0px 1px 80px 40px;\n}\n\n.btn:active .btn-blur:before {\n  --transition: 0.5s;\n}\n\n.btn--primary {\n  --btn-bg: #111111;\n  --btn-gradient-from: #111111;\n  --btn-gradient-to: rgba(29, 6, 240, 0.5);\n  --btn-text-color: #ffffff;\n  --btn-shadow: #9b14c438;\n}\n\n@keyframes turn {\n  0% {\n    transform: translateY(-50%) rotate(0deg)\n  }\n\n  to {\n    transform: translateY(-50%) rotate(1turn)\n  }\n}\n\n', colors: '#ffffff,#111111,#9b14c438', radii: '10px,40px,inherit', shadows: '0 0 2px 2px var(--btn-shadow), 0 0 4px 4px var(--btn-shadow), 0 0 8px 8px var(--btn-shadow),rgba(0, 131, 253, 0.596) 0px 1px 80px 40px,rgb(0, 131, 253) 0px 1px 80px 40px', techniques: '3d-transform,glow-shadow,gradient,animation'),
const GalaxyComp(id: 'Pradeepsaranbishnoi_dull-mole-49', cat: 'Buttons', author: 'Pradeepsaranbishnoi', tags: 'button', html: '<div class="voltage-button">\n  \n  <button>Button</button>\n  <svg version="1.1" xmlns="http://www.w3.org/2000/svg" x="0px" y="0px" viewBox="0 0 234.6 61.3" preserveAspectRatio="none" xml:space="preserve">\n \n    <filter id="glow">\n      <feGaussianBlur class="blur" result="coloredBlur" stdDeviation="2"></feGaussianBlur>\n      <feTurbulence type="fractalNoise" baseFrequency="0.075" numOctaves="0.3" result="turbulence"></feTurbulence>\n  <feDisplacementMap in="SourceGraphic" in2="turbulence" scale="30" xChannelSelector="R" yChannelSelector="G" result="displace"></feDisplacementMap>\n      <feMerge>\n        <feMergeNode in="coloredBlur"></feMergeNode>\n        <feMergeNode in="coloredBlur"></feMergeNode>\n        <feMergeNode in="coloredBlur"></feMergeNode>\n        <feMergeNode in="displace"></feMergeNode>\n        <feMergeNode in="SourceGraphic"></feMergeNode>\n      </feMerge>\n    </filter>\n    <path class="voltage line-1" d="m216.3 51.2c-3.7 0-3.7-1.1-7.3-1.1-3.7 0-3.7 6.8-7.3 6.8-3.7 0-3.7-4.6-7.3-4.6-3.7 0-3.7 3.6-7.3 3.6-3.7 0-3.7-0.9-7.3-0.9-3.7 0-3.7-2.7-7.3-2.7-3.7 0-3.7 7.8-7.3 7.8-3.7 0-3.7-4.9-7.3-4.9-3.7 0-3.7-7.8-7.3-7.8-3.7 0-3.7-1.1-7.3-1.1-3.7 0-3.7 3.1-7.3 3.1-3.7 0-3.7 10.9-7.3 10.9-3.7 0-3.7-12.5-7.3-12.5-3.7 0-3.7 4.6-7.3 4.6-3.7 0-3.7 4.5-7.3 4.5-3.7 0-3.7 3.6-7.3 3.6-3.7 0-3.7-10-7.3-10-3.7 0-3.7-0.4-7.3-0.4-3.7 0-3.7 2.3-7.3 2.3-3.7 0-3.7 7.1-7.3 7.1-3.7 0-3.7-11.2-7.3-11.2-3.7 0-3.7 3.5-7.3 3.5-3.7 0-3.7 3.6-7.3 3.6-3.7 0-3.7-2.9-7.3-2.9-3.7 0-3.7 8.4-7.3 8.4-3.', css: '\n/* From Uiverse.io by Pradeepsaranbishnoi - Tags: button */\n.voltage-button {\n  position: relative;\n}\n\n.voltage-button button {\n  color: white;\n  background: #0D1127;\n  padding: 1rem 3rem 1rem 3rem;\n  border-radius: 5rem;\n  border: 5px solid #5978F3;\n  font-size: 1.2rem;\n  line-height: 1em;\n  letter-spacing: 0.075em;\n  transition: background 0.3s;\n}\n\n.voltage-button button:hover {\n  cursor: pointer;\n  background: #0F1C53;\n}\n\n.voltage-button button:hover + svg, .voltage-button button:hover + svg + .dots {\n  opacity: 1;\n}\n\n.voltage-button svg {\n  display: block;\n  position: absolute;\n  top: -0.75em;\n  left: -0.25em;\n  width: calc(100% + 0.5em);\n  height: calc(100% + 1.5em);\n  pointer-events: none;\n  opacity: 0;\n  transition: opacity 0.4s;\n  transition-delay: 0.1s;\n}\n\n.voltage-button svg path {\n  stroke-dasharray: 100;\n  filter: url("#glow");\n}\n\n.voltage-button svg path.line-1 {\n  stroke: #f6de8d;\n  stroke-dashoffset: 0;\n  animation: spark-1 3s linear infinite;\n}\n\n.voltage-button svg path.line-2 {\n  stroke: #6bfeff;\n  stroke-dashoffset: 500;\n  animation: spark-2 3s linear infinite;\n}\n\n.voltage-button .dots {\n  opacity: 0;\n  transition: opacity 0.3s;\n  transition-delay: 0.4s;\n}\n\n.voltage-button .dots .dot {\n  width: 1rem;\n  height: 1rem;\n  background: white;\n  border-radius: 100%;\n  position: absolute;\n  opacity: 0;\n}\n\n.voltage-button .dots .dot-1 {\n  top: 0;\n  left: 20%;\n  animation: fly-up 3s linear infinite;\n}\n\n.voltage-button .dots .dot-2 {\n  top: 0;\n  left: 55%;\n  animation: fly-up 3s linear infinite;\n  animation-delay: 0.5s;\n}\n\n.voltage-button .dots .dot-3 {\n  top: 0;\n  left: 80%;\n  animation: fly-up 3s linear infinite;\n  animation-delay: 1s;\n}\n\n.voltage-button .dots .dot-4 {\n  bottom: 0;\n  left: 30%;\n  animation: fly-down 3s linear infinite;\n  animation-delay: 2.5s;\n}\n\n.voltage-button .dots .dot-5 {\n  bottom: 0;\n  left: 65%;\n  animation: fly-down 3s linear infinite;\n  animation-delay: 1.5s;\n}\n\n@keyframes spark-1 {\n  to {\n    stroke-dashoffset: -1000;\n  }\n}\n\n@key', colors: '#0d1127,#5978f3,#0f1c53,#6bfeff,#f6de8d', radii: '100%,5rem', shadows: '', techniques: '3d-transform,animation,filter-effect,svg-icon'),
const GalaxyComp(id: 'Pradeepsaranbishnoi_jolly-robin-0', cat: 'Buttons', author: 'Pradeepsaranbishnoi', tags: 'simple,neumorphism,skeuomorphism,3d,button', html: '<div class="container">\n  <div class="toggle">\n    <input type="checkbox">\n    <span class="button"></span>\n    <span class="label">☼</span>\n  </div>\n</div>', css: '\n/* From Uiverse.io by Pradeepsaranbishnoi - Tags: simple, neumorphism, skeuomorphism, 3d, button */\n.toggle {\n  display: inline-block;\n}\n\n.toggle {\n  position: relative;\n  height: 100px;\n  width: 100px;\n}\n\n.toggle:before {\n  box-shadow: 0;\n  border-radius: 84.5px;\n  background: #fff;\n  position: absolute;\n  margin-left: -36px;\n  margin-top: -36px;\n  opacity: 0.2;\n  height: 72px;\n  width: 72px;\n  left: 50%;\n  top: 50%;\n}\n\n.toogle input:checked~.label {\n  color: rgba(255,0,0,0.8);\n}\n\n.toggle .button {\n  transition: all 300ms cubic-bezier(0.23, 1, 0.32, 1);\n  box-shadow: 0 15px 25px -4px rgba(0, 0, 0, 0.5), inset 0 -3px 4px -1px rgba(0, 0, 0, 0.2), 0 -10px 15px -1px rgba(255, 255, 255, 0.6), inset 0 3px 4px -1px rgba(255, 255, 255, 0.2), inset 0 0 5px 1px rgba(255, 255, 255, 0.8), inset 0 20px 30px 0 rgba(255, 255, 255, 0.2);\n  border-radius: 68.8px;\n  position: absolute;\n  background: #eaeaea;\n  margin-left: -34.4px;\n  margin-top: -34.4px;\n  display: block;\n  height: 68.8px;\n  width: 68.8px;\n  left: 50%;\n  top: 50%;\n}\n\n.toggle .label {\n  transition: color 300ms ease-out;\n  line-height: 101px;\n  text-align: center;\n  position: absolute;\n  font-weight: 700;\n  font-size: 28px;\n  display: block;\n  opacity: 0.9;\n  height: 100%;\n  width: 100%;\n  color: rgba(0, 0, 0, 0.9);\n}\n\n.toggle input {\n  opacity: 0;\n  position: absolute;\n  cursor: pointer;\n  z-index: 1;\n  height: 100%;\n  width: 100%;\n  left: 0;\n  top: 0;\n}\n\n.toggle input:active ~ .button {\n  filter: blur(0.5px);\n  box-shadow: 0 12px 25px -4px rgba(0, 0, 0, 0.4), inset 0 -8px 30px 1px rgba(255, 255, 255, 0.9), 0 -10px 15px -1px rgba(255, 255, 255, 0.6), inset 0 8px 25px 0 rgba(0, 0, 0, 0.4), inset 0 0 10px 1px rgba(255, 255, 255, 0.6);\n}\n\n.toggle input:active ~ .label {\n  font-size: 26px;\n  color: rgba(0, 0, 0, 0.45);\n}\n\n.toggle input:checked ~ .button {\n  filter: blur(0.5px);\n  box-shadow: 0 10px 25px -4px rgba(0, 0, 0, 0.4), inset 0 -8px 25px -1px rgba(255, 255, 255, 0.9), 0 -10px 15px -1px rgba(255, 255, 255, 0.6), ', colors: '#eaeaea,#fff', radii: '68.8px,84.5px', shadows: '0,0 15px 25px -4px rgba(0, 0, 0, 0.5), inset 0 -3px 4px -1px rgba(0, 0, 0, 0.2), 0 -10px 15px -1px rgba(255, 255, 255, 0.6,0 12px 25px -4px rgba(0, 0, 0, 0.4), inset 0 -8px 30px 1px rgba(255, 255, 255, 0.9), 0 -10px 15px -1px rgba(255, 255, 25', techniques: 'glassmorphism,cubic-bezier,glow-shadow,checkbox-input'),
const GalaxyComp(id: 'Pradeepsaranbishnoi_spotty-chipmunk-79', cat: 'Buttons', author: 'Pradeepsaranbishnoi', tags: 'button', html: '<input id="c" type="checkbox">\n<label id="upload_app" for="c">\n  <div id="app">\n    <div id="arrow"></div>\n    <div id="success">\n      <i class="fas fa-check-circle"></i>\n    </div>\n  </div>\n</label>', css: '\n/* From Uiverse.io by Pradeepsaranbishnoi - Tags: button */\n#c {\n  display: none;\n}\n\n#upload_app {\n  display: block;\n  position: absolute;\n  top: 50%;\n  right: 0;\n  left: 0;\n  margin: 0 auto;\n  width: 120px;\n  height: 42px;\n  transform: translateY(-50%);\n  transition: 0.3s ease width;\n  cursor: pointer;\n}\n\n#app {\n  position: absolute;\n  top: 0;\n  right: 0;\n  bottom: 0;\n  left: 0;\n  background-color: #fff;\n  border: 2px solid #143240;\n  overflow: hidden;\n  z-index: 2;\n}\n\n#app:before {\n  content: "Upload";\n  position: absolute;\n  top: 0;\n  right: 0;\n  padding: 12px;\n  left: 0;\n  color: #143240;\n  font-size: 14px;\n  line-height: 14px;\n  font-weight: bold;\n  z-index: 1;\n}\n\n#arrow {\n  position: absolute;\n  top: 0;\n  right: 0;\n  width: 38px;\n  height: 38px;\n  background-color: #fff;\n  z-index: 2;\n}\n\n#arrow:before,\n#arrow:after {\n  content: "";\n  position: absolute;\n  top: 18px;\n  width: 10px;\n  height: 2px;\n  background-color: #143240;\n}\n\n#arrow:before {\n  right: 17px;\n  transform: rotateZ(-45deg);\n}\n\n#arrow:after {\n  right: 11px;\n  transform: rotateZ(45deg);\n}\n\n#success {\n  position: absolute;\n  top: 0;\n  right: 0;\n  width: 54px;\n  height: 54px;\n  margin: -8px;\n  background-color: #143240;\n  transform: scale(0);\n  border-radius: 50%;\n  z-index: 3;\n}\n\n#success i {\n  font-size: 20px;\n  color: #fff;\n  display: block;\n  width: 20px;\n  height: 20px;\n  margin: 17px auto;\n  transform: scale(0);\n}\n\n#c:checked + #upload_app {\n  width: 42px;\n}\n\n#c:checked + #upload_app #arrow:before {\n  animation: _a 0.4s ease 0.4s forwards, _incHeight 4s ease 1s forwards;\n}\n\n#c:checked + #upload_app #arrow:after {\n  animation: _b 0.4s ease 0.4s forwards, _incHeight 4s ease 1s forwards;\n}\n\n#c:checked + #upload_app #success {\n  animation: _success 0.4s cubic-bezier(0, 0.74, 0.32, 1.21) 5s forwards;\n}\n\n#c:checked + #upload_app #success i {\n  animation: _success 0.3s cubic-bezier(0, 0.74, 0.32, 1.21) 5.2s forwards;\n}\n\n@keyframes _a {\n  0% {\n    top: 18px;\n    right: 17px;\n    width: 10px;\n    transf', colors: '#143240,#fff,#ffc107', radii: '50%', shadows: '', techniques: 'cubic-bezier,3d-transform,animation,checkbox-input'),
const GalaxyComp(id: 'PriyanshuGupta28_brave-mole-100', cat: 'Buttons', author: 'PriyanshuGupta28', tags: 'simple,button,css effect,click animation,buttons,bounce animation,3d button,2d button', html: '<button class="pushable">\n      <span class="shadow"></span>\n      <span class="edge"></span>\n      <span class="front">\n        Push Me\n      </span>\n    </button>', css: '\n/* From Uiverse.io by PriyanshuGupta28 - Tags: simple, button, css effect, click animation, buttons, bounce animation, 3d button, 2d button */\n.pushable {\n  position: relative;\n  background: transparent;\n  padding: 0px;\n  border: none;\n  cursor: pointer;\n  outline-offset: 4px;\n  outline-color: deeppink;\n  transition: filter 250ms;\n  -webkit-tap-highlight-color: rgba(0, 0, 0, 0);\n}\n\n.shadow {\n  position: absolute;\n  top: 0;\n  left: 0;\n  height: 100%;\n  width: 100%;\n  background: hsl(226, 25%, 69%);\n  border-radius: 8px;\n  filter: blur(2px);\n  will-change: transform;\n  transform: translateY(2px);\n  transition: transform 600ms cubic-bezier(0.3, 0.7, 0.4, 1);\n}\n\n.edge {\n  position: absolute;\n  top: 0;\n  left: 0;\n  height: 100%;\n  width: 100%;\n  border-radius: 8px;\n  background: linear-gradient(\n    to right,\n    hsl(248, 39%, 39%) 0%,\n    hsl(248, 39%, 49%) 8%,\n    hsl(248, 39%, 39%) 92%,\n    hsl(248, 39%, 29%) 100%\n  );\n}\n\n.front {\n  display: block;\n  position: relative;\n  border-radius: 8px;\n  background: hsl(248, 53%, 58%);\n  padding: 16px 32px;\n  color: white;\n  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen,\n    Ubuntu, Cantarell, "Open Sans", "Helvetica Neue", sans-serif;\n  font-weight: 600;\n  text-transform: uppercase;\n  letter-spacing: 1.5px;\n  font-size: 1rem;\n  transform: translateY(-4px);\n  transition: transform 600ms cubic-bezier(0.3, 0.7, 0.4, 1);\n}\n\n.pushable:hover {\n  filter: brightness(110%);\n}\n\n.pushable:hover .front {\n  transform: translateY(-6px);\n  transition: transform 250ms cubic-bezier(0.3, 0.7, 0.4, 1.5);\n}\n\n.pushable:active .front {\n  transform: translateY(-2px);\n  transition: transform 34ms;\n}\n\n.pushable:hover .shadow {\n  transform: translateY(4px);\n  transition: transform 250ms cubic-bezier(0.3, 0.7, 0.4, 1.5);\n}\n\n.pushable:active .shadow {\n  transform: translateY(1px);\n  transition: transform 34ms;\n}\n\n.pushable:focus:not(:focus-visible) {\n  outline: none;\n}\n\n', colors: '', radii: '8px', shadows: '', techniques: 'glassmorphism,cubic-bezier,gradient,typography-transform'),
const GalaxyComp(id: 'PriyanshuGupta28_shaggy-wombat-39', cat: 'Buttons', author: 'PriyanshuGupta28', tags: 'button,hover effect,3d button,cool button,glass button,onclick effect', html: '<button role="button" class="button">Hover Me</button>', css: '\n/* From Uiverse.io by PriyanshuGupta28 - Tags: button, hover effect, 3d button, cool button, glass button, onClick effect */\n.button {\n  all: unset;\n  width: 100px;\n  height: 30px;\n  font-size: 16px;\n  background: transparent;\n  border: none;\n  position: relative;\n  color: #f0f0f0;\n  cursor: pointer;\n  z-index: 1;\n  padding: 10px 20px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  white-space: nowrap;\n  user-select: none;\n  -webkit-user-select: none;\n  touch-action: manipulation;\n  transition: 0.3s ease-in-out;\n}\n\n.button:hover {\n  box-shadow: rgba(0, 0, 0, 0.3) 0px 19px 38px, rgba(0, 0, 0, 0.22) 0px 15px 12px;\n}\n\n.button::after,\n.button::before {\n  content: \'\';\n  position: absolute;\n  bottom: 0;\n  right: 0;\n  z-index: -99999;\n  transition: all .4s;\n}\n\n.button::before {\n  transform: translate(0%, 0%);\n  width: 100%;\n  height: 100%;\n  background-color: #4158D0;\n  background-image: linear-gradient(43deg, #4158D0 0%, #C850C0 46%, #FFCC70 100%);\n  border-radius: 10px;\n}\n\n.button::after {\n  transform: translate(10px, 10px);\n  width: 35px;\n  height: 35px;\n  background: #6804da2f;\n  backdrop-filter: blur(5px);\n  -webkit-backdrop-filter: blur(5px);\n  border-radius: 50px;\n}\n\n.button:hover::before {\n  transform: translate(5%, 20%);\n  width: 110%;\n  height: 110%;\n}\n\n.button:hover::after {\n  border-radius: 10px;\n  transform: translate(0, 0);\n  width: 100%;\n  height: 100%;\n}\n\n.button:active::after {\n  transition: 0s;\n  transform: translate(0, 5%);\n}\n', colors: '#ffcc70,#f0f0f0,#6804da2f,#4158d0,#c850c0', radii: '50px,10px', shadows: 'rgba(0, 0, 0, 0.3) 0px 19px 38px, rgba(0, 0, 0, 0.22) 0px 15px 12px', techniques: 'glassmorphism,glow-shadow,gradient,pseudo-elements'),
