const GalaxyComp(id: 'rhino-corey_cowardly-chicken-15', cat: 'Buttons', author: 'rhino-corey', tags: 'button', html: '<button> Hexagonal Button\n</button>', css: '\n/* From Uiverse.io by rhino-corey - Tags: button */\nbutton {\n display: inline-block;\n position: relative;\n color: #fff;\n font-weight: 500;\n font-size: 14px;\n text-decoration: none;\n text-transform: uppercase;\n padding: 15px 30px;\n text-align: center;\n border: none;\n clip-path: polygon(7% 0, 93% 0, 100% 50%, 93% 100%, 7% 100%, 0 50%);\n background-color: #000000;\n background-image: radial-gradient(200% 70% at center 20%, rgba(48,44,45,1) -30%, rgba(50,46,47,1) 49%, rgba(22,18,19,1) 50%, rgba(22,18,19,1) 150%);\n background-repeat: no-repeat;\n transition: background-position-y ease-in-out 250ms;\n}\n\nbutton:hover {\n background-position-y: -50px;\n}\n\nbutton:active {\n transform: scale(0.99);\n}\n', colors: '#000000,#fff', radii: '', shadows: '', techniques: '3d-transform,gradient,clip-path,typography-transform'),
const GalaxyComp(id: 'Sameer2244_friendly-wasp-57', cat: 'Buttons', author: 'Sameer2244', tags: 'button,mario,game', html: '<div class="button-container">\n  <div class="button">\n    \n    <div class="button-icon">\n        <div class="one"></div>\n        <div class="two"></div>\n        <div class="dots"></div>\n        <div class="dots2"></div>\n    </div>\n  </div>\n    <div class="coin">\n    <svg id="svg" version="1.1" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="50" height="50" viewBox="0, 0, 400,400"><g id="svgg"><path id="path0" d="M149.843 25.433 C 149.709 25.781,149.600 31.361,149.600 37.833 L 149.600 49.600 125.374 49.600 C 109.439 49.600,100.883 49.742,100.374 50.014 C 99.622 50.417,99.600 51.116,99.600 75.014 L 99.600 99.600 87.833 99.600 C 81.361 99.600,75.781 99.709,75.433 99.843 C 74.881 100.054,74.350 299.616,74.900 300.085 C 74.955 300.132,80.580 300.267,87.400 300.385 L 99.800 300.600 99.903 325.300 L 100.006 350.000 124.370 350.000 C 137.771 350.000,149.019 350.109,149.367 350.243 C 149.925 350.457,150.000 351.926,150.000 362.643 L 150.000 374.800 199.994 374.800 L 249.988 374.800 250.094 362.500 L 250.200 350.200 275.000 350.000 L 299.800 349.800 300.000 325.000 L 300.200 300.200 312.500 300.094 L 324.800 299.988 324.800 200.000 L 324.800 100.012 312.500 99.906 L 300.200 99.800 300.000 75.000 L 299.800 50.200 275.200 50.000 L 250.600 49.800 250.385 37.400 C 250.267 30.580,250.132 24.955,250.085 24.900 C 249.617 24.352,150.054 24.881,149.843 25.433 M249.503 37.600 C 249.594 48.500,249.677 49.853,250.279 50.300 C 250.783 50.674,253.964 50.800,262.8', css: '\n/* From Uiverse.io by Sameer2244 - Tags: button, mario, game */\n.button {\n  width: 6rem;\n  height: 6rem;\n  background-color: #da6b34;\n  border-radius: 0;\n  box-shadow: 5px 5px 0px black;\n  transform: translate(0,0);\n  z-index: 1;\n  padding: 0;\n  position: relative;\n}\n\n.coin {\n  position: absolute;\n  z-index: -2;\n  top: 50%;\n  transform: translate(0,-20px);\n  right: 45%;\n}\n\n.mario {\n  position: absolute;\n  z-index: 1;\n  top: 50%;\n  transform: translate(15px,200px);\n  right: 45%;\n}\n\n.button:active ~ .mario {\n  animation: jump2 0.6s ease-in-out;\n}\n\n.button:active {\n  transform: translate(0,-15px);\n}\n\n.button:active ~ .coin {\n  animation: jump 1s;\n}\n\n.button:hover {\n  animation: animate 1s infinite;\n}\n\n.button-icon {\n  position: relative;\n  top: 25%;\n  left: 63%;\n  z-index: 1;\n  transform: scale(1.5);\n}\n\n.overlay {\n  position: absolute;\n  width: 6rem;\n  height: 6rem;\n  background-color: #FFC07B;\n}\n\n.one {\n  position: absolute;\n  background-color: #DE5917;\n  box-shadow: 2px 2px 0px black;\n  width: 1rem;\n  height: 0.35rem;\n  z-index: 10;\n}\n\n.one:after {\n  content: "";\n  position: absolute;\n  background-color: #DE5917;\n  box-shadow: 2px 2px 0px black;\n  width: 0.5rem;\n  height: 0.5rem;\n  transform: translate(5px,15px);\n  z-index: 10;\n}\n\n.one:before {\n  content: "";\n  position: absolute;\n  background-color: #DE5917;\n  box-shadow: 2px 2px 0px black;\n  width: 0.5rem;\n  height: 0.5rem;\n  transform: translate(5px,25px);\n  z-index: 10;\n}\n\n.two {\n  position: absolute;\n  background-color: #DE5917;\n  box-shadow: 2px 2px 0px black;\n  width: 0.5rem;\n  height: 0.5rem;\n  transform: translate(-50%,50%);\n  z-index: 10;\n}\n\n.two::after {\n  content: "";\n  position: absolute;\n  background-color: #DE5917;\n  box-shadow: 2px 2px 0px black;\n  width: 0.5rem;\n  height: 0.8rem;\n  transform: translate(190%,-5%);\n  z-index: 10;\n}\n\n.two::before {\n  content: "";\n  position: absolute;\n  background-color: #DE5917;\n  width: 0.7rem;\n  height: 0.3rem;\n  transform: translate(12px,8px);\n  z-index: 10;\n}\n\n.do', colors: '#000,#da6b34,#ffc07b,#de5917', radii: '0', shadows: '5px 5px 0px black,2px 2px 0px black,2px 2px 0px black', techniques: '3d-transform,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'SanthoshSJ-Dev_short-goat-24', cat: 'Buttons', author: 'SanthoshSJ-Dev', tags: 'simple,blue,button,bubble,plain', html: '<button class="button">\n  <span>Bubble Button</span>\n  <svg aria-hidden="true" preserveAspectRatio="none" viewBox="-5 -5 110 110">\n    <path d="M0,0 C0,0 100,0 100,0 C100,0 100,100 100,100 C100,100 0,100 0,100 C0,100 0,0 0,0"></path>\n  </svg>\n</button>', css: '\n/* From Uiverse.io by SanthoshSJ-Dev - Tags: simple, blue, button, bubble, plain */\n.button {\n  appearance: none;\n  background: transparent;\n  border: 0;\n  color: #fff;\n  cursor: pointer;\n  font: inherit;\n  font-weight: 500;\n  line-height: 1;\n  padding: 1em 1.5em;\n  position: relative;\n  transition: filter 0.3s;\n}\n\n.button:hover {\n  filter: brightness(1.1);\n}\n\n.button:active {\n  filter: brightness(0.9);\n}\n\n.button>span {\n  display: block;\n  position: relative;\n  transition: transform 0.3s cubic-bezier(0.68, -0.6, 0.32, 1.6);\n  z-index: 1;\n}\n\n.button:hover>span {\n  transform: scale(1.05);\n}\n\n.button:active>span {\n  transform: scale(0.95);\n}\n\n.button>svg {\n  fill: #0c2cde;\n  position: absolute;\n  top: -5%;\n  left: -5%;\n  width: 110%;\n  height: 110%;\n}\n\n.button>svg>path {\n  transition: 0.3s cubic-bezier(0.68, -0.6, 0.32, 1.6);\n}\n\n.button:hover>svg>path {\n  d: path("M0,0 C0,-5 100,-5 100,0 C105,0 105,100 100,100 C100,105 0,105 0,100 C-5,100 -5,0 0,0");\n}\n\n.button:active>svg>path {\n  d: path("M0,0 C30,10 70,10 100,0 C95,30 95,70 100,100 C70,90 30,90 0,100 C5,70 5,30 0,0");\n}\n', colors: '#0c2cde,#fff', radii: '', shadows: '', techniques: 'cubic-bezier,3d-transform,filter-effect,svg-icon'),
const GalaxyComp(id: 'satyamchaudharydev_chatty-chipmunk-42', cat: 'Buttons', author: 'satyamchaudharydev', tags: 'button', html: '<button>\n  <p>Submit</p>\n</button>', css: '\n/* From Uiverse.io by satyamchaudharydev - Tags: button */\nbutton {\n border: none;\n width: 140px;\n height: 55px;\n color: #fff;\n font-family: "Arial";\n letter-spacing: 1.2px;\n font-weight: bold;\n z-index: 1;\n display: flex;\n background: #000;\n position: relative;\n}\n\nbutton p {\n margin: 0 auto;\n align-self: center;\n font-size: 1.5em;\n text-align: center;\n}\n\nbutton::after, button::before {\n position: absolute;\n content: "";\n width: 100%;\n z-index: -1;\n height: 10%;\n clip-path: polygon(0% 74%, 4% 75%, 8% 76%, 11% 77%, 15% 78%, 20% 78%, 25% 77%, 32% 77%, 37% 75%, 40% 74%, 43% 74%, 46% 73%, 52% 72%, 57% 72%, 65% 74%, 66% 75%, 71% 78%, 75% 82%, 81% 86%, 83% 88%, 88% 91%, 90% 94%, 94% 96%, 98% 98%, 100% 100%, 82% 100%, 0 100%);\n background: #97c45d;\n transition: 0.2s cubic-bezier(.02,.02,.23,.73);\n}\n\nbutton::after {\n bottom: 0;\n}\n\nbutton::before {\n transform: rotate(180deg);\n}\n\nbutton:hover::after {\n clip-path: path(\'M0 199.88C8.33 270.71 16.67 306.13 25 306.13C37.5 306.13 35.91 231.4 50 231.13C64.09 230.85 62.5 284.25 75 284.25C87.5 284.25 87.17 208.05 100 212.38C112.83 216.7 112.71 300.8 125 300.47C137.29 300.13 137.76 239.04 150.48 237.38C163.19 235.71 162.16 293.63 174.54 293.63C182.79 293.63 191.28 262.38 200 199.88L200 0.13L0 0.13L0 199.88Z\');\n height: 30%;\n}\n\nbutton:hover::before {\n clip-path: path(\'M0 199.88C8.33 270.71 16.67 306.13 25 306.13C37.5 306.13 35.91 231.4 50 231.13C64.09 230.85 62.5 284.25 75 284.25C87.5 284.25 87.17 208.05 100 212.38C112.83 216.7 112.71 300.8 125 300.47C137.29 300.13 137.76 239.04 150.48 237.38C163.19 235.71 162.16 293.63 174.54 293.63C182.79 293.63 191.28 262.38 200 199.88L200 0.13L0 0.13L0 199.88Z\');\n height: 100%;\n}\n\n', colors: '#97c45d,#000,#fff', radii: '', shadows: '', techniques: 'cubic-bezier,3d-transform,clip-path,pseudo-elements'),
const GalaxyComp(id: 'SelfMadeSystem_afraid-rabbit-12', cat: 'Buttons', author: 'SelfMadeSystem', tags: 'button,ripple,animated', html: '<button class="btn">\n  <span>Border ripple</span>\n  <div class="ripple-container">\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span></span>\n    <span', css: '\n/* From Uiverse.io by SelfMadeSystem - Tags: button, ripple, animated */\n/* Note the transparent background :) */\n.btn {\n  border-radius: 0.5em;\n  font-size: larger;\n  height: 3em;\n  width: 8em;\n  position: relative;\n  border: none;\n  background-color: transparent;\n  isolation: isolate;\n}\n\n.btn > span {\n  position: relative;\n  pointer-events: none;\n}\n\n.ripple-container {\n  position: absolute;\n  inset: -0.3em;\n  display: grid;\n  grid-template-columns: repeat(16, 0.5em);\n  border-radius: 0.8em;\n  padding: 0.3em;\n  mask: linear-gradient(#fff 0 0) content-box,\n      linear-gradient(#fff 0 0);\n  /* I forgor that I need the two mask composites because of firefoxxxxxx */\n  mask-composite: exclude;\n  mask-composite: xor;\n  -webkit-mask: linear-gradient(#fff 0 0) content-box,\n      linear-gradient(#fff 0 0);\n  -webkit-mask-composite: exclude;\n  -webkit-mask-composite: xor;\n  overflow: hidden;\n}\n\n.ripple-container > span {\n  position: relative;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n.ripple-container > span::after {\n  content: "";\n  pointer-events: none;\n  position: absolute;\n  background-color: hsl(218, 68%, 65%);\n  transition: width 0.5s ease-out, height 0.5s ease-out, opacity 1s;\n  width: 18em;\n  height: 18em;\n  opacity: 0;\n  border-radius: 999em;\n}\n\n.ripple-container > span:active::after {\n  transition: 0s;\n  width: 0em;\n  height: 0em;\n  opacity: 1;\n}\n\n.ripple-container::before {\n  content: "";\n  pointer-events: none;\n  position: absolute;\n  background-color: hsla(218, 68%, 65%, 0.5);\n  width: 13em;\n  height: 13em;\n  border-radius: 999em;\n  transition: transform 0.25s ease-out;\n  transform: translate(-25%, -25%) scale(0);\n}\n\n.ripple-container:hover::before {\n  transform: translate(-25%, -25%) scale(1);\n}\n\n', colors: '#fff', radii: '0.5em,999em,0.8em', shadows: '', techniques: '3d-transform,gradient,css-mask,pseudo-elements'),
const GalaxyComp(id: 'simontheonlyone_loud-husky-46', cat: 'Buttons', author: 'simontheonlyone', tags: 'exotic,button,active,weather,animated,focus,night,day', html: '<button>\n  <span class="night">Night</span>\n  <span class="day">Day</span>\n    <svg class="lightning" style="color: rgb(255, 228, 56);" xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" viewBox="0 0 16 16">\n      <path d="M5.52.359A.5.5 0 0 1 6 0h4a.5.5 0 0 1 .474.658L8.694 6H12.5a.5.5 0 0 1 .395.807l-7 9a.5.5 0 0 1-.873-.454L6.823 9.5H3.5a.5.5 0 0 1-.48-.641l2.5-8.5z" fill="#ffe438"></path> \n    </svg>\n    <svg class="mini-cloud" xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" viewBox="0 0 16 16"> \n      <path d="M4.406 3.342A5.53 5.53 0 0 1 8 2c2.69 0 4.923 2 5.166 4.579C14.758 6.804 16 8.137 16 9.773 16 11.569 14.502 13 12.687 13H3.781C1.708 13 0 11.366 0 9.318c0-1.763 1.266-3.223 2.942-3.593.143-.863.698-1.723 1.464-2.383z"></path>\n    </svg>\n    <svg class="stars star1" id="IconChangeColor" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512" height="20" width="20">\n      <path d="M208,512,155.62,372.38,16,320l139.62-52.38L208,128l52.38,139.62L400,320,260.38,372.38Z" id="mainIconPathAttribute" fill="yellow"></path>\n      <path d="M88,176,64.43,111.57,0,88,64.43,64.43,88,0l23.57,64.43L176,88l-64.43,23.57Z" id="mainIconPathAttribute" fill="yellow"></path>\n      <path d="M400,256l-31.11-80.89L288,144l80.89-31.11L400,32l31.11,80.89L512,144l-80.89,31.11Z" id="mainIconPathAttribute" fill="yellow"></path>\n    </svg>\n    <svg class="stars star2" id="IconChangeColor" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 ', css: '\n/* From Uiverse.io by simontheonlyone - Tags: exotic, button, active, weather, animated, focus, night, day */\nbutton {\n  position: relative;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  width: 11em;\n  height: 4em;\n  border: none;\n  border-radius: 2.1em;\n  background-color: rgb(23, 56, 128);\n  color: whitesmoke;\n  font-weight: bold;\n  font-size: 17px;\n  text-align: center;\n  cursor: pointer;\n  transition: background-color .2s linear 1.1s,\n  color .2s linear 1.1s;\n}\n\nbutton:active,\nbutton:focus {\n  background: rgb(254, 138, 30);\n}\n\nbutton .day {\n  position: absolute;\n  opacity: 0;\n  transition: all .2s ease 1.1s;\n}\n\nbutton .night {\n  transition: all .2s ease 1.1s;\n}\n\nbutton:active .night,\nbutton:focus .night {\n  color: transparent;\n}\n\nbutton:active .day,\nbutton:focus .day {\n  opacity: 1;\n}\n/* mini cloud */\n.mini-cloud {\n  content: \'\';\n  position: absolute;\n  inset: -26% 62%;\n  scale: 2;\n  opacity: 1;\n  color: rgb(150, 150, 150);\n  transform: rotate(3deg);\n  transition: scale .4s ease .3s,\n  opacity .4s ease 1.3s;\n  pointer-events: none;\n}\n/* lightning */\n.lightning {\n  content: \'\';\n  position: absolute;\n  inset: -4% 62%;\n  scale: 1.3;\n  transform: rotate(15deg);\n  transition: all .4s ease .2s,\n  opacity .4s ease 1.5s;\n  pointer-events: none;\n}\n/* stars */\n.stars {\n  content: \'\';\n  position: absolute;\n  pointer-events: none;\n}\n\n.star1 {\n  inset: 15% 10%;\n  scale: 1.2;\n  opacity: 1;\n  transition: all .4s ease .4s,\n  opacity .4s ease 1.6s;\n}\n\n.star2 {\n  inset: 45% 80%;\n  scale: 1;\n  opacity: 1;\n  transition: all .4s ease .5s,\n  opacity .4s ease 1.7s;\n}\n/* cloud */\n.cloud {\n  content: \'\';\n  position: absolute;\n  pointer-events: none;\n  border: none;\n}\n\n.left-side {\n  width: 4.4em;\n  height: 4.4em;\n  bottom: 0;\n  left: -.8em;\n  scale: 1;\n  border-radius: 50%;\n  z-index: -5;\n  background-color: rgb(15, 39, 91);\n  transition: all .6s ease .6s;\n}\n\n.left-side1 {\n  width: 4.4em;\n  height: 4.4em;\n  bottom: 0;\n  left: -.4em;\n  scale: .95;\n  border-radius:', colors: '#fe8a1e', radii: '2.1em,50%', shadows: '', techniques: '3d-transform,gradient,animation,svg-icon'),
const GalaxyComp(id: 'StealthWorm_young-badger-81', cat: 'Buttons', author: 'StealthWorm', tags: 'purple,pink,button,smooth,realistic,css,advanced,#button', html: '<button type="button" class="btn">\n  <div class="smoke">\n    <div class="cloud"></div>\n    <div class="cloud"></div>\n    <div class="cloud"></div>\n    <div class="cloud"></div>\n    <div class="cloud"></div>\n    <div class="cloud"></div>\n    <div class="cloud"></div>\n    <div class="cloud"></div>\n    <div class="cloud"></div>\n    <div class="cloud"></div>\n    <div class="cloud"></div>\n    <div class="cloud"></div>\n    <div class="cloud"></div>\n    <div class="cloud"></div>\n  </div>\n  <div class="title">\n    <span class="thunder">⚡</span>\n    <strong class="description">Join now</strong>\n  </div>\n  <div class="glass">\n    <div class="inner-glass"></div>\n  </div>\n</button>', css: '\n/* From Uiverse.io by StealthWorm  - Tags: purple, pink, button, smooth, realistic, css, advanced, #button */\n.btn {\n  z-index: 0;\n  overflow: hidden;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  cursor: pointer;\n  padding: 4px;\n  width: 20rem;\n  height: 6rem;\n  border-top: 2px double #ffffff92;\n  border-bottom: none;\n  border-left: 2px outset #0000007e;\n  border-right: 2px solid #e94fcab3;\n  border-radius: 1.8rem;\n  background-origin: border-box;\n  background-clip: content-box, border-box;\n  filter: hue-rotate(-15deg) drop-shadow(0px 30px 10px #00000028) saturate(2);\n\n  background: linear-gradient(\n    64.14deg,\n    #b938ff 0%,\n    #daa1f1 10%,\n    #f179ec 15.58%,\n    #fefffe 28.15%,\n    #fc9f9d 45.31%,\n    #ed8664 53.18%,\n    #ff7423 58.79%,\n    #ff875f 65.28%,\n    #fbabae 75.48%,\n    #fcbde5 85.31%,\n    #e94fca 100.29%\n  );\n  transition: all 0.5s;\n}\n\n.btn:hover {\n  transform: scale(1.1);\n  filter: hue-rotate(-365deg) drop-shadow(0px 30px 10px #00000028) saturate(2);\n}\n\n.btn:hover .title > strong {\n  font-size: 1.2rem;\n  font-weight: 800;\n  transition: all 0.8s;\n}\n\n.glass {\n  z-index: 10;\n  display: flex;\n  border: double 2px rgba(255, 255, 255, 0.263);\n  backdrop-filter: blur(2px);\n  filter: blur(1px) brightness(1.1) saturate(50%) hue-rotate(30deg);\n  border-radius: 1.6rem;\n  width: 100%;\n  height: 100%;\n  padding: 1rem;\n  background-color: #ffffff1c;\n  background-origin: content-box;\n  background-clip: content-box, border-box;\n  box-shadow: inset 0 0 10px #a84fd88d;\n}\n\n.inner-glass {\n  z-index: 10;\n  display: flex;\n  border-left: 1px solid rgba(255, 255, 255, 0.564);\n  border-right: 1px solid rgb(255, 255, 255);\n  backdrop-filter: blur(40px);\n  box-shadow: inset 0 0 20px rgba(246, 142, 213, 0.86);\n  -webkit-backdrop-filter: blur(5px);\n  border-radius: 0.6rem;\n  width: 100%;\n  height: 100%;\n  background-origin: border-box;\n  background-clip: content-box, border-box;\n  filter: brightness(140%);\n}\n\n.title {\n  inset: 0;\n  display: flex;\n  te', colors: '#ffffff1c,#ff5107fb,#f36b9d,#daa1f1,#fcbde5,#ff7423,#0000007e,#ffffff,#00000028,#b938ff', radii: '0.6rem,1.6rem,1.8rem,100%,9999px', shadows: 'inset 0 0 10px #a84fd88d,inset 0 0 20px rgba(246, 142, 213, 0.86)', techniques: 'glassmorphism,3d-transform,glow-shadow,gradient'),
const GalaxyComp(id: 'tarantino421_swift-zebra-86', cat: 'Buttons', author: 'tarantino421', tags: 'button,hover button,fall', html: '<div class="box">\n  <button class="button">FALL</button>\n  <div class="falling-leaves">\n    <span class="leaf" style="--i: 13; --hue:20"></span>\n    <span class="leaf" style="--i: 16; --hue:10"></span>\n    <span class="leaf" style="--i: 17; --hue:0"></span>\n    <span class="leaf" style="--i: 21; --hue:10"></span>\n    <span class="leaf" style="--i: 13; --hue:90"></span>\n    <span class="leaf" style="--i: 11; --hue:70"></span>\n    <span class="leaf" style="--i: 14; --hue:40"></span>\n    <span class="leaf" style="--i: 17; --hue:60"></span>\n    <span class="leaf" style="--i: 19; --hue:0"></span>\n    <span class="leaf" style="--i: 26; --hue:90"></span>\n    <span class="leaf" style="--i: 17; --hue:60"></span>\n    <span class="leaf" style="--i: 20; --hue:10"></span>\n  </div>\n</div>', css: '\n/* From Uiverse.io by tarantino421 - Tags: button, hover button, fall */\n.box {\n  --clr-shadow__border: #ef7305;\n  --clr-text: #F6F4EB;\n  --clr-falling-leaves: #441a12;\n  --size: 3rem;\n  position: relative;\n  outline: 1px solid var(--clr-shadow__border);\n}\n\n.button {\n  background: transparent;\n  padding: calc(var(--size) / 3) var(--size);\n  font-weight: 600;\n  font-size: 1.5rem;\n  border: none;\n  cursor: pointer;\n  color: var(--clr-text);\n  letter-spacing: 0.2rem;\n  text-shadow: 2px 0px var(--clr-shadow__border), 0px 2px var(--clr-shadow__border),\n    -2px 0px var(--clr-shadow__border), 0px -2px var(--clr-shadow__border);\n}\n\n.falling-leaves {\n  width: 100%;\n  height: 100%;\n  bottom: 0%;\n  transition: 0.5s ease-in-out;\n  z-index: -1;\n  opacity: 0;\n  overflow: hidden;\n  position: absolute;\n  display: flex;\n  background: var(--clr-falling-leaves);\n}\n\n.box:hover .falling-leaves {\n  opacity: 1;\n}\n\n.leaf {\n  height: 1rem;\n  width: 1rem;\n  clip-path: polygon(\n    45% 0%,\n    45% 10%,\n    15% 30%,\n    35% 60%,\n    20% 80%,\n    45% 100%,\n    70% 80%,\n    55% 60%,\n    85% 30%,\n    55% 10%,\n    55% 0%\n  );\n  background-color: hsl(var(--hue), 70%, 50%);\n  animation: falling-leaves-animation linear infinite;\n  animation-duration: calc(0.5s * var(--i));\n}\n\n@keyframes falling-leaves-animation {\n  0% {\n    transform: rotate(-10deg) translateY(calc(-51% * var(--i)));\n  }\n\n  50% {\n    transform: rotate(-40deg) translateY(calc(0% * var(--i)));\n  }\n\n  100% {\n    transform: rotate(150deg) translateY(calc(100% * var(--i)));\n  }\n}\n\n\n\n\n\n\n\n\n', colors: '#f6f4eb,#441a12,#ef7305', radii: '', shadows: '', techniques: '3d-transform,text-shadow,animation,clip-path'),
const GalaxyComp(id: 'TISEPSE_smart-newt-43', cat: 'Buttons', author: 'TISEPSE', tags: 'material design,black,button', html: '<button class="vlrt"><span class="green"></span>Hover effect</button>', css: '\n/* From Uiverse.io by TISEPSE  - Tags: material design, black, button */\n.vlrt {\n  height: 75px;\n  width: 170px;\n  border-radius: 4px;\n  font-size: 18px;\n  border: 3px solid;\n  color: #f5f5f5;\n  border-color: #b6b6b6;\n  background-color: rgba(0, 0, 0, 0.15);\n  backdrop-filter: blur(50px);\n  transition: 0.2s;\n  position: relative;\n  overflow: hidden;\n  cursor: pointer;\n}\n\n.vlrt:hover {\n  border-color: #16ff00;\n  letter-spacing: 2px;\n  font-size: 19px;\n  color: #fefefe;\n  text-shadow: 0 0.3rem rgb(51, 51, 51);\n  box-shadow: #16ff00 0px -30px 40px -30px inset;\n}\n\n.vlrt .green {\n  content: "";\n  width: 25px;\n  height: 25px;\n  position: absolute;\n  top: 0;\n  left: 0;\n  background-color: #16ff00;\n}\n\n.vlrt .green {\n  content: "";\n  width: 45px;\n  height: 45px;\n  position: absolute;\n  top: 0px;\n  left: 0px;\n  background-color: rgb(182, 182, 182);\n  transform: rotate(49deg) translateX(-32px) translateY(0px);\n}\n\n.vlrt:hover .green {\n  background-color: #16ff00;\n  transition: 0.5s;\n}\n\n.vlrt:active {\n  letter-spacing: 0px;\n  text-shadow: 0 0rem #333;\n  transition: 0.1s;\n  background-color: #1abc9c;\n}\n\n', colors: '#fefefe,#1abc9c,#f5f5f5,#333,#16ff00,#b6b6b6', radii: '4px', shadows: '#16ff00 0px -30px 40px -30px inset', techniques: 'glassmorphism,3d-transform,glow-shadow,text-shadow'),
const GalaxyComp(id: 'umairmanzoor1143_cuddly-jellyfish-95', cat: 'Buttons', author: 'umairmanzoor1143', tags: 'loading,button,on,off,glow,circle,rotate,click', html: '<button class="button">\n  <span class="span">Button</span>\n</button>', css: '\n/* From Uiverse.io by umairmanzoor1143  - Tags: loading, button, on, off, glow, circle, rotate, click */\n.button {\n  background: #fff;\n  position: relative;\n  border: none;\n  padding: 10px 20px;\n  display: inline-block;\n  font-size: 15px;\n  font-weight: 600;\n  text-transform: uppercase;\n  cursor: pointer;\n  transition: 0.5s;\n}\n.span {\n  display: inline-block;\n}\n.button:hover {\n  font-size: 20px;\n  transform: skew(-5deg);\n  padding-right: 30px;\n}\n.button::before {\n  content: "";\n  box-sizing: border-box;\n  position: absolute;\n  top: 50%;\n  left: 70%;\n  width: 15px;\n  height: 15px;\n  margin-top: -8px;\n  margin-left: -5px;\n  border-radius: 50%;\n  border: 2px solid #ccc;\n  border-top-color: #000;\n  opacity: 0;\n  animation: spinner 0.6s linear infinite;\n  transition: 0.5s;\n}\n.button:hover::before {\n  opacity: 1;\n  left: 85%;\n}\n@keyframes spinner {\n  to {\n    transform: rotate(360deg);\n  }\n}\n\n', colors: '#000,#fff,#ccc', radii: '50%', shadows: '', techniques: '3d-transform,animation,typography-transform,pseudo-elements'),
