const GalaxyComp(id: 'vinodjangid07_curly-panda-17', cat: 'Buttons', author: 'vinodjangid07', tags: 'button,arrow,hover effect,back to top,scroll to top', html: '<button class="Btn">\n  <svg height="1.2em" class="arrow" viewBox="0 0 512 512"><path d="M233.4 105.4c12.5-12.5 32.8-12.5 45.3 0l192 192c12.5 12.5 12.5 32.8 0 45.3s-32.8 12.5-45.3 0L256 173.3 86.6 342.6c-12.5 12.5-32.8 12.5-45.3 0s-12.5-32.8 0-45.3l192-192z"></path></svg>\n<p class="text">Back to Top</p>\n</button>', css: '\n/* From Uiverse.io by vinodjangid07 - Tags: button, arrow, hover effect, back to top, scroll to top */\n.Btn {\n  width: 45px;\n  height: 45px;\n  background: linear-gradient(#44ea76, #39fad7);\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  border-radius: 50%;\n  cursor: pointer;\n  position: relative;\n  border: none;\n}\n\n.arrow path {\n  fill: white;\n}\n\n.text {\n  font-size: 0.7em;\n  width: 100px;\n  position: absolute;\n  color: white;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  bottom: -18px;\n  opacity: 0;\n  transition-duration: .7s;\n}\n\n.Btn:hover .text {\n  opacity: 1;\n  transition-duration: .7s;\n}\n\n.Btn:hover .arrow {\n  animation: slide-in-bottom .7s cubic-bezier(0.250, 0.460, 0.450, 0.940) both;\n}\n\n@keyframes slide-in-bottom {\n  0% {\n    transform: translateY(10px);\n    opacity: 0;\n  }\n\n  100% {\n    transform: translateY(0);\n    opacity: 1;\n  }\n}\n\n', colors: '#44ea76,#39fad7', radii: '50%', shadows: '', techniques: 'cubic-bezier,gradient,animation,svg-icon'),
const GalaxyComp(id: 'vinodjangid07_great-ape-33', cat: 'Buttons', author: 'vinodjangid07', tags: 'instagram,gradient,button,social media', html: '<button class="Btn">\n <span class="svgContainer">\n   <svg fill="white" class="svgIcon" viewBox="0 0 448 512" height="1.5em" xmlns="http://www.w3.org/2000/svg"><path d="M224.1 141c-63.6 0-114.9 51.3-114.9 114.9s51.3 114.9 114.9 114.9S339 319.5 339 255.9 287.7 141 224.1 141zm0 189.6c-41.1 0-74.7-33.5-74.7-74.7s33.5-74.7 74.7-74.7 74.7 33.5 74.7 74.7-33.6 74.7-74.7 74.7zm146.4-194.3c0 14.9-12 26.8-26.8 26.8-14.9 0-26.8-12-26.8-26.8s12-26.8 26.8-26.8 26.8 12 26.8 26.8zm76.1 27.2c-1.7-35.9-9.9-67.7-36.2-93.9-26.2-26.2-58-34.4-93.9-36.2-37-2.1-147.9-2.1-184.9 0-35.8 1.7-67.6 9.9-93.9 36.1s-34.4 58-36.2 93.9c-2.1 37-2.1 147.9 0 184.9 1.7 35.9 9.9 67.7 36.2 93.9s58 34.4 93.9 36.2c37 2.1 147.9 2.1 184.9 0 35.9-1.7 67.7-9.9 93.9-36.2 26.2-26.2 34.4-58 36.2-93.9 2.1-37 2.1-147.8 0-184.8zM398.8 388c-7.8 19.6-22.9 34.7-42.6 42.6-29.5 11.7-99.5 9-132.1 9s-102.7 2.6-132.1-9c-19.6-7.8-34.7-22.9-42.6-42.6-11.7-29.5-9-99.5-9-132.1s-2.6-102.7 9-132.1c7.8-19.6 22.9-34.7 42.6-42.6 29.5-11.7 99.5-9 132.1-9s102.7-2.6 132.1 9c19.6 7.8 34.7 22.9 42.6 42.6 11.7 29.5 9 99.5 9 132.1s2.7 102.7-9 132.1z"></path></svg>\n </span>\n <span class="BG"></span>\n</button>', css: '\n/* From Uiverse.io by vinodjangid07 - Tags: instagram, gradient, button, social media */\n.Btn {\n  width: 45px;\n  height: 45px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  border: none;\n  background-color: transparent;\n  position: relative;\n  /* overflow: hidden; */\n  border-radius: 7px;\n  cursor: pointer;\n  transition: all .3s;\n}\n\n.svgContainer {\n  width: 100%;\n  height: 100%;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  background-color: transparent;\n  backdrop-filter: blur(4px);\n  letter-spacing: 0.8px;\n  border-radius: 10px;\n  transition: all .3s;\n  border: 1px solid rgba(156, 156, 156, 0.466);\n}\n\n.BG {\n  position: absolute;\n  content: "";\n  width: 100%;\n  height: 100%;\n  background: #f09433;\n  background: -moz-linear-gradient(45deg, #f09433 0%, #e6683c 25%, #dc2743 50%, #cc2366 75%, #bc1888 100%);\n  background: -webkit-linear-gradient(45deg, #f09433 0%,#e6683c 25%,#dc2743 50%,#cc2366 75%,#bc1888 100%);\n  background: linear-gradient(45deg, #f09433 0%,#e6683c 25%,#dc2743 50%,#cc2366 75%,#bc1888 100%);\n  filter: progid:DXImageTransform.Microsoft.gradient( startColorstr=\'#f09433\', endColorstr=\'#bc1888\',GradientType=1 );\n  z-index: -1;\n  border-radius: 9px;\n  pointer-events: none;\n  transition: all .3s;\n}\n\n.Btn:hover .BG {\n  transform: rotate(35deg);\n  transform-origin: bottom;\n}\n\n.Btn:hover .svgContainer {\n  background-color: rgba(156, 156, 156, 0.466);\n}\n\n', colors: '#bc1888,#e6683c,#f09433,#cc2366,#dc2743', radii: '7px,10px,9px', shadows: '', techniques: 'glassmorphism,3d-transform,gradient,svg-icon'),
const GalaxyComp(id: 'vinodjangid07_horrible-husky-70', cat: 'Buttons', author: 'vinodjangid07', tags: 'button,jelly,hover effect', html: '<button class="Btn">\n  Jelly Button\n</button>', css: '\n/* From Uiverse.io by vinodjangid07 - Tags: button, jelly, hover effect */\n.Btn {\n  position: relative;\n  width: 150px;\n  height: 55px;\n  border-radius: 45px;\n  border: none;\n  background-color: rgb(151, 95, 255);\n  color: white;\n  box-shadow: 0px 10px 10px rgb(210, 187, 253) inset,\n  0px 5px 10px rgba(5, 5, 5, 0.212),\n  0px -10px 10px rgb(124, 54, 255) inset;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.Btn::before {\n  width: 70%;\n  height: 2px;\n  position: absolute;\n  background-color: rgba(250, 250, 250, 0.678);\n  content: "";\n  filter: blur(1px);\n  top: 7px;\n  border-radius: 50%;\n}\n\n.Btn::after {\n  width: 70%;\n  height: 2px;\n  position: absolute;\n  background-color: rgba(250, 250, 250, 0.137);\n  content: "";\n  filter: blur(1px);\n  bottom: 7px;\n  border-radius: 50%;\n}\n\n.Btn:hover {\n  animation: jello-horizontal 0.9s both;\n}\n\n@keyframes jello-horizontal {\n  0% {\n    transform: scale3d(1, 1, 1);\n  }\n\n  30% {\n    transform: scale3d(1.25, 0.75, 1);\n  }\n\n  40% {\n    transform: scale3d(0.75, 1.25, 1);\n  }\n\n  50% {\n    transform: scale3d(1.15, 0.85, 1);\n  }\n\n  65% {\n    transform: scale3d(0.95, 1.05, 1);\n  }\n\n  75% {\n    transform: scale3d(1.05, 0.95, 1);\n  }\n\n  100% {\n    transform: scale3d(1, 1, 1);\n  }\n}\n\n', colors: '', radii: '50%,45px', shadows: '0px 10px 10px rgb(210, 187, 253) inset,\n  0px 5px 10px rgba(5, 5, 5, 0.212),\n  0px -10px 10px rgb(124, 54, 255) inset', techniques: 'glassmorphism,3d-transform,animation,pseudo-elements'),
const GalaxyComp(id: 'watchakorn-18k_chilly-cow-66', cat: 'Buttons', author: 'watchakorn-18k', tags: 'gradient,button,transition', html: '<button class="btn-space space">\n  Button\n</button>', css: '\n/* From Uiverse.io by watchakorn-18k - Tags: gradient, button, transition */\n.btn-space {\n  padding: 15px 45px;\n  text-align: center;\n  text-transform: uppercase;\n  -webkit-transition: 0.5s;\n  transition: 0.5s;\n  background-size: 500% auto;\n  font-weight: bold;\n  font-size: 1rem;\n  color: rgba(255, 255, 255, 0.103);\n  border-radius: 10px;\n}\n\n.btn-space:hover {\n  background-position: right center;\n  border-image-source: linear-gradient(90deg, #d53a9d,#743ad5 );\n  -webkit-box-shadow: 0 0 20px #743ad5;\n  box-shadow: 0 0 20px #743ad5;\n  color: rgb(255, 255, 255);\n  text-shadow: 1px 1px 10px #d53a9d;\n}\n\n.space {\n  background-image: -webkit-gradient(linear, left top, right top, from(#743ad5), color-stop(51%, #d53a9d), to(#743ad5));\n  background-image: linear-gradient(to right, #743ad5 0%, #d53a9d 51%, #743ad5 100%);\n  border-image-source: linear-gradient(45deg, #743ad5, #d53a9d );\n  border-image-outset: 1em;\n}\n\n\n\n\n', colors: '#743ad5,#d53a9d', radii: '10px', shadows: '0 0 20px #743ad5,0 0 20px #743ad5', techniques: 'glow-shadow,text-shadow,gradient,typography-transform'),
const GalaxyComp(id: 'Yashasewi_evil-dog-33', cat: 'Buttons', author: 'Yashasewi', tags: 'button', html: '<div class="item button-parrot" style="--bg-color: #2c3e50">\n    <button>Click Me!\n      <div class="parrot"></div>\n      <div class="parrot"></div>\n      <div class="parrot"></div>\n      <div class="parrot"></div>\n      <div class="parrot"></div>\n      <div class="parrot"></div>\n    </button>\n  </div>', css: '\n/* From Uiverse.io by Yashasewi - Tags: button */\nbutton {\n  background: transparent;\n  color: #fff;\n  border: 3px solid #fff;\n  border-radius: 50px;\n  padding: 0.8rem 2rem;\n  font: 18px "Margarine", sans-serif;\n  outline: none;\n  cursor: pointer;\n  position: relative;\n  transition: 0.2s ease-in-out;\n  letter-spacing: 2px;\n}\n\n.name {\n  width: 100%;\n  text-align: center;\n  padding: 0 0 3rem;\n  padding-top: 4rem;\n  font: 500 14px "Rubik", sans-serif;\n  letter-spacing: 0.5px;\n  text-transform: uppercase;\n  text-shadow: 0 1px 1px rgba(0, 0, 0, 0.4);\n}\n\n.button-parrot .parrot {\n  position: absolute;\n  width: 60px;\n  text-align: center;\n  animation: blink 0.8s infinite;\n  color: transparent;\n}\n\n.button-parrot .parrot:before {\n  content: "Click Me!";\n}\n\n.button-parrot .parrot:nth-child(1) {\n  top: -30px;\n  left: -40px;\n  font: 12px/1 "Margarine", sans-serif;\n  transform: rotate(-20deg);\n  animation-duration: 0.5s;\n}\n\n.button-parrot .parrot:nth-child(2) {\n  font: 12px/1 "Margarine", sans-serif;\n  right: -40px;\n  top: -20px;\n  transform: rotate(15deg);\n  animation-duration: 0.3s;\n}\n\n.button-parrot .parrot:nth-child(3) {\n  font: 16px/1 "Margarine", sans-serif;\n  top: -60px;\n  left: 15px;\n  transform: rotate(10deg);\n  animation-duration: 1s;\n}\n\n.button-parrot .parrot:nth-child(4) {\n  font: 18px/1 "Margarine", sans-serif;\n  top: -70px;\n  left: 95px;\n  transform: rotate(2deg);\n  animation-duration: 0.7s;\n}\n\n.button-parrot .parrot:nth-child(5) {\n  font: 14px/1 "Margarine", sans-serif;\n  top: 80px;\n  left: 105px;\n  transform: rotate(-20deg);\n  animation-duration: 0.8s;\n}\n\n.button-parrot .parrot:nth-child(6) {\n  font: 12px/1 "Margarine", sans-serif;\n  top: 80px;\n  left: 5px;\n  transform: rotate(10deg);\n  animation-duration: 1.2s;\n}\n\n.button-parrot button:hover .parrot:before {\n  content: "Do it!";\n  width: 70px;\n}\n\n@keyframes blink {\n  25%, 75% {\n    color: transparent;\n  }\n\n  40%, 60% {\n    color: #fff;\n  }\n}\n', colors: '#fff', radii: '50px', shadows: '', techniques: '3d-transform,text-shadow,animation,typography-transform'),
const GalaxyComp(id: '0xnihilism_nasty-husky-13', cat: 'Cards', author: '0xnihilism', tags: 'newsletter,card,light,box-shadow,hover button,cool card,brutalism', html: '<div class="card">\n  <span class="card__title">Newsletter</span>\n  <p class="card__content">\n    Get existential crisis delivered straight to your inbox every week.\n  </p>\n  <form class="card__form">\n    <input required="" type="email" placeholder="Your life" />\n    <button class="card__button">Click me</button>\n  </form>\n</div>', css: '\n/* From Uiverse.io by 0xnihilism  - Tags: newsletter, card, light, box-shadow, hover button, cool card, brutalism */\n.card {\n  width: 300px;\n  padding: 20px;\n  background: #fff;\n  border: 6px solid #000;\n  box-shadow: 12px 12px 0 #000;\n  transition: transform 0.3s, box-shadow 0.3s;\n}\n\n.card:hover {\n  transform: translate(-5px, -5px);\n  box-shadow: 17px 17px 0 #000;\n}\n\n.card__title {\n  font-size: 32px;\n  font-weight: 900;\n  color: #000;\n  text-transform: uppercase;\n  margin-bottom: 15px;\n  display: block;\n  position: relative;\n  overflow: hidden;\n}\n\n.card__title::after {\n  content: "";\n  position: absolute;\n  bottom: 0;\n  left: 0;\n  width: 90%;\n  height: 3px;\n  background-color: #000;\n  transform: translateX(-100%);\n  transition: transform 0.3s;\n}\n\n.card:hover .card__title::after {\n  transform: translateX(0);\n}\n\n.card__content {\n  font-size: 16px;\n  line-height: 1.4;\n  color: #000;\n  margin-bottom: 20px;\n}\n\n.card__form {\n  display: flex;\n  flex-direction: column;\n  gap: 15px;\n}\n\n.card__form input {\n  padding: 10px;\n  border: 3px solid #000;\n  font-size: 16px;\n  font-family: inherit;\n  transition: transform 0.3s;\n  width: calc(100% - 26px); /* Adjust for padding and border */\n}\n\n.card__form input:focus {\n  outline: none;\n  transform: scale(1.05);\n  background-color: #000;\n  color: #ffffff;\n}\n\n.card__button {\n  border: 3px solid #000;\n  background: #000;\n  color: #fff;\n  padding: 10px;\n  font-size: 18px;\n  left: 20%;\n  font-weight: bold;\n  text-transform: uppercase;\n  cursor: pointer;\n  position: relative;\n  overflow: hidden;\n  transition: transform 0.3s;\n  width: 50%;\n  height: 100%;\n}\n\n.card__button::before {\n  content: "Sure?";\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 105%;\n  background-color: #5ad641;\n  color: #000;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  transform: translateY(100%);\n  transition: transform 0.3s;\n}\n\n.card__button:hover::before {\n  transform: translateY(0);\n}\n\n.card__button:active {\n  transfor', colors: '#000,#ffffff,#fff,#5ad641', radii: '', shadows: '12px 12px 0 #000,17px 17px 0 #000', techniques: '3d-transform,animation,typography-transform,pseudo-elements'),
const GalaxyComp(id: '0xnihilism_thin-crab-36', cat: 'Cards', author: '0xnihilism', tags: 'icon,minimalist,notification,card,hover,brutalist', html: '<div class="brutalist-card">\n  <div class="brutalist-card__header">\n    <div class="brutalist-card__icon">\n      <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">\n        <path\n          d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z"\n        ></path>\n      </svg>\n    </div>\n    <div class="brutalist-card__alert">Warning</div>\n  </div>\n  <div class="brutalist-card__message">\n    This is a brutalist card with a very angry button. Proceed with caution,\n    you\'ve been warned.\n  </div>\n  <div class="brutalist-card__actions">\n    <a class="brutalist-card__button brutalist-card__button--mark" href="#"\n      >Mark as Read</a\n    >\n    <a class="brutalist-card__button brutalist-card__button--read" href="#"\n      >Okay</a\n    >\n  </div>\n</div>', css: '\n/* From Uiverse.io by 0xnihilism  - Tags: icon, minimalist, notification, card, hover, brutalist */\n.brutalist-card {\n  width: 320px;\n  border: 4px solid #000;\n  background-color: #fff;\n  padding: 1.5rem;\n  box-shadow: 10px 10px 0 #000;\n  font-family: "Arial", sans-serif;\n}\n\n.brutalist-card__header {\n  display: flex;\n  align-items: center;\n  gap: 1rem;\n  margin-bottom: 1rem;\n  border-bottom: 2px solid #000;\n  padding-bottom: 1rem;\n}\n\n.brutalist-card__icon {\n  flex-shrink: 0;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  background-color: #000;\n  padding: 0.5rem;\n}\n\n.brutalist-card__icon svg {\n  height: 1.5rem;\n  width: 1.5rem;\n  fill: #fff;\n}\n\n.brutalist-card__alert {\n  font-weight: 900;\n  color: #000;\n  font-size: 1.5rem;\n  text-transform: uppercase;\n}\n\n.brutalist-card__message {\n  margin-top: 1rem;\n  color: #000;\n  font-size: 0.9rem;\n  line-height: 1.4;\n  border-bottom: 2px solid #000;\n  padding-bottom: 1rem;\n  font-weight: 600;\n}\n\n.brutalist-card__actions {\n  margin-top: 1rem;\n}\n\n.brutalist-card__button {\n  display: block;\n  width: 100%;\n  padding: 0.75rem;\n  text-align: center;\n  font-size: 1rem;\n  font-weight: 700;\n  text-transform: uppercase;\n  border: 3px solid #000;\n  background-color: #fff;\n  color: #000;\n  position: relative;\n  transition: all 0.2s ease;\n  box-shadow: 5px 5px 0 #000;\n  overflow: hidden;\n  text-decoration: none;\n  margin-bottom: 1rem;\n}\n\n.brutalist-card__button--read {\n  background-color: #000;\n  color: #fff;\n}\n\n.brutalist-card__button::before {\n  content: "";\n  position: absolute;\n  top: 0;\n  left: -100%;\n  width: 100%;\n  height: 100%;\n  background: linear-gradient(\n    120deg,\n    transparent,\n    rgba(255, 255, 255, 0.3),\n    transparent\n  );\n  transition: all 0.6s;\n}\n\n.brutalist-card__button:hover::before {\n  left: 100%;\n}\n\n.brutalist-card__button:hover {\n  transform: translate(-2px, -2px);\n  box-shadow: 7px 7px 0 #000;\n}\n\n.brutalist-card__button--mark:hover {\n  background-color: #296fbb;\n  border-color: #296fbb;', colors: '#ff0000,#296fbb,#000,#800000,#004280,#fff', radii: '', shadows: '10px 10px 0 #000,5px 5px 0 #000,7px 7px 0 #000', techniques: 'gradient,typography-transform,svg-icon,pseudo-elements'),
