th: 200px;\n  height: 35%;\n  background-color: blue;\n  position: absolute;\n  z-index: -1;\n  left: 0;\n  top: 0;\n  display: flex;\n  font-size: 30px;\n  align-items: center;\n  justify-content: center;\n  text-align: center;\n  color: #fff;\n}\n\n.card::before {\n  content: \'france\';\n  color: #fff;\n  text-transform: uppercase;\n  width: 200px;\n  height: 35%;\n  background-color: red;\n  position: absolute;\n  z-index: -1;\n  right: 0;\n  bottom: 0;\n  text-align: center;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 30px;\n}\n\n.card:hover {\n  transform: scale(1.1);\n}\n\n.card svg {\n  width: 100px;\n  align-items: center;\n  display: flex;\n  justify-content: center;\n  margin-left: auto;\n  margin-right: auto;\n}\n\n', colors: '#fff', radii: '8px', shadows: '', techniques: '3d-transform,typography-transform,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'Admin12121_average-parrot-89', cat: 'Cards', author: 'Admin12121', tags: 'card,cardhover,card animation', html: '<div class="main">\n<div class="card">\n  <div class="card-content">\n    <div class="h3"><span>UI</span>VERSE</div>\n    <div class="h1">Love to Code.</div>\n    <p class="p">Love to spend hours in codeing and get lost in own fantasy world of code, the feeling 😂🚀😊 </p>\n  </div>\n</div>\n</div>', css: '\n/* From Uiverse.io by Admin12121 - Tags: card, cardhover , card animation */\n.h3 span {\n  font-weight: 800;\n  background: linear-gradient(125deg, #b663ff, #13c1ef);\n  text-transform: uppercase;\n  -webkit-background-cLip: text;\n  -webkit-text-filL-coLor: transparent;\n}\n\n.h3::after {\n  content: \'\';\n  margin-top: -5px;\n  height: 3px;\n  width: 25%;\n  background: linear-gradient(125deg, #b663ff, #13c1ef);\n  display: block;\n}\n\n.main {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n.card {\n  width: 80%;\n  position: relative;\n  background-color: rgb(16 16 16);\n  border: 1px solid rgb(255 255 255 / 5%);\n  border-radius: 1.5rem;\n  padding: 1rem;\n}\n\n.card:after {\n  content: "";\n  height: 70px;\n  width: 1px;\n  position: absolute;\n  left: -1px;\n  top: 65%;\n  transition: top, opacity;\n  transition-duration: 600ms;\n  transition-timing-function: ease;\n  background: linear-gradient(transparent, mediumslateblue,transparent);\n  box-shadow: 0 0 30px mediumslateblue;\n  opacity: 0;\n}\n\n.card:after {\n  top: 65%;\n  opacity: 0;\n}\n\n.card:hover:after {\n  top: 25%;\n  opacity: 1;\n}\n\n.card-content {\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  align-items: center;\n  background-image: radial-gradient(\n    rgba(255, 255, 255, 0.1) 1px, \n    transparent 1px\n  );\n  background-position: 50% 50%;\n  background-size: 1.1rem 1.1rem;\n  padding: 2.3rem;\n  border-radius: 1.25rem;\n  overflow: hidden;\n}\n\n.card-content .h1,.h3,.p {\n  text-align: center;\n}\n\n.card-content .h1 {\n  color: rgb(250 249 246);\n  font-size: 2.6rem;\n}\n\n.card-content  .h3 {\n  color: #fff;\n  text-transform: uppercase;\n  font-size: 1.5rem;\n}\n\n.card-content  .p {\n  color: rgb(255 255 255 / 75%);\n  line-height: 1.3rem;\n}\n\n@media(max-width: 700px) {\n  .card {\n    width: calc(100% - 2rem);\n    margin: 0rem 1rem;\n    padding: 0.75rem;\n    border-radius: 1rem;\n  }\n}\n\n@media(max-width: 600px) {\n  .card-content {\n    padding: 3rem;\n  }\n\n  .card-content  .h1 {\n    font-size: 2.2rem;\n  }\n}\n\n', colors: '#13c1ef,#fff,#b663ff', radii: '1.25rem,1rem,1.5rem', shadows: '0 0 30px mediumslateblue', techniques: 'glow-shadow,gradient,typography-transform,pseudo-elements'),
const GalaxyComp(id: 'Admin12121_brown-bird-6', cat: 'Cards', author: 'Admin12121', tags: 'card,business card,card template,card design', html: '<div class="price-section">\n	<article class="price-table">\n		<div class="price"><small>\$</small>249</div>\n		<span class="title">Solo Version</span>\n		<span class="description">A single license for solo designers, developers and freelancers.\n		</span>\n		<div class="features">\n			\n			<details class="feature">\n				<summary>\n					<i aria-hidden="true" class="checkmark">\n						<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="24" height="24">\n							<path fill="none" d="M0 0h24v24H0z"></path>\n							<path fill="currentColor" d="M10 15.172l9.192-9.193 1.415 1.414L10 18l-6.364-6.364 1.414-1.414z"></path>\n						</svg>\n					</i>\n					<span class="name">Free updates</span>\n					<i aria-hidden="true" class="question-icon">\n						<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="24" height="24">\n							<path fill="none" d="M0 0h24v24H0z"></path>\n							<path fill="currentColor" d="M12 22C6.477 22 2 17.523 2 12S6.477 2 12 2s10 4.477 10 10-4.477 10-10 10zm0-2a8 8 0 1 0 0-16 8 8 0 0 0 0 16zm-1-5h2v2h-2v-2zm2-1.645V14h-2v-1.5a1 1 0 0 1 1-1 1.5 1.5 0 1 0-1.471-1.794l-1.962-.393A3.501 3.501 0 1 1 13 13.355z"></path>\n						</svg>\n					</i>\n				</summary>\n				<div class="answer">\n					You will gain access to every future update.\n				</div>\n			</details>\n			<details class="feature">\n				<summary>\n					<i aria-hidden="true" class="checkmark">\n						<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="24" height="24">\n							<path fill="none" d="M0 0h', css: '\n/* From Uiverse.io by Admin12121 - Tags: card, business card, card template, card design */\n.price-section {\n  color: #fff;\n}\n/* End basic CSS override */\n.price-table {\n  background-color: #152148;\n  border-radius: 16px;\n  max-width: 355px;\n  padding: 25px;\n  display: flex;\n  flex-direction: column;\n  box-shadow: 0 15px 45px 0 rgba(0, 0, 0, 0.15);\n  position: relative;\n  background-image: linear-gradient(135deg, rgba(74, 222, 128, 0.15), rgba(29, 123, 219, 0.1) 20%, #152148 40%, #152148 100%);\n}\n\n.price-table:after {\n  content: "";\n  display: block;\n  top: -3px;\n  left: -3px;\n  bottom: -3px;\n  right: -3px;\n  z-index: -1;\n  position: absolute;\n  border-radius: 16px;\n  background-image: linear-gradient(135deg, #4ade80, #1d7bdb 40%, #293359 60%, #152148 100%);\n}\n\n.price-table .price {\n  font-size: 3rem;\n  line-height: 1;\n  font-weight: 700;\n  display: inline-flex;\n  align-self: center;\n  align-items: center;\n  gap: 4px;\n  position: relative;\n  color: #fff;\n}\n\n.price-table .price small {\n  font-size: 1.25rem;\n  font-weight: 400;\n  position: absolute;\n  left: -1.5ch;\n}\n\n.price-table .title {\n  font-size: 1.25rem;\n  font-weight: 600;\n  line-height: 1.25;\n  text-align: center;\n  margin-top: 10px;\n  color: #fff;\n}\n\n.price-table .description {\n  font-size: 1rem;\n  text-align: center;\n  margin-top: 2px;\n}\n\n.features {\n  margin-top: 22px;\n}\n\n.feature {\n  position: relative;\n}\n\n.feature + .feature {\n  margin-top: 16px;\n}\n\n.feature summary {\n  display: inline-flex;\n  align-items: center;\n  list-style: none;\n}\n\n.feature summary::-webkit-details-marker {\n  display: none;\n}\n\n.feature[open] summary:after {\n  content: "";\n  display: block;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  position: fixed;\n  z-index: 50;\n}\n\n.feature[open] div {\n  -webkit-animation: scale 0.15s ease;\n  animation: scale 0.15s ease;\n}\n\n.feature .checkmark {\n  width: 24px;\n  height: 24px;\n  border-radius: 50%;\n  background-color: #4ade80;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n', colors: '#293359,#1d7bdb,#152148,#4ade80,#111b40,#fff', radii: '50%,6px,16px', shadows: '0 15px 45px 0 rgba(0, 0, 0, 0.15),0 15px 30px 0 rgba(0, 0, 0, 0.1)', techniques: '3d-transform,gradient,animation,svg-icon'),
const GalaxyComp(id: 'Admin12121_fluffy-vampirebat-68', cat: 'Cards', author: 'Admin12121', tags: 'card,popup', html: '<div class="wrapper">\n\n<article>\n	<span class="h1">How to create a pop-up without JavaScript</span>\n	<p>Ever wanted a pop-up mechanism on your website, but you don\'t want to use JavaScript? Here\'s how:</p>\n\n	<p>Toggle the <strong>How it works</strong> button for more info.</p>\n\n</article>\n\n<details>\n	<summary>How it works<svg viewBox="0 0 256 256" fill="currentColor" height="192" width="192" xmlns="http://www.w3.org/2000/svg"><rect fill="none" height="256" width="256"></rect><circle stroke-width="16" stroke-linejoin="round" stroke-linecap="round" stroke="currentColor" fill="none" r="96" cy="128" cx="128"></circle><circle r="12" cy="180" cx="128"></circle><path stroke-width="16" stroke-linejoin="round" stroke-linecap="round" stroke="currentColor" fill="none" d="M127.9995,144.0045v-8a28,28,0,1,0-28-28"></path></svg></summary>\n	<div>\n			<p>The scaling effect you see when you open this <code>&lt;details&gt;</code> element is created by using a keyframe animation.</p>\n		<p></p><pre><code>@keyframes scale { \n&nbsp;0% {\n&nbsp;&nbsp;transform: scale(0);\n&nbsp;}\n&nbsp;100% {\n&nbsp;&nbsp;transform: scale(1);\n&nbsp;}\n}</code></pre> <p></p>\n<p>This animation is added to the <code>&lt;div&gt;</code>, but only when the <code>[open]</code> attribute is toggled.</p>\n<p></p><pre><code>details[open] div { \n&nbsp;animation: scale .15s ease;\n}</code></pre><p></p>\n	<p>Sadly there\'s no way (that I know of) to animate the  <code>&lt;div&gt;</code> when the  <code>&lt;details&gt;</code> is closing.<', css: '\n/* From Uiverse.io by Admin12121 - Tags: card, popup */\n.wrapper {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  flex-direction: column;\n}\n\narticle {\n  margin-top: 50px;\n  width: 90%;\n  max-width: 600px;\n  margin-left: auto;\n  margin-right: auto;\n  font-size: 1.125rem;\n  padding: 1.5rem;\n  background-color: #fff;\n  border-radius: 10px;\n  box-shadow: 0 15px 20px -10px rgba(0, 0, 0, 0.1);\n}\n\narticle > * + * {\n  margin-top: 0.5em;\n}\n\narticle:is(h1, h2, h3) + * {\n  margin-top: 0.5em;\n}\n\narticle .h1 {\n  font-weight: 900;\n  font-size: 2rem;\n  line-height: 1.125;\n}\n\narticle code {\n  background-color: #eee;\n  font-weight: 600;\n  font-family: monospace;\n}\n\ndetails {\n  position: relative;\n  right: 16px;\n  margin-top: 35px;\n  bottom: 16px;\n  color: #6b7280;\n  display: flex;\n  flex-direction: column;\n}\n\ndetails div {\n  background-color: #1e1e27;\n  box-shadow: 0 5px 10px rgba(0, 0, 0, 0.15);\n  padding: 1rem;\n  border-radius: 8px;\n  position: absolute;\n  height: 350px;\n  width: 400px;\n  bottom: calc(100% + 1rem);\n  right: -50%;\n  overflow: auto;\n  transform-origin: 100% 100%;\n  color: #95a3b9;\n}\n\ndetails div::-webkit-scrollbar {\n  width: 15px;\n  background-color: #1e1e27;\n}\n\ndetails div::-webkit-scrollbar-thumb {\n  width: 5px;\n  border-radius: 99em;\n  background-color: #95a3b9;\n  border: 5px solid #1e1e27;\n}\n\ndetails div > * + * {\n  margin-top: 0.75em;\n}\n\ndetails div p > code {\n  font-size: 1rem;\n  font-family: monospace;\n}\n\ndetails div pre {\n  white-space: pre-line;\n  border: 1px solid #95a3b9;\n  border-radius: 6px;\n  font-family: monospace;\n  padding: 0.75em;\n  font-size: 0.875rem;\n  color: #fff;\n}\n\ndetails[open] div {\n  -webkit-animation: scale 0.25s ease;\n  animation: scale 0.25s ease;\n}\n\nsummary {\n  display: inline-flex;\n  margin-left: auto;\n  margin-right: auto;\n  justify-content: center;\n  align-items: center;\n  font-weight: 600;\n  padding: 0.75em 3em 0.75em 1.25em;\n  border-radius: 99em;\n  color: #fff;\n  background-color: #185adb;\n  box-shadow: 0 5', colors: '#1e1e27,#185adb,#95a3b9,#1348af,#eee,#6b7280,#fff', radii: '10px,6px,99em,8px', shadows: '0 15px 20px -10px rgba(0, 0, 0, 0.1),0 5px 10px rgba(0, 0, 0, 0.15),0 5px 15px rgba(0, 0, 0, 0.1)', techniques: '3d-transform,animation,details-accordion,svg-icon'),
const GalaxyComp(id: 'ahmedgamal-hub_popular-starfish-56', cat: 'Cards', author: 'ahmedgamal-hub', tags: 'card,about me,blur filter,animated,circle loader,border,advanced,box-shadow', html: '<div class="one-div"></div>', css: '\n/* From Uiverse.io by ahmedgamal-hub - Tags: card, about me, blur filter, animated, circle loader, border, advanced, box-shadow */\n@-webkit-keyframes spinner-border {\n  to {\n    -webkit-transform: rotate(360deg);\n    transform: rotate(360deg);\n  }\n}\n\n@keyframes spinner-border {\n  to {\n    -webkit-transform: rotate(360deg);\n    transform: rotate(360deg);\n  }\n}\n\n.one-div {\n  position: relative;\n  font-size: 20px;\n  color: #fff;\n  text-align: center;\n  display: inline-block;\n  width: 15rem;\n  height: 15rem;\n  vertical-align: text-center;\n}\n\n.one-div::after {\n  content: \'\';\n  position: absolute;\n  left: 0;\n  top: -10px;\n  width: 100%;\n  height: 100%;\n  border: 0.25em solid currentColor;\n  border-right-color: #2AE4FF;\n  border-top-color: #2AE4FF;\n  border-bottom-color: #2AE4FF;\n  border-radius: 50%;\n  box-shadow: 0 0 3px #fff, 0 0 10px #fff, 0 0 20px #fff, 0 0 40px #0ba9ca,\n  0 0 110px #ED306F, 0 0 80px #0ba9ca;\n  -webkit-animation: spinner-border 7s linear infinite;\n  animation: spinner-border 7s linear infinite;\n}\n\n\n', colors: '#ed306f,#fff,#0ba9ca,#2ae4ff', radii: '50%', shadows: '0 0 3px #fff, 0 0 10px #fff, 0 0 20px #fff, 0 0 40px #0ba9ca,\n  0 0 110px #ED306F, 0 0 80px #0ba9ca', techniques: '3d-transform,glow-shadow,animation,pseudo-elements'),
const GalaxyComp(id: 'alexroumi_polite-dodo-16', cat: 'Cards', author: 'alexroumi', tags: 'minimalist,social,card,social media,light&dark', html: '<div class="card">\n  <img\n    class="image"\n    alt=""\n    src="https://uiverse.io/build/_assets/astronaut-WTFWARES.png"\n  />\n  <div class="heading">We\'re on Social Media</div>\n  <div class="icons">\n    <a class="instagram" href="https://www.instagram.com/uiverse.io/">\n      <svg\n        xmlns="http://www.w3.org/2000/svg"\n        fill="none"\n        viewBox="0 0 24 25"\n        height="25"\n        width="24"\n      >\n        <path\n          stroke-linejoin="round"\n          stroke-linecap="round"\n          stroke-width="2"\n          stroke="currentColor"\n          d="M17.0459 7.5H17.0559M3.0459 12.5C3.0459 9.986 3.0459 8.73 3.3999 7.72C3.71249 6.82657 4.22237 6.01507 4.89167 5.34577C5.56096 4.67647 6.37247 4.16659 7.2659 3.854C8.2759 3.5 9.5329 3.5 12.0459 3.5C14.5599 3.5 15.8159 3.5 16.8269 3.854C17.7202 4.16648 18.5317 4.67621 19.201 5.34533C19.8702 6.01445 20.3802 6.82576 20.6929 7.719C21.0459 8.729 21.0459 9.986 21.0459 12.5C21.0459 15.014 21.0459 16.27 20.6929 17.28C20.3803 18.1734 19.8704 18.9849 19.2011 19.6542C18.5318 20.3235 17.7203 20.8334 16.8269 21.146C15.8169 21.5 14.5599 21.5 12.0469 21.5C9.5329 21.5 8.2759 21.5 7.2659 21.146C6.37268 20.8336 5.56131 20.324 4.89202 19.6551C4.22274 18.9862 3.71274 18.1751 3.3999 17.282C3.0459 16.272 3.0459 15.015 3.0459 12.501V12.5ZM15.8239 11.94C15.9033 12.4387 15.8829 12.9481 15.7641 13.4389C15.6453 13.9296 15.4304 14.392 15.1317 14.7991C14.833 15.2063 14.4566 15.5501 14.0242 15.8108C13.5917 16.0715 13.1119 16.2439 12.6124 16.318C', css: '\n/* From Uiverse.io by alexroumi  - Tags: minimalist, social, card, social media, light&dark */\n.card {\n  background-color: #ffd093;\n  background: radial-gradient(\n    circle,\n    rgba(147, 119, 91, 1) 0%,\n    rgba(255, 208, 147, 1) 50%\n  );\n  aspect-ratio: 4/5;\n  height: 27rem;\n  border-radius: 25px;\n  padding: 10px;\n  outline: 5px solid #56300b;\n  outline-offset: -15px;\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n}\n\n.image {\n  align-self: center;\n}\n\n.card::before {\n  width: 10px;\n  height: 10px;\n  background-color: blue;\n  position: absolute;\n  top: 10px;\n  left: 10px;\n}\n\n.image {\n  filter: sepia(70%) saturate(100%) brightness(70%) hue-rotate(100deg)\n    brightness(1.1);\n  width: 230px;\n}\n\n.heading {\n  text-align: center;\n}\n\n.icons {\n  display: flex;\n  justify-content: center;\n  gap: 7px;\n  margin-top: 5px;\n  padding-bottom: 10px;\n}\n\n.discord,\n.x,\n.instagram {\n  color: #56300b;\n}\n\n', colors: '#56300b,#ffd093', radii: '25px', shadows: '', techniques: 'gradient,filter-effect,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'alexruix_heavy-elephant-39', cat: 'Cards', author: 'alexruix', tags: 'gradient,card', html: '<div class="card">\n  <div class="card-info">\n    <p class="title">Magic Card</p>\n  </div>\n</div>', css: '\n/* From Uiverse.io by alexruix - Tags: gradient, card */\n.card {\n --background: linear-gradient(to left, #f7ba2b 0%, #ea5358 100%);\n width: 190px;\n height: 254px;\n padding: 5px;\n border-radius: 1rem;\n overflow: visible;\n background: #f7ba2b;\n background: var(--background);\n position: relative;\n z-index: 1;\n}\n\n.card::after {\n position: absolute;\n content: "";\n top: 30px;\n left: 0;\n right: 0;\n z-index: -1;\n height: 100%;\n width: 100%;\n transform: scale(0.8);\n filter: blur(25px);\n background: #f7ba2b;\n background: var(--background);\n transition: opacity .5s;\n}\n\n.card-info {\n --color: #181818;\n background: var(--color);\n color: var(--color);\n display: flex;\n justify-content: center;\n align-items: center;\n width: 100%;\n height: 100%;\n overflow: visible;\n border-radius: .7rem;\n}\n\n.card .title {\n font-weight: bold;\n letter-spacing: .1em;\n}\n\n/*Hover*/\n.card:hover::after {\n opacity: 0;\n}\n\n.card:hover .card-info {\n color: #f7ba2b;\n transition: color 1s;\n}\n\n', colors: '#f7ba2b,#181818,#ea5358', radii: '1rem,.7rem', shadows: '', techniques: 'glassmorphism,3d-transform,gradient,pseudo-elements'),
const GalaxyComp(id: 'andrew-demchenk0_hard-cougar-86', cat: 'Cards', author: 'andrew-demchenk0', tags: 'animation,card,hover,light,product,project,hover effect', html: '<div class="card">\n    <div class="card__img"><svg viewBox="0 0 128 128" xml:space="preserve" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink"><rect class="st1" height="78.6" transform="matrix(0.9761 0.2175 -0.2175 0.9761 15.4391 -12.3278)" width="101.2" x="13.1" y="24.7"></rect><rect class="st53" height="78.6" transform="matrix(0.9761 0.2175 -0.2175 0.9761 15.4391 -12.3278)" width="101.2" x="13.1" y="24.7"></rect><polygon class="st16" points="116,62 116,35.4 38.1,18 22.1,18 5.8,91.3 76.2,107 106,107"></polygon><polygon class="st1" points="97.2,23 10,23 10,102 111,102 111,36.8"></polygon><polygon class="st53" points="97.2,23 10,23 10,102 111,102 111,36.8"></polygon><g><rect class="st7" height="58" width="80" x="20" y="34"></rect><g><polygon class="st9" points="100.2,92 73.1,44.2 51.2,75.5 40,58.7 20.2,92 39.7,92"></polygon><circle class="st18" cx="57" cy="52" r="11"></circle><polygon class="st1" points="40,58.5 31.6,72.6 34.6,78.2 37.9,75.2 43.5,79.9 47,78.2 51,75.2"></polygon><path class="st1" d="M57.7,66c0,0,4.1,7.2,4.3,6.6c0.2-0.6,6.1-5.6,6.1-5.6l6.9,3.6l1.5-10.3L88.9,72L73.1,44.1L57.7,66z"></path><polygon class="st15" points="73.1,44.2 83.6,92 100.2,92"></polygon><polyline class="st2" points="100.2,91.9 73.1,44.1 39.7,91.9"></polyline><polyline class="st2" points="51.2,75.4 40,58.5 20.2,91.9"></polyline><polygon class="st15" points="51.2,75.4 40,58.5 47,81.3"></polygon><polyline class="st2" points="51.5,91.9 67.1,70.5 80.4,91.9"></polyline><po', css: '\n/* From Uiverse.io by andrew-demchenk0 - Tags: animation, card, hover, light, product, project, hover effect */\n.card {\n  --main-color: #323232;\n  --sub-color: #5b5b5b;\n  --bg-color: #c7c7c7;\n  --accent-color: #242C88;\n  position: relative;\n  font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Roboto, Oxygen, Ubuntu, Cantarell, \'Open Sans\', \'Helvetica Neue\', sans-serif;\n  width: 270px;\n  padding: 25px;\n  border-radius: 25px;\n  display: flex;\n  flex-direction: column;\n  gap: 5px;\n  background-color: var(--bg-color);\n  transition: all 0.2s;\n  cursor: pointer;\n  box-shadow: 0px 0px 5px -1.5px #000;\n}\n\n.card::before {\n  content: \'\';\n  width: 99%;\n  height: 99%;\n  background: var(--sub-color);\n  position: absolute;\n  z-index: -1;\n  top: 1px;\n  left: 1px;\n  border-radius: 25px;\n  transition: all 0.3s;\n}\n\n.card__wrapper {\n  display: flex;\n  flex-direction: row;\n  justify-content: space-between;\n  align-items: center;\n}\n\n.card__img {\n  width: 100%;\n}\n\n.card__title {\n  color: var(--main-color);\n  font-weight: 900;\n  font-size: 25px;\n}\n\n.card__subtitle {\n  color: var(--sub-color);\n  font-weight: 600;\n  font-size: 20px;\n}\n\n.card__icon {\n  width: 40px;\n  height: 40px;\n  transform: rotate(-45deg);\n  transition: all 0.3s;\n}\n\n.card__icon svg {\n  width: 100%;\n  height: 100%;\n}\n\n.card__icon g {\n  fill: var(--main-color);\n}\n\n.card__icon circle, polyline, line {\n  stroke: var(--main-color);\n}\n\n.card:hover .card__icon {\n  transform: rotate(0);\n}\n\n.card:hover .card__icon circle, .card:hover .card__icon polyline, .card:hover .card__icon line {\n  stroke: var(--accent-color);\n}\n\n.card:hover .card__icon g {\n  fill: var(--accent-color);\n}\n\n.card:hover {\n  box-shadow: 0px 0px 20px -5px #000;\n}\n\n.card:hover::before {\n  transform: rotate(10deg);\n  box-shadow: 0px 0px 20px -5px #000;\n}\n\n/* remove svg from class ="card__img" and last styles below css code before use */\n.st1 {\n  fill: #fff\n}\n\n.st2 {\n  fill: none;\n  stroke: #242c88;\n  stroke-width: 2;\n  stroke-linecap: round;\n  stroke-line', colors: '#242c88,#c7c7c7,#323232,#5b5b5b,#589fff,#000,#ffc408,#bc8d66,#fff', radii: '25px', shadows: '0px 0px 5px -1.5px #000,0px 0px 20px -5px #000,0px 0px 20px -5px #000', techniques: '3d-transform,glow-shadow,svg-icon,pseudo-elements'),
