const GalaxyComp(id: 'bhaveshxrawat_dangerous-quail-58', cat: 'Cards', author: 'bhaveshxrawat', tags: 'card', html: '<div class="card">\n    <h2>CARD</h2>\n</div>', css: '\n/* From Uiverse.io by bhaveshxrawat - Tags: card */\n.card {\n  width: 190px;\n  height: 254px;\n  background: #07182E;\n  position: relative;\n  display: flex;\n  place-content: center;\n  place-items: center;\n  overflow: hidden;\n  border-radius: 20px;\n}\n\n.card h2 {\n  z-index: 1;\n  color: white;\n  font-size: 2em;\n}\n\n.card::before {\n  content: \'\';\n  position: absolute;\n  width: 100px;\n  background-image: linear-gradient(180deg, rgb(0, 183, 255), rgb(255, 48, 255));\n  height: 130%;\n  animation: rotBGimg 3s linear infinite;\n  transition: all 0.2s linear;\n}\n\n@keyframes rotBGimg {\n  from {\n    transform: rotate(0deg);\n  }\n\n  to {\n    transform: rotate(360deg);\n  }\n}\n\n.card::after {\n  content: \'\';\n  position: absolute;\n  background: #07182E;\n  ;\n  inset: 5px;\n  border-radius: 15px;\n}  \n/* .card:hover:before {\n  background-image: linear-gradient(180deg, rgb(81, 255, 0), purple);\n  animation: rotBGimg 3.5s linear infinite;\n} */\n\n\n', colors: '#07182e', radii: '15px,20px', shadows: '', techniques: '3d-transform,gradient,animation,pseudo-elements'),
const GalaxyComp(id: 'Brola2008_calm-octopus-51', cat: 'Cards', author: 'Brola2008', tags: 'gradient,card,box-shadow', html: '<div class="one-div"></div>', css: '\n/* From Uiverse.io by Brola2008 - Tags: gradient, card, box-shadow */\n.one-div {\n  width: 190px;\n  height: 250px;\n  background: linear-gradient(-45deg, rgb(9, 16, 109) ,  rgba(0,255,239,1));\n  border-radius: 20px;\n  box-shadow: 10px 10px 15px rgba(0, 0, 0, 0.5);\n  transition: 0.5s ease;\n}\n\n.one-div::after {\n  content: "HOVER ME";\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%,-50%);\n  font-weight: bold;\n  text-shadow: 1px 1px 4px rgb(0,0,0);\n  transition: .3s;\n}\n\n.one-div:hover {\n  scale: 1.1;\n  border-radius: 20px 80px;\n  box-shadow: 11px 11px 25px rgba(0, 0, 0, 0.5);\n}\n\n.one-div:hover::after {\n  content: "THANKS";\n  color: aqua;\n}\n\n', colors: '', radii: '20px 80px,20px', shadows: '10px 10px 15px rgba(0, 0, 0, 0.5),11px 11px 25px rgba(0, 0, 0, 0.5)', techniques: '3d-transform,text-shadow,gradient,pseudo-elements'),
