9e45af, #e54dd3);\n  height: 298px;\n  width: 238px;\n  position: absolute;\n  top: -4px;\n  left: -4px;\n  z-index: -1;\n  border-radius: 24px;\n}\n\n.heading {\n  line-height: 10px;\n  font-size: 18px;\n  text-align: center;\n  font-weight: bold;\n  color: white;\n}\n\n.heading span {\n  position: relative;\n  top: 22px;\n  font-size: 50px;\n  font-weight: bolder;\n  background: linear-gradient(233deg, #091296, #580aab, #9e45af, #e54dd3);\n  background-size: 400% 400%;\n  animation: galaxy_background 7s ease infinite;\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n  z-index: 10;\n}\n\n.heading span::after {\n  content: \'Galaxy\';\n  position: absolute;\n  padding-top: 20px;\n  translate: 0px -19px;\n  left: 0;\n  top: 25px;\n  width: 100%;\n  height: 100%;\n  background-image: radial-gradient(#ffffff 1px, transparent 0);\n  background-size: 15px 20px;\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n  color: rgba(0, 0, 0, 0);\n  animation: infinite galaxy_bg_dots 3s linear;\n  pointer-events: none;\n}\n\n.item {\n  color: white;\n  font-weight: bold;\n  width: fit-content;\n  height: fit-content;\n  position: absolute;\n  transition: 0.2s;\n  cursor: pointer;\n}\n\n.item--create:hover {\n  color: #9e45af;\n}\n\n.item--post:hover {\n  color: #580aab;\n}\n\n.item--inspire:hover {\n  color: #e54dd3;\n}\n\n.item svg {\n}\n\n.item--create {\n  top: 80px;\n  left: 15px;\n  rotate: -5deg;\n}\n\n.item--create::before {\n  content: \'\';\n  position: absolute;\n  height: 6px;\n  width: 6px;\n  border-radius: 3px;\n  background-color: white;\n  top: 25px;\n  left: 80px;\n  animation: infinite dots 3.5s;\n  animation-delay: 0s;\n  scale: 0;\n  opacity: 0;\n}\n\n.item', colors: '#e54dd3,#091296,#161617,#323232,#580aab,#9e45af,#ffffff', radii: '24px,10px,20px,3px', shadows: '', techniques: 'gradient,animation,svg-icon,pseudo-elements'),
const GalaxyComp(id: 'DellBee_honest-pug-16', cat: 'Cards', author: 'DellBee', tags: 'card', html: '<div class="card">\n    <div class="heading">Join the Open-Source <span>Galaxy</span></div>\n    <div class="content">\n        <div class="item item--create">\n            <svg height="24" width="24" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">\n                <path d="M24 12L18.3431 17.6569L16.9289 16.2426L21.1716 12L16.9289 7.75736L18.3431 6.34315L24 12ZM2.82843 12L7.07107 16.2426L5.65685 17.6569L0 12L5.65685 6.34315L7.07107 7.75736L2.82843 12ZM9.78845 21H7.66009L14.2116 3H16.3399L9.78845 21Z" fill="currentColor"></path>\n            </svg>\n            <span>Create</span>\n        </div>\n        <div class="item item--post">\n            <svg height="24" width="24" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">\n                <path d="M4.99958 12.9998C4.99958 7.91186 7.90222 3.56348 11.9996 1.81787C16.0969 3.56348 18.9996 7.91186 18.9996 12.9998C18.9996 13.8227 18.9236 14.6263 18.779 15.4026L20.7194 17.2352C20.8845 17.3911 20.9238 17.6388 20.815 17.8381L18.3196 22.4132C18.1873 22.6556 17.8836 22.7449 17.6412 22.6127C17.5993 22.5898 17.5608 22.5611 17.5271 22.5273L15.2925 20.2927C15.1049 20.1052 14.8506 19.9998 14.5854 19.9998H9.41379C9.14857 19.9998 8.89422 20.1052 8.70668 20.2927L6.47209 22.5273C6.27683 22.7226 5.96025 22.7226 5.76498 22.5273C5.73122 22.4935 5.70246 22.4551 5.67959 22.4132L3.18412 17.8381C3.07537 17.6388 3.11464 17.3911 3.27975 17.2352L5.22014 15.4026C5.07551 14.6263 4.99958 13.8227 4.99958 12.9998ZM6.47542 19.6955L7.29247 18.8785C7.85508 18', css: '\n/* From Uiverse.io by DellBee - Tags: card */\n.card {\n  border: 3px solid rgb(20, 228, 255);\n  height: 250px;\n  width: 300px;\n  border-radius: 20px;\n  color: white;\n  opacity: 0.5;\n  transition: all 0.2s;\n}\n\n.card:hover {\n  opacity: 2;\n  filter: drop-shadow( 0 0 10px rgb(20, 228, 255)) drop-shadow(0 0 60px rgb(20, 228, 255));\n}\n\n.card:hover ~ .heading {\n  filter: drop-shadow( 0 0 10px rgb(248, 125, 146)) drop-shadow(0 0 60px rgb(248, 125, 146));\n}\n\n.card:hover ~ button {\n  filter: drop-shadow( 0 0 10px rgb(248, 125, 146)) drop-shadow(0 0 60px rgb(248, 125, 146));\n  box-shadow: inset 0 0 0 0 rgb(248, 125, 146);\n}\n\n.heading {\n  color: rgb(248, 125, 146);\n  display: flex;\n  justify-content: center;\n  font-weight: bolder;\n  position: relative;\n  top: 10px;\n}\n\n.content {\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  align-items: center;\n  position: relative;\n  top: 20px;\n}\n\n.item {\n  display: flex;\n  margin-top: 20px;\n  cursor: pointer;\n}\n\n.item svg {\n  display: flex;\n  position: relative;\n  right: 5px;\n}\n\n.item:hover {\n  color: rgb(248, 125, 146);\n  filter: drop-shadow( 0 0 10px rgb(248, 125, 146)) drop-shadow(0 0 60px rgb(248, 125, 146));\n}\n\n.item:hover svg {\n  right: 15px;\n  transition: all 0.3s;\n}\n\nbutton {\n  background-color: transparent;\n  color: white;\n  border: 2px solid rgb(248, 125, 146);\n  position: relative;\n  height: 30px;\n  top: 50px;\n  left: 50%;\n  transform: translate(-50%);\n  border-radius: 5px;\n  transition: ease-out 0.3s;\n}\n\nbutton:hover {\n  color: white;\n  box-shadow: inset -110px 0 0 0 rgb(248, 125, 146);\n  filter: drop-shadow( 0 0 10px rgb(248, 125, 146)) drop-shadow(0 0 60px rgb(248, 125, 146));\n}\n\nbutton:active {\n  transform: scale(0.8) translate(-50%)\n}\n\n\n\n\n', colors: '', radii: '20px,5px', shadows: 'inset 0 0 0 0 rgb(248, 125, 146),inset -110px 0 0 0 rgb(248, 125, 146)', techniques: '3d-transform,glow-shadow,filter-effect,svg-icon'),
const GalaxyComp(id: 'devkennyy_angry-panther-84', cat: 'Cards', author: 'devkennyy', tags: 'card', html: '<div class="card">\n    <div class="heading">Join the Open-Source <span>Galaxy</span></div>\n    <div class="content">\n        <div class="item item--create">\n            <svg height="24" width="24" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">\n                <path d="M24 12L18.3431 17.6569L16.9289 16.2426L21.1716 12L16.9289 7.75736L18.3431 6.34315L24 12ZM2.82843 12L7.07107 16.2426L5.65685 17.6569L0 12L5.65685 6.34315L7.07107 7.75736L2.82843 12ZM9.78845 21H7.66009L14.2116 3H16.3399L9.78845 21Z" fill="currentColor"></path>\n            </svg>\n            <span>Create</span>\n        </div>\n        <div class="item item--post">\n            <svg height="24" width="24" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">\n                <path d="M4.99958 12.9998C4.99958 7.91186 7.90222 3.56348 11.9996 1.81787C16.0969 3.56348 18.9996 7.91186 18.9996 12.9998C18.9996 13.8227 18.9236 14.6263 18.779 15.4026L20.7194 17.2352C20.8845 17.3911 20.9238 17.6388 20.815 17.8381L18.3196 22.4132C18.1873 22.6556 17.8836 22.7449 17.6412 22.6127C17.5993 22.5898 17.5608 22.5611 17.5271 22.5273L15.2925 20.2927C15.1049 20.1052 14.8506 19.9998 14.5854 19.9998H9.41379C9.14857 19.9998 8.89422 20.1052 8.70668 20.2927L6.47209 22.5273C6.27683 22.7226 5.96025 22.7226 5.76498 22.5273C5.73122 22.4935 5.70246 22.4551 5.67959 22.4132L3.18412 17.8381C3.07537 17.6388 3.11464 17.3911 3.27975 17.2352L5.22014 15.4026C5.07551 14.6263 4.99958 13.8227 4.99958 12.9998ZM6.47542 19.6955L7.29247 18.8785C7.85508 18', css: '\n/* From Uiverse.io by devkennyy - Tags: card */\n.card {\n  color: #fff;\n  margin: 40px auto;\n  background-color: rgba(255,255,255,0.06);\n  border: 1px solid rgba(255,255,255,0.1);\n  width: 100%;\n  border-radius: 15px;\n  padding: 32px;\n  backdrop-filter: blur(10px);\n}\n\n.heading {\n  font-weight: 700;\n  margin-bottom: 15px;\n  text-align: center;\n  text-shadow: 1px 1px 2px rgba(0, 0, 0, 0.3);\n}\n\n.heading span {\n  display: inline-block;\n  background-clip: text;\n  color: #3498db;\n}\n\n.content {\n  display: flex;\n  justify-content: space-around;\n  margin-bottom: 20px\n}\n\n.item {\n  align-items: center;\n  display: flex;\n  flex-direction: column;\n  font-size: 14px;\n  text-align: center;\n  transition: 0.3s;\n}\n\n.item svg {\n  height: 48px;\n  margin-bottom: 5px;\n  width: 48px;\n}\n\n.item--create,\n.item--post,\n.item--inspire {\n  color: #5a5aeb !important;\n}\n\n.content .item {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  flex-direction: column;\n  text-transform: uppercase;\n  font-weight: 700\n}\n\n.content .item span {\n  margin-top: 8px;\n  font-size: 14px;\n  color: #f1f1f1;\n  font-weight: 400;\n  cursor: pointer\n}\n\nbutton {\n  display: inline-block;\n  padding: 24px 32px;\n  border: 0;\n  text-decoration: none;\n  border-radius: 15px;\n  background-color: rgba(255,255,255,0.1);\n  border: 1px solid rgba(255,255,255,0.1);\n  backdrop-filter: blur(30px);\n  color: rgba(255,255,255,0.8);\n  font-size: 14px;\n  letter-spacing: 2px;\n  cursor: pointer;\n  text-transform: uppercase;\n}\n\nbutton:hover {\n  background-color: rgba(255,255,255,0.2);\n}\n', colors: '#f1f1f1,#5a5aeb,#fff,#3498db', radii: '15px', shadows: '', techniques: 'glassmorphism,text-shadow,typography-transform,svg-icon'),
const GalaxyComp(id: 'ElektroRaks_sour-otter-25', cat: 'Cards', author: 'ElektroRaks', tags: 'card,polygon,blur filter,text animation,rotate,clip-path', html: '<div class="card">\n     <div class="box">\n          <div class="content">\n               <span class="card-title">CSS Clip-Path </span>\n          <div class="text">\n               <strong>ELEKTRO RAKS</strong>\n               <p>Custom card</p>\n          </div>\n          </div>\n     </div>\n</div>', css: '\n/* From Uiverse.io by ElektroRaks - Tags: card, polygon, blur filter, text animation, rotate, clip-path */\n.card {\n  width: 11.875em;\n  height: 15.875em;\n  background: linear-gradient(135deg, #1afbf0, #da00ff);\n  background-position: center;\n  background-size: cover;\n  background-repeat: no-repeat;\n}\n\n.box {\n  width: 100%;\n  height: 100%;\n  background-color: rgba(255, 255, 255, 0.074);\n  -webkit-backdrop-filter: blur(20px);\n  backdrop-filter: blur(20px);\n}\n\n.content {\n  display: flex;\n  flex-direction: column;\n  justify-content: space-between;\n  width: 100%;\n  height: 100%;\n  padding: 10px;\n  background-position: center;\n  background-size: cover;\n  background-repeat: no-repeat;\n  clip-path: polygon(54% 27%, 100% 50%, 100% 100%, 51% 74%, 0 50%, 0% 0%);\n  transition: 0.5s;\n  line-height: 1.2;\n}\n\n.card-title {\n  width: 100%;\n  font-weight: bold;\n  color: white;\n  display: block;\n  padding-top: 6.3em;\n  font-size: 1.2em;\n  transform: rotate(34deg);\n  transition: 0.5s;\n  margin-left: 25%;\n}\n\n.text {\n  color: white;\n  opacity: 0;\n  transition: 0.5s;\n}\n\n.card:hover .content {\n  clip-path: polygon(100% 0, 100% 50%, 100% 100%, 0% 100%, 0 50%, 0% 0%);\n}\n\n.card:hover .card-title {\n  padding-top: 1em;\n  margin-left: 0%;\n  transform: rotate(0deg);\n}\n\n.card:hover .text {\n  opacity: 1;\n}\n', colors: '#da00ff,#1afbf0', radii: '', shadows: '', techniques: 'glassmorphism,3d-transform,gradient,clip-path'),
const GalaxyComp(id: 'FrM-bot_soft-rabbit-4', cat: 'Cards', author: 'FrM-bot', tags: 'card', html: '<div class="card">\n    <div class="img-container">\n        <div class="img">\n        </div>\n        <div class="description card">\n            <span class="title">\n                Card\n            </span>\n        </div>\n    </div>\n</div>', css: '\n/* From Uiverse.io by FrM-bot - Tags: card */\n/* From uiverse.io by @FrM-bot */\n.card {\n  width: 200px;\n  height: min-content;\n  transition: all .3s;\n  position: relative;\n  border-radius: .5rem 2rem;\n  box-shadow: 0px 15px 20px -5px rgba(0, 0, 0, 0.5);\n}\n\n.card:hover {\n  transform: scale(1.03);\n}\n\n.img {\n  transition: all .3s;\n  background: #ff0084;\n  background: -webkit-linear-gradient(to right, #33001b, #ff0084);\n  background: linear-gradient(to right, #33001b, #ff0084);\n  width: 100%;\n}\n\n.img:hover {\n  transform: scale(1.3);\n}\n\n.img-container {\n  display: grid;\n  border-radius: .5rem 2rem;\n  height: 270px;\n  overflow: hidden;\n}\n\n.description {\n  position: absolute;\n  bottom: .5rem;\n  left: .5rem;\n  text-align: start;\n  padding: .5rem 1em;\n  width: 90%;\n  transition: all 0.5s ease;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n  backdrop-filter: blur(.1rem);\n  background-color: rgba(0, 0, 0, 0.2);\n  border-radius: .5rem 2rem;\n}\n\n.description:hover {\n  transform: perspective(100px) translateX(7px) rotateX(3deg) rotateY(3deg) scale(1);\n  box-shadow: none;\n}\n\n.title {\n  color: aliceblue;\n}\n', colors: '#33001b,#ff0084', radii: '.5rem 2rem', shadows: '0px 15px 20px -5px rgba(0, 0, 0, 0.5),none', techniques: 'glassmorphism,3d-transform,gradient,perspective'),
const GalaxyComp(id: 'Gerente-S4V1T4R_shaggy-kangaroo-21', cat: 'Cards', author: 'Gerente-S4V1T4R', tags: 'card', html: '<div class="container">\n  <div class="box">\n    <div class="content">\n      \n    </div>\n  </div>\n</div>', css: '\n/* From Uiverse.io by Gerente-S4V1T4R - Tags: card */\n.container {\n  --background: linear-gradient(to left, #880505 0%, #f36b11 100%);\n  width: 190px;\n  height: 254px;\n  padding: 4px;\n  border-radius: 5px;\n  overflow: visible;\n  display: flex;\n  align-items: center;\n  background: var(--background);\n  position: relative;\n}\n\n.container .box {\n  position: relative;\n  width: 190px;\n  height: 244px;\n  background: #1b1b1b;\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-pack: center;\n  -ms-flex-pack: center;\n  justify-content: center;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n  border-radius: 10px;\n}\n\n.container .box .content {\n  position: relative;\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-pack: center;\n  -ms-flex-pack: center;\n  justify-content: center;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n  -webkit-box-orient: vertical;\n  -webkit-box-direction: normal;\n  -ms-flex-direction: column;\n  flex-direction: column;\n  text-align: center;\n  gap: 20px;\n  padding: 0 20px;\n  width: 100%;\n  height: 100%;\n  overflow: hidden;\n}\n\n.container .box .content .icon {\n  width: 50px;\n  height: 50px;\n  -webkit-box-shadow: 0 0 0 4px #e6e6e6,\n    0 0 0 6px rgb(212, 10, 10);\n  box-shadow: 0 0 0 4px #e6e6e6,\n    0 0 0 6px rgb(212, 10, 10);\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-pack: center;\n  -ms-flex-pack: center;\n  justify-content: center;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n  font-size: 2.5em;\n  -webkit-transition: 0.5s ease-in-out;\n  transition: 0.5s ease-in-out;\n}\n\n.container .box::before {\n  content: \'\';\n  position: absolute;\n  inset: -10px 50px;\n  border-top: 4px solid rgb(99, 89, 247);\n  z-index: -1;\n  border-bottom: 4px solid rgb(65, 44, 250);\n  z-index: -1;\n  z-index: -1;\n  -webkit-transform: skewY(15deg);\n  -ms-transform: skewY(15deg);\n  transform: skewY(15deg);', colors: '#e6e6e6,#1b1b1b,#aa551d,#880505,#f36b11', radii: '10px,50%,5px', shadows: '0 0 0 4px #e6e6e6,\n    0 0 0 6px rgb(212, 10, 10),0 0 0 4px #e6e6e6,\n    0 0 0 6px rgb(212, 10, 10)', techniques: '3d-transform,glow-shadow,gradient,pseudo-elements'),
const GalaxyComp(id: 'gharsh11032000_ancient-starfish-68', cat: 'Cards', author: 'gharsh11032000', tags: 'gradient,card,hover,hover effect', html: '<div class="card">\n  <div class="main-content">\n    <div class="header">\n  <span>Article on</span>\n  <span>29-June-2023</span>\n</div>\n<p class="heading">Different ways to use CSS in React</p>\n<div class="categories">\n  <span>React</span>\n  <span>Css</span>\n</div>\n  </div>\n<div class="footer">\n  by Harsh Gupta\n</div>\n</div>', css: '\n/* From Uiverse.io by gharsh11032000 - Tags: gradient, card, hover, hover effect */\n.card {\n  width: 320px;\n  height: 350px;\n  padding: 20px;\n  color: white;\n  background: linear-gradient(#212121, #212121) padding-box,\n              linear-gradient(145deg, transparent 35%,#e81cff, #40c9ff) border-box;\n  border: 2px solid transparent;\n  border-radius: 8px;\n  display: flex;\n  flex-direction: column;\n  cursor: pointer;\n  transform-origin: right bottom;\n  transition: all 0.6s cubic-bezier(0.23, 1, 0.320, 1);\n}\n\n.card .main-content {\n  flex: 1;\n}\n\n.card .header span:first-child {\n  font-weight: 600;\n  color: #717171;\n  margin-right: 4px;\n}\n\n.card .heading {\n  font-size: 24px;\n  margin: 24px 0 16px;\n  font-weight: 600;\n}\n\n.card .categories {\n  display: flex;\n  gap: 8px;\n}\n\n.card .categories span {\n  background-color: #e81cff;\n  padding: 4px 8px;\n  font-weight: 600;\n  text-transform: uppercase;\n  font-size: 12px;\n  border-radius: 50em;\n}\n\n.card .footer {\n  font-weight: 600;\n  color: #717171;\n  margin-right: 4px;\n}\n\n.card:hover {\n  rotate: 8deg;\n}\n', colors: '#212121,#717171,#40c9ff,#e81cff', radii: '50em,8px', shadows: '', techniques: 'cubic-bezier,3d-transform,gradient,typography-transform')
  ];

  static List<GalaxyComp> byCategory(String cat) =>
      curated.where((c) => c.cat == cat).toList();

  static List<GalaxyComp> byTechnique(String tech) =>
      curated.where((c) => c.techniques.contains(tech)).toList();

  static List<GalaxyComp> byStyle(String style) =>
      curated.where((c) => c.tags.contains(style.toLowerCase())).toList();

  static List<GalaxyComp> bestOf({required String category, String? technique}) {
    var results = byCategory(category);
    if (technique != null) {
      results = results.where((c) => c.techniques.contains(technique)).toList();
    }
    return results.take(20).toList();
  }

  /// Build a CSS technique reference snippet for prompt injection.
  static String buildTechniqueRef(String technique) {
    final examples = curated.where((c) => c.techniques.contains(technique)).take(3).toList();
    if (examples.isEmpty) return '';
    final buf = StringBuffer();
    buf.writeln('## CSS Technique: \$technique');
    for (final ex in examples) {
      buf.writeln('### {ex.cat} example (tags: {ex.tags})');
      final css = ex.css.length > 600 ? '\${ex.css.substring(0, 600)}...' : ex.css;
      buf.writeln('```css');
      buf.writeln(css);
      buf.writeln('```');
      buf.writeln();
    }
    return buf.toString();
  }
}

class GalaxyComp {

  const GalaxyComp({required this.id, required this.cat, required this.author,
    required this.tags, required this.html, required this.css,
    required this.colors, required this.radii, required this.shadows,
    required this.techniques});
  final String id, cat, author, tags, html, css;
  final String colors, radii, shadows, techniques;

  List<String> get tagList => tags.split(',').where((t) => t.isNotEmpty).toList();
  List<String> get techniqueList => techniques.split(',').where((t) => t.isNotEmpty).toList();
  List<String> get colorList => colors.split(',').where((t) => t.isNotEmpty).toList();
}
